window.HADITH_CACHE["muslim_2"] = {"1001":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْجَمَاعَةِ أَفْضَلُ مِنْ صَلَاةِ أَحَدِكُمْ وَحْدَهُ بِخَمْسَةٍ وَعِشْرِينَ جُزْءًا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] katanya; pernah aku menyetorkan kepada [Malik] dari [Ibnu Syihab] dari [Said bin Musayyab] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat jama'ah lebih utama dua puluh lima derajat daripada shalat salah seorang diantara kalian dengan sendiri.\""},"1002":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَفْضُلُ صَلَاةٌ فِي الْجَمِيعِ عَلَى صَلَاةِ الرَّجُلِ وَحْدَهُ خَمْسًا وَعِشْرِينَ دَرَجَةً قَالَ وَتَجْتَمِعُ مَلَائِكَةُ اللَّيْلِ وَمَلَائِكَةُ النَّهَارِ فِي صَلَاةِ الْفَجْرِقَالَ أَبُو هُرَيْرَةَ اقْرَءُوا إِنْ شِئْتُمْ{ وَقُرْآنَ الْفَجْرِ إِنَّ قُرْآنَ الْفَجْرِ كَانَ مَشْهُودًا }و حَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدٌ وَأَبُو سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِ عَبْدِ الْأَعْلَى عَنْ مَعْمَرٍ إِلَّا أَنَّهُ قَالَ بِخَمْسٍ وَعِشْرِينَ جُزْءًا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalat secara berjamaah lebih utama dua puluh lima derajat daripada shalat secara individual, \" Beliau melanjutkan: \"Dan para malaikat malam dan malaikat siang berkumpul ketika shalat fajar (subuh).\" Abu Hurairah; \"jika kalian berkenan, maka bacalah \"Dan tunaikanlah bacaan fajar (subuh) sesungguhnya bacaan (shalat subuh) disaksikan oleh para malaikat.\" QS. Al-Isra\"; 78. Dan telah menceritakan kepadaku [Abu Bakr bin Ishaq] telah menceritakan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] katanya; telah mengabarkan kepadaku [Said] dan [Abu Salamah], bahwa [Abu Hurairah] berkata; \"Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda seperti hadis Abdul A'la dari Ma'mar, hanya ia mengatakan dengan redaksi \"Lebih utama dua puluh lima bagian.\""},"1003":{"ar":"و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا أَفْلَحُ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ سَلْمَانَ الْأَغَرِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الْجَمَاعَةِ تَعْدِلُ خَمْسًا وَعِشْرِينَ مِنْ صَلَاةِ الْفَذِّ","id":"Dan telah menceritakan kepada kami [Abdullah bin Maslamah bin Qo'nab], telah menceritakan kepada kami [Aflah] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [Salman Al Agharr] dari [Abu Hurairah] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat jama'ah menyamai dua puluh lima kali shalat yang dikerjakan secara sendirian.\""},"1004":{"ar":"حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ وَمُحَمَّدُ بْنُ حَاتِمٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُمَرُ بْنُ عَطَاءِ بْنِ أَبِي الْخُوَارِ أَنَّهُ بَيْنَا هُوَ جَالِسٌ مَعَ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ إِذْ مَرَّ بِهِمْ أَبُو عَبْدِ اللَّهِ خَتَنُ زَيْدِ بْنِ زَبَّانٍ مَوْلَى الْجُهَنِيِّينَ فَدَعَاهُ نَافِعٌ فَقَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةٌ مَعَ الْإِمَامِ أَفْضَلُ مِنْ خَمْسٍ وَعِشْرِينَ صَلَاةً يُصَلِّيهَا وَحْدَهُ","id":"Telah menceritakan kepadaku [Harun bin Abdullah] dan [Muhammad bin Hatim], keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad], katanya; [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Umar bin Atha` bin Abu Al Khuwar], bahwa ketika ia duduk bersama Nafi' bin Jubair bin Muth'im, tiba-tiba [Abu Abdullah] yaitu suami saudara perempuan Zaid bin Zabban, mantan budak orang-orang Bani Juhainah. Lalu Nafi' memanggilnya dan berkata; \"Aku mendengar [Abu Hurairah] mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat bersama Imam lebih utama dua puluh lima kali dibandingkan shalat yang dilakukan secara sendirian.\""},"1005":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْجَمَاعَةِ أَفْضَلُ مِنْ صَلَاةِ الْفَذِّ بِسَبْعٍ وَعِشْرِينَ دَرَجَةً","id":"Telah menceritakan kepada kami [Yahya bin Yahya], katanya; aku menyetorkan hapalan kepada [Malik] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat jama'ah lebih utama dua puluh tujuh derajat daripada shalat sendirian.\""},"1006":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الرَّجُلِ فِي الْجَمَاعَةِ تَزِيدُ عَلَى صَلَاتِهِ وَحْدَهُ سَبْعًا وَعِشْرِينَو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ وَابْنُ نُمَيْرٍ قَالَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي قَالَا حَدَّثَنَا عُبَيْدُ اللَّهِ بِهَذَا الْإِسْنَادِ قَالَ ابْنُ نُمَيْرٍ عَنْ أَبِيهِ بِضْعًا وَعِشْرِينَ و قَالَ أَبُو بَكْرٍ فِي رِوَايَتِهِ سَبْعًا وَعِشْرِينَ دَرَجَةً و حَدَّثَنَاه ابْنُ رَافِعٍ أَخْبَرَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنَا الضَّحَّاكُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بِضْعًا وَعِشْرِينَ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna], katanya; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] katanya; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalatnya seseorang dengan berjama'ah melebihi shalatnya yang dikerjakan secara sendiri sebanyak dua puluh tujuh derajat.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], telah menceritakan kepada kami [Abu Usamah] dan [Ibnu Numair] katanya, (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ayahku], keduanya berkata; telah menceritakan kepada kami [Ubaidullah] dengan sanad seperti ini. Ibnu Numair berkata dari ayahnya dengan redaksi \"Sebanyak dua puluh tujuh derajat.\" Abu Bakr berkata dalam priwayatannya; \"Kurang lebih dua puluh derajat.\" Telah menceritakan kepada kami [Ibnu Rafi'] telah mengabarkan kepada kami [Ibnu Abu Fudaik] telah mengabarkan kepada kami [Adl Dlahak] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan redaksi \"Kurang lebih dua puluh derajat.\""},"1007":{"ar":"و حَدَّثَنِي عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَدَ نَاسًا فِي بَعْضِ الصَّلَوَاتِ فَقَالَ لَقَدْ هَمَمْتُ أَنْ آمُرَ رَجُلًا يُصَلِّي بِالنَّاسِ ثُمَّ أُخَالِفَ إِلَى رِجَالٍ يَتَخَلَّفُونَ عَنْهَا فَآمُرَ بِهِمْ فَيُحَرِّقُوا عَلَيْهِمْ بِحُزَمِ الْحَطَبِ بُيُوتَهُمْ وَلَوْ عَلِمَ أَحَدُهُمْ أَنَّهُ يَجِدُ عَظْمًا سَمِينًا لَشَهِدَهَا يَعْنِي صَلَاةَ الْعِشَاءِ","id":"Dan telah menceritakan kepadaku ['Amru An Naqid] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Zanad] dari [Al A'raj] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam tidak menjumpai beberapa orang dalam beberapa shalat, maka komentar beliau \"Sungguh aku berkeinginan kuat menyuruh seseorang untuk mengimami orang-orang, kemudian aku pergi untuk menemui orang-orang yang tidak menghadirinya dan kusuruh mereka untuk membakari rumah-rumah mereka dengan sebongkah kayu. Kalaulah seorang dari mereka tahu bahwa akan mereka dapatkan unta yang gemuk, niscaya akan mereka hadiri shalat isya`.\""},"1008":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لَهُمَا قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَثْقَلَ صَلَاةٍ عَلَى الْمُنَافِقِينَ صَلَاةُ الْعِشَاءِ وَصَلَاةُ الْفَجْرِ وَلَوْ يَعْلَمُونَ مَا فِيهِمَا لَأَتَوْهُمَا وَلَوْ حَبْوًا وَلَقَدْ هَمَمْتُ أَنْ آمُرَ بِالصَّلَاةِ فَتُقَامَ ثُمَّ آمُرَ رَجُلًا فَيُصَلِّيَ بِالنَّاسِ ثُمَّ أَنْطَلِقَ مَعِي بِرِجَالٍ مَعَهُمْ حُزَمٌ مِنْ حَطَبٍ إِلَى قَوْمٍ لَا يَشْهَدُونَ الصَّلَاةَ فَأُحَرِّقَ عَلَيْهِمْ بُيُوتَهُمْ بِالنَّارِ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Al A'masy] (Dan diriwayatkan dari jalan lain) telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] sedangkan lafadz hadits darinya, keduanya berkata; telah menceritakan kepada kami [Abu Muawiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat yang dirasakan berat bagi orang-orang munafik adalah shalat isya` dan shalat subuh, sekiranya mereka mengetahui keutamaannya, niscaya mereka akan mendatanginya sekalipun dengan merangkak. Sungguh aku berkeinginan untuk menyuruh seseorang sehingga shalat didirikan, kemudian kusuruh seseorang dan ia mengimami manusia, lalu aku bersama beberapa orang membawa kayu bakar untuk menjumpai suatu kaum yang tidak menghadiri shalat, lantas aku baker rumah mereka.\""},"1009":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَاوَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ هَمَمْتُ أَنْ آمُرَ فِتْيَانِي أَنْ يَسْتَعِدُّوا لِي بِحُزَمٍ مِنْ حَطَبٍ ثُمَّ آمُرَ رَجُلًا يُصَلِّي بِالنَّاسِ ثُمَّ تُحَرَّقُ بُيُوتٌ عَلَى مَنْ فِيهَاو حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَأَبُو كُرَيْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ وَكِيعٍ عَنْ جَعْفَرِ بْنِ بُرْقَانَ عَنْ يَزِيدَ بْنِ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] katanya; ini yang diceritakan kepada kami oleh [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, -lalu Abu Hurairah menyebutkan beberapa hadis, yang diantaranya- Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku berkeinginan menyuruh para pemuda supaya mempersiapkan kayu bakar, kemudian aku menyuruh seseorang untuk mengimami orang-orang, lalu rumah-rumah sekaligus para penghuninya (yang tidak menghadiri shalat jamaah) supaya dibakar.\" Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Abu Kuraib] dan [Ishaq bin Ibrahim] dari [Waki'] dari [Ja'far bin Barqan] dari [Yazid bin Al Asham] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam dengan hadits seperti di atas."},"1010":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ سَمِعَهُ مِنْهُ عَنْ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِقَوْمٍ يَتَخَلَّفُونَ عَنْ الْجُمُعَةِ لَقَدْ هَمَمْتُ أَنْ آمُرَ رَجُلًا يُصَلِّي بِالنَّاسِ ثُمَّ أُحَرِّقَ عَلَى رِجَالٍ يَتَخَلَّفُونَ عَنْ الْجُمُعَةِ بُيُوتَهُمْ","id":"Dan telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] dari [Abu Al Ahwash] bahwa Abu Ishaq mendengar darinya, dari [Abdullah], bahwsanya Nabi shallallahu 'alaihi wasallam bersabda kepada orang-orang yang ketinggalan shalat jumat; \"Sungguh aku berkeinginan untuk menyuruh seseorang mengimami manusia, kemudian kusuruh untuk membakar rumah-rumah orang-orang yang ketinggalan (shalat) jumat.\""},"1011":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ وَسُوَيْدُ بْنُ سَعِيدٍ وَيَعْقُوبُ الدَّوْرَقِيُّ كُلُّهُمْ عَنْ مَرْوَانَ الْفَزَارِيِّ قَالَ قُتَيْبَةُ حَدَّثَنَا الْفَزَارِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَصَمِّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ الْأَصَمِّ عَنْ أَبِي هُرَيْرَةَ قَالَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ أَعْمَى فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهُ لَيْسَ لِي قَائِدٌ يَقُودُنِي إِلَى الْمَسْجِدِ فَسَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُرَخِّصَ لَهُ فَيُصَلِّيَ فِي بَيْتِهِ فَرَخَّصَ لَهُ فَلَمَّا وَلَّى دَعَاهُ فَقَالَ هَلْ تَسْمَعُ النِّدَاءَ بِالصَّلَاةِ قَالَ نَعَمْ قَالَ فَأَجِبْ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ishaq bin Ibrahim] dan [Suwaid bin Sa'id] dan [Ya'kub Ad Dauraqi], semuanya dari [Marwan Al Fizari]. [Qutaibah] mengatakan; telah menceritakan kepada kami [Al Fizari] dari ['Ubaidullah bin Al Asham], dia berkata; telah menceritakan kepada kami [Yazid bin Al Asham] dari [Abu Hurairah] dia berkata; \"Seorang buta (tuna netra) pernah menemui Nabi shallallahu 'alaihi wasallam dan berujar \"Wahai Rasulullah, saya tidak memiliki seseorang yang akan menuntunku ke masjid.\" Lalu dia meminta keringanan kepada Rasulullah shallallahu 'alaihi wasallam untuk shalat di rumah. Ketika sahabat itu berpaling, beliau kembali bertanya: \"Apakah engkau mendengar panggilan shalat (adzan)?\" laki-laki itu menjawab; \"Benar.\" Beliau bersabda: \"Penuhilah seruan tersebut (hadiri jamaah shalat).\""},"1012":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ الْعَبْدِيُّ حَدَّثَنَا زَكَرِيَّاءُ بْنُ أَبِي زَائِدَةَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عُمَيْرٍ عَنْ أَبِي الْأَحْوَصِ قَالَقَالَ عَبْدُ اللَّهِ لَقَدْ رَأَيْتُنَا وَمَا يَتَخَلَّفُ عَنْ الصَّلَاةِ إِلَّا مُنَافِقٌ قَدْ عُلِمَ نِفَاقُهُ أَوْ مَرِيضٌ إِنْ كَانَ الْمَرِيضُ لَيَمْشِي بَيْنَ رَجُلَيْنِ حَتَّى يَأْتِيَ الصَّلَاةَ وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَّمَنَا سُنَنَ الْهُدَى وَإِنَّ مِنْ سُنَنِ الْهُدَى الصَّلَاةَ فِي الْمَسْجِدِ الَّذِي يُؤَذَّنُ فِيهِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], telah menceritakan kepada kami [Muhammad bin Bisyr Al 'Abdi], telah menceritakan kepada kami [Zakariya bin Abu Zaidah] telah menceritakan kepada kami [Abdul Malik bin Umair] dari [Abu Al Ahwash] katanya; [Abdullah] mengatakan; \"Kami dahulu berpendapat, bahwa tidaklah seseorang yang tidak menghadiri shalat (jamaah) melainkan ia seorang munafik yang telah jelas kemunafikannya, atau kalaulah ia sakit, maka ia berjalan dengan cara dipapah diantara dua orang hingga ia hadiri shalat.\" Abdullah bin Mas'ud berkata; Rasulullah shallallahu 'alaihi wasallam telah mengajari kami sunnah-sunnah petunjuk, dan diantara sunnah petunjuk adalah shalat wajib di masjid yang karenanya dikumandangkan adzan."},"1013":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ أَبِي الْعُمَيْسِ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ مَنْ سَرَّهُ أَنْ يَلْقَى اللَّهَ غَدًا مُسْلِمًا فَلْيُحَافِظْ عَلَى هَؤُلَاءِ الصَّلَوَاتِ حَيْثُ يُنَادَى بِهِنَّفَإِنَّ اللَّهَ شَرَعَ لِنَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُنَنَ الْهُدَى وَإِنَّهُنَّ مِنْ سُنَنِ الْهُدَى وَلَوْ أَنَّكُمْ صَلَّيْتُمْ فِي بُيُوتِكُمْ كَمَا يُصَلِّي هَذَا الْمُتَخَلِّفُ فِي بَيْتِهِ لَتَرَكْتُمْ سُنَّةَ نَبِيِّكُمْ وَلَوْ تَرَكْتُمْ سُنَّةَ نَبِيِّكُمْ لَضَلَلْتُمْ وَمَا مِنْ رَجُلٍ يَتَطَهَّرُ فَيُحْسِنُ الطُّهُورَ ثُمَّ يَعْمِدُ إِلَى مَسْجِدٍ مِنْ هَذِهِ الْمَسَاجِدِ إِلَّا كَتَبَ اللَّهُ لَهُ بِكُلِّ خَطْوَةٍ يَخْطُوهَا حَسَنَةً وَيَرْفَعُهُ بِهَا دَرَجَةً وَيَحُطُّ عَنْهُ بِهَا سَيِّئَةً وَلَقَدْ رَأَيْتُنَا وَمَا يَتَخَلَّفُ عَنْهَا إِلَّا مُنَافِقٌ مَعْلُومُ النِّفَاقِ وَلَقَدْ كَانَ الرَّجُلُ يُؤْتَى بِهِ يُهَادَى بَيْنَ الرَّجُلَيْنِ حَتَّى يُقَامَ فِي الصَّفِّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Al Fadl bin Dukain] dari [Abu Al Umais] dari [Ali bin Al Aqmar] dari [Abu Al Ahwash] dari [Abdullah], katanya; \"Siapa berkehendak menjumpai Allah besok sebagai seorang muslim, hendaklah ia jaga semua shalat yang ada, dimanapun ia mendengar panggilan shalat itu, sesungguhnya Allah telah mensyare'atkan kepada nabi kalian sunnah-sunnah petunjuk, dan sesungguhnya semua shalat, diantara sunnah-sunnah petunjuk itu, kalau kalian shalat di rumah kalian sebagaimana seseorang yang tidak hadir di masjid, atau rumahnya, berarti telah kalian tinggalkan sunnah nabi kalian, sekiranya kalian tinggalkan sunnah nabi kalian, sungguh kalian akan sesat, tidaklah seseorang bersuci dengan baik, kemudian ia menuju salah satu masjid yang ada, melainkan Allah menulis kebaikan baginya dari setiap langkah kakinya, dan dengannya Allah mngngkat derajatnya, dan menghapus kesalahan karenanya, menurut pendapat kami, tidaklah seseorang ketinggalan dari shalat, melainkan dia seorang munafik yang jelas kemunafikannya (munafik tulen), sungguh dahulu seseorang dari kami harus dipapah diantara dua orang hingga diberdirikan si shaff (barisan) shalat yang ada.\""},"1014":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ إِبْرَاهِيمَ بْنِ الْمُهَاجِرِ عَنْ أَبِي الشَّعْثَاءِ قَالَكُنَّا قُعُودًا فِي الْمَسْجِدِ مَعَ أَبِي هُرَيْرَةَ فَأَذَّنَ الْمُؤَذِّنُ فَقَامَ رَجُلٌ مِنْ الْمَسْجِدِ يَمْشِي فَأَتْبَعَهُ أَبُو هُرَيْرَةَ بَصَرَهُ حَتَّى خَرَجَ مِنْ الْمَسْجِدِ فَقَالَ أَبُو هُرَيْرَةَ أَمَّا هَذَا فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Al Ahwash] dari [Ibrahim bin Al Muhajir] dari [Abu Sya'tsa'], katanya; \"Ketika kami tengah duduk-duudk di masjid bersama [Abu Hurairah], dan ketika seorang muadzin mengumandangkan adzan, seseorang berdiri meninggalkan masjid sambil berjalan. Abu Hurairah terus mengawasinya hingga laki-laki keluar dari amsjid. Abu Hurairah lalu berkata; \"Orang ini telah membangkang Abul Qasim shallallahu 'alaihi wasallam.\""},"1015":{"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ الْمَكِّيُّ حَدَّثَنَا سُفْيَانُ هُوَ ابْنُ عُيَيْنَةَ عَنْ عُمَرَ بْنِ سَعِيدٍ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ الْمُحَارِبِيِّ عَنْ أَبِيهِ قَالَسَمِعْتُ أَبَا هُرَيْرَةَ وَرَأَى رَجُلًا يَجْتَازُ الْمَسْجِدَ خَارِجًا بَعْدَ الْأَذَانِ فَقَالَ أَمَّا هَذَا فَقَدْ عَصَى أَبَا الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan telah menceritakan kepada kami [Ibnu Abu Umar Al Makki] telah menceritakan kepada kami [Sufyan] yaitu Ibnu Uyainah, dari [Umar bin Said] dari [Asy'ats bin Abu Sya'tsa' Al Muharibi] dari [ayahnya], katanya; \"Aku mendengar [Abu Hurairah] ketika ia melihat seseorang yang tengah keluar melewati masjid setelah dikumandangkan adzan; \"Orang ini telah membangkang Abul Qasim shallallahu 'alaihi wasallam.\""},"1016":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْمُغِيرَةُ بْنُ سَلَمَةَ الْمَخْزُومِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ وَهُوَ ابْنُ زِيَادٍ حَدَّثَنَا عُثْمَانُ بْنُ حَكِيمٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ أَبِي عَمْرَةَ قَالَ دَخَلَ عُثْمَانُ بْنُ عَفَّانَ الْمَسْجِدَ بَعْدَ صَلَاةِ الْمَغْرِبِ فَقَعَدَ وَحْدَهُ فَقَعَدْتُ إِلَيْهِفَقَالَ يَا ابْنَ أَخِي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَلَّى الْعِشَاءَ فِي جَمَاعَةٍ فَكَأَنَّمَا قَامَ نِصْفَ اللَّيْلِ وَمَنْ صَلَّى الصُّبْحَ فِي جَمَاعَةٍ فَكَأَنَّمَا صَلَّى اللَّيْلَ كُلَّهُو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْأَسَدِيُّ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ جَمِيعًا عَنْ سُفْيَانَ عَنْ أَبِي سَهْلٍ عُثْمَانَ بْنِ حَكِيمٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Al Mughirah bin Salamah Al Makhzumi] telah menceritakan kepada kami [Abdul Wahid yaitu Ibnu Ziyad], telah menceritakan kepada kami [Usman bin Hakim] telah menceritakan kepada kami [Abdurrahman bin Abu 'Amrah] katanya; [Usman bin Affan] memasuki masjid setelah shalat maghrib, ia lalu duduk seorang diri, maka aku pun duduk menyertainya. Katanya; \"Wahai keponakanku, aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat isya` berjama'ah, seolah-olah ia shalat malam selama separuh malam, dan barangsiapa shalat shubuh berjamaah, seolah-olah ia telah shalat seluruh malamnya.\" Dan telah menceritakan kepadaku hadis ini [Zuhair bin Harb] telah menceritakan kepada kami [Muhammad bin Abdullah Al Asadi] (Dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Muhammad bin Rafi'] katanya; telah menceritakan kepada kami [Abdurrazaq], semuanya dari [Sufyan] dari [Abu Sahl Usman bin Hakim] dengan sanad seperti ini."},"1017":{"ar":"و حَدَّثَنِي نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ مُفَضَّلٍ عَنْ خَالِدٍ عَنْ أَنَسِ بْنِ سِيرِينَ قَالَ سَمِعْتُ جُنْدَبَ بْنَ عَبْدِ اللَّهِ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى الصُّبْحَ فَهُوَ فِي ذِمَّةِ اللَّهِ فَلَا يَطْلُبَنَّكُمْ اللَّهُ مِنْ ذِمَّتِهِ بِشَيْءٍ فَيُدْرِكَهُ فَيَكُبَّهُ فِي نَارِ جَهَنَّمَ","id":"Dan telah menceritakan kepadaku [Nashr bin Ali Al Juhdlami] telah menceritakan kepada kami [Bisyr yaitu Ibn Al Mufadlal] dari [Khalid] dari [Anas bin Sirin] katanya; aku mendengar [Jundab bin Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat subuh, maka ia berada dalam jaminan Allah, oleh karena itu jangan sampai Allah menuntut sesuatu dari kalian sebagai imbalan jaminan-Nya, sehingga Allah menangkapnya dan menyungkurkannya ke dalam neraka jahannam.\""},"1018":{"ar":"و حَدَّثَنِيهِ يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا إِسْمَعِيلُ عَنْ خَالِدٍ عَنْ أَنَسِ بْنِ سِيرِينَ قَالَ سَمِعْتُ جُنْدَبًا الْقَسْرِيَّ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ صَلَّى صَلَاةَ الصُّبْحِ فَهُوَ فِي ذِمَّةِ اللَّهِ فَلَا يَطْلُبَنَّكُمْ اللَّهُ مِنْ ذِمَّتِهِ بِشَيْءٍ فَإِنَّهُ مَنْ يَطْلُبْهُ مِنْ ذِمَّتِهِ بِشَيْءٍ يُدْرِكْهُ ثُمَّ يَكُبَّهُ عَلَى وَجْهِهِ فِي نَارِ جَهَنَّمَو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الْحَسَنِ عَنْ جُنْدَبِ بْنِ سُفْيَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا وَلَمْ يَذْكُرْ فَيَكُبَّهُ فِي نَارِ جَهَنَّمَ","id":"Dan telah menceritakan kepada kami [Ya'kub bin Ibrahim Ad Dauraqi] telah menceritakan kepada kami [Ismail] dari [Khalid] dari [Anas bin Sirin] katanya; aku mendengar [Jundab Al Qasri] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat subuh, maka ia berada dalam jaminan Allah, oleh karena itu jangan sampai Allah karena jaminan-Nya menuntut kalian dengan suatu hal, karena siapa yang Allah menuntutnya sesuatu karena jaminan-Nya, Allah pasti akan menemukannya dan menelungkupkannya diatas wajahnya di neraka jahannam.\" Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah], telah menceritakan kepada kami [Yazid bin Harun] dari [Dawud bin Abu Hind] dari [Al Hasan] dari [Jundab bin Sufyan] dari Nabi shallallahu 'alaihi wasallam dengan hadis seperti ini, namun ia tidak menyebutkan \"Lantas Allah menelungkupkannya ke dalam neraka jahannam.\""},"1019":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ مَحْمُودَ بْنَ الرَّبِيعِ الْأَنْصَارِيَّ حَدَّثَهُأَنَّ عِتْبَانَ بْنَ مَالِكٍ وَهُوَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّنْ شَهِدَ بَدْرًا مِنْ الْأَنْصَارِ أَنَّهُ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ أَنْكَرْتُ بَصَرِي وَأَنَا أُصَلِّي لِقَوْمِي وَإِذَا كَانَتْ الْأَمْطَارُ سَالَ الْوَادِي الَّذِي بَيْنِي وَبَيْنَهُمْ وَلَمْ أَسْتَطِعْ أَنْ آتِيَ مَسْجِدَهُمْ فَأُصَلِّيَ لَهُمْ وَدِدْتُ أَنَّكَ يَا رَسُولَ اللَّهِ تَأْتِي فَتُصَلِّي فِي مُصَلًّى فَأَتَّخِذَهُ مُصَلًّى قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَأَفْعَلُ إِنْ شَاءَ اللَّهُ قَالَ عِتْبَانُ فَغَدَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ الصِّدِّيقُ حِينَ ارْتَفَعَ النَّهَارُ فَاسْتَأْذَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَذِنْتُ لَهُ فَلَمْ يَجْلِسْ حَتَّى دَخَلَ الْبَيْتَ ثُمَّ قَالَ أَيْنَ تُحِبُّ أَنْ أُصَلِّيَ مِنْ بَيْتِكَ قَالَ فَأَشَرْتُ إِلَى نَاحِيَةٍ مِنْ الْبَيْتِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَبَّرَ فَقُمْنَا وَرَاءَهُ فَصَلَّى رَكْعَتَيْنِ ثُمَّ سَلَّمَ قَالَ وَحَبَسْنَاهُ عَلَى خَزِيرٍ صَنَعْنَاهُ لَهُ قَالَ فَثَابَ رِجَالٌ مِنْ أَهْلِ الدَّارِ حَوْلَنَا حَتَّى اجْتَمَعَ فِي الْبَيْتِ رِجَالٌ ذَوُو عَدَدٍ فَقَالَ قَائِلٌ مِنْهُمْ أَيْنَ مَالِكُ بْنُ الدُّخْشُنِ فَقَالَ بَعْضُهُمْ ذَلِكَ مُنَافِقٌ لَا يُحِبُّ اللَّهَ وَرَسُولَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَقُلْ لَهُ ذَلِكَ أَلَا تَرَاهُ قَدْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يُرِيدُ بِذَلِكَ وَجْهَ اللَّهِ قَالَ قَالُوا اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ فَإِنَّمَا نَرَى وَجْهَهُ وَنَصِيحَتَهُ لِلْمُنَافِقِينَ قَالَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَإِنَّ اللَّهَ قَدْ حَرَّمَ عَلَى النَّارِ مَنْ قَالَ لَا إِلَهَ إِلَّا اللَّهُ يَبْتَغِي بِذَلِكَ وَجْهَ اللَّهِقَالَ ابْنُ شِهَابٍ ثُمَّ سَأَلْتُ الْحُصَيْنَ بْنَ مُحَمَّدٍ الْأَنْصَارِيَّ وَهُوَ أَحَدُ بَنِي سَالِمٍ وَهُوَ مِنْ سَرَاتِهِمْ عَنْ حَدِيثِ مَحْمُودِ بْنِ الرَّبِيعِ فَصَدَّقَهُ بِذَلِكَ و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ كِلَاهُمَا عَنْ عَبْدِ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي مَحْمُودُ بْنُ رَبِيعٍ عَنْ عِتْبَانَ بْنِ مَالِكٍ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَاقَ الْحَدِيثَ بِمَعْنَى حَدِيثِ يُونُسَ غَيْرَ أَنَّهُ قَالَ فَقَالَ رَجُلٌ أَيْنَ مَالِكُ بْنُ الدُّخْشُنِ أَوْ الدُّخَيْشِنِ وَزَادَ فِي الْحَدِيثِ قَالَ مَحْمُودٌ فَحَدَّثْتُ بِهَذَا الْحَدِيثِ نَفَرًا فِيهِمْ أَبُو أَيُّوبَ الْأَنْصَارِيُّ فَقَالَ مَا أَظُنُّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا قُلْتَ قَالَ فَحَلَفْتُ إِنْ رَجَعْتُ إِلَى عِتْبَانَ أَنْ أَسْأَلَهُ قَالَ فَرَجَعْتُ إِلَيْهِ فَوَجَدْتُهُ شَيْخًا كَبِيرًا قَدْ ذَهَبَ بَصَرُهُ وَهُوَ إِمَامُ قَوْمِهِ فَجَلَسْتُ إِلَى جَنْبِهِ فَسَأَلْتُهُ عَنْ هَذَا الْحَدِيثِ فَحَدَّثَنِيهِ كَمَا حَدَّثَنِيهِ أَوَّلَ مَرَّةٍ قَالَ الزُّهْرِيُّ ثُمَّ نَزَلَتْ بَعْدَ ذَلِكَ فَرَائِضُ وَأُمُورٌ نَرَى أَنَّ الْأَمْرَ انْتَهَى إِلَيْهَا فَمَنْ اسْتَطَاعَ أَنْ لَا يَغْتَرَّ فَلَا يَغْتَرَّ و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ مَحْمُودِ بْنِ الرَّبِيعِ قَالَ إِنِّي لَأَعْقِلُ مَجَّةً مَجَّهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ دَلْوٍ فِي دَارِنَا قَالَ مَحْمُودٌ فَحَدَّثَنِي عِتْبَانُ بْنُ مَالِكٍ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّ بَصَرِي قَدْ سَاءَ وَسَاقَ الْحَدِيثَ إِلَى قَوْلِهِ فَصَلَّى بِنَا رَكْعَتَيْنِ وَحَبَسْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى جَشِيشَةٍ صَنَعْنَاهَا لَهُ وَلَمْ يَذْكُرْ مَا بَعْدَهُ مِنْ زِيَادَةِ يُونُسَ وَمَعْمَرٍ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya At Tujibi] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] bahwa [Mahmud bin Rabi' Al Anshari] menceritakan kepadanya; bahwa ['Utban bin Malik] -seorang sahabat Nabi shallallahu 'alaihi wasallam yang turut serta dalam perang badar, dari kaum Anshar- pernah menemui Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Wahai Rasulullah, aku tidak lagi percaya terhadap penglihatanku (pandangan sudah kabur) dan aku terbiasa shalat mengimami kaumku, jika hujan turun, maka lembah yang berada antara aku dan mereka mengalir deras, sehingga aku tak bisa mendatangi masjid mereka dan shalat mengimami mereka. Aku sangat berkeinginan sekiranya anda datang dan shalat di mushalla kaumku, sehingga aku menjadikannya sebagai mushalla. Beliau bersabda: \"Baiklah, saya akan datang insya Allah.\" Itban berkata; \"Lalu Rasulullah shallallahu 'alaihi wasallam berangkat bersama Abu Bakr As sidiq ketika hari agak siang. Rasulullah shallallahu 'alaihi wasallam meminta izin, setelah aku memberinya izin, beliau tidak duduk hingga masuk rumah, kemudian beliau bertanya: \"Dimanakah engkau menginginkan supaya aku shalat di rumahmu?\" Maka aku tunjukan ke sudut rumah. Rasulullah shallallahu 'alaihi wasallam pun berdiri dan bertakbir, lalu kami berdiri di belakangnya dan beliau mendirikan shalat dua rakaat, kemudian beliau mengucapkan salam.\" Itban berkata; lalu kami menahan beliau karena ada masakan khazir yaitu daging yang dicampur tepung berkuahyang sengaja kami masak untuk beliau. Kata Itban selanjutknya; Lalu beberapa laki-laki dari tetangga yang ikut berkumpul di sekitar kami, lalu seseorang berkata; \"Dimanakah Malik bin Dukhsyun?\" sebagian mereka menjawab; \"Dia adalah seorang munafik yang tidak mencintai Allah dan Rasul-Nya.\" Seketika itu pula Rasulullah Shallallahu 'alahi wasallam menegur: \"Janganlah kamu mengatakan seperti itu, bukankah engkau tahu bahwa ia telah mengucapkan laa ilaaha illallah yang ia niyatkan untuk memperoleh wajah Allah?\" [Ibn Syihab] berkata; kemudian aku bertanya [Al Hushain bin Muhammad Al Anshari] yaitu salah seorang bani Salim -ia adalah sosok manusia yang paling mulia di kalangan mereka- tentang hadis Mahmud bin Rabi', lantas dia membenarkannya. Telah menceritakan kepada kami [Muhammad bin Rafi'] dan [Abd bin Humaid], keduanya dari [Abdurrazaq] katanya; telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] katanya; telah menceritakan kepadaku [Mahmud bin Rabi'] dari [Itban bin Malik], katanya; Aku mendatangi Rasulullah shallallahu 'alaihi wasallam, kemudian beliau membawakan hadits seperti hadits Yunus, hanyasaja ia mengatakan; \"Lantas seseorang bertanya; 'Dimanakah Malik bin Duhsyun? atau dengan redaksi Dukhaisyin?\" Dan ia tambahkan dalam hadisnya, Mahmud berkata; dan aku menyampaikan hadits ini kepada sejumlah orang yang diantara mereka adalah Abu Ayyub Al Anshari, katanya; \"Setahuku bukan Rasulullah Shallallahu 'alahi wasallam yang berkata. Mahmud berkata; \"Maka aku bersumpah jika aku kembali kepada Itban, aku akan menanyainya.\" Mahmud melanjutkan; \"Aku pun kembali menemuinya dan aku menemuinya ketika ia telah lanjut usia dan pandangannya telah buta, ketika itu ia menjadi imam kaumnya. Lalu aku duduk disampingnya, aku bertanya kepadanya tentang hadits ini, ia lalu mnceritakannya sebagaimana dahulu ia menceritakan kepadaku pertama kali. [Az Zuhri] berkata; \"Setelah itu, diturunkan beberapa fardhu dan masalah yang kami lihat segala urusan telah selesai, oleh karena itu siapa yang bisa untuk tidak tertipu, maka lakukanlah.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Al Walid bin Muslim] dari [Auza'i], katanya; telah menceritakan kepadaku [Az Zuhri] dari [Mahmud bin Rabi'] katanya; aku masih teringat semprotan yang dilakukan Rasulullah shallallahu 'alaihi wasallam dari suatu ember milik kampungku.\" Mahmud berkata; telah menceritakan kepadaku [Itban bin Malik], katanya; aku berkata; \"Wahai Rasulullah, penglihatanku telah memburuk, lalu ia menyampaikan suatu hadis hingga ucapannya; \"Maka beliau shalat dua raka'at mengimami kami, setelah itu kami menahan Rasulullah shallallahu 'alaihi wasallam karena masakan Khasyisyah, yaitu bubur tepung bercampur daging yang kami masak untuk beliau.\" Namun sesudah itu Mahmud bin Rabi' tidak menyebut tambahan Yunus dan Ma'mar."},"1020":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِ�� طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ جَدَّتَهُ مُلَيْكَةَ دَعَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِطَعَامٍ صَنَعَتْهُ فَأَكَلَ مِنْهُ ثُمَّ قَالَ قُومُوا فَأُصَلِّيَ لَكُمْ قَالَ أَنَسُ بْنُ مَالِكٍ فَقُمْتُ إِلَى حَصِيرٍ لَنَا قَدْ اسْوَدَّ مِنْ طُولِ مَا لُبِسَ فَنَضَحْتُهُ بِمَاءٍ فَقَامَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَصَفَفْتُ أَنَا وَالْيَتِيمُ وَرَاءَهُ وَالْعَجُوزُ مِنْ وَرَائِنَا فَصَلَّى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ انْصَرَفَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya], katanya; aku pernah menyetorkan hapalan kepada [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik], bahwa neneknya Mulaikah pernah mengundang Rasulullah shallallahu 'alaihi wasallam karena hidangan yang aku buat. Beliau pun memakannya, setelah itu beliau bersabda: \"Berdirilah kalian, aku akan mengimami untuk kalian.\" Anas bin Malik berkata; \"Aku lalu berdiri menuju sebuah tikar yang warnanya telah menghitam, karena sekian lama dipakai, lalu kuperciki dengan air, saementara Rasulullah shallallahu 'alaihi wasallam berdiri diatasnya. Aku lalu membuat shaff bersama seorang anak yatim yang berada di belakang beliau dan seorang wanita tua di belakang kami. Rasulullah shallallahu 'alaihi wasallam kemudian shalat dua raka'at mengimami kami, selanjutnya beliau beranjak pergi.\""},"1021":{"ar":"و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ وَأَبُو الرَّبِيعِ كِلَاهُمَا عَنْ عَبْدِ الْوَارِثِ قَالَ شَيْبَانُ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسَنَ النَّاسِ خُلُقًا فَرُبَّمَا تَحْضُرُ الصَّلَاةُ وَهُوَ فِي بَيْتِنَا فَيَأْمُرُ بِالْبِسَاطِ الَّذِي تَحْتَهُ فَيُكْنَسُ ثُمَّ يُنْضَحُ ثُمَّ يَؤُمُّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَقُومُ خَلْفَهُ فَيُصَلِّي بِنَا وَكَانَ بِسَاطُهُمْ مِنْ جَرِيدِ النَّخْلِ","id":"Dan telah menceritakan kepada kami [Syaiban bin Farukh] dan [Abu Rabi'], keduanya dari [Abdul Warits]. [Syaiban] mengatakan; telah menceritakan kepada kami [Abdul Warits] dari [Abu Tayyah] dari [Anas bin Malik], katanya; Rasulullah shallallahu 'alaihi wasallam adalah sosok manusia yang terbaik akhlaknya, ketika waktu shalat tiba dan beliau di rumah kami, maka beliau memerintahkan agar dibentangkan tikar yang ada dibawahnya. Kemudian disapu dan diperciki air. Lalu Rasulullah shallallahu 'alaihi wasallam mengimami, sementara kami berdiri di belakang beliau, lalu beliau shalat bersama kami. Dan tikar mereka ketika itu terbuat dari pelepah kurma.\""},"1022":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا سُلَيْمَانُ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَدَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْنَا وَمَا هُوَ إِلَّا أَنَا وَأُمِّي وَأُمُّ حَرَامٍ خَالَتِي فَقَالَ قُومُوا فَلِأُصَلِّيَ بِكُمْ فِي غَيْرِ وَقْتِ صَلَاةٍ فَصَلَّى بِنَا فَقَالَ رَجُلٌ لِثَابِتٍ أَيْنَ جَعَلَ أَنَسًا مِنْهُ قَالَ جَعَلَهُ عَلَى يَمِينِهِ ثُمَّ دَعَا لَنَا أَهْلَ الْبَيْتِ بِكُلِّ خَيْرٍ مِنْ خَيْرِ الدُّنْيَا وَالْآخِرَةِ فَقَالَتْ أُمِّي يَا رَسُولَ اللَّهِ خُوَيْدِمُكَ ادْعُ اللَّهَ لَهُ قَالَ فَدَعَا لِي بِكُلِّ خَيْرٍ وَكَانَ فِي آخِرِ مَا دَعَا لِي بِهِ أَنْ قَالَ اللَّهُمَّ أَكْثِرْ مَالَهُ وَوَلَدَهُ وَبَارِكْ لَهُ فِيهِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Sulaiman] dari [Tsabit] dari [Anas] katanya; Nabi shallallahu 'alaihi wasallam pernah menemui kami ketika tidak ada seorangpun selain aku, ibuku, dan Ummu Haram, bibiku. Lalu beliau bersabda: \"Berdirilah kalian, aku akan shalat bersama kalian diluar waktu shalat.\" Maka beliau shalat bersama kami.\" Seseorang bertanya kepada Tsabit; \"Dimanakah beliau meletakkan Anas?\" Tsabit menjawab; \"Beliau meletakkan Anas di sebelah kanannya, lantas beliau mendokan kebaikan untuk kami, ahli bait, dengan kebaikan dunia dan akhirat.\" Kemudian ibuku berkata; \"Wahai Rasulullah, pelayan kecilmu -maksudnya Anas- tolong do'akanlah kebaikan untuknya!\" Beliau kemudian mendo'akan segala kebaikan untukku, terakhir kali doa beliau untukku adalah dengan bacaan ALLAAHUMMA AKTSIR MALAHU WAWALADAHU WABAARIK LAHU FIIHI (Ya Allah, perbanyaklah hartanya dan anaknya, dan berilah barakah padanya baginya).\""},"1023":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ الْمُخْتَارِ سَمِعَ مُوسَى بْنَ أَنَسٍ يُحَدِّثُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِهِ وَبِأُمِّهِ أَوْ خَالَتِهِ قَالَ فَأَقَامَنِي عَنْ يَمِينِهِ وَأَقَامَ الْمَرْأَةَ خَلْفَنَاو حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ ح و حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ يَعْنِي ابْنَ مَهْدِيٍّ قَالَ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepada kami [Ubaidullah bin Muadz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Mukhtar], ia mendengar [Musa bin Anas] mnceritakan dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat bersmanya dan ibunya atau bibinya. Kata Anas selanjutnya; \"Kemudian beliau menempatkanku di sebelah kanannya dan beliau menempatkan wanita di belakang kami.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Zuhair bin Harb] katanya; telah menceritakan kepada kami [Abdurrahman yaitu Ibnu Mahdi] katanya; telah menceritakan kepada kami [Syu'bah] dengan isnad ini."},"1024":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا عَبَّادُ بْنُ الْعَوَّامِ كِلَاهُمَا عَنْ الشَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَدَّادٍ قَالَ حَدَّثَتْنِي مَيْمُونَةُ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَأَنَا حِذَاءَهُ وَرُبَّمَا أَصَابَنِي ثَوْبُهُ إِذَا سَجَدَ وَكَانَ يُصَلِّي عَلَى خُمْرَةٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi], telah mengabarkan kepada kami [Khalid bin Abdullah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] katanya; telah menceritakan kepada kami ['Abbad bin Al 'Awwam] keduanya dari [Asy Syaibani] dari [Abdullah bin Syidad], katanya; telah menceritakan kepadaku [Maimunah] isteri Nabi shallallahu 'alaihi wasallam, katanya; Rasululah shallallahu 'alaihi wasallam pernah shalat dan aku sejajar dengan beliau, adakalanya pakaian beliau mengenaiku jika beliau sujud, dan beliau ketika itu shalat diatas kain.\""},"1025":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنِي سُوَيْدُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ جَمِيعًا عَنْ الْأَعْمَشِ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَاللَّفْظُ لَهُ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ الْخُدْرِيُّأَنَّهُ دَخَلَ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَجَدَهُ يُصَلِّي عَلَى حَصِيرٍ يَسْجُدُ عَلَيْهِ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib], keduanya berkata; telah menceritakan kepada kami [Abu Muawiyah] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Suwaid bin Said], katanya; telah menceritakan kepada kami [Ali bin Mushir] semuanya dari [Al A'masy] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ishaq bin Ibrahim] dan lafadz miliknya, telah mengabarkan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Al-A'masy] dari [Abu Sufyan] dari [Jabir] katanya; telah menceritakan kepada kami [Abu Said Al Khudzri] bahwa dia pernah menemui Rasulullah shallallahu 'alaihi wasallam dan ia mendapati beliau tengah shalat diatas tikar yang beliau pergunakan untuk bersujud.\""},"1026":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ قَالَ أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ الرَّجُلِ فِي جَمَاعَةٍ تَزِيدُ عَلَى صَلَاتِهِ فِي بَيْتِهِ وَصَلَاتِهِ فِي سُوقِهِ بِضْعًا وَعِشْرِينَ دَرَجَةً وَذَلِكَ أَنَّ أَحَدَهُمْ إِذَا تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْمَسْجِدَ لَا يَنْهَزُهُ إِلَّا الصَّلَاةُ لَا يُرِيدُ إِلَّا الصَّلَاةَ فَلَمْ يَخْطُ خَطْوَةً إِلَّا رُفِعَ لَهُ بِهَا دَرَجَةٌ وَحُطَّ عَنْهُ بِهَا خَطِيئَةٌ حَتَّى يَدْخُلَ الْمَسْجِدَ فَإِذَا دَخَلَ الْمَسْجِدَ كَانَ فِي الصَّلَاةِ مَا كَانَتْ الصَّلَاةُ هِيَ تَحْبِسُهُ وَالْمَلَائِكَةُ يُصَلُّونَ عَلَى أَحَدِكُمْ مَا دَامَ فِي مَجْلِسِهِ الَّذِي صَلَّى فِيهِ يَقُولُونَ اللَّهُمَّ ارْحَمْهُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ تُبْ عَلَيْهِ مَا لَمْ يُؤْذِ فِيهِ مَا لَمْ يُحْدِثْ فِيهِحَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ أَخْبَرَنَا عَبْثَرٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ بَكَّارِ بْنِ الرَّيَّانِ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ زَكَرِيَّاءَ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى قَالَ حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ كُلُّهُمْ عَنْ الْأَعْمَشِ فِي هَذَا الْإِسْنَادِ بِمِثْلِ مَعْنَاهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib], semuanya dari [Abu Muawiyah]. [Abu Kuraib] mengatakan; telah menceritakan kepada kami [Abu Muawiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seseorang dengan berjama'ah melebihi dua puluh sembilan derajat dari shalat seseorang yang dikerjakan di rumahnya dan di pasarnya, demikian itu karena bila salah seorang diantara mereka berwudhu' dengan menyempurnakan wudlu'nya, lalu mendatangi masjid, dan tidak ada yang mendorongnya kecuali untuk shalat, maka tidaklah ia melangkah satu langkah, kecuali akan ditinggikan derajatnya dan dihapus kesalahannya, hingga ia masuk masjid, jika ia telah masuk masjid, maka ia dihitung dalam shalat selama ia tertahan oleh shalat, dan malaikat terus mendoakan salah seorang diantara kalian selama ia dalam majlisnya yang ia pergunakan untuk shalat, malaikat akan berdoa; \"Ya Allah, rahmatilah dia, Ya Allah, ampunilah dia, Ya Allah maafkanlah dia, \" selama ia tidak melakukan gangguan dan belum berhadats.\" Telah menceritakan kepada kami [Said bin 'Amru] dan [Al Asy'ats] telah mengabarkan kepada kami [Abtsar] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Muhammad bin Bukkar bin Rayyan] katanya; telah menceritakan kepada kami [Ismail bin Zakariya] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Al Mutsanna] katanya; telah menceritakan kepada kami [Ibnu Adi] dari [Syu'bah] semuanya dari [Al A'masy] tentang sanad dan maksud yang sama."},"1027":{"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ السَّخْتِيَانِيِّ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَلَائِكَةَ تُصَلِّي عَلَى أَحَدِكُمْ مَا دَامَ فِي مَجْلِسِهِ تَقُولُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ مَا لَمْ يُحْدِثْ وَأَحَدُكُمْ فِي صَلَاةٍ مَا كَانَتْ الصَّلَاةُ تَحْبِسُهُ","id":"Dan telah menceritakan kepada kami [Ibn Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ayyub As Sakhtiyani] dari [Ibnu Sirin] dari [Abu Hurairah] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Para malaikat akan mendoakan salah seorang diantara kalian selama ia dalam majlisnya, mereka memohon; \"Ya Allah, ampunilah dia, Ya Allah, rahmatilah dia, \" selama ia belum berhadas, dan salah seorang diantara kalian dihitung dalam shalatnya selama ia tertahan oleh shalat.\""},"1028":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَبِي رَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ الْعَبْدُ فِي صَلَاةٍ مَا كَانَ فِي مُصَلَّاهُ يَنْتَظِرُ الصَّلَاةَ وَتَقُولُ الْمَلَائِكَةُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُ حَتَّى يَنْصَرِفَ أَوْ يُحْدِثَ قُلْتُ مَا يُحْدِثُ قَالَ يَفْسُو أَوْ يَضْرِطُ","id":"Telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Abu Rafi'] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang hamba masih dihitung dalam shalat selama ia berada di tempat shalatnya untuk menunggu shalat dan malaikat akan mendoakannya; \"Ya Allah, ampunilah dia, Ya Allah, rahmatilah dia, \" hingga ia beranjak atau berhadats.\" Aku bertanya; \"Apa yang dimaksud berhadats?\" Jawabnya; \"Kentut.\""},"1029":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَزَالُ أَحَدُكُمْ فِي صَلَاةٍ مَا دَامَتْ الصَّلَاةُ تَحْبِسُهُ لَا يَمْنَعُهُ أَنْ يَنْقَلِبَ إِلَى أَهْلِهِ إِلَّا الصَّلَاةُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] katanya; aku pernah menyetorkan hapalan kepada [Malik] dari [Abu Zanad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang diantara kalian masih dihitung dalam shalat selama ia tertahan oleh shalat, dan tidak ada yang menhannya untuk kembali ke keluarganya selain shalat.\""},"1030":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ ح و حَدَّثَنِي مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ هُرْمُزَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحَدُكُمْ مَا قَعَدَ يَنْتَظِرُ الصَّلَاةَ فِي صَلَاةٍ مَا لَمْ يُحْدِثْ تَدْعُو لَهُ الْمَلَائِكَةُ اللَّهُمَّ اغْفِرْ لَهُ اللَّهُمَّ ارْحَمْهُو حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِ هَذَا","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Muhammad bin Salamah Al Muradi] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Yunus] dari [Ibnu Syihab] dari [Ibnu Hurmuz] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Salah seorang diantara kalian dihitung dalam shalatnya selama duduk menunggu shalat, dan tidak berhadats, malaikat juga akan mendoakannya; \"Ya Allah, ampunilah dia, ya Allah, rahmatilah dia.\" Dan telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hamam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini."},"1031":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَرَّادٍ الْأَشْعَرِيُّ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَعْظَمَ النَّاسِ أَجْرًا فِي الصَّلَاةِ أَبْعَدُهُمْ إِلَيْهَا مَمْشًى فَأَبْعَدُهُمْ وَالَّذِي يَنْتَظِرُ الصَّلَاةَ حَتَّى يُصَلِّيَهَا مَعَ الْإِمَامِ أَعْظَمُ أَجْرًا مِنْ الَّذِي يُصَلِّيهَا ثُمَّ يَنَامُوَفِي رِوَايَةِ أَبِي كُرَيْبٍ حَتَّى يُصَلِّيَهَا مَعَ الْإِمَامِ فِي جَمَاعَةٍ","id":"Telah menceritakan kepada kami [Abdullah bin Barrad Al Asy'ari] dan [Abu Kuraib], keduanya berkata; telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Manusia paling besar pahalanya dalam shalat adalah yang paling jauh perjalannya, lalu yang selanjutnya, dan seseorang yang menunggu shalat hingga melakukannya bersama imam, lebih besar pahalanya daripada yang melakukannya kemudian tidur.\" Dan dalam suatu periwayatan Abu Kuraib disebutkan; \"Hingga ia tunaikan shalat bersama imam secara berjama'ah.\""},"1032":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا عَبْثَرٌ عَنْ سُلَيْمَانَ التَّيْمِيِّ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَجُلٌ لَا أَعْلَمُ رَجُلًا أَبْعَدَ مِنْ الْمَسْجِدِ مِنْهُ وَكَانَ لَا تُخْطِئُهُ صَلَاةٌ قَالَ فَقِيلَ لَهُ أَوْ قُلْتُ لَهُ لَوْ اشْتَرَيْتَ حِمَارًا تَرْكَبُهُ فِي الظَّلْمَاءِ وَفِي الرَّمْضَاءِ قَالَ مَا يَسُرُّنِي أَنَّ مَنْزِلِي إِلَى جَنْبِ الْمَسْجِدِ إِنِّي أُرِيدُ أَنْ يُكْتَبَ لِي مَمْشَايَ إِلَى الْمَسْجِدِ وَرُجُوعِي إِذَا رَجَعْتُ إِلَى أَهْلِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ جَمَعَ اللَّهُ لَكَ ذَلِكَ كُلَّهُو حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا الْمُعْتَمِرُ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَخْبَرَنَا جَرِيرٌ كِلَاهُمَا عَنْ التَّيْمِيِّ بِهَذَا الْإِسْنَادِ بِنَحْوِهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abtsar] dari [Sulaiman At Tamimi] dari [Abu Usman An Nahdi] dari [Ubay bin Ka'b] katanya; seseorang yang setahuku tak ada lagi yang lebih jauh (rumahnya) dari masjid, dan ia tak pernah ketinggalan dari shalat. Ubay berkata; maka ia diberi saran atau kusarankan; \"Bagaimana sekiranya jika kamu membeli keledai untuk kamu kendarai saat gelap atau saat panas terik? laki-lakiitu menjawab; \"Aku tidak ingin rumahku disamping masjid, sebab aku ingin jalanku ke masjid dan kepulanganku ke rumah semua dicatat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Telah Allah himpun untukmu semuanya tadi.\" Dan telah menceritakan kepada kami [Muhammad bin Abdul A'la] telah menceritakan kepada kami [Al Mu'tamir] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ishaq bin Ibrahim] katanya; telah mengabarkan kepada kami [Jarir], keduanya dari [At Taimi] dengan sanad seperti ini."},"1033":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا عَبَّادُ بْنُ عَبَّادٍ حَدَّثَنَا عَاصِمٌ عَنْ أَبِي عُثْمَانَ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكَانَ رَجُلٌ مِنْ الْأَنْصَارِ بَيْتُهُ أَقْصَى بَيْتٍ فِي الْمَدِينَةِ فَكَانَ لَا تُخْطِئُهُ الصَّلَاةُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَتَوَجَّعْنَا لَهُ فَقُلْتُ لَهُ يَا فُلَانُ لَوْ أَنَّكَ اشْتَرَيْتَ حِمَارًا يَقِيكَ مِنْ الرَّمْضَاءِ وَيَقِيكَ مِنْ هَوَامِّ الْأَرْضِ قَالَ أَمَ وَاللَّهِ مَا أُحِبُّ أَنَّ بَيْتِي مُطَنَّبٌ بِبَيْتِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَحَمَلْتُ بِهِ حِمْلًا حَتَّى أَتَيْتُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ قَالَ فَدَعَاهُ فَقَالَ لَهُ مِثْلَ ذَلِكَ وَذَكَرَ لَهُ أَنَّهُ يَرْجُو فِي أَثَرِهِ الْأَجْرَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لَكَ مَا احْتَسَبْتَو حَدَّثَنَا سَعِيدُ بْنُ عَمْرٍو الْأَشْعَثِيُّ وَمُحَمَّدُ بْنُ أَبِي عُمَرَ كِلَاهُمَا عَنْ ابْنِ عُيَيْنَةَ ح و حَدَّثَنَا سَعِيدُ بْنُ أَزْهَرَ الْوَاسِطِيُّ قَالَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا أَبِي كُلُّهُمْ عَنْ عَاصِمٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami] telah menceritakan kepada kami ['Abbad bin 'Abbad] telah menceritakan kepada kami ['Ashim] dari [Abu Utsman] dari [Ubay bin Ka'b], katanya; \"Seorang laki-laki Anshar memiliki rumah yang paling jauh di Madinah, namun dirinya tidak pernah ketinggalan shalat bersama Rasulullah shallallahu 'alaihi wasallam. Ubay melanjutkan; \"Kami pun merasa iba terhadapnya hingga aku berkata; \"Alangkah baiknya sekiranya engkau membeli seekor keledai yang menjagamu dari sengatan panas dan serangga-serangga bumi yang membahayakan.\" laki-laki itu berkata; \"Demi Allah, aku tidak ingin rumahku diikat dengan rumah Muhammad shallallahu 'alaihi wasallam.\" Ubay melanjutkan; \"Akupun merasa tersinggung dengan kekasaran jawabannya, sehingga aku mendatangi Nabiyullah shallallahu 'alaihi wasallam dan aku beritahukan kepada beliau.\" Ubay berkata; Setelah itu beliau memanggilnya dan laki-laki itu memberi jawaban yang sama. Dia mengungkapkan, bahwa dengan langkah kakinya, dirinya sangat berharap memperoleh pahala. Maka Nabi shallallahu 'alaihi wasallam bersabda; \"Bagimu apa yang engkau harapkan.\" Dan telah menceritakan kepada kami [Said bin 'Amru Al Asy'ats] dan [Muhammad bin Umar], keduanya dari [Ibnu Uyainah]. (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Said bin Azhar Al Wasithi] katanya; telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Ayahku], semuanya dari ['Ashim] dengan sanad seperti ini."},"1034":{"ar":"و حَدَّثَنَا حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَقَ حَدَّثَنَا أَبُو الزُّبَيْرِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ قَالَكَانَتْ دِيَارُنَا نَائِيَةً عَنْ الْمَسْجِدِ فَأَرَدْنَا أَنْ نَبِيعَ بُيُوتَنَا فَنَقْتَرِبَ مِنْ الْمَسْجِدِ فَنَهَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ لَكُمْ بِكُلِّ خَطْوَةٍ دَرَجَةً","id":"Dan telah menceritakan kepada kami [Hajjaj bin Asy Syair] telah menceritakan kepada kami [Rauh bin 'Ubadah] telah menceritakan kepada kami [Zakariya bin Ishaq] telah menceritakan kepada kami [Abu Zubair] katanya; aku mendengar [Jabir bin Abdullah] mengatakan; \"Rumah kami terpencil dari masjid, maka kami ingin menjual rumah kami dengan harapan untuk kami pindahkan dekat masjid, maka Rasulullah shallallahu 'alaihi wasallam melarang kami seraya berujar: \"Setiap langkah, kamu akan memperoleh pahala.\""},"1035":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ قَالَ حَدَّثَنِي الْجُرَيْرِيُّ عَنْ أَبِي نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَخَلَتْ الْبِقَاعُ حَوْلَ الْمَسْجِدِ فَأَرَادَ بَنُو سَلِمَةَ أَنْ يَنْتَقِلُوا إِلَى قُرْبِ الْمَسْجِدِ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُمْ إِنَّهُ بَلَغَنِي أَنَّكُمْ تُرِيدُونَ أَنْ تَنْتَقِلُوا قُرْبَ الْمَسْجِدِ قَالُوا نَعَمْ يَا رَسُولَ اللَّهِ قَدْ أَرَدْنَا ذَلِكَ فَقَالَ يَا بَنِي سَلِمَةَ دِيَارَكُمْ تُكْتَبْ آثَارُكُمْ دِيَارَكُمْ تُكْتَبْ آثَارُكُمْ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdusshamad bin Abdul Warits] katanya; aku mendengar [Ayahku] menceritakan, katanya; telah menceritakan kepadaku [Al Jurairi] dari [Abu Nadlrah] dari [Jabir bin Abdullah] katanya; \"Di sekitar masjid ada beberapa bidang tanah yang masih kosong, maka Bani Salamah berinisiatif untuk pindah dekat masjid. Ketika berita ini sampai ke telinga Rasulullah shallallahu 'alaihi wasallam, beliau bersabda; \"Rupanya telah sampai berita kepadaku bahwa kalian ingin pindah dekat masjid.\" Mereka menjawab; \"Benar wahai Rasulullah, kami memang ingin seperti itu.\" Beliau lalu bersabda: \"Wahai Bani Salamah, pertahankanlah rumah kalian, sebab langkah kalian akan dicatat, pertahankanlah rumah kalian, sebab langkah kalian akan dicatat.\""},"1036":{"ar":"حَدَّثَنَا عَاصِمُ بْنُ النَّضْرِ التَّيْمِيُّ حَدَّثَنَا مُعْتَمِرٌ قَالَ سَمِعْتُ كَهْمَسًا يُحَدِّثُ عَنْ أَبِي نَضْرَةَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَأَرَادَ بَنُو سَلِمَةَ أَنْ يَتَحَوَّلُوا إِلَى قُرْبِ الْمَسْجِدِ قَالَ وَالْبِقَاعُ خَالِيَةٌ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا بَنِي سَلِمَةَ دِيَارَكُمْ تُكْتَبْ آثَارُكُمْ فَقَالُوا مَا كَانَ يَسُرُّنَا أَنَّا كُنَّا تَحَوَّلْنَا","id":"Telah menceritakan kepada kami ['Ashim bin Nadar At Taimi] telah menceritakan kepada kami [Mu'tamir] katanya; Aku mendengar [Kahmas] menceritakan dari [Abu Nadlrah] dari [Jabir bin Abdullah] katanya; Bani Salamah berkeinginan pindah ke dekat masjid. Jabir melanjutkan; \"Ketika itu, ada beberapa lahan yang masih kosong. Ketika berita ini sampai ke Nabi shallallahu 'alaihi wasallam, beliau lalu bersabda; \"Wahai Bani Salamah, Pertahankanlah rumah kalian, sebab langkah kalian akan dicatat.\" Selanjutnya mereka berkata; \"Setelah itu kami tak ingin lagi pindah rumah.\""},"1037":{"ar":"حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا زَكَرِيَّاءُ بْنُ عَدِيٍّ أَخْبَرَنَا عُبَيْدُ اللَّهِ يَعْنِي ابْنَ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ أَبِي حَازِمٍ الْأَشْجَعِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَطَهَّرَ فِي بَيْتِهِ ثُمَّ مَشَى إِلَى بَيْتٍ مِنْ بُيُوتِ اللَّهِ لِيَقْضِيَ فَرِيضَةً مِنْ فَرَائِضِ اللَّهِ كَانَتْ خَطْوَتَاهُ إِحْدَاهُمَا تَحُطُّ خَطِيئَةً وَالْأُخْرَى تَرْفَعُ دَرَجَةً","id":"Telah menceritakan kepadaku [Ishaq bin Manshur] telah mengabarkan kepada kami [Zakariya bin 'Adi], telah mengabarkan kepada kami ['Ubaidullah yaitu Ibnu 'Amru] dari [Zaid bin Abu Unaisah] dari ['Adi bin Tsabit] dari [Abu Hazim Al Asyaj] dari [Abu Hurairah] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersuci di rumahnya, kemudian berjalan ke salah satu rumah Allah (masjid) untuk melaksanakan kewajiban yang Allah tetapkan, maka kedua langkahnya, yang satu menghapus kesalahan dan satunya lagi meninggikan derajat.\""},"1038":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح وَقَالَ قُتَيْبَةُ حَدَّثَنَا بَكْرٌ يَعْنِي ابْنَ مُضَرَ كِلَاهُمَا عَنْ ابْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَفِي حَدِيثِ بَكْرٍأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَرَأَيْتُمْ لَوْ أَنَّ نَهْرًا بِبَابِ أَحَدِكُمْ يَغْتَسِلُ مِنْهُ كُلَّ يَوْمٍ خَمْسَ مَرَّاتٍ هَلْ يَبْقَى مِنْ دَرَنِهِ شَيْءٌ قَالُوا لَا يَبْقَى مِنْ دَرَنِهِ شَيْءٌ قَالَ فَذَلِكَ مَثَلُ الصَّلَوَاتِ الْخَمْسِ يَمْحُو اللَّهُ بِه��نَّ الْخَطَايَا","id":"Dan telah menceritakan kepada kami [Qutaibah bin Said] telah menceritakan kepada kami [Laits] (dan diriwayatkan dari jalur lain) [Qutaibah] mengatakan; telah menceritakan kepada kami [Bakr yaitu bin Mudlar], keduanya dari [Ibnu Al Hadi] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda, sedangkan dalam hadis Bakr, ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bagaimana pendapat kalian, sekiranya ada sungai berada dekat pintu salah seorang diantara kalian yang ia pergunakan untuk mandi lima kali dalam sehari, mungkinkah kotorannya masih tersisa?\" Para sahabat menjawab; \"Kotorannya tidak akan tersisa.\" Beliau bersabda; \"Itulah perumpamaan kelima shalat, yang dengannya Allah akan menghapus kesalahan-kesalahan.\""},"1039":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ وَهُوَ ابْنُ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الصَّلَوَاتِ الْخَمْسِ كَمَثَلِ نَهْرٍ جَارٍ غَمْرٍ عَلَى بَابِ أَحَدِكُمْ يَغْتَسِلُ مِنْهُ كُلَّ يَوْمٍ خَمْسَ مَرَّاتٍقَالَ قَالَ الْحَسَنُ وَمَا يُبْقِي ذَلِكَ مِنْ الدَّرَنِ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib], keduanya berkata; telah menceritakan kepada kami [Abu Muawiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir bin Abdullah] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan kelima shalat bagaikan sungai yang mengalir deras di pintu salah seorang diantara kalian, yang ia pergunakan untuk mandi lima kali sehari semalam.\" Abu Sufyan berkata; Al Hasan mengatakan; \"Mungkinkah ada kotoran yang tersisa?\""},"1040":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ مُطَرِّفٍ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ غَدَا إِلَى الْمَسْجِدِ أَوْ رَاحَ أَعَدَّ اللَّهُ لَهُ فِي الْجَنَّةِ نُزُلًا كُلَّمَا غَدَا أَوْ رَاحَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Zuhair bin Harb] keduanya berkata; telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Mutharrif] dari [Zaid bin Aslam] dari ['Atha` bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa berangkat pagi atau sore hari ke masjid, maka Allah akan mempersiapkan persinggahan baginya di surga, Itu dilakukan-Nya setiapkali keberangkatan pagi atau sore hari.\""},"1041":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا سِمَاكٌ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَاللَّفْظُ لَهُ قَالَ أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ سِمَاكِ بْنِ حَرْبٍ قَالَقُلْتُ لِجَابِرِ بْنِ سَمُرَةَ أَكُنْتَ تُجَالِسُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ كَثِيرًا كَانَ لَا يَقُومُ مِنْ مُصَلَّاهُ الَّذِي يُصَلِّي فِيهِ الصُّبْحَ أَوْ الْغَدَاةَ حَتَّى تَطْلُعَ الشَّمْسُ فَإِذَا طَلَعَتْ الشَّمْسُ قَامَ وَكَانُوا يَتَحَدَّثُونَ فَيَأْخُذُونَ فِي أَمْرِ الْجَاهِلِيَّةِ فَيَضْحَكُونَ وَيَتَبَسَّمُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus], telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Simak] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Yahya bin Yahya] dan lafadz ada padanya, dia berkata; telah mengabarkan kepada kami [Abu Khaitsamah] dari [Simak bin Harb] katanya; aku berkata kepada [Jabir bin Samurah]; \"Mungkin anda pernah duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam? Dia menjawab; \"Ya, dan itu banyak kesempatan, Beliau shallallahu 'alaihi wasallam tidak pernah beranjak dari tempat shalatnya ketika subuh atau pagi hari hingga matahari terbit, jika matahari terbit, maka beliau beranjak pergi. Para sahabat seringkali bercerita-cerita dan berkisah-kisah semasa jahiliyahnya, lantas mereka pun tertawa, namun beliau hanya tersenyum.\""},"1042":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ قَالَ أَبُو بَكْرٍ وَحَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ عَنْ زَكَرِيَّاءَ كِلَاهُمَا عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا صَلَّى الْفَجْرَ جَلَسَ فِي مُصَلَّاهُ حَتَّى تَطْلُعَ الشَّمْسُ حَسَنًاو حَدَّثَنَا قُتَيْبَةُ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ قَالَ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ كِلَاهُمَا عَنْ سِمَاكٍ بِهَذَا الْإِسْنَادِ وَلَمْ يَقُولَا حَسَنًا","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan]. [Abu Bakr] mengatakan; telah menceritakan kepada kami [Muhammad bin Bisyr] dari [Zakariya], keduanya dari [Simak] dari [Jabir bin Samurah], bahwa apabila Nabi shallallahu 'alaihi wasallam shalat fajar (subuh), beliau akan tetap duduk di tempat shalatnya hingga matahari terbit secara sempurna.\" Dan telah menceritakan kepada kami [Qutaibah] dan [Abu Bakr bin Abu Syaibah], keduanya berkata; telah menceritakan kepada kami [Abu Al Ahwash] katanya; (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnul Al Mutsanna] dan [Ibnu Basyar], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] keduanya dari [Simak] dengan sanad ini, namun keduanya tidak mengatakan; \"secara sempurna.\""},"1043":{"ar":"و حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَإِسْحَقُ بْنُ مُوسَى الْأَنْصَارِيُّ قَالَا حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ حَدَّثَنِي ابْنُ أَبِي ذُبَابٍ فِي رِوَايَةِ هَارُونَ وَفِي حَدِيثِ الْأَنْصَارِيِّ حَدَّثَنِي الْحَارِثُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ مِهْرَانَ مَوْلَى أَبِي هُرَيْرَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَحَبُّ الْبِلَادِ إِلَى اللَّهِ مَسَاجِدُهَا وَأَبْغَضُ الْبِلَادِ إِلَى اللَّهِ أَسْوَاقُهَا","id":"Dan telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Ishaq bin musa Al Anshari] keduanya berkata; telah menceritakan kepada kami [Anas bin Iyadl] telah menceritakan kepadaku [Ibnu Abu Dzubab] dalam periwayatan Harun dan dalam hadis Al Anshari, telah menceritakan kepadaku [Al Harits] dari [Abdurrahman bin Mihran], mantan budak [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lokasi yang paling Allah cintai adalah masjid, dan Lokasi yang paling Allah benci adalah pasar.\""},"1044":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانُوا ثَلَاثَةً فَلْيَؤُمَّهُمْ أَحَدُهُمْ وَأَحَقُّهُمْ بِالْإِمَامَةِ أَقْرَؤُهُمْو حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ ح و حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ حَدَّثَنَا مُعَاذٌ وَهُوَ ابْنُ هِشَامٍ حَدَّثَنِي أَبِي كُلُّهُمْ عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا سَالِمُ بْنُ نُوحٍ ح و حَدَّثَنَا حَسَنُ بْنُ عِيسَى حَدَّثَنَا ابْنُ الْمُبَارَكِ جَمِيعًا عَنْ الْجُرَيْرِيِّ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Said] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Abu Nadlrah] dari [Abu Said Al Khudri] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika seseorang bertiga, hendaklah salah seorang diantara mereka menjadi imam, dan yang paling berhak menjadi imam adalah yang paling banyak hapalan Al Qurannya.\" Dan telah menceritakan kepada kami [Muhammad bin Basyar], telah menceritakan kepada kami [Yahya bin Said] telah menceritakan kepada kami [Syu'bah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Said bin Abu 'Arubah] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Abu Ghassan Al Misma'i], telah menceritakan kepada kami [Mu'adz yaitu Ibn Hisyam] telah menceritakan kepadaku [Ayahku] semuanya dari [Qatadah] dengan sanad seperti ini. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Salim bin Nuh] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Hasan bin Isa] telah menceritakan kepada kami [Ibnul Mubarak] semuanya dari [Al Jurairi] dari [Abu Nadlrah] dari [Abu Said] dari Nabi shallallahu 'alaihi wasallam."},"1045":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو سَعِيدٍ الْأَشَجُّ كِلَاهُمَا عَنْ أَبِي خَالِدٍ قَالَ أَبُو بَكْرٍ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ الْأَعْمَشِ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ عَنْ أَوْسِ بْنِ ضَمْعَجٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ الْقَوْمَ أَقْرَؤُهُمْ لِكِتَابِ اللَّهِ فَإِنْ كَانُوا فِي الْقِرَاءَةِ سَوَاءً فَأَعْلَمُهُمْ بِالسُّنَّةِ فَإِنْ كَانُوا فِي السُّنَّةِ سَوَاءً فَأَقْدَمُهُمْ هِجْرَةً فَإِنْ كَانُوا فِي الْهِجْرَةِ سَوَاءً فَأَقْدَمُهُمْ سِلْمًا وَلَا يَؤُمَّنَّ الرَّجُلُ الرَّجُلَ فِي سُلْطَانِهِ وَلَا يَقْعُدْ فِي بَيْتِهِ عَلَى تَكْرِمَتِهِ إِلَّا بِإِذْنِهِقَالَ الْأَشَجُّ فِي رِوَايَتِهِ مَكَانَ سِلْمًا سِنًّا حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا إِسْحَقُ أَخْبَرَنَا جَرِيرٌ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا الْأَشَجُّ حَدَّثَنَا ابْنُ فُضَيْلٍ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Said Al Asyaj], keduanya dari [Abu Khalid]. [Abu Bakr] mengatakan; telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Al A'masy], dari [Ismail bin Raja'] dari [Aus bin Dham'aj] dari [Abu Mas'ud Al Asnhari], katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Yang berhak menjadi imam atas suatu kaum adalah yang paling menguasai bacaan kitabullah (Alquran), jika dalam bacaan kapasitasnya sama, maka yang paling tahu terhadap sunnah, jika dalam as sunnah (hadis) kapasitasnya sama, maka yang paling dahulu hijrah, jika dalam hijrah sama, maka yang pertama-tama masuk Islam, dan jangan seseorang mengimami seseorang di daerah wewenangnya, dan jangan duduk di rumah seseorang di ruang tamunya, kecuali telah mendapatkan izin darinya.\" Kata Al Asyaj dalam periwayatannya dengan redaksi \"Maka yang menjadi pertimbangan kapasitas adalah keIslaman dan usia, \" Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Mu'awiyah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ishaq] telah mengabarkan kepada kami [Jarir] dan [Abu Mu'awiyah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Al-Asyajj] telah menceritakan kepada kami [Ibnu Fudlail] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan], semuanya dari [Al A'masy] dengan sanad seperti ini."},"1046":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ إِسْمَعِيلَ بْنِ رَجَاءٍ قَالَ سَمِعْتُ أَوْسَ بْنَ ضَمْعَجٍ يَقُولُ سَمِعْتُ أَبَا مَسْعُودٍ يَقُولُاقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَؤُمُّ الْقَوْمَ أَقْرَؤُهُمْ لِكِتَابِ اللَّهِ وَأَقْدَمُهُمْ قِرَاءَةً فَإِنْ كَانَتْ قِرَاءَتُهُمْ سَوَاءً فَلْيَؤُمَّهُمْ أَقْدَمُهُمْ هِجْرَةً فَإِنْ كَانُوا فِي الْهِجْرَةِ سَوَاءً فَلْيَؤُمَّهُمْ أَكْبَرُهُمْ سِنًّا وَلَا تَؤُمَّنَّ الرَّجُلَ فِي أَهْلِهِ وَلَا فِي سُلْطَانِهِ وَلَا تَجْلِسْ عَلَى تَكْرِمَتِهِ فِي بَيْتِهِ إِلَّا أَنْ يَأْذَنَ لَكَ أَوْ بِإِذْنِهِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] kata [Ibnul Mutsanna]; telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Ismail bin Raja'] katanya; aku mendengar [Aus bin Dham'aj] mengatakan; Aku mendengar [Abu Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Hendaknya yang berhak menjadi imam suatu kaum adalah yang paling banyak dan paling baik bacaan kitabullah (alquran), jika dalam bacaan sama, maka yang paling dahulu hijrah, jika mereka dalam hijrah sama, maka yang lebih dewasa, dan jangan sampai seseorang menjadi imam dalam keluarga orang lain dan jangan pula dalam wilayah kekuasaan (wewenang) nya dan jangan duduk di tempat duduk di rumah orang lain selain telah mendapat izin, atau seizinnya.\""},"1047":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ شَبَبَةٌ مُتَقَارِبُونَ فَأَقَمْنَا عِنْدَهُ عِشْرِينَ لَيْلَةً وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِيمًا رَقِيقًا فَظَنَّ أَنَّا قَدْ اشْتَقْنَا أَهْلَنَا فَسَأَلَنَا عَنْ مَنْ تَرَكْنَا مِنْ أَهْلِنَا فَأَخْبَرْنَاهُ فَقَالَ ارْجِعُوا إِلَى أَهْلِيكُمْ فَأَقِيمُوا فِيهِمْ وَعَلِّمُوهُمْ وَمُرُوهُمْ فَإِذَا حَضَرَتْ الصَّلَاةُ فَلْيُؤَذِّنْ لَكُمْ أَحَدُكُمْ ثُمَّ لِيَؤُمَّكُمْ أَكْبَرُكُمْو حَدَّثَنَا أَبُو الرَّبِيعِ الزَّهْرَانِيُّ وَخَلَفُ بْنُ هِشَامٍ قَالَا حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ بِهَذَا الْإِسْنَادِ و حَدَّثَنَاه ابْنُ أَبِي عُمَرَ حَدَّثَنَا عَبْدُ الْوَهَّابِ عَنْ أَيُّوبَ قَالَ قَالَ لِي أَبُو قِلَابَةَ حَدَّثَنَا مَالِكُ بْنُ الْحُوَيْرِثِ أَبُو سُلَيْمَانَ قَالَ أَتَيْتُ رَسُولَ اللَّهِ فِي نَاسٍ وَنَحْنُ شَبَبَةٌ مُتَقَارِبُونَ وَاقْتَصَّا جَمِيعًا الْحَدِيثَ بِنَحْوِ حَدِيثِ ابْنِ عُلَيَّةَ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ismail bin Ibrahim] telah menceritakan kepada kami [Ayyub] dari [Abu Qilabah] dari [Malik bin Huwairits] katanya; kami menemui Rasulullah shallallahu 'alaihi wasallam ketika kami masih remaja sebaya, lalu kami menginap di rumah beliau selama dua puluh malam. Rasulullah shallallahu 'alaihi wasallam adalah sosok yang berhati pengasih dan lembut. Beliau sadar bahwa kami telah merindukan keluarga kami, dan beliau menanyakan kepada kami mengenai orang yang telah kami tinggal dari keluarga-keluarga kami, dan kami pun memberitahukan kepada beliau. Selanjutnya beliau bersabda: \"Sekarang kembalilah kepada keluarga kalian, dan diamlah bersama mereka, ajarilah mereka dan suruhlah mereka. Jika waktu shalat tiba, hendaknya salah seorang diantara kalian mengumandangkan adzan dan yang paling dewasa menjadi imam.\" Dan telah menceritakan kepada kami [Abu Rabi' Az Zahrani] dan [Khalaf bin Hisyam], keduanya berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dengan sanad ini. Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Abdul Wahhab] dari [Ayyub] katanya; [Abu Qilabah] mengatakan kepadaku; telah menceritakan kepada kami [Malik bin Huwairits Abu Sulaiman], katanya; Aku pernah menemui Rasulullah shallallahu 'alaihi wasallam, ketika itu beliau berada di tengah-tengah orang dan kami waktu itu masih remaja sebaya, lalu keduanya mengisahkan hadis seperti hadis Ibnu 'Ulayyah."},"1048":{"ar":"و حَدَّثَنِي إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا عَبْدُ الْوَهَّابِ الثَّقَفِيُّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ مَالِكِ بْنِ الْحُوَيْرِثِ قَالَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَصَاحِبٌ لِي فَلَمَّا أَرَدْنَا الْإِقْفَالَ مِنْ عِنْدِهِ قَالَ لَنَا إِذَا حَضَرَتْ الصَّلَاةُ فَأَذِّنَا ثُمَّ أَقِيمَا وَلْيَؤُمَّكُمَا أَكْبَرُكُمَاو حَدَّثَنَاه أَبُو سَعِيدٍ الْأَشَجُّ حَدَّثَنَا حَفْصٌ يَعْنِي ابْنَ غِيَاثٍ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ بِهَذَا الْإِسْنَادِ وَزَادَ قَالَ الْحَذَّاءُ وَكَانَا مُتَقَارِبَيْنِ فِي الْقِرَاءَةِ","id":"Dan telah menceritakan kepadaku [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [Abdul Wahhab Ats Tsaqafi] dari [Khalid Al Khadza`] dari [Abu Qilabah] dari [Malik bin Huwairits] katanya; aku menemui Nabi shallallahu 'alaihi wasallam bersama seorang kawanku. Ketika kami hendak kembali pulang, beliau berpesan: \"Jika waktu shalat telah tiba, maka kumandangkanlah adzan, dan dirikanlah shalat, hendaknya yang berhak menjadi iamam adalah yang paling dewasa diantara kalian.\" Dan telah menceritakan kepada kami [Abu Said Al Asyajj] telah menceritakan kepada kami [Hafs yaitu Ibnu Ghiyats] telah menceritakan kepada kami [Khalid Al Khadza`] dengan sanad ini, dia sedikit menambahkan, Al Khadza` mengatakan; keduanya (yaitu Malik bin Huwairits dan kawannya) dalam bacaan hampir sama (selevel)."},"1049":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ أَنَّهُمَا سَمِعَا أَبَا هُرَيْرَةَ يَقُولُاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ يَفْرُغُ مِنْ صَلَاةِ الْفَجْرِ مِنْ الْقِرَاءَةِ وَيُكَبِّرُ وَيَرْفَعُ رَأْسَهُ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ يَقُولُ وَهُوَ قَائِمٌ اللَّهُمَّ أَنْجِ الْوَلِيدَ بْنَ الْوَلِيدِ وَسَلَمَةَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ وَالْمُسْتَضْعَفِينَ مِنْ الْمُؤْمِنِينَ اللَّهُمَّ اشْدُدْ وَطْأَتَكَ عَلَى مُضَرَ وَاجْعَلْهَا عَلَيْهِمْ كَسِنِي يُوسُفَ اللَّهُمَّ الْعَنْ لِحْيَانَ وَرِعْلًا وَذَكْوَانَ وَعُصَيَّةَ عَصَتْ اللَّهَ وَرَسُولَهُ ثُمَّ بَلَغَنَا أَنَّهُ تَرَكَ ذَلِكَ لَمَّا أُنْزِلَ{ لَيْسَ لَكَ مِنْ الْأَمْرِ شَيْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَالِمُونَ }و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ قَالَا حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ إِلَى قَوْلِهِ وَاجْعَلْهَا عَلَيْهِمْ كَسِنِي يُوسُفَ وَلَمْ يَذْكُرْ مَا بَعْدَهُ","id":"Telah menceritakan kepadaku [Abu At Thahir] dan [Harmalah bin Yahya], keduanya berkata; telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] katanya; telah mengabarkan kepadaku [Said bin Musayyab] dan [Abu Salamah bin Abdurrahman bin 'Auf], keduanya mendengar [Abu Hurairah] berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam shalat fajar (subuh), yaitu setelah membaca, bertakbir dan mengangkat kepalanya, beliau membaca \"Sami'allahu liman hamidah. Rabbanaa walakal hamdu.\" Kemudian beliau membaca lagi dan beliau masih berdiri, yaitu; ALLAAHUMMA ANJI ALWALID BIN WALID WA SALAMAH BIN HISYAM, WA AYYASY BIN ABU RABIAH, WAL MUSTADH'AFIINA MINAL MUL'MINIINA, ALLAAHUMMASY DUD WATH'ATHAKA 'ALAA MUDHARR WAJ'ALHAA 'ALIHIM KASINII YUUSUFA, ALLAAHUMMAL'AN LIHYAANA WARI'LAN WADZAKWAAANA WA'USHAYYAH ASHATALLAAHA WARASUULAHU (Ya Allah, selamatkanlah Walid bin walid, Salamah bin Hisyam, Ayyasy bin Abu Rabiah dan orang-orang mukmin yang lemah, Ya Allah, perkuatlah hukumanmu kepada Mudharr dan jadikanlah untuk mereka masa-masa paceklik sebagaimana paceklik Yusuf, Ya Allah, laknatilah Lihyan, Ri'l, dan Dzakwan, mereka yang telah membangkang Allah dan Rasul-Nya.\" Kemudian sampai berita kepada kami, bahwa beliau meninggakan doa (qunut) tersebut, tepatnya ketika turun ayat \"Tidak ada urusanmu entah Allah mengampuni mereka atau menyiksa mereka, sesungguhnya mereka orang-orang yang zhalim (QS. Ali Imran 128), Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan ['Amru An Naqid], keduanya berkata; telah menceritakan kepada kami [Ibn 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam hingga sabdanya: \"Ya Allah, jadikanlah untuk mereka tahun-tahun paceklik sebagaimana tahun-tahun paceklik Yusuf.\" Dan ia tidak menyebutkan kalimat sesudahnya."},"1050":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاوَاللَّهِ لَأُقَرِّبَنَّ بِكُمْ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ أَبُو هُرَيْرَةَ يَقْنُتُ فِي الظُّهْرِ وَالْعِشَاءِ الْآخِرَةِ وَصَلَاةِ الصُّبْحِ وَيَدْعُو لِلْمُؤْمِنِينَ وَيَلْعَنُ الْكُفَّارَ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Yahya bin Abu Katsir], katanya; telah menceritakan kepada kami [Abu Salamah bin Abdurrahman], ia mendengar [Abu Hurairah] mengatakan; \"Demi Allah, akan aku akan berusaha mendekatkan kalian dengan Shalat Rasulullah shallallahu 'alaihi wasallam.\" Selanjutnya Abu Hurairah melakukan qunut dalam shalat zhuhur, isya`, dan shalat subuh, mendoakan kebaikan untuk orang-orang mukmin dan melaknat orang-orang kafir.\""},"1051":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الَّذِينَ قَتَلُوا أَصْحَابَ بِئْرِ مَعُونَةَ ثَلَاثِينَ صَبَاحًا يَدْعُو عَلَى رِعْلٍ وَذَكْوَانَ وَلِحْيَانَ وَعُصَيَّةَ عَصَتْ اللَّهَ وَرَسُولَهُ قَالَ أَنَسٌ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِي الَّذِينَ قُتِلُوا بِبِئْرِ مَعُونَةَ قُرْآنًا قَرَأْنَاهُ حَتَّى نُسِخَ بَعْدُ أَنْ بَلِّغُوا قَوْمَنَا أَنْ قَدْ لَقِينَا رَبَّنَا فَرَضِيَ عَنَّا وَرَضِينَا عَنْهُ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya], katanya; aku membaca di hadapan [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik], katanya; Rasulullah shallallahu 'alaihi wasallam mendoakan kecelakaan untuk orang-orang yang telah membantai para sahabat di Bi'r Ma'unah selama tiga puluh hari setiap pagi, beliau mend'oakan kecelakaan terhadap kabilah Ri'il, Dzakwan, dan Lihyan serta Ushayyah yang telah membangkang Allah dan Rasul-Nya.\" Anas melanjutkan; \"Allah Azza wa Jalla telah menurunkan ayat Al Qur'an untuk para sahabat yang terbantai di Bi'r Ma'unah yang biasa kami baca, hingga ayat tersebut dimansukh di kemudian hari. Ayat tersebut bunyinya AN BALLIGHUU QAUMANAA AN QAD LAQIINAA RABBANAA FARADLIYA ANNAA WARADLIINAA 'ANHU, (Sampaikanlah kepada kaum kami bahwa kami telah menjumpai Tuhan kami, dan Dia ridla terhadap kami, dan kami pun ridla terhadap-Nya).\""},"1052":{"ar":"و حَدَّثَنِي عَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ قَالَ قُلْتُ لِأَنَسٍهَلْ قَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الصُّبْحِ قَالَ نَعَمْ بَعْدَ الرُّكُوعِ يَسِيرًا","id":"Dan telah menceritakan kepadaku ['Amru An Naqid] dan [Zuhair bin Harb], keduanya berkata; telah menceritakan kepada kami [Ismail] dari [Ayyub] dari [Muhammad] katanya; aku bertanya kepada [Anas]; \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah qubut dalam subuhnya?\" Anas menjawab; \"Benar, sebentar setelah ruku'.\""},"1053":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا أَنَسُ بْنُ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا بَعْدَ الرُّكُوعِ فِي صَلَاةِ الْفَجْرِ يَدْعُو عَلَى بَنِي عُصَيَّةَ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz bin Asad] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Anas bin Sirin] dari [Anas bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam pernah melakukan doa qunut selama sebulan setelah ruku' pada shalat fajar (subuh), beliau mendo'akan kebinasaan untuk Bani 'Ushayyah.\""},"1054":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ عَاصِمٍ عَنْ أَنَسٍ قَالَسَأَلْ��ُهُ عَنْ الْقُنُوتِ قَبْلَ الرُّكُوعِ أَوْ بَعْدَ الرُّكُوعِ فَقَالَ قَبْلَ الرُّكُوعِ قَالَ قُلْتُ فَإِنَّ نَاسًا يَزْعُمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ بَعْدَ الرُّكُوعِ فَقَالَ إِنَّمَا قَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهْرًا يَدْعُو عَلَى أُنَاسٍ قَتَلُوا أُنَاسًا مِنْ أَصْحَابِهِ يُقَالُ لَهُمْ الْقُرَّاءُ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib], keduanya berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari ['Ashim] dari [Anas], kata 'Ashim; Aku pernah bertanya kepada Anas tentang doa qunut, apakah sebelum ataukah setelah ruku'?, Anas menjawab; \"Sebelum ruku'.\" Ashim mengatakan; Aku berkata; \"Namun orang-orang beranggapan bahwa Rasulullah shallallahu 'alaihi wasallam melakukan qunut setelah ruku'.\" Anas menjawab; \"Hanyasanya Rasulullah shallallahu 'alaihi wasallam melakukan qunut selama sebulan, beliau mendo'akan kebinasaan untuk orang-orang yang membantai sahabatnya yang dijuluki Al Qurra' (Para Ahlul Qur'an).\""},"1055":{"ar":"حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُامَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدَ عَلَى سَرِيَّةٍ مَا وَجَدَ عَلَى السَّبْعِينَ الَّذِينَ أُصِيبُوا يَوْمَ بِئْرِ مَعُونَةَ كَانُوا يُدْعَوْنَ الْقُرَّاءَ فَمَكَثَ شَهْرًا يَدْعُو عَلَى قَتَلَتِهِمْو حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا حَفْصٌ وَابْنُ فُضَيْلٍ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا مَرْوَانُ كُلُّهُمْ عَنْ عَاصِمٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ بِهَذَا الْحَدِيثِ يَزِيدُ بَعْضُهُمْ عَلَى بَعْضٍ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari ['Ashim] katanya; aku mendengar [Anas] mengtaakan; \"Belum pernah aku melihat Rasulullah shallallahu 'alaihi wasallam sedemikian murkanya karena kehilangan pasukannya, sebagaimana kemurkaan beliau ketika kehilangan tujuh puluh sahabatnya yang terbantai pada peristiwa Bi'ru Ma'unah, ketujuh puluh sahabat tersebut digelari Qurra` (para Ahlul Qur'an), oleh karena itu selama sebulan penuh beliau mendoakan kecelakaan kepada kaum yang telah membunuhnya.\" Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Hafs] dan [Ibnu Fudlail] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibn Abu Umar] telah menceritakan kepada kami [Marwan] semuanya dari ['Ashim] dari [Anas] dari Nabi shallallahu 'alaihi wasallam dengan hadis seperti ini, dan satu sama lain saling menambah.\""},"1056":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ حَدَّثَنَا هِشَامٌ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَنَتَ شَهْرًا يَدْعُو عَلَى أَحْيَاءٍ مِنْ أَحْيَاءِ الْعَرَبِ ثُمَّ تَرَكَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdurrahman] telah menceritakan kepada kami [Hisyam] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam melakukan doa \"qunut\" selama sebulan, beliau mendo'akan kebinasaan terhadap sejumlah penduduk dusun arab, setelah itu beliau meninggalkannya.\""},"1057":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ قَالَ سَمِعْتُ ابْنَ أَبِي لَيْلَى قَالَ حَدَّثَنَا الْبَرَاءُ بْنُ عَازِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْنُتُ فِي الصُّبْحِ وَالْمَغْرِبِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah], katanya; \"Aku mendengar [Ibnu Abu Laila] berkata; telah menceritakan kepada kami [Al Barra` bin 'Azib], bahwa Rasulullah shallallahu 'alaihi wasallam pernah melakukan qunut ketika subuh dan maghrib.\""},"1058":{"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ الْبَرَاءِ قَالَقَنَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْفَجْرِ وَالْمَغْرِبِ","id":"Dan Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Sufyan] dari ['Amru bin Murrah] dari [Abdurrahman bin Abu Laila] dari [Al Barra'] katanya; Rasulullah shallallahu 'alaihi wasallam pernah melakukan qunut ketika (shalat) subuh (fajar) dan maghrib.\""},"1059":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قَفَلَ مِنْ غَزْوَةِ خَيْبَرَ سَارَ لَيْلَهُ حَتَّى إِذَا أَدْرَكَهُ الْكَرَى عَرَّسَ وَقَالَ لِبِلَالٍ اكْلَأْ لَنَا اللَّيْلَ فَصَلَّى بِلَالٌ مَا قُدِّرَ لَهُ وَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ فَلَمَّا تَقَارَبَ الْفَجْرُ اسْتَنَدَ بِلَالٌ إِلَى رَاحِلَتِهِ مُوَاجِهَ الْفَجْرِ فَغَلَبَتْ بِلَالًا عَيْنَاهُ وَهُوَ مُسْتَنِدٌ إِلَى رَاحِلَتِهِ فَلَمْ يَسْتَيْقِظْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَا بِلَالٌ وَلَا أَحَدٌ مِنْ أَصْحَابِهِ حَتَّى ضَرَبَتْهُمْ الشَّمْسُ فَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلَهُمْ اسْتِيقَاظًا فَفَزِعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَيْ بِلَالُ فَقَالَ بِلَالٌ أَخَذَ بِنَفْسِي الَّذِي أَخَذَ بِأَبِي أَنْتَ وَأُمِّي يَا رَسُولَ اللَّهِ بِنَفْسِكَ قَالَ اقْتَادُوا فَاقْتَادُوا رَوَاحِلَهُمْ شَيْئًا ثُمَّ تَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَمَرَ بِلَالًا فَأَقَامَ الصَّلَاةَ فَصَلَّى بِهِمْ الصُّبْحَ فَلَمَّا قَضَى الصَّلَاةَ قَالَ مَنْ نَسِيَ الصَّلَاةَ فَلْيُصَلِّهَا إِذَا ذَكَرَهَا فَإِنَّ اللَّهَ قَالَ{ أَقِمْ الصَّلَاةَ لِذِكْرِي }قَالَ يُونُسُ وَكَانَ ابْنُ شِهَابٍ يَقْرَؤُهَا لِلذِّكْرَى","id":"Telah menceritakan kepadaku [Harmalah bin Yahya At Tujibi] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Sa'id bin Musayyab] dari [Abu Hurairah], bahwa ketika Rasulullah shallallahu 'alaihi wasallam kembali dari perang Khaibar, beliau terus berjalan di malam hari, ketika beliau diserang kantuk, maka beliau singgah. Beliau bersabda kepada Bilal \"Hendaknya kamu yang mengawasi tidur kami malam ini!.\" Bilal pun shalat sekemampuan yang ditakdirkan, sementara Rasulullah shallallahu 'alaihi wasallam tidur. Begitu juga dengan para sahabatnya. Ketika mendekati fajar, Bilal bersandar kepada unta tunggangannya, rupanya kedua mata Bilal terasa berat hingga ketiduran, dengan posisi bersandar kepada untanya. Di pagi harinya Rasulullah shallallahu 'alaihi wasallam belum juga bangun, demikian juga Bilal, dan tak satupun dari sahabatnya yang bangun hingga mereka terbangun oleh sinar matahari yang menyengat. Rasulullah shallallahu 'alaihi wasallam akhirnya yang pertama-tama bangun. Rasulullah Shallallahu 'alahi wasallam merasa kaget dan menyeru: \"Hei Bilal!\" Bilal Menjawab; \"Wahai Rasulullah, tadi nyawaku telah dipegang Dzat yang memegang nyawamu, demi ayah dan ibuku sebagai tebusanmu! Beliau lalu bersabda: \"Mari tuntunlah hewan tunggangan kalian.\" Para sahabat pun menuntun hewan tunggangannya, sesaat kemudian Rasulullah shallallahu 'alaihi wasallam berwudhu\". Beliau lalu memerintahkan Bilal supaya mengumandangkan iqamat shalat. Setelah itu Beliau mengimami shalat subuh bersama mereka. Selesai shalat, beliau bersabda: \"Siapa yang terlupa shalat, lakukanlah ketika ingat, sebab Allah ta'ala berfirman \"Dirikanlah shalat untuk mengingat-Ku.\" QS. Toha 14. Yunus berkata; sedangkan Ibnu Syihab membacanya dengan lidzdzikraa. "},"1060":{"ar":"و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ الْمُغِيرَةِ حَدَّثَنَا ثَابِتٌ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ قَالَخَطَبَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّكُمْ تَسِيرُونَ عَشِيَّتَكُمْ وَلَيْلَتَكُمْ وَتَأْتُونَ الْمَاءَ إِنْ شَاءَ اللَّهُ غَدًا فَانْطَلَقَ النَّاسُ لَا يَلْوِي أَحَدٌ عَلَى أَحَدٍ قَالَ أَبُو قَتَادَةَ فَبَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسِيرُ حَتَّى ابْهَارَّ اللَّيْلُ وَأَنَا إِلَى جَنْبِهِ قَالَ فَنَعَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَمَالَ عَنْ رَاحِلَتِهِ فَأَتَيْتُهُ فَدَعَمْتُهُ مِنْ غَيْرِ أَنْ أُوقِظَهُ حَتَّى اعْتَدَلَ عَلَى رَاحِلَتِهِ قَالَ ثُمَّ سَارَ حَتَّى تَهَوَّرَ اللَّيْلُ مَالَ عَنْ رَاحِلَتِهِ قَالَ فَدَعَمْتُهُ مِنْ غَيْرِ أَنْ أُوقِظَهُ حَتَّى اعْتَدَلَ عَلَى رَاحِلَتِهِ قَالَ ثُمَّ سَارَ حَتَّى إِذَا كَانَ مِنْ آخِرِ السَّحَرِ مَالَ مَيْلَةً هِيَ أَشَدُّ مِنْ الْمَيْلَتَيْنِ الْأُولَيَيْنِ حَتَّى كَادَ يَنْجَفِلُ فَأَتَيْتُهُ فَدَعَمْتُهُ فَرَفَعَ رَأْسَهُ فَقَالَ مَنْ هَذَا قُلْتُ أَبُو قَتَادَةَ قَالَ مَتَى كَانَ هَذَا مَسِيرَكَ مِنِّي قُلْتُ مَا زَالَ هَذَا مَسِيرِي مُنْذُ اللَّيْلَةِ قَالَ حَفِظَكَ اللَّهُ بِمَا حَفِظْتَ بِهِ نَبِيَّهُ ثُمَّ قَالَ هَلْ تَرَانَا نَخْفَى عَلَى النَّاسِ ثُمَّ قَالَ هَلْ تَرَى مِنْ أَ��َدٍ قُلْتُ هَذَا رَاكِبٌ ثُمَّ قُلْتُ هَذَا رَاكِبٌ آخَرُ حَتَّى اجْتَمَعْنَا فَكُنَّا سَبْعَةَ رَكْبٍ قَالَ فَمَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الطَّرِيقِ فَوَضَعَ رَأْسَهُ ثُمَّ قَالَ احْفَظُوا عَلَيْنَا صَلَاتَنَا فَكَانَ أَوَّلَ مَنْ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالشَّمْسُ فِي ظَهْرِهِ قَالَ فَقُمْنَا فَزِعِينَ ثُمَّ قَالَ ارْكَبُوا فَرَكِبْنَا فَسِرْنَا حَتَّى إِذَا ارْتَفَعَتْ الشَّمْسُ نَزَلَ ثُمَّ دَعَا بِمِيضَأَةٍ كَانَتْ مَعِي فِيهَا شَيْءٌ مَنْ مَاءٍ قَالَ فَتَوَضَّأَ مِنْهَا وُضُوءًا دُونَ وُضُوءٍ قَالَ وَبَقِيَ فِيهَا شَيْءٌ مِنْ مَاءٍ ثُمَّ قَالَ لِأَبِي قَتَادَةَ احْفَظْ عَلَيْنَا مِيضَأَتَكَ فَسَيَكُونُ لَهَا نَبَأٌ ثُمَّ أَذَّنَ بِلَالٌ بِالصَّلَاةِ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ ثُمَّ صَلَّى الْغَدَاةَ فَصَنَعَ كَمَا كَانَ يَصْنَعُ كُلَّ يَوْمٍ قَالَ وَرَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكِبْنَا مَعَهُ قَالَ فَجَعَلَ بَعْضُنَا يَهْمِسُ إِلَى بَعْضٍ مَا كَفَّارَةُ مَا صَنَعْنَا بِتَفْرِيطِنَا فِي صَلَاتِنَا ثُمَّ قَالَ أَمَا لَكُمْ فِيَّ أُسْوَةٌ ثُمَّ قَالَ أَمَا إِنَّهُ لَيْسَ فِي النَّوْمِ تَفْرِيطٌ إِنَّمَا التَّفْرِيطُ عَلَى مَنْ لَمْ يُصَلِّ الصَّلَاةَ حَتَّى يَجِيءَ وَقْتُ الصَّلَاةِ الْأُخْرَى فَمَنْ فَعَلَ ذَلِكَ فَلْيُصَلِّهَا حِينَ يَنْتَبِهُ لَهَا فَإِذَا كَانَ الْغَدُ فَلْيُصَلِّهَا عِنْدَ وَقْتِهَا ثُمَّ قَالَ مَا تَرَوْنَ النَّاسَ صَنَعُوا قَالَ ثُمَّ قَالَ أَصْبَحَ النَّاسُ فَقَدُوا نَبِيَّهُمْ فَقَالَ أَبُو بَكْرٍ وَعُمَرُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَكُمْ لَمْ يَكُنْ لِيُخَلِّفَكُمْ وَقَالَ النَّاسُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَيْدِيكُمْ فَإِنْ يُطِيعُوا أَبَا بَكْرٍ وَعُمَرَ يَرْشُدُوا قَالَ فَانْتَهَيْنَا إِلَى النَّاسِ حِينَ امْتَدَّ النَّهَارُ وَحَمِيَ كُلُّ شَيْءٍ وَهُمْ يَقُولُونَ يَا رَسُولَ اللَّهِ هَلَكْنَا عَطِشْنَا فَقَالَ لَا هُلْكَ عَلَيْكُمْ ثُمَّ قَالَ أَطْلِقُوا لِي غُمَرِي قَالَ وَدَعَا بِالْمِيضَأَةِ فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُبُّ وَأَبُو قَتَادَةَ يَسْقِيهِمْ فَلَمْ يَعْدُ أَنْ رَأَى النَّاسُ مَاءً فِي الْمِيضَأَةِ تَكَابُّوا عَلَيْهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْسِنُوا الْمَلَأَ كُلُّكُمْ سَيَرْوَى قَالَ فَفَعَلُوا فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصُبُّ وَأَسْقِيهِمْ حَتَّى مَا بَقِيَ غَيْرِي وَغَيْرُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثُمَّ صَبَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي اشْرَبْ فَقُلْتُ لَا أَشْرَبُ حَتَّى تَشْرَبَ يَا رَسُولَ اللَّهِ قَالَ إِنَّ سَاقِيَ الْقَوْمِ آخِرُهُمْ شُرْبًا قَالَ فَشَرِبْتُ وَشَرِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَتَى النَّاسُ الْمَاءَ جَامِّينَ رِوَاءً قَالَ فَقَالَ عَبْدُ اللَّهِ بْنُ رَبَاحٍ إِنِّي لَأُحَدِّثُ هَذَا الْحَدِيثَ فِي مَسْجِدِ الْجَامِعِ إِذْ قَالَ عِمْرَانُ بْنُ حُصَيْنٍ انْظُرْ أَيُّهَا الْفَتَى كَيْفَ تُحَدِّثُ فَإِنِّي أَحَدُ الرَّكْبِ تِلْكَ اللَّيْلَةَ قَالَ قُلْتُ فَأَنْتَ أَعْلَمُ بِالْحَدِيثِ فَقَالَ مِمَّنْ أَنْتَ قُلْتُ مِنْ الْأَنْصَارِ قَالَ حَدِّثْ فَأَنْتُمْ أَعْلَمُ بِحَدِيثِكُمْ قَالَ فَحَدَّثْتُ الْقَوْمَ فَقَالَ عِمْرَانُ لَقَدْ شَهِدْتُ تِلْكَ اللَّيْلَةَ وَمَا شَعَرْتُ أَنَّ أَحَدًا حَفِظَهُ كَمَا حَفِظْتُهُ","id":"Dan telah menceritakan kepada kami [Syaiban bin Farukh] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Al Mughirah], telah menceritakan kepada kami [Tsabit] dari [Abdullah bin Rabah] dari [Abu Qatadah] katanya; Rasulullah shallallahu 'alaihi wasallam pernah menyampaikan pidato kepada kami, sabdanya; \"Ingatlah, sesungguhnya kalian sekarang berangkat mengarungi waktu sore dan malam kalian, dan kalian akan sampai mata air esok hari, insya Allah.\" Lalu para sahabat berangkat dan tak satupun para sahabat yang bersandarkan (berboncengan) dengan temannya. Abu Qatadah berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam berangkat hingga pertengahan malam, -ketika itu aku berada disampingnya- ternyata Rasulullah shallallahu 'alaihi wasallam mulai terserang kantuk sehingga badan beliau kelihatan oleng dari hewan kendaraannya. Maka aku mendatangi beliau, aku luruskan badannya dan kutopang dari bawahnya dengan harapan tidak membangunkannya sampai beliau duduk diatas hewan kendaraannya secara normal.\" Abu Qatadah melanjutkan; Setelah itu beliau berangkat, ketika sebagian besar malam telah berlalu, badan beliau kembali oleng dari kendaraannya, dan aku kembali meluruskan badan beliau dengan menopang dari bawah, supaya tidak membangunkannya. Beliau terus menyusuri perjalanan, ketika waktu sahur (waktu sebelum terbitnya fajar -pent) tiba, badan beliau oleng jauh lebih dahsyat daripada oleng yang pertama dan kedua, hingga beliau nyaris terjatuh. Lalu aku mendatangi beliau, kubenarkan tidurnya dan kutopang dari bawahnya. Sesaat kemudian beliau angkat kepalanya dan bertanya: \"Siapakah ini?\" Aku menjawab; \"Aku Abu Qatadah\" beliau bertanya: \"Semenjak kapan engkau mengawasiku dalam perjalanan?\" Aku menjawab; \"Semenjak tadi malam, \" Beliau bersabda: \"Semoga Allah selalu menjagamu karena engkau menjaga nabi-Nya, \" Kemudian beliau bertanya: \"Apakah anda mengira kita tidak terlihat oleh orang lain?\" kemudian beliau bertanya lagi: \"Apakah engkau melihat yang lain?\" Aku menjawab; \"Ini ada seorang pengendara, \" aku berkata lagi; \"Ini datang lagi seorang pengendara, \" hingga kami berkumpul dan berjumlah tujuh pengendara.\" Abu Qatadah berkata; Rupanya Rasulullah shallallahu 'alaihi wasallam mencoba untuk menikung dari jalan sambil menyandarkan kepalanya, kemudian beliau berpesan: \"Tolong jaga shalat kami!\" Dan yang pertama kali bangun adalah Rasulullah shallallahu 'alaihi wasallam, ketika sinar matahari nampak nyata di punggungnya. Abu Qatadah mengatakan; kami lalu bangun sambil terkejut. Beliau bersabda: \"Naiklah kalian semua.\" Kami lalu meneruskan perjalanan sambil menaiki kendaraan kami, ketika matahari agak meninggi, beliau turun dan meminta bejana berisi sedikit air yang aku bawa untuk wudlu', Rasulullah shallallahu 'alaihi wasallam pun berwudlu' dengan wudlu' tidak seperti biasanya, namun airnya masih tersisa sedikit. Setelah itu beliau berpesan kepada Abu Qatadah: \"Jagalah bejana wudlu'mu, sebab suatu saat bejanamu akan menjadi legenda!\" Bilal lantas mengumandangkan adzan untuk shalat. Setelah itu Rasulullah shallallahu 'alaihi wasallam shalat dua rakaat, dan diteruskan dengan shalat subuh, beliau melakukan hal itu sebagaimana beliau melakukan di setiap harinya.\" Abu Qatadah melanjutkan; Rasulullah shallallahu 'alaihi wasallam lantas berkendara dan kami pun berkendara bersamanya, ketika kami satu sama lain saling berbisik; \"Apa kaffarat kami karena telah mengakhirkan shalat dari waktunya?\" Beliau kemudian bersabda: \"Bukanlah aku teladan bagi kalian?\" kemudian beliau bersabda: \"Tidaklah dikatakan mengakhirkan (meremehkan) shalat karena ketiduran, hanyasanya meremehkan (shalat) itu bagi orang yang tidak menunaikan shalat hingga tiba waktu shalat yang lain. Oleh kerena itu, siapa yang melakukan hal ini, hendaknya ia shalat ketika sadar. Dan hendaknya esok hari sebisa mungkin ia melakukan tepat pada waktunya.\" Kemudian Abdullah bertanya: \"Menurutmu, apa yang di lakukan oleh para sahabat?\" Abu Qatadah menjawab; \"Setelah itu para sahabat kehilangan nabi mereka.\" Abu Bakr dan Umar lalu berseru; 'Rasulullah shallallahu 'alaihi wasallam berada di belakang kalian, dan beliau tidak meninggalkan kalian!\" Justeru sebagian sahabat mengatakan; \"Tidak, Rasulullah shallallahu 'alaihi wasallam ada di depan kalian.\" Sekiranya mereka menta'ati Abu Bakr dan Umar, mereka tidak akan tersesat. Abu Qatadah melanjutkan; \"Maka kami dapat menyusul semua sahabat ketika terik matahari sangat panas dan segala-galanya menjadi panas, lalu mereka berkeluh; \"Wahai Rasulullah, celaka kita kehausan.\" Beliau menjawab: \"Tidak, kalian tidak akan celaka!\" Beliau lalu bersabda: \"Berikan wadah kecilku padaku!\" kemudian beliau meminta bejana untuk berwudlu'. Rasulullah shallallahu 'alaihi wasallam lalu mengucurkan air, sementara Abu Qatadah memberi minum para sahabat. Ketika para sahabat melihat air dikucurkan dari bejana, maka mereka berdesak-desakan, Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Berbuat baiklah, sebab kalian semua akan minum hingga puas.\" Mereka akhirnya melakukan perintah beliau, sementara Rasulullah shallallahu 'alaihi wasallam terus mengucurkan air sedang Abu Qatadah membagi minuman kepada para sahabat hingga tidak tersisa selain aku dan Rasulullah shallallahu 'alaihi wasallam. Kemudian Rasulullah shallallahu 'alaihi wasallam mengucurkan sambil berujar kepadaku: \"Silahkan kamu meminumnya.\" Aku menjawab; \"Saya tidak akan minum hingga engkau minum wahai Rasulullah!.\" Beliau bersabda: \"Yang memberi minum seharusnya yang terakhir kali minum.\" Abu Qatadah berkata; \"Maka aku pun minum dan Rasulullah shallallahu 'alaihi wasallam juga minum.\" Abu Qatadah melanjutkan; \"Kemudian para sahabat mendatangi air dan mereka merasa puas karena kenyang minum.\" Kata Abdullah bin Rabah; \"Sungguh akan aku sampaikan hadits ini di masjid agung. Tiba-tiba [Imran bin Hushain] berkata; \"Telitilah terlebih dahulu wahai anak muda, bagaimana engkau akan menyampaikannya, sebab aku adalah salah satu dari pengendara di malam itu.\" Abdullah bin Rabah berkata; \"Aku bertanya; \"Kalau begitu, anda lebih tahu tentang hadits ini.\" Imran bertanya; \"Dari manakah asalmu?\" Aku menjawab; \"Dari Anshar.\" Imran berkata; \"Baiklah, sampaikanlah hadits itu, sebab engkau lebih tahu dengan haditsmu.\" Abdullah berkata; \"Setelah itu aku menyampaikan hadits itu kepada orang-orang.\" Imran berkata: \"Aku menyaksikan peristiwa malam itu, dan tidak ada seorangpun yang lebih bisa mengingatnya, sebagaimana aku mengingatnya.\""},"1061":{"ar":"و حَدَّثَنِي أَحْمَدُ بْنُ سَعِيدِ بْنِ صَخْرٍ الدَّارِمِيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا سَلْمُ بْنُ زَرِيرٍ الْعُطَارِدِيُّ قَالَ سَمِعْتُ أَبَا رَجَاءٍ الْعُطَارِدِيَّ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَكُنْتُ مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَسِيرٍ لَهُ فَأَدْلَجْنَا لَيْلَتَنَا حَتَّى إِذَا كَانَ فِي وَجْهِ الصُّبْحِ عَرَّسْنَا فَغَلَبَتْنَا أَعْيُنُنَا حَتَّى بَزَغَتْ الشَّمْسُ قَالَ فَكَانَ أَوَّلَ مَنْ اسْتَيْقَظَ مِنَّا أَبُو بَكْرٍ وَكُنَّا لَا نُوقِظُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَنَامِهِ إِذَا نَامَ حَتَّى يَسْتَيْقِظَ ثُمَّ اسْتَيْقَظَ عُمَرُ فَقَامَ عِنْدَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يُكَبِّرُ وَيَرْفَعُ صَوْتَهُ بِالتَّكْبِيرِ حَتَّى اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَفَعَ رَأْسَهُ وَرَأَى الشَّمْسَ قَدْ بَزَغَتْ قَالَ ارْتَحِلُوا فَسَارَ بِنَا حَتَّى إِذَا ابْيَضَّتْ الشَّمْسُ نَزَلَ فَصَلَّى بِنَا الْغَدَاةَ فَاعْتَزَلَ رَجُلٌ مِنْ الْقَوْمِ لَمْ يُصَلِّ مَعَنَا فَلَمَّا انْصَرَفَ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا فُلَانُ مَا مَنَعَكَ أَنْ تُصَلِّيَ مَعَنَا قَالَ يَا نَبِيَّ اللَّهِ أَصَابَتْنِي جَنَابَةٌ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَيَمَّمَ بِالصَّعِيدِ فَصَلَّى ثُمَّ عَجَّلَنِي فِي رَكْبٍ بَيْنَ يَدَيْهِ نَطْلُبُ الْمَاءَ وَقَدْ عَطِشْنَا عَطَشًا شَدِيدًا فَبَيْنَمَا نَحْنُ نَسِيرُ إِذَا نَحْنُ بِامْرَأَةٍ سَادِلَةٍ رِجْلَيْهَا بَيْنَ مَزَادَتَيْنِ فَقُلْنَا لَهَا أَيْنَ الْمَاءُ قَالَتْ أَيْهَاهْ أَيْهَاهْ لَا مَاءَ لَكُمْ قُلْنَا فَكَمْ بَيْنَ أَهْلِكِ وَبَيْنَ الْمَاءِ قَالَتْ مَسِيرَةُ يَوْمٍ وَلَيْلَةٍ قُلْنَا انْطَلِقِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ وَمَا رَسُولُ اللَّهِ فَلَمْ نُمَلِّكْهَا مِنْ أَمْرِهَا شَيْئًا حَتَّى انْطَلَقْنَا بِهَا فَاسْتَقْبَلْنَا بِهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهَا فَأَخْبَرَتْهُ مِثْلَ الَّذِي أَخْبَرَتْنَا وَأَخْبَرَتْهُ أَنَّهَا مُوتِمَةٌ لَهَا صِبْيَانٌ أَيْتَامٌ فَأَمَرَ بِرَاوِيَتِهَا فَأُنِيخَتْ فَمَجَّ فِي الْعَزْلَاوَيْنِ الْعُلْيَاوَيْنِ ثُمَّ بَعَثَ بِرَاوِيَتِهَا فَشَرِبْنَا وَنَحْنُ أَرْبَعُونَ رَجُلًا عِطَاشٌ حَتَّى رَوِينَا وَمَلَأْنَا كُلَّ قِرْبَةٍ مَعَنَا وَإِدَاوَةٍ وَغَسَّلْنَا صَاحِبَنَا غَيْرَ أَنَّا لَمْ نَسْقِ بَعِيرًا وَهِيَ تَكَادُ تَنْضَرِجُ مِنْ الْمَاءِ يَعْنِي الْمَزَادَتَيْنِ ثُمَّ قَالَ هَاتُوا مَا كَانَ عِنْدَكُمْ فَجَمَعْنَا لَهَا مِنْ كِسَرٍ وَتَمْرٍ وَصَرَّ لَهَا صُرَّةً فَقَالَ لَهَا اذْهَبِي فَأَطْعِمِي هَذَا عِيَالَكِ وَاعْلَمِي أَنَّا لَمْ نَرْزَأْ مِنْ مَائِكِ فَلَمَّا أَتَتْ أَهْلَهَا قَالَتْ لَقَدْ لَقِيتُ أَسْحَرَ الْبَشَرِ أَوْ إِنَّهُ لَنَبِيٌّ كَمَا زَعَمَ كَانَ مِنْ أَمْرِهِ ذَيْتَ وَذَيْتَ فَهَدَى اللَّهُ ذَاكَ الصِّرْمَ بِتِلْكَ الْمَرْأَةِ فَأَسْلَمَتْ وَأَسْلَمُواحَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ أَخْبَرَنَا النَّضْرُ بْنُ شُمَيْلٍ حَدَّثَنَا عَوْفُ بْنُ أَبِي جَمِيلَةَ الْأَعْرَابِيُّ عَنْ أَبِي رَجَاءٍ الْعُطَارِدِيِّ عَنْ عِمْرَانَ بْنِ الْحُصَيْنِ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَسَرَيْنَا لَيْلَةً حَتَّى إِذَا كَانَ مِنْ آخِرِ اللَّيْلِ قُبَيْلَ الصُّبْحِ وَقَعْنَا تِلْكَ الْوَقْعَةَ الَّتِي لَا وَقْعَةَ عِنْدَ الْمُسَافِرِ أَحْلَى مِنْهَا فَمَا أَيْقَظَنَا إِلَّا حَرُّ الشَّمْسِ وَسَاقَ الْحَدِيثَ بِنَحْوِ حَدِيثِ سَلْمِ بْنِ زَرِيرٍ وَزَادَ وَنَقَصَ وَقَالَ فِي الْحَدِيثِ فَلَمَّا اسْتَيْقَظَ عُمَرُ بْنُ الْخَطَّابِ وَرَأَى مَا أَصَابَ النَّاسَ وَكَانَ أَجْوَفَ جَلِيدًا فَكَبَّرَ وَرَفَعَ صَوْتَهُ بِالتَّكْبِيرِ حَتَّى اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِشِدَّةِ صَوْتِهِ بِالتَّكْبِيرِ فَلَمَّا اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَكَوْا إِلَيْهِ الَّذِي أَصَابَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا ضَيْرَ ارْتَحِلُوا وَاقْتَصَّ الْحَدِيثَ","id":"Dan telah menceritakan kepadaku [Ahmad bin Said bin Sakhr Ad Darimi] telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid], telah menceritakan kepada kami [Salam bin Zarir Al 'Utharidi], katanya; aku mendengar [Abu Raja' Al 'Utharidi] dari [Imran bin Hushain] katanya; aku bersama Nabi shallallahu 'alaihi wasallam dalam suatu perjalanan, hingga kami masuki malam kami. Menjelang subuh, kami singgah dalam perjalanan, rupanya kami tak kuasa menahan mata kami yang kelelahan (ketiduran) hingga matahari terbit.\" Imran melanjutkan; \"Dan yang pertama kali bangun adalah Abu Bakr. Dan kami tidak pernah membangunkan Rasulullah shallallahu 'alaihi wasallam dari tidurnya hingga beliau bangun sendiri. Setelah itu Umar bangun, ia berdiri di sisi Nabi shallallahu 'alaihi wasallam dan bertakbir sambil mengeraskan suaranya hingga Rasulullah shallallahu 'alaihi wasallam terbangun. Ketika beliau mengangkat kepalanya, beliau melihat ternyata matahari telah terbit, beliau lalu bersabda: \"Berangkatlah kalian.\" Maka beliau meneruskan perjalanan bersama kami, setelah matahari memutih, beliau singgah dan shalat subuh bersama kami. Ternyata ada seseorang yang mengisolir diri dari para sahabat. Ia tidak ikut shalat bersama kami. Selesai shalat, Rasulullah shallallahu 'alaihi wasallam bertanya kepada sahabat tersebut: \"Wahai Fulan, apa yang menghalangimu untuk shalat bersama kami?\" Dia menjawab; \"Wahai Nabiyullah, aku tengah junub.\" Rasulullah shallallahu 'alaihi wasallam lalu memerintahkan supaya dia bertayammum dengan permukaan tanah. Setelah itu dia mengerjakan shalat. Kemudian beliau memrintahkanku supaya bersegera menaiki kendaraan guna mencari air. Ketika itu kami merasa kehausan. Saat kami tengah berjalan, tiba-tiba seorang wanita menjulurkan kedua kakinya diantara mizadah yaitu geriba air bersusun. Kami berkata kepada wanita itu; \"Dimana ada air?\" wanita itu menjawab; \"Wah, wah, kalian tak punya air?\" kami menjawab; \"Berapa jarak antara keluargamu dan sumber mata air?\" dia menjawab; \"Perjalanan sehari-semalam.\" Kami berkata; \"Pergilah menemui Rasulullah shallallahu 'alaihi wasallam!\" Dia menjawab; \"Siapa itu Rasulullah?\" Kami belum bias mengendalikan urusan wanita itu, hingga kami mengajaknya dan menghadapkannya ke Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bertanya kepada wanita itu, lalu wanita itu mengabarkan asal usulnya sebagaimana ia mengabarkan kepada kami. Dirinya mengebarkan kepada beliau bahwa ia adalah pengasuh beberapa anak yatim. Lantas beliau memerintahkan supaya unta pembawa air itu diderumkan. Dengan mulutnya, beliau lalu menyemprotkan air ke air yang dikucurkan dari dua geriba kulit bagian atas, kemudian beliau sebarkan ke unta pembawa air. Ketika itu kami bergegas untuk minum, ketika itu jumlah kami sebanyak empat puluh orang yang semuanya merasa kehausan, hingga kami pun puas, kami juga sempat memenuhi setiap geriba dan jerigen kami (dengan air tersebut), kami juga dapat memandikan teman kami. Hanya kami tidak memberi minum unta kami karena nyaris mau pecah. Maksud kami, air yang berasal dari dua mizadah. Kemudian beliau bersabda: \"Kumpulkan bawaan yang kalian bawa!\" Maka kami mengumpulkan bekal yang kami bawa sebagai hadiah untuk wanita itu, yaitu berupa kurma, tali, dan daging. Beliau lalu bersabda kepada wanita itu: \"Pulanglah, dan pergunakanlah bekal ini untuk keluargamu, ketahuilah bahwa kami sama sekali tidak mengurangi sedikitpun air yang kamu bawa!\" Ketika wanita itu menemui keluarganya, ia berkata; \"Sungguh telah menemukan manusia paling penyihir di muka bumi, ataukah dia seorang nabi sebagaimana ia akui? Diantara kisahnya adalah demikian-demikian.\" Rupanya Allah memberikan hidayah kepada penghuni kampung lewat wanita itu, sehingga ia masuk Islam, dan mereka pun masuk Islam.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim Al Hanzhali] telah mengabarkan kepada kami [An nadlr bin Syumail] telah menceritakan kepada kami [Auf bin Abu Jamilah Al A'rabi] dari [Abu Raja' Al 'Atharidi] dari [Imran bin Hushain], katanya; kami pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan. Suatu malam, kami menyusuri perjalanan hingga akhir malam, beberapa saat menjelang subuh, kami singgah. Dan tidak ada persinggahan (istirahat) bagi seorang musafir yang lebih enak daripada persinggahan (istirahat) ketika itu. Pada saat itu, tidak ada seorangpun yang membangunkan kami selain sinar panas matahari.\" Lalu dia membawakan hadits itu sebagaimana hadits Salam bin Zarir dengan adanya tambahan dan pengurangan. Ia berkata dalam hadisnya; \"Ketika Umar bin Khattab bangun, ia menemukan musibah yang menimpa para sahabatnya. Dia adalah sosok yang beliau berbadan besar dan kuat, dia langsung memekikkan takbir hingga Rasulullah shallallahu 'alaihi wasallam terbangun karena suara takbirnya yang keras. Ketika Rasulullah shallallahu 'alaihi wasallam bangun, para sahabat mengeluhkan kepada beliau perihal sesuatu yang telah mereka alami. Rasulullah shallallahu 'alaihi wasallam hanya bersabda: \"Tidak masalah, teruskanlah perjalanan kalian…\" lalu perawi mengisahkan hadits tersebut.\""},"1062":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ فِي سَفَرٍ فَعَرَّسَ بِلَيْلٍ اضْطَجَعَ عَلَى يَمِينِهِ وَإِذَا عَرَّسَ قُبَيْلَ الصُّبْحِ نَصَبَ ذِرَاعَهُ وَوَضَعَ رَأْسَهُ عَلَى كَفِّهِ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Bakar bin Abdullah] dari [Abdullah bin Rabah] dari [Abu Qatadah] katanya; Jika Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan lalu singgah di waktu malamnya, maka beliau berbaring dengan bertumpu lambung kanannya, apabila beliau singgah di saat-saat sebelum subuh, maka beliau tegakkan hastanya searah badannya, kemudian beliau letakkan kepalanya diatas telapak tangannya.\""},"1063":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَسِيَ صَلَاةً أَوْ نَامَ عَنْهَا فَكَفَّارَتُهَا أَنْ يُصَلِّيَهَا إِذَا ذَكَرَهَا","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Said] dari [Qatadah] dari [Anas bin Malik] katanya; Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa lupa shalat atau ketiduran karenanya, maka kaffaratnya adalah menunaikannya disaat ingat.\""},"1064":{"ar":"و حَدَّثَنَا نَصْرُ بْنُ عَلِيٍّ الْجَهْضَمِيُّ حَدَّثَنِي أَبِي حَدَّثَنَا الْمُثَنَّى عَنْ قَتَادَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا رَقَدَ أَحَدُكُمْ عَنْ الصَّلَاةِ أَوْ غَفَلَ عَنْهَا فَلْيُصَلِّهَا إِذَا ذَكَرَهَا فَإِنَّ اللَّهَ يَقُولُ أَقِمْ الصَّلَاةَ لِذِكْرَى","id":"Telah menceritakan kepada kami [Nashr bin Ali Al Jahdlami] telah menceritakan kepadaku [Ayahku] telah menceritakan kepada kami [Al Mutsanna] dari [Qatadah] dari [Anas bin Malik] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang diantar kalian ketiduran dari (tidak mengerjakan) shalat, hendaknya ia mengerjakan ketika ingat, sebab Allah Ta'ala berfirman; Dirikanlah shalat untuk mengingat-Ku.\""},"1065":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى قَالَا حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْفَرَضَ اللَّهُ الصَّلَاةَ حِينَ فَرَضَهَا رَكْعَتَيْنِ ثُمَّ أَتَمَّهَا فِي الْحَضَرِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ عَلَى الْفَرِيضَةِ الْأُولَى","id":"Dan telah menceritakan kepadaku [Abu Thahir] dan [Harmalah bin Yahya] keduanya berkata; telah menceritakan kepada kami [Ibnuu Wahb] dari [Yunus] dari [Ibnu Syihab], katanya; telah menceritakan kepadaku ['Urwah bin Zubair] bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam mengatakan; \"Diawal mula, Allah menetapkan shalat ketika diwajibkan-Nya sebanyak dua rakaat, kemudian Allah sempurnakan (ditambah) ketika mukim, sedangkan shalat safar ditetapkan sesuai ketentuan pertama (dua rakaat).\""},"1066":{"ar":"و حَدَّثَنِي عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ الصَّلَاةَ أَوَّلَ مَا فُرِضَتْ رَكْعَتَيْنِ فَأُقِرَّتْ صَلَاةُ السَّفَرِ وَأُتِمَّتْ صَلَاةُ الْحَضَرِقَالَ الزُّهْرِيُّ فَقُلْتُ لِعُرْوَةَ مَا بَالُ عَائِشَةَ تُتِمُّ فِي السَّفَرِ قَالَ إِنَّهَا تَأَوَّلَتْ كَمَا تَأَوَّلَ عُثْمَانُ","id":"Dan telah menceritakan kepadaku [Ali bin Khasyram] telah mengabarkan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah], bahwa ketika pertama kali, shalat ditetapkan sebanyak dua rakaat, lantas dua rakaat ditetapkan untuk shalat safar, sedangkan ketika bermukim, shalat disempurnakan (ditambah).\" [Az Zuhri] mengatakan; \"Saya tanyakan kepada ['Urwah]; \"Lalu apa alasan ['Aisyah] shalat secara sempurna (tidak diringkas) ketika safar?\" Jawabnya; \"Ia mempunyai kesimpulan sebagaimana kesimpulan Utsman.\""},"1067":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَزُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرُونَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَقُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ{ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَنْ تَقْصُرُوا مِنْ الصَّلَاةِ إِنْ خِفْتُمْ أَنْ يَفْتِنَكُمْ الَّذِينَ كَفَرُوا }فَقَدْ أَمِنَ النَّاسُ فَقَالَ عَجِبْتُ مِمَّا عَجِبْتَ مِنْهُ فَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ صَدَقَةٌ تَصَدَّقَ اللَّهُ بِهَا عَلَيْكُمْ فَاقْبَلُوا صَدَقَتَهُو حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمنِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي عَمَّارٍ عَنْ عَبْدِ اللَّهِ بْنِ بَابَيْهِ عَنْ يَعْلَى بْنِ أُمَيَّةَ قَالَ قُلْتُ لِعُمَرَ بْنِ الْخَطَّابِ بِمِثْلِ حَدِيثِ ابْنِ إِدْرِيسَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] dan [Zuhair bin Harb] dan [Ishaq bin Ibrahim]. Ishaq mengatakan; telah mengabarkan kepada kami, sedangkan yang lainnya mengatakan; telah menceritakan kepada kami [Abdullah bin Idris] dari [Ibnu Juraij] dari [Ibnu Abu Ammar] dari [Abdullah bin Babaihi] dari [Ya'la bin 'Umayyah], katanya; \"Aku berkata kepada [Umar bin Khattab] mengenai ayat yang berbunyi Tak ada dosa atasmu meng-qashar shalat, jika kamu khawatir terhadap orang-orang kafir yang hendak memberi cobaan kepadamu.\" QS. Annisa'; 101, sementara manusia saat ini dalam kondisi aman (maksudnya tidak dalam kondisi perang).\" Umar menjawab; \"Sungguh aku juga pernah penasaran tentang ayat itu sebagaimana kamu penasaran, lalu aku tanyakan kepada Rasulullah shallallahu 'alaihi wasallam tentang ayat tersebut, beliau lalu menjawab: \"Itu (mengqashar shalat) adalah sedekah yang Allah berikan kepada kalian. Oleh karena itu, terimalah sedekah-Nya.\" Dan telah menceritakan kepada kami [Muhammad bin Abu Bakr Al Muqaddami], telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij] katanya; telah menceritakan kepadaku [Abdurrahman bin Abdullah bin Abu 'Ammar] dari [Abdullah bin Babaihi], dari [Ya'la bin 'Umayyah] katanya; Aku pernah bertanya kepada [Umar bin Khatthab] semisal hadis Ibnu Idris."},"1068":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ جَمِيعًا عَنْ الْقَاسِمِ بْنِ مَالِكٍ قَالَ عَمْرٌو حَدَّثَنَا قَاسِمُ بْنُ مَالِكٍ الْمُزَنِيُّ حَدَّثَنَا أَيُّوبُ بْنُ عَائِذٍ الطَّائِيُّ عَنْ بُكَيْرِ بْنِ الْأَخْنَسِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍ قَالَإِنَّ اللَّهَ فَرَضَ الصَّلَاةَ عَلَى لِسَانِ نَبِيِّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمُسَافِرِ رَكْعَتَيْنِ وَعَلَى الْمُقِيمِ أَرْبَعًا وَفِي الْخَوْفِ رَكْعَةً","id":"Dan telah menceritakan kepada kami [Abu Bukair bin Abu Syaibah] dan ['Amru An Naqid] semuanya dari [Al Qasim bin Malik]. ['Amru] mengatakan; telah menceritakan kepada kami [Qasim bin Malik Al Muzani] telah menceritakan kepada kami [Ayyub bin 'Aidz Ath Tha`i] dari [Bukair bin Al Akhnas] dari [Mujahid] dari [Ibnu Abbas], katanya; \"Allah mewajibkan shalat melalui perantaran lisan Nabi kalian bagi seorang musafir sebanyak dua raka'at, sedang untuk orang yang bermukim sebanyak empat raka'at, dan ketika kondisi ketakutan (takut) sebanyak satu raka'at.\""},"1069":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو وَهُوَ ابْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى صَلَاةَ الْمُسَافِرِ بِمِنًى وَغَيْرِهِ رَكْعَتَيْنِوَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ رَكْعَتَيْنِ صَدْرًا مِنْ خِلَافَتِهِ ثُمَّ أَتَمَّهَا أَرْبَعًا و حَدَّثَنَاه زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ ح و حَدَّثَنَاه إِسْحَقُ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ جَمِيعًا عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ قَالَ بِمِنًى وَلَمْ يَقُلْ وَغَيْرِهِ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yhaya] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku ['Amru yaitu Ibnu Al Harits] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [Ayahnya] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau pernah mengerjakan shalat musafir di Mina dan lainnya sebanyak dua rakaat, Abu Bakar, Umar dan awal pemerintahan Utsman juga dua rakaat, setelah itu dia menyempurnakannya empat rakaat.\" Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Auza'i] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ishaq] dan ['Abd bin Humaid], keduanya berkata; telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar], semuanya dari [Az Zuhri] dengan sanad seperti ini, katanya; \"Di Mina, \" namun dia tidak menyebutkan yang lainnya."},"1070":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى رَكْعَتَيْنِ وَأَبُو بَكْرٍ بَعْدَهُ وَعُمَرُ بَعْدَ أَبِي بَكْرٍ وَعُثْمَانُ صَدْرًا مِنْ خِلَافَتِهِ ثُمَّ إِنَّ عُثْمَانَ صَلَّى بَعْدُ أَرْبَعًا فَكَانَ ابْنُ عُمَرَ إِذَا صَلَّى مَعَ الْإِمَامِ صَلَّى أَرْبَعًا وَإِذَا صَلَّاهَا وَحْدَهُ صَلَّى رَكْعَتَيْنِو حَدَّثَنَاه ابْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ ح و حَدَّثَنَاه أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ أَبِي زَائِدَةَ ح و حَدَّثَنَاه ابْنُ نُمَيْرٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ كُلُّهُمْ عَنْ عُبَيْدِ اللَّهِ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], katanya; \"Ia pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam di Mina dua rakaat, begitu pula Abu bakar, dan Umar, dan dan di awal pemerintahan Usman, setelah itu Usman menyempurnakan shalat empat rakaat. Apabila Ibnu Umar shalat bersama Imam, maka ia shalat empat rakaat, namun jika shalat sendirian, dia shalat dua rakaat.\" Telah menceritakan kepada kami [Ibnu Al Mutsanna] dan ['Ubaidullah bin Sa'id], keduanya berkata; telah menceritakan kepada kami [Yahya yaitu Al Qatthan] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Abu Zaidah], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami ['Uqbah bin Khalid] semuanya dari ['Ubaidullah] dengan sanad seperti ini."},"1071":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ خُبَيْبِ بْنِ عَبْدِ الرَّحْمَنِ سَمِعَ حَفْصَ بْنَ عَاصِمٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى صَلَاةَ الْمُسَافِرِ وَأَبُو بَكْرٍ وَعُمَرُ وَعُثْمَانُ ثَمَانِيَ سِنِينَ أَوْ قَالَ سِتَّ سِنِينَقَالَ حَفْصٌ وَكَانَ ابْنُ عُمَرَ يُصَلِّي بِمِنًى رَكْعَتَيْنِ ثُمَّ يَأْتِي فِرَاشَهُ فَقُلْتُ أَيْ عَمِّ لَوْ صَلَّيْتَ بَعْدَهَا رَكْعَتَيْنِ قَالَ لَوْ فَعَلْتُ لَأَتْمَمْتُ الصَّلَاةَ و حَدَّثَنَاه يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى قَالَ حَدَّثَنِي عَبْدُ الصَّمَدِ قَالَا حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ وَلَمْ يَقُولَا فِي الْحَدِيثِ بِمِنًى وَلَكِنْ قَالَا صَلَّى فِي السَّفَرِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Muadz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Syu'bah] dari [Khubaib bin Abdurrahman] ia mendengar [Hafs bin 'Ashim] dari [Ibnu Umar] katanya; Nabi shallallahu 'alaihi wasallam pernah shalat di Mina dengan shalatnya musafir, begitu juga Abu Bakr, Umar dan Usman selama delapan tahun.\" -Atau mengatakan; enam tahun- [Hafs] mengatakan; [Ibnu Umar] shalat di Mina dua rakaat, kemudian ia mendatangi tempat tidurnya. Lalu aku berkata kepadanya; \"Wahai paman, alangkah baiknya sekiranya engkau lakukan setelahnya dua rakaat.\" Dia menjawab; \"Kalaulah aku lakukan dua shalat sunnah itu, niscaya kusempurnakan shalatku.\" Telah menceritakan kepada kami [Yahya bin Habib] telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Al Mutsanna] katanya; telah menceritakan kepadaku [Abdusshamad] keduanya berkata; telah menceritakan kepada kami [Syu'bah] dengan sanad seperti ini, namun dalam hadisnya, ia tidak mengatakan \"Di Mina, \" namun ia mengatakan; \"Shalat dalam perjalanan.\""},"1072":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ عَنْ الْأَعْمَشِ حَدَّثَنَا إِبْرَاهِيمُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ يَقُولُاصَلَّى بِنَا عُثْمَانُ بِمِنًى أَرْبَعَ رَكَعَاتٍ فَقِيلَ ذَلِكَ لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍ فَاسْتَرْجَعَ ثُمَّ قَالَ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى رَكْعَتَيْنِ وَصَلَّيْتُ مَعَ أَبِي بَكْرٍ الصِّدِّيقِ بِمِنًى رَكْعَتَيْنِ وَصَلَّيْتُ مَعَ عُمَرَ بْنِ الْخَطَّابِ بِمِنًى رَكْعَتَيْنِ فَلَيْتَ حَظِّي مِنْ أَرْبَعِ رَكَعَاتٍ رَكْعَتَانِ مُتَقَبَّلَتَانِحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ قَالَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا إِسْحَقُ وَابْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى كُلُّهُمْ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Qutaibah bin Said] telah menceritakan kepada kami [Abdul Wahid] dari [Al A'masy] telah menceritakan kepada kami [Ibrahim], katanya; \"Aku mendengar [Abdurrahman bin Yazid] mengatakan; \"Utsman pernah shalat bersama kami di Mina sebanyak empat rakaat, lalu hal itu ditanyakan kepada [Ibnu Mas'ud], dia langsung beristirja' (mengucapkan inna lillah wa inna ilaihi raaji'un) dan berkata; \"Aku pernah shalat dua raka'at bersama Rasulullah shallallahu 'alaihi wasallam di Mina, dan aku shalat dua raka'at bersama Abu Bakr As Sidiq di Mina, dan aku juga pernah shalat dua raka'at bersama Umar bin Khattab di Mina. Sekiranya yang empat rakaat itu cukup aku kerjakan dua rakaat saja.\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Abu Muawiyah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Utsman bin Abu Syaibah] katanya; telah menceritakan kepada kami [Jarir] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ishaq] dan [Ibnu Husyrum], keduanya berkata; telah mengabarkan kepada kami [Isa] semuanya dari [Al A'masy] dengan sanad seperti ini."},"1073":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَقُتَيْبَةُ قَالَ يَحْيَى أَخْبَرَنَا و قَالَ قُتَيْبَةُ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ حَارِثَةَ بْنِ وَهْبٍ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى آمَنَ مَا كَانَ النَّاسُ وَأَكْثَرَهُ رَكْعَتَيْنِ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Qutaibah]. Yahya mengatakan; telah mengabarkan kepada kami, sedangkan Qutaibah mengatakan; telah menceritakan kepada kami [Abul Al Ahwash] dari [Abu Ishaq] dari [Haritsah bin Wahb] katanya; \"Aku pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam di Mina, di saat kondisi manusia sangat banyak dan aman.\""},"1074":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ حَدَّثَنِي حَارِثَةُ بْنُ وَهْبٍ الْخُزَاعِيُّ قَالَصَلَّيْتُ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِنًى وَالنَّاسُ أَكْثَرُ مَا كَانُوا فَصَلَّى رَكْعَتَيْنِ فِي حَجَّةِ الْوَدَاعِقَالَ مُسْلِم حَارِثَةُ بْنُ وَهْبٍ الْخُزَاعِيُّ هُوَ أَخُو عُبَيْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ لِأُمِّهِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] telah menceritakan kepadaku [Haritsah binti Wahb Al Khuza'i] katanya; \"Aku pernah shalat di belakang Rasulullah shallallahu 'alaihi wasallam di Mina, dan orang-orang melakukan apa yang telah berlaku, maka beliau melakukan dua rakaat ketika haji wada'.\" Muslim berkata; Haritsah bin Muslim Al Khuza'i adalah saudara seibu 'Ubaidullah bin Umar bin Khattab."},"1075":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ أَذَّنَ بِالصَّلَاةِ فِي لَيْلَةٍ ذَاتِ بَرْدٍ وَرِيحٍ فَقَالَ أَلَا صَلُّوا فِي الرِّحَالِ ثُمَّ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُ الْمُؤَذِّنَ إِذَا كَانَتْ لَيْلَةٌ بَارِدَةٌ ذَاتُ مَطَرٍ يَقُولُ أَلَا صَلُّوا فِي الرِّحَالِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya], katanya; aku menyetorkan hapalan kepada [Malik] dari [Nafi'] bahwa [Ibnu Umar] pernah mengumandangkan adzan shalat di malam yang sangat dingin dan berangin kencang, maka dalam adzannya ia mengucapkan; 'Alaa tusholluu fir rihaal (Tidak sebaiknyakah kalian shalat di persinggahan kalian?) kemudian katanya; Rasulullah shallallahu 'alaihi wasallam juga pernah memerintahkan mu'adzinnya jika malam sangat dingin dan terjadi hujan lebat untuk mengucapkan; 'Alaa tushalluu rir rihaal (Tidak seebaiknyakah kalian shalat di persinggahan kalian?) \""},"1076":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ أَنَّهُ نَادَى بِالصَّلَاةِ فِي لَيْلَةٍ ذَاتِ بَرْدٍ وَرِيحٍ وَمَطَرٍ فَقَالَ فِي آخِرِ نِدَائِهِ أَلَا صَلُّوا فِي رِحَالِكُمْ أَلَا صَلُّوا فِي الرِّحَالِ ثُمَّ قَالَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ الْمُؤَذِّنَ إِذَا كَانَتْ لَيْلَةٌ بَارِدَةٌ أَوْ ذَاتُ مَطَرٍ فِي السَّفَرِ أَنْ يَقُولَ أَلَا صَلُّوا فِي رِحَالِكُمْو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ نَادَى بِالصَّلَاةِ بِضَجْنَانَ ثُمَّ ذَكَرَ بِمِثْلِهِ وَقَالَ أَلَا صَلُّوا فِي رِحَالِكُمْ وَلَمْ يُعِدْ ثَانِيَةً أَلَا صَلُّوا فِي الرِّحَالِ مِنْ قَوْلِ ابْنِ عُمَرَ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami ['Ubaidullah] telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar], bahwa ia menyeru shalat pada malam yang sangat dingin dan hujan angin, di akhir seruannya ia berkata; 'Alaaa tushalluu fii rihaalikum, 'Alaa tushalluu fir rihaaal, (Tidak sebaiknyakah kalian di persinggahan kalian, tidak sebaiknyakah kalian shalat di persinggahan kalian?) \" Kemudian katanya; \"Dahulu Rasulullah shallallahu 'alaihi wasallam juga pernah menyuruh mu'adzinnya jika malam sangat dingin atau terjadi hujan, yaitu ketika safar untuk mengumandangkan 'Alaa tushalluu fii rihaalikum (Tidak sebaiknyakah kalian shalat di persinggahan kalian?).\" Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa ia menyerukan shalat di Dlajnan. kemudian ia menyebutkan hadits semisalnya, lalu ia menyerukan; 'Alaa tushalluu fii rihaalikum (Tidak sebaiknyakah kalian shalat di persinggahan kalian?).\" Namun dia tidak mengulang untuk kedua kalinya, dan kalimat; 'Alaa tushaliii frrihaal adalah ucapan Ibnu Umar sendiri."},"1077":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ ح و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ قَالَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَمُطِرْنَا فَقَالَ لِيُصَلِّ مَنْ شَاءَ مِنْكُمْ فِي رَحْلِهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Abu Zubair] dari [Jabir] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ahmad bin Yunus] katanya; telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] katanya; \"Kami berangkat bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, kemudian hujan mengguyur kami, lalu dia mengatakan; \"Siapa diantara kalian yang hendak shalat, hendaknya dikerjakan di persinggahannya.\""},"1078":{"ar":"و حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا إِسْمَعِيلُ عَنْ عَبْدِ الْحَمِيدِ صَاحِبِ الزِّيَادِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّهُقَالَ لِمُؤَذِّنِهِ فِي يَوْمٍ مَطِيرٍ إِذَا قُلْتَ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ أَشْهَدُ أَنَّ مُحَمَّدًا رَسُولُ اللَّهِ فَلَا تَقُلْ حَيَّ عَلَى الصَّلَاةِ قُلْ صَلُّوا فِي بُيُوتِكُمْ قَالَ فَكَأَنَّ النَّاسَ اسْتَنْكَرُوا ذَاكَ فَقَالَ أَتَعْجَبُونَ مِنْ ذَا قَدْ فَعَلَ ذَا مَنْ هُوَ خَيْرٌ مِنِّي إِنَّ الْجُمُعَةَ عَزْمَةٌ وَإِنِّي كَرِهْتُ أَنْ أُخْرِجَكُمْ فَتَمْشُوا فِي الطِّينِ وَالدَّحْضِو حَدَّثَنِيهِ أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ عَبْدِ الْحَمِيدِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الْحَارِثِ قَالَ خَطَبَنَا عَبْدُ اللَّهِ بْنُ عَبَّاسٍ فِي يَوْمٍ ذِي رَدْغٍ وَسَاقَ الْحَدِيثَ بِمَعْنَى حَدِيثِ ابْنِ عُلَيَّةَ وَلَمْ يَذْكُرْ الْجُمُعَةَ وَقَالَ قَدْ فَعَلَهُ مَنْ هُوَ خَيْرٌ مِنِّي يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و قَالَ أَبُو كَامِلٍ حَدَّثَنَا حَمَّادٌ عَنْ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بِنَحْوِهِ و حَدَّثَنِيهِ أَبُو الرَّبِيعِ الْعَتَكِيُّ هُوَ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ حَدَّثَنَا أَيُّوبُ وَعَاصِمٌ الْأَحْوَلُ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ فِي حَدِيثِهِ يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا ابْنُ شُمَيْلٍ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا عَبْدُ الْحَمِيدِ صَاحِبُ الزِّيَادِيِّ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ الْحَارِثِ قَالَ أَذَّنَ مُؤَذِّنُ ابْنِ عَبَّاسٍ يَوْمَ جُمُعَةٍ فِي يَوْمٍ مَطِيرٍ فَذَكَرَ نَحْوَ حَدِيثِ ابْنِ عُلَيَّةَ وَقَالَ وَكَرِهْتُ أَنْ تَمْشُوا فِي الدَّحْضِ وَالزَّلَلِ و حَدَّثَنَاه عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ ح و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ كِلَاهُمَا عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ أَنَّ ابْنَ عَبَّاسٍ أَمَرَ مُؤَذِّنَهُ فِي حَدِيثِ مَعْمَرٍ فِي يَوْمِ جُمُعَةٍ فِي يَوْمٍ مَطِيرٍ بِنَحْوِ حَدِيثِهِمْ وَذَكَرَ فِي حَدِيثِ مَعْمَرٍ فَعَلَهُ مَنْ هُوَ خَيْرٌ مِنِّي يَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَاه عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا أَحْمَدُ بْنُ إِسْحَقَ الْحَضْرَمِيُّ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا أَيُّوبُ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ قَالَ وُهَيْبٌ لَمْ يَسْمَعْهُ مِنْهُ قَالَ أَمَرَ ابْنُ عَبَّاسٍ مُؤَذِّنَهُ فِي يَوْمِ جُمُعَةٍ فِي يَوْمٍ مَطِيرٍ بِنَحْوِ حَدِيثِهِمْ","id":"Dan telah menceritakan kepadaku [Ali bin Hujr As Sa'di] telah menceritakan kepada kami [Ismail] dari [Abdul Hamid] kawan Az Ziyadi, dari [Abdulah bin Al Harits] dari [Abdullah bin Abbas] dia mengatakan kepada muadzinnya ketika turun hujan, jika engkau telah mengucapkan \"Asyhadu an laa ilaaha illallaah, asyhadu anna Muhammadan Rasulullah, \" maka janganlah kamu mengucapkan \"Hayya alash shalaah, \" namun ucapkanlah shalluu fii buyuutikum (Shalatlah kalian di persinggahan kalian).\" Abdullah bin Abbas berkata; \"Ternyata orang-orang sepertinya tidak menyetujui hal ini, lalu ia berkata; \"Apakah kalian merasa heran terhadap ini kesemua? Padahal yang demikian pernah dilakukan oleh orang yang lebih baik dariku. Shalat jum'at memang wajib, namun aku tidak suka jika harus membuat kalian keluar sehingga kalian berjalan di lumpur dan comberan.\" Telah menceritakan kepada kami [Abu Kamil Al Jahdari] tentang hadits tersebut, telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid] dari [Abdul Hamid], katanya; \"Aku pernah mendengar [Abdullah bin Harits] mengtakan; [Abdullah bin Abbas] pernah berpidato di hadapan kami, tepatnya ketika hari turun hujan, lalu dia membawakan hadits yang semakna dengan hadits Ibnu 'Ulayyah, namun dirinya tidak menyebutkan jumat, katanya; hal ini juga pernah dilakukan oleh orang yang lebih baik daripadaku, yakni Nabi shallallahu 'alaihi wasallam. Dan [Abu Kamil] mengatakan; telah menceritakan kepada kami [Hammad] dari ['Ashim] dari [Abdulah bin Harits] dengan hadits yang sama. Telah menceritakan kepadaku [Abu Rabi' Al 'Ataki yaitu Az Zahrani] telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid] telah menceritakan kepada kami [Ayyub] dan ['Ashim Al Ahwal] dengan sanad ini, namun dia tidak menyebutkan \"Yakni Nabi shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Ibnu Syumail] telah mengabarkan kepada kami [Syu'bah] telah menceritakan kepada kami [Abdul Hamid] kawannya Az ziyadi, katanya; \"Aku mendengar [Abdullah bin Al Harits] katanya; \"Muadzin [Ibnu Abbas] mengumandangkan adzan pada hari jumat ketika hujan deras, \" dia kemudian menyebutkan seperti haditsnya Ibnu 'Ulayyah, dia mengatakan; \"Dan aku tidak suka jika kalian berjalan dalam comberan.\" Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Said bin Amir] dari [Syu'bah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami ['Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar], keduanya dari ['Ashim Al Ahwal] dari [Abdullah bin Al Harits] bahwa [Ibnu Abbas] pernah menyuruh muadzinnya -dalam hadis Ma'mar- pada hari jumat ketika hari hujan semisal hadis mereka, dia juga menyebutkan dalam hadis Ma'mar; \"Dan orang yang lebih baik dariku juga pernah melakukan hal ini, yakni Nabi shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami ['Abd bin Humaid] telah menceritakan kepada kami [Ahmad bin Ishaq Al Khadhrami] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Ayyub] dari [Abdullah bin Al Harits]. [Wuhaib] mengatakan; \"Namun Ayyub tidak mendengarnya dari Abdulah bin Al Harits.\" Ibnu Al Harits berkata; [Ibnu Abbas] menyuruh muadzinnya pada hari jumat ketika hari turun hujan, seperti hadits mereka."},"1079":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي سُبْحَتَهُ حَيْثُمَا تَوَجَّهَتْ بِهِ نَاقَتُهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat sunnah kearah manapun hewan tunggangannya menghadap."},"1080":{"ar":"و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي عَلَى رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ بِهِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam pernah shalat diatas hewan tunggangannya kearah manapun hewan tunggangannya menghadap."},"1081":{"ar":"و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهُوَ مُقْبِلٌ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ عَلَى رَاحِلَتِهِ حَيْثُ كَانَ وَجْهُهُ قَالَ وَفِيهِ نَزَلَتْ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }و حَدَّثَنَاه أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ الْمُبَارَكِ وَابْنُ أَبِي زَائِدَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي كُلُّهُمْ عَنْ عَبْدِ الْمَلِكِ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَفِي حَدِيثِ ابْنِ مُبَارَكٍ وَابْنِ أَبِي زَائِدَةَ ثُمَّ تَلَا ابْنُ عُمَرَ{ فَأَيْنَمَا تُوَلُّوا فَثَمَّ وَجْهُ اللَّهِ }وَقَالَ فِي هَذَا نَزَلَتْ","id":"Dan telah menceritakan kepadaku ['Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Yahya bin Said] dari [Abdul Malik bin Abu Sulaiman] katanya; telah menceritakan kepada kami [Said bin Jubair] dari [Ibnu Umar] katanya; Rasulullah shallallahu 'alaihi wasallam pernah shalat diatas kendarannya ke arah mana saja beliau menghadap, yaitu ketika berangkat dari Makkah menuju Madinah. Dan pada saat itu diturunkan pula ayat \" Kearah manapun engkau menghadap, maka engkau menghadap wajah Allah QS. Albaqarah; 115, Telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Al Mubarak] dan [Ibnu Zaidah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [ayahku], semuanya dari [Abdul Malik] dengan sanad seperti ini, namun dalam hadis Ibnu Al Mubarak dan Ibnu Abi Zaidah disebutkan; \"Kemudian Ibnu Umar membacakan ayat \"Kearah manapun engkau menghadap, maka engkau menghadap wajah Allah. QS. Albaqarah; 115, Dia lalu berkata; \"Tentang masalah inilah ayat ini diturunkan.\""},"1082":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ عَمْرِو بْنِ يَحْيَى الْمَازِنِيِّ عَنْ سَعِيدِ بْنِ يَسَارٍ عَنْ ابْنِ عُمَرَ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى حِمَارٍ وَهُوَ مُوَجِّهٌ إِلَى خَيْبَرَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] katanya; \"Aku pernah menyetorkan hapalan di hadapan [Malik] dari ['Amru bin Yahya Al Mazini] dari [Said bin Yasar] dari [Ibnu Umar], katanya; \"Aku pernah menemui Rasulullah shallallahu 'alaihi wasallam ketika beliau tengah shalat diatas keledai dan menghadap ke Khaibar.\""},"1083":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ أَبِي بَكْرِ بْنِ عُمَرَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ عَنْ سَعِيدِ بْنِ يَسَارٍ أَنَّهُ قَالَ كُنْتُ أَسِيرُ مَعَ ابْنِ عُمَرَ بِطَرِيقِ مَكَّةَ قَالَ سَعِيدٌ فَلَمَّا خَشِيتُ الصُّبْحَ نَزَلْتُ فَأَوْتَرْتُ ثُمَّ أَدْرَكْتُهُ فَقَالَ لِي ابْنُ عُمَرَ أَيْنَ كُنْتَ فَقُلْتُ لَهُ خَشِيتُ الْفَجْرَ فَنَزَلْتُ فَأَوْتَرْتُفَقَالَ عَبْدُ اللَّهِ أَلَيْسَ لَكَ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسْوَةٌ فَقُلْتُ بَلَى وَاللَّهِ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُوتِرُ عَلَى الْبَعِيرِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] katanya; aku menyetorkan hapalan di hadapan [Malik] dari [Abu Bakar bin Umar bin Abdurrahman bin Abdullah bin Umar bin Khattab] dari [Sa'id bin Yasar], katanya; \"Aku pernah mengadakan perjalan bersama [Ibnu Umar] lewat jalanan Makkah. Sa'id melanjutkan; \"Ketika aku khawatir kehilangan waktu subuh, maka akupun singgah, aku lalu melakukan shalat witir, yang di teruskan dengan shalat shubuh. Maka Ibnu Umar berkata kepadaku; \"Apa maksud dari apa yang telah kamu lakukan?\" Aku menjawab; \"Aku sangat khawatir kehilangan shalat shubuh, maka aku pun singgah dan kulakukan shalat witir.\" Abdullah bin Umar berkata; \"Bukankah pada diri Rasulullah shallallahu 'alaihi wasallam terdapat teladan yang baik?\" Aku menjawab; \"Demi Allah, benar.\" Abdullah bin Umar berkata; \"Rasulullah shallallahu 'alaihi wasallam dulu juga pernah melakukan witir diatas untanya.\""},"1084":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ أَنَّهُ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي عَلَى رَاحِلَتِهِ حَيْثُمَا تَوَجَّهَتْ بِهِقَالَ عَبْدُ اللَّهِ بْنُ دِينَارٍ كَانَ ابْنُ عُمَرَ يَفْعَلُ ذَلِكَ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] katanya; \"Aku pernah menyetorkan hapalan di hadapan [Malik] dari [Abdullah bin Dinar] dari [Ibnu Umar] dia mengatakan; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat diatas hewan tunggangannya ke arah manapun hewan tunggangannya menghadap.\" [Abdullah bin Dinar] berkata; Dan [Ibnu Umar] juga pernah melakukan seperti ini."},"1085":{"ar":"و حَدَّثَنِي عِيسَى بْنُ حَمَّادٍ الْمِصْرِيُّ أَخْبَرَنَا اللَّيْثُ حَدَّثَنِي ابْنُ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُوتِرُ عَلَى رَاحِلَتِهِ","id":"Dan telah menceritakan kepadaku [Isa bin Hammad Al Mishri] telah mengabarkan kepada kami [Al Laits] telah menceritakan kepadaku [Ibnu Al Had] dari [Abdullah bin Dinar] dari [Abdullah bin Umar] bahwa ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah melakukan witir diatas hewan tunggangannya.\""},"1086":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَبِّحُ عَلَى الرَّاحِلَةِ قِبَلَ أَيِّ وَجْهٍ تَوَجَّهَ وَيُوتِرُ عَلَيْهَا غَيْرَ أَنَّهُ لَا يُصَلِّي عَلَيْهَا الْمَكْتُوبَةَ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [Ayahnya] katanya; \"Rasulullah shallallahu 'alaihi wasallam pernah melakukan shalat sunnah diatas hewan tunggangannya, menghadap ke arah mana saja beliau menghadap, dan beliau juga melakukan witir diatas tunggangannya, namun beliau tidak melakukan shalat wajib diatas tunggangan.\""},"1087":{"ar":"و حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ وَحَرْمَلَةُ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَامِرِ بْنِ رَبِيعَةَ أَخْبَرَهُ أَنَّ أَبَاهُ أَخْبَرَهُأَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي السُّبْحَةَ بِاللَّيْلِ فِي السَّفَرِ عَلَى ظَهْرِ رَاحِلَتِهِ حَيْثُ تَوَجَّهَتْ","id":"Telah menceritakan kepada kami ['Amru bin Sawwad] dan [Harmalah] katanya; telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Abdullah bin 'Amir bin Rabiah] bahwa dia telah mengabarkan kepadanya, bahwa [Ayahnya] telah mengabarkan kepadanya, bahwa dia pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat sunnah malam hari, ketika dalam perjalanan di atas punggung hewan tunggangannya, kearah mana saja beliau menghadap.\""},"1088":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا أَنَسُ بْنُ سِيرِينَ قَالَ تَلَقَّيْنَا أَنَسَ بْنَ مَالِكٍ حِينَ قَدِمَ الشَّامَ فَتَلَقَّيْنَاهُ بِعَيْنِ التَّمْرِ فَرَأَيْتُهُ يُصَلِّي عَلَى حِمَارٍ وَوَجْهُهُ ذَلِكَ الْجَانِبَ وَأَوْمَأَ هَمَّامٌ عَنْ يَسَارِ الْقِبْلَةِ فَقُلْتُ لَهُ رَأَيْتُكَ تُصَلِّي لِغَيْرِ الْقِبْلَةِقَالَ لَوْلَا أَنِّي رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْعَلُهُ لَمْ أَفْعَلْهُ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Affan bin Muslim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Anas bin Sirin] katanya; \"Kami pernah bertemu [Anas bin Malik] ketika tiba di Syam, dan kami menemuinya di lokasi yang bernama 'Ain Tamr, aku melihat beliau shalat diatas keledai, sedangkan wajahnya menghadap ke arah tempat tersebut. Lalu Hammam mengisyaratkan ke arah kiri kiblat. Maka aku tanyakan kepadanya; \"Kenapa aku melihatmu shalat ke bukan arah kiblat? Dia menjawab; \"Sekiranya aku tidak melihat Rasulullah shallallahu 'alaihi wasallam melakukannya, tentu aku tidak akan melakukannya.\""},"1089":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَجِلَ بِهِ السَّيْرُ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya], katanya; Aku pernah menyetorkan hapalan di hadapan [Malik] dari [Nafi'] dari [Ibnu Umar] katanya; \"Ketika beliau melakukan perjalanan dengan terburu-buru, maka Rasulullah shallallahu 'alaihi wasallam menjamak antara shalat Magrib dan Isya'.\""},"1090":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ أَنَّ ابْنَ عُمَرَ كَانَ إِذَا جَدَّ بِهِ السَّيْرُ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ بَعْدَ أَنْ يَغِيبَ الشَّفَقُوَيَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا جَدَّ بِهِ السَّيْرُ جَمَعَ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] katanya; telah mengabarkan kepadaku [Nafi'] bahwa apabila [Ibnu Umar] melakukan perjalanan antara Maghrib dan Isyak', yaitu setelah mega merah menghilang, dia akan mengatakan; \"Jika Rasulullah shallallahu 'alaihi wasallam melakukan perjalanan, maka beliau menjamak antara Maghrib dan isya'.\""},"1091":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَقُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ كُلُّهُمْ عَنْ ابْنِ عُيَيْنَةَ قَالَ عَمْرٌو حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَجْمَعُ بَيْنَ الْمَغْرِبِ وَالْعِشَاءِ إِذَا جَدَّ بِهِ السَّيْرُ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Qutaibah bin Said] dan [Abu Bakar bin Abu Syaibah] dan ['Amru An Naqid], semuanya dari [Ibnu 'Uyainah]. ['Amru] berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [Ayahnya], bahwa aku pernah melihat Rasulullah shallallahu 'alaihi wasallam menjamk antara Maghrib dan Isya' jika dalam perjalanannya."},"1092":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنَ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّ أَبَاهُ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَعْجَلَهُ السَّيْرُ فِي السَّفَرِ يُؤَخِّرُ صَلَاةَ الْمَغْرِبِ حَتَّى يَجْمَعَ بَيْنَهَا وَبَيْنَ صَلَاةِ الْعِشَاءِ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] katanya; telah mengabarkan kepadaku [Salim bin Abdullah] bahwa [Ayahnya] mengatakan; \"Aku pernah melihat apabila Rasulullah shallallahu 'alaihi wasallam menyegerakan perjalanannya, beliau akan mengakhirkan shalat maghrib hingga beliau menjamak antara shalat tersebut dengan shalat isya'.\""},"1093":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُفَضَّلُ يَعْنِي ابْنَ فَضَالَةَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ارْتَحَلَ قَبْلَ أَنْ تَزِيغَ الشَّمْسُ أَخَّرَ الظُّهْرَ إِلَى وَقْتِ الْعَصْرِ ثُمَّ نَزَلَ فَجَمَعَ بَيْنَهُمَا فَإِنْ زَاغَتْ الشَّمْسُ قَبْلَ أَنْ يَرْتَحِلَ صَلَّى الظُّهْرَ ثُمَّ رَكِبَ","id":"Telah menceritakan kepada kami [Qutaibah bin Said] Telah menceritakan kepada kami [Almufadhdhal] yakni Ibnu fadhalah dari [Uqail] dari [Ibnu Syihab] dari [Anas bin Malik] katanya, Dahulu Rasulullah shallallahu 'alaihi wasallam jika melakukan safar (perjalanan) sebelum matahari miring, maka beliau mengakhirkan shalat zhuhur hingga waktu ashar, kemudian singgah dan beliau jamak antara keduanya. Namun jika melakukan perjalanan dan matahari telah miring, beliau lakuakn shalat zhuhur terlebih dahulu kemudian beliau naik kendarannya."},"1094":{"ar":"و حَدَّثَنِي عَمْرٌو النَّاقِدُ حَدَّثَنَا شَبَابَةُ بْنُ سَوَّارٍ الْمَدَايِنِيُّ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ عُقَيْلِ بْنِ خَالِدٍ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ أَنْ يَجْمَعَ بَيْنَ الصَّلَاتَيْنِ فِي السَّفَرِ أَخَّرَ الظُّهْرَ حَتَّى يَدْخُلَ أَوَّلُ وَقْتِ الْعَصْرِ ثُمَّ يَجْمَعُ بَيْنَهُمَا","id":"Dan telah menceritakan kepadaku ['Amru annqid] telah menceritakan kepada kami [Syababah bin Suwar Al madayini] telah menceritakan kepada kami [Laits bin Sa'd] dari [Uqail bin Khalid] dari [Az Zuhri] dari [Anas] katanya; \"Apabila Nabi shallallahu 'alaihi wasallam hendak menjamak antara dua shalat ketika dalam perjalanan, beliau mengakhirkan shalat zhuhur hingga awal waktu ashar, kemudian beliau menjamak antara keduanya.\""},"1095":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَعَمْرُو بْنُ سَوَّادٍ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ حَدَّثَنِي جَابِرُ بْنُ إِسْمَعِيلَ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَجِلَ عَلَيْهِ السَّفَرُ يُؤَخِّرُ الظُّهْرَ إِلَى أَوَّلِ وَقْتِ الْعَصْرِ فَيَجْمَعُ بَيْنَهُمَا وَيُؤَخِّرُ الْمَغْرِبَ حَتَّى يَجْمَعَ بَيْنَهَا وَبَيْنَ الْعِشَاءِ حِينَ يَغِيبُ الشَّفَقُ","id":"Dan telah menceritakan kepadaku [Abu Thahir] dan ['Amru bin Sawwad] keduanya berkata; telah mengabarkan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Jabir bin Ismail] dari ['Uqail] dari [Ibnu Syihab] dari [Anas] dari Nabi shallallahu 'alaihi wasallam, apabila beliau menyegerakan safarnya, maka beliau mengakhirkan shalat zhuhur hingga awal waktu ashar, lalu beliau menjamak antara keduanya, beliau juga akhirkan Maghrib hingga beliau menjamak dengan isya` sampai mega merah menghilang.\""},"1096":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ أَبِي الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍقَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ وَالْعَصْرَ جَمِيعًا وَالْمَغْرِبَ وَالْعِشَاءَ جَمِيعًا فِي غَيْرِ خَوْفٍ وَلَا سَفَرٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] katanya; Aku pernah menyetorkan hapalan kepada [Malik] dari [Abu Zubair] dari [Said bin Jubair] dari [Ibnu Abbas] katanya; Rasulullah shallallahu 'alaihi wasallam pernah shalat zhuhur dan ashar semuanya, dan antara Maghrib dan Isya' semuanya bukan karena ketakutan dan tidak pula ketika safar.\""},"1097":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ وَعَوْنُ بْنُ سَلَّامٍ جَمِيعًا عَنْ زُهَيْرٍ قَالَ ابْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍقَالَ صَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الظُّهْرَ وَالْعَصْرَ جَمِيعًا بِالْمَدِينَةِ فِي غَيْرِ خَوْفٍ وَلَا سَفَرٍقَالَ أَبُو الزُّبَيْرِ فَسَأَلْتُ سَعِيدًا لِمَ فَعَلَ ذَلِكَ فَقَالَ سَأَلْتُ ابْنَ عَبَّاسٍ كَمَا سَأَلْتَنِي فَقَالَ أَرَادَ أَنْ لَا يُحْرِجَ أَحَدًا مِنْ أُمَّتِهِ","id":"Dan telah menceritakan kepada kami [Ahmad bin Yunus] dan ['Aun bin Salam] semuanya dari [Zuhair]. [Ibnu Yunus] mengatakan; telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Zubair] dari [Said bin Jubair] dari [Ibnu Abbas] katanya; Rasulullah shallallahu 'alaihi wasallam pernah shalat Zhuhur dan Ashar sekaligus di Madinah bukan karena takut dan bukan pula karena safar.\" [Abu Zubair] mengatakan; \"Aku bertanya kepada [Sa'id]; \"Mengapa beliau melakukan hal itu? Dia menjawab; Aku bertanya kepada [Ibnu Abbas] sebagaimana kamu bertanya kepadaku, lalu dia menjawab; \"Beliau ingin supaya tidak merepotkan (memberatkan) seorangpun dari umatnya.\""},"1098":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا قُرَّةُ حَدَّثَنَا أَبُو الزُّبَيْرِ حَدَّثَنَا سَعِيدُ بْنُ جُبَيْرٍ حَدَّثَنَا ابْنُ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَ الصَّلَاةِ فِي سَفْرَةٍ سَافَرَهَا فِي غَزْوَةِ تَبُوكَ فَجَمَعَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِقَالَ سَعِيدٌ فَقُلْتُ لِابْنِ عَبَّاسٍ مَا حَمَلَهُ عَلَى ذَلِكَ قَالَ أَرَادَ أَنْ لَا يُحْرِجَ أُمَّتَهُ","id":"Telah menceritakan kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] telah menceritakan kepada kami [Qurrah] telah menceritakan kepada kami [Abu Zubair] telah menceritakan kepada kami [Said bin Jubair] telah menceritakan kepada kami [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menjamak shalat dalam safar ketika perang tabuk, beliau menjamak antara zhuhur dan ashar, maghrib dan isya`, \" [Said] berkata; lalu aku berkata kepada [Ibnu Abbas]; \"Apa yang mendorong beliau melakukan hal itu? Dia menjawab; \"Beliau ingin supaya tidak memberatkan umatnya.\""},"1099":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ أَبِي الطُّفَيْلِ عَامِرٍ عَنْ مُعَاذٍ قَالَخَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ فَكَانَ يُصَلِّي الظُّهْرَ وَالْعَصْرَ جَمِيعًا وَالْمَغْرِبَ وَالْعِشَاءَ جَمِيعًا","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Zubair] dari [Abu Thufail Amir] dari [Mu'adz] katanya; \"Kami berangkat bersama Rasulullah shallallahu 'alaihi wasallam ketika perang Tabuk, lalu beliau melakukan shalat zhuhur dan ashar sekaligus, maghrib dan isya` sekaligus.\""},"1100":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا قُرَّةُ بْنُ خَالِدٍ حَدَّثَنَا أَبُو الزُّبَيْرِ حَدَّثَنَا عَامِرُ بْنُ وَاثِلَةَ أَبُو الطُّفَيْلِ حَدَّثَنَا مُعَاذُ بْنُ جَبَلٍ قَالَجَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَبَيْنَ الْمَغْرِبِ وَالْعِشَاءِقَالَ فَقُلْتُ مَا حَمَلَهُ عَلَى ذَلِكَ قَالَ فَقَالَ أَرَادَ أَنْ لَا يُحْرِجَ أُمَّتَهُ","id":"Telah menceritakan kepada kami [Yahya bin Habib] telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits] telah menceritakan kepada kami [Qurrah bin Khalid] telah menceritakan kepada kami [Abu Zubair] telah menceritakan kepada kami ['Amir bin Watsilah Abu Thufail] telah menceritakan kepada kami [Muadz bin Jabal] katanya; \"Ketika perang Tabuk, Rasulullah shallallahu 'alaihi wasallam pernah menjamak antara zhuhur dan ashar, antara maghrib dan isya'.\" 'Amir berkata; lalu aku bertanya kepadanya; \"Apa yang mendorong beliau melakukan hal itu? Mu'adz menjawab; \"Beliau ingin supaya tidak memberatkan umatnya.\""},"1101":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا أَبُو كُرَيْبٍ وَأَبُو سَعِيدٍ الْأَشَجُّ وَاللَّفْظُ لِأَب��ي كُرَيْبٍ قَالَا حَدَّثَنَا وَكِيعٌ كِلَاهُمَا عَنْ الْأَعْمَشِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَجَمَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِ بِالْمَدِينَةِ فِي غَيْرِ خَوْفٍ وَلَا مَطَرٍفِي حَدِيثِ وَكِيعٍ قَالَ قُلْتُ لِابْنِ عَبَّاسٍ لِمَ فَعَلَ ذَلِكَ قَالَ كَيْ لَا يُحْرِجَ أُمَّتَهُ وَفِي حَدِيثِ أَبِي مُعَاوِيَةَ قِيلَ لِابْنِ عَبَّاسٍ مَا أَرَادَ إِلَى ذَلِكَ قَالَ أَرَادَ أَنْ لَا يُحْرِجَ أُمَّتَهُ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Abu Muawiyah] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Kuraib] dan [Abu Said Al Asyajj] sedangkan lafadznya milik Abu Kuraib, keduanya berkata; telah menceritakan kepada kami [Waki'], keduanya dari [Al A'masy] dari [Habib bin Abu Tsabit] dari [Said bin Jubair] dari [Ibnu Abbas] katanya; \"Rasulullah shallallahu 'alaihi wasallam pernah menjamak antara zhuhur dan ashar, maghrib dan isya` di Madinah, bukan karena ketakutan dan bukan pula karena hujan.\" Dalam hadis Waki', katanya; aku tanyakan kepada Ibnu Abbas; \"Mengapa beliau lakukan hal itu?\" Dia menjawab; \"Beliau ingin supaya tidak memberatkan umatnya.\""},"1102":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرٍو عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيًا جَمِيعًا وَسَبْعًا جَمِيعًا قُلْتُ يَا أَبَا الشَّعْثَاءِ أَظُنُّهُ أَخَّرَ الظُّهْرَ وَعَجَّلَ الْعَصْرَ وَأَخَّرَ الْمَغْرِبَ وَعَجَّلَ الْعِشَاءَ قَالَ وَأَنَا أَظُنُّ ذَاكَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amru] dari [Jabir bin Zaid] dari [Ibnu Abbas], katanya; \"Aku pernah shalat bersama Nabi shallallahu 'alaihi wasallam delapan rakaat sekaligus, dan tujuh raka'at sekaligus.\" Lalu aku bertanya; \"Wahai Abu Sya'tsa', setahuku beliau mengakhirkan zhuhur dan menyegerakan ashar, dan beliau mengakhirkan maghrib dan menyegerakan isya`.\" Kata Abu Sya'tsa', setahuku juga seperti itu.\""},"1103":{"ar":"و حَدَّثَنَا أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِالْمَدِينَةِ سَبْعًا وَثَمَانِيًا الظُّهْرَ وَالْعَصْرَ وَالْمَغْرِبَ وَالْعِشَاءَ","id":"Dan telah menceritakan kepada kami [Abu Rabi' Az Zahrani] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Jabir bin Zaid] dari [Ibnu Abbas], bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat tujuh dan delapan rakaat, zhuhur dan ashar, maghrib dan isya` ketika di Madinah.\""},"1104":{"ar":"و حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادٌ عَنْ الزُّبَيْرِ بْنِ الْخِرِّيتِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ خَطَبَنَا ابْنُ عَبَّاسٍ يَوْمًا بَعْدَ الْعَصْرِ حَتَّى غَرَبَتْ الشَّمْسُ وَبَدَتْ النُّجُومُ وَجَعَلَ النَّاسُ يَقُولُونَ الصَّلَاةَ الصَّلَاةَ قَالَ فَجَاءَهُ رَجُلٌ مِنْ بَنِي تَمِيمٍ لَا يَفْتُرُ وَلَا يَنْثَنِي الصَّلَاةَ الصَّلَاةَفَقَالَ ابْنُ عَبَّاسٍ أَتُعَلِّمُنِي بِالسُّنَّةِ لَا أُمَّ لَكَ ثُمَّ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَمَعَ بَيْنَ الظُّهْرِ وَالْعَصْرِ وَالْمَغْرِبِ وَالْعِشَاءِقَالَ عَبْدُ اللَّهِ بْنُ شَقِيقٍ فَحَاكَ فِي صَدْرِي مِنْ ذَلِكَ شَيْءٌ فَأَتَيْتُ أَبَا هُرَيْرَةَ فَسَأَلْتُهُ فَصَدَّقَ مَقَالَتَهُ","id":"Dan telah menceritakan kepadaku [Abu Rabi' Az Zahrani] telah menceritakan kepada kami [Hammad] dari [Zubair bin Khirrit] dari [Abdullah bin Syaqiq] katanya; Suatu hari [Ibnu Abbas] pernah berpidato di hadapan kami, yaitu setelah ashar hingga matahari terbenam dan bintang-bintang mulai bermunculan, maka orang-orang berseru; \"Shalat, shalat!\" Tidak lama kemudian seorang laki-laki bani Tamim, seorang yang tak pernah loyo dan juga tak pernah malas datang; \"Shalat, shalat.\" Ibnu Abbas berkata; \"Apakah engkau hendak mengajariku sunnah, celaka kamu! Selanjutnya dia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam menjamak antara Zhuhur dan Ashar, Maghrib dan Isya'.\" [Abdullah bin Syaqiq] berkata; Maka dalam hatiku ada sesuatu yang mengganjal, sehingga aku menemui [Abu Hurairah] dan kutanyakan masalah ini kepadanya, ternyata ia membenarkan ucapan Ibnu Abbas."},"1105":{"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا عِمْرَانُ بْنُ حُدَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ الْعُقَيْلِيِّ قَالَقَالَ رَجُلٌ لِابْنِ عَبَّاسٍ الصَّلَاةَ فَسَكَتَ ثُمَّ قَالَ الصَّلَاةَ فَسَكَتَ ثُمَّ قَالَ الصَّلَاةَ فَسَكَتَ ثُمَّ قَالَ لَا أُمَّ لَكَ أَتُعَلِّمُنَا بِالصَّلَاةِ وَكُنَّا نَجْمَعُ بَيْنَ الصَّلَاتَيْنِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Imran bin Hudair] dari [Abdullah bin Syaqiq Al 'Uqaili] katanya; \"Seorang laki-laki pernah mengatakan kepada [Ibnu Abbas]; \"Shalat, shalat.\" Ibnu Abbas pun diam. laki-laki itu berkata lagi; \"Shalat!\" Ibnu Abbas kembali diam. laki-laki itu berkata; \"Shalat!\" Ibnu Abbas kembali diam. Kemudian Ibnu Abbas berkata; \"Apakah kamu hendak mengajari kami shalat? Padahal kami pernah menjamak antara dua shalat di masa Rasulullah shallallahu 'alaihi wasallam.\""},"1106":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَوَكِيعٌ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِ قَالَلَا يَجْعَلَنَّ أَحَدُكُمْ لِلشَّيْطَانِ مِنْ نَفْسِهِ جُزْءًا لَا يَرَى إِلَّا أَنَّ حَقًّا عَلَيْهِ أَنْ لَا يَنْصَرِفَ إِلَّا عَنْ يَمِينِهِ أَكْثَرُ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْصَرِفُ عَنْ شِمَالِهِحَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ وَعِيسَى بْنُ يُونُسَ ح و حَدَّثَنَاه عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى جَمِيعًا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bukair bin Abu Syaibah] telah menceritakan kepada kami [Abu Muawiyah] dan [Waki'] dari [Al A'masy] dari ['Umarah] dari [Al Aswad] dari [Abdullah] katanya; \"Janganlah salah seorang dari kalian memberi peluang sedikitpun kepada setan untuk menggangu shalatnya, bahwa tidak boleh seseorang beranjak pergi kecuali dari sebelah kanannya, dan tidaklah aku melihat Nabi shallallahu 'alaihi wasallam beranjak pergi dari sebelah kirinya.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dan [Isa bin Yunus] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ali bin Khasyram] telah mengabarkan kepada kami [Isa], semuanya dari [Al A'masy] dengan sanad seperti ini."},"1107":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ السُّدِّيِّ قَالَسَأَلْتُ أَنَسًا كَيْفَ أَنْصَرِفُ إِذَا صَلَّيْتُ عَنْ يَمِينِي أَوْ عَنْ يَسَارِي قَالَ أَمَّا أَنَا فَأَكْثَرُ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْصَرِفُ عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Said] telah menceritakan kepada kami [Abu 'Awanah] dari [As Sudi], katanya; \"Aku pernah bertanya kepada [Anas]; \"Bagaimana seharusnya aku melakukan ketika beranjak pergi dari shalat, aku beranjak ke sebelah kanan ataukah kiri?\" dia menjawab; \"Kebanyakan aku melihat Rasulullah shallallahu 'alaihi wasallam beranjak dari sebelah kanannya.\""},"1108":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ السُّدِّيِّ عَنْ أَنَسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَنْصَرِفُ عَنْ يَمِينِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [As Sudi] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam meninggalkan shalat dari sebelah kanan.\""},"1109":{"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ أَبِي زَائِدَةَ عَنْ مِسْعَرٍ عَنْ ثَابِتِ بْنِ عُبَيْدٍ عَنْ ابْنِ الْبَرَاءِ عَنْ الْبَرَاءِ قَالَكُنَّا إِذَا صَلَّيْنَا خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحْبَبْنَا أَنْ نَكُونَ عَنْ يَمِينِهِ يُقْبِلُ عَلَيْنَا بِوَجْهِهِ قَالَ فَسَمِعْتُهُ يَقُولُ رَبِّ قِنِي عَذَابَكَ يَوْمَ تَبْعَثُ أَوْ تَجْمَعُ عِبَادَكَو حَدَّثَنَاه أَبُو كُرَيْبٍ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ مِسْعَرٍ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرْ يُقْبِلُ عَلَيْنَا بِوَجْهِهِ","id":"Dan telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Abu Zaidah] dari [Mis'ar] dari [Tsabit bin 'Ubaid] dari [Ibnu Al Barra`] dari [Al Barra`] katanya; \"Jika kami shalat di belakang Rasulullah shallallahu 'alaihi wasallam, maka kami menyukai jika berada di sebelah kanan beliau, sehingga beliau menghadap kami dengan wajahnya.\" Al Barra` mengatakan; \"Aku mendengar beliau mengucapkan doa \"RABBI QINII 'ADZAABAKA YAUMA TAB'ATSU AW TAJMA'U IBADAADAKA (Ya Tuhanku, jagalah aku dari siksa-Mu ketika Engkau bangkitkan atau ketika Engkau kumpulkan hamba-hamba-Mu).\" Telah menceritakan kepada kami [Abu Kuraib] dan [Zuhair bin Harb] keduanya berkata; telah menceritakan kepada kami [Waki'] dari [Mis'ar] dengan sanad seperti ini, namun dia tidak menyebutkan redaksi \"Dan beliau menghadap kami dengan wajahnya.\""},"1110":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ حَنْبَلٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ وَرْقَاءَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُو حَدَّثَنِيهِ مُحَمَّدُ بْنُ حَاتِمٍ وَابْنُ رَافِعٍ قَالَا حَدَّثَنَا شَبَابَةُ حَدَّثَنِي وَرْقَاءُ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Ahmad bin Hanbal] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Warqa'] dari ['Amru bin Dinar] dari ['Atha` bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika iqamat telah dikumandangkan, maka tak ada shalat selain shalat wajib.\" Telah menceritakan kepada kami [Muhammad bin Hatim] dan [Ibnu Rafi'] keduanya berkata; telah menceritakan kepada kami [Syababah] telah menceritakan kepadaku [Warqa'] dengan sanad seperti ini."},"1111":{"ar":"و حَدَّثَنِي يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا رَوْحٌ حَدَّثَنَا زَكَرِيَّاءُ بْنُ إِسْحَقَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ قَالَ سَمِعْتُ عَطَاءَ بْنَ يَسَارٍ يَقُولُ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِذَا أُقِيمَتْ الصَّلَاةُ فَلَا صَلَاةَ إِلَّا الْمَكْتُوبَةُو حَدَّثَنَاه عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا زَكَرِيَّاءُ بْنُ إِسْحَقَ بِهَذَا الْإِسْنَادِ مِثْلَهُ و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ قَالَ حَمَّادٌ ثُمَّ لَقِيتُ عَمْرًا فَحَدَّثَنِي بِهِ وَلَمْ يَرْفَعْهُ","id":"Dan telah menceritakan kepadaku [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Zakariya bin Ishaq] telah menceritakan kepada kami ['Amru bin Dinar] katanya; aku mendengar ['Atha` bin Yasar] mengatakan dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jika iqamat telah dikumandangkan, maka tidak ada shalat selain shalat wajib.\" Telah menceritakan kepada kami [Abd bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Zakariya bin Ishaq] dengan sanad seperti ini. Telah menceritakan kepada kami [Hasan Al Hulwani] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hammad bin Zaid] dari [Ayyub] dari ['Amru bin Dinar] dari [Atha` bin Yasar] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. [Hammad] mengatakan; \"Aku pernah menemui ['Amr], lalu dia Menceritakan kepadaku, namun dia tidak memarfu'kannya."},"1112":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ ابْنِ بُحَيْنَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَرَّ بِرَجُلٍ يُصَلِّي وَقَدْ أُقِيمَتْ صَلَاةُ الصُّبْحِ فَكَلَّمَهُ بِشَيْءٍ لَا نَدْرِي مَا هُوَ فَلَمَّا انْصَرَفْنَا أَحَطْنَا نَقُولُ مَاذَا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ لِي يُوشِكُ أَنْ يُصَلِّيَ أَحَدُكُمْ الصُّبْحَ أَرْبَعًاقَالَ الْقَعْنَبِيُّ عَبْدُ اللَّهِ بْنُ مَالِكٍ ابْنُ بُحَيْنَةَ عَنْ أَبِيهِ قَالَ أَبُو الْحُسَيْنِ مُسْلِمٌ وَقَوْلُهُ عَنْ أَبِيهِ فِي هَذَا الْحَدِيثِ خَطَأٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] telah menceritakan kepada kami [Ibrahim bin Sa'd] dari [Ayahnya] dari [Hafs bin 'Ashim] dari [Abdullah bin Malik bin Buhainah] bahwa Rasulullah shallallahu 'alaihi wasallam suatu kali pernah melewati seseorang yang shalat, padahal shalat subuh telah diiqamati. Maka beliau bersabda dengan ucapan yang kami tidak di mengerti. Ketika kami selesai, maka kami bertanya kepadanya; \"Apa yang telah diucapkan Rasulullah shallallahu 'alaihi wasallam kepadamu?\" Dia menjawab; \"Beliau tadi mengucapkan kepadaku \"Nyaris salah seorang dari kalian melakukan shalat subuh sebanyak empat rakaat.\" Al Qa'nabi Abdullah bin Malik bin Buhainah berkata dari ayahnya, namun Abul Hasan Muslim berkata; \"Dan perkataan dari ayahnya dalam hadis ini adalah salah.\""},"1113":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ حَفْصِ بْنِ عَاصِمٍ عَنْ ابْنِ بُحَيْنَةَ قَالَأُقِيمَتْ صَلَاةُ الصُّبْحِ فَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا يُصَلِّي وَالْمُؤَذِّنُ يُقِيمُ فَقَالَ أَتُصَلِّي الصُّبْحَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Qutaibah bin Said] telah menceritakan kepada kami [Abu 'Awanah] dari [Said bin Ibrahim] dari [Hafs bin 'Ashim] dari [Ibnu Buhainah] katanya; \"Ketika shalat subuh telah diiqamati, Rasulullah shallallahu 'alaihi wasallam melihat seseorang yang sedang shalat padahal muadzin telah qamat, maka beliau menegurnya: \"Apakah kamu shalat subuh empat raka'at?\""},"1114":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ ح و حَدَّثَنِي حَامِدُ بْنُ عُمَرَ الْبَكْرَاوِيُّ حَدَّثَنَا عَبْدُ الْوَاحِدِ يَعْنِي ابْنَ زِيَادٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ كُلُّهُمْ عَنْ عَاصِمٍ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لَهُ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ الْفَزَارِيُّ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ عَبْدِ اللَّهِ بْنِ سَرْجِسَ قَالَ دَخَلَرَجُلٌ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاةِ الْغَدَاةِ فَصَلَّى رَكْعَتَيْنِ فِي جَانِبِ الْمَسْجِدِ ثُمَّ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا سَلَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا فُلَانُ بِأَيِّ الصَّلَاتَيْنِ اعْتَدَدْتَ أَبِصَلَاتِكَ وَحْدَكَ أَمْ بِصَلَاتِكَ مَعَنَا","id":"Telah menceritakan kepada kami [Abu Al Kamil Al Jahdari] telah menceritakan kepada kami [Hammad yaitu Ibnu Zaid] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Hamid bin Umar Al Bakrawi] telah menceritakan kepada kami [Abdul Wahid yaitu Ibnu Ziyad], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abu Muawiyah], semuanya dari ['Ashim], (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Zuhair bin Harb] sedangkan lafadznya dari dia, telah menceritakan kepada kami [Marwan bin Muawiyah Al Fizari] dari ['Ashim Al Ahwal] dari [Abdullah bin Sarjisa] katanya; \"Ketika Rasulullah shallallahu 'alaihi wasallam sedang shalat subuh, tiba-tiba seorang laki-laki masuk masjid dan melakukan shalat (sunnah) dua rakaat disamping masjid, setelah itu dia bergegas menyertai Rasulullah shallallahu 'alaihi wasallam. Ketika Rasulullah shallallahu 'alaihi wasallam mengucapkan salam, beliau bersabda: \"Wahai Fulan, shalat manakah yang kamu persiapkan, apakah shalatmu dengan sendiri ataukah bersama kami?.\""},"1115":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدٍ عَنْ أَبِي حُمَيْدٍ أَوْ عَنْ أَبِي أُسَيْدٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَقُلْ اللَّهُمَّ افْتَحْ لِي أَبْوَابَ رَحْمَتِكَ وَإِذَا خَرَجَ فَلْيَقُلْ اللَّهُمَّ إِنِّي أَسْأَلُكَ مِنْ فَضْلِكَقَالَ مُسْلِم سَمِعْتُ يَحْيَى بْنَ يَحْيَى يَقُولُ كَتَبْتُ هَذَا الْحَدِيثَ مِنْ كِتَابِ سُلَيْمَانَ بْنِ بِلَالٍ قَالَ بَلَغَنِي أَنَّ يَحْيَى الْحِمَّانِيَّ يَقُولُا وَأَبِي أُسَيْدٍ و حَدَّثَنَا حَامِدُ بْنُ عُمَرَ الْبَكْرَاوِيُّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عُمَارَةُ بْنُ غَزِيَّةَ عَنْ رَبِيعَةَ بْنِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَبْدِ الْمَلِكِ بْنِ سَعِيدِ بْنِ سُوَيْدٍ الْأَنْصَارِيِّ عَنْ أَبِي حُمَيْدٍ أَوْ عَنْ أَبِي أُسَيْدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Sulaiman bin Bilal] dari [Rabi'ah bin Abdurrahman] dari [Abdul Malik bin Sa'id] dari [Abu Humaid] atau dari [Abu Usaid] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"jika salah seorang diantara kalin masuk masjid, bacalah doa ALLAAHUMMAFTAH LII ABWAABA RAHMATIKA (Ya Allah, bukalah pintu-pintu rahmat-Mu).\" Dan apabila keluar, hendaknya ia membaca doa ALLAAHUMMA INNII AS`ALUKA MIN FADHLIKA (Ya Allah, aku meminta kurnia-Mu).\" Muslim berkata; Aku mendengar [Yahya bin Yahya] mengatakan; \"Aku menulis hadis ini dari kitab Sulaiman bin Bilal, katanya; telah sampai berita kepadaku bahwa [Yahya Al Himmani] mengatakan; dan [Abu Usaid], telah menceritakan kepada kami [Hamid bin Umar Al Bakrawi] telah menceritakan kepada kami [Bisyr bin Al Mufadlal] telah menceritakan kepada kami ['Umarah bin Ghaziyyah] dari [Rabi'ah bin Abdurrahman] dari [Abdul Malik bin Sa'id bin Suwaid Al Anshari] dari [Abu Humaid] atau [Abu Usaid] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini."},"1116":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا مَالِكٌ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ عَامِرِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ الزُّرَقِيِّ عَنْ أَبِي قَتَادَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلْيَرْكَعْ رَكْعَتَيْنِ قَبْلَ أَنْ يَجْلِسَ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] dan [Qutaibah bin Said] keduanya berkata; telah menceritakan kepada kami [Malik] (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Yahya bin Yahya] katanya; Aku pernah menyetorkan hapalan kepada [Malik] dari [Amir bin Abdullah bin Zubair] dari ['Amru bin Sulaim Az Zuraqi] dari [Abu Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang diantara kalian masuk masjid, shalatlah dua rakaat sebelum duduk.\""},"1117":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ عَنْ زَائِدَةَ قَالَ حَدَّثَنِي عَمْرُو بْنُ يَحْيَى الْأَنْصَارِيُّ حَدَّثَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ عَنْ عَمْرِو بْنِ سُلَيْمِ بْنِ خَلْدَةَ الْأَنْصَارِيِّ عَنْ أَبِي قَتَادَةَ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَدَخَلْتُ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسٌ بَيْنَ ظَهْرَانَيْ النَّاسِ قَالَ فَجَلَسْتُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مَنَعَكَ أَنْ تَرْكَعَ رَكْعَتَيْنِ قَبْلَ أَنْ تَجْلِسَ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ رَأَيْتُكَ جَالِسًا وَالنَّاسُ جُلُوسٌ قَالَ فَإِذَا دَخَلَ أَحَدُكُمْ الْمَسْجِدَ فَلَا يَجْلِسْ حَتَّى يَرْكَعَ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Husain bin Ali] dari [Zaidah] katanya; telah menceritakan kepadaku ['Amru bin Yahya Al Anshari] telah menceritakan kepadaku [Muhammad bin Yahya bin Habban] dari ['Amru bin Sulaim bin Khaldah Al Anshari] dari [Abu Qatadah] -salah seorang sahabat Rasulullah shallallahu 'alaihi wasallam- katanya; \"Aku masuk masjid ketika Rasulullah shallallahu 'alaihi wasallam duduk ditengah kerumuan para sahabat. Abu Qatadah melanjutkan; \"Maka aku langsung duduk. Ketika melihatku, Rasulullah shallallahu 'alaihi wasallam bersabda; \"Apa yang menghalangimu untuk melakukan dua rakaat sebelum duduk?\" Aku berkata; \"Wahai Rasulullah, aku melihat engkau telah duduk dan orang-orang juga duduk. Beliau bersabda: \"Jika salah sorang diantara kalian masuk masjid, janganlah ia duduk hingga melakukan dua raka'at.\""},"1118":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ جَوَّاسٍ الْحَنَفِيُّ أَبُو عَاصِمٍ حَدَّثَنَا عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ عَنْ سُفْيَانَ عَنْ مُحَارِبِ بْنِ دِثَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ لِي عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَيْنٌ فَقَضَانِي وَزَادَنِي وَدَخَلْتُ عَلَيْهِ الْمَسْجِدَ فَقَالَ لِي صَلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Ahmad bin Jawwash Al Hanafi Abu 'Ashim] telah menceritakan kepada kami ['Ubaidullah Al Asyja'i] dari [Sufyan] dari [Muharib bin Ditsar] dari [Jabir bin Abdullah] katanya; Nabi shallallahu 'alaihi wasallam pernah mempunyai hutang kepadaku, maka beliau melunasiku dan bahkan memberiku tambahan. Setelah aku masuk masjid menemuinya, tiba-tiba beliau bersabda: \"Shalatlah dua rakaat.\""},"1119":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ مُحَارِبٍ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُااشْتَرَى مِنِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعِيرًا فَلَمَّا قَدِمَ الْمَدِينَةَ أَمَرَنِي أَنْ آتِيَ الْمَسْجِدَ فَأُصَلِّي رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Muadz] telah menceritakan kepada kami [ayahku] telah menceritakan kepada kami [Syu'bah] dari [Muharib] dia mendnegar [Jabir bin Abdullah] mengatakan; \"Rasulullah shallallahu 'alaihi wasallam pernah membeli untaku, setibanya di Madinah, beliau menyuruhku untuk mendatangi masjid, lalu aku shalat dua rakaat.\""},"1120":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِي الثَّقَفِيَّ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَخَرَجْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَأَبْطَأَ بِي جَمَلِي وَأَعْيَا ثُمَّ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلِي وَقَدِمْتُ بِالْغَدَاةِ فَجِئْتُ الْمَسْجِدَ فَوَجَدْتُهُ عَلَى بَابِ الْمَسْجِدِ قَالَ الْآنَ حِينَ قَدِمْتَ قُلْتُ نَعَمْ قَالَ فَدَعْ جَمَلَكَ وَادْخُلْ فَصَلِّ رَكْعَتَيْنِ قَالَ فَدَخَلْتُ فَصَلَّيْتُ ثُمَّ رَجَعْتُ","id":"Telah menceritakan kepadaku [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab yaitu Ats Tsaqafi] telah menceritakan kepada kami ['Ubidullah] dari [Wahab bin Kisan] dari [Jabir bin Abdullah] katanya; \"Aku pernah berangkat bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu peperangan. Ternyata untaku berjalan sangat pelan karena keletihan. Rasululullah shallallahu 'alaihi wasallam tiba sebelumku, sedang aku tiba di waktu sore, lantas aku langsung mendatangi masjid dan aku menemui beliau, ketika itu beliau berada di pintu masjid. beliau bersabda: \"Apakah kamu baru datang?\" Aku menjawab; \"Benar.\" Beliau bersabda: \"Tinggalkanlah untamu, masuklah ke dalam masjid, dan lakukanlah shalat dua rakaat.\" Jabir berkata; \"Maka aku masuk masjid, lalu aku shalat dan pulang.\""},"1121":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا الضَّحَّاكُ يَعْنِي أَبَا عَاصِمٍ ح و حَدَّثَنِي مَحْمُودُ بْنُ غَيْلَانَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَا جَمِيعًا أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ شِهَابٍ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَبْدِ اللَّهِ بْنِ كَعْبٍ أَخْبَرَهُ عَنْ أَبِيهِ عَبْدِ اللَّهِ بْنِ كَعْبٍ وَعَنْ عَمِّهِ عُبَيْدِ اللَّهِ بْنِ كَعْبٍ عَنْ كَعْبِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَقْدَمُ مِنْ سَفَرٍ إِلَّا نَهَارًا فِي الضُّحَى فَإِذَا قَدِمَ بَدَأَ بِالْمَسْجِدِ فَصَلَّى فِيهِ رَكْعَتَيْنِ ثُمَّ جَلَسَ فِيهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Adl Dlahak yaitu Abu 'Ashim] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Mahmud bin Ghailan] telah menceritakan kepada kami [Abdurrazak] keduanya berkata; telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ibnu Syihab] bahwa [Abdurrahman bin Abdullah bin Ka'b] mengabarkan kepadanya, dari ayahnya yaitu [Abdullah bin Ka'b] dan dari pamannya yaitu ['Ubaidullah bin Ka'b] dari [Ka'b bin Malik], bahwa Rasulullah shallallahu 'alaihi wasallam tidak pernah tiba dari bepergian, melainkan pada siang hari ketika waktu dluha. Jika beliau tiba, maka beliau terlebih dahulu singgah di masjid dan melakukan shalat dua rakaat, kemudian beliau duduk.\""},"1122":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَقُلْتُ لِعَائِشَةَ هَلْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى قَالَتْ لَا إِلَّا أَنْ يَجِيءَ مِنْ مَغِيبِهِ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yazid bin Zurai'] dari [Said Al Jurairi] dari [Abdullah bin Syaqiq], katanya; \"Aku berkata kepada ['Aisyah]; \"Apakah Nabi shallallahu 'alaihi wasallam pernah shalat dhuha?\" Aisyah menjawab; \"Tidak pernah, kecuali jika beliau tiba dari safarnya.\""},"1123":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا كَهْمَسُ بْنُ الْحَسَنِ الْقَيْسِيُّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَقُلْتُ لِعَائِشَةَ أَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى قَالَتْ لَا إِلَّا أَنْ يَجِيءَ مِنْ مَغِيبِهِ","id":"Dan telah menceritakan kepada kami ['Ubaidullah bin Muadz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Kahmas bin Al Hasan Al Qaisi] dari [Abdullah bin Syaqiq] katanya; \"Aku bertanya kepada ['Aisyah] \"Apakah Nabi shallallahu 'alaihi wasallam pernah shalat dhuha? Dia menjawab; \"Tidak, kecuali jika beliau pulang dari bepergian.\""},"1124":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي سُبْحَةَ الضُّحَى قَطُّ وَإِنِّي لَأُسَبِّحُهَا وَإِنْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَدَعُ الْعَمَلَ وَهُوَ يُحِبُّ أَنْ يَعْمَلَ بِهِ خَشْيَةَ أَنْ يَعْمَلَ بِهِ النَّاسُ فَيُفْرَضَ عَلَيْهِمْ","id":"Telah menceritakan kepada kami [Yahya bin Yahya], katanya; aku pernah menyetorkan hapalan kepada [Malik] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah], katanya; \"Sama sekali belum pernah aku melihat Rasulullah shallallahu 'alaihi wasallam melakukan shalat sunnah dhuha, namun aku melakukan shalat sunnah dhuha. Rasulullah shallallahu 'alaihi wasallam meninggalkan amalan yang sebenarnya beliau suka melakukannya, karena beliau khawatir jangan-jangan para sahabat menirunya sehingga amalan itu diwajibkan.\""},"1125":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا يَزِيدُ يَعْنِي الرِّشْكَ حَدَّثَتْنِي مُعَاذَةُ أَنَّهَا سَأَلَتْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَاكَمْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي صَلَاةَ الضُّحَى قَالَتْ أَرْبَعَ رَكَعَاتٍ وَيَزِيدُ مَا شَاءَحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ يَزِيدَ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ يَزِيدُ مَا شَاءَ اللَّهُ","id":"Telah menceritakan kepada kami [Syaiban bin Farukh] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Yazid yaitu Yazid Ar Risyk] telah menceritakan kepadaku [Ma'adzah], ia pernah bertanya kepada ['Aisyah] Radhiyallahu'anha; \"Berapa raka'atkah Rasulullah shallallahu 'alaihi wasallam melakukan shalat (sunnah) dhuha?\" Aisyah menjawab; \"Empat raka'at, namun terkadang beliau menambah sekehendaknya.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Yazid] dengan sanad seperti ini, Yazid mengatakan; \"Sekehendak Allah.\" (bukan sekehehdaknya -pent)."},"1126":{"ar":"و حَدَّثَنِي يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ عَنْ سَعِيدٍ حَدَّثَنَا قَتَادَةُ أَنَّ مُعَاذَةَ الْعَدَوِيَّةَ حَدَّثَتْهُمْ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى أَرْبَعًا وَيَزِيدُ مَا شَاءَ اللَّهُو حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ بَشَّارٍ جَمِيعًا عَنْ مُعَاذِ بْنِ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepadaku [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Al Harits] dari [Said], telah menceritakan kepada kami [Qatadah], bahwa [Ma'adzah Al 'Adawiyah] menceritakan kepada mereka dari ['Aisyah] katanya; Rasulullah shallallahu 'alaihi wasallam pernah melakukan shalat dhuha sebanyak empat rakaat, dan terkadang beliau menambah sekehendak Allah.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ibnu Basyar], semuanya dari [Mu'adz bin Hisyam] katanya; telah menceritakan kepadaku [Ayahku] dari [Qatadah] dengan sanad seperti ini."},"1127":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَمَا أَخْبَرَنِي أَحَدٌ أَنَّهُ رَأَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الضُّحَى إِلَّا أُمُّ هَانِئٍ فَإِنَّهَا حَدَّثَتْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ بَيْتَهَا يَوْمَ فَتْحِ مَكَّةَ فَصَلَّى ثَمَانِي رَكَعَاتٍ مَا رَأَيْتُهُ صَلَّى صَلَاةً قَطُّ أَخَفَّ مِنْهَا غَيْرَ أَنَّهُ كَانَ يُتِمُّ الرُّكُوعَ وَالسُّجُودَوَلَمْ يَذْكُرْ ابْنُ بَشَّارٍ فِي حَدِيثِهِ قَوْلَهُ قَطُّ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Murrah] dari [Abdurrhman bin Abu Laila] katanya; \"Tidak ada seorangpun yang mengabariku bahwa ia melihat Nabi shallallahu 'alaihi wasallam melakukan shalat dhuha, selain [Ummu Hani`], dialah yang menceritakan bahwa Nabi shallallahu 'alaihi wasallam pernah masuk rumahnya ketika Penaklukan kota Makkah, lalu beliau shalat delapan rakaat, dan aku belum pernah melihat beliau melakukan shalat yang lebih ringan daripada shalat ketika itu, beliau menyempurnakan rukuk dan sujudnya.\" Namun dalam haditsnya, Ibnu Basyar tidak menyebutkan ucapannya sama sekali."},"1128":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي ابْنُ عَبْدِ اللَّهِ بْنِ الْحَارِثِ أَنَّ أَبَاهُ عَبْدَ اللَّهِ بْنَ الْحَارِثِ بْنِ نَوْفَلٍ قَالَسَأَلْتُ وَحَرَصْتُ عَلَى أَنْ أَجِدَ أَحَدًا مِنْ النَّاسِ يُخْبِرُنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَّحَ سُبْحَةَ الضُّحَى فَلَمْ أَجِدْ أَحَدًا يُحَدِّثُنِي ذَلِكَ غَيْرَ أَنَّ أُمَّ هَانِئٍ بِنْتَ أَبِي طَالِبٍ أَخْبَرَتْنِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى بَعْدَ مَا ارْتَفَعَ النَّهَارُ يَوْمَ الْفَتْحِ فَأُتِيَ بِثَوْبٍ فَسُتِرَ عَلَيْهِ فَاغْتَسَلَ ثُمَّ قَامَ فَرَكَعَ ثَمَانِيَ رَكَعَاتٍ لَا أَدْرِي أَقِيَامُهُ فِيهَا أَطْوَلُ أَمْ رُكُوعُهُ أَمْ سُجُودُهُ كُلُّ ذَلِكَ مِنْهُ مُتَقَارِبٌ قَالَتْ فَلَمْ أَرَهُ سَبَّحَهَا قَبْلُ وَلَا بَعْدُقَالَ الْمُرَادِيُّ عَنْ يُونُسَ وَلَمْ يَقُلْ أَخْبَرَنِي","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] dan [Muhammad bin Salamah Al Muradi] keduanya berkata; telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] katanya; telah menceritakan kepadaku [Ibnu Abdullah bin Al Harits] bahwa ayahnya yatiu [Abdullah bin Al Harits bin Naufal] mengatakan; \"Aku bertanya dan memang aku sangat berkehendak agar seseorang mengabariku, katanya Rasulullah shallallahu 'alaihi wasallam pernah melakukan shalat sunnah dhuha, ternyata aku tidak mendapatkan seorang pun mengabarkan hal itu, selain [Ummu Hani` binti Abu Thalib]. Dia mengabariku bahwa Rasulullah shallallahu 'alaihi wasallam pernah datang ketika siang agak meninggi, yaitu ketika penaklukan kota Makkah, beliau diberi kain dan beliau pun ditutupi, kemudian beliau mandi. Setelah itu beliau berdiri dan ruku' sebanyak delapan rakaat, saya tidak tahu apakah berdirinya lebih lama ataukah ruku'nya, ataukah sujudnya, semua sepertinya hampir sama.\" Kata Ummu Hani selanjutnya; \"Padahal sebelum dan sesudah itu, aku belum pernah melihat beliau melakukan shalat sunnah dhuha.\" Al Muradi mengatakan dari Yunus, namun Yunus tidak mengatakan; \"Telah mengabariku.\""},"1129":{"ar":"و حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا مُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا وُهَيْبُ بْنُ خَالِدٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ أَبِي مُرَّةَ مَوْلَى عَقِيلٍ عَنْ أُمِّ هَانِئٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي بَيْتِهَا عَامَ الْفَتْحِ ثَمَانِيَ رَكَعَاتٍ فِي ثَوْبٍ وَاحِدٍ قَدْ خَالَفَ بَيْنَ طَرَفَيْهِ","id":"Dan telah menceritakan kepadaku [Hajjjaj bin Syair] telah menceritakan kepada kami [Mu'alla bin Asad] telah menceritakan kepada kami [Wuhaib bin Khalid] dari [Ja'far bin Muhammad] dari [Ayahnya] dari [Abu Murah] mantan budak Aqil, dari [Ummu Hani`], bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat delapan raka'at di rumahnya, yaitu ketika penaklukan kota Makkah dengan menyelempangkan kedua ujung kainnya.\""},"1130":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَسْمَاءَ الضُّبَعِيُّ حَدَّثَنَا مَهْدِيٌّ وَهُوَ ابْنُ مَيْمُونٍ حَدَّثَنَا وَاصِلٌ مَوْلَى أَبِي عُيَيْنَةَ عَنْ يَحْيَى بْنِ عُقَيْلٍ عَنْ يَحْيَى بْنِ يَعْمَرَ عَنْ أَبِي الْأَسْوَدِ الدُّؤَلِيِّ عَنْ أَبِي ذَرٍّعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يُصْبِحُ عَلَى كُلِّ سُلَامَى مِنْ أَحَدِكُمْ صَدَقَةٌ فَكُلُّ تَسْبِيحَةٍ صَدَقَةٌ وَكُلُّ تَحْمِيدَةٍ صَدَقَةٌ وَكُلُّ تَهْلِيلَةٍ صَدَقَةٌ وَكُلُّ تَكْبِيرَةٍ صَدَقَةٌ وَأَمْرٌ بِالْمَعْرُوفِ صَدَقَةٌ وَنَهْيٌ عَنْ الْمُنْكَرِ صَدَقَةٌ وَيُجْزِئُ مِنْ ذَلِكَ رَكْعَتَانِ يَرْكَعُهُمَا مِنْ الضُّحَى","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad bin Asma` Adl Dluba`i] telah menceritakan kepada kami [Mahdi yaitu Ibnu Maimun] telah menceritakan kepada kami [Washil] mantan budak Abu 'Uyainah dari [Yahya bin 'Uqail] dari [Yahya bin Ya'mar] dari [Abul Aswad Ad Du`ali] dari [Abu Dzarr] dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Setiap pagi dari persendian masing-masing kalian ada sedekahnya, setiap tasbih adalah sedekah, setiap tahmid adalah sedekah, dan setiap tahlil adalah sedekah, setiap takbir sedekah, setiap amar ma'ruf nahyi mungkar sedekah, dan semuanya itu tercukupi dengan dua rakaat dhuha.\""},"1131":{"ar":"و حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ وَمُحَمَّدُ بْنُ رَافِعٍ قَالَا حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ عَنْ الضَّحَّاكِ بْنِ عُثْمَانَ عَنْ إِبْرَاهِيمَ بْنِ عَبْدِ اللَّهِ بْنِ حُنَيْنٍ عَنْ أَبِي مُرَّةَ مَوْلَى أُمِّ هَانِئٍ عَنْ أَبِي الدَّرْدَاءِ قَالَأَوْصَانِي حَبِيبِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِثَلَاثٍ لَنْ أَدَعَهُنَّ مَا عِشْتُ بِصِيَامِ ثَلَاثَةِ أَيَّامٍ مِنْ كُلِّ شَهْرٍ وَصَلَاةِ الضُّحَى وَبِأَنْ لَا أَنَامَ حَتَّى أُوتِرَ","id":"Dan telah menceritakan kepadaku [Harun bin Abdullah] dan [Muhammad bin Rafi'] keduanya berkata; telah menceritakan kepada kami [Ibnu Abu Fudaik] dari [Adl Dlahak bin Utsman] dari [Ibrahim bin Abdullah bin Hunain] dari [Abu Murrah] mantan budak Ummu Hani` dari [Abu Darda`] katanya; \"Kekasihku shallallahu 'alaihi wasallam mewasiatkan kepadaku untuk melakukan tiga hal, yaitu agar aku tidak meninggalkan selama hidupku, puasa tiga hari tiap bulan, shalat dhuha dan tidak tidur sebelum shalat witir.\""},"1132":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ حَفْصَةَ أُمَّ الْمُؤْمِنِينَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا سَكَتَ الْمُؤَذِّنُ مِنْ الْأَذَانِ لِصَلَاةِ الصُّبْحِ وَبَدَا الصُّبْحُ رَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ قَبْلَ أَنْ تُقَامَ الصَّلَاةُو حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَقُتَيْبَةُ وَابْنُ رُمْحٍ عَنْ اللَّيْثِ بْنِ سَعْدٍ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ كُلُّهُمْ عَنْ نَافِعٍ بِهَذَا الْإِسْنَادِ كَمَا قَالَ مَالِكٌ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] katanya; aku pernah menyetorkan hapalan kepada [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa [Hafsah Umul Mukminin] mengabarinya, bahwa jika Mu'adzin diam dari adzan shalat shubuh, dan shubuhpun telah nampak, maka Rasulullah shallallahu 'alaihi wasallam melakukan shalat dua rakaat ringan sebelum shalat ditegakkan.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Qutaibah] dan [Ibnu Rumh], dari [Al Laits bin Sa'd] (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Zuhair bin Harb] dan ['Ubaidullah bin Sa'id], keduanya berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Ismail] dari [Ayyub] semuanya dari [Nafi'] dengan sanad seperti ini sebagaimana yang dikatakan Malik."},"1133":{"ar":"و حَدَّثَنِي أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ زَيْدِ بْنِ مُحَمَّدٍ قَالَ سَمِعْتُ نَافِعًا يُحَدِّثُ عَنْ ابْنِ عُمَرَ عَنْ حَفْصَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا طَلَعَ الْفَجْرُ لَا يُصَلِّي إِلَّا رَكْعَتَيْنِ خَفِيفَتَيْنِو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا النَّضْرُ حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepadaku [Ahmad bin Abdullah bin Al Hakam] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Zaid bin Muhammad] katanya; aku pernah mendengar [Nafi'] menceritakan dari [Ibnu Umar] dari [Hafsah] katanya; \"Jika fajar telah terbit, Rasulullah shallallahu 'alaihi wasallam tidak melakukan shalat selain dua rakaat ringan.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [An Nadlr] telah menceritakan kepada kami [Syu'bah] dengan sanad seperti ini."},"1134":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي رَكْعَتَيْ الْفَجْرِ إِذَا سَمِعَ الْأَذَانَ وَيُخَفِّفُهُمَاو حَدَّثَنِيهِ عَلِيُّ بْنُ حُجْرٍ حَدَّثَنَا عَلِيٌّ يَعْنِي ابْنَ مُسْهِرٍ ح و حَدَّثَنَاه أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَاه أَبُو بَكْرٍ وَأَبُو كُرَيْبٍ وَابْنُ نُمَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ ح و حَدَّثَنَاه عَمْرٌو النَّاقِدُ حَدَّثَنَا وَكِيعٌ كُلُّهُمْ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِ أَبِي أُسَامَةَ إِذَا طَلَعَ الْفَجْرُ","id":"Telah menceritakan kepada kami ['Amru An Naqid] telah menceritakan kepada kami ['Abdah bin Sulaiman] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah], katanya; \"Jika mendengar adzan (shubuh), maka Rasulullah shallallahu 'alaihi wasallam shalat dua rakaat fajar dengan meringankan (raka'at) keduanya.\" Telah menceritakan kepadaku [Ali bin Hujr] telah menceritakan kepada kami [Ali yaitu Ibnu Mushir], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Bakar] dan [Abu Kuraib] dan [Ibnu Numair] dari [Abdullah bin Numair], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami ['Amru An Naqid] telah menceritakan kepada kami [Waki'], semuanya dari [Hisyam] dengan sanad seperti ini, dan dalam hadis Abu Usamah disebutkan; \"Jika fajar telah terbit.\""},"1135":{"ar":"و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ هِشَامٍ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي رَكْعَتَيْنِ بَيْنَ النِّدَاءِ وَالْإِقَامَةِ مِنْ صَلَاةِ الصُّبْحِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] dari [Hisyam] dari [Yahya] dari [Abu Salamah] dari ['Aisyah], bahwa Nabiyullah shallallahu 'alaihi wasallam shalat dua rakaat antara adzan dan iqamat pada waktu shalat subuh."},"1136":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّهُ سَمِعَ عَمْرَةَ تُحَدِّثُ عَنْ عَائِشَةَ أَنَّهَا كَانَتْ تَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي رَكْعَتَيْ الْفَجْرِ فَيُخَفِّفُ حَتَّى إِنِّي أَقُولُ هَلْ قَرَأَ فِيهِمَا بِأُمِّ الْقُرْآنِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab], katanya; aku mendengar [Yahya bin Said] berkata; telah mengabarkan kepadaku [Muhammad bin Abdurrahman] bahwa ia mendengar ['Amrah] menceritakan dari ['Aisyah], bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam sering shalat dua rakaat fajar dan meringankan raka'atnya hingga aku berkata dalam hari; \"Apakah beliau membaca Alfatihah?.\""},"1137":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ حَدَّثَنِي عَطَاءٌ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَكُنْ عَلَى شَيْءٍ مِنْ النَّوَافِلِ أَشَدَّ مُعَاهَدَةً مِنْهُ عَلَى رَكْعَتَيْنِ قَبْلَ الصُّبْحِ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Said] dari [Ibnu Juraij] katanya; telah menceritakan kepadaku ['Atha`] dari ['Ubaid bin Umair] dari ['Aisyah], bahwa tidak ada shalat sunnah yang lebih di jaga Nabi shallallahu 'alaihi wasallam daripada dua raka'at sebelum subuh.\""},"1138":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ جَمِيعًا عَنْ حَفْصِ بْنِ غِيَاثٍ قَالَ ابْنُ نُمَيْرٍ حَدَّثَنَا حَفْصٌ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ مِنْ النَّوَافِلِ أَسْرَعَ مِنْهُ إِلَى الرَّكْعَتَيْنِ قَبْلَ الْفَجْرِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] telah menceritakan kepada kami [Hafs] dari [Ibnu Juraij] dari ['Atha`] dari [Ubaid bin Umair] dari ['Aisyah] katanya; \"Aku belum pernah melihat shalat sunnah yang lebih disegerakan untuk dikerjakan Nabi shallallahu 'alaihi wasallam daripada dua rakaat sebelum fajar.\""},"1139":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَكْعَتَا الْفَجْرِ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin 'Ubaid Al Ghabari] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dua rakaat fajar lebih baik daripada dunia seisinya.\""},"1140":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ عَبَّادٍ وَابْنُ أَبِي عُمَرَ قَالَا حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ عَنْ يَزِيدَ هُوَ ابْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ فِي رَكْعَتَيْ الْفَجْرِ قُلْ يَا أَيُّهَا الْكَافِرُونَ وَقُلْ هُوَ اللَّهُ أَحَدٌ","id":"Dan telah menceritakan kepadaku [Muhammad bin 'Abbad] dan [Ibnu Abu Umar], keduanya berkata; telah menceritakan kepada kami [Marwan bin Muawiyah] dari [Yazid yaitu Ibnu Kaisan] dari [Abu Hazim] dari [Abu Hurairah] bahwa dalam dua raka'at fajarnya, Rasulullah shallallahu 'alaihi wasallam membaca surat Al Kafirun dan Qul Huwallahu ahad (Surat al-ikhlash)."},"1141":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْفَزَارِيُّ يَعْنِي مَرْوَانَ بْنَ مُعَاوِيَةَ عَنْ عُثْمَانَ بْنِ حَكِيمٍ الْأَنْصَارِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ يَسَارٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي رَكْعَتَيْ الْفَجْرِ فِي الْأُولَى مِنْهُمَا{ قُولُوا آمَنَّا بِاللَّهِ وَمَا أُنْزِلَ إِلَيْنَا }الْآيَةَ الَّتِي فِي الْبَقَرَةِ وَفِي الْآخِرَةِ مِنْهُمَا{ آمَنَّا بِاللَّهِ وَاشْهَدْ بِأَنَّا مُسْلِمُونَ }","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Al Fazari yaitu Marwan bin Muawiyah] dari [Utsman bin Hakim Al Anshari], katanya; telah menceritakan kepadaku [Said bin Yasar] bahwa [Ibnu Abbas] mengabarinya; bahwa dalam dua raka'at fajar, tepatnya di raka'at pertama, Rasulullah shallallahu 'alaihi wasallam membaca \"Katakanlah, kami beriman kepada Allah dan apa yang diturunkan kepada kami.\" QS. Albaqarah 136, dan pada rakaat kedua membaca \"Kami beriman kepada Allah, dan saksikanlah bahwa kami orang muslim.\" QS. Ali Imran 52."},"1142":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبُو خَالِدٍ يَعْنِي سُلَيْمَانَ بْنَ حَيَّانَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ النُّعْمَانِ بْنِ سَالِمٍ عَنْ عَمْرِو بْنِ أَوْسٍ قَالَ حَدَّثَنِي عَنْبَسَةُ بْنُ أَبِي سُفْيَانَ فِي مَرَضِهِ الَّذِي مَاتَ فِيهِ بِحَدِيثٍ يَتَسَارُّ إِلَيْهِ قَالَ سَمِعْتُ أُمَّ حَبِيبَةَ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ صَلَّى اثْنَتَيْ عَشْرَةَ رَكْعَةً فِي يَوْمٍ وَلَيْلَةٍ بُنِيَ لَهُ بِهِنَّ بَيْتٌ فِي الْجَنَّةِقَالَتْ أُمُّ حَبِيبَةَ فَمَا تَرَكْتُهُنَّ مُنْذُ سَمِعْتُهُنَّ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَنْبَسَةُ فَمَا تَرَكْتُهُنَّ مُنْذُ سَمِعْتُهُنَّ مِنْ أُمِّ حَبِيبَةَ وَقَالَ عَمْرُو بْنُ أَوْسٍ مَا تَرَكْتُهُنَّ مُنْذُ سَمِعْتُهُنَّ مِنْ عَنْبَسَةَ وَقَالَ النُّعْمَانُ بْنُ سَالِمٍ مَا تَرَكْتُهُنَّ مُنْذُ سَمِعْتُهُنَّ مِنْ عَمْرِو بْنِ أَوْسٍ حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا دَاوُدُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ بِهَذَا الْإِسْنَادِ مَنْ صَلَّى فِي يَوْمٍ ثِنْتَيْ عَشْرَةَ سَجْدَةً تَطَوُّعًا بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Abu Khalid yaitu Sulaiman bin Hayyan] dari [Dawud bin Abu Hind] dari [Nu'man bin Salim] dari ['Amru bin Aus], katanya; telah menceritakan kepadaku [Anbasah bin Abu Sufyan] ketika sakitnya yang menyebabkan dia meninggal, dengan hadis yang membuatnya gembira. Katanya; aku mendengar [Ummu Habibah] mengatakan; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa shalat dua belas rakaat sehari semalam, maka akan dibangunkan baginya sebuah rumah di surga.\" [Ummu Habibah] berkata; Maka aku tidak akan meninggalkan dua belas rakaat itu semenjak aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam. Dan [Anbasah] juga berkata; \"Maka aku tidak akan meninggalkannya semenjak aku mendengarnya dari Ummu Habibah. Dan ['Amru bin Aus] juga berkata; \"Aku tidak akan meninggalkannya semenjak aku mendnegarnya dari Anbasah. [Nu'man bin Salim] juga berkata; \"Aku tidak akan meninggalkannya semenjak aku mendengarnya dari 'Amru bin Aus. Telah menceritakan kepadaku [Abu Ghassan Al Misma'i] telah menceritakan kepada kami [Bisyr bin Al Mufadldlal] telah menceritakan kepada kami [Dawud] dari [Nu'man bin Salim] dengan sanad seperti ini; \"Siapa yang shalat sunnah dua belas raka'at dalam sehari, maka akan dibangunkan baginya rumah di dalam surga.\""},"1143":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ عَنْ عَمْرِو بْنِ أَوْسٍ عَنْ عَنْبَسَةَ بْنِ أَبِي سُفْيَانَ عَنْ أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ مُسْلِمٍ يُصَلِّي لِلَّهِ كُلَّ يَوْمٍ ثِنْتَيْ عَشْرَةَ رَكْعَةً تَطَوُّعًا غَيْرَ فَرِيضَةٍ إِلَّا بَنَى اللَّهُ لَهُ بَيْتًا فِي الْجَنَّةِ أَوْ إِلَّا بُنِيَ لَهُ بَيْتٌ فِي الْجَنَّةِقَالَتْ أَمُّ حَبِيبَةَ فَمَا بَرِحْتُ أُصَلِّيهِنَّ بَعْدُ و قَالَ عَمْرٌو مَا بَرِحْتُ أُصَلِّيهِنَّ بَعْدُ و قَالَ النُّعْمَانُ مِثْلَ ذَلِكَ و حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ وَعَبْدُ اللَّهِ بْنُ هَاشِمٍ الْعَبْدِيُّ قَالَا حَدَّثَنَا بَهْزٌ حَدَّثَنَا شُعْبَةُ قَالَ النُّعْمَانُ بْنُ سَالِمٍ أَخْبَرَنِي قَالَ سَمِعْتُ عَمْرَو بْنَ أَوْسٍ يُحَدِّثُ عَنْ عَنْبَسَةَ عَنْ أُمِّ حَبِيبَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ عَبْدٍ مُسْلِمٍ تَوَضَّأَ فَأَسْبَغَ الْوُضُوءَ ثُمَّ صَلَّى لِلَّهِ كُلَّ يَوْمٍ فَذَكَرَ بِمِثْلِهِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Nu'man bin Salim] dari ['Amru bin Aus] dari [Anbasah bin Abu Sufyan] dari [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam, katanya; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim mendirikan shalat sunnah ikhlas karena Allah sebanyak dua belas rakaat selain shalat fardhu, melainkan Allah akan membangunkan baginya sebuah rumah di surga.\" -Atau dengan redaksi lain- \"Melainkan akan dibangunkan baginya rumah di surga.\" [Ummu Habibah] berkata; \"Setelah itu, aku selalu melaksanakan kedua belas rakaat itu.\" ['Amru] juga berkata; \"Aku tidak pernah meninggalkannya setelah itu.\" [Nu'man] juga mengatakan seperti itu. Dan telah menceritakan kepadaku [Abdurrahman bin Bisyr] dan [Abdullah bin Hasyim Al 'Abdi] keduanya berkata; telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Syu'bah]. [Nu'man bin Salim] mengatakan; telah menceritakan kepadaku, katanya; Aku mendengar ['Amru bin Aus] menceritakan dari [Anbasah] dari [Ummu Habibah] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba muslim berwudhu` kemudian menyempurnakan wudlu'nya, lalu shalat karena Allah setiap harinya…\" lalu dia menyebutkan hadits semisalnya."},"1144":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا يَحْيَى وَهُوَ ابْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبْلَ الظُّهْرِ سَجْدَتَيْنِ وَبَعْدَهَا سَجْدَتَيْنِ وَبَعْدَ الْمَغْرِبِ سَجْدَتَيْنِ وَبَعْدَ الْعِشَاءِ سَجْدَتَيْنِ وَبَعْدَ الْجُمُعَةِ سَجْدَتَيْنِ فَأَمَّا الْمَغْرِبُ وَالْعِشَاءُ وَالْجُمُعَةُ فَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِهِ","id":"Telah menceritakan kepadaku [Zuhair bin Harb] dan ['Ubaidullah bin Said] keduanya berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Said] dari ['Ubaidullah], katanya; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] katanya; \"Aku pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam dua raka'at sebelum Zhuhur dan dua raka'at setelahnya, dan dua raka'at setelah maghrib dan dua raka'at setelah isya`, dan dua raka'at setelah jumat, adapun (sunnah) maghrib dan isya` dan jumat, aku shalat bersama Nabi shallallahu 'alaihi wasallam di rumahnya.\""},"1145":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادٌ عَنْ بُدَيْلٍ وَأَيُّوبَ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي لَيْلًا طَوِيلًا فَإِذَا صَلَّى قَائِمًا رَكَعَ قَائِمًا وَإِذَا صَلَّى قَاعِدًا رَكَعَ قَاعِدًاو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ بُدَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ كُنْتُ شَاكِيًا بِفَارِسَ فَكُنْتُ أُصَلِّي قَاعِدًا فَسَأَلْتُ عَنْ ذَلِك عَائِشَةَ فَقَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي لَيْلًا طَوِيلًا قَائِمًا فَذَكَرَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id], telah menceritakan kepada kami [Hammad] dari [Budail] dan [Ayyub] dari [Abdullah bin Syaqiq] dari ['Aisyah] katanya; Rasulullah shallallahu 'alaihi wasallam biasa shalat malam sekian lama, jika beliau shalat dengan berdiri, maka beliau ruku' dengan berdiri, dan jika beliau shalat dengan duduk, maka beliau ruku' dengan duduk.\" Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Budail] dari [Abdullah bin Syaqiq], katanya; \"Aku pernah mengeluhkan nyeri, maka aku shalat dengan duduk, maka aku tanyakan hal itu kepada ['Aisyah], dia menjawab; \"Rasulullah shallallahu 'alaihi wasallam juga pernah shalat malam sekian lama sambil duduk, lalu ia menyebutkan haditnya.\""},"1146":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ عَنْ حُمَيْدٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ الْعُقَيْلِيِّ قَالَ سَأَلْتُ عَائِشَةَعَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ فَقَالَتْ كَانَ يُصَلِّي لَيْلًا طَوِيلًا قَائِمًا وَلَيْلًا طَوِيلًا قَاعِدًا وَكَانَ إِذَا قَرَأَ قَائِمًا رَكَعَ قَائِمًا وَإِذَا قَرَأَ قَاعِدًا رَكَعَ قَاعِدًا","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muadz bin Muadz] dari [Humaid] dari [Abdullah bin Syaqiq Al 'Uqaili] katanya; \"Aku pernah bertanya kepada ['Aisyah] tentang shalat (sunnah) nya Rasulullah shallallahu 'alaihi wasallam, Aisyah menjawab; \"Beliau biasa melakukan shalat malam sekian lama sambil berdiri, dan beliau juga biasa melakukan shalat sekian lama sambil duduk, jika beliau membaca sambil berdiri, maka beliau ruku' dengan berdiri, dan jika beliau membaca sambil duduk, maka beliau ruku' sambil duduk.\""},"1147":{"ar":"و حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ أَخْبَرَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ قَالَ ح و حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا ابْنُ نُمَيْرٍ جَمِيعًا عَنْ هِشَامِ بْنِ عُرْوَةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي شَيْءٍ مِنْ صَلَاةِ اللَّيْلِ جَالِسًا حَتَّى إِذَا كَبِرَ قَرَأَ جَالِسًا حَتَّى إِذَا بَقِيَ عَلَيْهِ مِنْ السُّورَةِ ثَلَاثُونَ أَوْ أَرْبَعُونَ آيَةً قَامَ فَقَرَأَهُنَّ ثُمَّ رَكَعَ","id":"Dan telah menceritakan kepadaku [Abu Rabi' Az Zahrani] telah mengabarkan kepada kami [Hammad yaitu Ibnu Zaid], katanya; (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Hasan bin Rabi'] telah menceritakan kepada kami [Mahdi bin Maimun], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Ibnu Numair] semuanya dari [Hisyam bin Urwah], (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Zuhair bin Harb] sedangkan lafadz (hadits) darinya, dia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam Ibn 'Urwah], katanya; telah mengabarkan kepadaku [Ayahku] dari ['Aisyah] katanya; \"Aku belum pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat dengan duduk, hingga ketika beliau telah lanjut usia, beliau membaca sambil duduk, jika bacaan beliau tinggal tiga puluh atau empat puluh ayat, beliau berdiri dan membaca, lalu beliau ruku'.\""},"1148":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ وَأَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي جَالِسًا فَيَقْرَأُ وَهُوَ جَالِسٌ فَإِذَا بَقِيَ مِنْ قِرَاءَتِهِ قَدْرُ مَا يَكُونُ ثَلَاثِينَ أَوْ أَرْبَعِينَ آيَةً قَامَ فَقَرَأَ وَهُوَ قَائِمٌ ثُمَّ رَكَعَ ثُمَّ سَجَدَ ثُمَّ يَفْعَلُ فِي الرَّكْعَةِ الثَّانِيَةِ مِثْلَ ذَلِكَ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya], katanya; aku menyetorkan hapalan kepada [Malik] dari [Abdullah bin Yazid] dan [Abu Nadlr] dari [Abu Salamah bin Abdurrahman] dari ['Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam pernah shalat dengan duduk, lalu beliau membaca dengan duduk, jika bacaan beliau tinggal sekitar tiga puluh atau empat puluh ayat, beliau berdiri sambil membaca dengan berdiri, kemudian beliau ruku' lalu sujud, beliau juga melakukan yang demikian pada rakaat ketiga.\""},"1149":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ الْوَلِيدِ بْنِ أَبِي هِشَامٍ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ وَهُوَ قَاعِدٌ فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ قَدْرَ مَا يَقْرَأُ إِنْسَانٌ أَرْبَعِينَ آيَةً","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim]. [Abu Bakar] mengatakan; telah menceritakan kepada kami [Ismail bin 'Ulayyah] dari [Al Walid bin Abu Hisyam] dari [Abu Bakar bin Muhammad] dari ['Amrah] dari ['Aisyah] katanya; \"Rasulullah shallallahu 'alaihi wasallam membaca (dalam shalat) dengan duduk, jika beliau hendak ruku', beliau berdiri seukuran seseorang membaca empat puluh ayat.\""},"1150":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ قُلْتُ لِعَائِشَةَهَلْ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي وَهُوَ قَاعِدٌ قَالَتْ نَعَمْ بَعْدَ مَا حَطَمَهُ النَّاسُو حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا كَهْمَسٌ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ قَالَ قُلْتُ لِعَائِشَةَ فَذَكَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yazid bin Zurai'] dari [Sa'id Al Jurairi] dari [Abdulah bin Syaqiq], katanya; saya bertanya kepada ['Aisyah]; \"Pernahkah Nabi shallallahu 'alaihi wasallam shalat dengan duduk?\" 'Aisyah menjawab; \"Benar, setelah beliau merasa dirinya lemah karena lanjut usia.\" Dan telah menceritakan kepada kami ['Ubaidullah bin Mu'adz] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Kahmas] dari [Abdullah bin Syaqiq] katanya; Aku bertanya kepada ['Aisyah], lalu ia menyebutkan dari Nabi shallallahu 'alaihi wasallam seperti hadits semisal."},"1151":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ وَهَارُونُ بْنُ عَبْدِ اللَّهِ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُثْمَانُ بْنُ أَبِي سُلَيْمَانَ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَمُتْ حَتَّى كَانَ كَثِيرٌ مِنْ صَلَاتِهِ وَهُوَ جَالِسٌ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] dan [Harun bin Abdullah], keduanya berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] katanya; [Ibn Juraij] berkata; telah mengabarkan kepadaku [Utsman bin Abu Sulaiman], bahwa [Abu Salamah bin Abdurrahman] mengabarinya, bahwa ['Aisyah] pernah mengabarinya, bahwa Nabi shallallahu 'alaihi wasallam tidak meninggal, hingga sekian banyak shalatnya beliau lakukan dengan duduk.\""},"1152":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ السَّائِبِ بْنِ يَزِيدَ عَنْ الْمُطَّلِبِ بْنِ أَبِي وَدَاعَةَ السَّهْمِيِّ عَنْ حَفْصَةَأَنَّهَا قَالَتْ مَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي سُبْحَتِهِ قَاعِدًا حَتَّى كَانَ قَبْلَ وَفَاتِهِ بِعَامٍ فَكَانَ يُصَلِّي فِي سُبْحَتِهِ قَاعِدًا وَكَانَ يَقْرَأُ بِالسُّورَةِ فَيُرَتِّلُهَا حَتَّى تَكُونَ أَطْوَلَ مِنْ أَطْوَلَ مِنْهَاو حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ جَمِيعًا عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُمَا قَالَا بِعَامٍ وَاحِدٍ أَوْ اثْنَيْنِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya], katanya, Pernah aku menyetorkan hapalan kepada [Malik] dari [Ibn Syihab] dari [Saib bin YAzid] dari [Muththalib bin Abi Wada'ah Assahmi] dari [Hafsah], katanya, belum pernha kulihat Rasulullah shallallahu 'alaihi wasallam dalam shalat sunnahnya beliau lakukan dengan duduk, hingga setahun sebelum wafatnya, beliau lakukan shalat sunnahnya dengan duduk, beliau baca sebuah surat dan beliau baca dengan tartil, hingga melebihi panjang daripada yang pernah beliau baca dengan panjang. Dan telah menceritakan kepadaku [Abu Tahir] dan [Harmalah], kata keduanya, Telah mengabarkan kepada kami [Ibn Wahb] telah mengabarkan kepadaku [Yunus] --Lewat jalur periwayatan lain-Dan Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin humaid], kata keduanya, Telah mengabarkan kepada kami [Abdurrazaq] Telah mengabarkan kepada kami [Ma'mar], kesemuanya dari [Azzuhri] dengan isnad ini semisalnya hanya keduanya katakan, setahun atau dua tahun sebelum kewafatannya."},"1153":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ حَسَنِ بْنِ صَالِحٍ عَنْ سِمَاكٍ قَالَ أَخْبَرَنِي جَابِرُ بْنُ سَمُرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمْ يَمُتْ حَتَّى صَلَّى قَاعِدًا","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Hasan bin Shalih] dari [Simak], katanya; telah mengabarkan kepadaku [Jabir bin Samurah] bahwa tidaklah Nabi shallallahu 'alaihi wasallam wafat hingga kebanyakan shalatnya, beliau lakukan dengan duduk.\""},"1154":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ هِلَالِ بْنِ يَسَافٍ عَنْ أَبِي يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَحُدِّثْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الرَّجُلِ قَاعِدًا نِصْفُ الصَّلَاةِ قَالَ فَأَتَيْتُهُ فَوَجَدْتُهُ يُصَلِّي جَالِسًا فَوَضَعْتُ يَدِي عَلَى رَأْسِهِ فَقَالَ مَا لَكَ يَا عَبْدَ اللَّهِ بْنَ عَمْرٍو قُلْتُ حُدِّثْتُ يَا رَسُولَ اللَّهِ أَنَّكَ قُلْتَ صَلَاةُ الرَّجُلِ قَاعِدًا عَلَى نِصْفِ الصَّلَاةِ وَأَنْتَ تُصَلِّي قَاعِدًا قَالَ أَجَلْ وَلَكِنِّي لَسْتُ كَأَحَدٍ مِنْكُمْو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ جَمِيعًا عَنْ مُحَمَّدِ بْنِ جَعْفَرٍ عَنْ شُعْبَةَ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا سُفْيَانُ كِلَاهُمَا عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ وَفِي رِوَايَةِ شُعْبَةَ عَنْ أَبِي يَحْيَى الْأَعْرَجِ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Hilal bin Yasaf] dari [Abu Yahya] dari [Abdullah bin 'Amru] katanya; diceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat seseorang yang dilakukanya dengan duduk, memperoleh separoh pahala shalat (dengan berdiri).\" Abdullah bin 'Amru berkata; Lalu aku menemui beliau, ternyata aku mendapati beliau shalat dengan duduk, lalu aku meletakkan tanganku diatas kepalanya, maka beliau bersabda: \"Apa urusanmu wahai Abdullah bin 'Amru?\" Aku menjawab; \"Disampaikan kepadaku wahai Rasulullah, bahwa engkau bersabda: \"Shalat seseorang dengan duduk mendapat separoh pahala shalat dengan berdiri, \" lalu kenapa engkau shalat dengan duduk?\" Beliau menjawab: \"Benar, namun aku tidak seperti kalian.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], semuanya dari [Muhmamad bin Ja'far] dari [Syubah], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnul Al Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Sufyan], keduanya dari [Manshur] dengan sanad ini dan dalam periwayatan Syu'bah, dari Abu Yahya Al A'raj."},"1155":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِيمَا بَيْنَ أَنْ يَفْرُغَ مِنْ صَلَاةِ الْعِشَاءِ وَهِيَ الَّتِي يَدْعُو النَّاسُ الْعَتَمَةَ إِلَى الْفَجْرِ إِحْدَى عَشْرَةَ رَكْعَةً يُسَلِّمُ بَيْنَ كُلِّ رَكْعَتَيْنِ وَيُوتِرُ بِوَاحِدَةٍ فَإِذَا سَكَتَ الْمُؤَذِّنُ مِنْ صَلَاةِ الْفَجْرِ وَتَبَيَّنَ لَهُ الْفَجْرُ وَجَاءَهُ الْمُؤَذِّنُ قَامَ فَرَكَعَ رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ اضْطَجَعَ عَلَى شِقِّهِ الْأَيْمَنِ حَتَّى يَأْتِيَهُ الْمُؤَذِّنُ لِلْإِقَامَةِو حَدَّثَنِيهِ حَرْمَلَةُ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ بِهَذَا الْإِسْنَادِ وَسَاقَ حَرْمَلَةُ الْحَدِيثَ بِمِثْلِهِ غَيْرَ أَنَّهُ لَمْ يَذْكُرْ وَتَبَيَّنَ لَهُ الْفَجْرُ وَجَاءَهُ الْمُؤَذِّنُ وَلَمْ يَذْكُرْ الْإِقَامَةَ وَسَائِرُ الْحَدِيثِ بِمِثْلِ حَدِيثِ عَمْرٍو سَوَاءً","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah menceritakan kepada kami [Ibn Wahb] telah mengabarkan kepadaku ['Amru bin Al Harits] dari [Ibnu Syihab] dari ['Urwah bin Zubair] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, dia berkata; Rasulullah shallallahu 'alaihi wasallam pernah shalat antara habis shalat isya' yang biasa disebut 'atamah hingga waktu fajar. Beliau melakukan sebelas rakaat, setiap dua rakaat beliau salam, dan beliau juga melakukan witir satu rakaat. Jika muadzin shalat fajar telah diam, dan fajar telah jelas, sementara muadzin telah menemui beliau, maka beliau melakukan dua kali raka'at ringan, kemudian beliau berbaring diatas lambung sebelah kanan hingga datang muadzin untuk iqamat.\" Dan telah menceritakan kepadaku [Harmalah] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dengan sanad hadits ini. Harmalah juga membawakan hadits semisalnya, hanya saja ia tidak menyebutkan redaksi \"Ketika fajar telah jelas, dan muadzin menemui beliau.\" Dia juga tidak menyebutkan \"iqamat\" dan semuanya sama seperti haditsnya 'Amru."},"1156":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً يُوتِرُ مِنْ ذَلِكَ بِخَمْسٍ لَا يَجْلِسُ فِي شَيْءٍ إِلَّا فِي آخِرِهَاو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ ح و حَدَّثَنَاه أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ وَأَبُو أُسَامَةَ كُلُّهُمْ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata; telah menceritakan kepada kami [Abdullah bin Numair], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Ayahku] telah menceritakan kepada kami [Hisyam] dari [Ayahnya] dari ['Aisyah] dia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa shalat malam tiga belas rakaat, dengan lima rakaat witir, beliau tidak pernah melakukan sambil duduk selain di akhir (hayatnya).\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah], telah menceritakan kepada kami ['Abdah bin Sulaiman], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] dan [Abu Usamah], semuanya dari [Hisyam] dengan sanad hadits ini.\""},"1157":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُ سَأَلَ عَائِشَةَكَيْفَ كَانَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَمَضَانَ قَالَتْ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَزِيدُ فِي رَمَضَانَ وَلَا فِي غَيْرِهِ عَلَى إِحْدَى عَشْرَةَ رَكْعَةً يُصَلِّي أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي أَرْبَعًا فَلَا تَسْأَلْ عَنْ حُسْنِهِنَّ وَطُولِهِنَّ ثُمَّ يُصَلِّي ثَلَاثًا فَقَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَنَامُ قَبْلَ أَنْ تُوتِرَ فَقَالَ يَا عَائِشَةُ إِنَّ عَيْنَيَّ تَنَامَانِ وَلَا يَنَامُ قَلْبِي","id":"Telah menceritakan kepada kami [Yahya bin Yahya] katanya; aku menyetorkan hapalan kepada [Malik] dari [Said bin Abu Said Al Maqbari] dari [Abu Salamah bin Abdurrahman] bahwa dia pernah bertanya kepada ['Aisyah]; \"Bagaimanakah shalat (sunnah) Rasulullah shallallahu 'alaihi wasallam pada bulan Ramadhan?\" Aisyah menjawab; \"Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat sunnah baik ketika Ramadhan atau diluar ramadhan tak lebih dari sebelas rakaat, beliau mengerjakan empat rakaat, kamu tidak usah menanyakan kualitas dan panjangnya shalat beliau, setelah itu beliau mengerjakan empat rakaat, kamu tidak usah menanyakan kualitas dan panjangnya shalat beliau, kemudian beliau shalat tiga rakaat.\" Aisyah berkata; lalu aku bertanya; \"Wahai Rasulullah, apakah anda tidur sebelum witir? Beliau menjawab: \"Wahai 'Aisyah, kedua mataku memang tidur, namun hatiku tidak.\""},"1158":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ قَالَ سَأَلْتُ عَائِشَةَعَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَ يُصَلِّي ثَلَاثَ عَشْرَةَ رَكْعَةً يُصَلِّي ثَمَانَ رَكَعَاتٍ ثُمَّ يُوتِرُ ثُمَّ يُصَلِّي رَكْعَتَيْنِ وَهُوَ جَالِسٌ فَإِذَا أَرَادَ أَنْ يَرْكَعَ قَامَ فَرَكَعَ ثُمَّ يُصَلِّي رَكْعَتَيْنِ بَيْنَ النِّدَاءِ وَالْإِقَامَةِ مِنْ صَلَاةِ الصُّبْحِو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا حُسَيْنُ بْنُ مُحَمَّدٍ حَدَّثَنَا شَيْبَانُ عَنْ يَحْيَى قَالَ سَمِعْتُ أَبَا سَلَمَةَ ح و حَدَّثَنِي يَحْيَى بْنُ بِشْرٍ الْحَرِيرِيُّ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ أَنَّهُ سَأَلَ عَائِشَةَ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ غَيْرَ أَنَّ فِي حَدِيثِهِمَا تِسْعَ رَكَعَاتِ قَائِمًا يُوتِرُ مِنْهُنَّ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] telah menceritakan kepada kami [Hisyam], dari [Yahya] dari [Abu Salamah] katanya; \"Aku pernah bertanya kepada ['Aisyah] tentang shalatnya Rasulullah shallallahu 'alaihi wasallam. Aisyah menjawab; \"Beliau melakukan shalat tiga belas rakaat, beliau shalat delapan rakaat kemudian witir, setelah itu beliau shalat dua rakaat dengan duduk. Jika beliau hendak ruku', maka beliau berdiri dahulu lalu ruku', setelah itu beliau shalat dua rakaat antara (adzan) dan iqamat shalat subuh.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Husain bin Muhammad] telah menceritakan kepada kami [Syaiban] dari [Yahya] katanya; \"Aku pernah mendengar [Abu Salamah], (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Yahya bin Bisyr Al Hariri] telah menceritakan kepada kami [Muawiyah yaitu Ibnu Sallam] dari [Yahya bin Abu Katsir] katanya; telah mengabarkan kepadaku [Abu Salamah] bahwa ia bertanya kepada ['Aisyah] tentang shalat Rasulullah shallallahu 'alaihi wasallam, seperti hadits di atas, hanya dalam hadisnya disebutkan dengan redaksi \"Sembilan rakaat sambil berdiri, termasuk dengan witirnya.\""},"1159":{"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي لَبِيدٍ سَمِعَ أَبَا سَلَمَةَ قَالَأَتَيْتُ عَائِشَةَ فَقُلْتُ أَيْ أُمّهْ أَخْبِرِينِي عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كَانَتْ صَلَاتُهُ فِي شَهْرِ رَمَضَانَ وَغَيْرِهِ ثَلَاثَ عَشْرَةَ رَكْعَةً بِاللَّيْلِ مِنْهَا رَكْعَتَا الْفَجْرِ","id":"Telah menceritakan kepada kami ['Amru An Naqid] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abdullah bin Abu Labid] ia mendengar [Abu Salamah], katanya; Aku pernah menemui ['Aisyah] seraya berkata; \"Wahai bunda, beritahukanlah kepadaku tentang shalat (malam) Rasulullah shallallahu 'alaihi wasallam!\" Dia menjawab; \"Beliau biasa mengerjakan shalat (malam) baik dibulan Ramadhan atau selainnya sebanyak tiga belas rakaat, termasuk dua rakaat fajar.\""},"1160":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ أَبِي إِسْحَقَ قَالَ سَأَلْتُ الْأَسْوَدَ بْنَ يَزِيدَ عَمَّا حَدَّثَتْهُ عَائِشَةُعَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ يَنَامُ أَوَّلَ اللَّيْلِ وَيُحْيِ آخِرَهُ ثُمَّ إِنْ كَانَتْ لَهُ حَاجَةٌ إِلَى أَهْلِهِ قَضَى حَاجَتَهُ ثُمَّ يَنَامُ فَإِذَا كَانَ عِنْدَ النِّدَاءِ الْأَوَّلِ قَالَتْ وَثَبَ وَلَا وَاللَّهِ مَا قَالَتْ قَامَ فَأَفَاضَ عَلَيْهِ الْمَاءَ وَلَا وَاللَّهِ مَا قَالَتْ اغْتَسَلَ وَأَنَا أَعْلَمُ مَا تُرِيدُ وَإِنْ لَمْ يَكُنْ جُنُبًا تَوَضَّأَ وُضُوءَ الرَّجُلِ لِلصَّلَاةِ ثُمَّ صَلَّى الرَّكْعَتَيْنِ","id":"Dan telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Abu Ishaq] katanya; Aku bertanya kepada [Al Aswad bin Yazid] dari segala yang diceritakan oleh ['Aisyah] tentang shalat (malam) Rasulullah shallallahu 'alaihi wasallam. Dia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidur di awal malam, dan beliau hidupkan (beliau lakukan aktivitas) di akhir malamnya, jika beliau mempunyai hajat kepada isterinya, beliau lakukan hajatnya, kemudian beliau tidur. Jika panggilan (adzan) pertama telah diserukan, Aisyah melanjutkan; beliau langsung bergegas.\" Demi Allah, Aisyah tidak menggunakan menyebutkan \"Sambil berdiri\", setelah itu beliau mengguyurkan air. Demi Allah, Aisyah tidak menyebutkan dengan redaksi \"Mandi.\" Dan aku mengetahui apa yang kamu inginkan, kalaulah beliau tidak junub, maka beliau berwudlu sebagaimana wudlu seseorang untuk shalat, kemudian beliau mengerjakan shalat dua rakaat.\""},"1161":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا عَمَّارُ بْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ حَتَّى يَكُونَ آخِرَ صَلَاتِهِ الْوِتْرُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib], keduanya berkata; telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami ['Ammar bin Zuraiq] dari [Abu Ishaq] dari [Al Aswad] dari ['Aisyah], katanya; \"Rasulullah shallallahu 'alaihi wasallam biasa shalat malam hingga akhir shalat yang beliau lakukan adalah witir.\""},"1162":{"ar":"حَدَّثَنَا أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ بِشْرٍ عَنْ مِسْعَرٍ عَنْ سَعْدٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْمَا أَلْفَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّحَرُ الْأَعْلَى فِي بَيْتِي أَوْ عِنْدِي إِلَّا نَائِمًا","id":"Telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Bisyr] dari [Mis'ar] dari [Sa'd] dari [Abu Salamah] dari ['Aisyah] dia berkata; \"Aku tidak menemukan Rasulullah shallallahu 'alaihi wasallam ketika sahur pertama (akhir malam sebelum terbit fajar -pent) di rumahku -atau disisiku- selain kutemukan beliau dalam keadaan tidur.\""},"1163":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَنَصْرُ بْنُ عَلِيٍّ وَابْنُ أَبِي عُمَرَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي النَّضْرِ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى رَكْعَتَيْ الْفَجْرِ فَإِنْ كُنْتُ مُسْتَيْقِظَةً حَدَّثَنِي وَإِلَّا اضْطَجَعَو حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ سَعْدٍ عَنْ ابْنِ أَبِي عَتَّابٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Nashr bin Ali] dan [Ibnu Abu Umar]. [Abu Bakar] mengatakan; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Abu Nadlr] dari [Abu Salamah] dari ['Aisyah] katanya; \"Jika Nabi shallallahu 'alaihi wasallam selesai shalat dua rakaat fajar, dan aku sudah bangun, maka beliau akan mengajakku berbincang-bincang, jika aku belum bangun, maka beliau tidur lagi.\" Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Ziyad bin Sa'd] dari [Ibn Abu Attab] dari [Abu Salamah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1164":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ فَإِذَا أَوْتَرَ قَالَ قُومِي فَأَوْتِرِي يَا عَائِشَةُ","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Tamim bin Salamah] dari ['Urwah bin Zubair] dari ['Aisyah] katanya; \"Jika Rasulullah shallallahu 'alaihi wasallam shalat malam, dan telah melaksanakan shalat witir, maka beliau berseru: \"Witirlah wahai 'Aisyah!\""},"1165":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ أَنَّ سَعْدَ بْنَ هِشَامِ بْنِ عَامِرٍ أَرَادَ أَنْ يَغْزُوَ فِي سَبِيلِ اللَّهِ فَقَدِمَ الْمَدِينَةَ فَأَرَادَ أَنْ يَبِيعَ عَقَارًا لَهُ بِهَا فَيَجْعَلَهُ فِي السِّلَاحِ وَالْكُرَاعِ وَيُجَاهِدَ الرُّومَ حَتَّى يَمُوتَفَلَمَّا قَدِمَ الْمَدِينَةَ لَقِيَ أُنَاسًا مِنْ أَهْلِ الْمَدِينَةِ فَنَهَوْهُ عَنْ ذَلِكَ وَأَخْبَرُوهُ أَنَّ رَهْطًا سِتَّةً أَرَادُوا ذَلِكَ فِي حَيَاةِ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَهَاهُمْ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَلَيْسَ لَكُمْ فِيَّ أُسْوَةٌ فَلَمَّا حَدَّثُوهُ بِذَلِكَ رَاجَعَ امْرَأَتَهُ وَقَدْ كَانَ طَلَّقَهَا وَأَشْهَدَ عَلَى رَجْعَتِهَا فَأَتَى ابْنَ عَبَّاسٍ فَسَأَلَهُ عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ابْنُ عَبَّاسٍ أَلَا أَدُلُّكَ عَلَى أَعْلَمِ أَهْلِ الْأَرْضِ بِوِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَالَ عَائِشَةُ فَأْتِهَا فَاسْأَلْهَا ثُمَّ ائْتِنِي فَأَخْبِرْنِي بِرَدِّهَا عَلَيْكَ فَانْطَلَقْتُ إِلَيْهَا فَأَتَيْتُ عَلَى حَكِيمِ بْنِ أَفْلَحَ فَاسْتَلْحَقْتُهُ إِلَيْهَا فَقَالَ مَا أَنَا بِقَارِبِهَا لِأَنِّي نَهَيْتُهَا أَنْ تَقُولَ فِي هَاتَيْنِ الشِّيعَتَيْنِ شَيْئًا فَأَبَتْ فِيهِمَا إِلَّا مُضِيًّا قَالَ فَأَقْسَمْتُ عَلَيْهِ فَجَاءَ فَانْطَلَقْنَا إِلَى عَائِشَةَ فَاسْتَأْذَنَّا عَلَيْهَا فَأَذِنَتْ لَنَا فَدَخَلْنَا عَلَيْهَا فَقَالَتْ أَحَكِيمٌ فَعَرَفَتْهُ فَقَالَ نَعَمْ فَقَالَتْ مَنْ مَعَكَ قَالَ سَعْدُ بْنُ هِشَامٍ قَالَتْ مَنْ هِشَامٌ قَالَ ابْنُ عَامِرٍ فَتَرَحَّمَتْ عَلَيْهِ وَقَالَتْ خَيْرًا قَالَ قَتَادَةُ وَكَانَ أُصِيبَ يَوْمَ أُحُدٍ فَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْبِئِينِي عَنْ خُلُقِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَلَسْتَ تَقْرَأُ الْقُرْآنَ قُلْتُ بَلَى قَالَتْ فَإِنَّ خُلُقَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ الْقُرْآنَ قَالَ فَهَمَمْتُ أَنْ أَقُومَ وَلَا أَسْأَلَ أَحَدًا عَنْ شَيْءٍ حَتَّى أَمُوتَ ثُمَّ بَدَا لِي فَقُلْتُ أَنْبِئِينِي عَنْ قِيَامِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ أَلَسْتَ تَقْرَأُ يَا أَيُّهَا الْمُزَّمِّلُ قُلْتُ بَلَى قَالَتْ فَإِنَّ اللَّهَ عَزَّ وَجَلَّ افْتَرَضَ قِيَامَ اللَّيْلِ فِي أَوَّلِ هَذِهِ السُّورَةِ فَقَامَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ حَوْلًا وَأَمْسَكَ اللَّهُ خَاتِمَتَهَا اثْنَيْ عَشَرَ شَهْرًا فِي السَّمَاءِ حَتَّى أَنْزَلَ اللَّهُ فِي آخِرِ هَذِهِ السُّورَةِ التَّخْفِيفَ فَصَارَ قِيَامُ اللَّيْلِ تَطَوُّعًا بَعْدَ فَرِيضَةٍ قَالَ قُلْتُ يَا أُمَّ الْمُؤْمِنِينَ أَنْبِئِينِي عَنْ وِتْرِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ كُنَّا نُعِدُّ لَهُ سِوَاكَهُ وَطَهُورَهُ فَيَبْعَثُهُ اللَّهُ مَا شَاءَ أَنْ يَبْعَثَهُ مِنْ اللَّيْلِ فَيَتَسَوَّكُ وَيَتَوَضَّأُ وَيُصَلِّي تِسْعَ رَكَعَاتٍ لَا يَجْلِسُ فِيهَا إِلَّا فِي الثَّامِنَةِ فَيَذْكُرُ اللَّهَ وَيَحْمَدُهُ وَيَدْعُوهُ ثُمَّ يَنْهَضُ وَلَا يُسَلِّمُ ثُمَّ يَقُومُ فَيُصَلِّ التَّاسِعَةَ ثُمَّ يَقْعُدُ فَيَذْكُرُ اللَّهَ وَيَحْمَدُهُ وَيَدْعُوهُ ثُمَّ يُسَلِّمُ تَسْلِيمًا يُسْمِعُنَا ثُمَّ يُصَلِّي رَكْعَتَيْنِ بَعْدَ مَا يُسَلِّمُ وَهُوَ قَاعِدٌ وَتِلْكَ إِحْدَى عَشْرَةَ رَكْعَةً يَا بُنَيَّ فَلَمَّا سَنَّ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخَذَهُ اللَّحْمُ أَوْتَرَ بِسَبْعٍ وَصَنَعَ فِي الرَّكْعَتَيْنِ مِثْلَ صَنِيعِهِ الْأَوَّلِ فَتِلْكَ تِسْعٌ يَا بُنَيَّ وَكَانَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى صَلَاةً أَحَبَّ أَنْ يُدَاوِمَ عَلَيْهَا وَكَانَ إِذَا غَلَبَهُ نَوْمٌ أَوْ وَجَعٌ عَنْ قِيَامِ اللَّيْلِ صَلَّى مِنْ النَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةً وَلَا أَعْلَمُ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَرَأَ الْقُرْآنَ كُلَّهُ فِي لَيْلَةٍ وَلَا صَلَّى لَيْلَةً إِلَى الصُّبْحِ وَلَا صَامَ شَهْرًا كَامِلًا غَيْرَ رَمَضَانَ قَالَ فَانْطَلَقْتُ إِلَى ابْنِ عَبَّاسٍ فَحَدَّثْتُهُ بِحَدِيثِهَا فَقَالَ صَدَقَتْ لَوْ كُنْتُ أَقْرَبُهَا أَوْ أَدْخُلُ عَلَيْهَا لَأَتَيْتُهَا حَتَّى تُشَافِهَنِي بِهِ قَالَ قُلْتُ لَوْ عَلِمْتُ أَنَّكَ لَا تَدْخُلُ عَلَيْهَا مَا حَدَّثْتُكَ حَدِيثَهَاو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ أَنَّهُ طَلَّقَ امْرَأَتَهُ ثُمَّ انْطَلَقَ إِلَى الْمَدِينَةِ لِيَبِيعَ عَقَارَهُ فَذَكَرَ نَحْوَهُ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ حَدَّثَنَا قَتَادَةُ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ أَنَّهُ قَالَ انْطَلَقْتُ إِلَى عَبْدِ اللَّهِ بْنِ عَبَّاسٍ فَسَأَلْتُهُ عَنْ الْوِتْرِ وَسَاقَ الْحَدِيثَ بِقِصَّتِهِ وَقَالَ فِيهِ قَالَتْ مَنْ هِشَامٌ قُلْتُ ابْنُ عَامِرٍ قَالَتْ نِعْمَ الْمَرْءُ كَانَ عَامِرٌ أُصِيبَ يَوْمَ أُحُدٍ و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ كِلَاهُمَا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى أَنَّ سَعْدَ بْنَ هِشَامٍ كَانَ جَارًا لَهُ فَأَخْبَرَهُ أَنَّهُ طَلَّقَ امْرَأَتَهُ وَاقْتَصَّ الْحَدِيثَ بِمَعْنَى حَدِيثِ سَعِيدٍ وَفِيهِ قَالَتْ مَنْ هِشَامٌ قَالَ ابْنُ عَامِرٍ قَالَتْ نِعْمَ الْمَرْءُ كَانَ أُصِيبَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ أُحُدٍ وَفِيهِ فَقَالَ حَكِيمُ بْنُ أَفْلَحَ أَمَا إِنِّي لَوْ عَلِمْتُ أَنَّكَ لَا تَدْخُلُ عَلَيْهَا مَا أَنْبَأْتُكَ بِحَدِيثِهَا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna Al 'Anzi] telah menceritakan kepada kami [Muhammad bin Abu 'Adi] dari [Said] dari [Qatadah] dari [Zurarah], bahwa [Sa'd bin Hisyam bin Amir] hendak berangkat berperang fi sabilillah. Ia lalu tiba di kota Madinah dan hendak menjual lahan pilihannya di Madinah untuk ia belikan senjata dan kuda perang, supaya dapat memerangi Romawi hingga mati. Seketika ia tiba di Madinah, ia menemui beberapa orang Madinah. Rupanya mereka melarang menjual lahan miliknya, mereka lalu mengabarinya bahwa pada saat Nabiyullah masih hidup, enam orang berniat seperti itu, namun Nabiyullah shallallahu 'alaihi wasallam melarangnya, beliau bersabda: \"Bukankah dalam diriku terdapat teladan yang baik untukmu?\" Setelah mereka menceritakan hal itu kepada Sa'd, lantas Sa'd kembali merujuk isterinya yang sebelumnya telah dicerai, setelah itu ia bertanya kepada Ibnu Abbas tentang witir Rasulullah shallallahu 'alaihi wasallam. Ibnu Abbas menjawab; \"Maukah kuberitahukan kepadamu kepada orang yang paling tahu tentang witir Rasulullah shallallahu 'alaihi wasallam? Sa'ad bertanya; \"Siapa? Ibnu Abbas menjawab; \" ['Aisyah], datanglah kepadanya, dan bertanyalah, setelah itu datanglah kekadaku, dan beritahukanlah jawabannya kepadaku.\" Maka aku berangkat menemuinya, dan kudatangi Hakim bin Aflah, dan kuminta dia untuk menemui 'Aisyah. rupanya dia menjawab; \"Saya bukan orang yang dekat dengan Aisyah, sebab aku pernah melarang beliau Aisyah untuk berkomentar terhadap sesuatu mengenai dua kubu kaum muslimin yang bertikai. Ternyata Aisyah enggan, dan terus berkomentar tentang dua kubu tersebut.\" Sa'ad berkata; \"Aku pun bersumpah atasnya, hingga Hakim bersedia untuk menemuinya. Kami terus berangkat menuju Aisyah, kami meminta ijin dan Aisyah memberi ijin kepada kami, akhirnya kami menemui beliau. 'Aisyah bertanya; \"Apa benar ini Hakim?\" Rupanya Aisyah mengenalnya. Hakim menjawab; \"Benar.\" Aisytah bertanya; \"Lalu siapa yang bersamamu?\" Hakim menjawab; \"Dia adalah Sa'd bin Hisyam.\" Aisyah bertanya lagi; \"Hisyam siapa?.\" Hakim menjawab; \"Hisyam bin 'Amir.\" Akhirnya 'Aisyah tahu dan bersikap simpati terhadapnya sembari berujar; \"Baiklah, kalau begitu.\" -Qatadah berkata; Hisyam bin Amir gugur ketika perang Uhud- lantas aku (Saad) bertanya; \"Wahai Ummul mukminin, beritahukanlah kepadaku tentang akhlak Rasulullah shallallahu 'alaihi wasallam!.' 'Aisyah menjawab; \"Bukankah engkau telah membaca Alquran?\" Aku menjawab; \"Benar, \" Aisyah berkata; \"Akhlak Nabi shallallahu 'alaihi wasallam adalah Al Quran.\" Sa'd berkata; \"Mendengar itu, aku hendak berdiri dan tidak akan bertanya lagi tentang sesuatu kepada seseorang hingga aku meninggal, kemudian muncul dibenakku, lalu aku bertanya; \"Beritahukanlah kepadaku tentang shalat malamnya Rasulullah shallallahu 'alaihi wasallam?\" 'Aisyah balik bertanya; \"Bukankah engkau pernah membaca surat Al Muzammil? Aku menjawab; \"Benar\" Kata Aisyah; \"Allah Azza wa Jalla pernah mewajibkan qiyamullail (shalat malam) di awal surat ini turun, sehingga Nabiyullah shallallahu 'alaihi wasallam dan para sahabatnya mendirikannya selama setahun, dan Allah menahan penutupnya di langit selama dua belas bulan hingga Allah turunkan akhir surat ini sebagai bentuk keringanan, sehingga shalat malam menjadi sunnah setelah diwajibkan. Kata Sa'ad; \"Wahai Ummul mukminin, beritahukanlah kepadaku tentang witir Rasulullah shallallahu 'alaihi wasallam! Jawabnya; \"Kami dulu sering mempersiapkan siwaknya dan bersucinya, setelah itu Allah membangunkannya sekehendaknya untuk bangun malam. Beliau lalu bersiwak dan berwudhu` dan shalat sembilan rakaat. Beliau tidak duduk dalam kesembilan rakaat itu selain pada rakaat kedelapan, beliau menyebut nama Allah, memuji-Nya dan berdoa kepada-Nya, kemudian beliau bangkit dan tidak mengucapkan salam. Setelah itu beliau berdiri dan shalat untuk rakaat ke sembilannya. Kemudian beliau berdzikir kepada Allah, memuji-Nya dan berdoa kepada-Nya, lalu beliau mengucapkan salam dengan nyaring agar kami mendengarnya. Setelah itu beliau shalat dua rakaat setelah salam sambil duduk, itulah sebelas rakaat wahai anakku. Ketika Nabiyullah berusia lanjut dan beliau telah merasa kegemukan, beliau berwitir dengan tujuh rakaat, dan beliau lakukan dalam dua rakaatnya sebagaimana yang beliau lakukan pada yang pertama, maka itu berarti sembilan wahai anakku. Jika Rasulullah shallallahu 'alaihi wasallam mengerjakan shalat, maka beliau suka dikerjakan secara terus menerus (kontinyu). Jika beliau ketiduran atau sedang sakit sehingga tidak dapat melakukannya di malam hari, maka beliau shalat di waktu siangnya sebanyak dua belas rakaat, seingatku Nabiyullah shallallahu 'alaihi wasallam tidak pernah membaca satu mushaf (keseluruhan Alquran) dalam satu malam, tidak pula shalat malam hingga subuh, tidak pula pula puasa sebulan penuh selain bulan Ramadhan.\" Kata Sa'ad; \"Setelah itu aku berangkat menemui Ibnu Abbas, aku lalu menceritakan kepadanya tentang haditsnya tersebut, Ibnu Abbas lalu berkata; \"Aisyah benar.\" Kalaulah aku mendekatinya atau menemuinya, tentu aku menemuinya hingga berhadapan satu sama lain untuk menyampaikan hadits tersebut. Sa'ad melanjutkan; Aku berkata; \"Sekiranya aku tahu bahwa engkau tidak menemuinya, tentu tidak aku ceritakan kepadamu hadits tersebut.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsannana] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [Ayahku] dari [Qatadah] dari [Zurarah bin Abu Aufa] dari [Sa'id bin Hisyam], bahwa ia pernah mencerai isterinya, kemudian ia berangkat ke Madinah untuk menjual lahan pilihannya, lantas ia menyebutkan hadits yang serupa. Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Said bin Abu Arubah] telah menceritakan kepada kami [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] bahwa ia mengatakan; aku pergi menemui Abdullah bin Abbas dan bertanya kepadanya tentang shalat witir, lalu ia menyebutkan hadis beserta kisahnya, dan dalam haditsnya, dia menyebutkan; Aisyah bertanya; 'Hisyam siapa?\" Aku menjawab; \"Ibnu 'Amir.\" Kata 'Aisyah; \"Dia adalah sebaik-baik orang.\" Amir gugur dalam perang Uhud. Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Rafi'] keduanya dari [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Qatadah] dari [Zurarah bin Aufa], bahwa [Sa'd bin Hisyam] adalah tetangganya, lantas Sa'd mengabarkan kepadanya bahwa ia telah mencerai isterinya dan ia kisahkan hadis semakna hadis Sa'id, dalam redaksinya disebutkan; Aisyah berkata; \"Hisyam siapa?\" Sa'd menjawab; \"Hisyam bin Amir. Aisyah menjawab; \"Dia adalah sebaik-baik orang, ia gugur ketika berperang bersama Rasulullah shallallahu 'alaihi wasallam pada perang Uhud.\" Dan dalam hadits tersebut disebutkan; \"Maka Hakim bin Aflah berujar; \"Kalaulah aku tahu bahwa engkau tidak menemuinya, tentu aku tidak menceritakan hadits ini kepadamu.\""},"1166":{"ar":"حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ وَقُتَيْبَةُ بْنُ سَعِيدٍ جَمِيعًا عَنْ أَبِي عَوَانَةَ قَالَ سَعِيدٌ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا فَاتَتْهُ الصَّلَاةُ مِنْ اللَّيْلِ مِنْ وَجَعٍ أَوْ غَيْرِهِ صَلَّى مِنْ النَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةً","id":"Telah menceritakan kepada kami [Said bin Manshur] dan [Qutaibah bin Said], semuanya dari [Abu 'Awanah], [Said] mengatakan; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah], bahwa apabila Rasulullah shallallahu 'alaihi wasallam ketinggalan shalat malam karena sakit atau lainnya, maka beliau melaksanakan shalat pada siangnya sebanyak dua belas rakaat.\""},"1167":{"ar":"و حَدَّثَنَا عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى وَهُوَ ابْنُ يُونُسَ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ عَنْ سَعْدِ بْنِ هِشَامٍ الْأَنْصَارِيِّ عَنْ عَائِشَةَ قَالَتْكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَمِلَ عَمَلًا أَثْبَتَهُ وَكَانَ إِذَا نَامَ مِنْ اللَّيْلِ أَوْ مَرِضَ صَلَّى مِنْ النَّهَارِ ثِنْتَيْ عَشْرَةَ رَكْعَةً قَالَتْ وَمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ لَيْلَةً حَتَّى الصَّبَاحِ وَمَا صَامَ شَهْرًا مُتَتَابِعًا إِلَّا رَمَضَانَ","id":"Dan telah menceritakan kepada kami [Ali bin Khasyram] telah mengabarkan kepada kami [Isa yaitu Ibnu Yunus], dari [Syu'bah] dari [Qatadah] dari [Zurarah] dari [Sa'd bin Hisyam Al Anshari] dari ['Aisyah] katanya; \"Jika Rasulullah shallallahu 'alaihi wasallam melakukan suatu aktivitas, maka beliau berusaha melanggengkannya (menjadikan abadi, rutin), jika beliau ketiduran malam hari atau sakit, maka beliau melaksanakan shalat dua belas raka'at di siang harinya.\" 'Aisyah melanjutkan; \"Aku tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam shalat malam hingga pagi hari, dan beliau juga tidak pernah berpuasa sebulan penuh secara turut berturut selain bulan Ramadhan.\""},"1168":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ ح و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ ابْنِ شِهَابٍ عَنْ السَّائِبِ بْنِ يَزِيدَ وَعُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ أَخْبَرَاهُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ عَنْ حِزْبِهِ أَوْ عَنْ شَيْءٍ مِنْهُ فَقَرَأَهُ فِيمَا بَيْنَ صَلَاةِ الْفَجْرِ وَصَلَاةِ الظُّهْرِ كُتِبَ لَهُ كَأَنَّمَا قَرَأَهُ مِنْ اللَّيْلِ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] telah menceritakan kepada kami [Abdullah bin Wahb], (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Abu Thahir] dan [Harmalah], keduanya berkata; telah mengabarkan kepada kami [Ibnu Wahab] dari [Yunus bin Yazid] dari [Ibnu Syihab] dari [Sa'ib bin Yazid] dan ['Ubaidullah bin Abdillah], keduanya mengebarkan kepadanya, dari [Abdurrahman bin Abdul Qari`], katanya; aku mendengar [Umar bin Khattab] mengatakan; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang ketiduran dari hizib (bacaan alquran) atau sesuatu daripadanya, lantas ia membacanya ketika diantara shalat fajar (subuh) dan shalat zhuhur, maka akan dicatat baginya sebagaimana ia membacanya ketika malam hari.\""},"1169":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ الْقَاسِمِ الشَّيْبَانِيِّأَنَّ زَيْدَ بْنَ أَرْقَمَ رَأَى قَوْمًا يُصَلُّونَ مِنْ الضُّحَى فَقَالَ أَمَا لَقَدْ عَلِمُوا أَنَّ الصَّلَاةَ فِي غَيْرِ هَذِهِ السَّاعَةِ أَفْضَلُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ الْأَوَّابِينَ حِينَ تَرْمَضُ الْفِصَالُ","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Ibnu Numair] keduanya berkata; telah menceritakan kepada kami [Ismail yaitu Ibnu 'Ulayyah] dari [Ayyub] dari [Al Qasim Asy Syaibani] bahwa [Zaid bin Arqam] pernah melihat suatu kaum yang tengah mengerjakan shalat dluha, lalu dia berkata; \"Tidakkah mereka tahu bahwa shalat diluar waktu ini lebih utama? sebab Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat awwabin (orang yang bertaubat) dikerjakan ketika anak unta mulai beranjak karena kepanasan.\""},"1170":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامِ بْنِ أَبِي عَبْدِ اللَّهِ قَالَ حَدَّثَنَا الْقَاسِمُ الشَّيْبَانِيُّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَهْلِ قُبَاءَ وَهُمْ يُصَلُّونَ فَقَالَ صَلَاةُ الْأَوَّابِينَ إِذَا رَمِضَتْ الْفِصَالُ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam bin Abu Abdullah] katanya; telah menceritakan kepada kami [Al Qasim Asy Syaibani] dari [Zaid bin Arqam] katanya; Rasulullah shallallahu 'alaihi wasallam pernah berangkat menemui penduduk Quba' ketika mereka tengah mengerjakan shalat, lalu beliau bersabda: \"Shalat awwabin (orang yang bertaubat) dikerjakan ketika anak unta mulai beranjak karena kepanasan.\""},"1171":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَ زُهَيْرٌ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبَّادٍ وَاللَّفْظُ لَهُ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَمْرٌو عَنْ طَاوُسٍ عَنْ ابْنِ عُمَرَ ح و حَدَّثَنَا الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَلَاةِ اللَّيْلِ فَقَالَ مَثْنَى مَثْنَى فَإِذَا خَشِيتَ الصُّبْحَ فَأَوْتِرْ بِرَكْعَةٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan ['Amru An Naqid] dan [Zuhair bin Harb] kata [Zuhair]; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Zuhri] dari [Salim] dari [Ayahnya] ia mendengar Nabi shallallahu 'alaihi wasallam bersabda, (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Muhammad bin 'Abbad] dan lafadz miliknya, telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami ['Amru] dari [Thawus] dari [Ibnu Umar], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Az Zuhri] dari [Salim] dari [Ayahnya] bahwa seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam tentang shalat malam, beliau menjawab: \"Dua-dua, jika engkau khawatir tiba waktu shalat subuh, maka witirlah satu rakaat.\""},"1172":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ أَنَّ سَالِمَ بْنَ عَبْدِ اللَّهِ بْنِ عُمَرَ وَحُمَيْدَ بْنَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ حَدَّثَاهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ بْنِ الْخَطَّابِ أَنَّهُ قَالَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ صَلَاةُ اللَّيْلِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا خِفْتَ الصُّبْحَ فَأَوْتِرْ بِوَاحِدَةٍ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahab] telah mengabarkan kepadaku ['Amru] bahwa [Ibnu Syihab], telah menceritakannya kepadanya, bahwa [Salim bin Abdullah bin Umar] dan [Humaid bin Abdurrahman bin 'Auf], keduanya menceritakan kepadanya dari [Abdullah bin Umar bin Khattab], dia mengatakan; \"Seorang laki-laki berdiri dan berkata; \"Wahai Rasulullah, Bagaimanakah tata cara shalat malam?\" Beliau menjawab: \"Shalat malam dua-dua, jika kamu khawatir tiba awaktu subuh, maka witirlah sekali (satu raka'at).\""},"1173":{"ar":"و حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ وَبُدَيْلٌ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَجُلًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بَيْنَهُ وَبَيْنَ السَّائِلِ فَقَالَ يَا رَسُولَ اللَّهِ كَيْفَ صَلَاةُ اللَّيْلِ قَالَ مَثْنَى مَثْنَى فَإِذَا خَشِيتَ الصُّبْحَ فَصَلِّ رَكْعَةً وَاجْعَلْ آخِرَ صَلَاتِكَ وِتْرًا ثُمَّ سَأَلَهُ رَجُلٌ عَلَى رَأْسِ الْحَوْلِ وَأَنَا بِذَلِكَ الْمَكَانِ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَا أَدْرِي هُوَ ذَلِكَ الرَّجُلُ أَوْ رَجُلٌ آخَرُ فَقَالَ لَهُ مِثْلَ ذَلِكَو حَدَّثَنِي أَبُو كَامِلٍ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ وَبُدَيْلٌ وَعِمْرَانُ بْنُ حُدَيْرٍ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ ابْنِ عُمَرَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ وَالزُّبَيْرُ بْنُ الْخِرِّيتِ عَنْ عَبْدِ اللَّهِ بْنِ شَقِيقٍ عَنْ ابْنِ عُمَرَ قَالَ سَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَا بِمِثْلِهِ وَلَيْسَ فِي حَدِيثِهِمَا ثُمَّ سَأَلَهُ رَجُلٌ عَلَى رَأْسِ الْحَوْلِ وَمَا بَعْدَهُ","id":"Dan telah menceritakan kepadaku [Abu Rabi' Az Zarani] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Ayyub] dan [Budail] dari [Abdullah bin Syaqiq] dari [Abdullah bin Umar], bahwa seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam, ketika itu aku berada diantara beliau dan penanya; \"Wahai Rasulullah, bagaimanakah tata cara shalat malam?\" Beliau menjawab: \"Dua-dua, jika kamu khawatir tiba waktu shalat subuh, maka (witirlah) satu rakaat, dan jadikanlah akhir shalatmu witir.\" Tidak beberapa lama, seorang laki-laki yang telah mengakhiri masa berkabungnya bertanya kepada beliau, ketika itu aku masih disisi Rasulullah shallallahu 'alaihi wasallam. Aku tidak tahu, apakah yang bertanya laki-laki tadi ataukah laki-laki lain, dia bertanya kepada beliau seperti sebelumnya.\" Dan telah menceritakan kepadaku [Abu Kamil] telah menceritakan kepadaku [Hammad] telah menceritakan kepada kami [Ayyub] dan [Budail] dan ['Imran bin Hudair] dari [Abdullah bin Syaqiq] dari [Ibnu Umar], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Muhammad bin 'Ubaid Al Ghubari] dan telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Ayyub] dan [Zubair bin Khirrit] dari [Abdullah bin Syaqiq] dari [Ibnu Umar] katanya; \"Seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam…\" lantas keduanya menyebutkan hadits semisalnya, dan dalam hadis keduanya tak ada kalimat \"Kemudian seorang laki-laki yang telah mengakhiri masa berkabungnya bertanya kepada beliau.\" "},"1174":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا ابْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ قَالَمَنْ صَلَّى مِنْ اللَّيْلِ فَلْيَجْعَلْ آخِرَ صَلَاتِهِ وِتْرًا فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ بِذَلِكَ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Said] telah menceritakan kepada kami [Laits], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibn Rumh] telah mengabarkan kepada kami [Al Laits] dari [Nafi'] bahwa [Ibnu Umar] berkata; \"Barangsiapa mengerjakan shalat malam, hendaknya ia menjadikan akhir shalatnya witir, sebab Rasulullah shallallahu 'alaihi wasallam menyuruh yang demikian.\""},"1175":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَابْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى كُلُّهُمْ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْعَلُوا آخِرَ صَلَاتِكُمْ بِاللَّيْلِ وِتْرًا","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah], (dan diriwayatkan dari jalur lain) telah menceritakan kepada kami [Ibn Numair] telah menceritakan kepada kami [ayahku], (dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Zuhair bin Harb] dan [Ibnu Al Mutsanna] keduanya berkata; telah menceritakan kepada kami [Yahya], semuanya dari ['Ubaidullah], dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Jadikanlah akhir shalat malam kalian dengan witir.\""},"1176":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ أَبِي التَّيَّاحِ قَالَ حَدَّثَنِي أَبُو مِجْلَزٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوِتْرُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِ","id":"Telah menceritakan kepada kami [Syaiban bin Farukh] telah menceritakan kepada kami [Abdul Warits] dari [Abu Tayyah] katanya; telah menceritakan kepadaku [Abu Mijlaz] dari [Ibnu Umar] katanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Witir adalah satu rakaat yang dilakukan di akhir malam.\""},"1177":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَبِي مِجْلَزٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يُحَدِّثُعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوِتْرُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basyar], kata [Ibnul Mutsanna]; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Abu Mijlaz] katanya; Aku mendengar [Ibnu Umar] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Witir adalah satu rakaat yang dilakukan di akhir malam.\""},"1178":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَبِي مِجْلَزٍ قَالَسَأَلْتُ ابْنَ عَبَّاسٍ عَنْ الْوِتْرِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِوَسَأَلْتُ ابْنَ عُمَرَ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رَكْعَةٌ مِنْ آخِرِ اللَّيْلِ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdusshamad] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Abu Mijlaz] katanya; aku bertanya kepada [Ibnu Abbas] tentang witir, dia menjawab; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu rakaat dari akhir (shalat) malam.\"dan saya bertanya kepada [Ibnu Umar] maka beliau menjawab; Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu rakaat dari akhir (shalat) malam.\""},"1179":{"ar":"حَدَّثَنَا خَلَفُ بْنُ هِشَامٍ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَنَسِ بْنِ سِيرِينَ قَالَسَأَلْتُ ابْنَ عُمَرَ قُلْتُ أَرَأَيْتَ الرَّكْعَتَيْنِ قَبْلَ صَلَاةِ الْغَدَاةِ أَؤُطِيلُ فِيهِمَا الْقِرَاءَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ مَثْنَى مَثْنَى وَيُوتِرُ بِرَكْعَةٍ قَالَ قُلْتُ إِنِّي لَسْتُ عَنْ هَذَا أَسْأَلُكَ قَالَ إِنَّكَ لَضَخْمٌ أَلَا تَدَعُنِي أَسْتَقْرِئُ لَكَ الْحَدِيثَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ مَثْنَى مَثْنَى وَيُوتِرُ بِرَكْعَةٍ وَيُصَلِّي رَكْعَتَيْنِ قَبْلَ الْغَدَاةِ كَأَنَّ الْأَذَانَ بِأُذُنَيْهِقَالَ خَلَفٌ أَرَأَيْتَ الرَّكْعَتَيْنِ قَبْلَ الْغَدَاةِ وَلَمْ يَذْكُرْ صَلَاةِ و حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَنَسِ بْنِ سِيرِينَ قَالَ سَأَلْتُ ابْنَ عُمَرَ بِمِثْلِهِ وَزَادَ وَيُوتِرُ بِرَكْعَةٍ مِنْ آخِرِ اللَّيْلِ وَفِيهِ فَقَالَ بَهْ بَهْ إِنَّكَ لَضَخْمٌ","id":"Telah menceritakan kepada kami [Khalaf bin Hisyam] dan [Abu Kamil] keduanya berkata, telah menceritakan kepada kami [Hammad bin Zaid] dari [Anas bin Sirin] ia berkata; Saya bertanya kepada [Ibnu Umar], \"Bagaimana menurutmu tentang shalat sunnah sebelum shalat Ghadat (Shubuh), apakah saya memanjangkan bacaannya?\" Ibnu Umar menjawab, \"Biasanya Rasulullah shallallahu 'alaihi wasallam shalat malam dua raka'at dua raka'at dan witir satu raka'at.\" Anas bin Sirin berkata; Saya berkata, \"Bukan ini yang saya tanyakan padamu.\" Ibnu Umar berkata, \"Kamu ini benar-bernar seorang yang besar tubuhnya, apakah kamu meninggalkanku membacakan hadits bahwasanya; Rasulullah shallallahu 'alaihi wasallam shalat malam dua raka'at dua raka'at dan shalat witir satu raka'at. Kemudian beliau shalat dua raka'at sebelum shalat Ghadat (Shubuh), dan sepertinya adzan telah berdengung di kedua telinganya.\" Khalaf berkata; \"Bagaimana pendapat Anda mengenai dua raka'at sebelum Shubuh?\" ia tidak menyebutkan kata Shalat. Dan Telah menceritakan kepada kami [Ibnul Mutsanna] dan [Ibnu Basysyar] keduanya berkata, Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Anas bin Sirin] ia berkata; Saya bertanya kepada [Ibnu Umar] hadits yang semisal. Dan ia menambahkan; \"Dan beliau shalat witir satu raka'at di akhir malam.\" Dan di dalamnya juga terdapat ungkapan; \"Bah..bah.., kamu ini benar-benar seorang yang besar tubuhnya.\""},"1180":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عُقْبَةَ بْنَ حُرَيْثٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلَاةُ اللَّيْلِ مَثْنَى مَثْنَى فَإِذَا رَأَيْتَ أَنَّ الصُّبْحَ يُدْرِكُكَ فَأَوْتِرْ بِوَاحِدَةٍفَقِيلَ لِابْنِ عُمَرَ مَا مَثْنَى مَثْنَى قَالَ أَنْ تُسَلِّمَ فِي كُلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Uqbah bin Huraits] ia berkata, saya mendengar [Ibnu Umar] menceritakan bahwasanya; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat malam itu dua raka'at dua raka'at. Jika kamu telah merasa bahwa waktu Shubuh akan segera masuk, maka shalat witirlah dengan satu raka'at.\" Kemudian ditanyakanlah kepada Ibnu Umar, \"Apa artinya dua-dua?\" Ibnu Umar menjawab, \"Yaitu, kamu mengucapkan salam setiap dua raka'at.\""},"1181":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ خَافَ أَنْ لَا يَقُومَ مِنْ آخِرِ اللَّيْلِ فَلْيُوتِرْ أَوَّلَهُ وَمَنْ طَمِعَ أَنْ يَقُومَ آخِرَهُ فَلْيُوتِرْ آخِرَ اللَّيْلِ فَإِنَّ صَلَاةَ آخِرِ اللَّيْلِ مَشْهُودَةٌ وَذَلِكَ أَفْضَلُو قَالَ أَبُو مُعَاوِيَةَ مَحْضُورَةٌ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Hafsh] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang khawatir tidak bisa bangun di akhir malam, hendaklah ia melakukan witir di awal malam. Dan siapa yang berharap mampu bangun di akhir malam, hendaklah ia witir di akhir malam, karena shalat di akhir malam disaksikan (oleh para malaikat) dan hal itu adalah lebih afdlal (utama).\" Abu Mu'awiyah berkata; \"Mahdlurah (dihadiri oleh para malaikat).\""},"1182":{"ar":"و حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا مَعْقِلٌ وَهُوَ ابْنُ عُبَيْدِ اللَّهِ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّكُمْ خَافَ أَنْ لَا يَقُومَ مِنْ آخِرِ اللَّيْلِ فَلْيُوتِرْ ثُمَّ لِيَرْقُدْ وَمَنْ وَثِقَ بِقِيَامٍ مِنْ اللَّيْلِ فَلْيُوتِرْ مِنْ آخِرِهِ فَإِنَّ قِرَاءَةَ آخِرِ اللَّيْلِ مَحْضُورَةٌ وَذَلِكَ أَفْضَلُ","id":"Dan telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] Telah menceritakan kepada kami [Ma'qil] ia adalah Ibnu Ubaidullah, dari [Abu Zubair] dari [Jabir] ia berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa di antara kalian yang khawatir tidak bisa bangun di akhir malam, hendaklah ia witir dan baru kemudian tidur. Dan siapa yang yakin akan terbangun di akhir malam, hendaklah ia witir di akhir malam, karena bacaan di akhir malam dihadiri (oleh para Malaikat) dan hal itu adalah lebih utama.\""},"1183":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْضَلُ الصَّلَاةِ طُولُ الْقُنُوتِ","id":"Telah menceritakan kepada kami [Abdu Humaid] telah mengabarkan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Abu Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Shalat yang paling Afdlal (utama) adalah shalat yang lama berdirinya.\""},"1184":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الصَّلَاةِ أَفْضَلُ قَالَ طُولُ الْقُنُوتِقَالَ أَبُو بَكْرٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abi Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Mu'awiyah] telah menceritakan kepada kami [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya, \"Shalat (malam) yang bagaimanakah yang paling utama?\" beliau menjawab: \"(Yaitu shalat malam) yang paling lama berdirinya.\" Abu Bakr berkata, Telah menceritakan kepada kami Abu Mu'awiyah dari Al A'masy."},"1185":{"ar":"و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ فِي اللَّيْلِ لَسَاعَةً لَا يُوَافِقُهَا رَجُلٌ مُسْلِمٌ يَسْأَلُ اللَّهَ خَيْرًا مِنْ أَمْرِ الدُّنْيَا وَالْآخِرَةِ إِلَّا أَعْطَاهُ إِيَّاهُ وَذَلِكَ كُلَّ لَيْلَةٍ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di waktu malam terdapat suatu saat, tidaklah seorang muslim mendapati saat itu, lalu ia memohon kebaikan kepada Allah 'azza wajalla baik kebaikan dunia maupun akhirat, kecuali Allah memperkenankannya. Demikian itu terjadi pada setiap malam.\""},"1186":{"ar":"و حَدَّثَنِي سَلَمَةُ بْنُ شَبِيبٍ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ حَدَّثَنَا مَعْقِلٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ مِنْ اللَّيْلِ سَاعَةً لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ يَسْأَلُ اللَّهَ خَيْرًا إِلَّا أَعْطَاهُ إِيَّاهُ","id":"Dan telah menceritakan kepadaku [Salamah bin Syabib] telah menceritakan kepada kami [Al Hasan bin A'yan] telah menceritakan kepada kami [Ma'qil] dari [Abu Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya di antara waktu malam itu terdapat suatu saat, tidaklah seorang muslim menemui saat itu dan memohon kebaikan kepada Allah, kecuali Allah akan memperkenankannya.\""},"1187":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي عَبْدِ اللَّهِ الْأَغَرِّ وَعَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ رَبُّنَا تَبَارَكَ وَتَعَالَى كُلَّ لَيْلَةٍ إِلَى السَّمَاءِ الدُّنْيَا حِينَ يَبْقَى ثُلُثُ اللَّيْلِ الْآخِرُ فَيَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ وَمَنْ يَسْأَلُنِي فَأُعْطِيَهُ وَمَنْ يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Ibnu Syihab] dari [Abu Abdullah Al Agharr] dan dari [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rabb Tabaraka wa Ta'la turun ke langit dunia pada setiap malam, yakni saat sepertiga malam terakhir seraya berfirman, 'Siapa yang berdo'a kepadaKu niscaya akan Aku kabulkan dan siapa yang meminta kepadaKu niscaya akan Aku berikan dan siapa yang memohon ampun kepadaKu, niscaya akan Aku ampuni.'\""},"1188":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْقَارِيُّ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَنْزِلُ اللَّهُ إِلَى السَّمَاءِ الدُّنْيَا كُلَّ لَيْلَةٍ حِينَ يَمْضِي ثُلُثُ اللَّيْلِ الْأَوَّلُ فَيَقُولُ أَنَا الْمَلِكُ أَنَا الْمَلِكُ مَنْ ذَا الَّذِي يَدْعُونِي فَأَسْتَجِيبَ لَهُ مَنْ ذَا الَّذِي يَسْأَلُنِي فَأُعْطِيَهُ مَنْ ذَا الَّذِي يَسْتَغْفِرُنِي فَأَغْفِرَ لَهُ فَلَا يَزَالُ كَذَلِكَ حَتَّى يُضِيءَ الْفَجْرُ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub] ia dalah Ibnu Abdurrahman Al Qariy, dari [Suhail bin Abu Shalih] dari [bapaknya] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Allah turun ke langit dunia pada setiap malamnya, yaitu saat sepertiga malam terakhir seraya berfirman, 'Aku adalah Raja, Aku adalah Raja, Siapa yang berdo'a padaKu niscaya akan Aku kabulkan dan siapa yang meminta kepadaKu niscaya akan Aku berikan dan siapa yang meminta ampun kepadaKu, niscaya akan Aku ampuni.' Keadaan itu berlangsung hingga tiba waktu.\""},"1189":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا مَضَى شَطْرُ اللَّيْلِ أَوْ ثُلُثَاهُ يَنْزِلُ اللَّهُ تَبَارَكَ وَتَعَالَى إِلَى السَّمَاءِ الدُّنْيَا فَيَقُولُ هَلْ مِنْ سَائِلٍ يُعْطَى هَلْ مِنْ دَاعٍ يُسْتَجَابُ لَهُ هَلْ مِنْ مُسْتَغْفِرٍ يُغْفَرُ لَهُ حَتَّى يَنْفَجِرَ الصُّبْحُ","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Abul Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika pertengahan malam atau sepertiga malam telah berlalu, Allah Tabaraka wa Ta'ala turun ke langit dunia dan berfirman, 'Adakah orang yang meminta hingga diberi, adakah orang yang berdo'a hingga dikabulkan, dan adakah orang yang memohon ampun hingga dosanya diampuni.' Demikian itu terjadi hingga waktu Shubuh datang.\""},"1190":{"ar":"حَدَّثَنِي حَجَّاجُ بْنُ الشَّاعِرِ حَدَّثَنَا مُحَاضِرٌ أَبُو الْمُوَرِّعِ حَدَّثَنَا سَعْدُ بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي ابْنُ مَرْجَانَةَ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْزِلُ اللَّهُ فِي السَّمَاءِ الدُّنْيَا لِشَطْرِ اللَّيْلِ أَوْ لِثُلُثِ اللَّيْلِ الْآخِرِ فَيَقُولُ مَنْ يَدْعُونِي فَأَسْتَجِيبَ لَهُ أَوْ يَسْأَلُنِي فَأُعْطِيَهُ ثُمَّ يَقُولُ مَنْ يُقْرِضُ غَيْرَ عَدِيمٍ وَلَا ظَلُومٍقَالَ مُسْلِم ابْنُ مَرْجَانَةَ هُوَ سَعِيدُ بْنُ عَبْدِ اللَّهِ وَمَرْجَانَةُ أُمُّهُ حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ سَعْدِ بْنِ سَعِيدٍ بِهَذَا الْإِسْنَادِ وَزَادَ ثُمَّ يَبْسُطُ يَدَيْهِ تَبَارَكَ وَتَعَالَى يَقُولُ مَنْ يُقْرِضُ غَيْرَ عَدُومٍ وَلَا ظَلُومٍ","id":"Telah menceritakan kepadaku [Hajjaj bin Sya'ir] telah menceritakan kepada kami [Muhadlir Abul Muwarri'] Telah menceritakan kepada kami [Sa'd bin Sa'id] ia berkata, telah mengabarkan kepadaku [Ibnu Marjanah] ia berkata, saya mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah turun ke langit dunia pada pertengahan atau sepertiga malam terakhir seraya berfirman, 'Siapa yang memohon kepadaKu, niscya akan Aku perkenankan permohonannya, atau siapa yang meminta padaKu, niscaya akan Aku beri.' Kemudian Dia berfirman, 'Siapakah yang dapat berbuat ketaatan tanpa kefakiran atau kezhaliman? '\" Muslim berkata; Ibnu Marjanah adalah Sa'id bin Abdullah, dan Marjanah adalah ibunya. Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] Telah menceritakan kepada kami [Ibnu Wahb] ia berkata, telah mengabarkan kepadaku [Sulaiman bin Bilal] dari [Sa'd bin Sa'id] dengan sanad-sanad ini. Dan ia menambahkan, \"Kemudian (Allah) Tabaraka wa Ta'ala membentangkan kedua tanganNya seraya berfirman, 'Siapakah yang berbuat ketaatan tanpa kefakiran atau kezhaliman? '\""},"1191":{"ar":"حَدَّثَنَا عُثْمَانُ وَأَبُو بَكْرِ ابْنَا أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ الْحَنْظَلِيُّ وَاللَّفْظُ لِابْنَيْ أَبِي شَيْبَةَ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي إِسْحَقَ عَنْ الْأَغَرِّ أَبِي مُسْلِمٍ يَرْوِيهِ عَنْ أَبِي سَعِيدٍ وَأَبِي هُرَيْرَةَ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُمْهِلُ حَتَّى إِذَا ذَهَبَ ثُلُثُ اللَّيْلِ الْأَوَّلُ نَزَلَ إِلَى السَّمَاءِ الدُّنْيَا فَيَقُولُ هَلْ مِنْ مُسْتَغْفِرٍ هَلْ مِنْ تَائِبٍ هَلْ مِنْ سَائِلٍ هَلْ مِنْ دَاعٍ حَتَّى يَنْفَجِرَ الْفَجْرُو حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ حَدِيثَ مَنْصُورٍ أَتَمُّ وَأَكْثَرُ","id":"Telah menceritakan kepada kami [Utsman] dan [Abu Bakr] keduanya adalah anak dari Abu Syaibah dan [Ishaq bin Ibrahim Al Hanzhali] sedangkan lafazhnya dari Ibnu Abu Syaibah, [Ishaq] berkata, telah mengabarkan kepada kami -sementara dua orang yang lain- berkata, Telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Ishaq] dari [Al Agharr Abu Muslim] ia meriwayatkannya dari [Abu Sa'id] dan [Abu Hurairah] keduanya berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menunda hingga sepertiga malam pertama berlalu, Dia pun turun ke langit dunia dan berfirman, 'Adalah orang yang meminta ampun? Adakah orang yang bertaubat? Adakah orang yang meminta? Adakah orang yang memohon? ' hingga fajar terbit.\" Dan Telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya berkata, Telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dengan sanad-sanad ini, hanya saja hadits Manshur lebih lengkap dan banyak."},"1192":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Ibnu Syihab] dari [Humaid bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang menunaikan shalat pada malam bulan Ramadlan (shalat tarawih) dengan penuh keimanan dan mengharap (pahala dari Allah), maka dosa-dosanya yang telah berlalu akan diampuni.\""},"1193":{"ar":"و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَغِّبُ فِي قِيَامِ رَمَضَانَ مِنْ غَيْرِ أَنْ يَأْمُرَهُمْ فِيهِ بِعَزِيمَةٍ فَيَقُولُ مَنْ قَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِفَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْأَمْرُ عَلَى ذَلِكَ ثُمَّ كَانَ الْأَمْرُ عَلَى ذَلِكَ فِي خِلَافَةِ أَبِي بَكْرٍ وَصَدْرًا مِنْ خِلَافَةِ عُمَرَ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami ['Abdu bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam memberikan motivasi untuk mengerjakan (shalat pada malam) Ramadlan dengan tidak mewajibkannya. Beliau bersabda: \"Barangsiapa yang menunaikan (shalat pada malam) Ramadlan dengan penuh keimanan dan mengharap (pahala dari Allah), maka dosa-dosanya yang telah berlalu akan diampuni.\" Kemudian Rasulullah shallallahu 'alaihi wasallam wafat, sementara perkara itu tetap seperti itu. Demikian pula pada kekhilafahan Abu Bakar hingga permulaan kekhilafahan Umar."},"1194":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَامَ رَمَضَانَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ وَمَنْ قَامَ لَيْلَةَ الْقَدْرِ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ مَا تَقَدَّمَ مِنْ ذَنْبِهِ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Yahya bin Abu Katsir] ia berkata, telah menceritakan kepada kami [Abu Salamah bin Abdurrahman] bahwa [Abu Hurairah] telah menceritakan kepada mereka, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berpuasa pada bulan Ramadlan dengan penuh keimanan dan mengharap (pahala dari Allah), maka dosa-dosanya yang telah lalu akan diampuni. Dan siapa yang menegakkan (shalat pada malam) Lailatul Qadr dengan keimanan dan mengharap (pahala dari Allah), maka dosa-dosanya yang telah lalu akan diampuni.\""},"1195":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا شَبَابَةُ حَدَّثَنِي وَرْقَاءُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَقُمْ لَيْلَةَ الْقَدْرِ فَيُوَافِقُهَا أُرَاهُ قَالَ إِيمَانًا وَاحْتِسَابًا غُفِرَ لَهُ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Syababah] telah menceritakan kepadaku [Warqa`] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang menegakkan (shalat dengan mengharap) malam Lailatul Qadr, lalu ia mendapatinya, -menurutku ia mengatakan- dengan penuh keimanan dan pengharapan (akan pahala dari Allah), maka ia akan diampuni.\""},"1196":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى فِي الْمَسْجِدِ ذَاتَ لَيْلَةٍ فَصَلَّى بِصَلَاتِهِ نَاسٌ ثُمَّ صَلَّى مِنْ الْقَابِلَةِ فَكَثُرَ النَّاسُ ثُمَّ اجْتَمَعُوا مِنْ اللَّيْلَةِ الثَّالِثَةِ أَوْ الرَّابِعَةِ فَلَمْ يَخْرُجْ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا أَصْبَحَ قَالَ قَدْ رَأَيْتُ الَّذِي صَنَعْتُمْ فَلَمْ يَمْنَعْنِي مِنْ الْخُرُوجِ إِلَيْكُمْ إِلَّا أَنِّي خَشِيتُ أَنْ تُفْرَضَ عَلَيْكُمْ قَالَ وَذَلِكَ فِي رَمَضَانَ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Ibnu Syihab] dari [Urwah] dari [Aisyah] bahwasanya; Pada suatu malam (di bulan Ramadlan), Rasulullah shallallahu 'alaihi wasallam shalat di Masjid, lalu diikuti oleh beberapa orang sahabat. Kemudian (pada malam kedua) beliau shalat lagi, dan ternyata diikuti oleh banyak orang. Dan pada malam ketiga atau keempat mereka berkumpul, namun Rasulullah shallallahu 'alaihi wasallam tidak keluar shalat bersama mereka. Maka setelah pagi, beliau bersabda: \"Sesungguhnya aku tahu apa yang kalian lakukan semalam. Tiada sesuatu pun yang menghalangiku untuk keluar dan shalat bersama kalian, hanya saja aku khawatir (shalat tarawih itu) akan diwajibkan atas kalian.\""},"1197":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ مِنْ جَوْفِ اللَّيْلِ فَصَلَّى فِي الْمَسْجِدِ فَصَلَّى رِجَالٌ بِصَلَاتِهِ فَأَصْبَحَ النَّاسُ يَتَحَدَّثُونَ بِذَلِكَ فَاجْتَمَعَ أَكْثَرُ مِنْهُمْ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي اللَّيْلَةِ الثَّانِيَةِ فَصَلَّوْا بِصَلَاتِهِ فَأَصْبَحَ النَّاسُ يَذْكُرُونَ ذَلِكَ فَكَثُرَ أَهْلُ الْمَسْجِدِ مِنْ اللَّيْلَةِ الثَّالِثَةِ فَخَرَجَ فَصَلَّوْا بِصَلَاتِهِ فَلَمَّا كَانَتْ اللَّيْلَةُ الرَّابِعَةُ عَجَزَ الْمَسْجِدُ عَنْ أَهْلِهِ فَلَمْ يَخْرُجْ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَطَفِقَ رِجَالٌ مِنْهُمْ يَقُولُونَ الصَّلَاةَ فَلَمْ يَخْرُجْ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى خَرَجَ لِصَلَاةِ الْفَجْرِ فَلَمَّا قَضَى الْفَجْرَ أَقْبَلَ عَلَى النَّاسِ ثُمَّ تَشَهَّدَ فَقَالَ أَمَّا بَعْدُ فَإِنَّهُ لَمْ يَخْفَ عَلَيَّ شَأْنُكُمْ اللَّيْلَةَ وَلَكِنِّي خَشِيتُ أَنْ تُفْرَضَ عَلَيْكُمْ صَلَاةُ اللَّيْلِ فَتَعْجِزُوا عَنْهَا","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] ia berkata, telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Aisyah] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam pernah keluar di tengah malam lalu beliau shalat di Masjid dan diikuti oleh beberapa orang, akhirnya mereka saling menceritakan tentang hal tersebut sehingga orang yang shalat bersama beliau semakin banyak. Pada malam ke dua, Rasulullah shallallahu 'alaihi wasallam keluar menunaikan shalat dan orang-orang pun shalat bersama beliau, kemudian mereka pun menyebut-nyebut kejadian itu sehingga pada malam ketiga jama'ah masjid semakin banyak dan mereka pun shalat bersama beliau. Pada malam ke empat masjid penuh sesak dan tidak dapat menampung jama'ahnya, tetapi Rasulullah shallallahu 'alaihi wasallam tidak keluar hingga beliau menunaikan shalat Fajar. Usai menunaikan shalat Fajar, beliau menghadap jama'ah, membaca syahadat kemudian bersabda: \"Amma ba'd, sesungguhnya tidak ada kekhawatiran yang menimpaku terkait dengan keadaan kalian semalam, akan tetapi saya hanya khawatir (shalat malam itu) akan diwajibkan atas kalian, sehingga kalian tidak sanggup melaksanakannya.\""},"1198":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ الرَّازِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي عَبْدَةُ عَنْ زِرٍّ قَالَ سَمِعْتُ أُبَيَّ بْنَ كَعْبٍ يَقُولُا وَقِيلَ لَهُ إِنَّ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ يَقُولُا مَنْ قَامَ السَّنَةَ أَصَابَ لَيْلَةَ الْقَدْرِ فَقَالَ أُبَيٌّ وَاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ إِنَّهَا لَفِي رَمَضَانَ يَحْلِفُ مَا يَسْتَثْنِي وَ وَاللَّهِ إِنِّي لَأَعْلَمُ أَيُّ لَيْلَةٍ هِيَهِيَ اللَّيْلَةُ الَّتِي أَمَرَنَا بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِيَامِهَا هِيَ لَيْلَةُ صَبِيحَةِ سَبْعٍ وَعِشْرِينَ وَأَمَارَتُهَا أَنْ تَطْلُعَ الشَّمْسُ فِي صَبِيحَةِ يَوْمِهَا بَيْضَاءَ لَا شُعَاعَ لَهَا","id":"Telah menceritakan kepada kami [Muhammad bin Mihran Ar Razi] telah menceritakan kepada kami [Al Walid bin Muslim] Telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Abdah] dari [Zirr] ia berkata, saya mendengar [Ubay bin Ka'ab] berkata, dan telah dikatakan kepadanya bahwa Abdullah bin Mas'ud berkata, \"Siapa yang melakukan shalat malam sepanjang tahun, niscaya ia akan menemui malam Lailatul Qadr.\" Ubay berkata, \"Demi Allah yang tidak ada ilah yang berhak disembah selain Allah, sesungguhnya malam itu terdapat dalam bulan Ramadlan. Dan demi Allah, sesungguhnya aku tahu malam apakah itu. Lailatul Qadr itu adalah malam, dimana Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menegakkan shalat di dalamnya, malam itu adalah malam yang cerah yaitu malam ke dua puluh tujuh (dari bulan Ramadlan). Dan tanda-tandanya ialah, pada pagi harinya matahari terbit berwarna putih tanpa sinar yang menyorot.\""},"1199":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ عَبْدَةَ بْنَ أَبِي لُبَابَةَ يُحَدِّثُ عَنْ زِرِّ بْنِ حُبَيْشٍ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ أُبَيٌّ فِي لَيْلَةِ الْقَدْرِ وَاللَّهِ إِنِّي لَأَعْلَمُهَا وَأَكْثَرُ عِلْمِي هِيَ اللَّيْلَةُ الَّتِي أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقِيَامِهَا هِيَ لَيْلَةُ سَبْعٍ وَعِشْرِينَوَإِنَّمَا شَكَّ شُعْبَةُ فِي هَذَا الْحَرْفِ هِيَ اللَّيْلَةُ الَّتِي أَمَرَنَا بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَحَدَّثَنِي بِهَا صَاحِبٌ لِي عَنْهُ و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَلَمْ يَذْكُرْ إِنَّمَا شَكَّ شُعْبَةُ وَمَا بَعْدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Abdah bin Abu Lubabah] menceritakan dari [Zirr bin Hubaisy] dari [Ubay bin Ka'ab] ia berkata; Ubay berkata mengenai Lailatul Qadr, \"Demi Allah, saya benar-benar mengetahuinya. Sejauh ilmu yang saya ketahui, lailatul Qadar adalah malam yang Rasulullah shallallahu 'alaihi wasallam telah memerintahkan kami untuk menegakkan (shalat di dalamnya), tepatnya adalah malam ke dua puluh tujuh.\" Syu'bah hanya ragu terkait dengan kalimat ini, \"Ia adalah malam yang Rasulullah shallallahu 'alaihi wasallam telah memerintahkan kami.\" Ia berkata, dan telah menceritakannya kepadaku darinya. Dan telah menceritakan kepadaku [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dengan isnad ini, hadits semisalnya. Namun ia tidak menyebutkan; \"Syu'bah hanya ragu terkait.\" dan selanjutnya."},"1200":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّهُ بَاتَ لَيْلَةً عِنْدَ مَيْمُونَةَ أُمِّ الْمُؤْمِنِينَ وَهِيَ خَالَتُهُ قَالَ فَاضْطَجَعْتُ فِي عَرْضِ الْوِسَادَةِ وَاضْطَجَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَهْلُهُ فِي طُولِهَا فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى انْتَصَفَ اللَّيْلُ أَوْ قَبْلَهُ بِقَلِيلٍ أَوْ بَعْدَهُ بِقَلِيلٍ اسْتَيْقَظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ يَمْسَحُ النَّوْمَ عَنْ وَجْهِهِ بِيَدِهِ ثُمَّ قَرَأَ الْعَشْرَ الْآيَاتِ الْخَوَاتِمَ مِنْ سُورَةِ آلِ عِمْرَانَ ثُمَّ قَامَ إِلَى شَنٍّ مُعَلَّقَةٍ فَتَوَضَّأَ مِنْهَا فَأَحْسَنَ وُضُوءَهُ ثُمَّ قَامَ فَصَلَّى قَالَ ابْنُ عَبَّاسٍ فَقُمْتُ فَصَنَعْتُ مِثْلَ مَا صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ذَهَبْتُ فَقُمْتُ إِلَى جَنْبِهِ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ الْيُمْنَى عَلَى رَأْسِي وَأَخَذَ بِأُذُنِي الْيُمْنَى يَفْتِلُهَا فَصَلَّى رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ رَكْعَتَيْنِ ثُمَّ أَوْتَرَ ثُمَّ اضْطَجَعَ حَتَّى جَاءَ الْمُؤَذِّنُ فَقَامَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ خَرَجَ فَصَلَّى الصُّبْحَو حَدَّثَنِي مُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ الْفِهْرِيِّ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ بِهَذَا الْإِسْنَادِ وَزَادَ ثُمَّ عَمَدَ إِلَى شَجْبٍ مِنْ مَاءٍ فَتَسَوَّكَ وَتَوَضَّأَ وَأَسْبَغَ الْوُضُوءَ وَلَمْ يُهْرِقْ مِنْ الْمَاءِ إِلَّا قَلِيلًا ثُمَّ حَرَّكَنِي فَقُمْتُ وَسَائِرُ الْحَدِيثِ نَحْوُ حَدِيثِ مَالِكٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata: Aku telah membacakan kepada [Malik] dari [Makhramah bin Sulaiman] dari [Kuraib] Maula Ibnu Abbas, bahwa [Ibnu Abbas] telah mengabarkan kepadanya bahwasanya; Pada suatu malam dia tidur di rumah bibinya, Maimunah, Ummul Mukminin. Dia tidur melintang kasur, sedangkan Rasulullah shallallahu 'alaihi wasallam dan isterinya memanjang kasur. Beliau tidur hingga lebih kurang sampai pertengan malam. Setelah itu, beliau bangun sambil menyapu kantuk dari mukanya. Kemudian beliau membaca sepuluh ayat penghabisan dari surat Ali Imran. Sesudah itu, beliau pergi ke tempat air, lalu beliau berwudlu dengan menyempurnakan wudlunya, dan sesudah itu beliau shalat. Ibnu Abbas berkata, \"Aku pun bangun kemudian melakukan sebagaimana yang dilakukan oleh Nabi shallallahu 'alaihi wasallam. Kemudian aku berdiri di samping kiri beliau. Tetapi beliau memegang kepalaku dengan tangannya dan memindahkanku ke sebelah kanannya. Mula-mula beliau shalat dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at, kemudian dua raka'at dan kemudian witir satu raka'at. Sesudah itu, beliau berbaring hingga terdengar muadzin mengumandangkan adzan Shubuh. Rasulullah shallallahu 'alaihi wasallam bangun, lalu shalat ringkas dua raka'at, sesudah itu beliau pergi ke (masjid) untuk mengerjakan shalat Shubuh.\" Dan telah menceritakan kepadaku [Muhammad bin Salamah Al Muradi] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Iyadl bin Abdullah Al Fihri] dari [Makhramah bin Sulaiman] dengan isnad ini. dan ia menambahkan; \"Kemudian beliau pergi ke tempat air, bersiwak dan berwudlu dengan menyempurnakan wudlunya. Dan beliau tidaklah menggunakan air kecuali hanya sedikit. Sesudah itu, beliau menggerakkanku, hingga aku pun bangun.\" Semua hadits (tentang ini) menyerupai haditsnya Malik."},"1201":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنَا عَمْرٌو عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَنِمْتُ عِنْدَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا تِلْكَ اللَّيْلَةَ فَتَوَضَّأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَامَ فَصَلَّى فَقُمْتُ عَنْ يَسَارِهِ فَأَخَذَنِي فَجَعَلَنِي عَنْ يَمِينِهِ فَصَلَّى فِي تِلْكَ اللَّيْلَةِ ثَلَاثَ عَشْرَةَ رَكْعَةً ثُمَّ نَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى نَفَخَ وَكَانَ إِذَا نَامَ نَفَخَ ثُمَّ أَتَاهُ الْمُؤَذِّنُ فَخَرَجَ فَصَلَّى وَلَمْ يَتَوَضَّأْقَالَ عَمْرٌو فَحَدَّثْتُ بِهِ بُكَيْرَ بْنَ الْأَشَجِّ فَقَالَ حَدَّثَنِي كُرَيْبٌ بِذَلِكَ","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] Telah menceritakan kepada kami [Amru] dari [Abdu Rabbih bin Sa'id] dari [Makhramah bin Sulaiman] dari [Kuraib] Maula Ibnu Abbas, dari [Ibnu Abbas] bahwa ia berkata; \"Saya pernah menginap di rumah Maimunah, isteri Nabi shallallahu 'alaihi wasallam, sementara pada malam itu Rasulullah shallallahu 'alaihi wasallam bermalam di rumahnya. Kemudian Rasulullah shallallahu 'alaihi wasallam berwudlu lalu berdiri dan shalat. Maka saya pun berdiri (shalat) di samping kirinya, lalu beliau memegangku dan meletakkanku di sebelah kanannya. Pada malam itu, beliau shalat sebanyak tiga belas raka'at. Sesudah itu, Rasulullah shallallahu 'alaihi wasallam tidur hingga beliau mendengkur. Memang, jika tidur beliau mendengkur. Kemudian seorang muadzin pun mendatangi beliau (untuk mengumandangkan adzan), hingga beliau keluar dan menunaikan shalat dengan tidak berwudlu lagi.\" [Amru] berkata; Saya menceritakannya kepada [Bukair bin Al Asyaj], ia berkata, telah menceritakan kepadaku [Kuraib] dengan hadits itu."},"1202":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا ابْنُ أَبِي فُدَيْكٍ أَخْبَرَنَا الضَّحَّاكُ عَنْ مَخْرَمَةَ بْنِ سُلَيْمَانَ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ لَيْلَةً عِنْدَ خَالَتِي مَيْمُونَةَ بِنْتِ الْحَارِثِ فَقُلْتُ لَهَا إِذَا قَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَيْقِظِينِي فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُمْتُ إِلَى جَنْبِهِ الْأَيْسَرِ فَأَخَذَ بِيَدِي فَجَعَلَنِي مِنْ شِقِّهِ الْأَيْمَنِ فَجَعَلْتُ إِذَا أَغْفَيْتُ يَأْخُذُ بِشَحْمَةِ أُذُنِي قَالَ فَصَلَّى إِحْدَى عَشْرَةَ رَكْعَةً ثُمَّ احْتَبَى حَتَّى إِنِّي لَأَسْمَعُ نَفَسَهُ رَاقِدًا فَلَمَّا تَبَيَّنَ لَهُ الْفَجْرُ صَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ","id":"Dan Telah menceritakan kepada kami [Muhammad bin Rafi'] Telah menceritakan kepada kami [Ibnu Abu Fudaik] telah mengabarkan kepada kami [Adl Dlahak] dari [Makhramah bin Sulaiman] dari [Kuraib] Maula Ibnu Abbas, dari [Ibnu Abbas] ia berkata; \"Pada suatu malam saya nginap di rumah bibiku Maimunah binti Al Harits. Saya berkata kepadanya, 'Jika Rasulullah shallallahu 'alaihi wasallam bangun (malam), maka bangunkanlah aku.' Kemudian Rasulullah shallallahu 'alaihi wasallam bangun (menunaikan shalat malam), dan aku pun ikut bangun dan shalat di sisi kirinya. Namun beliau memegang tanganku dan memindahkanku ke sebelah kanannya. Jika kantuk menyerangku, beliau memegang cuping telingaku. (pada malam itu) beliau shalat sebanyak sebelas raka'at. Sesudah itu beliau berbaring hingga saya mendengar hembusan nafasnya saat beliau tidur. Ketika waktu Fajar tiba, beliau mengerjakan shalat dua raka'at ringan."},"1203":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَبِتُّ فِي بَيْتِ خَالَتِي مَيْمُونَةَ فَبَقَيْتُ كَيْفَ يُصَلِّي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَامَ فَبَالَ ثُمَّ غَسَلَ وَجْهَهُ وَكَفَّيْهِ ثُمَّ نَامَ ثُمَّ قَامَ إِلَى الْقِرْبَةِ فَأَطْلَقَ شِنَاقَهَا ثُمَّ صَبَّ فِي الْجَفْنَةِ أَوْ الْقَصْعَةِ فَأَكَبَّهُ بِيَدِهِ عَلَيْهَا ثُمَّ تَوَضَّأَ وُضُوءًا حَسَنًا بَيْنَ الْوُضُوءَيْنِ ثُمَّ قَامَ يُصَلِّي فَجِئْتُ فَقُمْتُ إِلَى جَنْبِهِ فَقُمْتُ عَنْ يَسَارِهِ قَالَ فَأَخَذَنِي فَأَقَامَنِي عَنْ يَمِينِهِ فَتَكَامَلَتْ صَلَاةُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ عَشْرَةَ رَكْعَةً ثُمَّ نَامَ حَتَّى نَفَخَ وَكُنَّا نَعْرِفُهُ إِذَا نَامَ بِنَفْخِهِ ثُمَّ خَرَجَ إِلَى الصَّلَاةِ فَصَلَّى فَجَعَلَ يَقُولُ فِي صَلَاتِهِ أَوْ فِي سُجُودِهِ اللَّهُمَّ اجْعَلْ فِي قَلْبِي نُورًا وَفِي سَمْعِي نُورًا وَفِي بَصَرِي نُورًا وَعَنْ يَمِينِي نُورًا وَعَنْ شِمَالِي نُورًا وَأَمَامِي نُورًا وَخَلْفِي نُورًا وَفَوْقِي نُورًا وَتَحْتِي نُورًا وَاجْعَلْ لِي نُورًا أَوْ قَالَ وَاجْعَلْنِي نُورًاو حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ أَخْبَرَنَا شُعْبَةُ حَدَّثَنَا سَلَمَةُ بْنُ كُهَيْلٍ عَنْ بُكَيْرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ سَلَمَةُ فَلَقِيتُ كُرَيْبًا فَقَالَ قَالَ ابْنُ عَبَّاسٍ كُنْتُ عِنْدَ خَالَتِي مَيْمُونَةَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ ذَكَرَ بِمِثْلِ حَدِيثِ غُنْدَرٍ وَقَالَ وَاجْعَلْنِي نُورًا وَلَمْ يَشُكَّ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَهَنَّادُ بْنُ السَّرِيِّ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سَعِيدِ بْنِ مَسْرُوقٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ أَبِي رِشْدِينٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ بِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ وَاقْتَصَّ الْحَدِيثَ وَلَمْ يَذْكُرْ غَسْلَ الْوَجْهِ وَالْكَفَّيْنِ غَيْرَ أَنَّهُ قَالَ ثُمَّ أَتَى الْقِرْبَةَ فَحَلَّ شِنَاقَهَا فَتَوَضَّأَ وُضُوءًا بَيْنَ الْوُضُوءَيْنِ ثُمَّ أَتَى فِرَاشَهُ فَنَامَ ثُمَّ قَامَ قَوْمَةً أُخْرَى فَأَتَى الْقِرْبَةَ فَحَلَّ شِنَاقَهَا ثُمَّ تَوَضَّأَ وُضُوءًا هُوَ الْوُضُوءُ وَقَالَ أَعْظِمْ لِي نُورًا وَلَمْ يَذْكُرْ وَاجْعَلْنِي نُورًا و حَدَّثَنِي أَبُو الطَّاهِرِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَلْمَانَ الْحَجْرِيِّ عَنْ عُقَيْلِ بْنِ خَالِدٍ أَنَّ سَلَمَةَ بْنَ كُهَيْلٍ حَدَّثَهُ أَنَّ كُرَيْبًا حَدَّثَهُ أَنَّ ابْنَ عَبَّاسٍ بَاتَ لَيْلَةً عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْقِرْبَةِ فَسَكَبَ مِنْهَا فَتَوَضَّأَ وَلَمْ يُكْثِرْ مِنْ الْمَاءِ وَلَمْ يُقَصِّرْ فِي الْوُضُوءِ وَسَاقَ الْحَدِيثَ وَفِيهِ قَالَ وَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَتَئِذٍ تِسْعَ عَشْرَةَ كَلِمَةً قَالَ سَلَمَةُ حَدَّثَنِيهَا كُرَيْبٌ فَحَفِظْتُ مِنْهَا ثِنْتَيْ عَشْرَةَ وَنَسِيتُ مَا بَقِيَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ اجْعَلْ لِي فِي قَلْبِي نُورًا وَفِي لِسَانِي نُورًا وَفِي سَمْعِي نُورًا وَفِي بَصَرِي نُورًا وَمِنْ فَوْقِي نُورًا وَمِنْ تَحْتِي نُورًا وَعَنْ يَمِينِي نُورًا وَعَنْ شِمَالِي نُورًا وَمِنْ بَيْنِ يَدَيَّ نُورًا وَمِنْ خَلْفِي نُورًا وَاجْعَلْ فِي نَفْسِي نُورًا وَأَعْظِمْ لِي نُورًا و حَدَّثَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ أَخْبَرَنَا ابْنُ أَبِي مَرْيَمَ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ أَخْبَرَنِي شَرِيكُ بْنُ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَ رَقَدْتُ فِي بَيْتِ مَيْمُونَةَ لَيْلَةَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَهَا لِأَنْظُرَ كَيْفَ صَلَاةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِاللَّيْلِ قَالَ فَتَحَدَّثَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ أَهْلِهِ سَاعَةً ثُمَّ رَقَدَ وَسَاقَ الْحَدِيثَ وَفِيهِ ثُمَّ قَامَ فَتَوَضَّأَ وَاسْتَنَّ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad] yaitu anak Ja'far, telah menceritakan kepada kami [Syu'bah] dari [Salamah] dari [Kuraib] dari [Ibnu Abbas] ia berkata; \"Saya bermalan di rumah bibiku, Maimunah. Maka saya pun ingin melihat bagaimana Rasulullah shallallahu 'alaihi wasallam menunaikan shalat malam. (Maka pada malam itu) beliau bangun dan kencing. Kemudian beliau membasuh wajahnya, kedua tangannya dan tidur kembali. Kemudian beliau bangun dan langsung beranjak menuju qirbah (tempat air). Beliau membuka tutupnya dan menuangkannya ke dalam mangkuk kecil. Kemudian beliau menciduk dengan tangannya dan berwudlu dengan menyempurnakan wudlunya. Setelah itu beliau shalat, dan saya pun ikut shalat bersama beliau dengan berdiri di sebelah kirinya. Namun beliau memegang dan memindahkanku ke sebelah kanannya. (Pada malam itu) shalat Rasulullah shallallahu 'alaihi wasallam sempurna tiga belas raka'at. Sesudah itu beliau tidur hingga mendengku. Dan kami tahu jika tidur beliau mendengkur. Setelah itu, beliau keluar untuk menunaikan shalat Subuh. Kemudian beliau membaca di dalam shalat atau di dalam sujudnya: \"ALLAHUMMAJ'AL FII QALBII NUURAN WA FII SAM'II NUURAN WA FII BASHARII NUURAN WA 'AN YAMIINII NUURAN WA 'AN SYIMAALII NUURAN WA AMAAMII NUURAN WA KHALFII NUURAN WA FAUQII NUURAN WA TAHTII NUURAN WAJ'AL LII NUURAN -atau beliau mengatakan- WAJ'ALNII NUURAN (Ya Allah, berilah cahaya pada hatiku, cahaya dalam pendengaranku, cahaya dalam penglihatanku, cahaya dari sebelah kananku, cahaya dari sebelah kiriku, cahaya dari depanku, cahaya dari belakangku, cahanya dari atasku, cahaya dari bawahku, dan berilah aku cahaya).\" Dan telah menceritakan kepadaku [Ishaq bin Manshur] telah menceritakan kepada kami [An Nadlru bin Syumail] telah mengabarkan kepada kami [Syu'bah] Telah menceritakan kepada kami [Salamah bin Kuhail] dari [Bukair] dari [Kuraib] dari [Ibnu Abbas]. [Salamah berkata]; Saya menjumpai [Kuraib] maka ia pun berkata, [Ibnu Abbas] berkata; Saya berada di rumah bibiku, Maimunah kemudian datanglah Rasulullah shallallahu 'alaihi wasallam. Kemudian ia pun menyebutkan hadits serupa dengan hadits Ghundar, dan ia mengatakan; \"WAJ'ALNII NUURAN (Dan berilah aku cahaya).\" Tanpa keraguan. Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Hannad bin As Sariya] keduanya berkata, Telah menceritakan kepada kami [Abu Ahwash] dari [Sa'id bin Masruq] dari [Salamah bin Kuhail] dari [Abu Risydin] Maula Ibnu Abbas, dari [Ibnu Abbas] ia berkata; Saya bermalam di rumah bibiku, Maimunah. Ia pun mengkisahkan hadits, namun ia tidak menyebutkan Ghaslul Wajh wal Kaffain (membasuh wajah dan kedua telapak tangan). Hanya saja ia mengatakan; \"Kemudian beliau mendatangi qirbah dan membuka tutupnya, lalu beliau berwudlu di antara dua wudlu, kemudian beliau beranjak ke tempat tidurnya dan tidur. Setelah itu, beliau bangun kembali, lalu beranjak menuju qirbah (tempat air) lalu membuka tutupnya, kemudian berwudlu.\" Kemudian beliau membaca: \"A'ZHIM LII NUURA (Ya Allah, perbesarlah cahaya untukku).\" Dan ia tidak mengatakan; \"WAJ'AlNII NUURA.\" Dan telah menceritakan kepadaku [Abu Thahir] Telah menceritakan kepada kami [Ibnu Wahb] dari [Abdurrahman bin Salman Al Hajri] dari [Uqail bin Khalid] bahwa [Salamah bin Kuhail] telah menceritakan kepadanya bahwa [Kuraib] telah menceritakan kepadanya bahwa [Ibnu Abbas] pernah bermalam bersama Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam beranjak menuju qirbah (tempat air), menuangkan air darinya dan berwudlu dengan tidak banyak menggunakan air, namun beliau juga tidak mengurangi wudlunya. Ia pun menyebutkan hadits. Kemudian di dalam hadits itu ia mengatakan; Pada malam itu, Rasulullah shallallahu 'alaihi wasallam berdo'a dengan sembilan belas kata. Salamah berkata, telah menceritakannya kepadaku Kuraib, dan saya menghafal darinya dua belas kata dan sisanya lupa. Rasulullah shallallahu 'alaihi wasallam berdo'a: \"ALLAHUMMAJ'AL LII FI QALBII NUURAN WA FII LISAANII NUURAN, WA FII SAM'II NUURAN WA FII BASHARI NUURAN WA MIN FAUQII NUURAN WA MIN TAHTII NUURAN WA 'AN YAMIINII NUURAN WA 'AN SYIMAALII NUURAN WA MIN BAINI YADAYYA NUURAN WA MIN KHALFII NUURAN WAJ'AL FII NAFSII NUURAN WA A'ZHIM LII NUURAAN (Ya Allah jadikanlah cahaya di dalam hatiku, cahaya di dalam lisanku, cahaya dalam pendengaranku, cahaya dalam penglihatanku, cahaya dari atasku, cahaya dari bawahku, cahaya dari arah kananku, cahaya dari sebelah kiriku, cahaya dari arah depanku, cahaya dari belakangku, dan berilah cahaya di dalam jiwaku dan perbesarlah cahaya untukku).\" Dan telah menceritakan kepadaku [Abu Bakr bin Ishaq] telah mengabarkan kepada kami [Ibnu Abu Maryam] telah mengabarkan kepada kami [Muhammad bin Ja'far] telah mengabarkan kepadaku [Syarik bin Abu Namir] dari [Kuraib] dari [Ibnu Abbas] bahwa ia berkata; \"Saya bermalam di rumah Maimunah, yang saat itu Nabi shallallahu 'alaihi wasallam berada di rumahnya. Demikian itu, agar saya dapat melihat bagaimana shalat malam Rasulullah shallallahu 'alaihi wasallam. Nabi shallallahu 'alaihi wasallam berbincang-bincang bersama isterinya sejenak, kemudian beliau tidur.\" Ia pun menuturkan hadits. Dan di dalamnya ia mengatakan; \"Kemudian beliau bangun lalu berwudlu dan bersiwak.\""},"1204":{"ar":"حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ حَبِيبِ بْنِ أَبِي ثَابِتٍ عَنْ مُحَمَّدِ بْنِ عَلِيِّ بْنِ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّهُ رَقَدَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَيْقَظَ فَتَسَوَّكَ وَتَوَضَّأَ وَهُوَ يَقُولُ{ إِنَّ فِي خَلْقِ السَّمَوَاتِ وَالْأَرْضِ وَاخْتِلَافِ اللَّيْلِ وَالنَّهَارِ لَآيَاتٍ لِأُولِي الْأَلْبَابِ }فَقَرَأَ هَؤُلَاءِ الْآيَاتِ حَتَّى خَتَمَ السُّورَةَ ثُمَّ قَامَ فَصَلَّى رَكْعَتَيْنِ فَأَطَالَ فِيهِمَا الْقِيَامَ وَالرُّكُوعَ وَالسُّجُودَ ثُمَّ انْصَرَفَ فَنَامَ حَتَّى نَفَخَ ثُمَّ فَعَلَ ذَلِكَ ثَلَاثَ مَرَّاتٍ سِتَّ رَكَعَاتٍ كُلَّ ذَلِكَ يَسْتَاكُ وَيَتَوَضَّأُ وَيَقْرَأُ هَؤُلَاءِ الْآيَاتِ ثُمَّ أَوْتَرَ بِثَلَاثٍ فَأَذَّنَ الْمُؤَذِّنُ فَخَرَجَ إِلَى الصَّلَاةِ وَهُوَ يَقُولُ اللَّهُمَّ اجْعَلْ فِي قَلْبِي نُورًا وَفِي لِسَانِي نُورًا وَاجْعَلْ فِي سَمْعِي نُورًا وَاجْعَلْ فِي بَصَرِي نُورًا وَاجْعَلْ مِنْ خَلْفِي نُورًا وَمِنْ أَمَامِي نُورًا وَاجْعَلْ مِنْ فَوْقِي نُورًا وَمِنْ تَحْتِي نُورًا اللَّهُمَّ أَعْطِنِي نُورًا","id":"Telah menceritakan kepada kami [Washil bin Abdul A'la] Telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Hushain bin Abdurrahman] dari [Habib bin Abu Tsabit] dari [Muhammad bin Abu 'Ali bin Abdullah bin Abbas] dari [bapaknya] dari [Abdullah bin Abbas] bahwa ia pernah bermalam di sisi Rasulullah shallallahu 'alaihi wasallam. Kemudian beliau bangun dan langsung bersiwak kemudian berwudlu. Lalu beliau membaca: \"Sesungguhnya dalam penciptaan langit dan bumi, dan silih bergantinya malam dan siang terdapat tanda-tanda bagi orang-orang yang berakal.\" Beliau membaca ayat itu hingga selesai satu surat (Ali Imran). Kemudian beliau shalat dua raka'at dengan memanjangkannya berdirinya, ruku', dan sujudnya. Sesudah itu beliau tidur hingga terdengar hembusan nafasnya. Beliau melakukan hal itu hingga tiga kali yakni enam raka'at, dan setiap kalinya beliau mesti bersiwak dan berwudlu dan membaca ayat tadi, kemudian beliau shalat witir dengan tiga raka'at. Hingga sang muadzin mengumandangkan adzan. Maka beliau pun keluar untuk menunaikan shalat Shubuh seraya berdo'a: \"ALLAHUMMAJ 'AL FII QALBII NUURAN WA FII LISAANII NUURAN WAJ'AL FII SAM'I NUURAN WAJ'AL FII BASHARII NUURAN WAJ'AL MIN KHALFII NUURAN, WA MIN AMAAMII NUURAN, WAJ'AL MIN FAUQII NUURAN, WA MIN TAHTI NUURAAN, ALLAHUMMA'THINII NUURAN (Ya Allah berilah cahaya dalam hatiku, cahaya di lisanku, berilah cahaya dalam pendengaranku, berilah cahaya dalam penglihatanku, berilah aku cahaya dari belakangku, dari arah depanku, dan berikanlah cahaya dari atasku, dan arah bawahku. Ya Allah berilah aku cahaya).\""},"1205":{"ar":"و حَدَّثَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ وَمُحَمَّدُ بْنُ رَافِعٍ قَالَا حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ أَخْبَرَنِي أَبِي قَالَ سَمِعْتُ قَيْسَ بْنَ سَعْدٍ يُحَدِّثُ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَعَثَنِي الْعَبَّاسُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي بَيْتِ خَالَتِي مَيْمُونَةَ فَبِتُّ مَعَهُ تِلْكَ اللَّيْلَةَ فَقَامَ يُصَلِّي مِنْ اللَّيْلِ فَقُمْتُ عَنْ يَسَارِهِ فَتَنَاوَلَنِي مِنْ خَلْفِ ظَهْرِهِ فَجَعَلَنِي عَلَى يَمِينِهِو حَدَّثَنِي ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَ بِتُّ عِنْدَ خَالَتِي مَيْمُونَةَ نَحْوَ حَدِيثِ ابْنِ جُرَيْجٍ وَقَيْسِ بْنِ سَعْدٍ","id":"Dan telah menceritakan kepadaku [Harun bin Abdullah] dan [Muhammad bin Rafi'] keduanya berkata, telah menceritakan kepada kami [Wahb bin Jarir] telah mengabarkan kepadaku [bapakku] ia berkata, saya mendengar [Qais bin Sa'd] ia menceritakan dari ['Atha`] dari [Ibnu Abbas] ia berkata; \"Al Abbas mengutusku menemui Nabi shallallahu 'alaihi wasallam, sementara beliau berada di rumah bibiku Maimunah. Maka pada malam itu aku menginap bersama beliau. Kemudian beliau bangun dan menunaikan shalat malam. Lalu saya ikut shalat di sebelah kiri beliau, namun beliau memindahkanku dari arah belakangnya dan menempatkanku di samping kanannya.\" Dan telah menceritakan kepadaku [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Abdul Malik] dari [Atha`] dari [Ibnu Abbas] ia berkata; Saya bermalan di rumah bibiku, Maimunah. Yakni sebagaimana hadits Ibnu Juraij dan Qais bin Sa'd."},"1206":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ ح و حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي جَمْرَةَ قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُاكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي مِنْ اللَّيْلِ ثَلَاثَ عَشْرَةَ رَكْعَةً","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] -kemudian dalam jalur periwatan lain- Dan telah menceritakan kepada kami [Ibnul Mutsanna] dan [Ibnu Basysyar] keduanya berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Jamrah] ia berkata, saya mendengar [Ibnu Abbas] berkata; \"Biasanya Rasulullah shallallahu 'alaihi wasallam shalat malam sebanyak tiga belas raka'at.\""},"1207":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ أَنَّ عَبْدَ اللَّهِ بْنَ قَيْسِ بْنِ مَخْرَمَةَ أَخْبَرَهُ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ أَنَّهُ قَالَلَأَرْمُقَنَّ صَلَاةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّيْلَةَ فَصَلَّى رَكْعَتَيْنِ خَفِيفَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ طَوِيلَتَيْنِ طَوِيلَتَيْنِ طَوِيلَتَيْنِ ثُمَّ صَلَّى رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ صَلَّى رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ صَلَّى رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ صَلَّى رَكْعَتَيْنِ وَهُمَا دُونَ اللَّتَيْنِ قَبْلَهُمَا ثُمَّ أَوْتَرَ فَذَلِكَ ثَلَاثَ عَشْرَةَ رَكْعَةً","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] dari [Abdullah bin Abu Bakr] dari [bapaknya] bahwa [Abdullah bin Qais bin Makhramah] telah mengabarkan kepadanya dari [Zaid bin Khalid Al Juhani] bahwa ia berkata; Saya benar-benar akan memperhatikan shalat Rasulullah shallallahu 'alaihi wasallam pada malam ini. (Maka saya melihat) beliau shalat dua raka'at ringan. Kemudian beliau shalat dua raka'at yang sangat panjang. Kemudian beliau shalat dua raka'at lagi selain dua raka'at sebelumnya. Kemudian beliau shalat dua raka'at lagi selain dua raka'at sebelumnya. Kemudian beliau shalat lagi selain dua raka'at sebelumnya. Kemudian beliau shalat dua raka'at lagi selain dua raka'at sebelumnya. Dan sesudah itu beliau shalat witir, hingga bilangan semua raka'atnya adalah tiga belas raka'at."},"1208":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي الزُّبَيْرِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ إِذَا قَامَ إِلَى الصَّلَاةِ مِنْ جَوْفِ اللَّيْلِ اللَّهُمَّ لَكَ الْحَمْدُ أَنْتَ نُورُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ قَيَّامُ السَّمَوَاتِ وَالْأَرْضِ وَلَكَ الْحَمْدُ أَنْتَ رَبُّ السَّمَوَاتِ وَالْأَرْضِ وَمَنْ فِيهِنَّ أَنْتَ الْحَقُّ وَوَعْدُكَ الْحَقُّ وَقَوْلُكَ الْحَقُّ وَلِقَاؤُكَ حَقٌّ وَالْجَنَّةُ حَقٌّ وَالنَّارُ حَقٌّ وَالسَّاعَةُ حَقٌّ اللَّهُمَّ لَكَ أَسْلَمْتُ وَبِكَ آمَنْتُ وَعَلَيْكَ تَوَكَّلْتُ وَإِلَيْكَ أَنَبْتُ وَبِكَ خَاصَمْتُ وَإِلَيْكَ حَاكَمْتُ فَاغْفِرْ لِي مَا قَدَّمْتُ وَأَخَّرْتُ وَأَسْرَرْتُ وَأَعْلَنْتُ أَنْتَ إِلَهِي لَا إِلَهَ إِلَّا أَنْتَحَدَّثَنَا عَمْرٌو النَّاقِدُ وَابْنُ نُمَيْرٍ وَابْنُ أَبِي عُمَرَ قَالُوا حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ كِلَاهُمَا عَنْ سُلَيْمَانَ الْأَحْوَلِ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا حَدِيثُ ابْنِ جُرَيْجٍ فَاتَّفَقَ لَفْظُهُ مَعَ حَدِيثِ مَالِكٍ لَمْ يَخْتَلِفَا إِلَّا فِي حَرْفَيْنِ قَالَ ابْنُ جُرَيْجٍ مَكَانَ قَيَّامُ قَيِّمُ وَقَالَ وَمَا أَسْرَرْتُ وَأَمَّا حَدِيثُ ابْنِ عُيَيْنَةَ فَفِيهِ بَعْضُ زِيَادَةٍ وَيُخَالِفُ مَالِكًا وَابْنَ جُرَيْجٍ فِي أَحْرُفٍ و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا مَهْدِيٌّ وَهُوَ ابْنُ مَيْمُونٍ حَدَّثَنَا عِمْرَانُ الْقَصِيرُ عَنْ قَيْسِ بْنِ سَعْدٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ وَاللَّفْظُ قَرِيبٌ مِنْ أَلْفَاظِهِمْ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] dari [Abu Zubair] dari [Thawus] dari [Ibnu Abbas] bahwa; Rasulullah shallallahu 'alaihi wasallam jika bangun untuk mengerjakan shalat di tengah malam, beliau membaca: \"ALLAHUMMA LAKAL HAMDU ANTA NUURUS SAMAAWAATI WAL ARDLI WALAKAL HAMDU ANTA QAYYAMUS SAMAAWAATI WAL ARDLI WALAKAL HAMDU ANTA RABBUS SAMAAWAATI WAL ARDLI WA MAN FIIHINNA ANTAL HAQQU WA WA'DUKAL HAQQU WA QAULUKAL HAQQU WA LIQAA`UKA HAQQU WAL JANNATU HAQQU WAN NAARU HAQQU WAS SAA'ATU HAQQU. ALLAHUMMA LAKA ASLAMTU WA BIKA AAMANTU WA 'ALAIKA TAWAKKALTU WA ILAIKA ANABTU WA BIKA KHAASHAMTU WA ILAIKA HAAKAMTU FAGHFIRLII MAA QADDAMTU WA AKHKHARTU WA ASRARTU WA A'LANTU ANTA ILAAHI LAA ILAAHA ILLAA ANTA (Ya Allah, untukMu segala puji; Engkau cahaya langit dan bumi; untukMu segala puji, Engkau pendiri langit dan bumi; dan untukMu segala puji, Engkau Tuhan langit dan bumi dan segala isinya. Engkau Maha Benar! JanjiMu benar, firmanMu benar, hari perjumpaan denganMu benar, surga benar, neraka benar dan hari kiamat adalah benar. Ya Allah, kepadaMulah aku berserah diri, denganMu aku beriman, kepadaMu au bertawakkal, dan kepadaMu aku kembali; karena membela agamaMu aku bermusuhan, dan kepadaMu aku bertahkim (memohon keadilan). Karena itu, ampunilah segala dosa-dosaku, yang lama dan yang baru, yang rahasia dan yang nyata; Engkaulah ilahku, tidak ada ilah yang berhak disembah selain Engkau).\" Telah menceritakan kepada kami [Amru An Naqid] dan [Ibnu Numair] dan [Ibnu Abu Umar] mereka berkata, telah menceritakan kepada kami [Sufyan] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Rafi'] ia berkata, telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] keduanya dari [Sulaiman Al Ahwali] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam. Adapun hadits Ibnu Juraij, maka lafazhnya sama dengan hadits Malik kecuali pada dua huruf. Kalau Ibnu Juraij kata Qayyam menjadi Qayyim. Dan ia juga menyebutkan, \"WA MAA ASRARTU (dan juga dosa yang aku sembunyikan). Adapun hadits Ibnu 'Uyainah, maka di dalamnya terdapat tambahan dan menyelisihi Malik dan Ibnu Juraid pada banyak kata. Dan Telah menceritakan kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Mahdi] ia adalah Ibnu Maimun, telah menceritakan kepada kami [Imran Al Qashir] dari [Qais bin Sa'd] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini, sedangkan lafazhnya hampir sama dengan lafazh mereka."},"1209":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ حَدَّثَنَا يُوسُفُ الْمَاجِشُونُ حَدَّثَنِي أَبِي عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا قَامَ إِلَى الصَّلَاةِ قَالَ وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَاوَاتِ وَالْأَرْضَ حَنِيفًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا مِنْ الْمُسْلِمِينَ اللَّهُمَّ أَنْتَ الْمَلِكُ لَا إِلَهَ إِلَّا أَنْتَ أَنْتَ رَبِّي وَأَنَا عَبْدُكَ ظَلَمْتُ نَفْسِي وَاعْتَرَفْتُ بِذَنْبِي فَاغْفِرْ لِي ذُنُوبِي جَمِيعًا إِنَّهُ لَا يَغْفِرُ الذُّنُوبَ إِلَّا أَنْتَ وَاهْدِنِي لِأَحْسَنِ الْأَخْلَاقِ لَا يَهْدِي لِأَحْسَنِهَا إِلَّا أَنْتَ وَاصْرِفْ عَنِّي سَيِّئَهَا لَا يَصْرِفُ عَنِّي سَيِّئَهَا إِلَّا أَنْتَ لَبَّيْكَ وَسَعْدَيْكَ وَالْخَيْرُ كُلُّهُ فِي يَدَيْكَ وَالشَّرُّ لَيْسَ إِلَيْكَ أَنَا بِكَ وَإِلَيْكَ تَبَارَكْتَ وَتَعَالَيْتَ أَسْتَغْفِرُكَ وَأَتُوبُ إِلَيْكَ وَإِذَا رَكَعَ قَالَ اللَّهُمَّ لَكَ رَكَعْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ خَشَعَ لَكَ سَمْعِي وَبَصَرِي وَمُخِّي وَعَظْمِي وَعَصَبِي وَإِذَا رَفَعَ قَالَ اللَّهُمَّ رَبَّنَا لَكَ الْحَمْدُ مِلْءَ السَّمَاوَاتِ وَمِلْءَ الْأَرْضِ وَمِلْءَ مَا بَيْنَهُمَا وَمِلْءَ مَا شِئْتَ مِنْ شَيْءٍ بَعْدُ وَإِذَا سَجَدَ قَالَ اللَّهُمَّ لَكَ سَجَدْتُ وَبِكَ آمَنْتُ وَلَكَ أَسْلَمْتُ سَجَدَ وَجْهِي لِلَّذِي خَلَقَهُ وَصَوَّرَهُ وَشَقَّ سَمْعَهُ وَبَصَرَهُ تَبَارَكَ اللَّهُ أَحْسَنُ الْخَالِقِينَ ثُمَّ يَكُونُ مِنْ آخِرِ مَا يَقُولُ بَيْنَ التَّشَهُّدِ وَالتَّسْلِيمِ اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ وَمَا أَخَّرْتُ وَمَا أَسْرَرْتُ وَمَا أَعْلَنْتُ وَمَا أَسْرَفْتُ وَمَا أَنْتَ أَعْلَمُ بِهِ مِنِّي أَنْتَ الْمُقَدِّمُ وَأَنْتَ الْمُؤَخِّرُ لَا إِلَهَ إِلَّا أَنْتَو حَدَّثَنَاه زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو النَّضْرِ قَالَا حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي سَلَمَةَ عَنْ عَمِّهِ الْمَاجِشُونِ بْنِ أَبِي سَلَمَةَ عَنْ الْأَعْرَجِ بِهَذَا الْإِسْنَادِ وَقَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اسْتَفْتَحَ الصَّلَاةَ كَبَّرَ ثُمَّ قَالَ وَجَّهْتُ وَجْهِي وَقَالَ وَأَنَا أَوَّلُ الْمُسْلِمِينَ وَقَالَ وَإِذَا رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ وَقَالَ وَصَوَّرَهُ فَأَحْسَنَ صُوَرَهُ وَقَالَ وَإِذَا سَلَّمَ قَالَ اللَّهُمَّ اغْفِرْ لِي مَا قَدَّمْتُ إِلَى آخِرِ الْحَدِيثِ وَلَمْ يَقُلْ بَيْنَ التَّشَهُّدِ وَالتَّسْلِيمِ","id":"Telah menceritakan kepada kami [Muhammad bin Bukair Al Muqaddami] telah menceritakan kepada kami [Yusuf Al Majisyun] telah menceritakan kepadaku [bapakku] dari [Abdurrahman Al A'raj] dari [Ubaidullah bin Abu Rafi'] dari [Ali bin Abu Thalib] dari Rasulullah shallallahu 'alaihi wasallam; Biasanya apabila Rasulullah shallallahu 'alaihi wasallam shalat, beliau membaca (do'a iftitah) sebagai berikut: \"WAJJAHTU WAJHIYA LILLADZII FATHARAS SAMAAWAATI WAL ARDLA HANIIFAN WAMAA ANAA MINAL MUSYRIKIIN, INNA SHALAATII WA NUSUKII WA MAHYAAYA WA MAMAATII LILLAHI RABBIL 'AALAMIIN LAA SYARIIKA LAHU WA BIDZAALIKA UMIRTU WA ANAA MINAL MUSLIMIIN ALLAHUMMA ANTAL MALIKU LAA ILAAHA ILLAA ANTA, ANTA RABBII WA ANAA 'ABDUKA ZHALAMTU NAFSII WA'TARAFTU BI DZANBII FAGHFIL LII DZUNUUBII JAMII'AN INNAHU LAA YAGHFIRUDZ DZUNUUB ILLAA ANTA WAH DINII LIAHSANAIL AKHLAAQ LAA YAHDII LIAHSANIHAA ILLAA ANTA WASHRIF 'ANNII SAYYI`AHAA LAA YASHRIFU 'ANNII SAYYI`AHAA ILLAA ANTA LABBAIKA WA SA'DAIKA WAL KHAIRU KULLUHU FII YADAIK WASY SYARRU LAISA ILAIKA ANAA BIKA WA ILAIKA TABAARAKTA WA TA'AALAITA ASTAGHFIRUKA WA ATUUBU ILAIKA (Aku hadapkan wajahku kepada Allah, Maha pencipta langit dan bumi dengan keadaan ikhlas dan tidak mempersekutukanNya. Sesungguhnya shalatku, segala ibadahku, hidupku dan matiku, hanya semata-mata untuk Allah Rabb semesta alam. Tidak ada sekutu bagiNya, dan karena itu aku patuh kepada perintahNya, dan berserah diri kepadaNya. Ya Allah, Engkaulah Maha Penguasa. Tidak ada Ilah yang berhak disembah selain Engkau. Engkaulah Tuhanku dan aku adalah hambaMu. Aku telah menzhalimi diriku dan aku mengakui dosa-dosaku. Karena itu ampunilah dosa-dosaku semuanya. Sesungguhnya tidak ada yang berwenang untuk mengampuni segala dosa melainkan Engkau. Dan tunjukilah kepadaku akhlak yang paling bagus. Sesungguhnya tidak ada yang dapat menunjukkannya melainkan hanya Engkau. Dan jauhkanlah akhlak yang buruk dariku, karena sesungguhnya tidak ada yang sanggup menjauhkannya melainkan hanya Engkau. Labbaik wa sa'daik (Aku patuhi segala perintahMu, dan aku tolong agamaMu). Segala kebaikan berada di tanganMu. Sedangkan kejahatan tidak datang daripadaMu. Aku berpegang teguh denganMu dan kepadaMu. Maha Suci Engkau dan Maha Tinggi. Kumohon ampun dariMu dan aku bertobat kepadaMu).\" Dan jika beliau ruku' beliau membaca: \"ALLAHUMMA LAKA RAKA'TU WA BIKA AAMANTU WA LAKA ASLAMTU KHASYA'A LAKA SAM'II WA BASHARII WA MUKHKHII WA 'AZHMII WA 'ASHABII (Ya Allah, kepadaMu aku ruku', denganMu aku beriman, kepadaMu aku berserah diri, patuh dan tunduk kepadau pendengaranku, penglihatanku, otakku, tulang-tulangku dan otot-ototku semuanya).\" Kemudian bila beliau bangkit dari ruku' beliau membaca: \"ALLAHUMMA RABBANAA LAKAL HAMDU MIL`AS SAMAAWAATI WA MIL`AL ARDLI WA MIL`A MAA BAINAHUMAA WA MIL`A MAAS YI`TA MIN SYAI`IN BA'DU (Ya Allah, Tuhan kami, untuk-Mulah segala puji sepenuh langit dan bumi, dan sepenuh ruang antara keduanya, dan sepenuh apa yang Engkau kehendaki setelah itu).\" Kemudian apabila beliau sujud beliau membaca: \"ALLAHUMMA LAKA SAJADTU WA BIKA AAMANTU WA LAKA ASLAMTU SAJADA WAJHIY LILLADZII KHALAQAHU WA SHAWWARAHU WA SYAQQA SYAM'AHU WA BASHARAHU TABAARAKALLAHU AHSANUL KHALIQIIN (Ya Allah, kepada Engkau aku sujud, dengan Engkau aku beriman, dan kepada Engkau aku berserah diri. Mukaku sujud kepada Tuhan yang menciptakan dan membentuknya, yang membukakan pendengaran dan penglihatannya. Maha suci Allah sebaik-baik Maha pencipta).\" Kemudian pada akhir tasyahud sebelum memberi salam beliau membaca: \"ALLAHUMMAGH FIRLII MAA QADDAMTU WA MAA AKHKHARTU WAMAA ASRARTU WA MAA A'LANTU WA ASRAFTU WA MAA ANTA A'LAMU BIHI MINNII ANTAL MUQADDiMU WA ANTAL MU`AKHKHIRU LAA ILAAHA ILLAA ANTA (Ya Allah, ampunilah dosa-dosaku yang lama dan yang baru yang tersembunyi dan nyata, yang aku lakukan keterlaluan dan engkau lebih tahu daripadaku. Engkaulah yang memajukan dan memundurkan. Tidak ada ilah selain Engkau).\" Dan telah menceritakannya kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman bin Mahdi] -dalam jalur periwayatan yang lain- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu An Nadlr] keduanya berkata, telah menceritakan kepada kami [Abdul Aziz bin Abdullah bin Abu Salamah] dari [pamannya] Al Majisyuna bin Abu Salamah dari [Al A'raj] dengan isnad ini, dan ia berkata; Apabila Rasulullah shallallahu 'alaihi wasallam memulai shalat, beliau bertakbir dan membaca (do'a iftitah): \"WAJJAHTU WAJHIYA.\" Beliau juga membaca: \"WA ANA AWWALUL MUSLIMIN.\" Dan ketika beliau bangkit dari ruku', beliau membaca: \"ALLAHUMMA RABBANAA LAKAL HAMDU.\" Beliau juga melanjutkan: \"WA SHAWWARAHU FAAHSANA SHUWARAHU.\" Dan setelah setelah salam beliau membaca: \"ALLAHUMMAGHFIR LII MAA QADAMTU.\" hingga akhir hadits. Dan ia tidak mengatakan; \"Antara tasyahud dan salam.\""},"1210":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ جَرِيرٍ كُلُّهُمْ عَنْ الْأَعْمَشِ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ وَاللَّفْظُ لَهُ حَدَّثَنَا أَبِي حَدَّثَنَا الْأَعْمَشُ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ الْمُسْتَوْرِدِ بْنِ الْأَحْنَفِ عَنْ صِلَةَ بْنِ زُفَرَ عَنْ حُذَيْفَةَ قَالَصَلَّيْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ لَيْلَةٍ فَافْتَتَحَ الْبَقَرَةَ فَقُلْتُ يَرْكَعُ عِنْدَ الْمِائَةِ ثُمَّ مَضَى فَقُلْتُ يُصَلِّي بِهَا فِي رَكْعَةٍ فَمَضَى فَقُلْتُ يَرْكَعُ بِهَا ثُمَّ افْتَتَحَ النِّسَاءَ فَقَرَأَهَا ثُمَّ افْتَتَحَ آلَ عِمْرَانَ فَقَرَأَهَا يَقْرَأُ مُتَرَسِّلًا إِذَا مَرَّ بِآيَةٍ فِيهَا تَسْبِيحٌ سَبَّحَ وَإِذَا مَرَّ بِسُؤَالٍ سَأَلَ وَإِذَا مَرَّ بِتَعَوُّذٍ تَعَوَّذَ ثُمَّ رَكَعَ فَجَعَلَ يَقُولُ سُبْحَانَ رَبِّيَ الْعَظِيمِ فَكَانَ رُكُوعُهُ نَحْوًا مِنْ قِيَامِهِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ ثُمَّ قَامَ طَوِيلًا قَرِيبًا مِمَّا رَكَعَ ثُمَّ سَجَدَ فَقَالَ سُبْحَانَ رَبِّيَ الْأَعْلَى فَكَانَ سُجُودُهُ قَرِيبًا مِنْ قِيَامِهِقَالَ وَفِي حَدِيثِ جَرِيرٍ مِنْ الزِّيَادَةِ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا لَكَ الْحَمْدُ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] dan [Abu Mu'awiyah] -dalam jalur lain- Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] semuanya dari [Jarir] mereka semua dari [Al A'masy] -dalam jalur lain- telah menceritakan kepada kami [Ibnu Numair] -dan lafazh ini adalah darinya- telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Al A'masy] dari [Sa'id bin Ubaidah] dari [Al Mustaurid bin Al Ahnaf] dari [Shilah bin Zufar] dari [Hudzaifah] ia berkata; Pada suatu malam, saya shalat (Qiyamul Lail) bersama Rasulullah shallallahu 'alaihi wasallam, lalu beliau mulai membaca surat Al Baqarah. Kemudian saya pun berkata (dalam hati bahwa beliau) akan ruku' pada ayat yang ke seratus. Kemudian (seratus ayat pun) berlalu, lalu saya berkata (dalam hati bahwa) beliau akan shalat dengan (surat itu) dalam satu raka'at. Namun (surat Al Baqarah pun) berlalu, maka saya berkata (dalam hati bahwa) beliau akan segera sujud. Ternyata beliau melanjutkan dengan mulai membaca surat An Nisa` hingga selesai membacanya. Kemudian beliau melanjutkan ke surat Ali Imran hingga selesai hingga beliau selesai membacanya. Bila beliau membaca ayat tasbih, beliau bertasbih dan bila beliau membaca ayat yang memerintahkan untuk memohon, beliau memohon, dan bila beliau membaca ayat ta'awwudz (ayat yang memerintahkan untuk memohon perlindungan) beliau memohon perlindungan. Kemudian beliau ruku'. Dalam ruku', beliau membaca: \"SUBHAANA RABBIYAL 'AZHIIM (Maha Suci Tuhanku yang Maha Agung).\" Dan lama beliau ruku' hampir sama dengan berdirinya. Kemudian beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH (Maha Mendengar Allah akan orang yang memuji-Nya).\" Kemudian beliau berdiri dan lamanya berdiri lebih kurang sama dengan lamanya ruku'. Sesudah itu beliau sujud, dan dalam sujud beliau membaca: \"SUBHAANA RABBIYAL A'LAA (Maha Suci Tuhanku Yang Maha Tinggi).\" Lama beliau sujud hampir sama dengan lamanya berdiri. Sementara di dalam hadits Jarir terdapat tambahan; Beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH RABBANAA LAKAL HAMDU (Allah Maha Mendengar akan orang yang memuji-Nya, Ya Tuhan kami bagi-Mu segala puji).\""},"1211":{"ar":"و حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ جَرِيرٍ قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَقَالَ عَبْدُ اللَّهِ صَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَطَالَ حَتَّى هَمَمْتُ بِأَمْرِ سَوْءٍ قَالَ قِيلَ وَمَا هَمَمْتَ بِهِ قَالَ هَمَمْتُ أَنْ أَجْلِسَ وَأَدَعَهُو حَدَّثَنَاه إِسْمَعِيلُ بْنُ الْخَلِيلِ وَسُوَيْدُ بْنُ سَعِيدٍ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] keduanya dari [Jarir] -dalam jalur lain [Utsman] berkata- telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wa`il] ia berkata, [Abdullah] berkata; \"Saya pernah shalat bersama Rasulullah shallallahu 'alaihi wasallam lalu beliau memanjangkannya hingga saya berkeinginan untuk berbuat sesuatu yang tidak baik.\" Ditanyakan kepadanya, \"Perbuatan apa yang hendak kamu lakukan?\" Abdullah menjawab, \"Saya hendak duduk dan meninggalkannya.\" Dan telah menceritakannya kepada kami [Isma'il bin Khalil] dan [Suwaid bin Sa'id] dari [Ali bin Mushir] dari [Al A'masy] dengan isnad ini semisalnya."},"1212":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَذُكِرَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلٌ نَامَ لَيْلَةً حَتَّى أَصْبَحَ قَالَ ذَاكَ رَجُلٌ بَالَ الشَّيْطَانُ فِي أُذُنَيْهِ أَوْ قَالَ فِي أُذُنِهِ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq] -Utsman- berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] ia berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam mendengarkan cerita bahwa ada laki-laki yang tidur hingga pagi. Maka beliau bersabda: \"Itulah laki-laki yang telah dikencingi kedua telinganya oleh syetan.\" Atau beliau mengatakan; \"Di telinganya.\""},"1213":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ عُقَيْلٍ عَنْ الزُّهْرِيِّ عَنْ عَلِيِّ بْنِ حُسَيْنٍ أَنَّ الْحُسَيْنَ بْنَ عَلِيٍّ حَدَّثَهُ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَرَقَهُ وَفَاطِمَةَ فَقَالَ أَلَا تُصَلُّونَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا أَنْفُسُنَا بِيَدِ اللَّهِ فَإِذَا شَاءَ أَنْ يَبْعَثَنَا بَعَثَنَا فَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ قُلْتُ لَهُ ذَلِكَ ثُمَّ سَمِعْتُهُ وَهُوَ مُدْبِرٌ يَضْرِبُ فَخِذَهُ وَيَقُولُ{ وَكَانَ الْإِنْسَانُ أَكْثَرَ شَيْءٍ جَدَلًا }","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Uqail] dari [Az Zuhri] dari [Ali bin Husain] bahwa [Al Husain bin Ali] telah menceritakan kepadanya dari [Ali bin Abu Thalib] bahwa pada suatu malam tiba-tiba Nabi shallallahu 'alaihi wasallam mendatangi rumah kami -yakni rumahku bersama Fathimah- seraya berkata: \"Apakah kalian tidak shalat?\" jawabku, \"Wahai Rasulullah, sesungguhnya jiwa kami berada di tangan Allah. Bila Dia menghendaki kami bangun, tentu kami bangun.\" Mendengar jawaban itu beliau pergi. Kemudian terdengarlah olehku beliau memukul pahanya sambil bersabda: \"Memang, manusia itu suka membantah.\""},"1214":{"ar":"حَدَّثَنَا عَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَ عَمْرٌو حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْقِدُ الشَّيْطَانُ عَلَى قَافِيَةِ رَأْسِ أَحَدِكُمْ ثَلَاثَ عُقَدٍ إِذَا نَامَ بِكُلِّ عُقْدَةٍ يَضْرِبُ عَلَيْكَ لَيْلًا طَوِيلًا فَإِذَا اسْتَيْقَظَ فَذَكَرَ اللَّهَ انْحَلَّتْ عُقْدَةٌ وَإِذَا تَوَضَّأَ انْحَلَّتْ عَنْهُ عُقْدَتَانِ فَإِذَا صَلَّى انْحَلَّتْ الْعُقَدُ فَأَصْبَحَ نَشِيطًا طَيِّبَ النَّفْسِ وَإِلَّا أَصْبَحَ خَبِيثَ النَّفْسِ كَسْلَانَ","id":"Telah menceritakan kepada kami [Amru An Naqid] dan [Zuhair bin Harb] -Amru- berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] sampai pada Nabi shallallahu 'alaihi wasallam (bahwa beliau bersabda): \"Syetan akan mengikat tengkuk salah seorang dari kalian saat ia tidur dengan tiga ikatan. Dengan setiap ikatan ia akan membisikkan padamu bahwa malam masih panjang. Jika ia terbangun lalu berdzikir kepada Allah, lepaslah satu ikatan, jika ia berwudlu maka lepaslah dua ikatan. Dan jika ia melanjutkan dengan shalat, maka lepaslah seluruh ikatan itu, sehingga pada pagi harinya ia mulai dengan penuh kesemangatan dan jiwanya pun sehat. Namun jika tidak, maka dia akan memasuki waktu pagi dengan jiwa yang keji dan penuh kemalasan.\""},"1215":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اجْعَلُوا مِنْ صَلَاتِكُمْ فِي بُيُوتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًا","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya] dari [Ubaidullah] ia berkata, telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jadikanlah sebagian shalat kalian (dilakukan) di rumah-rumah kalian, dan janganlah kalian menjadikannya sebagai kuburan.\""},"1216":{"ar":"و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ أَخْبَرَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ صَلُّوا فِي بُيُوتِكُمْ وَلَا تَتَّخِذُوهَا قُبُورًا","id":"Dan Telah menceritakan kepada kami [Ibnul Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] telah mengabarkan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Shalatlah di rumah-rumah kalian, dan janganlah kalian menjadikannya sebagai kuburan.\""},"1217":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَضَى أَحَدُكُمْ الصَّلَاةَ فِي مَسْجِدِهِ فَلْيَجْعَلْ لِبَيْتِهِ نَصِيبًا مِنْ صَلَاتِهِ فَإِنَّ اللَّهَ جَاعِلٌ فِي بَيْتِهِ مِنْ صَلَاتِهِ خَيْرًا","id":"Dan Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian telah menunaikan shalat di Masjidnya, hendaknya ia menyisakan sebagian shalatnya untuk (dikerjakan) di rumahnya, karena dari shalatnya itu, Allah akan menjadikan kebaikan di dalam rumahnya.\""},"1218":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَرَّادٍ الْأَشْعَرِيُّ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الْبَيْتِ الَّذِي يُذْكَرُ اللَّهُ فِيهِ وَ��لْبَيْتِ الَّذِي لَا يُذْكَرُ اللَّهُ فِيهِ مَثَلُ الْحَيِّ وَالْمَيِّتِ","id":"Telah menceritakan kepada kami [Abdullah bin Barrad Al Asy'ari] dan [Muhammad bin Al 'Ala`] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Perumpamaan rumah yang di dalamnya selalu disebut nama Allah Ta'ala dengan rumah yang di dalamnya tidak pernah disebut nama Allah adalah sebagaimana orang hidup dan orang mati.\""},"1219":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ عَبْدِ الرَّحْمَنِ الْقَارِيُّ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَجْعَلُوا بُيُوتَكُمْ مَقَابِرَ إِنَّ الشَّيْطَانَ يَنْفِرُ مِنْ الْبَيْتِ الَّذِي تُقْرَأُ فِيهِ سُورَةُ الْبَقَرَةِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman Al Qariy] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian jadikan rumah-rumah kalian sebagai kuburan, sesungguhnya syetan itu akan lari dari rumah yang di dalamnya dibacakan surat Al Baqarah.\""},"1220":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا سَالِمٌ أَبُو النَّضْرِ مَوْلَى عُمَرَ بْنِ عُبَيْدِ اللَّهِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَاحْتَجَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُجَيْرَةً بِخَصَفَةٍ أَوْ حَصِيرٍ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فِيهَا قَالَ فَتَتَبَّعَ إِلَيْهِ رِجَالٌ وَجَاءُوا يُصَلُّونَ بِصَلَاتِهِ قَالَ ثُمَّ جَاءُوا لَيْلَةً فَحَضَرُوا وَأَبْطَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْهُمْ قَالَ فَلَمْ يَخْرُجْ إِلَيْهِمْ فَرَفَعُوا أَصْوَاتَهُمْ وَحَصَبُوا الْبَابَ فَخَرَجَ إِلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُغْضَبًا فَقَالَ لَهُمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا زَالَ بِكُمْ صَنِيعُكُمْ حَتَّى ظَنَنْتُ أَنَّهُ سَيُكْتَبُ عَلَيْكُمْ فَعَلَيْكُمْ بِالصَّلَاةِ فِي بُيُوتِكُمْ فَإِنَّ خَيْرَ صَلَاةِ الْمَرْءِ فِي بَيْتِهِ إِلَّا الصَّلَاةَ الْمَكْتُوبَةَو حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ قَالَ سَمِعْتُ أَبَا النَّضْرِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ ثَابِتٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اتَّخَذَ حُجْرَةً فِي الْمَسْجِدِ مِنْ حَصِيرٍ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهَا لَيَالِيَ حَتَّى اجْتَمَعَ إِلَيْهِ نَاسٌ فَذَكَرَ نَحْوَهُ وَزَادَ فِيهِ وَلَوْ كُتِبَ عَلَيْكُمْ مَا قُمْتُمْ بِهِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Salim Abu Nadlr] maula Umar bin Ubaidullah, dari [Busr bin Sa'id] dari [Zaid bin Tsabit] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memasang tenda dari tikar pada sebuah tempat di Masjid, sehingga merupakan sebuah kamar tempat beliau shalat (malam). Melihat hal itu, beberapa orang sahabat mendatangi tempat itu dan mereka shalat pula mengikuti Nabi shallallahu 'alaihi wasallam shalat. Pada suatu malam mereka datang pula, tetapi Rasulullah shallallahu 'alaihi wasallam terlambat, sehingga beliau tidak keluar sama sekali menemui mereka. Oleh karena itu, mereka mengeraskan suara dan melempar pintu dengan kerikil, untuk memberi tahu Nabi shallallahu 'alaihi wasallam, karena mereka menyangka kalau-kalau beliau lupa. Maka dalam keadaan marah Rasulullah shallallahu 'alaihi wasallam keluar menemui mereka sambil bersabda: \"Janganlah kalian berbuat demikian, karena aku mengira bahwa shalat malam itu akan diwajibkan kepada kalian. Karena itu, shalatlah kalian di rumah kalian masing-masing, karena sebaik-baik shalat seseorang adalah yang dilakukan di rumahnya sendiri, kecuali shalat wajib.\" Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Musa bin Uqbah] ia berkata, saya mendengar [Abu An Nadlr] dari [Busr bin Sa'id] dari [Zaid bin Tsabit] bahwa Nabi shallallahu 'alaihi wasallam memasang tenda dari tikar pada sebuah tempat di Masjid, sehingga merupakan sebuah kamar tempat beliau shalat (malam). Melihat hal itu, beberapa orang sahabat mendatangi tempat itu. Maka ia pun menyebutkan hadits yang serupa dengannya. Dan ia menambahkan di dalamnya; \"Jika (shalat malam) itu diwajibkan atas kalian, niscaya kalian tidak akan mampu melakukannya.\""},"1221":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ يَعْنِي الثَّقَفِيَّ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَصِيرٌ وَكَانَ يُحَجِّرُهُ مِنْ اللَّيْلِ فَيُصَلِّي فِيهِ فَجَعَلَ النَّاسُ يُصَلُّونَ بِصَلَاتِهِ وَيَبْسُطُهُ بِالنَّهَارِ فَثَابُوا ذَاتَ لَيْلَةٍ فَقَالَ يَا أَيُّهَا النَّاسُ عَلَيْكُمْ مِنْ الْأَعْمَالِ مَا تُطِيقُونَ فَإِنَّ اللَّهَ لَا يَمَلُّ حَتَّى تَمَلُّوا وَإِنَّ أَحَبَّ الْأَعْمَالِ إِلَى اللَّهِ مَا دُووِمَ عَلَيْهِ وَإِنْ قَلَّ وَكَانَ آلُ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَمِلُوا عَمَلًا أَثْبَتُوهُ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] yakni Ats Tsaqafi, telah menceritakan kepada kami [Ubaidullah] dari [Sa'id bin Abu Sa'id] dari [Abu Salamah] dari [Aisyah] bahwa ia berkata; \"Rasulullah shallallahu 'alaihi wasallam mempunyai sehelai tikar yang dibentangkannya pada malam hari, sehingga merupakan tabir sebuah kamar tempat beliau shalat. Lalu orang-orang pun shalat pula bersama beliau. Dan dibentangkannya di siang hari. Pada suatu malam mereka kembali berkumpul mengikuti beliau. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: 'Wahai sekalian manusia, hendaklah kalian beramal menurut kemampuan kalian, sebab Allah tidak akan pernah bosan hingga kalian bosan sendiri. Sesungguhnya amalan yang paling disukai Allah, adalah amalan yang dikerjakan secara terus menerus meskipun sedikit. Dan bila keluarga Muhammad shallallahu 'alaihi wasallam melakukan suatu amalan, maka mereka akan menekuninya.'\""},"1222":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ أَنَّهُ سَمِعَ أَبَا سَلَمَةَ يُحَدِّثُ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ أَيُّ الْعَمَلِ أَحَبُّ إِلَى اللَّهِ قَالَ أَدْوَمُهُ وَإِنْ قَلَّ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Sa'id bin Ibrahim] bahwa ia mendengar [Abu Salamah] menceritakan dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya, \"Amal yang bagaimanakah yang paling dicintai oleh Allah?\" Aisyah menjawab, \"Amalan yang dikerjakan secara kontinyu meskipun sedikit.\""},"1223":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ زُهَيْرٌ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَ سَأَلْتُ أُمَّ الْمُؤْمِنِينَ عَائِشَةَ قَالَقُلْتُ يَا أُمَّ الْمُؤْمِنِينَ كَيْفَ كَانَ عَمَلُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ كَانَ يَخُصُّ شَيْئًا مِنْ الْأَيَّامِ قَالَتْ لَا كَانَ عَمَلُهُ دِيمَةً وَأَيُّكُمْ يَسْتَطِيعُ مَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَطِيعُ","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Ishaq bin Ibrahim] -Zuhari berkata- telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Alqamah] ia berkata; Saya bertanya kepada Ummul mukminin [Aisyah], \"Wahai Ummul mukminin, bagaimanah amalan Rasulullah shallallahu 'alaihi wasallam? Apakah beliau mengkhususkan suatu amalan pada hari tertentu?\" Aisyah menjawab, \"Tidak, amalan beliau adalah terus menerus. Dan siapa pun kalian, pasti akan mampu melakukan amalan yang Rasulullah shallallahu 'alaihi wasallam mampu melakukannya.\""},"1224":{"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا سَعْدُ بْنُ سَعِيدٍ أَخْبَرَنِي الْقَاسِمُ بْنُ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَحَبُّ الْأَعْمَالِ إِلَى اللَّهِ تَعَالَى أَدْوَمُهَا وَإِنْ قَلَّ قَالَ وَكَانَتْ عَائِشَةُ إِذَا عَمِلَتْ الْعَمَلَ لَزِمَتْهُ","id":"Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Sa'd bin Sa'id] telah mengabarkan kepadaku [Al Qasim bin Muhammad] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Amalan yang paling dicintai Allah adalah yang terus-menerus (dilakukan) meskipun sedikit.\" Al Qasim berkata; Dan Aisyah, bila ia mengerjakan suatu amalan, maka ia kan menekuninya."},"1225":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا ابْنُ عُلَيَّةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ عَنْ عَبْدِ الْعَزِيزِ بْنِ صُهَيْبٍ عَنْ أَنَسٍ قَالَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْجِدَ وَحَبْلٌ مَمْدُودٌ بَيْنَ سَارِيَتَيْنِ فَقَالَ مَا هَذَا قَالُوا لِزَيْنَبَ تُصَلِّي فَإِذَا كَسِلَتْ أَوْ فَتَرَتْ أَمْسَكَتْ بِهِ فَقَالَ حُلُّوهُ لِيُصَلِّ أَحَدُكُمْ نَشَاطَهُ فَإِذَا كَسِلَ أَوْ فَتَرَ قَعَدَوَفِي حَدِيثِ زُهَيْرٍ فَلْيَقْعُدْ و حَدَّثَنَاه شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Ibnu Ulayyah] -dalam jalur lain- Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il] dari [Abdul Aziz bin Shuhaib] dari [Anas] ia berkata; \"Suatu ketika, Rasulullah shallallahu 'alaihi wasallam masuk Masjid. Lalu beliau melihat seuntai tali yang terbentang di antara dua tiang, maka beliau pun bertanya: 'Tali apa ini? ' Mereka menjawab, 'Tali yang dibentangkan oleh Zainab dan digunakannya shalat. Bila ia malas atau letih, maka dia akan berpegangan dengan tali itu.' Maka Nabi shallallahu 'alaihi wasallam bersabda: 'Lepaskanlah tali itu. Hendaklah salah seorang dari kalian shalat ketika kondisi semangat. Sedangkan ika ia malas atau letih, hendaklah ia duduk.'\" Sedangkan dalam haditsnya Zuhair tertera; \"Hendaklah ia duduk.\" Dan telah menceritakannya kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dari [Anas] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1226":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى وَمُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُأَنَّ الْحَوْلَاءَ بِنْتَ تُوَيْتِ بْنِ حَبِيبِ بْنِ أَسَدِ بْنِ عَبْدِ الْعُزَّى مَرَّتْ بِهَا وَعِنْدَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ هَذِهِ الْحَوْلَاءُ بِنْتُ تُوَيْتٍ وَزَعَمُوا أَنَّهَا لَا تَنَامُ اللَّيْلَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنَامُ اللَّيْلَ خُذُوا مِنْ الْعَمَلِ مَا تُطِيقُونَ فَوَاللَّهِ لَا يَسْأَمُ اللَّهُ حَتَّى تَسْأَمُوا","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] dan [Muhammad bin Salamah Al Muradi] ia berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] ia berkata, telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Aisyah] isteri Nabi shallallahu 'alaihi wasallam telah mengabarkan kepadanya bahwa Al Haula`a binti Tuwait bin Habib bin Asad bin Abdul 'Uzza melewatinya, sementara di sisinya ada Rasulullah shallallahu 'alaihi wasallam. Aisyah pun berkata; Saya berkata, \"Wanita ini adalah Al Haula` binti Tuwait, orang-orang menganggap bahwa ia tidak pernah tidur malam.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Benarkan ia tidak tidur malam? Hendaklah kalian beramal sesuai dengan kemampuan kalian, karena demi Allah, Allah tidak akan bosan hingga kalian sendiri yang bosan.\""},"1227":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَاللَّفْظ لَهُ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ هِشَامٍ قَالَ أَخْبَرَنِي أَبِي عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي امْرَأَةٌ فَقَالَ مَنْ هَذِهِ فَقُلْتُ امْرَأَةٌ لَا تَنَامُ تُصَلِّي قَالَ عَلَيْكُمْ مِنْ الْعَمَلِ مَا تُطِيقُونَ فَوَاللَّهِ لَا يَمَلُّ اللَّهُ حَتَّى تَمَلُّوا وَكَانَ أَحَبَّ الدِّينِ إِلَيْهِ مَا دَاوَمَ عَلَيْهِ صَاحِبُهُوَفِي حَدِيثِ أَبِي أُسَامَةَ أَنَّهَا امْرَأَةٌ مِنْ بَنِي أَسَدٍ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin Urwah] -dalam jalur lain- Dan telah menceritakan kepadaku [Zuhair bin Harb] -dan lafazh hadits darinya- telah menceritakan kepada kami [Yahya bin Sa'id] dari [Hisyam] ia berkata, telah mengabarkan kepadaku [bapakku] dari [Aisyah] ia berkata; \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam rumahku, yang saat itu saya bersama dengan seorang wanita. Maka beliau pun bertanya: 'Siapa wanita ini? ' Saya menjawab, 'Ia adalah seorang wanita yang tidak pernah tidur karena selalu menunaikan shalat sepanjang malam.' Maka beliau bersabda: 'Beribadahlah kalian sesuai dengan kemampuan kalian. Demi Allah, Dia tidak akan pernah bosan hingga kalian sendiri yang bosan. Dan amalan agama yang paling dicintai olehNya adalah yang dikerjakan dengan kontinyu oleh pelakunya.'\" Dalam hadits Usamah bahwa wanita itu berasal dari Bani Asad."},"1228":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ جَمِيعًا عَنْ هِشَامِ بْنِ عُرْوَةَ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَاللَّفْظُ لَهُ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا نَعَسَ أَحَدُكُمْ فِي الصَّلَاةِ فَلْيَرْقُدْ حَتَّى يَذْهَبَ عَنْهُ النَّوْمُ فَإِنَّ أَحَدَكُمْ إِذَا صَلَّى وَهُوَ نَاعِسٌ لَعَلَّهُ يَذْهَبُ يَسْتَغْفِرُ فَيَسُبُّ نَفْسَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] -dalam jalur periwayatan lain- Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] semuanya dari [Hisyam bin Urwah] -dalam jalur lain- Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] -lafazh darinya- dari [Malik bin Anas] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian mengantuk di dalam shalatnya, maka hendaklah ia tidur hingga rasa kantuknya hilang. Karena jika salah seorang dari kalian shalat dalam keadaan mengantuk, mungkin saja ia memohon ampunan, namun ternyata justru mencaci-maki dirinya sendiri.\""},"1229":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَعَنْ مُحَمَّدٍ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ أَحَادِيثَ مِنْهَا وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا قَامَ أَحَدُكُمْ مِنْ اللَّيْلِ فَاسْتَعْجَمَ الْقُرْآنُ عَلَى لِسَانِهِ فَلَمْ يَدْرِ مَا يَقُولُ فَلْيَضْطَجِعْ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] ia berkata, ini yang diceritakan kepada kami oleh [Abu Hurairah] dari Muhammad Rasulullah shallallahu 'alaihi wasallam. Ia pun menyebutkan hadits di antaranya adalah; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian mengerjakan shalat malam kemudian tidak mampu membaca Al Qur`an (karena ngantuk), sehingga tidak mengerti apa yang ia baca maka hendaknya ia tidur dahulu.\""},"1230":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ رَجُلًا يَقْرَأُ مِنْ اللَّيْلِ فَقَالَ يَرْحَمُهُ اللَّهُ لَقَدْ أَذْكَرَنِي كَذَا وَكَذَا آيَةً كُنْتُ أَسْقَطْتُهَا مِنْ سُورَةِ كَذَا وَكَذَا","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [bapaknya] dari [Aisyah] bahwasanya; Pada suatu malam Nabi shallallahu 'alaihi wasallam mendengar seroang laki-laki membaca (Al Qur`an), maka beliau pun bersabda: \"Semoga Allah memberinya rahmat. Ia telah mengingatkanku ayat ini dan ini. Yakni ayat yang aku lupa dari surat ini dan surat itu.\""},"1231":{"ar":"و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا عَبْدَةُ وَأَبُو مُعَاوِيَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَمِعُ قِرَاءَةَ رَجُلٍ فِي الْمَسْجِدِ فَقَالَ رَحِمَهُ اللَّهُ لَقَدْ أَذْكَرَنِي آيَةً كُنْتُ أُنْسِيتُهَا","id":"Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Abdah] dan [Abu Mu'awiyah] dari [Hisyam] dari [bapaknya] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mendengar bacaan seorang laki-laki di Masjid, maka beliau pun bersabda: \"Semoga Allah memberinya rahmat. Dia telah mengingatkanku akan suatu ayat, yang aku telah dilupakan daripadanya.\""},"1232":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّمَا مَثَلُ صَاحِبِ الْقُرْآنِ كَمَثَلِ الْإِبِلِ الْمُعَقَّلَةِ إِنْ عَاهَدَ عَلَيْهَا أَمْسَكَهَا وَإِنْ أَطْلَقَهَا ذَهَبَتْحَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَعُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالُوا حَدَّثَنَا يَحْيَى وَهُوَ الْقَطَّانُ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي كُلُّهُمْ عَنْ عُبَيْدِ اللَّهِ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ أَيُّوبَ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ ح و حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ الْمُسَيَّبِيُّ حَدَّثَنَا أَنَسٌ يَعْنِي ابْنَ عِيَاضٍ جَمِيعًا عَنْ مُوسَى بْنِ عُقْبَةَ كُلُّ هَؤُلَاءِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَعْنَى حَدِيثِ مَالِكٍ وَزَادَ فِي حَدِيثِ مُوسَى بْنِ عُقْبَةَ وَإِذَا قَامَ صَاحِبُ الْقُرْآنِ فَقَرَأَهُ بِاللَّيْلِ وَالنَّهَارِ ذَكَرَهُ وَإِذَا لَمْ يَقُمْ بِهِ نَسِيَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang yang hafal Al Qur`an, ialah seperti unta yang ditambatkan. Jika ia tetap diawasi, dia akan tetap tertambat, tetapi jika ia dibiarkan maka akan lepas.\" telah menceritakan kepada kami [Zuhair bin Harb] dan [Muhammad bin Al Mutsanna] dan [Ubaidullah bin Sa'id] mereka berkata, telah menceritakan kepada kami [Yahya Al Qaththan] -dalam jalur lain- telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abu Khalid Al Ahmar] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] semuanya dari [Ubaidullah] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Ayyub] -dalam jalur lain- Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub] yakni Ibnu Abdurrahman. -Dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Ishaq Al Musayyibi] Telah menceritakan kepada kami [Anas] yakni Ibnu Iyadl, semuanya dari [Musa bin Uqbah] mereka semua dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam yang semakna dengan hadits Malik. Dan ia menambahkan di dalam hadits Musa bin Uqbah; \"Jika seorang penghafal Al Qur`an shalat lalu ia membacanya pada malam dan siang hari, niscaya ia akan senantiasa mengingatnya. Namun, jika ia tidak melakukan hal itu, niscaya ia akan melupakannya.\""},"1233":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ إِسْحَقُ أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَمَا لِأَحَدِهِمْ يَقُولُ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ اسْتَذْكِرُوا الْقُرْآنَ فَلَهُوَ أَشَدُّ تَفَصِّيًا مِنْ صُدُورِ الرِّجَالِ مِنْ النَّعَمِ بِعُقُلِهَا","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] dan [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] -Ishaq- berkata, telah mengabarkan kepada kami -dua orang yang lain- berkata telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Abu Wa`il] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Alangkah buruknya seorang yang berkata, 'Aku lupa ayat ini dan itu.' Akan tetapi ia telah dilupakan Allah. Sering-seringlah mengingat (membaca) Al Qur`an, karena ia lebih cepat hilangnya dari dada seseorang, daripada unta yang lepas dari ikatannya.\""},"1234":{"ar":"حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي وَأَبُو مُعَاوِيَةَ ح و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَاللَّفْظُ لَهُ قَالَ أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ قَالَ قَالَ عَبْدُ اللَّهِتَعَاهَدُوا هَذِهِ الْمَصَاحِفَ وَرُبَّمَا قَالَ الْقُرْآنَ فَلَهُوَ أَشَدُّ تَفَصِّيًا مِنْ صُدُورِ الرِّجَالِ مِنْ النَّعَمِ مِنْ عُقُلِهِ قَالَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَقُلْ أَحَدُكُمْ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ","id":"Telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] dan [Abu Mu'awiyah] -dalam jalur lain- Dan telah menceritakan kepada kami [Yahya bin Yahya] -lafazh adalah miliknya- ia berkata, telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] ia berkata, [Abdullah] berkata; \"Sering-seringlah kalian membaca Mushhaf ini -sepertinya ia juga mengatakan- Al Qur`an, karena ia lebih cepat hilangnya dari dada para penghafalnya daripada unta dari ikatannya.\" Abdullah berkata; Dan Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Janganlah salah seorang dari kalian mengatakan, 'Saya telah lupa ayat ini dan itu.' akan tetapi ia telah dilupakan.\""},"1235":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي عَبْدَةُ بْنُ أَبِي لُبَابَةَ عَنْ شَقِيقِ بْنِ سَلَمَةَ قَالَ سَمِعْتُ ابْنَ مَسْعُودٍ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِئْسَمَا لِلرَّجُلِ أَنْ يَقُولَ نَسِيتُ سُورَةَ كَيْتَ وَكَيْتَ أَوْ نَسِيتُ آيَةَ كَيْتَ وَكَيْتَ بَلْ هُوَ نُسِّيَ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Abdah bin Abu Lubabah] dari [Syaqiq bin Salamah] ia berkata, saya mendengar [Ibnu Mas'ud] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Alangkah buruknya bagi seorang yang berkata, 'Saya telah lupa surat ini dan itu atau saya lupa ayat ini dan itu.' Akan tetapi ia dilupakan.\""},"1236":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بَرَّادٍ الْأَشْعَرِيُّ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَىعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تَعَاهَدُوا هَذَا الْقُرْآنَ فَوَالَّذِي نَفْسُ مُحَمَّدٍ بِيَدِهِ لَهُوَ أَشَدُّ تَفَلُّتًا مِنْ الْإِبِلِ فِي عُقُلِهَاوَلَفْظُ الْحَدِيثِ لِابْنِ بَرَّادٍ","id":"Telah menceritakan kepada kami [Abdullah bin Barrad Al Asy'ari] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Jagalah oleh kalian Al Qur`an ini (dengan banyak membacanya), karena demi Dzat yang jiwa Muhammad berada di tangan-Nya, ia lebih cepat hilangnya daripada unta dari tambatannya.\" Lafazh hadits ini dari Ibnu Barrad."},"1237":{"ar":"حَدَّثَنِي عَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَيَبْلُغُ بِهِ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِو حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ ح و حَدَّثَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو كِلَاهُمَا عَنْ ابْنِ شِهَابٍ بِهَذَا الْإِسْنَادِ قَالَ كَمَا يَأْذَنُ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ","id":"Telah menceritakan kepada kami [Amru An Naqid] dan [Zuhair bin Harb] keduanya berkata, telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah] hingga sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah tidak menaruh perhatian terhadap sesuatu, seperti perhatiannya terhadap Nabi yang melagukan Al Qur`an dengan suara yang indah.\" Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] -dalam jalur lain- Dan telah menceritakan kepadaku [Yunus bin Abdul A'la] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Amru] keduanya dari [Ibnu Syihab] dengan isnad ini. Ia mengatakan; \"Sebagaimana perhatianNya terhadap Nabi saat melagukan Al Qur`an.\""},"1238":{"ar":"حَدَّثَنِي بِشْرُ بْنُ الْحَكَمِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّهُسَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا أَذِنَ اللَّهُ لِشَيْءٍ مَا أَذِنَ لِنَبِيٍّ حَسَنِ الصَّوْتِ يَتَغَنَّى بِالْقُرْآنِ يَجْهَرُ بِهِو حَدَّثَنِي ابْنُ أَخِي ابْنِ وَهْبٍ حَدَّثَنَا عَمِّي عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عُمَرُ بْنُ مَالِكٍ وَحَيْوَةُ بْنُ شُرَيْحٍ عَنْ ابْنِ الْهَادِ بِهَذَا الْإِسْنَادِ مِثْلَهُ سَوَاءً وَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ سَمِعَ","id":"Telah menceritakan kepadaku [Bisyr bin Al Hakam] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] telah menceritakan kepada kami [Yazid] ia adalah Ibnul Hadi, dari [Muhammad bin Ibrahim] dari [Abu Salamah] dari [Abu Hurairah] bahwa mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak menaruh perhatian terhadap sesuatu, seperti perhatianNya terhadap Nabi ketika melagukan Al Qur`an dengan suara yang indah dan nyaring.\" Dan telah menceritakan kepadaku [Anak saudara Ibnu Wahab] telah menceritakan kepada kami [pamanku] Abdullah bin Wahb, telah mengabarkan kepadaku [Umar bin Malik] dan [Haiwah bin Syuraih] dari [Ibnul Hadi] dengan isnad ini semisalnya. Dan ia mengatakan; Bahwa Rasulullah shallallahu 'alaihi wasallam tidak mengatakan; \"Mendengar.\""},"1239":{"ar":"و حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا هِقْلٌ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَذِنَ اللَّهُ لِشَيْءٍ كَأَذَنِهِ لِنَبِيٍّ يَتَغَنَّى بِالْقُرْآنِ يَجْهَرُ بِهِو حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَابْنُ حُجْرٍ قَالُوا حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ حَدِيثِ يَحْيَى بْنِ أَبِي كَثِيرٍ غَيْرَ أَنَّ ابْنَ أَيُّوبَ قَالَ فِي رِوَايَتِهِ كَإِذْنِهِ","id":"Telah menceritakan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Hiql] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tidak menaruh perhatian terhadap sesuatu pun seperti perhatianNya terhadap Nabi saat melagukan Al Qur`an dengan menyaringkan suaranya.\" Dan telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah bin Sa'id] dan [Ibnu Hujr] mereka berkata, telah menceritakan kepada kami [Isma'il] ia adalah Ibnu Ja'far, dari [Muhammad bin Amru] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam seperti haditsnya Yahya bin Abu Katsir. Hanya saja Ayyub mengatakan dalam riwayatnya, \"Seperti perhatianNya.\""},"1240":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا مَالِكٌ وَهُوَ ابْنُ مِغْوَلٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ عَبْدَ اللَّهِ بْنَ قَيْسٍ أَوْ الْأَشْعَرِيَّ أُعْطِيَ مِزْمَارًا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Malik bin Mighwal] dari [Abdullah bin Buraidah] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Abdullah bin Qais atau Al Asy'ari telah diberikan salah satu mizmar (suara yang merdu) dari mizmar yang dimiliki keluarga Dawud.\""},"1241":{"ar":"و حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا طَلْحَةُ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَبِي مُوسَى لَوْ رَأَيْتَنِي وَأَنَا أَسْتَمِعُ لِقِرَاءَتِكَ الْبَارِحَةَ لَقَدْ أُوتِيتَ مِزْمَارًا مِنْ مَزَامِيرِ آلِ دَاوُدَ","id":"Dan telah menceritakan kepada kami [Dawud bin Rusyaid] telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Thalhah] dari [Abu Burdah] dari [Abu Musa] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Abu Musa: \"Seandainya saja semalam kamu mengetahuiku sedang mendengarkan bacaanmu. Sungguh engkau telah diberi suara yang bagus sebagaimana yang telah diberikan kepada keluarga Daud.\""},"1242":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ وَوَكِيعٌ عَنْ شُعْبَةَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ الْمُزَنِيَّ يَقُولُاقَرَأَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ الْفَتْحِ فِي مَسِيرٍ لَهُ سُورَةَ الْفَتْحِ عَلَى رَاحِلَتِهِ فَرَجَّعَ فِي قِرَاءَتِهِقَالَ مُعَاوِيَةُ لَوْلَا أَنِّي أَخَافُ أَنْ يَجْتَمِعَ عَلَيَّ النَّاسُ لَحَكَيْتُ لَكُمْ قِرَاءَتَهُ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dan [Waki'] dari [Syu'bah] dari [Mu'awiyah bin Qurrah] ia berkata, saya mendengar [Abdullah bin Mughaffal Al Muzani] berkata; Nabi shallallahu 'alaihi wasallam membaca surat Al Fath pada tahun Al Fath (penaklukan kota Makkah) dalam suatu perjalanan disaat beliau berada di atas kendaraannya. Kemudian beliau mengulang-mengulang bacaannya. Mu'awiyah berkata; \"Sekiranya aku tidak khawatir manusia akan berkumpul mengerumuniku, niscaya akan saya ceritakan kepada kalian seperti apa bacaan beliau.\""},"1243":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ فَتْحِ مَكَّةَ عَلَى نَاقَتِهِ يَقْرَأُ سُورَةَ الْفَتْحِقَالَ فَقَرَأَ ابْنُ مُغَفَّلٍ وَرَجَّعَ فَقَالَ مُعَاوِيَةُ لَوْلَا النَّاسُ لَأَخَذْتُ لَكُمْ بِذَلِكَ الَّذِي ذَكَرَهُ ابْنُ مُغَفَّلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنَاه يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي قَالَا حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَفِي حَدِيثِ خَالِدِ بْنِ الْحَارِثِ قَالَ عَلَى رَاحِلَةٍ يَسِيرُ وَهُوَ يَقْرَأُ سُورَةَ الْفَتْحِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] -Ibnul Mutsanna- berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Mu'awiyah bin Qurrah] ia berkata, saya mendengar [Abdullah bin Mughaffal], ia berkata; Pada hari Fathu Makkah, saya melihat Rasulullah shallallahu 'alaihi wasallam di atas untanya membaca surat Al Fath. Ibnu Mughaffal pun membacanya dan mengulangi bacaannya kembali. Kemudian Mu'awiyah berkata, \"Sekiranya bukan karena (akan berkumpulnya) manusia, niscaya saya melakukan seperti yang telah disebutkan oleh Ibnu Mughaffal dari Nabi shallallahu 'alaihi wasallam.\" Dan telah menceritakannya kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Harits] -dalam jalur lain- Dan telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [bapakku] ia berkata, telah menceritakan kepada kami [Syu'bah] dengan isnad ini semisalnya. Dan di dalam hadits Khalid bin Harits, ia berkata; \"Di atas kendaraannya yang berjalan, sementara beliau membaca surat Al Fath.\""},"1244":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ أَبِي إِسْحَقَ عَنْ الْبَرَاءِ قَالَكَانَ رَجُلٌ يَقْرَأُ سُورَةَ الْكَهْفِ وَعِنْدَهُ فَرَسٌ مَرْبُوطٌ بِشَطَنَيْنِ فَتَغَشَّتْهُ سَحَابَةٌ فَجَعَلَتْ تَدُورُ وَتَدْنُو وَجَعَلَ فَرَسُهُ يَنْفِرُ مِنْهَا فَلَمَّا أَصْبَحَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ تِلْكَ السَّكِينَةُ تَنَزَّلَتْ لِلْقُرْآنِ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Abu Ishaq] dari [Al Baraa`] ia berkata; Ada seorang laki-laki membaca surat Al Kahfi, sementara di sampingnya terdapat seekor kuda yang terikat dengan dua tali ikatan. Tiba-tiba ia dinaungi oleh gumpalan awan. Awan tersebut kemudian berputar-putar dan mendekat, hingga kuda itu pun lari. Ketika pagi, laki-laki itu mendatangi Nabi shallallahu 'alaihi wasallam dan menuturkan hal itu kepada beliau, maka beliau pun bersabda: \"Itulah As sakinah (ketenangan) yang turun bagi (pembaca) Al Qur`an.\""},"1245":{"ar":"و حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ وَاللَّفْظُ لِابْنِ الْمُثَنَّى قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ يَقُولُاقَرَأَ رَجُلٌ الْكَهْفَ وَفِي الدَّارِ دَابَّةٌ فَجَعَلَتْ تَنْفِرُ فَنَظَرَ فَإِذَا ضَبَابَةٌ أَوْ سَحَابَةٌ قَدْ غَشِيَتْهُ قَالَ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اقْرَأْ فُلَانُ فَإِنَّهَا السَّكِينَةُ تَنَزَّلَتْ عِنْدَ الْقُرْآنِ أَوْ تَنَزَّلَتْ لِلْقُرْآنِو حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ وَأَبُو دَاوُدَ قَالَا حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ يَقُولُا فَذَكَرَا نَحْوَهُ غَيْرَ أَنَّهُمَا قَالَا تَنْقُزُ","id":"Dan telah menceritakan kepada kami [Ibnul Mutsanna] dan [Ibnu Basysyar] -sedangkan lafazh dari Ibnul Mutsanna- keduanya berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, saya mendengar [Al Baraa`] berkata; Seorang laki-laki membaca surat Al Kahfi, sementara di dalam rumahnya terdapat seekor Kuda. Tiba-tiba kuda itu lari, maka ia pun melihat dan ternyata ada awan yang menaunginya. Maka laki-laki itu pun menuturkan kejadikan itu kepada Nabi shallallahu 'alaihi wasallam. Beliau bersabda: \"Itu adalah As Sakinah (ketenangan) yang turun saat (membaca Al Qur`an) atau untuk (pembaca) Al Qur`an.\" Dan telah menceritakan kepada kami [Ibnul Mutsanna] telah menceritakan kepada kami [Abdurrahman bin Mahdi] dan [Abu Dawud] keduanya berkata, telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] ia berkata, saya mendengar [Al Baraa`] berkata. Maka ia pun menyebutkan hadits semisalnya. Hanya saja keduanya mengatakan; \"(Kuda itu) meloncat lari.\""},"1246":{"ar":"و حَدَّثَنِي حَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ وَحَجَّاجُ بْنُ الشَّاعِرِ وَتَقَارَبَا فِي اللَّفْظِ قَالَا حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي حَدَّثَنَا يَزِيدُ بْنُ الْهَادِ أَنَّ عَبْدَ اللَّهِ بْنَ خَبَّابٍ حَدَّثَهُ أَنَّ أَبَا سَعِيدٍ الْخُدْرِيَّ حَدَّثَهُأَنَّ أُسَيْدَ بْنَ حُضَيْرٍ بَيْنَمَا هُوَ لَيْلَةً يَقْرَأُ فِي مِرْبَدِهِ إِذْ جَالَتْ فَرَسُهُ فَقَرَأَ ثُمَّ جَالَتْ أُخْرَى فَقَرَأَ ثُمَّ جَالَتْ أَيْضًا قَالَ أُسَيْدٌ فَخَشِيتُ أَنْ تَطَأَ يَحْيَى فَقُمْتُ إِلَيْهَا فَإِذَا مِثْلُ الظُّلَّةِ فَوْقَ رَأْسِي فِيهَا أَمْثَالُ السُّرُجِ عَرَجَتْ فِي الْجَوِّ حَتَّى مَا أَرَاهَا قَالَ فَغَدَوْتُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ بَيْنَمَا أَنَا الْبَارِحَةَ مِنْ جَوْفِ اللَّيْلِ أَقْرَأُ فِي مِرْبَدِي إِذْ جَالَتْ فَرَسِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ ابْنَ حُضَيْرٍ قَالَ فَقَرَأْتُ ثُمَّ جَالَتْ أَيْضًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ ابْنَ حُضَيْرٍ قَالَ فَقَرَأْتُ ثُمَّ جَالَتْ أَيْضًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ ابْنَ حُضَيْرٍ قَالَ فَانْصَرَفْتُ وَكَانَ يَحْيَى قَرِيبًا مِنْهَا خَشِيتُ أَنْ تَطَأَهُ فَرَأَيْتُ مِثْلَ الظُّلَّةِ فِيهَا أَمْثَالُ السُّرُجِ عَرَجَتْ فِي الْجَوِّ حَتَّى مَا أَرَاهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تِلْكَ الْمَلَائِكَةُ كَانَتْ تَسْتَمِعُ لَكَ وَلَوْ قَرَأْتَ لَأَصْبَحَتْ يَرَاهَا النَّاسُ مَا تَسْتَتِرُ مِنْهُمْ","id":"Dan telah menceritakan kepadaku [Hasan bin Ali Al Hulwani] dan [Hajjaj bin Asy Sya'ir] -kedua lafazhnya hampir sama- keduanya berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Yazid bin Al Hadi] bahwa [Abdullah bin Khabbab] telah menceritakan kepadanya bahwa [Abu Sa'id Al Khudri] telah menceritakan kepadanya bahwasanya; Pada suatu malam, Usaid bin Hudlair membaca (surat Al Kahfi) di tempat penambatan kudanya. Tiba-tiba kudanya meloncat, ia membaca lagi, dan kuda itupun meloncat lagi. Kemudian ia membaca lagi, dan kuda itu meloncat kembali. Usaid berkata, \"Saya khawatir kuda itu akan menginjak Yahya, maka aku pun berdiri ke arahnya. Ternyata (aku melihat) sepertinya ada Zhullah (sesuatu yang menaungi) di atas kepalaku, di dalamnya terdapat cahaya yang menjulang ke angkasa hingga aku tidak lagi melihatnya. Maka pada pagi harinya, aku menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, semalam saya membaca (Al Qur`an) di tempat penambatan kudaku namun tiba-tiba kudaku meloncat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah wahai Ibnu Hudlair.\" Kemudian aku pun membacanya lagi, dan kuda itu juga meloncat kembali. Beliau bersabda: \"Bacalah wahai Ibnu Hudlair.\" Kemudian aku pun membacanya lagi, dan kuda itu juga meloncat kembali. Beliau bersabda lagi, \"Bacalah wahai Ibnu Hudlair.\" Ibnu Hudlair berkata; Maka sesudah itu, akhirnya saya beranjak. Saat itu Yahya dekat dengan kuda, maka saya khawatir kuda itu akan menginjaknya. Kemudian saya melihat sesuatu seperti Zhullah (sesuatu yang menaungi) yang di dalamnya terdapat cahaya yang naik ke atas angkasa hingga saya tidak lagi melihatnya. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Itu adalah Malaikat yang sedang menyimak bacaanmu, sekiranya kamu terus membaca, niscaya pada pagi harinya manusia akan melihatnya dan Malaikat itu tidak bisa menutup diri dari pandangan mereka.\""},"1247":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو كَامِلٍ الْجَحْدَرِيُّ كِلَاهُمَا عَنْ أَبِي عَوَانَةَ قَالَ قُتَيْبَةُ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَثَلُ الْمُؤْمِنِ الَّذِي يَقْرَأُ الْقُرْآنَ مَثَلُ الْأُتْرُجَّةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا طَيِّبٌ وَمَثَلُ الْمُؤْمِنِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ مَثَلُ التَّمْرَةِ لَا رِيحَ لَهَا وَطَعْمُهَا حُلْوٌ وَمَثَلُ الْمُنَافِقِ الَّذِي يَقْرَأُ الْقُرْآنَ مَثَلُ الرَّيْحَانَةِ رِيحُهَا طَيِّبٌ وَطَعْمُهَا مُرٌّ وَمَثَلُ الْمُنَافِقِ الَّذِي لَا يَقْرَأُ الْقُرْآنَ كَمَثَلِ الْحَنْظَلَةِ لَيْسَ لَهَا رِيحٌ وَطَعْمُهَا مُرٌّو حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ كِلَاهُمَا عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّ فِي حَدِيثِ هَمَّامٍ بَدَلَ الْمُنَافِقِ الْفَاجِرِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Kamil Al Jahdari] keduanya dari [Abu 'Awanah] -Qutaibah- berkata telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] dari [Abu Musa Al Asy'ari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perumpamaan orang mukmin yang membaca Al Qur`an adalah seperti buah Utrujah, baunya harum dan rasanya juga enak. Dan perumpamaan orang mukmin yang tidak membaca Al Qur`an adalah seperti buah kurma, baunya tidak semerbak, namun rasanya manis. Sedangkan perumpamaan orang munafik yang membaca Al Qur`an adalah laksana buah Raihanah yang baunya harum namun rasanya pahit. Dan perumpamaan orang munafik yang tidak membaca Al Qur`an adalah seperti buah Hanzhalah, baunya tidak wangi dan rasanya juga pahit.\" Dan telah menceritakan kepada kami [Haddab bin Khalid] telah menceritakan kepada kami [Hammam] -dan dalam jalur lain- telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] keduanya dari [Qatadah] dengan isnad ini semisalnya. Hanya saja di dalam hadits Hammam, kata munafik ia ganti dengan Fajir (orang yang berdosa)."},"1248":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ جَمِيعًا عَنْ أَبِي عَوَانَةَ قَالَ ابْنُ عُبَيْدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَاهِرُ بِالْقُرْآنِ مَعَ السَّفَرَةِ الْكِرَامِ الْبَرَرَةِ وَالَّذِي يَقْرَأُ الْقُرْآنَ وَيَتَتَعْتَعُ فِيهِ وَهُوَ عَلَيْهِ شَاقٌّ لَهُ أَجْرَانِو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ كِلَاهُمَا عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ و قَالَ فِي حَدِيثِ وَكِيعٍ وَالَّذِي يَقْرَأُ وَهُوَ يَشْتَدُّ عَلَيْهِ لَهُ أَجْرَانِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin Ubaid Al Ghubari] semuanya dari [Abu 'Awanah] - [Ibnu Ubaid] - berkata, telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Zurarah bin Aufa] dari [Sa'd bin Hisyam] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang mukmin yang mahir membaca Al Qur`an, maka kedudukannya di akhirat ditemani oleh para malaikat yang mulia. Dan orang yang membaca Al Qur`an dengan gagap, ia sulit dalam membacanya, maka ia mendapat dua pahala.\" Dalam jalur lain; telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Sa'id] dan diganti dengan jalur periwayatan lain, dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Hisyam Ad Dastawa`i] keduanya dari [Qatadah] dengan isnad ini. Dan ia berkata dalam haditsnya Waki'; \"Dan orang yang membaca Al Qur`an sedang ia kesulitan dalam membacanya, maka baginya dua pahala.\""},"1249":{"ar":"حَدَّثَنَا هَدَّابُ بْنُ خَالِدٍ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأُبَيٍّ إِنَّ اللَّهَ أَمَرَنِي أَنْ أَقْرَأَ عَلَيْكَ قَالَ آللَّهُ سَمَّانِي لَكَ قَالَ اللَّهُ سَمَّاكَ لِي قَالَ فَجَعَلَ أُبَيٌّ يَبْكِي","id":"Telah menceritakan kepada kami [Haddab bin Khalid] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ubay: \"Sesungguhnya Allah telah memerintahkan kepadaku untuk membacakan kepadamu.\" Ubay bertanya, \"Apakah Allah menyebut namaku kepada Anda?\" beliau menjawab: \"Ya, Allah menyebut namamu kepadaku.\" Maka Ubay pun menangis karenanya."},"1250":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُبَيِّ بْنِ كَعْبٍ إِنَّ اللَّهَ أَمَرَنِي أَنْ أَقْرَأَ عَلَيْكَ لَمْ يَكُنْ الَّذِينَ كَفَرُوا قَالَ وَسَمَّانِي لَكَ قَالَ نَعَمْ قَالَ فَبَكَىحَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ أَنَسًا يَقُولُا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأُبَيٍّ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Qatadah] menceritakan dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ubay bin Ka'ab: \"Allah memerintahkan kepadaku untuk membacakan kepadamu, 'LAM YAKUNILLADZIINA KAFARUU..' (surat Al Bayyinah).\" Ubay bertanya, \"Apakah Allah menyebut namaku kepada Anda?\" beliau menjawab: \"Ya.\" Maka Ubay pun menangis karenanya. Telah menceritakan kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid] yakni Ibnul Harits, telah menceritakan kepada kami [Syu'bah] dari [Qatadah] ia berkata, saya mendengar [Anas] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada Ubay. Dengan hadits semisalnya."},"1251":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ جَمِيعًا عَنْ حَفْصٍ قَالَ أَبُو بَكْرٍ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبِيدَةَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ عَلَيَّ الْقُرْآنَ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أَشْتَهِي أَنْ أَسْمَعَهُ مِنْ غَيْرِي فَقَرَأْتُ النِّسَاءَ حَتَّى إِذَا بَلَغْتُ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }رَفَعْتُ رَأْسِي أَوْ غَمَزَنِي رَجُلٌ إِلَى جَنْبِي فَرَفَعْتُ رَأْسِي فَرَأَيْتُ دُمُوعَهُ تَسِيلُحَدَّثَنَا هَنَّادُ بْنُ السَّرِيِّ وَمِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ جَمِيعًا عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ وَزَادَ هَنَّادٌ فِي رِوَايَتِهِ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ اقْرَأْ عَلَيَّ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] semuanya dari [Hafsh] -[Abu Bakr]- berkata, telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari [Abidah] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Bacakanlah Al Qur`an kepadaku.\" Abdullah berkata; saya bertanya, \"Wahai Rasulullah, apakah saya membacakannya kepada Anda, sementara Al Qur`an diturunkan kepada Anda?\" beliau bersabda: \"Saya suka untuk mendengarnya dari orang lain.\" Maka saya pun membaca surat An Nisa`, hingga (bacaanku) sampai pada ayat: \"Dan kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu).\" Aku mengangkat kepalaku -atau- seorang laki-laki datang ke sampingku, dan aku pun mengangkat kepala, maka aku melihat air mata beliau menetes. Telah menceritakan kepada kami [Hannad bin As Sariy] dan [Mindab bin Harits At Tamimi] semuanya dari [Ali bin Mushir] dari [Al A'masy] dengan isnad ini. Hannad menambahkan dalam riwayatnya; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku sementara beliau berada di atas mimbar: \"Bacakanlah (Al Qur`an) untukku.\""},"1252":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ حَدَّثَنِي مِسْعَرٌ وَقَالَ أَبُو كُرَيْبٍ عَنْ مِسْعَرٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ إِبْرَاهِيمَ قَالَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِعَبْدِ اللَّهِ بْنِ مَسْعُودٍ اقْرَأْ عَلَيَّ قَالَ أَقْرَأُ عَلَيْكَ وَعَلَيْكَ أُنْزِلَ قَالَ إِنِّي أُحِبُّ أَنْ أَسْمَعَهُ مِنْ غَيْرِي قَالَ فَقَرَأَ عَلَيْهِ مِنْ أَوَّلِ سُورَةِ النِّسَاءِ إِلَى قَوْلِهِ{ فَكَيْفَ إِذَا جِئْنَا مِنْ كُلِّ أُمَّةٍ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَى هَؤُلَاءِ شَهِيدًا }فَبَكَىقَالَ مِسْعَرٌ فَحَدَّثَنِي مَعْنٌ عَنْ جَعْفَرِ بْنِ عَمْرِو بْنِ حُرَيْثٍ عَنْ أَبِيهِ عَنْ ابْنِ مَسْعُودٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَهِيدًا عَلَيْهِمْ مَا دُمْتُ فِيهِمْ أَوْ مَا كُنْتُ فِيهِمْ شَكَّ مِسْعَرٌ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] telah menceritakan kepadaku [Mis'ar] - [Abu Kuraib] - berkata, dari [Mis'ari] dari [Amru bin Murrah] dari [Ibrahim] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepada [Abdullah bin Mas'ud]: \"Bacakanlah Al Qur`an kepadaku.\" Abdullah bertanya, \"Apakah saya akan membacakannya kepada Anda, sementara Al Qur`an diturunkan kepada Anda?\" beliau bersabda: \"Saya suka untuk mendengarnya dari orang lain.\" Maka Abdullah bin Mas'ud pun membaca ayat pertama surat An Nisa` hingga ayat: \"Maka bagaimanakah (halnya orang kafir nanti), apabila kami mendatangkan seseorang saksi (rasul) dari tiap-tiap umat dan kami mendatangkan kamu (Muhammad) sebagai saksi atas mereka itu (sebagai umatmu).\" Maka beliau pun menangis. [Mis'ar] berkata; telah menceritakan kepadaku [Ma'n] dari [Ja'far bin Amru bin Huraits] dari [bapaknya] dari [Ibnu Mas'ud] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda kepada: \"(Saya) menjadi saksi, selama aku hidup di tengah-tengah mereka. -atau- selama aku masih berada di tengah-tengah mereka.\" Mis'ar ragu (diantara dua pernyataan tersebut)."},"1253":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ كُنْتُ بِحِمْصَ فَقَالَ لِي بَعْضُ الْقَوْمِ اقْرَأْ عَلَيْنَا فَقَرَأْتُ عَلَيْهِمْ سُورَةَ يُوسُفَ قَالَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ وَاللَّهِ مَا هَكَذَا أُنْزِلَتْ قَالَقُلْتُ وَيْحَكَ وَاللَّهِ لَقَدْ قَرَأْتُهَا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي أَحْسَنْتَفَبَيْنَمَا أَنَا أُكَلِّمُهُ إِذْ وَجَدْتُ مِنْهُ رِيحَ الْخَمْرِ قَالَ فَقُلْتُ أَتَشْرَبُ الْخَمْرَ وَتُكَذِّبُ بِالْكِتَابِ لَا تَبْرَحُ حَتَّى أَجْلِدَكَ قَالَ فَجَلَدْتُهُ الْحَدَّ و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ جَمِيعًا عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ وَلَيْسَ فِي حَدِيثِ أَبِي مُعَاوِيَةَ فَقَالَ لِي أَحْسَنْتَ","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dari [Abdullah] ia berkata; Saya berada di Himsh, lalu salah seorang dari suatu kaum berkata kepadaku, \"Bacakanlah Al Qur`an kepada kami.\" Maka aku pun membacakan surat Yusuf kepada mereka. Lalu salah seorang dari mereka berkata, \"Demi Allah, tidaklah seperti itu (bacaannya) ayat ini diturunkan. Abdullah berkata; Saya berkata, \"Celaka kamu, demi Allah, sungguh, saya telah membacakannya kepada Rasulullah shallallahu 'alaihi wasallam lalu beliau bersabda kepadaku: 'Kamu telah membacanya dengan benar.'\" Di tengah-tengah pembicaraanku, saya mencium aroma khamer darinya, maka saya pun bertanya, \"Apakah kamu meminum khamer lalu mendustakan kitab? Kamu tidak boleh meninggalkan tempat ini hingga saya menderamu.\" Akhirnya aku pun menegakkan had atasnya. Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Khasyram] keduanya berkata, telah mengabarkan kepada kami [Isa bin Yunus] -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Mu'awiyah] semuanya dari [Al A'masy] dengan isnad ini, dan di dalam hadits Mu'awiyah tidak tercantum; \"Lalu beliau bersabda kepadaku: 'AHSANTA (kamu telah membacanya dengan benar).'\""},"1254":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو سَعِيدٍ الْأَشَجُّ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُحِبُّ أَحَدُكُمْ إِذَا رَجَعَ إِلَى أَهْلِهِ أَنْ يَجِدَ فِيهِ ثَلَاثَ خَلِفَاتٍ عِظَامٍ سِمَانٍ قُلْنَا نَعَمْ قَالَ فَثَلَاثُ آيَاتٍ يَقْرَأُ بِهِنَّ أَحَدُكُمْ فِي صَلَاتِهِ خَيْرٌ لَهُ مِنْ ثَلَاثِ خَلِفَاتٍ عِظَامٍ سِمَانٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Sa'id Al Asyaj] keduanya berkata, telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah salah seorang dari kalian suka, bila ia kembali kepada isterinya akan mendapatkan tiga ekor unta yang sedang bunting lagi gemuk-gemuk?\" kami menjawab, \"Ya.\" Beliau bersabda: \"Tiga ayat yang dibaca oleh salah seorang dari kalian di dalam shalatnya adalah lebih baik daripada ketiga ekor unta yang bunting dan gemuk itu.\""},"1255":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا الْفَضْلُ بْنُ دُكَيْنٍ عَنْ مُوسَى بْنِ عُلَيٍّ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ فِي الصُّفَّةِ فَقَالَ أَيُّكُمْ يُحِبُّ أَنْ يَغْدُوَ كُلَّ يَوْمٍ إِلَى بُطْحَانَ أَوْ إِلَى الْعَقِيقِ فَيَأْتِيَ مِنْهُ بِنَاقَتَيْنِ كَوْمَاوَيْنِ فِي غَيْرِ إِثْمٍ وَلَا قَطْعِ رَحِمٍ فَقُلْنَا يَا رَسُولَ اللَّهِ نُحِبُّ ذَلِكَ قَالَ أَفَلَا يَغْدُو أَحَدُكُمْ إِلَى الْمَسْجِدِ فَيَعْلَمُ أَوْ يَقْرَأُ آيَتَيْنِ مِنْ كِتَابِ اللَّهِ عَزَّ وَجَلَّ خَيْرٌ لَهُ مِنْ نَاقَتَيْنِ وَثَلَاثٌ خَيْرٌ لَهُ مِنْ ثَلَاثٍ وَأَرْبَعٌ خَيْرٌ لَهُ مِنْ أَرْبَعٍ وَمِنْ أَعْدَادِهِنَّ مِنْ الْإِبِلِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Al Fadlu bin Dukain] dari [Musa bin Ulay] ia berkata, saya mendengar [bapakku] menceritakan dari [Uqbah bin Amir] ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar sementara kami sedang berada di Shuffah (tempat berteduhnya para Fuqara dari kalangan muhajirin), kemudian beliau bertanya: \"Siapakah di antara kalian yang suka pergi ke Buthhan atau ke Aqiq, lalu ia pulang dengan membawa dua ekor unta yang gemuk-gemuk dengan tanpa membawa dosa dan tidak pula memutuskan silaturahmi?\" Maka kami pun menjawab, \"Kami semua menyukai hal itu.\" beliau melanjutkan sabdanya: \"Sungguh, salah seorang dari kalian pergi ke masjid lalu ia mempelajari atau membaca dua ayat dari kitabullah 'azza wajalla adalah lebih baik baginya daripada dua unta. Tiga (ayat) lebih baik dari tiga ekot unta, empat ayat lebih baik daripada empat ekor unta. Dan berapa pun jumlah unta.\""},"1256":{"ar":"حَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ وَهُوَ الرَّبِيعُ بْنُ نَافِعٍ حَدَّثَنَا مُعَاوِيَةُ يَعْنِي ابْنَ سَلَّامٍ عَنْ زَيْدٍ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ يَقُولُ حَدَّثَنِي أَبُو أُمَامَةَ الْبَاهِلِيُّ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ اقْرَءُوا الْقُرْآنَ فَإِنَّهُ يَأْتِي يَوْمَ الْقِيَامَةِ شَفِيعًا لِأَصْحَابِهِ اقْرَءُوا الزَّهْرَاوَيْنِ الْبَقَرَةَ وَسُورَةَ آلِ عِمْرَانَ فَإِنَّهُمَا تَأْتِيَانِ يَوْمَ الْقِيَامَةِ كَأَنَّهُمَا غَمَامَتَانِ أَوْ كَأَنَّهُمَا غَيَايَتَانِ أَوْ كَأَنَّهُمَا فِرْقَانِ مِنْ طَيْرٍ صَوَافَّ تُحَاجَّانِ عَنْ أَصْحَابِهِمَا اقْرَءُوا سُورَةَ الْبَقَرَةِ فَإِنَّ أَخْذَهَا بَرَكَةٌ وَتَرْكَهَا حَسْرَةٌ وَلَا تَسْتَطِيعُهَا الْبَطَلَةُقَالَ مُعَاوِيَةُ بَلَغَنِي أَنَّ الْبَطَلَةَ السَّحَرَةُ و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى يَعْنِي ابْنَ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ بِهَذَا الْإِسْنَادِ مِثْلَهُ غَيْرَ أَنَّهُ قَالَ وَكَأَنَّهُمَا فِي كِلَيْهِمَا وَلَمْ يَذْكُرْ قَوْلَ مُعَاوِيَةَ بَلَغَنِي","id":"Telah menceritakan kepadaku [Al Hasan bin Ali Al Hulwani] telah menceritakan kepada kami [Abu Taubah] ia adalah Ar Rabi' bin Nafi', telah menceritakan kepada kami [Mu'awiyah] yakni Ibnu Sallam, dari [Zaid] bahwa ia mendengar [Abu Sallam] berkata, telah menceritakan kepadaku [Abu Umamah Al Bahili] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bacalah Al Qur`an, karena ia akan datang memberi syafa'at kepada para pembacanya pada hari kiamat nanti. Bacalah Zahrawain, yakni surat Al Baqarah dan Ali Imran, karena keduanya akan datang pada hari kiamat nanti, seperti dua tumpuk awan menaungi pembacanya, atau seperti dua kelompok burung yang sedang terbang dalam formasi hendak membela pembacanya. Bacalah Al Baqarah, karena dengan membacanya akan memperoleh barokah, dan dengan tidak membacanya akan menyebabkan penyesalan, dan pembacanya tidak dapat dikuasai (dikalahkan) oleh tukang-tukang sihir.\" Mu'awiyah berkata; \"Telah sampai (khabar) kepadaku bahwa, Al Bathalah adalah tukang-tukang sihir.\" Dan telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Yahya] yakni Ibnu Hassan, Telah menceritakan kepada kami [Mu'awiyah] dengan isnad ini, hanya saja ia mentatakan; \"Wa Ka`annahumaa fii Kilaihimaa.\" dan ia tidak menyebutkan ungkapan Mu'awiyah, \"Telah sampai (khabar) padaku.\""},"1257":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ أَخْبَرَنَا يَزِيدُ بْنُ عَبْدِ رَبِّهِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ مُهَاجِرٍ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ قَالَ سَمِعْتُ النَّوَّاسَ بْنَ سَمْعَانَ الْكِلَابِيَّ يَقُولُاسَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يُؤْتَى بِالْقُرْآنِ يَوْمَ الْقِيَامَةِ وَأَهْلِهِ الَّذِينَ كَانُوا يَعْمَلُونَ بِهِ تَقْدُمُهُ سُورَةُ الْبَقَرَةِ وَآلُ عِمْرَانَ وَضَرَبَ لَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةَ أَمْثَالٍ مَا نَسِيتُهُنَّ بَعْدُ قَالَ كَأَنَّهُمَا غَمَامَتَانِ أَوْ ظُلَّتَانِ سَوْدَاوَانِ بَيْنَهُمَا شَرْقٌ أَوْ كَأَنَّهُمَا حِزْقَانِ مِنْ طَيْرٍ صَوَافَّ تُحَاجَّانِ عَنْ صَاحِبِهِمَا","id":"Telah menceritakan kepada kami [Ishaq bin Manshur] telah mengabarkan kepada kami [Yazid bin Abdu Rabbih] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Muhammad bin Muhajir] dari [Al Walid bin Abdurrahman Al Jurasyi] dari [Jubair bin Nufair] ia berkata, saya mendengar [An Nawwas bin Sam'an Al Kilabi] berkata; Saya mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Al Qur`an akan didatangkan pada hari kiamat bersama Ahlinya yang telah beramal dengannya, dan yang pertama kali adalah surat Al Baqarah dan Ali Imran.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan tiga permisalan terkait dengan keduanya, aku tidak akan melupakannya setelah itu. yakni: \"Seperti dua tumpuk awan hitam yang diantara keduanya terdapat cahaya, atau seperti dua kelompok burung yang sedang terbang dalam formasi hendak membela pembacanya.\""},"1258":{"ar":"حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ وَأَحْمَدُ بْنُ جَوَّاسٍ الْحَنْفِيُّ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ عَمَّارِ بْنِ رُزَيْقٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَبَيْنَمَا جِبْرِيلُ قَاعِدٌ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَمِعَ نَقِيضًا مِنْ فَوْقِهِ فَرَفَعَ رَأْسَهُ فَقَالَ هَذَا بَابٌ مِنْ السَّمَاءِ فُتِحَ الْيَوْمَ لَمْ يُفْتَحْ قَطُّ إِلَّا الْيَوْمَ فَنَزَلَ مِنْهُ مَلَكٌ فَقَالَ هَذَا مَلَكٌ نَزَلَ إِلَى الْأَرْضِ لَمْ يَنْزِلْ قَطُّ إِلَّا الْيَوْمَ فَسَلَّمَ وَقَالَ أَبْشِرْ بِنُورَيْنِ أُوتِيتَهُمَا لَمْ يُؤْتَهُمَا نَبِيٌّ قَبْلَكَ فَاتِحَةُ الْكِتَابِ وَخَوَاتِيمُ سُورَةِ الْبَقَرَةِ لَنْ تَقْرَأَ بِحَرْفٍ مِنْهُمَا إِلَّا أُعْطِيتَهُ","id":"Telah menceritakan kepada kami [Hasan bin Rabi'] dan [Ahmad bin Jawwas Al Hanfi] keduanya berkata, telah menceritakan kepada kami [Abul Ahwash] dari [Ammar bin Ruzaiq] dari [Abdullah bin Isa] dari [Sa'id bin Jubair] dari [Ibnu Abbas] ia berkata; Ketika malaikat Jibril sedang duduk di samping Nabi shallallahu 'alaihi wasallam tiba-tiba ia mendengar suara pintu dibuka dari arah atas kepalanya. Lalu malaikat Jibril berkata: \"Itu adalah suara salah satu pintu langit yang dibuka, sebelumnya ia belum pernah dibuka sama sekali kecuali pada hari ini.\" Lalu keluarlah daripadanya malaikat. Jibril berkata: \"Ini adalah malaikat yang hendak turun ke bumi, sebelumnya ia belum pernah turun ke bumi sama sekali kecuali pada hari ini saja.\" Lalu ia memberi salam dan berkata: \"Bergembiralah atas dua cahaya yang diberikan kepadamu dan belum pernah diberikan kepada seorang Nabipun sebelummu, yaitu pembuka Al Kitab (surat Al Fatihah) dan penutup surat Al Baqarah. Tidaklah kamu membaca satu huruf dari kedua surat itu kecuali pasti akan diberikan kepadamu.\""},"1259":{"ar":"و حَدَّثَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ لَقِيتُ أَبَا مَسْعُودٍ عِنْدَ الْبَيْتِفَقُلْتُ حَدِيثٌ بَلَغَنِي عَنْكَ فِي الْآيَتَيْنِ فِي سُورَةِ الْبَقَرَةِ فَقَالَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْآيَتَانِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ مَنْ قَرَأَهُمَا فِي لَيْلَةٍ كَفَتَاهُو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ كِلَاهُمَا عَنْ مَنْصُورٍ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Manshur] dari [Ibrahim] dari [Abdurrahman bin Yazid] ia berkata; Saya menjumpai [Abu Mas'ud] di Baitullah, maka saya pun berkata, \"Ada satu hadits dari Anda yang telah sampai kepadaku tentang dua ayat yang terdapat di dalam surat Al Baqarah.\" Abu Mas'ud berkata; Ya, Rasulullah shallallahu 'alaihi wasallam telah bersabda: \"Siapa yang membaca kedua ayat itu, yakni akhir dari surat Al Baqarah, niscaya keduanya akan memeliharanya dari bencana.\" Dan telah menceritakannya kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] keduanya dari [Manshur] dengan isnad ini."},"1260":{"ar":"و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ أَخْبَرَنَا ابْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَلْقَمَةَ بْنِ قَيْسٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَرَأَ هَاتَيْنِ الْآيَتَيْنِ مِنْ آخِرِ سُورَةِ الْبَقَرَةِ فِي لَيْلَةٍ كَفَتَاهُقَالَ عَبْدُ الرَّحْمَنِ فَلَقِيتُ أَبَا مَسْعُودٍ وَهُوَ يَطُوفُ بِالْبَيْتِ فَسَأَلْتُهُ فَحَدَّثَنِي بِهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ و حَدَّثَنِي عَلِيُّ بْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى يَعْنِي ابْنَ يُونُسَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ جَمِيعًا عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصٌ وَأَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ أَبِي مَسْعُودٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Minjab bin Harits At Tamimi] telah mengabarkan kepada kami [Ibnu Mushir] dari [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Alqamah bin Qais] dari [Abu Mas'ud Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang membaca dua ayat ini, yakni dari akhir surat Al Baqarah di suatu malam, maka keduanya akan menjaganya dari bencana.\" Abdurrahman berkata; Saya menjumpai Abu Mas'ud yang sedang melakukan thawaf di Baitullah, maka saya bertanya kepadanya. Maka ia pun menceritakannya kepadaku dari Nabi shallallahu 'alaihi wasallam. Dan telah menceritakan kepadaku [Ali bin Khasyram] telah mengabarkan kepada kami [Isa] yakni Ibnu Yunus. -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] semuanya dari [Al A'masy] dari [Ibrahim] dari [Alqamah] dan [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam semisalnya. -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Hafsh] dan [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Abdurrahman bin Yazid] dari [Abu Mas'ud] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1261":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ الْغَطَفَانِيِّ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمَرِيِّ عَنْ أَبِي الدَّرْدَاءِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَفِظَ عَشْرَ آيَاتٍ مِنْ أَوَّلِ سُورَةِ الْكَهْف عُصِمَ مِنْ الدَّجَّالِو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا هَمَّامٌ جَمِيعًا عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ قَالَ شُعْبَةُ مِنْ آخِرِ الْكَهْفِ و قَالَ هَمَّامٌ مِنْ أَوَّلِ الْكَهْف كَمَا قَالَ هِشَامٌ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Salim bin Abul Ja'd Al Ghathafani] dari [Ma'dan bin Abu Thalhah Al Ya'mari] dari [Abu Darda`] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Siapa yang menghafal sepuluh ayat dari awal surat Al Kahfi, maka ia akan terpelihara dari (kejahatan) Dajjall.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] -dalam jalur lain- Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Hammam] semuanya dari [Qatadah] dengan isnad ini. Syu'bah berkata; \"Dari akhir surat Al Kahfi.\" Hammam berkata; \"Dari awal surat Al Kahfi.\" Sebagaimana yang dikatakan Hisyam."},"1262":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ أَبِي السَّلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ الْأَنْصَارِيِّ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَقَالَ رَسُولُ اللَّهِ يَا أَبَا الْمُنْذِرِ أَتَدْرِي أَيُّ آيَةٍ مِنْ كِتَابِ اللَّهِ مَعَكَ أَعْظَمُ قَالَ قُلْتُ اللَّهُ وَرَسُولُهُ أَعْلَمُ قَالَ يَا أَبَا الْمُنْذِرِ أَتَدْرِي أَيُّ آيَةٍ مِنْ كِتَابِ اللَّهِ مَعَكَ أَعْظَمُ قَالَ قُلْتُ{ اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ }قَالَ فَضَرَبَ فِي صَدْرِي وَقَالَ وَاللَّهِ لِيَهْنِكَ الْعِلْمُ أَبَا الْمُنْذِرِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] dari [Al Jurairi] dari [Abu As Salil] dari [Abdullah bin Rabah Al Anshari] dari [Ubay bin Ka'ab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hai Abu Mundzir! tahukah kamu, ayat manakah di antara ayat-ayat Al Qur`an yang ada padamu yang paling utama?\" Abu Mundzir berkata; saya menjawab, \"Allah dan Rasul-Nya yang lebih mengetahui.\" Beliau bertanya lagi: \"Hai Abu Mundzir, tahukah kamu, ayat manakah di antara ayat-ayat Al Qur`an yang ada padamu yang paling utama?\" Abu Mundzir berkata; Saya menjawab, \"ALLAHU LAA ILAAHA ILLAA HUWAL HAYYUL QAYYUUM.\" Abu Mundzir berkata; lalu beliau menepuk dadaku seraya bersabda: \"Demi Allah, semoga dadamu dipenuhi dengan ilmu, wahai Abu Mundzir.\""},"1263":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَ زُهَيْرٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الدَّرْدَاءِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيَعْجِزُ أَحَدُكُمْ أَنْ يَقْرَأَ فِي لَيْلَةٍ ثُلُثَ الْقُرْآنِ قَالُوا وَكَيْفَ يَقْرَأْ ثُلُثَ الْقُرْآنِ قَالَ قُلْ هُوَ اللَّهُ أَحَدٌ تَعْدِلُ ثُلُثَ الْقُرْآنِو حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ الْعَطَّارُ جَمِيعًا عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِهِمَا مِنْ قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ جَزَّأَ الْقُرْآنَ ثَلَاثَةَ أَجْزَاءٍ فَجَعَلَ قُلْ هُوَ اللَّهُ أَحَدٌ جُزْءًا مِنْ أَجْزَاءِ الْقُرْآنِ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] dan [Muhammad bin Basysyar] - [Zuhair] berkata- telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Qatadah] dari [Salim bin Abul Ja'd] dari [Ma'dan bin Abu Thalhah] dari [Abu Darda`] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak sanggupkah salah seorang dari kalian membaca sepertiga Al Qur`an dalam semalam?\" Mereka balik bertanya, \"Bagaimana cara membaca sepertiganya?\" Nabi shallallahu 'alaihi wasallam menjawab: \"'QUL HUWALLAHU AHAD' (surat Al Ikhlash) sama dengan sepertiga Al Qur`an.\" Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Muhammad bin Bakr] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Aban Al Aththar] semuanya dari [Qatadah] dengan isnad ini. Dan di dalam hadits keduanya adalah dari sabda Nabi shallallahu 'alaihi wasallam: \"Sesungguhnya Allah 'azza wajalla menjadikan Al Qur`an itu tiga bagian. Lalu Dia menjadikan, 'QUL HUWALLAHU AHAD.' Sebagai satu bagian dari bagian-bagian Al Qur`an.\""},"1264":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ وَيَعْقُوبُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ يَحْيَى قَالَ ابْنُ حَاتِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ حَدَّثَنَا يَزِيدُ بْنُ كَيْسَانَ حَدَّثَنَا أَبُو حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْشُدُوا فَإِنِّي سَأَقْرَأُ عَلَيْكُمْ ثُلُثَ الْقُرْآنِ فَحَشَدَ مَنْ حَشَدَ ثُمَّ خَرَجَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ ثُمَّ دَخَلَ فَقَالَ بَعْضُنَا لِبَعْضٍ إِنِّي أُرَى هَذَا خَبَرٌ جَاءَهُ مِنْ السَّمَاءِ فَذَاكَ الَّذِي أَدْخَلَهُ ثُمَّ خَرَجَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي قُلْتُ لَكُمْ سَأَقْرَأُ عَلَيْكُمْ ثُلُثَ الْقُرْآنِ أَلَا إِنَّهَا تَعْدِلُ ثُلُثَ الْقُرْآنِ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] dan [Ya'qub bin Ibrahim] semuanya dari [Yahya] - [Ibnu Hatim] - berkata; telah menceritakan kepada kami [Yahya bin Sa'id] telah menceritakan kepada kami [Yazid bin Kaisan] telah menceritakan kepada kami [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berkumpullah kamu semuanya, karena aku akan membacakan kepada kalian sepertiga Al Qur`an.\" Maka berkumpullah kami, yang sempat berkumpul, kemudian Nabi shallallahu 'alaihi wasallam keluar dan membaca: \"QUL HUWALLAHU AHAD.\" Setelah itu, beliau masuk kembali. Maka kami saling berkata satu sama lain.\"Aku mengira bahwa wahyu ini baru diturunkan dari langit, sehingga Nabi shallallahu 'alaihi wasallam segera masuk ke dalam kamarnya.\" Tak berapa lama kemudian Nabi shallallahu 'alaihi wasallam keluar seraya bersabda: \"Tadi aku berjanji akan membacakan sepertiga Al Qur`an kepada kalian. Ketahuilah bahwa, 'QUL HUWALLAHU AHAD' adalah sama nilainya dengan sepertiga Al Qur`an.\""},"1265":{"ar":"و حَدَّثَنَا وَاصِلُ بْنُ عَبْدِ الْأَعْلَى حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ بَشِيرٍ أَبِي إِسْمَعِيلَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَخَرَجَ إِلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَقْرَأُ عَلَيْكُمْ ثُلُثَ الْقُرْآنِ فَقَرَأَ قُلْ هُوَ اللَّهُ أَحَدٌ اللَّهُ الصَّمَدُ حَتَّى خَتَمَهَا","id":"Dan telah menceritakan kepada kami [Washil bin Abdul A'la] telah menceritakan kepada kami [Ibnu Fudlail] dari [Basyir bin Abu Isma'il] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam keluar dan bersa bda: \"Saya akan membacakan kepada kalian (surat yang menyamai) sepertiga Al Qur`an.\" Maka beliau pun membaca: \"QUL HUWALLAHU AHAD.\" Beliau membacanya hingga selesai."},"1266":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ بْنِ وَهْبٍ حَدَّثَنَا عَمِّي عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنَا عَمْرُو بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ أَبِي هِلَالٍ أَنَّ أَبَا الرِّجَالِ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ أُمِّهِ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ وَكَانَتْ فِي حَجْرِ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ رَجُلًا عَلَى سَرِيَّةٍ وَكَانَ يَقْرَأُ لِأَصْحَابِهِ فِي صَلَاتِهِمْ فَيَخْتِمُ بِقُلْ هُوَ اللَّهُ أَحَدٌ فَلَمَّا رَجَعُوا ذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ سَلُوهُ لِأَيِّ شَيْءٍ يَصْنَعُ ذَلِكَ فَسَأَلُوهُ فَقَالَ لِأَنَّهَا صِفَةُ الرَّحْمَنِ فَأَنَا أُحِبُّ أَنْ أَقْرَأَ بِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبِرُوهُ أَنَّ اللَّهَ يُحِبُّهُ","id":"Telah menceritakan kepada kami [Ahmad bin Abdurrahman bin Wahb] telah menceritakan kepada kami pamanku yaitu [Abdullah bin Wahb], telah menceritakan kepada kami [Amru bin Harits] dari [Sa'id bin Abu Hilal] bahwa [Abu Rijal] Muhammad bin Abdurrahman, telah menceritakan kepadanya dari ibunya [Amrah binti Abdurrahman], saat itu ia berada di rumah Aisyah, isteri Nabi shallallahu 'alaihi wasallam, dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam mengutus seorang lelaki dalam suatu sariyyah (pasukan khusus yang ditugaskan untuk operasi tertentu). Laki-laki tersebut ketika menjadi imam shalat bagi para sahabatnya selalu mengakhiri bacaan suratnya dengan \"QUL HUWALLAHU AHAD.\" Ketika mereka pulang, disampaikan berita tersebut kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Tanyakanlah kepadanya kenapa ia melakukan hal itu?\" Lalu merekapun menanyakan kepadanya. Ia menjawab, \"Karena didalamnya terdapat sifat Ar Rahman, dan aku senang untuk selalu membacanya.\" Mendengar itu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beritahukanlah kepadanya bahwa Allah Ta'ala juga mencintainya.\""},"1267":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ بَيَانٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ تَرَ آيَاتٍ أُنْزِلَتْ اللَّيْلَةَ لَمْ يُرَ مِثْلُهُنَّ قَطُّ قُلْ أَعُوذُ بِرَبِّ الْفَلَقِ وَقُلْ أَعُوذُ بِرَبِّ النَّاسِ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Bayan] dari [Qais bin Abu Hazim] dari [Uqbah bin Amir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidakkah kalian lihat beberapa ayat yang diturunkah semalam, belum ada ayat yang serupa dengannya. Yaitu; 'QUL A'UUDZU BIRABBIL FALAQ dan QUL A'UUDZU BIRABBINNAAS' (surat Al Falaq dan An Nas)."},"1268":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ عَنْ قَيْسٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُنْزِلَ أَوْ أُنْزِلَتْ عَلَيَّ آيَاتٌ لَمْ يُرَ مِثْلُهُنَّ قَطُّ الْمُعَوِّذَتَيْنِو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو أُسَامَةَ كِلَاهُمَا عَنْ إِسْمَعِيلَ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَفِي رِوَايَةِ أَبِي أُسَامَةَ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ وَكَانَ مِنْ رُفَعَاءِ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan telah menceritakan kepadaku [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [bapakku] dari [Isma'il] dari [Qais] dari [Uqbah bin Amir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku: \"Telah diturunkan kepadaku beberapa ayat yang belum pernah ada ayat yang menyerupainya. Yaitu Al Mu'awwidzatain (surat Al Falaq dan An Nas).\" Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Waki'] -dalam jalur lain- Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abu Usamah] keduanya dari [Isma'il] dengan isnad ini semisalnya. Dan dalam riwayat Abu Usamah dari Uqbah bin Amir Al Juhani. Dan ia dalah termasuk salah seorang yang 'arif dari kalangan sahabat Muhammad shallallahu 'alaihi wasallam."},"1269":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ وَزُهَيْرُ بْنُ حَرْبٍ كُلُّهُمْ عَنْ ابْنِ عُيَيْنَةَ قَالَ زُهَيْرٌ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا الزُّهْرِيُّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ الْقُرْآنَ فَهُوَ يَقُومُ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا فَهُوَ يُنْفِقُهُ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] dan [Amru An Naqid] dan [Zuhair bin Harb] semuanya dari [Ibnu Uyainah] -[Zuhair]- berkata; Telah menceritakan kepada kami [Sufyan bin Uyainah] Telah menceritakan kepada kami [Az Zuhri] dari [Salim] dari [bapaknya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh dengki kecuali pada dua hal. (Pertama) kepada seorang yang telah diberi Allah (hafalan) Al Qur`an, sehingga ia membacanya siang dan malam. (Kedua) kepada seorang yang dikaruniakan Allah harta kekayaan, lalu dibelanjakannya harta itu siang dan malam (di jalan Allah), \""},"1270":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا عَلَى اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ هَذَا الْكِتَابَ فَقَامَ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ وَرَجُلٌ آتَاهُ اللَّهُ مَالًا فَتَصَدَّقَ بِهِ آنَاءَ اللَّيْلِ وَآنَاءَ النَّهَارِ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata, telah mengabarkan kepadaku [Salim bin Abdullah bin Umar] dari [bapaknya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh dengki kecuali pada dua hal. (Pertama) kepada seorang yang telah diberi Allah (hafalan) Al Qur`an, hingga ia membacanya siang dan malam. (Kedua) kepada seorang yang dikaruniakan Allah harta kekayaan, lalu dibelanjakannya harta itu siang dan malam (di jalan Allah), \""},"1271":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مَسْعُودٍ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي وَمُحَمَّدُ بْنُ بِشْرٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ عَنْ قَيْسٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَسَدَ إِلَّا فِي اثْنَتَيْنِ رَجُلٌ آتَاهُ اللَّهُ مَالًا فَسَلَّطَهُ عَلَى هَلَكَتِهِ فِي الْحَقِّ وَرَجُلٌ آتَاهُ اللَّهُ حِكْمَةً فَهُوَ يَقْضِي بِهَا وَيُعَل��ِمُهَا","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Isma'il] dari [Qais] ia berkata, [Abdullah bin Mas'ud] berkata; -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] dan [Muhammad bin Bisyr] keduanya berkata, telah menceritakan kepada kami [Isma'il] dari [Qais] ia berkata, aku mendengar [Abdullah bin Mas'ud] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh hasad (dengki) kecuali pada dua hal. (Pertama) kepada seorang yang dikaruniakan Allah harta kekayaan, lalu ia membelanjakannya dalam kebenaran. (Dan yang kedua) kepada seorang laki-laki yang diberi Allah hikmah (ilmu), hingga ia memberi keputusan dengannya dan juga mengajarkannya.\""},"1272":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنِي أَبِي عَنْ ابْنِ شِهَابٍ عَنْ عَامِرِ بْنِ وَاثِلَةَ أَنَّ نَافِعَ بْنَ عَبْدِ الْحَارِثِ لَقِيَ عُمَرَ بِعُسْفَانَ وَكَانَ عُمَرُ يَسْتَعْمِلُهُ عَلَى مَكَّةَ فَقَالَ مَنْ اسْتَعْمَلْتَ عَلَى أَهْلِ الْوَادِي فَقَالَ ابْنَ أَبْزَى قَالَ وَمَنْ ابْنُ أَبْزَى قَالَ مَوْلًى مِنْ مَوَالِينَا قَالَ فَاسْتَخْلَفْتَ عَلَيْهِمْ مَوْلًى قَالَ إِنَّهُ قَارِئٌ لِكِتَابِ اللَّهِ عَزَّ وَجَلَّ وَإِنَّهُ عَالِمٌ بِالْفَرَائِضِقَالَ عُمَرُ أَمَا إِنَّ نَبِيَّكُمْ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ قَالَ إِنَّ اللَّهَ يَرْفَعُ بِهَذَا الْكِتَابِ أَقْوَامًا وَيَضَعُ بِهِ آخَرِينَو حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ وَأَبُو بَكْرِ بْنُ إِسْحَقَ قَالَا أَخْبَرَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي عَامِرُ بْنُ وَاثِلَةَ اللَّيْثِيُّ أَنَّ نَافِعَ بْنَ عَبْدِ الْحَارِثِ الْخُزَاعِيَّ لَقِيَ عُمَرَ بْنَ الْخَطَّابِ بِعُسْفَانَ بِمِثْلِ حَدِيثِ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ الزُّهْرِيِّ","id":"Dan telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Ya'qub bin Ibrahim] telah menceritakan kepadaku [bapakku] dari [Ibnu Syihab] dari [Amir bin Watsilah] bahwasanya; Nafi' bin Abdul Harits, pada suatu ketika bertemu dengan Khalifah [Umar] di 'Usfan. Ketika itu, Nafi' bertugas sebagai pejabat di kota Makkah. Umar bertanya kepada Nafi', \"Siapa yang Anda angkat sebagai kepala bagi penduduk Wadli?\" Nafi' menjawab, \"Ibnu Abza.\" Umar bertanya lagi, \"Siapakah itu Ibnu Abza?\" Nafi' menjawab, \"Salah seorang Maula (budak yang telah dimerdekakan) di antara beberapa Maula kami.\" Umar bertanya, \"Kenapa Maula yang diangkat?\" Nafi' menjawab, \"Karena ia adalah seorang yang pintar tentang Kitabullah dan pandai tentang ilmu fara`idl (ilmu tentang pembagian harta warisan).\" Umar berkata, \"Benar, Nabi kalian shallallahu 'alaihi wasallam telah bersabda: 'Sesungguhnya Allah akan memuliakan suatu kaum dengan kitab ini (Al Qur`an) dan menghinakan yang lain.'\" Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] dan [Abu Bakar bin Ishaq] keduanya berkata, telah mengabarkan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata, telah menceritakan kepadaku [Amir bin Watsilah Al Laitsi] bahwa Nafi' bin Abdul Harits Al Khuza'i menjumpai [Umar bin Al Khaththab] di 'Usfan. Yakni serupa dengan hadits Ibrahim bin Sa'd dari Az Zuhri."},"1273":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُاسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا فَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ اقْرَأْ فَقَرَأَ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِي اقْرَأْ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُو حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخَرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ الْقَارِيَّ أَخْبَرَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُا سَمِعْتُ هِشَامَ بْنَ حَكِيمٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَاقَ الْحَدِيثَ بِمِثْلِهِ وَزَادَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَتَصَبَّرْتُ حَتَّى سَلَّمَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ كَرِوَايَةِ يُونُسَ بِإِسْنَادِهِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Ibnu Syihab] dari [Urwah bin Zubair] dari [Abdurrahman bin Abdul Qari] ia berkata, saya mendengar [Umar bin Al Khaththab] berkata; Aku mendengar Hisyam bin Hakim bin Hizam membaca surat Al Furqan, tidak seperti bacaan (qiraat) yang pernah beliau shallallahu 'alaihi wasallam bacakan kepadaku. Karena itu hampir saja aku bertindak kasar terhadapnya. Tetapi kubiarkan saja dia hingga pergi. Namun kupegang bajunya, lalu kubawa dia ke hadapan Rasulullah shallallahu 'alaihi wasallam. Ujarku, \"Wahai Rasulullah, aku mendengar orang ini membaca surat Al Furqan tidak seperti yang Anda bacakan kepadaku, bagaimana ini?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Lepaskanlah ia, suruh ia membacanya kembali.\" Lalu Hisyam membacakan kembali seperti yang dibacanya tadi. Setelah itu, Nabi shallallahu 'alaihi wasallam bersabda: \"Memang seperti inilah ia diturunkan.\" Kemudian Nabi shallallahu 'alaihi wasallam menyuruhku pula untuk membaca. Lalu kubaca seperti bacaan yang biasa kubaca. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ya, ayat itu memang diturunkan seperti itu. Sesungguhnya Al Qur`an itu diturunkan dengan tujuh huruf (tujuh dialek bahasa). Karena itu, bacalah dengan huruf yang mudah bagi kalian.\" Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Miswar bin Makhramah] dan [Abdurrahman bin Abdul Qari] telah mengarbarkan kepadanya, bahwa keduanya telah mendengar [Umar bin Al Khaththab] berkata; Saya mendengar Hisyam bin Hakim membaca surat Al Furqan pada masa Rasulullah shallallahu 'alaihi wasallam. Ia pun menyebutkan hadits yang serupa. Dan ia menambahkan; \"Dan aku hampir saja berbuat kasar terhadapnya di saat shalat. Namun aku berusaha bersabar hingga ia mengucapkan salam.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin Humaid] keduanya berkata, telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] sebagaimana riwayat Yunus dengan Isnadnya."},"1274":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَ أَنَّ ابْنَ عَبَّاسٍ حَدَّثَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَقْرَأَنِي جِبْرِيلُ عَلَيْهِ السَّلَام عَلَى حَرْفٍ فَرَاجَعْتُهُ فَلَمْ أَزَلْ أَسْتَزِيدُهُ فَيَزِيدُنِي حَتَّى انْتَهَى إِلَى سَبْعَةِ أَحْرُفٍقَالَ ابْنُ شِهَابٍ بَلَغَنِي ��َنَّ تِلْكَ السَّبْعَةَ الْأَحْرُفَ إِنَّمَا هِيَ فِي الْأَمْرِ الَّذِي يَكُونُ وَاحِدًا لَا يَخْتَلِفُ فِي حَلَالٍ وَلَا حَرَامٍ و حَدَّثَنَاه عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku [Ubaidullah bin Abdullah bin Utbah] bahwa [Ibnu Abbas] telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mula-mula Jibril membacakan Al Qur`an padaku dengan satu huruf (bacaan dengan satu lahjah) saja. Lalu saya memohon agar ditambahkan. Maka Jibril pun menambahkannya hingga menjadi tujuh huruf (lahjah bacaan).\" Ibnu Syihab berkata; \"Telah sampai khabar kepadaku bahwa tujuh huruf itu, dalam masalah hukum adalah satu, tidak ada pertentangan di dalamnya mengenai halal dan haram.\" Dan telah menceritakannya kepada kami [Abdu bin Humaid] telah mengabarkan kepada kami [Abdur Razaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dengan Isnad ini."},"1275":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ جَدِّهِ عَنْ أُبَيِّ بْنِ كَعْبٍ قَالَكُنْتُ فِي الْمَسْجِدِ فَدَخَلَ رَجُلٌ يُصَلِّي فَقَرَأَ قِرَاءَةً أَنْكَرْتُهَا عَلَيْهِ ثُمَّ دَخَلَ آخَرُ فَقَرَأَ قِرَاءَةً سِوَى قَرَاءَةِ صَاحِبِهِ فَلَمَّا قَضَيْنَا الصَّلَاةَ دَخَلْنَا جَمِيعًا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ هَذَا قَرَأَ قِرَاءَةً أَنْكَرْتُهَا عَلَيْهِ وَدَخَلَ آخَرُ فَقَرَأَ سِوَى قِرَاءَةِ صَاحِبِهِ فَأَمَرَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَرَأَا فَحَسَّنَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَأْنَهُمَا فَسَقَطَ فِي نَفْسِي مِنْ التَّكْذِيبِ وَلَا إِذْ كُنْتُ فِي الْجَاهِلِيَّةِ فَلَمَّا رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَدْ غَشِيَنِي ضَرَبَ فِي صَدْرِي فَفِضْتُ عَرَقًا وَكَأَنَّمَا أَنْظُرُ إِلَى اللَّهِ عَزَّ وَجَلَّ فَرَقًا فَقَالَ لِي يَا أُبَيُّ أُرْسِلَ إِلَيَّ أَنْ اقْرَأْ الْقُرْآنَ عَلَى حَرْفٍ فَرَدَدْتُ إِلَيْهِ أَنْ هَوِّنْ عَلَى أُمَّتِي فَرَدَّ إِلَيَّ الثَّانِيَةَ اقْرَأْهُ عَلَى حَرْفَيْنِ فَرَدَدْتُ إِلَيْهِ أَنْ هَوِّنْ عَلَى أُمَّتِي فَرَدَّ إِلَيَّ الثَّالِثَةَ اقْرَأْهُ عَلَى سَبْعَةِ أَحْرُفٍ فَلَكَ بِكُلِّ رَدَّةٍ رَدَدْتُكَهَا مَسْأَلَةٌ تَسْأَلُنِيهَا فَقُلْتُ اللَّهُمَّ اغْفِرْ لِأُمَّتِي اللَّهُمَّ اغْفِرْ لِأُمَّتِي وَأَخَّرْتُ الثَّالِثَةَ لِيَوْمٍ يَرْغَبُ إِلَيَّ الْخَلْقُ كُلُّهُمْ حَتَّى إِبْرَاهِيمُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنِي إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عِيسَى عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى أَخْبَرَنِي أُبَيُّ بْنُ كَعْبٍ أَنَّهُ كَانَ جَالِسًا فِي الْمَسْجِدِ إِذْ دَخَلَ رَجُلٌ فَصَلَّى فَقَرَأَ قِرَاءَةً وَاقْتَصَّ الْحَدِيثَ بِمِثْلِ حَدِيثِ ابْنِ نُمَيْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Abdullah bin Isa bin Abdurrahman bin Abu Laila] dari [kakeknya] dari [Ubay bin Ka'ab] ia berkata; Suatu ketika saya sedang berada di dalam Masjid, tiba-tiba datanglah seorang laki-laki dan shalat. Lalu ia membaca (Al Qur`an) dengan dengan qiraah (bacaan) yang saya ingkari. Kemudian datanglah seorang laki-laki lain dan membaca (Al Qur`an) dengan qiraah yang lain lagi. Usai menunaikan shalat, kami semua menemui Rasulullah shallallahu 'alaihi wasallam. Ujarku, \"Sesungguhnya orang ini membaca (Al Qur`an) dengan qiraah yang saya ingkari. kemudian datanglah laki-laki lain lalu ia membaca (Al Qur`an) dengan qiraah yang lain lagi.\" Maka Rasulullah shallallahu 'alaihi wasallam pun memerintahkan keduanya untuk mengulangi bacaannya masing-masing, lalu Nabi shallallahu 'alaihi wasallam membenarkannya. Setelah itu, hilanglah prasangka dusta di dalam hatiku dan juga perasaan saat aku masih jahiliyah dulu. Maka ketika Rasulullah shallallahu 'alaihi wasallam melihat sesuatu yang telah menimpaku, beliau menepuk-nepuk dadaku, dan terbukalah bagiku suatu pengetahuan yang seakan-akan aku melihat Allah dengan penuh ketakutan. Kemudian beliau bersabda: \"Wahai Ubay, (Jibril) telah diutus kepadaku agar aku membaca Al Qur`an dengan satu huruf (lahjah bacaan) saja, maka saya pun terus mendesaknya agar memberikan keringanan atas umatku. Maka ia pun kembali kepadaku agar aku membacanya dengan dua huruf. Aku masih terus mendesaknya lagi agar memberikan keringanan atas umatku. Maka ia pun kembali lagi (dan memberikan keringanan) agar aku membacanya dengan tujuh huruf. Jibril berkata, 'Begitulah setiap kamu kembali, kuperkenankan permintaanmu.' Maka aku pun berdo'a: 'ALLAHUMMAGHFIR LI UMMATII (Ya Allah ampunilah umatku).' Dan saya mengakhirkan yang ketiga untuk suatu hari, dimana seluruh makhluk mengharap padaku, hingga Ibrahim shallallahu 'alaihi wasallam.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepadaku [Isma'il bin Abu Khalid] telah menceritakan kepadaku [Abdullah bin Isa] dari [Abdurrahman bin Abu Laila] telah mengabarkan kepadaku [Ubay bin Ka'ab] bahwa suatu ketika ia duduk di dalam masjid, tiba-tiba masuklah seorang laki-laki kemudian shalat dan membaca (Al Qur`an) dengan sebuah qiraah. Ia pun mengkisahkan hadits yang serupa dengan hadits Ibnu Numair."},"1276":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ ح و حَدَّثَنَاه ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ أَبِي لَيْلَى عَنْ أُبَيِّ بْنِ كَعْبٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَ أَضَاةِ بَنِي غِفَارٍ قَالَ فَأَتَاهُ جِبْرِيلُ عَلَيْهِ السَّلَام فَقَالَ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تَقْرَأَ أُمَّتُكَ الْقُرْآنَ عَلَى حَرْفٍ فَقَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ وَإِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ أَتَاهُ الثَّانِيَةَ فَقَالَ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تَقْرَأَ أُمَّتُكَ الْقُرْآنَ عَلَى حَرْفَيْنِ فَقَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ وَإِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ جَاءَهُ الثَّالِثَةَ فَقَالَ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تَقْرَأَ أُمَّتُكَ الْقُرْآنَ عَلَى ثَلَاثَةِ أَحْرُفٍ فَقَالَ أَسْأَلُ اللَّهَ مُعَافَاتَهُ وَمَغْفِرَتَهُ وَإِنَّ أُمَّتِي لَا تُطِيقُ ذَلِكَ ثُمَّ جَاءَهُ الرَّابِعَةَ فَقَالَ إِنَّ اللَّهَ يَأْمُرُكَ أَنْ تَقْرَأَ أُمَّتُكَ الْقُرْآنَ عَلَى سَبْعَةِ أَحْرُفٍ فَأَيُّمَا حَرْفٍ قَرَءُوا عَلَيْهِ فَقَدْ أَصَابُواو حَدَّثَنَاه عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ مِثْلَهُ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Syu'bah] -dalam jalur lain- Dan telah menceritakannya kepada kami [Ibnul Mutsanna] dan [Ibnu Basysyar] - [Ibnul Mutsanna] - berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ibnu Abu Laila] dari [Ubay bin Ka'ab] bahwasanya Nabi shallallahu 'alaihi wasallam berada di kolam air Bani Ghifar. Kemudian beliau didatangi Jibril 'Alaihis salam seraya berkata, \"Sesungguhnya Allah memerintahkanmu untuk membacakan Al Qur`an kepada umatmu dengan satu huruf (lahjah bacaan).\" Beliau pun bersabda: \"Saya memohon kasih sayang dan ampunan-Nya, sesungguhnya umatku tidak akan mampu akan hal itu.\" kemudian Jibril datang untuk kedua kalinya dan berkata, \"Sesungguhnya Allah memerintahkanmu untuk membacakan Al Qur`an kepada umatmu dengan dua huruf.\" Beliau pun bersabda: \"Saya memohon kasih sayang dan ampunan-Nya, sesungguhnya umatku tidak akan mampu akan hal itu.\" Lalu Jibril mendatanginya untuk ketiga kalinya seraya berkata, \"Sesungguhnya Allah memerintahkanmu untuk membacakan Al Qur`an kepada umatmu dengan tiga huruf.\" Beliau bersabda \"Saya memohon kasih sayang dan ampunan-Nya, sesungguhnya umatku tidak akan mampu akan hal itu.\" Kemudian Jibril datang untuk yang keempat kalinya dan berkata, \"Sesungguhnya Allah memerintahkanmu untuk membacakan Al Qur`an kepada umatmu dengan tujuh huruf. Dengan huruf yang manapun yang mereka gunakan untuk membaca, maka bacaan mereka benar.\" Dan telah menceritakannya kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dengan isnad ini semisalnya."},"1277":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ جَمِيعًا عَنْ وَكِيعٍ قَالَ أَبُو بَكْرٍ حَدَّثَنَا وَكِيعٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ جَاءَ رَجُلٌ يُقَالُ لَهُ نَهِيكُ بْنُ سِنَانٍ إِلَى عَبْدِ اللَّهِ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ كَيْفَ تَقْرَأُ هَذَا الْحَرْفَ أَلِفًا تَجِدُهُ أَمْ يَاءً{ مِنْ مَاءٍ غَيْرِ آسِنٍ }أَوْ{ مِنْ مَاءٍ غَيْرِ يَاسِنٍ }قَالَ فَقَالَ عَبْدُ اللَّهِ وَكُلَّ الْقُرْآنِ قَدْ أَحْصَيْتَ غَيْرَ هَذَا قَالَ إِنِّي لَأَقْرَأُ الْمُفَصَّلَ فِي رَكْعَةٍ فَقَالَ عَبْدُ اللَّهِ هَذًّا كَهَذِّ الشِّعْرِ إِنَّ أَقْوَامًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ تَرَاقِيَهُمْ وَلَكِنْ إِذَا وَقَعَ فِي الْقَلْبِ فَرَسَخَ فِيهِ نَفَعَ إِنَّ أَفْضَلَ الصَّلَاةِ الرُّكُوعُ وَالسُّجُودُإِنِّي لَأَعْلَمُ النَّظَائِرَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُنُ بَيْنَهُنَّ سُورَتَيْنِ فِي كُلِّ رَكْعَةٍ ثُمَّ قَامَ عَبْدُ اللَّهِ فَدَخَلَ عَلْقَمَةُ فِي إِثْرِهِ ثُمَّ خَرَجَ فَقَالَ قَدْ أَخْبَرَنِي بِهَاقَالَ ابْنُ نُمَيْرٍ فِي رِوَايَتِهِ جَاءَ رَجُلٌ مِنْ بَنِي بَجِيلَةَ إِلَى عَبْدِ اللَّهِ وَلَمْ يَقُلْ نَهِيكُ بْنُ سِنَانٍ و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ قَالَ جَاءَ رَجُلٌ إِلَى عَبْدِ اللَّهِ يُقَالُ لَهُ نَهِيكُ بْنُ سِنَانٍ بِمِثْلِ حَدِيثِ وَكِيعٍ غَيْرَ أَنَّهُ قَالَ فَجَاءَ عَلْقَمَةُ لِيَدْخُلَ عَلَيْهِ فَقُلْنَا لَهُ سَلْهُ عَنْ النَّظَائِرِ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهَا فِي رَكْعَةٍ فَدَخَلَ عَلَيْهِ فَسَأَلَهُ ثُمَّ خَرَجَ عَلَيْنَا فَقَالَ عِشْرُونَ سُورَةً مِنْ الْمُفَصَّلِ فِي تَأْلِيفِ عَبْدِ اللَّهِ و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا الْأَعْمَشُ فِي هَذَا الْإِسْنَادِ بِنَحْوِ حَدِيثِهِمَا وَقَالَ إِنِّي لَأَعْرِفُ النَّظَائِرَ الَّتِي كَانَ يَقْرَأُ بِهِنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْنَتَيْنِ فِي رَكْعَةٍ عِشْرِينَ سُورَةً فِي عَشْرِ رَكَعَاتٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] semuanya dari [Waki'] - [Abu Bakar] berkata- telah menceritakan kepada kami [Waki'] dari [Al A'masy] dari [Abu Wa`il] ia berkata; Seorang laki-laki yang namanya Nahik bin Sinan mendatangi [Abdullah] dan berkata, \"Wahai Abu Abdurrrahman, bagaimana Anda membaca huruf ini, dengan huruf Alif ataukah Yaa`, yaitu: \"MIN MAA`IN GHAIRI `AASIN\" ataukah, \"MIN MAA`IN GHARI YAASIN.\" Maka Abdullah menjawab, \"Apakah setiap Al Qur`an telah kamu hitung selain ini?\" Nahik berkata lagi, \"Sesungguhnya aku benar-benar telah membaca Al Mufashshal dalam satu raka'at.\" Abdullah berkata, \"Cepatnya beliau membaca adalah seperti cepatnya membaca sya'ir. Ada suatu kaum yang membaca Al Qur`an, namun bacaan mereka tidak sampai melewati batas tenggorokan. Bacaan yang terpatri di dalam hati dan menancap kuat di dalamnya, baru akan bermanfaat. Bagian shalat yang paling utama adalah ruku' dan sujud. Aku benar-benar telah mengetahui An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya), yang mana Rasulullah shallallahu 'alaihi wasallam membacanya pada setiap raka'at.\" Kemudian Abdullah berdiri, lalu masuklah Alqamah ke belakang kemudian keluar dan berkata, \"Ia telah mengabarkannya kepadaku.\" Ibnu Numair berkata dalam riwayatnya; Seorang laki-laki dari Bani Bajilah datang kepada Abdullah.\" Ia tidak menyebutkan Nahik bin Sinan. Dan telah menceritakan kepada kami [Abu Kuraib] Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Wa`il] ia berkata; \"Seorang laki-laki yang bernama Nahik bin Sinan datang kepada [Abdullah].\" Yakni serupa dengan haditsnya Waki', hanya saja ia menyebutkan; Kemudian datanglah Alqamah untuk menemui Abdullah, maka kami pun berkata kepadanya, \"Tanyakanlah padanya tentang An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya) dimana Rasulullah shallallahu 'alaihi wasallam telah membacanya dalam satu raka'at.\" Lalu ia pun masuk menemuinya dan bertanya kepadanya. Sesudah itu, ia keluar dan berkata, \"Yaitu dua puluh surat dari Al Mufashshal dalam Ta`lifnya Abdullah. Dan telah meceritakannya kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus] Telah menceritakan kepada kami [Al A'masy] dalam isnad ini sebagaimana hadits keduanya. Dan ia menyebutkan; Sungguh, saya benar-benar telah mengetahui An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya) yang telah dibaca oleh Rasulullah shallallahu 'alaihi wasallam dua surat dalam satu raka'at, yakni dua puluh surat dalam sepuluh raka'at."},"1278":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا مَهْدِيُّ بْنُ مَيْمُونٍ حَدَّثَنَا وَاصِلٌ الْأَحْدَبُ عَنْ أَبِي وَائِلٍ قَالَ غَدَوْنَا عَلَى عَبْدِ اللَّهِ بْنِ مَسْعُودٍ يَوْمًا بَعْدَ مَا صَلَّيْنَا الْغَدَاةَ فَسَلَّمْنَا بِالْبَابِ فَأَذِنَ لَنَا قَالَ فَمَكَثْنَا بِالْبَابِ هُنَيَّةً قَالَ فَخَرَجَتْ الْجَارِيَةُ فَقَالَتْ أَلَا تَدْخُلُونَ فَدَخَلْنَا فَإِذَا هُوَ جَالِسٌ يُسَبِّحُ فَقَالَ مَا مَنَعَكُمْ أَنْ تَدْخُلُوا وَقَدْ أُذِنَ لَكُمْ فَقُلْنَا لَا إِلَّا أَنَّا ظَنَنَّا أَنَّ بَعْضَ أَهْلِ الْبَيْتِ نَائِمٌ قَالَ ظَنَنْتُمْ بِآلِ ابْنِ أُمِّ عَبْدٍ غَفْلَةً قَالَ ثُمَّ أَقْبَلَ يُسَبِّحُ حَتَّى ظَنَّ أَنَّ الشَّمْسَ قَدْ طَلَعَتْ فَقَالَ يَا جَارِيَةُ انْظُرِي هَلْ طَلَعَتْ قَالَ فَنَظَرَتْ فَإِذَا هِيَ لَمْ تَطْلُعْ فَأَقْبَلَ يُسَبِّحُ حَتَّى إِذَا ظَنَّ أَنَّ الشَّمْسَ قَدْ طَلَعَتْ قَالَ يَا جَارِيَةُ انْظُرِي هَلْ طَلَعَتْ فَنَظَرَتْ فَإِذَا هِيَ قَدْ طَلَعَتْ فَقَالَ الْحَمْدُ لِلَّهِ الَّذِي أَقَالَنَا يَوْمَنَا هَذَا فَقَالَ مَهْدِيٌّ وَأَحْسِبُهُ قَالَ وَلَمْ يُهْلِكْنَا بِذُنُوبِنَا قَالَ فَقَالَ رَجُلٌ مِنْ الْقَوْمِ قَرَأْتُ الْمُفَصَّلَ الْبَارِحَةَ كُلَّهُ قَالَ فَقَالَ عَبْدُ اللَّهِ هَذًّا كَهَذِّ الشِّعْرِإِنَّا لَقَدْ سَمِعْنَا الْقَرَائِنَ وَإِنِّي لَأَحْفَظُ الْقَرَائِنَ الَّتِي كَانَ يَقْرَؤُهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَمَانِيَةَ عَشَرَ مِنْ الْمُفَصَّلِ وَسُورَتَيْنِ مِنْ آلِ حم","id":"Telah menceritakan kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Mahdi bin Maimun] telah menceritakan kepada kami [Washil Al Ahdab] dari [Abu Wa`il] ia berkata; Pada suatu hari setelah menunaikan shalat Shubuh, kami pergi menemui [Abdullah bin Mas'ud]. Kami mengucapkan salam di depan pintu, lalu ia pun mengizinkan kami, namun kami tetap berada di dekat pintu sejenak lalu keluarlah seorang budak wanita dan berkata, \"Tidakkah kalian masuk?” Maka kami segera masuk, dan ternyata kami dapati Ibnu Mas'ud sedang duduk bertasbih. Ibnu Mas'ud bertanya, \"Apa yang menghalangi kalian untuk masuk, padahal kalian telah diizinkan?” Kami menjawab, \"Tidak ada, melainkan kami hanya menyangka bahwa sebagian penghuni rumah masih tidur.\" Ibnu Mas'ud berkata, \"Kalian menyangka bahwa keluarga Ibnu Ummi Abdu adalah para pemalas?” Dia kemudian meneruskan bacaan tasbihnya hingga kami mengira bahwa matahari telah terbit. Lalu ia bertanya, \"Wahai Jariyah (budak wanita), lihatlah apakah matahari telah terbit?” budak wanita itu pun melihat, ternyata matahari belum terbit. Maka Ibnu Mas'ud kembali bertasbih hingga ia merasa bahwa matahari telah terbit, lalu ia pun bertanya lagi, \"Wahai Jariyah, apakah matahari telah terbit?” budak wanita itu pun melihatnya, dan ternyata matahari telah terbit. Maka Ibnu Mas'ud berkata, \"Segala puji bagi Allah Yang telah membangkitkan kami di hari ini.\" Mahdi berkata; Aku menduga bahwa ia berkata, \"Dan Dia tidak membinasakan kami lantaran dosa-dosa kami.\" Lalu berkatalah seorang laki-laki dari kaum itu, \"Semalam, saya telah membaca Al Mufashshal seluruhnya.\" Maka Abdullah bin Mas'ud pun berkata, \"Cepatnya beliau membaca adalah seperti cepatnya membaca sya'ir. Saya telah mengetahui An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya), yang mana Rasulullah shallallahu 'alaihi wasallam membacanya yaitu delapan belas surat dari Al Mufashshal dan dua surat dari Alif Lamm Hammim.\""},"1279":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا حُسَيْنُ بْنُ عَلِيٍّ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ مَنْصُورٍ عَنْ شَقِيقٍ قَالَ جَاءَ رَجُلٌ مِنْ بَنِي بَجِيلَةَ يُقَالُ لَهُ نَهِيكُ بْنُ سِنَانٍ إِلَى عَبْدِ اللَّهِ فَقَالَ إِنِّي أَقْرَأُ الْمُفَصَّلَ فِي رَكْعَةٍ فَقَالَ عَبْدُ اللَّهِ هَذًّا كَهَذِّ الشِّعْرِلَقَدْ عَلِمْتُ النَّظَائِرَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِنَّ سُورَتَيْنِ فِي رَكْعَةٍ","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Husain bin Ali Al Ju'fi] dari [Za`idah] dari [Manshur] dari [Syaqiq] ia berkata; Seorang laki-laki dari Bani Bajilah yang biada dipanggil Nahik bin Sinan datang menemui [Abdullah] dan berkata, \"Saya membaca Al Mufashshal (surat-surat yang berada di antara surat Qaaf -atau Hujurat- hingga akhir mushhaf) dalam satu raka'at.\" Maka Abdullah pun berkata, \"Engkau membaca seperti cepatnya pembacaan sya'ir. Saya telah mengetahui An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya), yang mana Rasulullah shallallahu 'alaihi wasallam membacanya dua surat pada setiap raka'at.\""},"1280":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ مُرَّةَ أَنَّهُ سَمِعَ أَبَا وَائِلٍ يُحَدِّثُ أَنَّ رَجُلًا جَاءَ إِلَى ابْنِ مَسْعُودٍ فَقَالَ إِنِّي قَرَأْتُ الْمُفَصَّلَ اللَّيْلَةَ كُلَّهُ فِي رَكْعَةٍ فَقَالَ عَبْدُ اللَّهِ هَذًّا كَهَذِّ الشِّعْرِفَقَالَ عَبْدُ اللَّهِ لَقَدْ عَرَفْتُ النَّظَائِرَ الَّتِي كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرُنُ بَيْنَهُنَّ قَالَ فَذَكَرَ عِشْرِينَ سُورَةً مِنْ الْمُفَصَّلِ سُورَتَيْنِ سُورَتَيْنِ فِي كُلِّ رَكْعَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] -[Ibnul Mutsanna]- berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] dari [Amru bin Murrah] bahwa ia mendengar [Abu wa`il] menceritakan; bahwa seorang laki-laki menemui [Ibnu Mas'ud] seraya berkata, \"Tadi malam saya membaca Al Mufashshal (surat-surat yang berada di antara surat Qaaf -atau Hujurat- hingga akhir mushhaf) seluruhnya dalam satu raka'at.\" Maka Abdullah pun berkata, \"Cepatnya beliau membaca adalah seperti pembacaan sya'ir yang jauh dari ketergesa-gesaan.\" Abdullah berkata; \"Saya telah mengetahui An Nazha`ir (surat-surat yang hampir sama baik panjangnya atau pun maknanya), yang mana Rasulullah shallallahu 'alaihi wasallam membacanya.\" Lalu ia pun menyebutkan dua puluh surat dari Al Mufashshal. Yakni dua surat dua surat pada setiap raka'atnya."},"1281":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو إِسْحَقَ قَالَ رَأَيْتُ رَجُلًا سَأَلَ الْأَسْوَدَ بْنَ يَزِيدَ وَهُوَ يُعَلِّمُ الْقُرْآنَ فِي الْمَسْجِدِ فَقَالَكَيْفَ تَقْرَأُ هَذِهِ الْآيَةَ{ فَهَلْ مِنْ مُدَّكِرٍ }أَدَالًا أَمْ ذَالًا قَالَ بَلْ دَالًا سَمِعْتُ عَبْدَ اللَّهِ بْنَ مَسْعُودٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ{ مُدَّكِرٍ }دَالًا","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Ishaq] ia berkata, saya melihat seorang laki-laki bertanya [Al Aswad bin Yazid] yang sedang mengajarkan Al Qur`an di masjid, \"Bagaimana Anda membaca ayat ini, 'FAHAL MIM MUDDAKIR' apakah dengan huruf Dal ataukah Dzal?.\" Al Aswad menjawab, \"Yang benar adalah dengan huruf Dal. Saya mendengar [Ibnu Mas'ud] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam membaca: \"MUDDAKIR (Yakni dengan huruf Dal).\""},"1282":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ عَنْ عَبْدِ اللَّهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ هَذَا الْحَرْفَ{ فَهَلْ مِنْ مُدَّكِرٍ }","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] -Ibnul Mutsanna- berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dari [Abdullah] dari Nabi shallallahu 'alaihi wasallam, bahwasanya beliau membaca huruf ini: \"FAHAL MIM MUDDAKIR.\""},"1283":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِأَبِي بَكْرٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَقَدِمْنَا الشَّامَ فَأَتَانَا أَبُو الدَّرْدَاءِ فَقَالَ أَفِيكُمْ أَحَدٌ يَقْرَأُ عَلَى قِرَاءَةِ عَبْدِ اللَّهِ فَقُلْتُ نَعَمْ أَنَا قَالَ فَكَيْفَ سَمِعْتَ عَبْدَ اللَّهِ يَقْرَأُ هَذِهِ الْآيَةَ{ وَاللَّيْلِ إِذَا يَغْشَى }قَالَ سَمِعْتُهُ يَقْرَأُ{ وَاللَّيْلِ إِذَا يَغْشَى }وَالذَّكَرِ وَالْأُنْثَى قَالَ وَأَنَا وَاللَّهِ هَكَذَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا وَلَكِنْ هَؤُلَاءِ يُرِيدُونَ أَنْ أَقْرَأَ وَمَا خَلَقَ فَلَا أُتَابِعُهُمْو حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ إِبْرَاهِيمَ قَالَ أَتَى عَلْقَمَةُ الشَّامَ فَدَخَلَ مَسْجِدًا فَصَلَّى فِيهِ ثُمَّ قَامَ إِلَى حَلْقَةٍ فَجَلَسَ فِيهَا قَالَ فَجَاءَ رَجُلٌ فَعَرَفْتُ فِيهِ تَحَوُّشَ الْقَوْمِ وَهَيْئَتَهُمْ قَالَ فَجَلَسَ إِلَى جَنْبِي ثُمَّ قَالَ أَتَحْفَظُ كَمَا كَانَ عَبْدُ اللَّهِ يَقْرَأُ فَذَكَرَ بِمِثْلِهِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] -sedang lafazhnya dari Abu Bakr- keduanya berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Alqamah] ia berkata; Kami mendatangi negeri Syam, lalu [Abu Darda] menjumpai kami seraya bertanya, \"Adakah di antara kalian yang membaca dengan qiraahnya Abdullah bin Mas'ud?\" Saya menjawab, \"Ya. Sayalah orangnya.\" Ia bertanya, \"Lalu bagaimana engkau mendengar Ibnu Mas'ud membaca ayat ini: 'WAL LAILI IDZAA YAGHSYAA.'?\" Saya menjawab, \"Saya mendengarnya membaca; 'WAL LAILI IDZAA YAGHSYAA WADZDZAKARI WAL UNTSAA.'\" Ia (Abu Darda') berkata, adapun saya, demi Allah, saya telah mendengar Rasulullah shallallahu 'alaihi wasallam membacanya seperti itu. Akan tetapi mereka menginginkan agar aku membaca; 'WA MAA KHALAQA', namun saya tidak menuruti mereka.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Mughirah] dari [Ibrahim] ia berkata; [Alqamah] mendatangi negeri Syam, lalu ia masuk Masjid, dan shalat di dalamnya. Kemudian ia berdiri menuju Halaqah dan duduk di situ. Kemudian datanglah [seorang laki-laki] dan saya pun tahu akan reaksi dan sikap orang-orang padanya. Lalu laki-laki itu duduk di sampingku dan bertanya, \"Apakah kamu hafal sebagaimana Abdullah membaca (Al Qur`an)?\" maka ia pun menyebutkan hadits semisalnya."},"1284":{"ar":"حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ عَلْقَمَةَ قَالَ لَقِيتُ أَبَا الدَّرْدَاءِفَقَالَ لِي مِمَّنْ أَنْتَ قُلْتُ مِنْ أَهْلِ الْعِرَاقِ قَالَ مِنْ أَيِّهِمْ قُلْتُ مِنْ أَهْلِ الْكُوفَةِ قَالَ هَلْ تَقْرَأُ عَلَى قِرَاءَةِ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ قُلْتُ نَعَمْ قَالَ فَاقْرَأْ{ وَاللَّيْلِ إِذَا يَغْشَى }قَالَ فَقَرَأْتُ{ وَاللَّيْلِ إِذَا يَغْشَى وَالنَّهَارِ إِذَا تَجَلَّى }وَالذَّكَرِ وَالْأُنْثَى قَالَ فَضَحِكَ ثُمَّ قَالَ هَكَذَا سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَاو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنِي عَبْدُ الْأَعْلَى حَدَّثَنَا دَاوُدُ عَنْ عَامِرٍ عَنْ عَلْقَمَةَ قَالَ أَتَيْتُ الشَّامَ فَلَقِيتُ أَبَا الدَّرْدَاءِ فَذَكَرَ بِمِثْلِ حَدِيثِ ابْنِ عُلَيَّةَ","id":"Telah menceritakan kepada kami [Ali bin Hujr As Sa'di] telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Dawud bin Abu Hind] dari [Asy Sya'bi] dari [Alqamah] ia berkata; Saya berjumpa dengan [Abu Darda`], lalu ia bertanya kepadaku, \"Dari manakah kamu?\" Saya menjawab, \"Dari penduduk Iraq.\" Ia bertanya lagi, \"Dari daerah mana?\" Saya menjawab, \"Dari penduduk Kufah.\" Ia bertanya lagi, \"Apakah kamu membaca Al Qur`an dengan qira`ahnya Abdullah bin Mas'ud?\" Saya menjawab, \"Ya.\" Ia berkata, \"Kalau begitu, bacalah: 'WAL LAILI IDZAA YAGHSYAA.'\" Maka saya pun membacakannya, \"WAL LAILI IDZAA YAGHSYAA WAN NAHAARI IDZAA TAJALLAA WADZ DZAKARI WAL UNTSAA.\" Lalu Abu Darda` pun tertawa kemudian berkata; \"Seperti inilah saya mendengar Rasulullah shallallahu 'alaihi wasallam membacanya.\" Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepadaku [Abdul A'la] telah menceritakan kepada kami [Dawud] dari [Amir] dari [Alqamah] ia berkata; Saya mendatangi negeri Syam dan bertemu dengan [Abu Darda`]. Ia pun menyebutkan hadits yang serupa dengan haditsnya Ibnu Ulayyah."},"1285":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَعَنْ الصَّلَاةِ بَعْدَ الصُّبْحِ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Muhammad bin Yahya bin Habban] dari [Al A'raj] dari [Abu Hurairah] bahwasanya; \"Rasulullah shallallahu 'alaihi wasallam melarang shalat sesudah shalat Asar hingga matahari terbenam, dan sesudah shalat Shubuh hingga matahari terbit.\""},"1286":{"ar":"و حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ وَإِسْمَعِيلُ بْنُ سَالِمٍ جَمِيعًا عَنْ هُشَيْمٍ قَالَ دَاوُدُ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا مَنْصُورٌ عَنْ قَتَادَةَ قَالَ أَخْبَرَنَا أَبُو الْعَالِيَةِ عَنْ ابْنِ عَبَّاسٍ قَالَسَمِعْتُ غَيْرَ وَاحِدٍ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْهُمْ عُمَرُ بْنُ الْخَطَّابِ وَكَانَ أَحَبَّهُمْ إِلَيَّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الصَّلَاةِ بَعْدَ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ وَبَعْدَ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُو حَدَّثَنِيهِ زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ ح و حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ حَدَّثَنَا عَبْدُ الْأَعْلَى حَدَّثَنَا سَعِيدٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي كُلُّهُمْ عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ فِي حَدِيثِ سَعِيدٍ وَهِشَامٍ بَعْدَ الصُّبْحِ حَتَّى تَشْرُقَ الشَّمْسُ","id":"Dan telah menceritakan kepada kami [Dawud bin Rusyaid] dan [Isma'il bin Salim] semuanya dari [Husyaim] -[Dawud]- berkata, telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Manshur] dari [Qatadah] ia berkata, telah mengabarkan kepada kami [Abul 'Aliyah] dari [Ibnu Abbas] ia berkata, \"Saya mendengar lebih dari seorang dari kalangan sahabat Rasulullah shallallahu 'alaihi wasallam termasuk di ataranya adalah [Umar bin Al Khaththab] -dan ia adalah yang paling saya cintai di antara mereka- bahwa Rasulullah shallallahu 'alaihi wasallam melarang shalat sesudah shalat Shubuh hingga matahari terbit dan sesudah shalat Asar hingga matahari terbenam.\" Dan telah menceritakannya kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] -dalam jalur lain- Dan telah menceritakan kepadaku [Abu Ghassan Al Misma'i] telah menceritakan kepada kami [Abdul A'la] telah menceritakan kepada kami [Sa'id] -dalam jalur lain- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] mereka semua dari [Qatadah] dengan isnad ini, hanya saja di dalam haditsnya Sa'id dan Hisyam; \"Setelah shalat Shubuh hingga matahari terbit.\""},"1287":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ قَالَ أَخْبَرَنِي عَطَاءُ بْنُ يَزِيدَ اللَّيْثِيُّ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ الْخُدْرِيَّ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا صَلَاةَ بَعْدَ صَلَاةِ الْعَصْرِ حَتَّى تَغْرُبَ الشَّمْسُ وَلَا صَلَاةَ بَعْدَ صَلَاةِ الْفَجْرِ حَتَّى تَطْلُعَ الشَّمْسُ","id":"Telah menceritakan kepada kami [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] bahwa [Ibnu Syihab] telah mengabarkan kepadanya, ia berkata, telah mengabarkan kepadaku ['Atha` bin Yazid Al Laitsi] bahwa ia mendengar [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh shalat sesudah Ashar hingga matahari terbenam dan tidak boleh shalat sesudah shalat Fajar hingga matahari terbit.\""},"1288":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَتَحَرَّى أَحَدُكُمْ فَيُصَلِّيَ عِنْدَ طُلُوعِ الشَّمْسِ وَلَا عِنْدَ غُرُوبِهَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu menunggu-nunggu waktu shalat sehingga mengerjakan shalat ketika matahari terbit, dan jangan pula pada waktu matahari terbenam.\""},"1289":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَمُحَمَّدُ بْنُ بِشْرٍ قَالَا جَمِيعًا حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحَرَّوْا بِصَلَاتِكُمْ طُلُوعَ الشَّمْسِ وَلَا غُرُوبَهَا فَإِنَّهَا تَطْلُعُ بِقَرْنَيْ شَيْطَانٍ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] Telah menceritakan kepada kami [bapakku] dan [Muhammad bin Bisyr] keduanya berkata, Telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian menunda-nunda shalat sehingga mengerjakannya saat matahari terbit, dan jangan pula saat terbenamnya, karena matahari itu terbit di antara dua tanduk syetan.\""},"1290":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي وَابْنُ بِشْرٍ قَالُوا جَمِيعًا حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَدَا حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تَبْرُزَ وَإِذَا غَابَ حَاجِبُ الشَّمْسِ فَأَخِّرُوا الصَّلَاةَ حَتَّى تَغِيبَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] Telah menceritakan kepada kami [bapakku] dan [Ibnu Bisyr] mereka berkata, Telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila sebagian matahari mulai terbit, maka tundalah shalat sampai matahari itu benar-benar terbit (dengan sempurna). Dan bila sebagian matahari itu mulai terbenam, maka tundalah shalat sampai matahari tersebut benar-benar terbenam.\""},"1291":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ عَنْ خَيْرِ بْنِ نُعَيْمٍ الْحَضْرَمِيِّ عَنْ ابْنِ هُبَيْرَةَ عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَصَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ بِالْمُخَمَّصِ فَقَالَ إِنَّ هَذِهِ الصَّلَاةَ عُرِضَتْ عَلَى مَنْ كَانَ قَبْلَكُمْ فَضَيَّعُوهَا فَمَنْ حَافَظَ عَلَيْهَا كَانَ لَهُ أَجْرُهُ مَرَّتَيْنِ وَلَا صَلَاةَ بَعْدَهَا حَتَّى يَطْلُعَ الشَّاهِدُ وَالشَّاهِدُ النَّجْمُو حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ خَيْرِ بْنِ نُعَيْمٍ الْحَضْرَمِيِّ عَنْ عَبْدِ اللَّهِ بْنِ هُبَيْرَةَ السَّبَائِيِّ وَكَانَ ثِقَةً عَنْ أَبِي تَمِيمٍ الْجَيْشَانِيِّ عَنْ أَبِي بَصْرَةَ الْغِفَارِيِّ قَالَ صَلَّى بِنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَصْرَ بِمِثْلِهِ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] dari [Khair bin Nu'aim Al Hadlrami] dari [Ibnu Hubairah] dari [Abu Tamim Al Jaisyani] dari [Abu Bashrah Al Ghifari] ia berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam mengimami kami shalat Ashar di Mukhammas. Maka beliau bersabda: \"Sesungguhnya shalat Ashar ini pernah diwajibkan kepada orang-orang yang sebelum kalian, tetapi mereka sia-siakan. Karena itu, siapa yang memelihara shalat ini, dia akan mendapatkan pahala ganda. Dan tidak boleh shalat sesudahnya, hingga bintang terbit.\" Dan telah menceritakan kepadaku [Zuhair bin Harb] Telah menceritakan kepada kami [Ya'qub bin Ibrahim] Telah menceritakan kepada kami [bapakku] dari [Ibnu Ishaq] ia berkata, telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Khair bin Nu'aim Al Hadlrami] dari [Abdullah bin Hubairah As Saba`i] -ia adalah seorang yang tsiqqah (terpercaya) - dari [Abu Tamim Al Jaisyani] dari [Abu Bashrah Al Ghifari] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah shalat Ashar bersama kami. Yakni hadits semisalnya."},"1292":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ مُوسَى بْنِ عُلَيٍّ عَنْ أَبِيهِ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ الْجُهَنِيَّ يَقُولُاثَلَاثُ سَاعَاتٍ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَانَا أَنْ نُصَلِّيَ فِيهِنَّ أَوْ أَنْ نَقْبُرَ فِيهِنَّ مَوْتَانَا حِينَ تَطْلُعُ الشَّمْسُ بَازِغَةً حَتَّى تَرْتَفِعَ وَحِينَ يَقُومُ قَائِمُ الظَّهِيرَةِ حَتَّى تَمِيلَ الشَّمْسُ وَحِينَ تَضَيَّفُ الشَّمْسُ لِلْغُرُوبِ حَتَّى تَغْرُبَ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] dari [Musa bin Ali] dari [bapaknya] ia berkata, saya mendengar [Uqbah bin Amir Al Juhani] berkata; \"Ada tiga waktu, yang mana Rasulullah shallallahu 'alaihi wasallam telah melarang kita untuk shalat atau menguburkan jenazah pada waktu-waktu tersebut. (Pertama), saat matahari terbit hingga ia agak meninggi. (Kedua), saat matahari tepat berada di pertengahan langit (tengah hari tepat) hingga ia telah condong ke barat, (Ketiga), saat matahari hampir terbenam, hingga ia terbenam sama sekali.\""},"1293":{"ar":"حَدَّثَنِي أَحْمَدُ بْنُ جَعْفَرٍ الْمَعْقِرِيُّ حَدَّثَنَا النَّضْرُ بْنُ مُحَمَّدٍ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنَا شَدَّادُ بْنُ عَبْدِ اللَّهِ أَبُو عَمَّارٍ وَيَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي أُمَامَةَ قَالَ عِكْرِمَةُ وَلَقِيَ شَدَّادٌ أَبَا أُمَامَةَ وَوَاثِلَةَ وَصَحِبَ أَنَسًا إِلَى الشَّامِ وَأَثْنَى عَلَيْهِ فَضْلًا وَخَيْرًا عَنْ أَبِي أُمَامَةَ قَالَ قَالَ عَمْرُو بْنُ عَبَسَةَ السُّلَمِيُّكُنْتُ وَأَنَا فِي الْجَاهِلِيَّةِ أَظُنُّ أَنَّ النَّاسَ عَلَى ضَلَالَةٍ وَأَنَّهُمْ لَيْسُوا عَلَى شَيْءٍ وَهُمْ يَعْبُدُونَ الْأَوْثَانَ فَسَمِعْتُ بِرَجُلٍ بِمَكَّةَ يُخْبِرُ أَخْبَارًا فَقَعَدْتُ عَلَى رَاحِلَتِي فَقَدِمْتُ عَلَيْهِ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَخْفِيًا جُرَءَاءُ عَلَيْهِ قَوْمُهُ فَتَلَطَّفْتُ حَتَّى دَخَلْتُ عَلَيْهِ بِمَكَّةَ فَقُلْتُ لَهُ مَا أَنْتَ قَالَ أَنَا نَبِيٌّ فَقُلْتُ وَمَا نَبِيٌّ قَالَ أَرْسَلَنِي اللَّهُ فَقُلْتُ وَبِأَيِّ شَيْءٍ أَرْسَلَكَ قَالَ أَرْسَلَنِي بِصِلَةِ الْأَرْحَامِ وَكَسْرِ الْأَوْثَانِ وَأَنْ يُوَحَّدَ اللَّهُ لَا يُشْرَكُ بِهِ شَيْءٌ قُلْتُ لَهُ فَمَنْ مَعَكَ عَلَى هَذَا قَالَ حُرٌّ وَعَبْدٌ قَالَ وَمَعَهُ يَوْمَئِذٍ أَبُو بَكْرٍ وَبِلَالٌ مِمَّنْ آمَنَ بِهِ فَقُلْتُ إِنِّي مُتَّبِعُكَ قَالَ إِنَّكَ لَا تَسْتَطِيعُ ذَلِكَ يَوْمَكَ هَذَا أَلَا تَرَى حَالِي وَحَالَ النَّاسِ وَلَكِنْ ارْجِعْ إِلَى أَهْلِكَ فَإِذَا سَمِعْتَ بِي قَدْ ظَهَرْتُ فَأْتِنِي قَالَ فَذَهَبْتُ إِلَى أَهْلِي وَقَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَكُنْتُ فِي أَهْلِي فَجَعَلْتُ أَتَخَبَّرُ الْأَخْبَارَ وَأَسْأَلُ النَّاسَ حِينَ قَدِمَ الْمَدِينَةَ حَتَّى قَدِمَ عَلَيَّ نَفَرٌ مِنْ أَهْلِ يَثْرِبَ مِنْ أَهْلِ الْمَدِينَةَ فَقُلْتُ مَا فَعَلَ هَذَا الرَّجُلُ الَّذِي قَدِمَ الْمَدِينَةَ فَقَالُوا النَّاسُ إِلَيْهِ سِرَاعٌ وَقَدْ أَرَادَ قَوْمُهُ قَتْلَهُ فَلَمْ يَسْتَطِيعُوا ذَلِكَ فَقَدِمْتُ الْمَدِينَةَ فَدَخَلْتُ عَلَيْهِ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَعْرِفُنِي قَالَ نَعَمْ أَنْتَ الَّذِي لَقِيتَنِي بِمَكَّةَ قَالَ فَقُلْتُ بَلَى فَقُلْتُ يَا نَبِيَّ اللَّهِ أَخْبِرْنِي عَمَّا عَلَّمَكَ اللَّهُ وَأَجْهَلُهُ أَخْبِرْنِي عَنْ الصَّلَاةِ قَالَ صَلِّ صَلَاةَ الصُّبْحِ ثُمَّ أَقْصِرْ عَنْ الصَّلَاةِ حَتَّى تَطْلُعَ الشَّمْسُ حَتَّى تَرْتَفِعَ فَإِنَّهَا تَطْلُعُ حِينَ تَطْلُعُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَحِينَئِذٍ يَسْجُدُ لَهَا الْكُفَّارُ ثُمَّ صَلِّ فَإِنَّ الصَّلَاةَ مَشْهُودَةٌ مَحْضُورَةٌ حَتَّى يَسْتَقِلَّ الظِّلُّ بِالرُّمْحِ ثُمَّ أَقْصِرْ عَنْ الصَّلَاةِ فَإِنَّ حِينَئِذٍ تُسْجَرُ جَهَنَّمُ فَإِذَا أَقْبَلَ الْفَيْءُ فَصَلِّ فَإِنَّ الصَّلَاةَ مَشْهُودَةٌ مَحْضُورَةٌ حَتَّى تُصَلِّيَ الْعَصْرَ ثُمَّ أَقْصِرْ عَنْ الصَّلَاةِ حَتَّى تَغْرُبَ الشَّمْسُ فَإِنَّهَا تَغْرُبُ بَيْنَ قَرْنَيْ شَيْطَانٍ وَحِينَئِذٍ يَسْجُدُ لَهَا الْكُفَّارُ قَالَ فَقُلْتُ يَا نَبِيَّ اللَّهِ فَالْوُضُوءَ حَدِّثْنِي عَنْهُ قَالَ مَا مِنْكُمْ رَجُلٌ يُقَرِّبُ وَضُوءَهُ فَيَتَمَضْمَضُ وَيَسْتَنْشِقُ فَيَنْتَثِرُ إِلَّا خَرَّتْ خَطَايَا وَجْهِهِ وَفِيهِ وَخَيَاشِيمِهِ ثُمَّ إِذَا غَسَلَ وَجْهَهُ كَمَا أَمَرَهُ اللَّهُ إِلَّا خَرَّتْ خَطَايَا وَجْهِهِ مِنْ أَطْرَافِ لِحْيَتِهِ مَعَ الْمَاءِ ثُمَّ يَغْسِلُ يَدَيْهِ إِلَى الْمِرْفَقَيْنِ إِلَّا خَرَّتْ خَطَايَا يَدَيْهِ مِنْ أَنَامِلِهِ مَعَ الْمَاءِ ثُمَّ يَمْسَحُ رَأْسَهُ إِلَّا خَرَّتْ خَطَايَا رَأْسِهِ مِنْ أَطْرَافِ شَعْرِهِ مَعَ الْمَاءِ ثُمَّ يَغْسِلُ قَدَمَيْهِ إِلَى الْكَعْبَيْنِ إِلَّا خَرَّتْ خَطَايَا رِجْلَيْهِ مِنْ أَنَامِلِهِ مَعَ الْمَاءِ فَإِنْ هُوَ قَامَ فَصَلَّى فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ وَمَجَّدَهُ بِالَّذِي هُوَ لَهُ أَهْلٌ وَفَرَّغَ قَلْبَهُ لِلَّهِ إِلَّا انْصَرَفَ مِنْ خَطِيئَتِهِ كَهَيْئَتِهِ يَوْمَ وَلَدَتْهُ أُمُّهُ فَحَدَّثَ عَمْرُو بْنُ عَبَسَةَ بِهَذَا الْحَدِيثِ أَبَا أُمَامَةَ صَاحِبَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ أَبُو أُمَامَةَ يَا عَمْرَو بْنَ عَبَسَةَ انْظُرْ مَا تَقُولُ فِي مَقَامٍ وَاحِدٍ يُعْطَى هَذَا الرَّجُلُ فَقَالَ عَمْرٌو يَا أَبَا أُمَامَةَ لَقَدْ كَبِرَتْ سِنِّي وَرَقَّ عَظْمِي وَاقْتَرَبَ أَجَلِي وَمَا بِي حَاجَةٌ أَنْ أَكْذِبَ عَلَى اللَّهِ وَلَا عَلَى رَسُولِ اللَّهِ لَوْ لَمْ أَسْمَعْهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا مَرَّةً أَوْ مَرَّتَيْنِ أَوْ ثَلَاثًا حَتَّى عَدَّ سَبْعَ مَرَّاتٍ مَا حَدَّثْتُ بِهِ أَبَدًا وَلَكِنِّي سَمِعْتُهُ أَكْثَرَ مِنْ ذَلِكَ","id":"Telah menceritakan kepadaku [Ahmad bin Ja'far Al Ma'qiri] telah menceritakan kepada kami [An Nadlr bin Muhammad] telah menceritakan kepada kami [Ikrimah bin Ammar] telah menceritakan kepada kami [Syaddad bin Abdullah Abu Ammar] dan [Yahya bin Abu Katsir] dari [Abu Umamah] - Ikrimah berkata; Syaddad telah berjumpa dengan Abu Umamah dan Watsilah, juga pernah menemani Anas ke negeri Syam, ia telah memujinya dengan keutamaan dan kebaikan- Dari Abu Umamah ia berkata, [Amru bin Abasah As Sulami] berkata; Pada masa jahiliyah dulu, saya mengira bahwa manusia ketika itu berada dalam kesesatan. Mereka tidaklah memiliki sesuatu pun (yang patut dibanggakan), mereka saat itu menyembah berhala. Lalu saya mendengar tentang sosok seorang laki-laki di Makkah yang sedang menyampaikan beberapa kabar berita. Kemudian aku duduk di atas hewan tungganganku. Saya mendatangi Rasulullah shallallahu 'alaihi wasallam ketika beliau di 'Ukadz, lalu aku bertanya, “Siapa tuan?” Beliau menjawab: “Seorang Nabi.” Aku bertanya lagi, “Nabi yang bagimana?” Beliau menjawab: “Allah telah mengutusku.” Aku bertanya lagi, “Engkau diutus dengan apa?” Beliau menjawab: “Aku diutus untuk menyambung tali silaturahmi, menghancurkan berhala, dan agar Allah ditauhidkan dan tidak dipersekutukan.” Lalu aku bertanya lagi, \"Siapakah orang yang menjadi pengikut Anda dalam perkara ini (Din Islam)?” Beliau menjawab: \"Seorang yang merdeka dan juga sorang budak.\" Sementara saat itu beliau bersama Abu Bakar dan Bilal radliallahu 'anhuma. Kemudian beliau bersabda kepadaku: \"Pulanglah kamu hingga Allah menguatkan Rasul-Nya.\" Setelah itu, saya mendatangi beliau dan berkata, \"Semoga Allah menjadikanku sebagai tebusanmu. Ajarkanlah aku sesuatu yang Anda ketahui sementara aku tidak mengetahuinya, yaitu sesuatu yang tidak membahayakanmu dan Allah juga memberikan aku manfaat dengannya. Apakah ada suatu waktu yang lebih utama dari waktu yang lain, dan adakah suatu waktu yang harus kita waspadai?” Beliau menjawab: \"Sungguh, kamu telah bertanya kepadaku tentang sesuatu yang belum pernah ditanyakan oleh seorang pun sebelummu. Sesungguhnya Allah 'azza wajalla turun pada sepertiga akhir malam, dan Dia mengampuni dosa apa saja kecuali syirik dan perbuatan yang melampaui batas. Shalat adalah suatu ibadah yang disaksikan dan dihadiri (oleh para malaikat) maka hendaklah kamu shalat hingga matahari terbit. Dan apabila matahari telah terbit, maka janganlah kamu shalat hingga matahari meninggi, karena matahari terbit diantara dua tanduk syetan, dan shalat pada waktu itu adalah shalatnya orang-orang kafir. Kemudian, jika matahari sudah meninggi, maka shalatlah, karena shalat pada waktu itu disaksikan dan dihadiri (oleh para malaikat) hingga pertengahan siang. Saat matahari berada di pertengahan langit, maka janganlah kamu shalat, karena pada waktu itu api neraka sedang dinyalahkan hingga bayangan kembali muncul. Dan apabila bayangan sudah kembali maka shalatlah kamu, karena shalat pada waktu itu disaksikan dan dihadiri (oleh para malaikat) hingga matahari turun untuk terbenam. Ketika matahari hari hendak terbenam, maka janganlah kamu shalat hingga benar-benar terbenam, Karena matahari terbenam diantara dua tanduk syetan dan pada waktu itulah orang-orang kafir beribadah.\" Aku berkata, \"Wahai Nabi Allah, beritahulah aku tentang wudlu.\" Beliau bersabda: \"Tidaklah salah seorang dari kalian yang menyempurnakan wudlu, lalu ia berkumur-kumur dan beristinsyaq (menghirup air ke dalam hidung lalu menghembuskannya) kecuali dosa-dosa wajahnya, bibirnya dan hidungnya akan turut melebur. Kemudian, bila ia membasuh wajahnya sebagaimana yang diperintahkan Allah, niscaya dosa-dosa wajahnya akan melebur bersama air dari ujung-ujung jenggotnya. Dan tidaklah ia membasuh kedua tangannya hingga pergelangan siku kecuali dosa-dosa kedua tangannya akan melebur bersama air dari jari-jemarinya. Dan tidaklah ia membasuh kepalanya kecuali dosa-dosa kepalanya akan melebur bersama air dari ujung-ujung rambutnya. Dan tidaklah ia membasuh kedua kakinya hingga mata kaki kecuali dosa-dosa kedua kakinya juga melebur bersama air dari jari-jari kakinya. Dan bila ia berdiri dan shalat lalu memuji Allah serta menyanjung-Nya dan juga memujinya dengan sesuatu yang memang Dialah yang berhak atasnya lalu mengkhusyukkan hatinya semata-semata hanya untuk Allah, maka niscaya ia akan belepas diri dari dosa-dosanya sebagaimana hari ia dilahirkan oleh ibunya.\" Amru bin Habasyah menceritakan hadits ini kepada Abu Umamah salah seorang dari sahabat Rasulullallah shallallahu 'alaihi wasallam. Maka Abu Umamah pun berkata padanya, \"Wahai Amru bin Abasah, lihatlah apa yang telah kamu katakana di tempat yang sama, 'Laki-laki ini akan diberi.'\" Amru berkata, \"Wahai Abu Umamah, sungguh usiaku telah lanjut dan tulang-tulangku juga telah rapuh sementara ajalku pun telah dekat, maka tidaklah aku berhajat untuk berdusta atas nama Allah dan tidak juga atas nama Rasulullah shallallahu 'alaihi wasallam. Sekiranya aku tidak mendengarnya dari Rasulullah shallallahu 'alaihi wasallam kecuali hanya sekali atau dua kali, atau tiga kali -hingga ia menghitungnya sendiri sampai tujuh kali- niscaya aku tidak akan menceritakannya selama-lamanya. Akan tetapi aku telah mendengarnya lebih dari itu.\""},"1294":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ طَاوُسٍ عَنْ أَبِيهِعَنْ عَائِشَةَ أَنَّهَا قَالَتْ وَهِمَ عُمَرُ إِنَّمَا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُتَحَرَّى طُلُوعُ الشَّمْسِ وَغُرُوبُهَا","id":"Telah menceritakan kepada kami [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin Thawus] dari [bapaknya] dari [Aisyah] bahwa ia berkata; Umar telah keliru, hanyasanya Rasulullah shallallahu 'alaihi wasallam melarang melaksanakan shalat pada disaat matahari terbit dan disaat terbenam adalah jika dikerjakan dengan sengaja dan dengan anggapan bahwa hal itu lebih baik."},"1295":{"ar":"و حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْلَمْ يَدَعْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ قَالَ فَقَالَتْ عَائِشَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَتَحَرَّوْا طُلُوعَ الشَّمْسِ وَلَا غُرُوبَهَا فَتُصَلُّوا عِنْدَ ذَلِكَ","id":"Dan telah menceritakan kepada kami [Hasan Al Hulwani] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Ibnu Thawus] dari [bapaknya] dari [Aisyah] bahwa ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah meninggalkan dua raka'at sesudah Ashar.\" Thawus berkata; Aisyah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu menunggu-nunggu waktu saat matahari terbit, dan jangan pula pada waktu matahari terbenam hingga kalian shalat pada waktu itu.\""},"1296":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى التُّجِيبِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو وَهُوَ ابْنُ الْحَارِثِ عَنْ بُكَيْرٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍأَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ وَعَبْدَ الرَّحْمَنِ بْنَ أَزْهَرَ وَالْمِسْوَرَ بْنَ مَخْرَمَةَ أَرْسَلُوهُ إِلَى عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا اقْرَأْ عَلَيْهَا السَّلَامَ مِنَّا جَمِيعًا وَسَلْهَا عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ وَقُلْ إِنَّا أُخْبِرْنَا أَنَّكِ تُصَلِّينَهُمَا وَقَدْ بَلَغَنَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْهُمَا قَالَ ابْنُ عَبَّاسٍ وَكُنْتُ أَضْرِبُ مَعَ عُمَرَ بْنِ الْخَطَّابِ النَّاسَ عَلَيْهَا قَالَ كُرَيْبٌ فَدَخَلْتُ عَلَيْهَا وَبَلَّغْتُهَا مَا أَرْسَلُونِي بِهِ فَقَالَتْ سَلْ أُمَّ سَلَمَةَ فَخَرَجْتُ إِلَيْهِمْ فَأَخْبَرْتُهُمْ بِقَوْلِهَا فَرَدُّونِي إِلَى أُمِّ سَلَمَةَ بِمِثْلِ مَا أَرْسَلُونِي بِهِ إِلَى عَائِشَةَ فَقَالَتْ أُمُّ سَلَمَةَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْهُمَا ثُمَّ رَأَيْتُهُ يُصَلِّيهِمَا أَمَّا حِينَ صَلَّاهُمَا فَإِنَّهُ صَلَّى الْعَصْرَ ثُمَّ دَخَلَ وَعِنْدِي نِسْوَةٌ مِنْ بَنِي حَرَامٍ مِنْ الْأَنْصَارِ فَصَلَّاهُمَا فَأَرْسَلْتُ إِلَيْهِ الْجَارِيَةَ فَقُلْتُ قُومِي بِجَنْبِهِ فَقُولِي لَهُ تَقُولُ أُمُّ سَلَمَةَ يَا رَسُولَ اللَّهِ إِنِّي أَسْمَعُكَ تَنْهَى عَنْ هَاتَيْنِ الرَّكْعَتَيْنِ وَأَرَاكَ تُصَلِّيهِمَا فَإِنْ أَشَارَ بِيَدِهِ فَاسْتَأْخِرِي عَنْهُ قَالَ فَفَعَلَتْ الْجَارِيَةُ فَأَشَارَ بِيَدِهِ فَاسْتَأْخَرَتْ عَنْهُ فَلَمَّا انْصَرَفَ قَالَ يَا بِنْتَ أَبِي أُمَيَّةَ سَأَلْتِ عَنْ الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ إِنَّهُ أَتَانِي نَاسٌ مِنْ عَبْدِ الْقَيْسِ بِالْإِسْلَامِ مِنْ قَوْمِهِمْ فَشَغَلُونِي عَنْ الرَّكْعَتَيْنِ اللَّتَيْنِ بَعْدَ الظُّهْرِ فَهُمَا هَاتَانِ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya At Tujibi] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Amru bin Harits] dari [Bukair] dari [Kuraib] Maula Ibnu Abbas, bahwa Abdullah bin Abbas dan Abdurrahman bin Azhar dan Al Miswar bin Makhramah mereka mengutusnya agar menemui Aisyah isteri Nabi shallallahu 'alaihi wasallam seraya berpesan, \"Sampaikan salam kami kepadanya dan tanyakan mengenai dua raka'at setelah Ashar kemudian katakanlah bahwa kami telah mendengar kabar bahwa Anda menunaikannya padahal telah sampai kepada kami bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dua raka'at itu.\" Ibnu Abbas berkata, \"Saya dan Umar pernah memukul beberapa orang karena menunaikan dua raka'at setelah Ashar.\" Kuraib berkata; Maka saya pun menemui Aisyah dan menyampaikan pesan-pesan mereka. Lalu Aisyah pun berkata, \"Tanyakanlah kepada [Ummu Salamah].\" Akhirnya aku pun kembali kepada mereka, dan menyampaikan komentar Aisyah. Kemudian mereka kembali mengutusku untuk menemui Ummu Aisyah dan menanyakan pertanyaan yang sama. Ummu Salamah menjawab, \"Saya telah mendengar Rasulullah shallallahu 'alaihi wasallam melarang shalat dua raka'at sesudah Ashar itu. Namun setelah itu, saya melihat beliau melakukannya. Dan memang sebelum menunaikannya, terlebih dahulu menunaikan shalat Ashar. Sesudah itu, beliau masuk menemuiku, sementara di sisiku terdapat beberapa orang wanita Anshar dari Bani Haram, kemudian beliau melaksanakan dua raka'at (Setelah Ashar itu). Lalu saya mengutus seorang budak wanita seraya berkata padanya, \"Berdirilah kamu di samping beliau, dan katakanlah padanya, 'Ummu Salamah berkata; Wahai Rasulullah, saya telah mendengar tuan melarang dua raka'at ini, namun saya melihat Anda melakukannya.' Dan jika ia memberi isyarat dengan tangannya, maka mundurlah.\" Budak wanita itu pun melakukannya, kemudian beliau memberi isyarat, maka budak wanita itu pun mundur. Usai menunaikan shalat, beliau bersabda: \"Wahai binti Abu Umayyah, kamu tadi menanyakan tentang dua raka'at setelah Ashar. Sesungguhnya saya telah didatangi oleh beberapa orang dari Bani Abdul Qais dengan menyatakan keIslaman kaumnya hingga mereka menyibukkanku untuk menunaikan dua raka'at setelah Zhuhur, maka dua raka'at ini sebagai penggantinya.\""},"1297":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَعَلِيُّ بْنُ حُجْرٍ قَالَ ابْنُ أَيُّوبَ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ أَخْبَرَنِي مُحَمَّدٌ وَهُوَ ابْنُ أَبِي حَرْمَلَةَ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَأَنَّهُ سَأَلَ عَائِشَةَ عَنْ السَّجْدَتَيْنِ اللَّتَيْنِ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّيهِمَا بَعْدَ الْعَصْرِ فَقَالَتْ كَانَ يُصَلِّيهِمَا قَبْلَ الْعَصْرِ ثُمَّ إِنَّهُ شُغِلَ عَنْهُمَا أَوْ نَسِيَهُمَا فَصَلَّاهُمَا بَعْدَ الْعَصْرِ ثُمَّ أَثْبَتَهُمَا وَكَانَ إِذَا صَلَّى صَلَاةً أَثْبَتَهَاقَالَ يَحْيَى بْنُ أَيُّوبَ قَالَ إِسْمَعِيلُ تَعْنِي دَاوَمَ عَلَيْهَا","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] dan [Ali bin Hujr] -Ibnu Ayyub- berkata, telah menceritakan kepada kami [Isma'il] ia adalah -Ibnu Ja'far- telah mengabarkan kepadaku [Muhammad] -ia adalah Ibnu Abu Harmalah- ia berkata, telah mengabarkan kepadaku [Abu Salamah] bahwa ia pernah bertanya kepada [Aisyah] mengenai dua sujud yang dilakukan oleh Rasulullah shallallahu 'alaihi wasallam sesudah shalat Ashar, maka ia menjawab; \"Dulu beliau melakukannya sebelum Ashar, kemudian beliau tersibukkan darinya atau lupa, sehingga beliau melaksanakannya sesudah shalat Ashar kemudian beliau selalu menunaikannya. Dan biasanya, bila beliau melaksanakan suatu shalat, maka beliau menekuninya.\" Yahya bin Ayyub berkata; Isma'il berkata, \"Yakni beliau selalu menunaikannya.\""},"1298":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي جَمِيعًا عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ بَعْدَ الْعَصْرِ عِنْدِي قَطُّ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] semuanya dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] ia berkata; Menurutku, Rasulullah shallallahu 'alaihi wasallam sama sekali tidak pernah meninggalkan dua raka'at sesudah Ashar.\""},"1299":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ ح و حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ وَاللَّفْظُ لَهُ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ أَخْبَرَنَا أَبُو إِسْحَقَ الشَّيْبَانِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْأَسْوَدِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْصَلَاتَانِ مَا تَرَكَهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي قَطُّ سِرًّا وَلَا عَلَانِيَةً رَكْعَتَيْنِ قَبْلَ الْفَجْرِ وَرَكْعَتَيْنِ بَعْدَ الْعَصْرِ","id":"Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Ali bin Mushir] -dalam jalur lain- Dan telah menceritakan kepada kami [Ali bin Hujr] -dengan lafazh hadits darinya- telah mengabarkan kepada kami [Ali bin Mushir] telah mengabarkan kepada kami [Abu Ishaq Asy Syaibani] dari [Abdurrahman bin Al Aswad] dari [bapaknya] dari [Aisyah] ia berkata; \"Ada dua shalat yang sama sekali tidak pernah ditinggalkan oleh Rasulullah shallallahu 'alaihi wasallam di rumahku, baik secara sembunyi maupun terang-terangan, yaitu dua raka'at sebelum subuh dan dua raka'at sesudah asar.\""},"1300":{"ar":"و حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي إِسْحَقَ عَنْ الْأَسْوَدِ وَمَسْرُوقٍ قَالَا نَشْهَدُ عَلَى عَائِشَةَ أَنَّهَا قَالَتْمَا كَانَ يَوْمُهُ الَّذِي كَانَ يَكُونُ عِنْدِي إِلَّا صَلَّاهُمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِي تَعْنِي الرَّكْعَتَيْنِ بَعْدَ الْعَصْرِ","id":"Telah menceritakan kepada kami [Ibnul Mutsanna] dan [Ibnu Basysyar] -Ibnul Mutsanna- berkata, telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Abu Ishaq] dari [Al Aswad] dan [Masruq] keduanya berkata, kami menyaksikan [Aisyah] bahwa ia berkata, \"Tidak ada satu hari pun dari hari-hari Rasulullah shallallahu 'alaihi wasallam yang beliau habiskan di tempatku, kecuali beliau menunaikan dua raka'at itu, yakni dua raka'at sesudah asar.\""},"1301":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ جَمِيعًا عَنْ ابْنِ فُضَيْلٍ قَالَ أَبُو بَكْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ مُخْتَارِ بْنِ فُلْفُلٍ قَالَ سَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ التَّطَوُّعِ بَعْدَ الْعَصْرِ فَقَالَ كَانَ عُمَرُ يَضْرِبُ الْأَيْدِي عَلَى صَلَاةٍ بَعْدَ الْعَصْرِوَكُنَّا نُصَلِّي عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ بَعْدَ غُرُوبِ الشَّمْسِ قَبْلَ صَلَاةِ الْمَغْرِبِ فَقُلْتُ لَهُ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّاهُمَا قَالَ كَانَ يَرَانَا نُصَلِّيهِمَا فَلَمْ يَأْمُرْنَا وَلَمْ يَنْهَنَا","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] semuanya dari [Ibnu Fudlail], [Abu Bakar] berkata, telah menceritakan kepada kami [Muhammad bin Fudlail] dari [Mukhtar bin Fulful] ia berkata, saya bertanya kepada [Anas bin Malik] mengenai shalat tathawwu' sesudah shalat asar. Maka ia menjawab, \"Dulu Umar memukul tangan seseorang karena shalat sesudah Asar. Dan pada masa Rasulullah shallallahu 'alaihi wasallam kami biasa menunaikan dua raka'at setelah terbenamnya matahari dan sebelum shalat Maghrib.\" Saya bertanya lagi padanya, \"Apakah Rasulullah shallallahu 'alaihi wasallam pernah melakukannya?\" Ia menjawab, \"Beliau melihat kami melakukannya, namun beliau tidak memerintahkan kami dan tidak pula melarang.\""},"1302":{"ar":"و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ عَبْدِ الْعَزِيزِ وَهُوَ ابْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكُنَّا بِالْمَدِينَةِ فَإِذَا أَذَّنَ الْمُؤَذِّنُ لِصَلَاةِ الْمَغْرِبِ ابْتَدَرُوا السَّوَارِيَ فَيَرْكَعُونَ رَكْعَتَيْنِ رَكْعَتَيْنِ حَتَّى إِنَّ الرَّجُلَ الْغَرِيبَ لَيَدْخُلُ الْمَسْجِدَ فَيَحْسِبُ أَنَّ الصَّلَاةَ قَدْ صُلِّيَتْ مِنْ كَثْرَةِ مَنْ يُصَلِّيهِمَا","id":"Telah menceritakan kepada kami [Syaiban bin Farruh] telah menceritakan kepada kami [Abdul Warits] dari [Abdul Aziz] dan ia adalah Ibnu Shuhaib dari [Anas bin Malik] ia berkata; \"Dulu, ketika kami di Madinah, bila sang muadzin telah mengumandangkan adzan Maghrib, maka para sahabat segera mendekati tiang-tiang masjid lalu mereka melaksanakan shalat dua rakaat-dua rakaat, sampai sekiranya ada orang asing masuk masjid, niscaya akan menyangka bahwa shalat telah ditunaikan karena banyaknya orang yang melakukannya.\""},"1303":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ وَوَكِيعٌ عَنْ كَهْمَسٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ الْمُزَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ كُلِّ أَذَانَيْنِ صَلَاةٌ قَالَهَا ثَلَاثًا قَالَ فِي الثَّالِثَةِ لِمَنْ شَاءَو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ إِلَّا أَنَّهُ قَالَ فِي الرَّابِعَةِ لِمَنْ شَاءَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dan [Waki'] dari [Kahmas] ia berkata, telah menceritakan kepada kami [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal Al Muzani] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diantara setiap dua adzan itu ada shalat tathawwu'.\" Beliau mengulanginya hingga tiga kali. Dan pada kali yang ketiga beliau bersabda: \"Bagi siapa saja yang mau mengerjakannya.\" Dan telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] dari [Al Jurairi] dari [Abdullah bin Buraidah] dari [Abdullah bin Mughaffal] dari Nabi shallallahu 'alaihi wasallam semisalnya. Hanya saja ia mengatakan; Pada kali yang keempat, \"Bagi siapa yang mau.\""},"1304":{"ar":"حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ بِإِحْدَى الطَّائِفَتَيْنِ رَكْعَةً وَالطَّائِفَةُ الْأُخْرَى مُوَاجِهَةُ الْعَدُوِّ ثُمَّ انْصَرَفُوا وَقَامُوا فِي مَقَامِ أَصْحَابِهِمْ مُقْبِلِينَ عَلَى الْعَدُوِّ وَجَاءَ أُولَئِكَ ثُمَّ صَلَّى بِهِمْ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَةً ثُمَّ سَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ قَضَى هَؤُلَاءِ رَكْعَةً وَهَؤُلَاءِ رَكْعَةًو حَدَّثَنِيهِ أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا فُلَيْحٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ أَبِيهِ أَنَّهُ كَانَ يُحَدِّثُ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْخَوْفِ وَيَقُولُ صَلَّيْتُهَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْمَعْنَى","id":"Telah menceritakan kepada kami [Abdu bin Humaid] telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah shalat Khauf bersama kami. Mula-mula satu kelompok pasukan mengikuti beliau shalat satu raka'at, sedangkan kelompok yang lain berjaga-jaga menghadap ke arah musuh. Setelah selesai satu raka'at, kelompok pertama pergi berjaga-jaga, menggantikan kelompok kedua, sedangkan kelompok kedua shalat bersama Rasulullah shallallahu 'alaihi wasallam. Kemudian setelah Rasulullah shallallahu 'alaihi wasallam selesai shalat, masing-masing rombongan menyempurnakan shalat mereka satu raka'at lagi.\" Dan telah menceritakannya kepadaku [Abu Rabi' Az Zhahrani] telah menceritakan kepada kami [Fulaih] dari [Az Zuhri] dari [Salim bin Abdullah bin Umar] dari [bapaknya] bahwa ia menceritakan tentang shalat Khauf Rasulullah shallallahu 'alaihi wasallam. Dan ia berkata; Saya pernah shalat Khauf bersama Rasulullah shallallahu 'alaihi wasallam. Yakni semakna dengan ini."},"1305":{"ar":"و حَدَّثَنَا أ��بُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فِي بَعْضِ أَيَّامِهِ فَقَامَتْ طَائِفَةٌ مَعَهُ وَطَائِفَةٌ بِإِزَاءِ الْعَدُوِّ فَصَلَّى بِالَّذِينَ مَعَهُ رَكْعَةً ثُمَّ ذَهَبُوا وَجَاءَ الْآخَرُونَ فَصَلَّى بِهِمْ رَكْعَةً ثُمَّ قَضَتْ الطَّائِفَتَانِ رَكْعَةً رَكْعَةًقَالَ وَقَالَ ابْنُ عُمَرَ فَإِذَا كَانَ خَوْفٌ أَكْثَرَ مِنْ ذَلِكَ فَصَلِّ رَاكِبًا أَوْ قَائِمًا تُومِئُ إِيمَاءً","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan] dari [Musa bin Uqbah] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Pada suatu hari Rasulullah shallallahu 'alaihi wasallam pernah mengimami shalat khauf. Mula-mula beliau shalat satu raka'at dengan satu kelompok pasukan, sedangkan pasukan yang lain berjaga-jaga menghadapi musuh. Usai satu raka'at, kelompok pertama berjaga-jaga dan kelompok kedua shalat mengikuti Rasulullah shallallahu 'alaihi wasallam satu raka'at. Sesudah itu, masing-masing kelompok menyempurnakan shalat mereka satu raka'at lagi.\" Ibnu Umar berkata, \"Apabila situasi kemanan lebih parah dari itu, maka beliau shalat di atas kendaraan atau sambil berdiri, dengan cara menggunakan isyarat (kepala atau mata).\""},"1306":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فَصَفَّنَا صَفَّيْنِ صَفٌّ خَلْفَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْعَدُوُّ بَيْنَنَا وَبَيْنَ الْقِبْلَةِ فَكَبَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَبَّرْنَا جَمِيعًا ثُمَّ رَكَعَ وَرَكَعْنَا جَمِيعًا ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَرَفَعْنَا جَمِيعًا ثُمَّ انْحَدَرَ بِالسُّجُودِ وَالصَّفُّ الَّذِي يَلِيهِ وَقَامَ الصَّفُّ الْمُؤَخَّرُ فِي نَحْرِ الْعَدُوِّ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السُّجُودَ وَقَامَ الصَّفُّ الَّذِي يَلِيهِ انْحَدَرَ الصَّفُّ الْمُؤَخَّرُ بِالسُّجُودِ وَقَامُوا ثُمَّ تَقَدَّمَ الصَّفُّ الْمُؤَخَّرُ وَتَأَخَّرَ الصَّفُّ الْمُقَدَّمُ ثُمَّ رَكَعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكَعْنَا جَمِيعًا ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ وَرَفَعْنَا جَمِيعًا ثُمَّ انْحَدَرَ بِالسُّجُودِ وَالصَّفُّ الَّذِي يَلِيهِ الَّذِي كَانَ مُؤَخَّرًا فِي الرَّكْعَةِ الْأُولَى وَقَامَ الصَّفُّ الْمُؤَخَّرُ فِي نُحُورِ الْعَدُوِّ فَلَمَّا قَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السُّجُودَ وَالصَّفُّ الَّذِي يَلِيهِ انْحَدَرَ الصَّفُّ الْمُؤَخَّرُ بِالسُّجُودِ فَسَجَدُوا ثُمَّ سَلَّمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَلَّمْنَا جَمِيعًا قَالَ جَابِرٌ كَمَا يَصْنَعُ حَرَسُكُمْ هَؤُلَاءِ بِأُمَرَائِهِمْ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Abdul Malik bin Abu Sulaiman] dari [Atha`] dari [Jabir bin Abdullah] ia berkata; \"Aku pernah ikut menunaikan shalat Khauf bersama Rasulullah shallallahu 'alaihi wasallam. Kami berbaris dua shaf di belakang Rasulullah shallallahu 'alaihi wasallam, sedangkan musuh berada tepat antara kami dan kiblat (di hadapan kami). Mula-mula Nabi shallallahu 'alaihi wasallam bertakbir, lalu kami semua ikut bertakbir. Kemudian beliau ruku' dan kami pun ikut ruku' semua. Kemudian beliau I'tidal (bangkit) dari ruku', maka kami bangkit pula semuanya. Sesudah itu, beliau turun untuk sujud bersama-sama dengan shaf yang pertama, sedangkan shaf kedua tetap berdiri untuk berjaga-jaga. Ketika Nabi shallallahu 'alaihi wasallam bersama shaf pertama telah selesai sujud dan telah berdiri, barulah shaf kedua turun untuk sujud, dan mereka terus bangun kembali. Sesudah itu, shaf kedua maju ke depan, sedangkan shaf pertama mundur. Kemudian Nabi shallallahu 'alaihi wasallam ruku' dan kami ruku' pula semuanya. Kemudian beliau bangkit dari ruku', lalu kami bangkit pula semuanya. Kemudian beliau turun untuk sujud diikuti oleh shaf yang berada di belakang beliau. Sedangkan shaf yang setelahnya (tadinya shaf pertama) tetap berdiri untuk berjaga-jaga ke arah musuh. Ketika Nabi shallallahu 'alaihi wasallam dan shaf yang berada di belakangnya telah selesai sujud, barulah shaf yang kedua turun untuk sujud. Kemudian Nabi shallallahu 'alaihi wasallam mengucapkan salam, dan kami pun mengucapkan salam semuanya.\" Jabir berkata; Sebagaimana yang dilakukan oleh para penjaga kalian bersama para pemimpinnya."},"1307":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ يُونُسَ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَغَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْمًا مِنْ جُهَيْنَةَ فَقَاتَلُونَا قِتَالًا شَدِيدًا فَلَمَّا صَلَّيْنَا الظُّهْرَ قَالَ الْمُشْرِكُونَ لَوْ مِلْنَا عَلَيْهِمْ مَيْلَةً لَاقْتَطَعْنَاهُمْ فَأَخْبَرَ جِبْرِيلُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَلِكَ فَذَكَرَ ذَلِكَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَقَالُوا إِنَّهُ سَتَأْتِيهِمْ صَلَاةٌ هِيَ أَحَبُّ إِلَيْهِمْ مِنْ الْأَوْلَادِ فَلَمَّا حَضَرَتْ الْعَصْرُ قَالَ صَفَّنَا صَفَّيْنِ وَالْمُشْرِكُونَ بَيْنَنَا وَبَيْنَ الْقِبْلَةِ قَالَ فَكَبَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَبَّرْنَا وَرَكَعَ فَرَكَعْنَا ثُمَّ سَجَدَ وَسَجَدَ مَعَهُ الصَّفُّ الْأَوَّلُ فَلَمَّا قَامُوا سَجَدَ الصَّفُّ الثَّانِي ثُمَّ تَأَخَّرَ الصَّفُّ الْأَوَّلُ وَتَقَدَّمَ الصَّفُّ الثَّانِي فَقَامُوا مَقَامَ الْأَوَّلِ فَكَبَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَبَّرْنَا وَرَكَعَ فَرَكَعْنَا ثُمَّ سَجَدَ مَعَهُ الصَّفُّ الْأَوَّلُ وَقَامَ الثَّانِي فَلَمَّا سَجَدَ الصَّفُّ الثَّانِي ثُمَّ جَلَسُوا جَمِيعًا سَلَّمَ عَلَيْهِمْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو الزُّبَيْرِ ثُمَّ خَصَّ جَابِرٌ أَنْ قَالَ كَمَا يُصَلِّي أُمَرَاؤُكُمْ هَؤُلَاءِ","id":"Telah menceritakan kepada kami [Ahmad bin Abdullah bin Yunus] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Abu Zubair] dari [Jabir] ia berkata; Kami pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam menghadapi orang-orang Juhainah. Mereka menyerang kami dengan serangan yang dahsyat. Ketika kami menunaikan shalat Zhuhur, orang-orang musyrik itu berkata, \"Seandainya kita menyerang mereka, pasti kita akan mengalahkan mereka.\" Maka Malaikat Jibril memberitahukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam pun memberitakannya kepada kami. Para sahabat mengatakan bahwa akan tiba kepada mereka suatu shalat yang lebih mereka senangi daripada anak-anak. Ketika waktu Asar tiba, beliau membariskan kami untuk shalat dalam dua shaf, sementara orang-orang musyrik berada di antara kami dan kiblat. Lalu Rasulullah shallallahu 'alaihi wasallam bertakbir, dan kami pun ikut bertakbir. Beliau ruku' kami pun ruku'. Kemudian beliau sujud, kami pun sujud. Lalu shaf pertama mundur dan shaf kedua maju (tukar posisi) untuk berdiri di tempat shaf pertama. Kemudian Rasulullah shallallahu 'alaihi wasallam bertakbir, kami ikut bertakbir, dan beliau ruku' kami pun ruku', lalu beliau sujud dengan diikuti shaf pertama sedangkan shaf kedua tetap berdiri. Setelah shaf kedua sujud, kemudian mereka semuanya duduk, maka Rasulullah shallallahu 'alaihi wasallam mengucapkan salam.\" Abu Zubair berkata; Jabir mengkhususkan, \"Sebagaimana shalaf (Khauf) yang dilakukan oleh para pemimpin kalian.\""},"1308":{"ar":"حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ صَالِحِ بْنِ خَوَّاتِ بْنِ جُبَيْرٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى بِأَصْحَابِهِ فِي الْخَوْفِ فَصَفَّهُمْ خَلْفَهُ صَفَّيْنِ فَصَلَّى بِالَّذِينَ يَلُونَهُ رَكْعَةً ثُمَّ قَامَ فَلَمْ يَزَلْ قَائِمًا حَتَّى صَلَّى الَّذِينَ خَلْفَهُمْ رَكْعَةً ثُمَّ تَقَدَّمُوا وَتَأَخَّرَ الَّذِينَ كَانُوا قُدَّامَهُمْ فَصَلَّى بِهِمْ رَكْعَةً ثُمَّ قَعَدَ حَتَّى صَلَّى الَّذِينَ تَخَلَّفُوا رَكْعَةً ثُمَّ سَلَّمَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al 'Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari [Abdurrahman bin Qasim] dari [bapaknya] dari [Shalih bin Khawwat bin Jubair] dari [Sahl bin Abu Hatsmah] bahwasanya; Rasulullah shallallahu 'alaihi wasallam pernah shalat Khauf bersama para sahabatnya. Maka beliau membariskan mereka menjadi dua shaf di belakangnya. Kemudian beliau shalat satu raka'at bersama shaf yang tepat berada di belakang beliau. Setelah menunaikan satu raka'at, mereka pun berdiri dan terus berdiri, hingga shaf kedua selesai shalat satu raka'at. Setelah shaf kedua selesai shalat raka'at, mereka maju ke depan sementara shaf yang tadinya di depan mundur, maka beliau shalaf bersama mereka satu raka'at. Kemudian beliau duduk hingga shaf yang dibelakang shalat satu raka'at, setelah itu baru beliau salam.\""},"1309":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ صَالِحِ بْنِ خَوَّاتٍ عَمَّنْ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ ذَاتِ الرِّقَاعِ صَلَاةَ الْخَوْفِأَنَّ طَائِفَةً صَفَّتْ مَعَهُ وَطَائِفَةٌ وِجَاهَ الْعَدُوِّ فَصَلَّى بِالَّذِينَ مَعَهُ رَكْعَةً ثُمَّ ثَبَتَ قَائِمًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ انْصَرَفُوا فَصَفُّوا وِجَاهَ الْعَدُوِّ وَجَاءَتْ الطَّائِفَةُ الْأُخْرَى فَصَلَّى بِهِمْ الرَّكْعَةَ الَّتِي بَقِيَتْ ثُمَّ ثَبَتَ جَالِسًا وَأَتَمُّوا لِأَنْفُسِهِمْ ثُمَّ سَلَّمَ بِهِمْ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Yazid bin Ruman] dari [Shalih bin Khawwat] dari [seorang] yang pernah shalat Khauf bersama Rasulullah shallallahu 'alaihi wasallam pada hari Dzatur Riqa'. Bahwa satu kelompok berbaris satu shaf di belakang beliau, sementara kelompok yang lain berjaga-jaga dengan menghadap ke arah musuh. Maka beliau pun shalat satu raka'at bersama kelompok pertama, kemudian beliau berdiri dan tetap berdiri, lalu kelompok pertama tadi menyempurnakan shalatnya masing-masing dan bubar kemudian membuat shaf untuk menghadapi musuh. Setelah itu, datanglah kelompok kedua sehingga beliau shalat bersama mereka satu raka'at, kemudian beliau duduk, sementara mereka menyempurnakan shalatnya masing-masing, baru kemudian beliau salam bersama mereka."},"1310":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ قَالَأَقْبَلْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى إِذَا كُنَّا بِذَاتِ الرِّقَاعِ قَالَ كُنَّا إِذَا أَتَيْنَا عَلَى شَجَرَةٍ ظَلِيلَةٍ تَرَكْنَاهَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَجَاءَ رَجُلٌ مِنْ الْمُشْرِكِينَ وَسَيْفُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُعَلَّقٌ بِشَجَرَةٍ فَأَخَذَ سَيْفَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرَطَهُ فَقَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَخَافُنِي قَالَ لَا قَالَ فَمَنْ يَمْنَعُكَ مِنِّي قَالَ اللَّهُ يَمْنَعُنِي مِنْكَ قَالَ فَتَهَدَّدَهُ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَغْمَدَ السَّيْفَ وَعَلَّقَهُ قَالَ فَنُودِيَ بِالصَّلَاةِ فَصَلَّى بِطَائِفَةٍ رَكْعَتَيْنِ ثُمَّ تَأَخَّرُوا وَصَلَّى بِالطَّائِفَةِ الْأُخْرَى رَكْعَتَيْنِ قَالَ فَكَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعُ رَكَعَاتٍ وَلِلْقَوْمِ رَكْعَتَانِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban bin Yazid] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Jabir] ia berkata; Kami berangkat bersama Rasulullah shallallahu 'alaihi wasallam hingga sampailah kami di Dzatur Riqa'. Biasanya, bila kami mendapati sebatang pohon yang bisa digunakan untuk berteduh, maka kami menjadikannya sebagai tempat peristirahatan Rasulullah shallallahu 'alaihi wasallam. Di kala itu, datanglah seorang laki-laki dari kaum musyrikin, sementara pedang Rasulullah shallallahu 'alaihi wasallam tergantung di pohon. Maka laki-laki musyrik itu pun mengambil pedang Rasulullah shallallahu 'alaihi wasallam dan menghunuskannya seraya berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Apakah kamu takut padaku?\" beliau menjawab: \"Tidak.\" Laki-laki itu bertanya lagi, \"Lalu siapa yang akan menolongmu dari ancamanku?\" beliau menjawab: \"Allah-lah yang akan menolongku dari ancamanmu.\" Lalu para sahabat pun menakuti-nakutinya hingga ia memasukkan kembali pedang itu ke dalam sarungnya dan menggantungnya. Setelah itu, dikumandangkanlah adzan untuk mengerjakan shalat. Maka mula-mula beliau shalat dengan satu kelompok sebanyak dua raka'at, setelah itu, mereka pun mundur. Kemudian datanglah kelompok lain dan shalat bersama beliau dua raka'at. Sehingga Rasulullah shallallahu 'alaihi wasallam mengerjakannya empat raka'at, sementara masing-masing kelompok dua raka'at."},"1311":{"ar":"و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى يَعْنِي ابْنَ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ وَهُوَ ابْنُ سَلَّامٍ أَخْبَرَنِي يَحْيَى أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ جَابِرًا أَخْبَرَهُأَنَّهُ صَلَّى مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَاةَ الْخَوْفِ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِإِحْدَى الطَّائِفَتَيْنِ رَكْعَتَيْنِ ثُمَّ صَلَّى بِالطَّائِفَةِ الْأُخْرَى رَكْعَتَيْنِ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَ رَكَعَاتٍ وَصَلَّى بِكُلِّ طَائِفَةٍ رَكْعَتَيْنِ","id":"Dan telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Yahya] -yaitu putranya Hassan- telah menceritakan kepada kami [Mu'awiyah] -yaitu putranya Sallam- telah mengabarkan kepadaku [Yahya] telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] bahwa [Jabir] telah mengabarkan kepadanya, bahwasanya; Dia pernah shalat Khauf bersama Rasulullah shallallahu 'alaihi wasallam. Mula-mula beliau shalat dua rakaat bersama dengan salah satu dari dua pasukan. Kemudian beliau shalat dua raka'at pula dengan pasukan yang lain. Sehingga beliau shallallahu 'alaihi wasallam mengerjakan shalat empat raka'at, dimana beliau mengerjakan shalat bersama masing-masing pasukan sebanyak dua raka'at."},"1312":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ وَمُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ قَالَا أَخْبَرَنَا اللَّيْثُ ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا أَرَادَ أَحَدُكُمْ أَنْ يَأْتِيَ الْجُمُعَةَ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dan [Muhammad bin Rumh bin Al Muhajir] keduanya berkata, telah mengabarkan kepada kami [Laits] -dalam jalur lain- Dan telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Abdullah] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian hendak menunaikan shalat Jum'at, hendaklah ia mandi terlebih dahulu.\""},"1313":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا ابْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ وَهُوَ قَائِمٌ عَلَى الْمِنْبَرِ مَنْ جَاءَ مِنْكُمْ الْجُمُعَةَ فَلْيَغْتَسِلْو حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ سَالِمٍ وَعَبْدِ اللَّهِ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Laits] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Rumh] telah mengabarkan kepada kami [Laits] dari [Ibnu Syihab] dari [Abdullah bin Abdullah bin Umar] dari [Abdullah bin Umar] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda disaat berada di atas mimbar: \"Barangsiapa di antara kalian ingin mendatangi shalat Jum'at hendaklah ia mandi.\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ibnu Syihab] dari [Salim] dan [Abdullah] -keduanya adalah anak Abdullah bin Umar- dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan hadits semisalnya. Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [bapaknya] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda. Yakni dengan hadits yang serupa."},"1314":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ حَدَّثَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ عَنْ أَبِيهِ أَنَّ عُمَرَ بْنَ الْخَطَّابِ بَيْنَا هُوَ يَخْطُبُ النَّاسَ يَوْمَ الْجُمُعَةِ دَخَلَ رَجُلٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَادَاهُ عُمَرُ أَيَّةُ سَاعَةٍ هَذِهِ فَقَالَ إِنِّي شُغِلْتُ الْيَوْمَ فَلَمْ أَنْقَلِبْ إِلَى أَهْلِي حَتَّى سَمِعْتُ النِّدَاءَ فَلَمْ أَزِدْ عَلَى أَنْ تَوَضَّأْتُقَالَ عُمَرُ وَالْوُضُوءَ أَيْضًا وَقَدْ عَلِمْتَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْمُرُ بِالْغُسْلِ","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah menceritakan kepadaku [Salim bin Abdullah] dari [bapaknya] bahwa; Ketika [Umar bin Al Khaththab] sedang berkhuthbah pada hari jum'at dihadapan jama'ah, masuklah seorang laki-laki dari sahabat Rasulullah shallallahu 'alaihi wasallam, lalu Umar pun memanggilnya seraya bertanya, \"Sudah jam berapakah ini?\" Laki-laki itu menjawab, \"Aku sangat sibuk hari ini. Aku tidak sempat pulang, sehingga ketika kedengaran adzan, tidak ada yang dapat aku lakukan kecuali berwudlu.\" Umar berkata, \"Engkau hanya berwudlu?. Bukankah Engkau tahu bahwa Rasulullah shallallahu 'alaihi wasallam juga memerintahkan untuk mandi?\""},"1315":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي يَحْيَى بْنُ أَبِي كَثِيرٍ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنِي أَبُو هُرَيْرَةَ قَالَ بَيْنَمَا عُمَرُ بْنُ الْخَطَّابِ يَخْطُبُ النَّاسَ يَوْمَ الْجُمُعَةِ إِذْ دَخَلَ عُثْمَانُ بْنُ عَفَّانَ فَعَرَّضَ بِهِ عُمَرُ فَقَالَ مَا بَالُ رِجَالٍ يَتَأَخَّرُونَ بَعْدَ النِّدَاءِ فَقَالَ عُثْمَانُ يَا أَمِيرَ الْمُؤْمِنِينَ مَا زِدْتُ حِينَ سَمِعْتُ النِّدَاءَ أَنْ تَوَضَّأْتُ ثُمَّ أَقْبَلْتُفَقَالَ عُمَرُ وَالْوُضُوءَ أَيْضًا أَلَمْ تَسْمَعُوا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا جَاءَ أَحَدُكُمْ إِلَى الْجُمُعَةِ فَلْيَغْتَسِلْ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] ia berkata, telah menceritakan kepadaku [Yahya bin Abu Katsir] telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] telah menceritakan kepadaku [Abu Hurairah] ia berkata; Ketika [Umar bin Al Khathab] berkhutbah di hadapan manusia pada hari Jum'at, tiba-tiba masuklah Utsman bin Affan, maka Umar pun memanggilnya seraya bertanya, \"Bagaimana orang-orang pada terlambat setelah mendengar adza?\" Utsman pun menjawab, \"Wahai Amirul Mukminin, saya tidak berbuat lagi setelah mendengar adzan kecuali langsung berwudlu dan berangkat.\" Umar berkata, \"Wudlu juga harus. Tetapi, bukankan kalian telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Jika salah seorang dari kalian hendak menunaikan shalat Jum'at, hendaklah ia mandi terlebih dahulu.'\""},"1316":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْغُسْلُ يَوْمَ الْجُمُعَةِ وَاجِبٌ عَلَى كُلِّ مُحْتَلِمٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Shafwan bin Sulaim] dari [Atha` bin Yasar] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandi pada hari jum'at adalah wajib bagi setiap muhtalim (yang telah beranjak dewasa).\""},"1317":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَأَحْمَدُ بْنُ عِيسَى قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي جَعْفَرٍ أَنَّ مُحَمَّدَ بْنَ جَعْفَرٍ حَدَّثَهُ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ النَّاسُ يَنْتَابُونَ الْجُمُعَةَ مِنْ مَنَازِلِهِمْ مِنْ الْعَوَالِي فَيَأْتُونَ فِي الْعَبَاءِ وَيُصِيبُهُمْ الْغُبَارُ فَتَخْرُجُ مِنْهُمْ الرِّيحُ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْسَانٌ مِنْهُمْ وَهُوَ عِنْدِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَنَّكُمْ تَطَهَّرْتُمْ لِيَوْمِكُمْ هَذَا","id":"Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] dan [Ahmad bin Isa] keduanya berkata. Telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Amru] dari [Ubaidullah bin Ja'far] bahwa [Muhammad bin Ja'far] telah menceritakan kepadanya dari [Urwah bin Zubair] dari [Aisyah] bahwa ia berkata; \"Ada orang-orang yang bergiliran datang untuk menunaikan shalat Jum'at dari rumah-rumah mereka di pegunungan. Mereka datang dengan memakai mantel lalu dipenuhi debu (hingga berbau tidak sedap). Beberapa orang di antara mereka mendatangi Rasulullah shallallahu 'alaihi wasallam yang ketika itu beliau berada di dekatku. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda kepada mereka: \"Alangkah baiknya, jika kalian pada hari ini mandi yang bersih.\""},"1318":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْكَانَ النَّاسُ أَهْلَ عَمَلٍ وَلَمْ يَكُنْ لَهُمْ كُفَاةٌ فَكَانُوا يَكُونُ لَهُمْ تَفَلٌ فَقِيلَ لَهُمْ لَوْ اغْتَسَلْتُمْ يَوْمَ الْجُمُعَةِ","id":"Dan telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [Laits] dari [Yahya bin Sa'id] dari [Amrah] dari [Aisyah] bahwa ia berkata; Dulu pada pekerja tidak memiliki pelayan hingga tubuh mereka mengeluarkan aroma yang tidak sedap, maka dikatakanlah kepada mereka, \"Sekiranya, kalian semua mandi pada hari jum'at.\""},"1319":{"ar":"و حَدَّثَنَا عَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنَا عَمْرُو بْنُ الْحَارِثِ أَنَّ سَعِيدَ بْنَ أَبِي هِلَالٍ وَبُكَيْرَ بْنَ الْأَشَجِّ حَدَّثَاهُ عَنْ أَبِي بَكْرِ بْنِ الْمُنْكَدِرِ عَنْ عَمْرِو بْنِ سُلَيْمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ غُسْلُ يَوْمِ الْجُمُعَةِ عَلَى كُلِّ مُحْتَلِمٍ وَسِوَاكٌ وَيَمَسُّ مِنْ الطِّيبِ مَا قَدَرَ عَلَيْهِإِلَّا أَنَّ بُكَيْرًا لَمْ يَذْكُرْ عَبْدَ الرَّحْمَنِ وَقَالَ فِي الطِّيبِ وَلَوْ مِنْ طِيبِ الْمَرْأَةِ","id":"Dan telah menceritakan kepada kami [Amru bin Sawwad Al Amiri] telah menceritakan kepada kami [Abdullah bin Wahb] telah mengabarkan kepada kami [Amru bin Harits] bahwa [Sa'id bin Abu Hilal] dan [Bukair bin Al Asyaj] keduanya telah menceritakan kepadanya dari [Abu Bakr bin Al Munkadir] dari [Amru bin Sulaim] dari [Abdurrahman bin Abu Sa'id Al Khudri] dari [bapaknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mandi pada hari jum'at adalah wajib bagi setiap muslim yang muhtalim (telah dewasa). Begitu pula menggosok gigi, memakai wewangian sekedar yang dapat ia lakukan.\" Kemudian Bukair tidak menyebutkan Abdurrahman. Dan ia berkata, berkenaan dengan wewangian; \"Meskipun dengan wewangian wanita.\""},"1320":{"ar":"حَدَّثَنَا حَسَنٌ الْحُلْوَانِيُّ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا ابْنُ جُرَيْجٍ ح و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي إِبْرَاهِيمُ بْنُ مَيْسَرَةَ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍأَنَّهُ ذَكَرَ قَوْلَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغُسْلِ يَوْمَ الْجُمُعَةِقَالَ طَاوُسٌ فَقُلْتُ لِابْنِ عَبَّاسٍ وَيَمَسُّ طِيبًا أَوْ دُهْنًا إِنْ كَانَ عِنْدَ أَهْلِهِ قَالَ لَا أَعْلَمُهُ و حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ ح و حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا الضَّحَّاكُ بْنُ مَخْلَدٍ كِلَاهُمَا عَنْ ابْنِ جُرَيْجٍ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Hasan Al Hulwani] telah menceritakan kepada kami [Rauh bin Ubadah] telah menceritakan kepada kami [Ibnu Juraij] -dalam jalur lain- Dan telah menceritakan kepadaku [Muhammad bin Rafi'] Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ibrahim bin Maisarah] dari [Thawus] dari [Ibnu Abbas] bahwa ia menyebutkan sabda Nabi shallallahu 'alaihi wasallam mengenai mandi pada hari Jum'at. [Thawus] berkata; Lalu saya bertanya kepada [Ibnu Abbas], \"Apakah beliau memakai wewangian atau minyak wangi saat berada bersama keluarganya?\" Ibnu Abbas menjawab, \"Saya tidak tahu.\" Dan telah menceritakannya kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Muhammad bin Bakar] -dalam jalur lain- Dan Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Adl Dlahhak bin Makhlad] keduanya dari [Ibnu Juraij] dengan isnad ini."},"1321":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حَقٌّ لِلَّهِ عَلَى كُلِّ مُسْلِمٍ أَنْ يَغْتَسِلَ فِي كُلِّ سَبْعَةِ أَيَّامٍ يَغْسِلُ رَأْسَهُ وَجَسَدَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Abdullah bin Thawus] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Merupakan hak Allah atas setiap muslim untuk mandi di setiap tujuh hari, dengan mencuci kepala dan seluruh badannya.\""},"1322":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ فِيمَا قُرِئَ عَلَيْهِ عَنْ سُمَيٍّ مَوْلَى أَبِي بَكْرٍ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْتَسَلَ يَوْمَ الْجُمُعَةِ غُسْلَ الْجَنَابَةِ ثُمَّ رَاحَ فَكَأَنَّمَا قَرَّبَ بَدَنَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّانِيَةِ فَكَأَنَّمَا قَرَّبَ بَقَرَةً وَمَنْ رَاحَ فِي السَّاعَةِ الثَّالِثَةِ فَكَأَنَّمَا قَرَّبَ كَبْشًا أَقْرَنَ وَمَنْ رَاحَ فِي السَّاعَةِ الرَّابِعَةِ فَكَأَنَّمَا قَرَّبَ دَجَاجَةً وَمَنْ رَاحَ فِي السَّاعَةِ الْخَامِسَةِ فَكَأَنَّمَا قَرَّبَ بَيْضَةً فَإِذَا خَرَجَ الْإِمَامُ حَضَرَتْ الْمَلَائِكَةُ يَسْتَمِعُونَ الذِّكْرَ","id":"Dan Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] -sesuai yang telah dibacakan kepadanya- dari [Sumayy] Maula Abu Bakar, dari [Abu Shalih As Samman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang mandi seperti mandi janabah pada hari jum'at, kemudian ia pergi ke masjid pada waktu yang pertama, maka pahalanya seperti pahala berkurban seekor unta. Siapa yang pergi ke masjid pada waktu kedua, maka pahalanya seperti berkorban seekor sapi. Dan siapa yang pergi ke masjid pada waktu yang ketiga, maka pahalanya seperti berkurban seekor kambing. Dan siapa yang pergi ke masjid pada waktu yang keempat, maka pahalanya seperti pahala berkorban dengan seekor ayam. Dan siapa yang tiba di masjid pada waktu yang kelima, maka pahalanya seperti berkurban sebutir telur. Apabila imam telah keluar, para malaikat hadir untuk mendengarkan khutbah (dan tidak ada lagi yang mencatat setelah itu).\""},"1323":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ رُمْحِ بْنِ الْمُهَاجِرِ قَالَ ابْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قُلْتَ لِصَاحِبِكَ أَنْصِتْ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغَوْتَو حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ عَبْدِ اللَّهِ بْنِ إِبْرَاهِيمَ بْنِ قَارِظٍ وَعَنْ ابْنِ الْمُسَيَّبِ أَنَّهُمَا حَدَّثَاهُ أَنَّ أَبَا هُرَيْرَةَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِهِ و حَدَّثَنِيهِ مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ شِهَابٍ بِالْإِسْنَادَيْنِ جَمِيعًا فِي هَذَا الْحَدِيثِ مِثْلَهُ غَيْرَ أَنَّ ابْنَ جُرَيْجٍ قَالَ إِبْرَاهِيمُ بْنُ عَبْدِ اللَّهِ بْنِ قَارِظٍ","id":"Dan Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin Rumh bin Muhajir] -[Ibnu Rumh]- berkata, telah mengabarkan kepada kami [Laits] dari [Uqail] dari [Ibnu Syihab] telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa [Abu Hurairah] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bila kamu berkata kepada temanmu, 'Diamlah, ' pada hari jum'at padahal Imam sedang berkhutbah, maka sungguh telah sia-sialah ibadah Jum'atmu.\" Dan telah menceritakan kepadaku [Abdul Malik bin Syu'aib bin Laits] telah menceritakan kepadaku [bapakku] dari [kakekku] Uqail bin Khalid, dari [Ibnu Syihab] dari [Umar bin Abdul Aziz] dari [Abdullah bin Ibrahim bin Qarizh] dan dari [Ibnul Musayyab] bahwa keduanya telah menceritakan kepadanya bahwa [Abu Hurairah] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda. Yakni dengan hadits semisalnya. Dan telah menceritakannya kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Muhammad bin Bakr] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ibnu Syihab] dengan dua sanad, yakni semua yang terdapat dalam haditsnya ini adalah serupa dengannya. Hanya saja [Ibnu Juraij] berkata; [Ibrahim bin Abdullah bin Qarizh]."},"1324":{"ar":"و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا قُلْتَ لِصَاحِبِكَ أَنْصِتْ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ فَقَدْ لَغِيتَقَالَ أَبُو الزِّنَادِ هِيَ لُغَةُ أَبِي هُرَيْرَةَ وَإِنَّمَا هُوَ فَقَدْ لَغَوْتَ","id":"Dan Telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila kamu mengatakan kepada temanmu pada hari Jum'at, 'Diamlah, ' padahal Imam sedang berkhutbah, maka sungguh kamu telah berbuat kesia-siaan.\" Abu Zinad berkata; Kata, 'FAQAD LAGHIITA' adalah menurut bahasanya Abu Hurairah, namun yang benar adalah, 'FAQAD LAGHAUTA.'"},"1325":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ ح و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَ يَوْمَ الْجُمُعَةِ فَقَالَ فِيهِ سَاعَةٌ لَا يُوَافِقُهَا عَبْدٌ مُسْلِمٌ وَهُوَ يُصَلِّي يَسْأَلُ اللَّهَ شَيْئًا إِلَّا أَعْطَاهُ إِيَّاهُزَادَ قُتَيْبَةُ فِي رِوَايَتِهِ وَأَشَارَ بِيَدِهِ يُقَلِّلُهَا","id":"Dan Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] -dalam jalur lain- Dan Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam menyebutkan tentang hari Jum'at, maka beliau bersabda: \"Di dalamnya terdapat satu waktu, tidaklah seorang muslim mendapati waktu itu lalu berdoa memohon kebaikan kepada Allah, kecuali Allah akan mengabulkan permohonannya.\" Qutaibah menambahkan di dalam riwayatnya; Beliau memberikan isyarat dengan tangannya, yakni waktunya sempit."},"1326":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فِي الْجُمُعَةِ لَسَاعَةً لَا يُوَافِقُهَا مُسْلِمٌ قَائِمٌ يُصَلِّي يَسْأَلُ اللَّهَ خَيْرًا إِلَّا أَعْطَاهُ إِيَّاهُ وَقَالَ بِيَدِهِ يُقَلِّلُهَا يُزَهِّدُهَاحَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ ابْنِ عَوْنٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ و حَدَّثَنِي حُمَيْدُ بْنُ مَسْعَدَةَ الْبَاهِلِيُّ حَدَّثَنَا بِشْرٌ يَعْنِي ابْنَ مُفَضَّلٍ حَدَّثَنَا سَلَمَةُ وَهُوَ ابْنُ عَلْقَمَةَ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Isma'il bin Ibrahim] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Abu Hurairah] ia berkata; Abul Qasim shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya pada hari Jum'at terdapat satu waktu, tidaklah seorang mukmin mendapati saat itu dengan berdo'a, memohon kebaikan kepada Allah, kecuali Allah akan mengabulkan permohonannya.\" Kemudian beliau memberikan isyarat dengan tangannya, yakni mempersempitnya. Telah menceritakan kepada kami [Ibnul Mutsanna] Telah menceritakan kepada kami [Ibnu Abu Adi] dari [Ibnu Aun] dari [Muhammad] dari [Abu Hurairah] ia berkata; Abul Qasim shallallahu 'alaihi wasallam bersabda: Yakni dengan hadits semisalnya. Dan telah menceritakan kepadaku [Humaid bin Mas'adah Al Bahili] Telah menceritakan kepada kami [Bisyr] yakni Ibnu Mufadldlal, Telah menceritakan kepada kami [Salamah bin Alqamah] dari [Muhammad] dari [Abu Hurairah] ia berkata; Abul Qasim shallallahu 'alaihi wasallam bersabda: Yakni dengan hadits yang semisalnya."},"1327":{"ar":"و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَلَّامٍ الْجُمَحِيُّ حَدَّثَنَا الرَّبِيعُ يَعْنِي ابْنَ مُسْلِمٍ عَنْ مُحَمَّدِ بْنِ زِيَادٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ فِي الْجُمُعَةِ لَسَاعَةً لَا يُوَافِقُهَا مُسْلِمٌ يَسْأَلُ اللَّهَ فِيهَا خَيْرًا إِلَّا أَعْطَاهُ إِيَّاهُ قَالَ وَهِيَ سَاعَةٌ خَفِيفَةٌو حَدَّثَنَاه مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ حَدَّثَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَمْ يَقُلْ وَهِيَ سَاعَةٌ خَفِيفَةٌ","id":"Dan Telah menceritakan kepada kami [Abdurrahman bin Sallam Al Jumahi] Telah menceritakan kepada kami [Ar Rabi'] yakni Ibnu Muslim, dari [Muhammad bin Ziyad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Sesungguhnya pada hari Jum'at terdapat satu waktu, tidaklah seorang mukmin mendapati waktu tersebut dengan berdo'a, memohon kebaikan kepada Allah, kecuali Allah akan mengabulkan permohonannya. Dan waktu itu sangatlah singkat.\" Dan telah menceritakannya kepadaku [Muhammad bin Rafi'] Telah menceritakan kepada kami [Abdurrazaq] Telah menceritakan kepada kami [Ma'mar] dari [Hammam bin Munabbih] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam; namun ia tidak mengatakan; \"Dan saat itu sangatlah sempit.\""},"1328":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَعَلِيُّ بْنُ خَشْرَمٍ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ مَخْرَمَةَ بْنِ بُكَيْرٍ ح و حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَأَحْمَدُ بْنُ عِيسَى قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا مَخْرَمَةُ عَنْ أَبِيهِ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى الْأَشْعَرِيِّ قَالَقَالَ لِي عَبْدُ اللَّهِ بْنُ عُمَرَ أَسَمِعْتَ أَبَاكَ يُحَدِّثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَأْنِ سَاعَةِ الْجُمُعَةِ قَالَ قُلْتُ نَعَمْ سَمِعْتُهُ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هِيَ مَا بَيْنَ أَنْ يَجْلِسَ الْإِمَامُ إِلَى أَنْ تُقْضَى الصَّلَاةُ","id":"Dan telah menceritakan kepadaku [Abu Thahir] dan [Ali bin Khasyram] keduanya berkata, telah mengabarkan kepada kami [Ibnu Wahb] dari [Makhramah bin Bukair] -dalam jalur lain- Dan telah menceritakan kepada kami [Harun bin Sa'id Al Aili] dan [Ahmad bin Isa] keduanya berkata, telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami [Makhramah] dari [bapaknya] dari [Abu Burdah bin Abu Musa Al Asy'ari] ia berkata; Abdullah bin Umar bertanya padaku, \"Apakah kamu pernah mendengar [ayahmu] meriwayatkan hadits dari Rasulullah shallallahu 'alaihi wasallam perihal satu waktu (yang mustajab) pada hari Jum'at?\" Abu Burdah berkata; Saya menjawab, \"Ya, aku mendengarnya berkata: Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Waktunya ialah antara imam duduk (di mimbar) hingga selesai shalat Jum'at.\""},"1329":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ الْأَعْرَجُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ يَوْمٍ طَلَعَتْ عَلَيْهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ أُدْخِلَ الْجَنَّةَ وَفِيهِ أُخْرِجَ مِنْهَا","id":"Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abdurrahman bin Al A'raj] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik hari adalah hari Jum'at, karena pada hari itulah Adam diciptakan. Pada hari itu pula ia dimasukkan ke dalam surga dan pada hari itu pula ia dikeluarkan daripadanya.\""},"1330":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا الْمُغِيرَةُ يَعْنِي الْحِزَامِيَّ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ يَوْمٍ طَلَعَتْ عَلَيْهِ الشَّمْسُ يَوْمُ الْجُمُعَةِ فِيهِ خُلِقَ آدَمُ وَفِيهِ أُدْخِلَ الْجَنَّةَ وَفِيهِ أُخْرِجَ مِنْهَا وَلَا تَقُومُ السَّاعَةُ إِلَّا فِي يَوْمِ الْجُمُعَةِ","id":"Dan Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Al Mughirah] yakni Al Hizami, dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik hari adalah hari Jum'at, karena pada hari itulah Adam diciptakan. Pada hari itu pula ia dimasukkan ke dalam surga dan pada hari itu pula ia dikeluarkan daripadanya. Dan hari kiamat tidak terjadi kecuali pada hari Jum'at.\""},"1331":{"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ الْآخِرُونَ وَنَحْنُ السَّابِقُونَ يَوْمَ الْقِيَامَةِ بَيْدَ أَنَّ كُلَّ أُمَّةٍ أُوتِيَتْ الْكِتَابَ مِنْ قَبْلِنَا وَأُوتِينَاهُ مِنْ بَعْدِهِمْ ثُمَّ هَذَا الْيَوْمُ الَّذِي كَتَبَهُ اللَّهُ عَلَيْنَا هَدَانَا اللَّهُ لَهُ فَالنَّاسُ لَنَا فِيهِ تَبَعٌ الْيَهُودُ غَدًا وَالنَّصَارَى بَعْدَ غَدٍو حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ وَابْنِ طَاوُسٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ الْآخِرُ��نَ وَنَحْنُ السَّابِقُونَ يَوْمَ الْقِيَامَةِ بِمِثْلِهِ","id":"Dan Telah menceritakan kepada kami [Amru An Naqid] Telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita (umat Muhammad) adalah umat yang terakhir (datang ke dunia), tetapi kita adalah umat yang terdahulu (diadili) pada hari kiamat. Padahal seluruh umat telah diberi kitab sebelum kita, sedangkan kita (diberi kitab) setelah mereka. Kemudian pada hari ini, yakni hari yang telah ditetapkan oleh Allah untuk kita, Allah telah memberikan petunjuk kepada kita. Dan umat-umat lain terkait dengan hari itu adalah pengikut, bagi orang-orang Yahudi adalah esok, sementara bagi orang-orang Nasrani adalah esok lusa.\" Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dari [Abu Zinad] dari [Al A'raj] dari [Abu Hurairah] dan [Ibnu Thawus] dari [bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita (umat Muhammad) adalah umat yang terakhir (datang ke dunia), tetapi kita adalah umat yang terdahulu (diadili) pada hari kiamat.\" Yakni dengan hadits semisalnya."},"1332":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَزُهَيْرُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ الْآخِرُونَ الْأَوَّلُونَ يَوْمَ الْقِيَامَةِ وَنَحْنُ أَوَّلُ مَنْ يَدْخُلُ الْجَنَّةَ بَيْدَ أَنَّهُمْ أُوتُوا الْكِتَابَ مِنْ قَبْلِنَا وَأُوتِينَاهُ مِنْ بَعْدِهِمْ فَاخْتَلَفُوا فَهَدَانَا اللَّهُ لِمَا اخْتَلَفُوا فِيهِ مِنْ الْحَقِّ فَهَذَا يَوْمُهُمْ الَّذِي اخْتَلَفُوا فِيهِ هَدَانَا اللَّهُ لَهُ قَالَ يَوْمُ الْجُمُعَةِ فَالْيَوْمَ لَنَا وَغَدًا لِلْيَهُودِ وَبَعْدَ غَدٍ لِلنَّصَارَى","id":"Dan Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Zuhair bin Harb] keduanya berkata, telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita (umat Muhammad) adalah yang terakhir (datang ke dunia), tetapi yang terdahulu (diadili) pada hari kiamat. Kita adalah yang paling dahulu masuk surga, padahal mereka diberi kitab lebih dahulu dari kita, sedangkan kita sesudah mereka. Lalu mereka berselisih, kemudian Allah memberikan petunjuk kepada kita, yakni kebenaran dari apa yang mereka perselisihkan. Inilah hari yang mereka perselisihkan, sedangkan Allah telah menunjukkannya kepada kita.\" Beliau bersabda lagi: \"Maka hari ini (Jum'at) adalah untuk kita. Esok (hari Sabtu) untuk kaum Yahudi, dan lusa (Ahad) untuk kaum Nasrani.\""},"1333":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ هَمَّامِ بْنِ مُنَبِّهٍ أَخِي وَهْبِ بْنِ مُنَبِّهٍ قَالَ هَذَا مَا حَدَّثَنَا أَبُو هُرَيْرَةَعَنْ مُحَمَّدٍ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْنُ الْآخِرُونَ السَّابِقُونَ يَوْمَ الْقِيَامَةِ بَيْدَ أَنَّهُمْ أُوتُوا الْكِتَابَ مِنْ قَبْلِنَا وَأُوتِينَاهُ مِنْ بَعْدِهِمْ وَهَذَا يَوْمُهُمْ الَّذِي فُرِضَ عَلَيْهِمْ فَاخْتَلَفُوا فِيهِ فَهَدَانَا اللَّهُ لَهُ فَهُمْ لَنَا فِيهِ تَبَعٌ فَالْيَهُودُ غَدًا وَالنَّصَارَى بَعْدَ غَدٍ","id":"Dan Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Hammam bin Munabbih] saudaranya Wahb bin Munabbih, ia berkata, telah menceritakan kepada kami [Abu Hurairah] dari Muhammad shallallahu 'alaihi wasallam, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita (umat Muhammad) adalah yang terakhir (datang ke dunia), tetapi yang terdahulu (diadili) pada hari kiamat. Padahal mereka diberi kitab lebih dahulu dari kita, sedangkan kita sesudah mereka. Dan hari ini (Jum'at) adalah hari yang telah diwajibkan atas mereka, namun mereka berselisih tentangnya. Kemudian Allah menunjukkannya pada kita. Karena itu, umat-umat lain terkait dengan hari Jum'at adalah pengikut. Bagi kaum Yahudi, besok. Sedangkan bagi kaum Nasrani lusa.\""},"1334":{"ar":"و حَدَّثَنَا أَبُو كُرَيْبٍ وَوَاصِلُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا ابْنُ فُضَيْلٍ عَنْ أَبِي مَالِكٍ الْأَشْجَعِيِّ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ وَعَنْ رِبْعِيِّ بْنِ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَضَلَّ اللَّهُ عَنْ الْجُمُعَةِ مَنْ كَانَ قَبْلَنَا فَكَانَ لِلْيَهُودِ يَوْمُ السَّبْتِ وَكَانَ لِلنَّصَارَى يَوْمُ الْأَحَدِ فَجَاءَ اللَّهُ بِنَا فَهَدَانَا اللَّهُ لِيَوْمِ الْجُمُعَةِ فَجَعَلَ الْجُمُعَةَ وَالسَّبْتَ وَالْأَحَدَ وَكَذَلِكَ هُمْ تَبَعٌ لَنَا يَوْمَ الْقِيَامَةِ نَحْنُ الْآخِرُونَ مِنْ أَهْلِ الدُّنْيَا وَالْأَوَّلُونَ يَوْمَ الْقِيَامَةِ الْمَقْضِيُّ لَهُمْ قَبْلَ الْخَلَائِقِوَفِي رِوَايَةِ وَاصِلٍ الْمَقْضِيُّ بَيْنَهُمْ حَدَّثَنَا أَبُو كُرَيْبٍ أَخْبَرَنَا ابْنُ أَبِي زَائِدَةَ عَنْ سَعْدِ بْنِ طَارِقٍ حَدَّثَنِي رِبْعِيُّ بْنُ حِرَاشٍ عَنْ حُذَيْفَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُدِينَا إِلَى الْجُمُعَةِ وَأَضَلَّ اللَّهُ عَنْهَا مَنْ كَانَ قَبْلَنَا فَذَكَرَ بِمَعْنَى حَدِيثِ ابْنِ فُضَيْلٍ","id":"Dan telah menceritakan kepada kami [Abu Kuraib] dan [Washil bin Abdul A'la] keduanya berkata, telah menceritakan kepada kami [Ibnu Fudlail] dari [Abu Malik Al Asyja'i] dari [Abu Hazim] dari [Abu Hurairah] dari [Rab'i bin Hirasy] dari [Hudzaifah] keduanya berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menyesatkan orang-orang yang sebelum kita tentang hari Jumat. Bagi orang Yahudi jatuhnya pada hari Sabtu, dan bagi orang Nasrani jatuhnya pada hari Ahad. Lalu Allah menunjuki kita yaitu pada hari Jum'at. Karena itu, terjadilah berturut-turut tiga hari berkumpul (hari besar), yaitu Jum'at, Sabtu dan Ahad. Hari kiamat kelak, mereka pun mengikuti kita juga, kita yang terakhir ke dunia, tetapi kitalah yang lebih dahulu diadili sebelum umat-umat yang lain.\" Sementara dalam riwayat Washil; \"Yang diadili di antara mereka.\" Telah menceritakan kepada kami [Abu Kuraib] telah mengabarkan kepada kami [Ibnu Abu Za`idah] dari [Sa'd bin Thariq] telah menceritakan kepadaku [Rib'i bin Hirasy] dari [Hudzaifah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kita ditunjukkan dengan hari Jum'at, sementara Allah telah menyesatkan umat-umat sebelum kita darinya.\" Dan ia pun menyebutkan hadits yang semakna dengan hadits Ibnu Fudlail."},"1335":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ وَعَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ قَالَ أَبُو الطَّاهِرِ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو عَبْدِ اللَّهِ الْأَغَرُّ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الْجُمُعَةِ كَانَ عَلَى كُلِّ بَابٍ مِنْ أَبْوَابِ الْمَسْجِدِ مَلَائِكَةٌ يَكْتُبُونَ الْأَوَّلَ فَالْأَوَّلَ فَإِذَا جَلَسَ الْإِمَامُ طَوَوْا الصُّحُفَ وَجَاءُوا يَسْتَمِعُونَ الذِّكْرَ وَمَثَلُ الْمُهَجِّرِ كَمَثَلِ الَّذِي يُهْدِي الْبَدَنَةَ ثُمَّ كَالَّذِي يُهْدِي بَقَرَةً ثُمَّ كَالَّذِي يُهْدِي الْكَبْشَ ثُمَّ كَالَّذِي يُهْدِي الدَّجَاجَةَ ثُمَّ كَالَّذِي يُهْدِي الْبَيْضَةَحَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَعَمْرٌو النَّاقِدُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Dan telah menceritakan kepadaku [Abu Thahir] dan [Harmalah] dan [Amru bin Sawwad Al Amiri] - [Abu Thahir] berkata- telah menceritakan kepada kami -sementara yang lain mengatakan- telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Abu Abdullah Al Agharr] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila hari Jum'at telah tiba, para Malaikat berdiri di setiap pintu Masjid, mencatat orang yang pertama-tama datang dan seterusnya. Apabila Imam telah datang (naik mimbar), maka mereka pun menutup shuhuf (buku catatan) dan bersegera untuk mendengarkan khutbah. Perumpamaan orang yang pertama-tama datang adalah seperti berkorban dengan seekor unta. Kemudian orang yang datang sesudah itu, seperti orang yang berkurban dengan seekor lembu. Kemudian seperti orang yang berkurban kibas. Kemudian seperti orang yang berkurban dengan seekor ayam. Dan kemudian seperti orang yang berkurban dengan sebutir telur.\" Telah menceritakan kepada kami [Yahya bin Yahya] dan [Amru An Naqid] dari [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1336":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا يَعْقُوبُ يَعْنِي ابْنَ عَبْدِ الرَّحْمَنِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَلَى كُلِّ بَابٍ مِنْ أَبْوَابِ الْمَسْجِدِ مَلَكٌ يَكْتُبُ الْأَوَّلَ فَالْأَوَّلَ مَثَّلَ الْجَزُورَ ثُمَّ نَزَّلَهُمْ حَتَّى صَغَّرَ إِلَى مَثَلِ الْبَيْضَةِ فَإِذَا جَلَسَ الْإِمَامُ طُوِيَتْ الصُّحُفُ وَحَضَرُوا الذِّكْرَ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Ya'qub bin Abdurrahman] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Di setiap pintu Masjid terdapat Malaikat yang akan mencatat orang yang pertama kali datang dan seterusnya. Beliau mempermisalkan mereka seperti orang berkurban dengan seekor unta, kemudian diturunkannya lagi hingga seperti seorang yang berkurban dengan sebutir telur. Dan ketika Imam telah duduk, maka shuhuf (lembaran catatan) ditutup, dan para Malaikat pun menyimak khutbah.\""},"1337":{"ar":"حَدَّثَنَا أُمَيَّةُ بْنُ بِسْطَامٍ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ حَدَّثَنَا رَوْحٌ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْتَسَلَ ثُمَّ أَتَى الْجُمُعَةَ فَصَلَّى مَا قُدِّرَ لَهُ ثُمَّ أَنْصَتَ حَتَّى يَفْرُغَ مِنْ خُطْبَتِهِ ثُمَّ يُصَلِّي مَعَهُ غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ الْأُخْرَى وَفَضْلُ ثَلَاثَةِ أَيَّامٍ","id":"Telah menceritakan kepada kami [Umayyah bin Bistham] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Rauh] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang mandi kemudian mendatangi Jum'at, lalu ia shalat semampuannya dan diam (mendengarkan khutbah) hingga selesai, kemudian ia lanjutkan dengan shalat bersama Imam, maka ia akan diampuni (dosa-dosa yang dilakukannya) antara hari itu dan hari jum'at yang lain. Dan bahkan hingga lebih tiga hari.\""},"1338":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَ يَحْيَى أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ تَوَضَّأَ فَأَحْسَنَ الْوُضُوءَ ثُمَّ أَتَى الْجُمُعَةَ فَاسْتَمَعَ وَأَنْصَتَ غُفِرَ لَهُ مَا بَيْنَهُ وَبَيْنَ الْجُمُعَةِ وَزِيَادَةُ ثَلَاثَةِ أَيَّامٍ وَمَنْ مَسَّ الْحَصَى فَقَدْ لَغَا","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] -Yahya berkata- telah mengabarkan kepada kami -sementara dua orang yang lain berkata- telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang berwudlu, lalu ia menyempurnakan wudlunya, kemudian mendatangi Jum'at, mendengarkan (khutbah) tanpa berkata-kata, maka akan diampuni (dosa-dosa yang dilakukannya) antara hari itu dengan hari jum'at yang lain, ditambah tiga hari. Dan barangsiapa yang memegang-megang batu kerikil, maka ia telah berbuat kesia-siaan.\""},"1339":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا يَحْيَى بْنُ آدَمَ حَدَّثَنَا حَسَنُ بْنُ عَيَّاشٍ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ نَرْجِعُ فَنُرِيحُ نَوَاضِحَنَا قَالَ حَسَنٌ فَقُلْتُ لِجَعْفَرٍ فِي أَيِّ سَاعَةٍ تِلْكَ قَالَ زَوَالَ الشَّمْسِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ishaq bin Ibrahim] telah menceritakan kepada kami [Yahya bin Adam] telah menceritakan kepada kami [Hasan bin Ayyasy] dari [Ja'far bin Muhammad] dari [bapaknya] dari [Jabir bin Abdullah] ia berkata; Kami pernah shalat (Jum'at) bersama Rasulullah shallallahu 'alaihi wasallam, kemudian kami pulang dan mengistirahatkan ternak kami. Hasan berkata; Saya bertanya kepada Ja'far, \"Kapankah waktunya?\" ia menjawab, \"Saat tergelincirnya matahari.\""},"1340":{"ar":"و حَدَّثَنِي الْقَاسِمُ بْنُ زَكَرِيَّاءَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ ح و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ قَالَا جَمِيعًا حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ جَعْفَرٍ عَنْ أَبِيهِ أَنَّهُ سَأَلَ جَابِرَ بْنَ عَبْدِ اللَّهِمَتَى كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي الْجُمُعَةَ قَالَ كَانَ يُصَلِّي ثُمَّ نَذْهَبُ إِلَى جِمَالِنَا فَنُرِيحُهَازَادَ عَبْدُ اللَّهِ فِي حَدِيثِهِ حِينَ تَزُولُ الشَّمْسُ يَعْنِي النَّوَاضِحَ","id":"Dan telah menceritakan kepadaku [Al Qasim bin Zakariya] telah menceritakan kepada kami [Khalid bin Makhlad] -dalam jalur lain- Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah menceritakan kepada kami [Yahya bin Hassan] keduanya berkata, telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Ja'far] dari [bapaknya] bahwa ia bertanya kepada [Jabir], \"Kapan Rasulullah shallallahu 'alaihi wasallam menunaikan shalat Jum'at?\" Ia menjawab, \"Bisanya beliau shalat Jum'at, kemudian setelah itu kami pulang ke ternak unta kami, dan mengistirahatkannya.\" Abdullah menambahkan di dalam haditsnya; \"Saat matahari tergelincir, yakni setelah unta diberi minum.\""},"1341":{"ar":"و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ وَيَحْيَى بْنُ يَحْيَى وَعَلِيُّ بْنُ حُجْرٍ قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي حَازِمٍ عَنْ أَبِيهِ عَنْ سَهْلٍ قَالَمَا كُنَّا نَقِيلُ وَلَا نَتَغَدَّى إِلَّا بَعْدَ الْجُمُعَةِزَادَ ابْنُ حُجْرٍ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Dan Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] dan [Yahya bin Yahya] dan [Ali bin Hujr] - [Yahya] berkata- telah mengabarkan kepada kami -sementara dua orang yang lain berkata- telah menceritakan kepada kami [Abdul Aziz bin Abu Hazim] dari [bapaknya] dari [Sahl] ia berkata; \"Biasanya kami tidak pernah tidur siang, dan tidak pula makan siang kecuali setelah menunaikan shalat Jum'at.\" Ibnu Hujr berkata; \"(Yakni) pada masa Rasulullah shallallahu 'alaihi wasallam.\""},"1342":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَا أَخْبَرَنَا وَكِيعٌ عَنْ يَعْلَى بْنِ الْحَارِثِ الْمُحَارِبِيِّ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَكُنَّا نُجَمِّعُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا زَالَتْ الشَّمْسُ ثُمَّ نَرْجِعُ نَتَتَبَّعُ الْفَيْءَ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Ishaq bin Ibrahim] keduanya berkata, telah mengabarkan kepada kami [Waki'] dari [Ya'la bin Al Harits Al Maharibi] dari [Iyas bin Salamah bin Al Akwa'] dari [bapaknya] ia berkata; \"Kami shalat Jum'at bersama Rasulullah shallallahu 'alaihi wasallam ketika matahari tergelincir. Setelah itu kami pulang dalam keadaan masih perlu mencari-cari naungan untuk tempat berlindung.\""},"1343":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ حَدَّثَنَا يَعْلَى بْنُ الْحَارِثِ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَكُنَّا نُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْجُمُعَةَ فَنَرْجِعُ وَمَا نَجِدُ لِلْحِيطَانِ فَيْئًا نَسْتَظِلُّ بِهِ","id":"Dan Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Hisyam bin Abdul Malik] Telah menceritakan kepada kami [Ya'la bin Harits] dari [Iyas bin Salamah bin Al Akwa'] dari [bapaknya] ia berkata; \"Kami shalat Jum'at bersama Rasulullah shallallahu 'alaihi wasallam, kemudian kami pulang namun kami tidak lagi mendapati naungan pada dinding untuk berteduh.\""},"1344":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ وَأَبُو كَامِلٍ الْجَحْدَرِيُّ جَمِيعًا عَنْ خَالِدٍ قَالَ أَبُو كَامِلٍ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ قَائِمًا ثُمَّ يَجْلِسُ ثُمَّ يَقُومُ قَالَ كَمَا يَفْعَلُونَ الْيَوْمَ","id":"Dan telah menceritakan kepada kami [Ubaidullah bin Umar Al Qawariri] dan [Abu Kamil Al Jahdari] semuanya dari [Khalid] - [Abu Kamil] berkata- telah menceritakan kepada kami [Khalid bin Harits] telah menceritakan kepada kami [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Adalah Rasulullah shallallahu 'alaihi wasallam berkhutbah pada hari Jum'at dengan berdiri kemudian beliau duduk dan berdiri lagi.\" Ibnu Umar berkata; \"Persis seperti yang dilakukan orang-orang pada hari ini.\""},"1345":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَحَسَنُ بْنُ الرَّبِيعِ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرَانِ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكَانَتْ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَتَانِ يَجْلِسُ بَيْنَهُمَا يَقْرَأُ الْقُرْآنَ وَيُذَكِّرُ النَّاسَ","id":"Dan Telah menceritakan kepada kami [Yahya bin Yahya] dan [Hasan bin Rabi'] dan [Abu Bakar bin Abu Syaibah] -Yahya berkata- telah mengabarkan kepada kami -sementara dua orang yang lain berkata- telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari [Jabir bin Samurah] ia berkata; \"Nabi shallallahu 'alaihi wasallam melakukan khutbah Jum'at dua kali, di mana beliau duduk di antara keduanya. Dalam khutbahnya beliau membaca Al Qur`an dan memberi peringatan kepada jama'ah.\""},"1346":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ سِمَاكٍ قَالَ أَنْبَأَنِي جَابِرُ بْنُ سَمُرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ قَائِمًا ثُمَّ يَجْلِسُ ثُمَّ يَقُومُ فَيَخْطُبُ قَائِمًا فَمَنْ نَبَّأَكَ أَنَّهُ كَانَ يَخْطُبُ جَالِسًا فَقَدْ كَذَبَ فَقَدْ وَاللَّهِ صَلَّيْتُ مَعَهُ أَكْثَرَ مِنْ أَلْفَيْ صَلَاةٍ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Simak] ia berkata, ia telah memberitakan kepadaku [Jabir bin Samurah] bahwasanya Rasulullah shallallahu 'alaihi wasallam berkhutbah sambil berdiri. Kemudian beliau duduk, setelah itu beliau berdiri kembali dan menyampaikan khutbah kedua. Maka barangsiapa yang memberitakan kepadamu bahwa beliau berkhutbah sambil duduk, sesungguhnya ia telah berkata dusta. Demi Allah, saya telah shalat bersama beliau lebih dari duaribu kali.\""},"1347":{"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ جَرِيرٍ قَالَ عُثْمَانُ حَدَّثَنَا جَرِيرٌ عَنْ حُصَيْن�� بْنِ عَبْدِ الرَّحْمَنِ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْطُبُ قَائِمًا يَوْمَ الْجُمُعَةِ فَجَاءَتْ عِيرٌ مِنْ الشَّامِ فَانْفَتَلَ النَّاسُ إِلَيْهَا حَتَّى لَمْ يَبْقَ إِلَّا اثْنَا عَشَرَ رَجُلًا فَأُنْزِلَتْ هَذِهِ الْآيَةُ الَّتِي فِي الْجُمُعَةِ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حُصَيْنٍ بِهَذَا الْإِسْنَادِ قَالَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ وَلَمْ يَقُلْ قَائِمًا","id":"Telah menceritakan kepada kami [Utsman bin Abu Syaibah] dan [Ishaq bin Ibrahim] keduanya dari [Jarir] - [Utsman] berkata- telah menceritakan kepada kami [Jarir] dari [Hushain bin Abdurrahman] dari [Salim bin Abul Ja'd] dari [Jabir bin Abdullah] bahwa Nabi shallallahu 'alaihi wasallam menyampaikan khutbah dengan berdiri pada hari Jum'at, tiba-tiba datanglah suatu Kafilah dagang dari negeri Syam; maka jama'ah pun berlarian menjemput Kafilah itu, hingga yang tinggal di Masjid hanya dua belas orang lagi. Maka diturunkanlah ayat ini (yakni pada surat Al Jumu'ah): \"Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya dan mereka tinggalkan kamu sedang berdiri (berkhutbah).\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Hushain] dengan isnad ini, ia berkata; Rasulullah shallallahu 'alaihi wasallam berkhutbah. -ia tidak mengatakan; berdiri."},"1348":{"ar":"و حَدَّثَنَا رِفَاعَةُ بْنُ الْهَيْثَمِ الْوَاسِطِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي الطَّحَّانَ عَنْ حُصَيْنٍ عَنْ سَالِمٍ وَأَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكُنَّا مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ فَقَدِمَتْ سُوَيْقَةٌ قَالَ فَخَرَجَ النَّاسُ إِلَيْهَا فَلَمْ يَبْقَ إِلَّا اثْنَا عَشَرَ رَجُلًا أَنَا فِيهِمْ قَالَ فَأَنْزَلَ اللَّهُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }إِلَى آخِرِ الْآيَةِ","id":"Dan Telah menceritakan kepada kami [Rifa'ah bin Al Haitsam Al Wasithi] telah menceritakan kepada kami [Khalid] yakni Ath Thahhan, dari [Hushain] dari [Salim] dan [Abu Sufyan] dari [Jabir bin Abdullah] ia berkata; Kami sedang bersama Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at, tiba-tiba datanglah suatu Kafilah dagang sehingga para jama'ah pun keluar menjemputnya hingga tidak tersisa lagi kecuali dua belas orang dan saya adalah salah seorang dari mereka. Maka Allah menurunkan ayat: \"Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya dan mereka tinggalkan kamu sedang berdiri (berkhotbah).\" Hingga akhir ayat."},"1349":{"ar":"و حَدَّثَنَا إِسْمَعِيلُ بْنُ سَالِمٍ أَخْبَرَنَا هُشَيْمٌ أَخْبَرَنَا حُصَيْنٌ عَنْ أَبِي سُفْيَانَ وَسَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَوْمَ الْجُمُعَةِ إِذْ قَدِمَتْ عِيرٌ إِلَى الْمَدِينَةِ فَابْتَدَرَهَا أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى لَمْ يَبْقَ مَعَهُ إِلَّا اثْنَا عَشَرَ رَجُلًا فِيهِمْ أَبُو بَكْرٍ وَعُمَرُ قَالَ وَنَزَلَتْ هَذِهِ الْآيَةُ{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا }","id":"Dan telah menceritakan kepada kami [Isma'il bin Salim] telah mengabarkan kepada kami [Husyaim] telah mengabarkan kepada kami [Hushaim] dari [Abu Sufyan] dan [Salim bin Abul Ja'di] dari [Jabir bin Abdullah] ia berkata; Ketika Nabi shallallahu 'alaihi wasallam berdiri menyampaikan khutbah pada hari Jum'at, tiba-tiba datanglah suatu Kafilah dagang ke Madinah, maka para sahabat Rasulullah shallallahu 'alaihi wasallam bergegas mendatanginya hingga tidak tersisa lagi orang yang bersamanya kecuali dua belas orang. Di antara mereka ada Abu Bakar dan Umar. Maka turunlah ayat ini: \"Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya.,.\""},"1350":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ أَبِي عُبَيْدَةَ عَنْ كَعْبِ بْنِ عُجْرَةَ قَالَدَخَلَ الْمَسْجِدَ وَعَبْدُ الرَّحْمَنِ ابْنُ أُمِّ الْحَكَمِ يَخْطُبُ قَاعِدًا فَقَالَ انْظُرُوا إِلَى هَذَا الْخَبِيثِ يَخْطُبُ قَاعِدًا وَقَالَ اللَّهُ تَعَالَى{ وَإِذَا رَأَوْا تِجَارَةً أَوْ لَهْوًا انْفَضُّوا إِلَيْهَا وَتَرَكُوكَ قَائِمًا }","id":"Dan Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari ['Amru bin Murrah] dari [Abu 'Ubaidah] dari [Ka'ab bin 'Ujrah], bahwa ia pernah memasuki sebuah masjid dan ketika itu Abdur Rahman bin Ummi Al Hakam menyampaikan khutbah sambil duduk, maka iapun berkata, \"Lihatlah orang yang buruk ini, ia berkhutbah sambil duduk padahal Allah Ta'ala telah berfirman: 'Dan apabila mereka melihat perniagaan atau permainan, mereka bubar untuk menuju kepadanya dan mereka tinggalkan kamu sedang berdiri (berkhotbah) …'\""},"1351":{"ar":"و حَدَّثَنِي الْحَسَنُ بْنُ عَلِيٍّ الْحُلْوَانِيُّ حَدَّثَنَا أَبُو تَوْبَةَ حَدَّثَنَا مُعَاوِيَةُ وَهُوَ ابْنُ سَلَّامٍ عَنْ زَيْدٍ يَعْنِي أَخَاهُ أَنَّهُ سَمِعَ أَبَا سَلَّامٍ قَالَ حَدَّثَنِي الْحَكَمُ بْنُ مِينَاءَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ وَأَبَا هُرَيْرَةَ حَدَّثَاهُأَنَّهُمَا سَمِعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى أَعْوَادِ مِنْبَرِهِ لَيَنْتَهِيَنَّ أَقْوَامٌ عَنْ وَدْعِهِمْ الْجُمُعَاتِ أَوْ لَيَخْتِمَنَّ اللَّهُ عَلَى قُلُوبِهِمْ ثُمَّ لَيَكُونُنَّ مِنْ الْغَافِلِينَ","id":"Dan telah menceritakan kepadaku [Al Hasan bin Ali Al Hulwani] telah menceritakan kepada kami [Abu Taubah] telah menceritakan kepada kami [Mu'awiyah] yaitu Ibnu Sallam dari [Zaid] yakni saudaranya, bahwa ia mendengar [Abu Sallam] ia berkata, telah menceritakan kepadaku [Al Hakam bin Mina`] bahwa [Abdullah bin Umar] dan [Abu Hurairah] keduanya telah menceritakan kepadanya, bahwa keduanya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbarnya: \"Hendaklah orang yang suka meninggalkan shalat Jum'at menghentikan perbuatannya, ataukah mereka ingin Allah membutakan hati mereka, dan sesudah itu mereka benar-benar menjadi orang yang lalai.\""},"1352":{"ar":"حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنْتُ أُصَلِّي مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَتْ صَلَاتُهُ قَصْدًا وَخُطْبَتُهُ قَصْدًا","id":"Telah menceritakan kepada kami [Hasan bin Rabi'] dan [Abu Bakar bin Abu Syaibah] keduanya berkata, Telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari [Jabir bin Samurah] ia berkata; Saya pernah shalat (Jum'at) bersama Rasulullah shallallahu 'alaihi wasallam, lama shalat dan khutbah beliau pertengahan (tidak terlalu panjang atau terlalu pendek)."},"1353":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ حَدَّثَنَا زَكَرِيَّاءُ حَدَّثَنِي سِمَاكُ بْنُ حَرْبٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَكُنْتُ أُصَلِّي مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَوَاتِ فَكَانَتْ صَلَاتُهُ قَصْدًا وَخُطْبَتُهُ قَصْدًاوَفِي رِوَايَةِ أَبِي بَكْرٍ زَكَرِيَّاءُ عَنْ سِمَاكٍ","id":"Dan Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] keduanya berkata, telah menceritakan kepada kami [Muhammad bin Bisyr] telah menceritakan kepada kami [Zakariya] telah menceritakan kepadaku [Simak bin Harb] dari [Jabir bin Samurah] ia berkata; \"Kami telah beberapa kali shalat (Jum'at) bersama Rasulullah shallallahu 'alaihi wasallam, maka shalat dan khutbah beliau adalah pertengahan (tidak terlalu panjang dan tidak pula terlalu pendek).\" Sementara dalam riwayat Abu Bakar bin Zakariya dari Simak."},"1354":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ بْنُ عَبْدِ الْمَجِيدِ عَنْ جَعْفَرِ بْنِ مُحَمَّدٍ عَنْ أَبِيهِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَطَبَ احْمَرَّتْ عَيْنَاهُ وَعَلَا صَوْتُهُ وَاشْتَدَّ غَضَبُهُ حَتَّى كَأَنَّهُ مُنْذِرُ جَيْشٍ يَقُولُ صَبَّحَكُمْ وَمَسَّاكُمْ وَيَقُولُ بُعِثْتُ أَنَا وَالسَّاعَةُ كَهَاتَيْنِ وَيَقْرُنُ بَيْنَ إِصْبَعَيْهِ السَّبَّابَةِ وَالْوُسْطَى وَيَقُولُ أَمَّا بَعْدُ فَإِنَّ خَيْرَ الْحَدِيثِ كِتَابُ اللَّهِ وَخَيْرُ الْهُدَى هُدَى مُحَمَّدٍ وَشَرُّ الْأُمُورِ مُحْدَثَاتُهَا وَكُلُّ بِدْعَةٍ ضَلَالَةٌ ثُمَّ يَقُولُ أَنَا أَوْلَى بِكُلِّ مُؤْمِنٍ مِنْ نَفْسِهِ مَنْ تَرَكَ مَالًا فَلِأَهْلِهِ وَمَنْ تَرَكَ دَيْنًا أَوْ ضَيَاعًا فَإِلَيَّ وَعَلَيَّو حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنِي سُلَيْمَانُ بْنُ بِلَالٍ حَدَّثَنِي جَعْفَرُ بْنُ مُحَمَّدٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُا كَانَتْ خُطْبَةُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ يَحْمَدُ اللَّهَ وَيُثْنِي عَلَيْهِ ثُمَّ يَقُولُ عَلَى إِثْرِ ذَلِكَ وَقَدْ عَلَا صَوْتُهُ ثُمَّ سَاقَ الْحَدِيثَ بِمِثْلِهِ و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ جَابِرٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ يَحْمَدُ اللَّهَ وَيُثْنِي عَلَيْهِ بِمَا هُوَ أَهْلُهُ ثُمَّ يَقُولُ مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَخَيْرُ الْحَدِيثِ كِتَابُ اللَّهِ ثُمَّ سَاقَ الْحَدِيثَ بِمِثْلِ حَدِيثِ الثَّقَفِيِّ","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Abdul Wahhab bin Abdul Majid] dari [Ja'far bin Muhammad] dari [bapaknya] dari [Jabir bin Abdullah] ia berkata, bahwasanya; Apabila Rasulullah shallallahu 'alaihi wasallam menyampaikan khutbah, maka kedua matanya memerah, suaranya lantang, dan semangatnya berkobar-kobar bagaikan panglima perang yang sedang memberikan komando kepada bala tentaranya. Beliau bersabda: \"Hendaklah kalian selalu waspada di waktu pagi dan petang. Aku diutus, sementara antara aku dan hari kiamat adalah seperti dua jari ini (yakni jari telunjuk dan jari tengah).\" Kemudian beliau melanjutkan bersabda: \"Amma ba'du. Sesungguhnya sebaik-baik perkataan adalah Kitabullah, sebaik-baik petunjuk adalah petunjuk Muhammad shallallahu 'alaihi wasallam. Seburuk-buruk perkara adalah perkara yang diada-adakan dan setiap bid'ah adalah sesat.\" Kemudian beliau bersabda: \"Aku lebih utama bagi setiap muslim daripada dirinya sendiri. Karena itu, siapa yang meninggalkan harta, maka harta itu adalah miliki keluarganya. Sedangkan siapa yang mati dengan meninggalkan hutang atau keluarga yang terlantar, maka hal itu adalah tanggungjawabku.\" Dan telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepadaku [Sulaiman bin Bilal] telah menceritakan kepadaku [Ja'far bin Muhammad] dari [bapaknya] ia berkata; Saya mendengar [Jabir bin Abdullah] berkata; Isi khutbah Nabi shallallahu 'alaihi wasallam pada hari Jum'at adalah, beliau memuji Allah, dan membaca puji-pujian atas-Nya, kemudian berliau menyampaikan khutbah dengan suara yang lantang. Kemudian ia pun menyebutkan hadits. Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Ja'far] dari [Bapaknya] dari [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam jika berkhotbah, beliau memuji Allah dan bersyukur kepadaNya kemudian beliau melanjutkan dengan kata; \"Barangsiapa yang Allah memberinya petunjuk, niscaya tidak ada yang akan menyesatkannya, dan barangsiapa yang sesat, niscaya tidak ada yang menunjukinya, dan sebaik-baik perkataan adalah Kitab Allah, \" kemudian hadits sebagaimana hadits Ats Tsaqafi."},"1355":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ الْمُثَنَّى كِلَاهُمَا عَنْ عَبْدِ الْأَعْلَى قَالَ ابْنُ الْمُثَنَّى حَدَّثَنِي عَبْدُ الْأَعْلَى وَهُوَ أَبُو هَمَّامٍ حَدَّثَنَا دَاوُدُ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ ضِمَادًا قَدِمَ مَكَّةَ وَكَانَ مِنْ أَزْدِ شَنُوءَةَ وَكَانَ يَرْقِي مِنْ هَذِهِ الرِّيحِ فَسَمِعَ سُفَهَاءَ مِنْ أَهْلِ مَكَّةَ يَقُولُونَ إِنَّ مُحَمَّدًا مَجْنُونٌ فَقَالَ لَوْ أَنِّي رَأَيْتُ هَذَا الرَّجُلَ لَعَلَّ اللَّهَ يَشْفِيهِ عَلَى يَدَيَّ قَالَ فَلَقِيَهُ فَقَالَ يَا مُحَمَّدُ إِنِّي أَرْقِي مِنْ هَذِهِ الرِّيحِ وَإِنَّ اللَّهَ يَشْفِي عَلَى يَدِي مَنْ شَاءَ فَهَلْ لَكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْحَمْدَ لِلَّهِ نَحْمَدُهُ وَنَسْتَعِينُهُ مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ أَمَّا بَعْدُ قَالَ فَقَالَ أَعِدْ عَلَيَّ كَلِمَاتِكَ هَؤُلَاءِ فَأَعَادَهُنَّ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَ مَرَّاتٍ قَالَ فَقَالَ لَقَدْ سَمِعْتُ قَوْلَ الْكَهَنَةِ وَقَوْلَ السَّحَرَةِ وَقَوْلَ الشُّعَرَاءِ فَمَا سَمِعْتُ مِثْلَ كَلِمَاتِكَ هَؤُلَاءِ وَلَقَدْ بَلَغْنَ نَاعُوسَ الْبَحْرِ قَالَ فَقَالَ هَاتِ يَدَكَ أُبَايِعْكَ عَلَى الْإِسْلَامِ قَالَ فَبَايَعَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَى قَوْمِكَ قَالَ وَعَلَى قَوْمِي قَالَ فَبَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَرِيَّةً فَمَرُّوا بِقَوْمِهِ فَقَالَ صَاحِبُ السَّرِيَّةِ لِلْجَيْشِ هَلْ أَصَبْتُمْ مِنْ هَؤُلَاءِ شَيْئًا فَقَالَ رَجُلٌ مِنْ الْقَوْمِ أَصَبْتُ مِنْهُمْ مِطْهَرَةً فَقَالَ رُدُّوهَا فَإِنَّ هَؤُلَاءِ قَوْمُ ضِمَادٍ","id":"Dan Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Al Mutsanna] keduanya dari [Al A'la] - [Ibnul Mutsanna] berkata- telah menceritakan kepadaku [Abdul A'la] ia adalah Abu Hammam, telah menceritakan kepada kami [Dawud] dari [Amru bin Sa'id] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwasanya; \"Suatu ketika, Dlimam pernah datang ke Makkah. Dia berasal dari Azdi Syanu`ah, dan pandai meruqyah (mengobati dengan bacaan-bacaan tertentu) seorang yang gila atau terkena gangguan jin. Kemudian pada suatu hari ia mendengar orang-orang bodoh penduduk Makkah mengatakan bahwa Muhammad itu gila. Maka Dlimad berkata, \"Sekiranya aku dapat melihat laki-laki ini, mudah-mudahan Allah menyembuhkannya melalui tanganku.\" Maka Dlimad pun menemui beliau, dan berkata, \"Wahai Muhammad, saya biasa meruqyah penyakit ini, dan Allah akan menyembuhkan melaliau tanganku siapa saja yang dikehendakinya. Maukah kamu?\" Maka Rasulullah shallallahu 'alaihi wasallam membaca: \"INNAL HAMDA LILLAHI NAHMADUHU WA NASTA'IINUHU MAN YAHDIHILLAHU FALAA MUDLILLA LAHU WA MAN YUDLLIL FALAA HAADLIYA LAHU WA ASYHADU AN LAA ILAAHA ILLALLAH WAHDAHU LAA SYARIIKA LAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUH AMMA BA'DU.\" Dlimad berkata, \"Ulangilah lagi kata-katamu tadi.\" Maka Nabi shallallahu 'alaihi wasallam pun mengulanginya kembali hingga tiga kali. Akhirnya Dlimad berkata, \"Aku telah mendengar kata-kata tukang tenun, kata-kata tukang sihir dan kata-kata tukang sya'ir tetapi aku belum pernah mendengar kata-kata seperti yang Anda ucapkan itu, akupun juga pernah mengarungi lautan. Berikanlah tangan Anda padaku, aku akan bersumpah setia dengan Anda untuk memeluk Islam.\" Maka beliau pun membai'atnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dan juga untuk kaummu.\" Dlimad berkata, \"Ya, juga untuk kaumku.\" Tidak berapa lama kemudian, Rasulullah shallallahu 'alaihi wasallam mengutus Sariyah (pasukan khusus yang ditugaskan utuk operasi tertentu), lalu mereka melewati kaumnya Dlimad. Lalu komandan pasukan itu bertanya kepada para prajuritnya, \"Adakah kalian mengambil sesuatu dari kampun itu?\" maka seorang laki-laki menyahut, \"Ada, saya telah mengambil ember mereka.\" maka sang komandan pun berkata, \"Kembalikanlah. Karena mereka adalah kaumnya Dlimad.\""},"1356":{"ar":"حَدَّثَنِي سُرَيْجُ بْنُ يُونُسَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ الْمَلِكِ بْنِ أَبْجَرَ عَنْ أَبِيهِ عَنْ وَاصِلِ بْنِ حَيَّانَ قَالَ قَالَ أَبُو وَائِلٍ خَطَبَنَا عَمَّارٌ فَأَوْجَزَ وَأَبْلَغَ فَلَمَّا نَزَلَ قُلْنَا يَا أَبَا الْيَقْظَانِ لَقَدْ أَبْلَغْتَ وَأَوْجَزْتَ فَلَوْ كُنْتَ تَنَفَّسْتَفَقَالَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ طُولَ صَلَاةِ الرَّجُلِ وَقِصَرَ خُطْبَتِهِ مَئِنَّةٌ مِنْ فِقْهِهِ فَأَطِيلُوا الصَّلَاةَ وَاقْصُرُوا الْخُطْبَةَ وَإِنَّ مِنْ الْبَيَانِ سِحْرًا","id":"Telah menceritakan kepadaku [Suraij bin Yunus] telah menceritakan kepada kami [Abdurrahman bin Abdul Malik bin Abjar] dari [bapaknya] dari [Washil bin Hayyan] ia berkata, [Abu Wa`il] berkata; [Ammar] pernah menyampaikan khutbah Jum'at kepada kami dengan bahasa yang singkat dan padat. Maka ketika ia turun dari mimbar, kami pun berkata kepadanya, \"Wahai Abu Yaqzhan! Khutbah Anda begitu singkat dan padat. Alangkah baiknya kalau Anda panjangkan lagi.\" Ammar berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya lamanya shalat dan pendeknya khutbah seseorang itu menunjukkan tentang pemahaman ia tentang agamanya. Karena itu, panjangkanlah shalat dan pendekkanlah khutbah, karena sebagian dari bayan (penjelasan) adalah sihir.\" "},"1357":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَبْدِ الْعَزِيزِ بْنِ رُفَيْعٍ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍأَنَّ رَجُلًا خَطَبَ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ رَشَدَ وَمَنْ يَعْصِهِمَا فَقَدْ غَوَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَ الْخَطِيبُ أَنْتَ قُلْ وَمَنْ يَعْصِ اللَّهَ وَرَسُولَهُ قَالَ ابْنُ نُمَيْرٍ فَقَدْ غَوِيَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammd bin Abdullah bin Numair] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Abdul Aziz bin Rufai'] dari [Tamim bin Tharafah] dari [Adi bin Hatim] bahwa seorang laki-laki berkhutbah di sisi Nabi shallallahu 'alaihi wasallam seraya berkata, \"Barangsiapa yang taat kepada Allah dan Rasul-Nya, maka ia telah mendapat petunjuk, dan siapa yang bermaksiat kepada keduanya, maka ia telah tersesat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seburuk-buruk Khathib adalah kamu. Maka katakanlah, 'Dan barangsiapa yang bermaksiat kepada Allah dan Rasul-Nya.\" Ibnu Numair mengatakan; \"Maka ia telah tersesat.\""},"1358":{"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ الْحَنْظَلِيُّ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ قَالَ قُتَيْبَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ عَطَاءً يُخْبِرُ عَنْ صَفْوَانَ بْنِ يَعْلَى عَنْ أَبِيهِ أَنَّهُسَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ عَلَى الْمِنْبَرِ{ وَنَادَوْا يَا مَالِكُ }","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Bakar bin Abu Syaibah] dan [Ishaq Al Hanzhali] semuanya dari [Ibnu Uyainah] - [Qutaibah berkata] - telah menceritakan kepada kami [Sufyan] dari [Amru] ia mendengar [Atha`] mengabarkan kepadanya dari [Shafwan bin Ya'la] dari [bapaknya] bahwa ia mendengar Nabi shallallahu 'alaihi wasallam membaca (ayat) di atas mimbar. Dan mereka memanggil, \"Wahai Malik.\""},"1359":{"ar":"و حَدَّثَنِي عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ أُخْتٍ لِعَمْرَةَ قَالَتْأَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ مِنْ فِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ وَهُوَ يَقْرَأُ بِهَا عَلَى الْمِنْبَرِ فِي كُلِّ جُمُعَةٍو حَدَّثَنِيهِ أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ عَنْ يَحْيَى بْنِ أَيُّوبَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ عَنْ أُخْتٍ لِعَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ كَانَتْ أَكْبَرَ مِنْهَا بِمِثْلِ حَدِيثِ سُلَيْمَانَ بْنِ بِلَالٍ","id":"Dan telah menceritakan kepadaku [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Amrah binti Abdurrahman] dari [saudara perempuan Amrah], ia berkata, \"Aku menghafal surat Qaaf langsung dari mulut Rasulullah shallallahu 'alaihi wasallam, yakni ketika beliau membacanya beberapa kali di atas mimbar dalam khutbah Jum'at.\" Dan telah menceritakannya kepadaku [Abu Thahir] telah mengabarkan kepada kami [Ibnu Wahb] dari [Yahya bin Ayyub] dari [Yahya bin Sa'id] dari [Amrah] dari [saudara perempuan] Amrah binti Abdurrahman dan lebih besar darinya. yakni sebagaimana hadits Sulaiman bin Bilal."},"1360":{"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ مُحَمَّدِ بْنِ إِسْحَقَ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ الْأَنْصَارِيُّ عَنْ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ سَعْدِ بْنِ زُرَارَةَ عَنْ أُمِّ هِشَامٍ بِنْتِ حَارِثَةَ بْنِ النُّعْمَانِ قَالَتْلَقَدْ كَانَ تَنُّورُنَا وَتَنُّورُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحِدًا سَنَتَيْنِ أَوْ سَنَةً وَبَعْضَ سَنَةٍ وَمَا أَخَذْتُ ق وَالْقُرْآنِ الْمَجِيدِ إِلَّا عَنْ لِسَانِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَؤُهَا كُلَّ يَوْمِ جُمُعَةٍ عَلَى الْمِنْبَرِ إِذَا خَطَبَ النَّاسَ","id":"Dan Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [bapakku] dari [Muhammad bin Ishaq] ia berkata, telah menceritakan kepadaku [Abdullah bin Abu Bakar bin Muhammad bin Amru bin Hazm Al Anshari] dari [Yahya bin Abdullah bin Abdurrahman bin Sa'd bin Zurarah] dari [Ummi Hisyam binti Haritsah bin Nu'man] ia berkata, \"Tempat pembuatan roti kami dan tempat pembuatan roti Rasulullah shallallahu 'alaihi wasallam adalah sama selama dua atau satu tahun lebih, dan tidaklah saya menghafal surat 'QAAF WAL QUR`ANIL MAJIID' kecuali dari lisan Rasulullah shallallahu 'alaihi wasallam, beliau membacanya pada setiap hari Jum'at di atas mimbar saat beliau menyampaikan khutbah kepada manusia.\""},"1361":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ حُصَيْنٍ عَنْ عُمَارَةَ بْنِ رُؤَيْبَةَ قَالَ رَأَى بِشْرَ بْنَ مَرْوَانَ عَلَى الْمِنْبَرِ رَافِعًا يَدَيْهِ فَقَالَ قَبَّحَ اللَّهُ هَاتَيْنِ الْيَدَيْنِلَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَزِيدُ عَلَى أَنْ يَقُولَ بِيَدِهِ هَكَذَا وَأَشَارَ بِإِصْبَعِهِ الْمُسَبِّحَةِو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ رَأَيْتُ بِشْرَ بْنَ مَرْوَانَ يَوْمَ جُمُعَةٍ يَرْفَعُ يَدَيْهِ فَقَالَ عُمَارَةُ بْنُ رُؤَيْبَةَ فَذَكَرَ نَحْوَهُ","id":"Dan Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Idris] dari [Hushain] dari [Umarah bin Ru`aibah] bahwa suatu ketika ia melihat Bisyra bin Marwan mengangkat kedua tangannya di atas mimbar, maka ia pun berkata; Semoga Allah menjelekkan kedua tangan ini. Sungguh, saya telah melihat Rasulullah shallallahu 'alaihi wasallam, beliau tidak menambah lagi setelah memberikan isyarat dengan tangannya seperti ini -ia pun memberi isyarat dengan jari telunjuknya-. Dan telah menceritakannya kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu Awanah] dari [Hushain bin Abdurrahman] ia berkata; Saya melihat Bisyra bin Marwan pada hari Jum'at mengangkat kedua tangannya, maka [Umarah bin Ru`aibah] pun berkata. Kemudian ia pun menyebutkan hadits semisal."},"1362":{"ar":"و حَدَّثَنَا أَبُو الرَّبِيعِ الزَّهْرَانِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا حَمَّادٌ وَهُوَ ابْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَبَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ إِذْ جَاءَ رَجُلٌ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَلَّيْتَ يَا فُلَانُ قَالَ لَا قَالَ قُمْ فَارْكَعْحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَيَعْقُوبُ الدَّوْرَقِيُّ عَنْ ابْنِ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ عَمْرٍو عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا قَالَ حَمَّادٌ وَلَمْ يَذْكُرْ الرَّكْعَتَيْنِ","id":"Dan Telah menceritakan kepada kami [Abu Rabi' Az Zahrani] dan [Qutaibah bin Sa'id] keduanya berkata, telah menceritakan kepada kami [Hammad] ia adalah Ibnu Zaid dari [Amru bin Dinar] dari [Jabir bin Abdullah] ia berkata; Ketika Rasulullah shallallahu 'alaihi wasallam menyampaikan khutbah pada hari Jum'at, tiba-tiba datanglah seorang laki-laki dan Nabi shallallahu 'alaihi wasallam pun bertanya kepadanya: \"Apakah kamu telah menunaikan shalat (dua raka'at) wahai Fulan?\" laki-laki itu pun menjawab, \"Belum.\" Beliau bersabda: \"Bangun dan shalatlah.\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ya'qub Ad Dauraqi] dari [Ibnu Ulayyah] dari [Ayyub] dari [Amru] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, yakni sebagaimana apa yang dikatakan Hammad, namun ia tidak menyebutkan dua raka'at."},"1363":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ قُتَيْبَةُ حَدَّثَنَا وَقَالَ إِسْحَقُ أَخْبَرَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُادَخَلَ رَجُلٌ الْمَسْجِدَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ فَقَالَ أَصَلَّيْتَ قَالَ لَا قَالَ قُمْ فَصَلِّ الرَّكْعَتَيْنِوَفِي رِوَايَةِ قُتَيْبَةَ قَالَ صَلِّ رَكْعَتَيْنِ","id":"Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Ishaq bin Ibrahim] -Qutaibah berkata- telah menceritakan kepada kami -dan Ishaq berkata- telah mengabarkan kepada kami [Sufyan] dari [Amru] ia mendengar [Jabir bin Abdullah] berkata; Seorang laki-laki masuk Masjid sementara Rasulullah shallallahu 'alaihi wasallam sedang menyampaikan khutbah Jum'at, maka beliau pun bertanya: \"Apakah kamu telah shalat?\" Laki-laki itu menjawab, \"belum.\" Maka beliau bersabda: \"Bangun dan shalatlah dua raka'at.\" dan dalam riwayat Qutaibah, \"Shalatlah dua raka'at.\""},"1364":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَمْرُو بْنُ دِينَارٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُاجَاءَ رَجُلٌ وَالنَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ يَخْطُبُ فَقَالَ لَهُ أَرَكَعْتَ رَكْعَتَيْنِ قَالَ لَا فَقَالَ ارْكَعْ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] dan [Abdu bin Humaid] -Ibnu Rafi' berkata- telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Amru bin Dinar] bahwa ia mendengar [Jabir bin Abdullah] berkata; Seorang laki-laki datang, sementara Nabi shallallahu 'alaihi wasallam sedang menyampaikan khutbah Jum'at di atas mimbar. Maka beliau pun bertanya padanya: \"Apakah kamu telah shalat dua raka'at?\" laki-laki itu menjawab, \"belum.\" Beliau bersabda: \"Ruku'lah (shalatlah).\""},"1365":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ فَقَالَ إِذَا جَاءَ أَحَدُكُمْ يَوْمَ الْجُمُعَةِ وَقَدْ خَرَجَ الْإِمَامُ فَلْيُصَلِّ رَكْعَتَيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Amru] ia berkata, saya mendengar [Jabir bin Abdulah] bahwa Nabi shallallahu 'alaihi wasallam berkhutbah seraya bersabda: \"Jika salah seorang dari kalian datang untuk mengerjakan shalat Jum'at, sementara imam telah keluar (naik mimbar), hendaklah ia shalat dua raka'at.\""},"1366":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا لَيْثٌ ح و حَدَّثَنَا مُحَمَّدُ بْنُ رُمْحٍ أَخْبَرَنَا اللَّيْثُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ أَنَّهُ قَالَجَاءَ سُلَيْكٌ الْغَطَفَانِيُّ يَوْمَ الْجُمُعَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ عَلَى الْمِنْبَرِ فَقَعَدَ سُلَيْكٌ قَبْلَ أَنْ يُصَلِّيَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرَكَعْتَ رَكْعَتَيْنِ قَالَ لَا قَالَ قُمْ فَارْكَعْهُمَا","id":"Dan Telah menceritakan kepada kami [Qutaibah bin Sa'id] Telah menceritakan kepada kami [Laits] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Rumh] telah mengabarkan kepada kami [Laits] dari [Abu Zubair] dari [Jabir] bahwa ia berkata; Sulaik Al Ghathafani datang pada hari Jum'at sementara Rasulullah shallallahu 'alaihi wasallam sedang duduk di atas mimbar, maka Sulaik pun duduk sebelum ia shalat. Maka Nabi shallallahu 'alaihi wasallam bertanya padanya, \"Apakah kamu telah shalat dua raka'at?\" ia menjawab, \"belum.\" Beliau bersabda: \"Bangunlah, dan shalatlah dua raka'at.\""},"1367":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَلِيُّ بْنُ خَشْرَمٍ كِلَاهُمَا عَنْ عِيسَى بْنِ يُونُسَ قَالَ ابْنُ خَشْرَمٍ أَخْبَرَنَا عِيسَى عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَجَاءَ سُلَيْكٌ الْغَطَفَانِيُّ يَوْمَ الْجُمُعَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ فَجَلَسَ فَقَالَ لَهُ يَا سُلَيْكُ قُمْ فَارْكَعْ رَكْعَتَيْنِ وَتَجَوَّزْ فِيهِمَا ثُمَّ قَالَ إِذَا جَاءَ أَحَدُكُمْ يَوْمَ الْجُمُعَةِ وَالْإِمَامُ يَخْطُبُ فَلْيَرْكَعْ رَكْعَتَيْنِ وَلْيَتَجَوَّزْ فِيهِمَا","id":"Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ali bin Khasyram] keduanya dari [Isa bin Yunus] - [Ibnu Khasyram] berkata- telah mengabarkan kepada kami [Isa] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir bin Abdullah] ia berkata; Sulaik Al Ghathafani datang pada hari Jum'at, sementara Rasulullah shallallahu 'alaihi wasallam sedang berkhutbah, ia pun duduk, maka beliau pun bertanya padanya: \"Wahai Sulaik, bangun dan shalatlah dua raka'at, kerjakanlah dengan ringan.\" Kemudian beliau bersabda: \"Jika salah seorang dari kalian datang pada hari Jum'at, sedangkan Imam sedang berkhutbah, maka hendaklah ia shalat dua raka'at dengan ringan.\""},"1368":{"ar":"و حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ حَدَّثَنَا حُمَيْدُ بْنُ هِلَالٍ قَالَقَالَ أَبُو رِفَاعَةَ انْتَهَيْتُ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ قَالَ فَقُلْتُ يَا رَسُولَ اللَّهِ رَجُلٌ غَرِيبٌ جَاءَ يَسْأَلُ عَنْ دِينِهِ لَا يَدْرِي مَا دِينُهُ قَالَ فَأَقْبَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتَرَكَ خُطْبَتَهُ حَتَّى انْتَهَى إِلَيَّ فَأُتِيَ بِكُرْسِيٍّ حَسِبْتُ قَوَائِمَهُ حَدِيدًا قَالَ فَقَعَدَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَعَلَ يُعَلِّمُنِي مِمَّا عَلَّمَهُ اللَّهُ ثُمَّ أَتَى خُطْبَتَهُ فَأَتَمَّ آخِرَهَا","id":"Dan Telah menceritakan kepada kami [Syaiban bin Farrukh] telah menceritakan kepada kami [Sulaiman bin Al Mughirah] telah menceritakan kepada kami [Humaid bin Hilal] ia berkata, [Abu Rifa'ah] berkata; \"Aku tiba di tempat Rasulullah shallallahu 'alaihi wasallam saat beliau sedang berkhutbah. Lalu aku berkata kepada beliau, \"Wahai Rasulullah, ada orang asing yang sengaja datang kepada Anda untuk bertanya tentang agama, ia tidak tahu apa agamanya.\" Maka Rasulullah shallallahu 'alaihi wasallam pun mendatangiku dan memutuskan khutbahnya. Ketika beliau sampai di dekatku, diberikanlah sebuah kursi -aku memperkirakan kaki-kakinya terbuat dari besi- untuk beliau duduki. Selanjutnya Rasulullah shallallahu 'alaihi wasallam duduk di kursi tersebut dan mengajarkan kepadaku perihal agama yang telah diajarkan Allah kepada beliau. Setelah itu, beliau meneruskan khutbahnya hingga selesai.\""},"1369":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا سُلَيْمَانُ وَهُوَ ابْنُ بِلَالٍ عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ ابْنِ أَبِي رَافِعٍ قَالَ اسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ عَلَى الْمَدِينَةِ وَخَرَجَ إِلَى مَكَّةَ فَصَلَّى لَنَا أَبُو هُرَيْرَةَ الْجُمُعَةَ فَقَرَأَ بَعْدَ سُورَةِ الْجُمُعَةِ فِي الرَّكْعَةِ الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ قَالَ فَأَدْرَكْتُ أَبَا هُرَيْرَةَ حِينَ انْصَرَفَ فَقُلْتُ لَهُ إِنَّكَ قَرَأْتَ بِسُورَتَيْنِ كَانَ عَلِيُّ بْنُ أَبِي طَالِبٍ يَقْرَأُ بِهِمَا بِالْكُوفَةِفَقَالَ أَبُو هُرَيْرَةَ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ بِهِمَا يَوْمَ الْجُمُعَةِو حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَا حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ كِلَاهُمَا عَنْ جَعْفَرٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي رَافِعٍ قَالَ اسْتَخْلَفَ مَرْوَانُ أَبَا هُرَيْرَةَ بِمِثْلِهِ غَيْرَ أَنَّ فِي رِوَايَةِ حَاتِمٍ فَقَرَأَ بِسُورَةِ الْجُمُعَةِ فِي السَّجْدَةِ الْأُولَى وَفِي الْآخِرَةِ إِذَا جَاءَكَ الْمُنَافِقُونَ وَرِوَايَةُ عَبْدِ الْعَزِيزِ مِثْلُ حَدِيثِ سُلَيْمَانَ بْنِ بِلَالٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] Telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Ja'far] dari [bapaknya] dari [Ibnu Abu Rafi'] ia berkata; Suatu ketika (khalifah) Marwan meminta kepada [Abu Hurairah] untuk menggantikannya (sebagai pemimpin) di Madinah, sementara Marwan pergi ke Makkah. Maka pada suatu hari Jum'at, Abu Hurairah mengimami kami shalat Jum'at. Ia membaca surat Al Jumu'ah pada raka'at pertama, dan surat Al Munafiqun pada raka'at kedua. Setelah selesai shalat, kutemui Abu Hurairah dan kukatakan kepadanya, \"Kedua surat yang Anda baca tadi, pernah dibaca oleh Ali bin Abi Thalib ketika ia berada di Kufah.\" Abu Hurairah berkata, \"Saya telah mendengar Rasulullah shallallahu 'alaihi wasallam membaca kedua surat itu pada hari Jum'at.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dan [Abu Bakar bin Abu Syaibah] keduanya berkata, telah menceritakan kepada kami [Hatim bin Isma'il] -dalam jalur lain- Dan telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Abdul Aziz] yakni Ad Darawardi, keduanya dari [Ja'far] dari [bapaknya] dari [Ubaidullah bin Abu Rafi'] ia berkata; Marwan meminta kepada [Abu Hurairah] untuk menggantikannya. Yakni semisalnya. Hanya saja dalam riwayat Hatim; \"Maka ia pun membaca surat Al Jumu'ah pada sujud yang pertama, sedangkan pada sujud (raka'at) terakhir ia membaca, 'IDZAA JAA`AKAL MUNAAFIQUUNA..'\" Sedangkan pada riwayat Abdul Aziz adalah serupa dengan hadits Sulaiman bin Bilal."},"1370":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَإِسْحَقُ جَمِيعًا عَنْ جَرِيرٍ قَالَ يَحْيَى أَخْبَرَنَا جَرِيرٌ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ عَنْ أَبِيهِ عَنْ حَبِيبِ بْنِ سَالِمٍ مَوْلَى النُّعْمَانِ بْنِ بَشِيرٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الْعِيدَيْنِ وَفِي الْجُمُعَةِ بِسَبِّحِ اسْمَ رَبِّكَ الْأَعْلَى وَهَلْ أَتَاكَ حَدِيثُ الْغَاشِيَةِ قَالَ وَإِذَا اجْتَمَعَ الْعِيدُ وَالْجُمُعَةُ فِي يَوْمٍ وَاحِدٍ يَقْرَأُ بِهِمَا أَيْضًا فِي الصَّلَاتَيْنِو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدِ بْنِ الْمُنْتَشِرِ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] dan [Ishaq] semuanya dari [Jarir] - [Yahya] berkata- telah mengabarkan kepada kami [Jarir] dari [Ibrahim bin Muhammad bin Al Muntasyir] dari [bapaknya] dari [Habib bin Salim] Maula Nu'man bin Basyir, dari [Nu'man bin Basyir] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam biasa membaca surat Al A'la dan surat Al Ghasyiah dalam shalat dua hari raya dan shalat Jum'at. Bila shalat Id bertepatan dengan hari Jum'at, beliau juga membaca kedua surat tersebut dalam kedua shalat itu.\" Dan telah menceritakannya kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abu 'Awanah] dari [Ibrahim bin Muhammad bin Al Muntasyir] dengan sanad-sanad ini."},"1371":{"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ قَالَكَتَبَ الضَّحَّاكُ بْنُ قَيْسٍ إِلَى النُّعْمَانِ بْنِ بَشِيرٍ يَسْأَلُهُ أَيَّ شَيْءٍ قَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ سِوَى سُورَةِ الْجُمُعَةِ فَقَالَ كَانَ يَقْرَأُ هَلْ أَتَاكَ","id":"Dan Telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Dlamrah bin Sa'id] dari [Ubaidullah bin Abdullah] ia berkata, Adl Dlahak bin Qais menulis surat kepada [An Nu'man bin Basyir] menanyakan tentang surat yang apa yang dibaca oleh Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at selain surat Jumu'ah. Maka ia menjawab, \"Beliau membaca surat Al Ghasyiah.\""},"1372":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ عَنْ سُفْيَانَ عَنْ مُخَوَّلِ بْنِ رَاشِدٍ عَنْ مُسْلِمٍ الْبَطِينِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْفَجْرِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ السَّجْدَةِ وَهَلْ أَتَى عَلَى الْإِنْسَانِ حِينٌ مِنْ الدَّهْرِ وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي صَلَاةِ الْجُمُعَةِ سُورَةَ الْجُمُعَةِ وَالْمُنَافِقِينَو حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا أَبُو كُرَيْبٍ حَدَّثَنَا وَكِيعٌ كِلَاهُمَا عَنْ سُفْيَانَ بِهَذَا الْإِسْنَادِ مِثْلَهُ و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ مُخَوَّلٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ فِي الصَّلَاتَيْنِ كِلْتَيْهِمَا كَمَا قَالَ سُفْيَانُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdah bin Sulaiman] dari [Sufyan] dari [Mukhawwal bin Rasyid] dari [Muslim Al Bathin] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa biasanya Nabi shallallahu 'alaihi wasallam ketika mengerjakan shalat Shubuh pada hari Jum'at, beliau membaca: \"ALIF LAAM MIIM TANZIIL\" (surat As Sajadah) dan, \"HAL ATAA 'ALAL INSAANI HIINUM MINAD DAHRI\" (surat Al Insan). Dan dalam shalat Jum'at beliau membaca surat Al Jumu'ah dan surat Al Munafiqun. Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [bapakku] -dalam jalur lain- dan Telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Waki'] keduanya dari [Sufyan] dengan isnad ini. Dan telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Mukhawwal] dengan sanad-sanad ini semisalnya pada dua shalat, sebagaimana yang dikatakan Sufyan."},"1373":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقْرَأُ فِي الْفَجْرِ يَوْمَ الْجُمُعَةِ الم تَنْزِيلُ وَهَلْ أَتَى","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Sa'd bin Ibrahim] dari [Abdurrahman bin Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa biasanya Nabi shallallahu 'alaihi wasallam dalam shalat Shubuh pada hari Jum'at, beliau membaca: \"ALIF LAAM MIIM TANZIIL\" (surat As Sajadah) dan, \"HAL ATAA\" (surat Al Insan)."},"1374":{"ar":"حَدَّثَنِي أَبُو الطَّاهِرِ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ أَبِيهِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقْرَأُ فِي الصُّبْحِ يَوْمَ الْجُمُعَةِ بِ الم تَنْزِيلُ فِي الرَّكْعَةِ الْأُولَى وَفِي الثَّانِيَةِ هَلْ أَتَى عَلَى الْإِنْسَانِ حِينٌ مِنْ الدَّهْرِ لَمْ يَكُنْ شَيْئًا مَذْكُورًا","id":"Telah menceritakan kepadaku [Abu Thahir] telah menceritakan kepada kami [Ibnu Wahb] dari [Ibrahim bin Sa'd] dari [bapaknya] dari [Al A'raj] dari [Abu Hurairah] bahwa dalam shalat Shubuh pada hari Jum'at biasanya Nabi shallallahu 'alaihi wasallam membaca \"ALIF LAAM MIIM TANZIIL\" (surat As Sajadah) pada raka'at pertama, dan pada raka'at kedua, \"HAL ATAA 'ALAL INSAANI HIINUM MINAD DAHRI LAM YAKUN SYAI`AN MADZKUURAA.\" (surat Al Insan)."},"1375":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّى أَحَدُكُمْ الْجُمُعَةَ فَلْيُصَلِّ بَعْدَهَا أَرْبَعًا","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Khalid bin Abdullah] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian telah menunaikan shalat Jum'at, maka hendaklah ia shalat empat raka'at setelahnya.\""},"1376":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا صَلَّيْتُمْ بَعْدَ الْجُمُعَةِ فَصَلُّوا أَرْبَعًازَادَ عَمْرٌو فِي رِوَايَتِهِ قَالَ ابْنُ إِدْرِيسَ قَالَ سُهَيْلٌ فَإِنْ عَجِلَ بِكَ شَيْءٌ فَصَلِّ رَكْعَتَيْنِ فِي الْمَسْجِدِ وَرَكْعَتَيْنِ إِذَا رَجَعْتَ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Amru An Naqid] keduanya berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Suhail] dari [bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika kalian ingin shalat (sunah) setelah menunaikan shalat Jum'at, maka shalatlah empat raka'at.\" Amru menambahkan di dalam riwayatnya; Ibnu Idris berkata, Suhail berkata; \"Jika kamu terburu-buru (karena suatu keperluan), maka shalatlah dua raka'at di Masjid dan dua raka'at di rumah.\""},"1377":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا عَمْرٌو النَّاقِدُ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا وَكِيعٌ ع��نْ سُفْيَانَ كِلَاهُمَا عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ مِنْكُمْ مُصَلِّيًا بَعْدَ الْجُمُعَةِ فَلْيُصَلِّ أَرْبَعًاوَلَيْسَ فِي حَدِيثِ جَرِيرٍ مِنْكُمْ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] -dalam jalur lain- Dan telah menceritakan kepada kami [Amru An Naqid] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Waki'] dari [Sufyan] keduanya dari [Suhail] dari [bapaknya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa di antara kalian yang ingin menunaikan shalat setelah shalat Jum'at, maka hendaklah ia shalat empat raka'at.\" Sedangkan di dalam hadits Jarir tidak terdapat kata, \"diantara kalian.\""},"1378":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَمُحَمَّدُ بْنُ رُمْحٍ قَالَا أَخْبَرَنَا اللَّيْثُ ح و حَدَّثَنَا قُتَيْبَةُ حَدَّثَنَا لَيْثٌ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّهُ كَانَ إِذَا صَلَّى الْجُمُعَةَ انْصَرَفَ فَسَجَدَ سَجْدَتَيْنِ فِي بَيْتِهِ ثُمَّ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَصْنَعُ ذَلِكَ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] dan [Muhammad bin Rumh] keduanya berkata, telah mengabarkan kepada kami [Laits] -dalam jalur lain- Dan telah menceritakan kepada kami [Qutaibah] telah menceritakan kepada kami [Laits] dari [Nafi'] dari [Abdullah] bahwasanya bila ia telah menunaikan shalat Jum'at, maka ia pulang dan shalat dua raka'at di rumahnya. Kemudian ia berkata, \"Rasulullah shallallahu 'alaihi wasallam biasa melakukan amalan tersebut.\""},"1379":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُوَصَفَ تَطَوُّعَ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَكَانَ لَا يُصَلِّي بَعْدَ الْجُمُعَةِ حَتَّى يَنْصَرِفَ فَيُصَلِّي رَكْعَتَيْنِ فِي بَيْتِهِقَالَ يَحْيَى أَظُنُّنِي قَرَأْتُ فَيُصَلِّي أَوْ أَلْبَتَّةَ","id":"Dan Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata; Saya telah membacakan kepada [Malik] dari [Nafi'] dari [Abdullah bin Umar] bahwa ia menshifati shalat tathawwu' Rasulullah shallallahu 'alaihi wasallam, ia berkata; \"Biasanya beliau tidak shalat setelah Shalat Jum'at hingga beliau pulang, kemudian beliau baru shalat dua raka'at di rumahnya.\" Yahya berkata; saya menduga kuat, bahwa saya telah membacakan; \"Maka (beliau) shalat atau Al Batah (benar-benar).\""},"1380":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَابْنُ نُمَيْرٍ قَالَ زُهَيْرٌ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا عَمْرٌو عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُصَلِّي بَعْدَ الْجُمُعَةِ رَكْعَتَيْنِ","id":"Dan Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] dan [Ibnu Numair] -Zhuhair berkata- telah menceritakan kepada kami [Sufyan bin Uyainah] telah menceritakan kepada kami [Amru] dari [Az Zuhri] dari [Salim] dari [bapaknya] bahwa Nabi shallallahu 'alaihi wasallam biasanya shalat dua raka'at setelah shalat Jum'at."},"1381":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عُمَرُ بْنُ عَطَاءِ بْنِ أَبِي الْخُوَارِ أَنَّ نَافِعَ بْنَ جُبَيْرٍ أَرْسَلَهُ إِلَى السَّائِبِ ابْنِ أُخْتِ نَمِرٍ يَسْأَلُهُ عَنْ شَيْءٍ رَآهُ مِنْهُ مُعَاوِيَةُ فِي الصَّلَاةِ فَقَالَ نَعَمْ صَلَّيْتُ مَعَهُ الْجُمُعَةَ فِي الْمَقْصُورَةِ فَلَمَّا سَلَّمَ الْإِمَامُ قُمْتُ فِي مَقَامِي فَصَلَّيْتُ فَلَمَّا دَخَلَ أَرْسَلَ إِلَيَّ فَقَالَ لَا تَعُدْ لِمَا فَعَلْتَ إِذَا صَلَّيْتَ الْجُمُعَةَ فَلَا تَصِلْهَا بِصَلَاةٍ حَتَّى تَكَلَّمَ أَوْ تَخْرُجَفَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَنَا بِذَلِكَ أَنْ لَا تُوصَلَ صَلَاةٌ بِصَلَاةٍ حَتَّى نَتَكَلَّمَ أَوْ نَخْرُجَو حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي عُمَرُ بْنُ عَطَاءٍ أَنَّ نَافِعَ بْنَ جُبَيْرٍ أَرْسَلَهُ إِلَى السَّائِبِ بْنِ يَزِيدَ ابْنِ أُخْتِ نَمِرٍ وَسَاقَ الْحَدِيثَ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ فَلَمَّا سَلَّمَ قُمْتُ فِي مَقَامِي وَلَمْ يَذْكُرْ الْإِمَامَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghundar] dari [Ibnu Juraij] ia berkata, telah mengabarkan kepadaku [Umar bin Atha` bin Abul Khuwar] bahwa Nafi' bin Jubair mengutusnya kepada [Sa`ib] putra saudara perempuan Namir untuk menanyakan sesuatu yang pernah dilihat oleh [Mu'awiyah] dalam shalat, maka Sa`ib berkata, \"Benar aku pernah shalat Jum'at bersama Mu'awiyah di dalam Maqshurah (suatu ruangan yang dibangun di dalam masjid). Setelah imam salam aku berdiri di tempatku kemudian aku menunaikan shalat sunnah. Ketika Mu'awiyah masuk, ia mengutus seseorang kepadaku dan utusan itu mengatakan, 'Jangan kamu ulangi perbuatanmu tadi. Jika kamu telah selesai mengerjakan shalat Jum'at, janganlah kamu sambung dengan shalat sunnah sebelum kamu berbincang-bincang atau sebelum kamu keluar dari masjid. Karena Rasulullah shallallahu 'alaihi wasallam memerintahkan hal itu kepada kita yaitu 'Janganlah suatu shalat disambung dengan shalat lain, kecuali setelah kita mengucapkan kata-kata atau keluar dari Masjid.'\" Dan telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata, [Ibnu Juraij] berkata; telah mengabarkan kepadaku [Umar bin Atha`] bahwa Nafi' bin Jubair telah mengutusnya kepada [Sa`ib bin Yazid bin Ukhti Namir]. Ia pun menyebutkan hadits yang semisalnya, hanya saja ia mengatakan; \"Ketika ia salam, saya langsung berdiri di tempatku.\" Ia tidak menyebutkan kata Imam."},"1382":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ جَمِيعًا عَنْ عَبْدِ الرَّزَّاقِ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي الْحَسَنُ بْنُ مُسْلِمٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَشَهِدْتُ صَلَاةَ الْفِطْرِ مَعَ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَعُمَرَ وَعُثْمَانَ فَكُلُّهُمْ يُصَلِّيهَا قَبْلَ الْخُطْبَةِ ثُمَّ يَخْطُبُ قَالَ فَنَزَلَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَأَنِّي أَنْظُرُ إِلَيْهِ حِينَ يُجَلِّسُ الرِّجَالَ بِيَدِهِ ثُمَّ أَقْبَلَ يَشُقُّهُمْ حَتَّى جَاءَ النِّسَاءَ وَمَعَهُ بِلَالٌ فَقَالَ{ يَا أَيُّهَا النَّبِيُّ إِذَا جَاءَكَ الْمُؤْمِنَاتُ يُبَايِعْنَكَ عَلَى أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا }فَتَلَا هَذِهِ الْآيَةَ حَتَّى فَرَغَ مِنْهَا ثُمَّ قَالَ حِينَ فَرَغَ مِنْهَا أَنْتُنَّ عَلَى ذَلِكِ فَقَالَتْ امْرَأَةٌ وَاحِدَةٌ لَمْ يُجِبْهُ غَيْرُهَا مِنْهُنَّ نَعَمْ يَا نَبِيَّ اللَّهِ لَا يُدْرَى حِينَئِذٍ مَنْ هِيَ قَالَ فَتَصَدَّقْنَ فَبَسَطَ بِلَالٌ ثَوْبَهُ ثُمَّ قَالَ هَلُمَّ فِدًى لَكُنَّ أَبِي وَأُمِّي فَجَعَلْنَ يُلْقِينَ الْفَتَخَ وَالْخَوَاتِمَ فِي ثَوْبِ بِلَالٍ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] dan [Abdu bin Humaid] semuanya dari [Abdurrazaq] - [Ibnu Rafi'] - berkata, telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Al Hasan bin Muslim] dari [Thawus] dari [Ibnu Abbas] ia berkata; \"Saya pernah menghadiri shalat Idul Fithri bersama Rasulullah shallallahu 'alaihi wasallam, Abu Bakar, Umar dan Utsman, mereka semua shalat terlebih dahulu sebelum khutbah.\" Kemudian Ibnu Abbas mengatakan bahwa Rasulullah shallallahu 'alaihi wasallam turun dari mimbar, sepertinya aku sempat melihat beliau ketika menyuruh orang-orang lelaki duduk dengan isyarat tangan beliau lalu beliau lewat di tengah sehingga beliau mendatangi kaum wanita disertai Bilal, dan beliau membaca ayat: \"Hai nabi, apabila datang kepadamu perempuan-perempuan yang beriman untuk mengadakan janji setia, bahwa mereka tiada akan menyekutukan Allah…\" beliau membaca ayat itu hingga selesai. Setelah itu, beliau bertanya: \"Apakah kalian ingin termasuk seperti yang disebutkan ayat itu?\" seorang wanita menjawab -ketika itu tidak ada wanita lain yang menjawab-, \"Benar, wahai Nabiyullah.\" Saat itu, beliau tidak tahu siapa perempuan itu. Beliau bersabda: \"Kalau demikian, bersedekahlah.\" Lalu Bilal membentangkan kainnya, kemudian ia mengatakan, \"Ayolah! Sungguh, sedekah ini menjadi penebus kalian dari (siksa neraka).\" Akhirnya para wanita itu pun meletakkan cincinnya di atas kain yang dihamparkan Bilal."},"1383":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ أَبِي عُمَرَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنَا أَيُّوبُ قَالَ سَمِعْتُ عَطَاءً قَالَ سَمِعْتُ ابْنَ عَبَّاسٍ يَقُولُاأَشْهَدُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَصَلَّى قَبْلَ الْخُطْبَةِ قَالَ ثُمَّ خَطَبَ فَرَأَى أَنَّهُ لَمْ يُسْمِعْ النِّسَاءَ فَأَتَاهُنَّ فَذَكَّرَهُنَّ وَوَعَظَهُنَّ وَأَمَرَهُنَّ بِالصَّدَقَةِ وَبِلَالٌ قَائِلٌ بِثَوْبِهِ فَجَعَلَتْ الْمَرْأَةُ تُلْقِي الْخَاتَمَ وَالْخُرْصَ وَالشَّيْءَو حَدَّثَنِيهِ أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنِي يَعْقُوبُ الدَّوْرَقِيُّ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ كِلَاهُمَا عَنْ أَيُّوبَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Dan Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Abu Umar] -Abu Bakar berkata- telah menceritakan kepada kami [Sufyan bin Uyainah] telah menceritakan kepada kami [Ayyub] ia berkata, saya mendengar [Atha`] berkata, saya mendengar [Ibnu Abbas] berkata; \"Saya menyaksikan Rasulullah shallallahu 'alaihi wasallam shalat Ied terlebih dahulu sebelum berkhutbah. Setelah menyampaikan khutbah beliau mengira bahwa kaum wanita belum mendengarnya, maka beliau pun mendatangi mereka dan mengingatkan mereka, memberi nasehat serta memerintahkan mereka untuk bersedekah, sementara Bilal membentangkan kainnya. Akhirnya kaum wanita pun meletakkan cincin dan kalung-kalung mereka (di atas hamparan kain Bilal).\" Dan telah menceritakan kepadaku [Abu Rabi' Az Zahrani] Telah menceritakan kepada kami [Hammad] -dalam jalur lain- Dan telah menceritakan kepadaku [Ya'qub Ad Dauraqi] telah menceritakan kepada kami [Isma'il bin Ibrahim] keduanya dari [Ayyub] dengan isnad ini, semisalnya."},"1384":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَمُحَمَّدُ بْنُ رَافِعٍ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُهُ يَقُولُإِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ يَوْمَ الْفِطْرِ فَصَلَّى فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ ثُمَّ خَطَبَ النَّاسَ فَلَمَّا فَرَغَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَزَلَ وَأَتَى النِّسَاءَ فَذَكَّرَهُنَّ وَهُوَ يَتَوَكَّأُ عَلَى يَدِ بِلَالٍ وَبِلَالٌ بَاسِطٌ ثَوْبَهُ يُلْقِينَ النِّسَاءُ صَدَقَةًقُلْتُ لِعَطَاءٍ زَكَاةَ يَوْمِ الْفِطْرِ قَالَ لَا وَلَكِنْ صَدَقَةً يَتَصَدَّقْنَ بِهَا حِينَئِذٍ تُلْقِي الْمَرْأَةُ فَتَخَهَا وَيُلْقِينَ وَيُلْقِينَ قُلْتُ لِعَطَاءٍ أَحَقًّا عَلَى الْإِمَامِ الْآنَ أَنْ يَأْتِيَ النِّسَاءَ حِينَ يَفْرُغُ فَيُذَكِّرَهُنَّ قَالَ إِي لَعَمْرِي إِنَّ ذَلِكَ لَحَقٌّ عَلَيْهِمْ وَمَا لَهُمْ لَا يَفْعَلُونَ ذَلِكَ","id":"Dan Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Muhammad bin Rafi' bin Rafi'] Telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Atha`] dari [Jabir bin Abdullah] ia berkata, saya mendengarnya berkata; \"Sesungguhnya Nabi shallallahu 'alaihi wasallam berdiri pada hari raya Iedul Fithri, lalu beliau shalat. Beliau shalat sebelum menyampaikan khuthbah. Seusai shalat, baru beliau menyampaikan khuthbah kepada manusia. Setelah Nabi shallallahu 'alaihi wasallam berkhutbah, beliau mendatangi kaum wanita lalu mengingatkan mereka sambil bersandar pada tangan Bilal. Sedangkan Bilal membentangkan kainnya, akhirnya kaum wanita pun melemparkan sedekahnya.\" Saya bertanya kepada Atha`, \"Apakah itu merupakan Zakat Fithri?\" ia menjawab, \"Tidak, akan tetapi itu adalah sedekah yang mereka keluarkan, saat itu para wanita melemparkan cincin, sehingga yang lain pun turut melempar.\" Saya bertanya lagi kepada Atha`, \"Apakah sekarang dapat dibenarkan, bila seorang imam mendatangi kaum wanita setelah menyampaikan khutbah lalu mengingatkan mereka?\" ia menjawab, \"Wahai Amru, sesungguhnya hal itu benar-benar termasuk tindakan yang benar, apa alasan mereka untuk tidak melakukannya?\""},"1385":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَشَهِدْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّلَاةَ يَوْمَ الْعِيدِ فَبَدَأَ بِالصَّلَاةِ قَبْلَ الْخُطْبَةِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ ثُمَّ قَامَ مُتَوَكِّئًا عَلَى بِلَالٍ فَأَمَرَ بِتَقْوَى اللَّهِ وَحَثَّ عَلَى طَاعَتِهِ وَوَعَظَ النَّاسَ وَذَكَّرَهُمْ ثُمَّ مَضَى حَتَّى أَتَى النِّسَاءَ فَوَعَظَهُنَّ وَذَكَّرَهُنَّ فَقَالَ تَصَدَّقْنَ فَإِنَّ أَكْثَرَكُنَّ حَطَبُ جَهَنَّمَ فَقَامَتْ امْرَأَةٌ مِنْ سِطَةِ النِّسَاءِ سَفْعَاءُ الْخَدَّيْنِ فَقَالَتْ لِمَ يَا رَسُولَ اللَّهِ قَالَ لِأَنَّكُنَّ تُكْثِرْنَ الشَّكَاةَ وَتَكْفُرْنَ الْعَشِيرَ قَالَ فَجَعَلْنَ يَتَصَدَّقْنَ مِنْ حُلِيِّهِنَّ يُلْقِينَ فِي ثَوْبِ بِلَالٍ مِنْ أَقْرِطَتِهِنَّ وَخَوَاتِمِهِنَّ","id":"Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Abdul Malik bin Abu Sulaiman] dari [Atha`] dari [Jabir bin Abdullah] ia berkata; Aku telah mengikuti shalat hari raya bersama Rasulullah shallallahu 'alaihi wasallam. Beliau memulainya dengan shalat sebelum menyampaikan khutbah, tanpa disertai adzan dan Iqamah. Setelah itu beliau berdiri sambil bersandar pada tangan Bilal. Kemudian beliau memerintahkan untuk selalu bertakwa kepada Allah, dan memberikan anjuran untuk selalu mentaati-nya. Beliau juga memberikan nasehat kepada manusia dan mengingatkan mereka. Setelah itu, beliau berlalu hingga sampai di tempat kaum wanita. Beliau pun memberikan nasehat dan peringatan kepada mereka. Beliau bersabda: \"Bersedekahlah kalian, karena kebanyakan kalian akan menjadi bahan bakar neraka jahannam.\" Maka berdirilah seorang wanita terbaik di antara mereka dengan wajah pucat seraya bertanya, \"Kenapa ya Rasulullah?\" beliau menjawab: \"Karena kalian lebih banyak mengadu (mengeluh) dan mengingkari kelebihan dan kebaikan suami.\" Akhirnya mereka pun menyedekahkan perhiasan yang mereka miliki dengan melemparkannya ke dalam kain yang dihamparkan Bilal, termasuk cincin dan kalung-kalung mereka."},"1386":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌ عَنْ ابْنِ عَبَّاسٍ وَعَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ الْأَنْصَارِيِّ قَالَالَمْ يَكُنْ يُؤَذَّنُ يَوْمَ الْفِطْرِ وَلَا يَوْمَ الْأَضْحَى ثُمَّ سَأَلْتُهُ بَعْدَ حِينٍ عَنْ ذَلِكَ فَأَخْبَرَنِي قَالَ أَخْبَرَنِي جَابِرُ بْنُ عَبْدِ اللَّهِ الْأَنْصَارِيُّ أَنْ لَا أَذَانَ لِلصَّلَاةِ يَوْمَ الْفِطْرِ حِينَ يَخْرُجُ الْإِمَامُ وَلَا بَعْدَ مَا يَخْرُجُ وَلَا إِقَامَةَ وَلَا نِدَاءَ وَلَا شَيْءَ لَا نِدَاءَ يَوْمَئِذٍ وَلَا إِقَامَةَ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Atha`] dari [Ibnu Abbas] dan dari [Jabir bin Abdullah Al Anshari] keduanya berkata; \"Tidak pernah dikumandangkan adzan pada saat Iedul Fithri dan tidak pula pada saat shalat Iedul Adlha.\" Kemudian setelah itu, saya menanyakan hal itu kepadanya, maka ia pun mengabarkan kepadaku, ia berkata; telah menceritakan kepadaku Jabir bin Abdullah Al Anshari bahwasanya; \"Tidak ada adzan untuk shalat Iedul Fithri saat Imam keluar, atau setelah keluarnya Imam. Dan tidak ada pula Iqamah, pengumuman serta tidak ada pula yang lain, tidak ada adzan dan tidak pula Iqamah.\""},"1387":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَطَاءٌأَنَّ ابْنَ عَبَّاسٍ أَرْسَلَ إِلَى ابْنِ الزُّبَيْرِ أَوَّلَ مَا بُويِعَ لَهُ أَنَّهُ لَمْ يَكُنْ يُؤَذَّنُ لِلصَّلَاةِ يَوْمَ الْفِطْرِ فَلَا تُؤَذِّنْ لَهَا قَالَ فَلَمْ يُؤَذِّنْ لَهَا ابْنُ الزُّبَيْرِ يَوْمَهُ وَأَرْسَلَ إِلَيْهِ مَعَ ذَلِكَ إِنَّمَا الْخُطْبَةُ بَعْدَ الصَّلَاةِ وَإِنَّ ذَلِكَ قَدْ كَانَ يُفْعَلُ قَالَ فَصَلَّى ابْنُ الزُّبَيْرِ قَبْلَ الْخُطْبَةِ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Atha`] bahwasanya; [Ibnu Abbas] mengirim seseorang kepada Ibnu Zubiar ketika pertama kali keluar (untuk menunaikan shalat Ied), \"Bahwa shalat Ied (ditunaikan) tanpa adzan. Karena itu, jangankan kamu mengumandangkan adzan.\" Maka Ibnu Zubair pun tidak menyuruh untuk mengumandangkan adzan. Kemudian para hari itu, ia juga mengutus kepadanya, bahwa penyampaian khutbah adalah sesudah shalat. Dan bahwa hal itu sebelumnya telah dilakukan oleh Rasulullah shallallahu 'alaihi wasallam. Akhirnya Ibnu Zubair pun shalat Ied sebelum khutbah."},"1388":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَحَسَنُ بْنُ الرَّبِيعِ وَقُتَيْبَةُ بْنُ سَعِيدٍ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ قَالَ يَحْيَى أَخْبَرَنَا و قَالَ الْآخَرُونَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ جَابِرِ بْنِ سَمُرَةَ قَالَصَلَّيْتُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعِيدَيْنِ غَيْرَ مَرَّةٍ وَلَا مَرَّتَيْنِ بِغَيْرِ أَذَانٍ وَلَا إِقَامَةٍ","id":"Dan Telah menceritakan kepada kami [Yahya bin Yahya] dan [Hasan bin Rabi'] dan [Qutaibah bin Sa'id] dan [Abu Bakar bin Abu Syaibah] - [Yahya] berkata- telah mengabarkan kepada kami -sementara orang-orang yang lain berkata- telah menceritakan kepada kami [Abul Ahwash] dari [Simak] dari [Jabir bin Samurah] ia berkata; Saya telah menunaikan shalat dua hari raya bersama Rasulullah shallallahu 'alaihi wasallam lebih dua kali, yakni (beliau menunaikannya) tanpa adzan dan iqamah."},"1389":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدَةُ بْنُ سُلَيْمَانَ وَأَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبَا بَكْرٍ وَعُمَرَ كَانُوا يُصَلُّونَ الْعِيدَيْنِ قَبْلَ الْخُطْبَةِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdah bin Sulaiman] dan [Abu Usamah] dari [Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam, Abu Bakar dan Umar, mereka semua menunaikan shalat dua hari raya sebelum khutbah."},"1390":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ قَالُوا حَدَّثَنَا إِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ دَاوُدَ بْنِ قَيْسٍ عَنْ عِيَاضِ بْنِ عَبْدِ اللَّهِ بْنِ سَعْدٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَخْرُجُ يَوْمَ الْأَضْحَى وَيَوْمَ الْفِطْرِ فَيَبْدَأُ بِالصَّلَاةِ فَإِذَا صَلَّى صَلَاتَهُ وَسَلَّمَ قَامَ فَأَقْبَلَ عَلَى النَّاسِ وَهُمْ جُلُوسٌ فِي مُصَلَّاهُمْ فَإِنْ كَانَ لَهُ حَاجَةٌ بِبَعْثٍ ذَكَرَهُ لِلنَّاسِ أَوْ كَانَتْ لَهُ حَاجَةٌ بِغَيْرِ ذَلِكَ أَمَرَهُمْ بِهَا وَكَانَ يَقُولُ تَصَدَّقُوا تَصَدَّقُوا تَصَدَّقُوا وَكَانَ أَكْثَرَ مَنْ يَتَصَدَّقُ النِّسَاءُ ثُمَّ يَنْصَرِفُفَلَمْ يَزَلْ كَذَلِكَ حَتَّى كَانَ مَرْوَانُ بْنُ الْحَكَمِ فَخَرَجْتُ مُخَاصِرًا مَرْوَانَ حَتَّى أَتَيْنَا الْمُصَلَّى فَإِذَا كَثِيرُ بْنُ الصَّلْتِ قَدْ بَنَى مِنْبَرًا مِنْ طِينٍ وَلَبِنٍ فَإِذَا مَرْوَانُ يُنَازِعُنِي يَدَهُ كَأَنَّهُ يَجُرُّنِي نَحْوَ الْمِنْبَرِ وَأَنَا أَجُرُّهُ نَحْوَ الصَّلَاةِ فَلَمَّا رَأَيْتُ ذَلِكَ مِنْهُ قُلْتُ أَيْنَ الِابْتِدَاءُ بِالصَّلَاةِ فَقَالَ لَا يَا أَبَا سَعِيدٍ قَدْ تُرِكَ مَا تَعْلَمُ قُلْتُ كَلَّا وَالَّذِي نَفْسِي بِيَدِهِ لَا تَأْتُونَ بِخَيْرٍ مِمَّا أَعْلَمُ ثَلَاثَ مِرَارٍ ثُمَّ انْصَرَفَ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] dan [Ibnu Hujr] mereka berkata, telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Dawud bin Qais] dari [Iyadl bin Abdullah bin Sa'd] dari [Abu Sa'id Al Khudri] bahwasanya Rasulullah shallallahu 'alaihi wasallam ketika keluar pada hari 'iedul Fitri dan 'iedul Adlha, beliau selalu memulainya dengan shalat. Dan jika beliau telah selesai mengerjakan shalat dan menutupnya dengan salam, beliau segera berdiri menghadap ke arah para jama'ah yang sedang duduk di tempat mereka shalat. Apabila beliau memiliki suatu keperluan seperti ingin mengutus sebuah pasukan beliau mengumumkannya kepada para jama'ah, atau beliau memiliki keperluan lain beliau menyuruh mereka agar mengerjakannya. Dan beliau selalu bersabda: \"Bersedekahlah kalian, bersedekahlah kalian, bersedekahlah kalian!.\" Dan orang yang paling banyak bersedekah adalah dari kalangan kaum wanita. Kemudian setelah itu beliau baru meninggalkan lapangan. Hal ini masih terus berlangsung sampai pada masa Marwan bin Al Hakam. Aku keluar dengan menggandeng Marwan hingga sampai di lapangan. Namun ternyata Katsir bin Ash Shalt telah membangun mimbar yang terbuat dari tanah dan batu bata. Dan tiba-tiba Marwan menarik tanganku seakan-akan ia menyuruhku naik ke mimbar dan memulainya dengan khutbah terlebih dahulu, dan akupun menyuruhnya untuk memulainya dengan shalat terlebih dahulu. Ketika aku melihat kejadian itu, aku berkata kepadanya, \"Mulailah dengan shalat!\" Namun ia menjawab, \"Tidak wahai Abu Sa'id, sesuatu yang kau ketahui itu telah ditinggalkan.\" Aku menjawab, \"Sekali-kali tidak, demi Dzat yang jiwaku berada di tanganNya, setahuku kalian tidak akan mendatangkan kebaikan sedikitpun (ia mengulangi hingga tiga kali).\" Kemudian ia pergi meninggalkan tempat itu."},"1391":{"ar":"حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَمَرَنَا تَعْنِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُخْرِجَ فِي الْعِيدَيْنِ الْعَوَاتِقَ وَذَوَاتِ الْخُدُورِ وَأَمَرَ الْحُيَّضَ أَنْ يَعْتَزِلْنَ مُصَلَّى الْمُسْلِمِينَ","id":"Telah menceritakan kepada kami [Abu Rabi' Az Zahrani] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ummu 'Athiyah] ia berkata; Nabi shallallahu 'alaihi wasallam memerintahkan kepada kami agar mengajak serta keluar para gadis dan wanita-wanita yang dipingit pada dua hari raya, dan beliau memerintahkan para wanita yang sedang haidl menjauh dari mushalla (tempat shalat) kaum muslimin."},"1392":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو خَيْثَمَةَ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْكُنَّا نُؤْمَرُ بِالْخُرُوجِ فِي الْعِيدَيْنِ وَالْمُخَبَّأَةُ وَالْبِكْرُ قَالَتْ الْحُيَّضُ يَخْرُجْنَ فَيَكُنَّ خَلْفَ النَّاسِ يُكَبِّرْنَ مَعَ النَّاسِ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Khaitsamah] dari [Ashim Al Ahwal] dari [Hafshah binti Sirin] dari [Ummu Athiyyah] ia berkata; Kami diperintahkan untuk turut keluar pada dua hari raya, demikian juga para para gadis. Dan para wanita yang sedang haid juga keluar, namun mereka berada di belakang jamaah dan ikut bertakbir bersama mereka."},"1393":{"ar":"و حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنَا هِشَامٌ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نُخْرِجَهُنَّ فِي الْفِطْرِ وَالْأَضْحَى الْعَوَاتِقَ وَالْحُيَّضَ وَذَوَاتِ الْخُدُورِ فَأَمَّا الْحُيَّضُ فَيَعْتَزِلْنَ الصَّلَاةَ وَيَشْهَدْنَ الْخَيْرَ وَدَعْوَةَ الْمُسْلِمِينَ قُلْتُ يَا رَسُولَ اللَّهِ إِحْدَانَا لَا يَكُونُ لَهَا جِلْبَابٌ قَالَ لِتُلْبِسْهَا أُخْتُهَا مِنْ جِلْبَابِهَا","id":"Dan telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Isa bin Yunus] telah menceritakan kepada kami [Hisyam] dari [Hafshah binti Sirin] dari [Ummu Athiyyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kepada kami agar mengajak serta keluar melakukan shalat idul fithri dan idul Adlha para gadis, wanita haid dan wanita yang sedang dipingit. Adapun mereka yang sedang haidl tidak ikut shalat, namun turut menyaksikan kebaikan dan menyambut seruan kaum muslimin. Saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam, \"Wahai Rasulullah, di antara kami ada yang tidak memiliki baju.\" Beliau menjawab: \"Hendaknya saudaranya yang memiliki jilbab memakaikannya.\""},"1394":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ حَدَّثَنَا أَبِي حَدَّثَنَا شُعْبَةُ عَنْ عَدِيٍّ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ يَوْمَ أَضْحَى أَوْ فِطْرٍ فَصَلَّى رَكْعَتَيْنِ لَمْ يُصَلِّ قَبْلَهَا وَلَا بَعْدَهَا ثُمَّ أَتَى النِّسَاءَ وَمَعَهُ بِلَالٌ فَأَمَرَهُنَّ بِالصَّدَقَةِ فَجَعَلَتْ الْمَرْأَةُ تُلْقِي خُرْصَهَا وَتُلْقِي سِخَابَهَاو حَدَّثَنِيهِ عَمْرٌو النَّاقِدُ حَدَّثَنَا ابْنُ إِدْرِيسَ ح و حَدَّثَنِي أَبُو بَكْرِ بْنُ نَافِعٍ وَمُحَمَّدُ بْنُ بَشَّارٍ جَمِيعًا عَنْ غُنْدَرٍ كِلَاهُمَا عَنْ شُعْبَةَ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Dan telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Anbari] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Syu'bah] dari [Adi] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam keluar pada hari raya Idul Adlha atau idul Fithri, lalu beliau shalat dua raka'at, beliau tidak mengerjakan shalat sebelum atau sesudahnya. Setelah itu, beliau mendatangi kaum wanita bersama Bilal. Kemudian beliau memerintahkan kepada mereka untuk bersedekah. Maka mereka (para wanita) pun memberikan anting-anting dan kalungnya. Dan telah menceritakannya kepadaku [Amru An Naqid] telah menceritakan kepada kami [Ibnu Idris] -dalam jalur lain- Dan telah menceritakan kepadaku [Abu Bakar bin Nafi'] dan [Muhammad bin Basysyar] semuanya dari [Ghundar] keduanya dari [Syu'bah] dengan sanad-sanad ini yang semisal."},"1395":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ الْمَازِنِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِأَنَّ عُمَرَ بْنَ الْخَطَّابِ سَأَلَ أَبَا وَاقِدٍ اللَّيْثِيَّ مَا كَانَ يَقْرَأُ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَضْحَى وَالْفِطْرِ فَقَالَ كَانَ يَقْرَأُ فِيهِمَا بِق وَالْقُرْآنِ الْمَجِيدِ وَاقْتَرَبَتْ السَّاعَةُ وَانْشَقَّ الْقَمَرُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Dlamrah bin Sa'id Al Mazini] dari [Ubaidullah bin Abdullah] bahwasa Umar bin Al Khaththab pernah bertanya kepada [Abu Waqid Al Laitsi], \"Surat apa yang dibaca oleh Rasulullah shallallahu 'alaihi wasallam ketika mengerjakan shalat Iedul Adlha dan Iedul Fithri?\" ia menjawab, \"Beliau membaca surat 'QAAF WAL QUR`ANIL MAJIID' dan 'IQTARABATIS SAA'ATU WAN SYAQQAL QAMAR.'\""},"1396":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَبُو عَامِرٍ الْعَقَدِيُّ حَدَّثَنَا فُلَيْحٌ عَنْ ضَمْرَةَ بْنِ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَسَأَلَنِي عُمَرُ بْنُ الْخَطَّابِ عَمَّا قَرَأَ بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمِ الْعِيدِ فَقُلْتُ بِاقْتَرَبَتِ السَّاعَةُ وَ ق وَالْقُرْآنِ الْمَجِيدِ","id":"Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abu Amir Al 'Aqadi] telah menceritakan kepada kami [Fulaih] dari [Dlamrah bin Sa'id] dari [Ubaidullah bin Abdullah bin Utbah] dari [Abu Waqid Al Laitsi] ia berkata; Umar bin Al Khathab bertanya kepadaku, \"Surat apa yang dibaca oleh Rasulullah shallallahu 'alaihi wasallam pada saat shalat Ied?\" saya menjawab, \"Yaitu, belia membaca surat, 'IQTARABATIS SAA'ATU' dan 'QAAF WAL QUR`ANIL MAJIID.'\""},"1397":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْدَخَلَ عَلَيَّ أَبُو بَكْرٍ وَعِنْدِي جَارِيَتَانِ مِنْ جَوَارِي الْأَنْصَارِ تُغَنِّيَانِ بِمَا تَقَاوَلَتْ بِهِ الْأَنْصَارُ يَوْمَ بُعَاثَ قَالَتْ وَلَيْسَتَا بِمُغَنِّيَتَيْنِ فَقَالَ أَبُو بَكْرٍ أَبِمَزْمُورِ الشَّيْطَانِ فِي بَيْتِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَذَلِكَ فِي يَوْمِ عِيدٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا بَكْرٍ إِنَّ لِكُلِّ قَوْمٍ عِيدًا وَهَذَا عِيدُنَاو حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى وَأَبُو كُرَيْبٍ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ وَفِيهِ جَارِيَتَانِ تَلْعَبَانِ بِدُفٍّ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Usamah] dari [Hisyam] dari [bapaknya] dari [Aisyah] ia berkata; Abu Bakar masuk ke dalam rumahku, sementara di tempatku terdapat dua orang budak wanita Anshar sedang bernyanyi sebagaimana yang dibawakan oleh orang-orang Anshar pada hari Bu'ats. Ia berkata, \"Namun keduanya bukanlah penyanyi yang terkenal.\" Maka Abu Bakar pun bertanya, \"Apakah di tempat Rasulullah shallallahu 'alaihi wasallam terdapat nyanyian syetan?\" Pada hari itu merupakan hari raya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Bakar, sesungguhnya setiap kaum itu miliki hari raya, dan hari ini merupakan hari raya untuk kita.\" Dan telah menceritakannya kepada kami [Yahya bin Yahya] dan [Abu Kuraib] semuanya dari [Abu Mu'awiyah] dari [Hisyam] dengan isnad ini. Dan di dalamnya dikatakan; Dua budak wanita yang bermain rebana."},"1398":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرٌو أَنَّ ابْنَ شِهَابٍ حَدَّثَهُ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أَبَا بَكْرٍ دَخَلَ عَلَيْهَا وَعِنْدَهَا جَارِيَتَانِ فِي أَيَّامِ مِنًى تُغَنِّيَانِ وَتَضْرِبَانِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسَجًّى بِثَوْبِهِ فَانْتَهَرَهُمَا أَبُو بَكْرٍ فَكَشَفَ رَسُولُ اللَّهِ عَنْهُ وَقَالَ دَعْهُمَا يَا أَبَا بَكْرٍ فَإِنَّهَا أَيَّامُ عِيدٍ وَقَالَتْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتُرُنِي بِرِدَائِهِ وَأَنَا أَنْظُرُ إِلَى الْحَبَشَةِ وَهُمْ يَلْعَبُونَ وَأَنَا جَارِيَةٌ فَاقْدِرُوا قَدْرَ الْجَارِيَةِ الْعَرِبَةِ الْحَدِيثَةِ السِّنِّ","id":"Telah menceritakan kepadaku [Harun bin Sa'id Al `Aili] telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Amru] bahwa [Ibnu Syihab] telah menceritakan kepadanya dari [Urwah] dari [Aisyah] bahwa pada hari-hari di Mina Abu Bakar masuk ke dalam rumahnya, sementara di tempatnya terdapat dua orang budak wanita yang sedang bernyanyi dan memukul rebana, sementara Rasulullah shallallahu 'alaihi wasallam menutup diri dengan kainnya. Kemudian Abu Bakar pun menghentikan keduanya, maka Rasulullah shallallahu 'alaihi wasallam pun menyingkap kainnya dan bersabda: \"Biarkanlah keduanya, wahai Abu Bakar. Karena hari-hari ini adalah hari raya.\" Aisyah berkata; \"Saya melihat Rasulullah shallallahu 'alaihi wasallam menutupiku dengan kainnya, sementara saya sedang melihat kepada orang-orang Habasyah yang sedang bermain. Saya adalah seorang anak wanita, karena itu berilah kesempatan kepada para anak wanita untuk bermain.\""},"1399":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ قَالَ قَالَتْ عَائِشَةُوَاللَّهِ لَقَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُومُ عَلَى بَابِ حُجْرَتِي وَالْحَبَشَةُ يَلْعَبُونَ بِحِرَابِهِمْ فِي مَسْجِدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتُرُنِي بِرِدَائِهِ لِكَيْ أَنْظُرَ إِلَى لَعِبِهِمْ ثُمَّ يَقُومُ مِنْ أَجْلِي حَتَّى أَكُونَ أَنَا الَّتِي أَنْصَرِفُ فَاقْدِرُوا قَدْرَ الْجَارِيَةِ الْحَدِيثَةِ السِّنِّ حَرِيصَةً عَلَى اللَّهْوِ","id":"Dan telah menceritakan kepadaku [Abu Thahir] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] dari [Urwah bin Zubair] ia berkata, [Aisyah] berkata; \"Saya melihat Rasulullah shallallahu 'alaihi wasallam berdiri di pintu kamarku, sementara orang-orang Habasyah sedang bermain tombak di masjid Rasulullah shallallahu 'alaihi wasallam, maka beliau menutupiku dengan kainnya agar aku dapat melihat permainan mereka. Kemudian beliau berdiri (agar aku lebih leluasa melihat), sampai saya sendiri yang berhenti (setelah bosan) melihatnya. Karena itu, berilah keleluasaan kepada anak-anak wanita untuk bermain.\""},"1400":{"ar":"حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَيُونُسُ بْنُ عَبْدِ الْأَعْلَى وَاللَّفْظُ لِهَارُونَ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنَا عَمْرٌو أَنَّ مُحَمَّدَ بْنَ عَبْدِ الرَّحْمَنِ حَدَّثَهُ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي جَارِيَتَانِ تُغَنِّيَانِ بِغِنَاءِ بُعَاثٍ فَاضْطَجَعَ عَلَى الْفِرَاشِ وَحَوَّلَ وَجْهَهُ فَدَخَلَ أَبُو بَكْرٍ فَانْتَهَرَنِي وَقَالَ مِزْمَارُ الشَّيْطَانِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ دَعْهُمَا فَلَمَّا غَفَلَ غَمَزْتُهُمَا فَخَرَجَتَا وَكَانَ يَوْمَ عِيدٍ يَلْعَبُ السُّودَانُ بِالدَّرَقِ وَالْحِرَابِ فَإِمَّا سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِمَّا قَالَ تَشْتَهِينَ تَنْظُرِينَ فَقُلْتُ نَعَمْ فَأَقَامَنِي وَرَاءَهُ خَدِّي عَلَى خَدِّهِ وَهُوَ يَقُولُ دُونَكُمْ يَا بَنِي أَرْفِدَةَ حَتَّى إِذَا مَلِلْتُ قَالَ حَسْبُكِ قُلْتُ نَعَمْ قَالَ فَاذْهَبِي","id":"Telah menceritakan kepadaku [Harun bin Sa'id Al `Aili] dan [Yunus bin Abdul A'la] -sedangkan lafazhnya dari Harun- keduanya berkata, telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepada kami [Amru] bahwa [Muhammad bin Abdur Rahman] telah menceritakan kepadanya dari ['Urwah] dari [Aisyah] ia berkata; Suatu ketika Rasulullah shallallahu 'alaihi wasallam masuk ke dalam rumahku, sementara di tempatku terdapat dua orang budak wanita yang sedang bernyanyi dengan nyanyian Bu'ats, lalu beliau langsung berbaring diatas tempat tidur dengan membalikkan wajahnya. Setelah itu, masuklah Abu Bakar dan langsung marah seraya berkata, \"Nyanyian syetan ada di sisi Rasulullah shallallahu 'alaihi wasallam?.\" Maka Rasulullah shallallahu 'alaihi wasallam pun menemuinya dan bersabda: \"Biarkanlah mereka berdua.\" Ketika ia tidak mengindahkan lagi, maka saya pun memberi isyarat pada kedua budak wanita itu sehingga keduanya pun keluar. Kemudian pada hari raya, orang-orang berkulit hitam bermain baju besi dan tombak. Kemungkinan saya yang bertanya kepada Rasulullah shallallahu 'alaihi wasallam atau pun beliau yang bertanya padaku, \"Apakah kamu ingin melihatnya?\" Saya menjawab, \"Ya.\" Maka beliau pun meletakkanku berdiri di belakangnya, pipiku menempel di pipi beliau. Dan beliau bersabda: \"Silahkan kalian bermain-main, wahai bani Arfidah (gelar bangsa Habasyah).\" Hingga apabila aku bosan, beliau bertanya, \"Cukup?\" Aku menjawab, \"Ya.\" Beliau berkata, \"Pergilah.\""},"1401":{"ar":"حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرٌ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَ حَبَشٌ يَزْفِنُونَ فِي يَوْمِ عِيدٍ فِي الْمَسْجِدِ فَدَعَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَضَعْتُ رَأْسِي عَلَى مَنْكِبِهِ فَجَعَلْتُ أَنْظُرُ إِلَى لَعِبِهِمْ حَتَّى كُنْتُ أَنَا الَّتِي أَنْصَرِفُ عَنْ النَّظَرِ إِلَيْهِمْو حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَحْيَى بْنُ زَكَرِيَّاءَ بْنِ أَبِي زَائِدَةَ ح و حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا مُحَمَّدُ بْنُ بِشْرٍ كِلَاهُمَا عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ وَلَمْ يَذْكُرَا فِي الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Zuhair bin Harb] telah menceritakan kepada kami [Jarir] dari [Hisyam] dari [bapaknya] dari [Aisyah] ia berkata; Orang-orang Habasyah sedang bermain-main di Masjid pada hari raya. Maka Nabi shallallahu 'alaihi wasallam memanggilku, aku pun meletakkan kepala di atas pundaknya untuk melihat permainan mereka sampai aku sendiri yang berhenti melihat mereka. Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yahya bin Zakariya bin Abu Za`idah] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Muhammad bin Bisyr] keduanya dari [Hisyam] dengan isnad ini, namun ia tidak menyebutkan; \"Di dalam masjid.\""},"1402":{"ar":"و حَدَّثَنِي إِبْرَاهِيمُ بْنُ دِينَارٍ وَعُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ وَعَبْدُ بْنُ حُمَيْدٍ كُلُّهُمْ عَنْ أَبِي عَاصِمٍ وَاللَّفْظُ لِعُقْبَةَ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ أَخْبَرَنِي عُبَيْدُ بْنُ عُمَيْرٍ أَخْبَرَتْنِي عَائِشَةُأَنَّهَا قَالَتْ لِلَعَّابِينَ وَدِدْتُ أَنِّي أَرَاهُمْ قَالَتْ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقُمْتُ عَلَى الْبَابِ أَنْظُرُ بَيْنَ أُذُنَيْهِ وَعَاتِقِهِ وَهُمْ يَلْعَبُونَ فِي الْمَسْجِدِقَالَ عَطَاءٌ فُرْسٌ أَوْ حَبَشٌ قَالَ وَقَالَ لِي ابْنُ عَتِيقٍ بَلْ حَبَشٌ","id":"Dan telah menceritakan kepadaku [Ibrahim bin Dinar] dan [Uqbah bin Murqam Al Amiy] dan [Abdu bin Humaid] semuanya dari [Abu Ashim] -sementara lafazhnya dari Uqbah- ia berkata, Telah menceritakan kepada kami [Abu Ashim] dari [Ibnu Juraij] ia berkata, telah mengabarkan kepadaku [Atha`] telah mengabarkan kepadaku [Ubaid bin Umair] telah mengabarkan kepadaku [Aisyah] bahwa ia berkata berkenaan dengan orang sedang bermain-main, \"Saya ingin melihat mereka.\" Maka Rasulullah shallallahu 'alaihi wasallam berdiri dan saya pun ikut berdiri di atas pintu sehingga saya melihat di antara kedua telinga dan pundak beliau, sementara mereka bermain-main di masjid. Atha` bertanya; Orang-orang Faris ataukah Habasyi? Dan Ibnu 'Atiq berkata kepadaku; Bahkan mereka adalah orang-orang Habasyi."},"1403":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنَا وَقَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَمَا الْحَبَشَةُ يَلْعَبُونَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحِرَابِهِمْ إِذْ دَخَلَ عُمَرُ بْنُ الْخَطَّابِ فَأَهْوَى إِلَى الْحَصْبَاءِ يَحْصِبُهُمْ بِهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعْهُمْ يَا عُمَرُ","id":"Dan telah menceritakan kepadaku [Muhammad bin Rafi'] dan [Abdu bin Humaid] -Abdu berkata- telah mengabarkan kepada kami -Ibnu Rafi' berkata- telah menceritakan kepada kami [Abdur Razaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari [Ibnul Musayyab] dari [Abu Hurairah] ia berkata; Ketika orang-orang Habasyah bermain-main tombak di sisi Rasulullah shallallahu 'alaihi wasallam, tiba-tiba Umar bin Al Khathab masuk dan segera mengulurkan tangannya mengambil tombak kecil untuk melempar mereka. Namun Rasulullah shallallahu 'alaihi wasallam segera bersabda: \"Biarkanlah mereka wahai Umar.\""},"1404":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ أَنَّهُ سَمِعَ عَبَّادَ بْنَ تَمِيمٍ يَقُولُ سَمِعْتُ عَبْدَ اللَّهِ بْنَ زَيْدٍ الْمَازِنِيَّ يَقُولُاخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُصَلَّى فَاسْتَسْقَى وَحَوَّلَ رِدَاءَهُ حِينَ اسْتَقْبَلَ الْقِبْلَةَ","id":"Dan telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Abdullah bin Bakar] bahwa ia mendengar ['Abbad bin Tamim] berkata, saya mendengar [Abdullah bin Zaid Al Mazani] berkata; \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam keluar ke tanah lapang untuk menunaikan shalat Istisqa`, kemudian beliau membalik pakaiannya ketika menghadap kiblat."},"1405":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَبَّادِ بْنِ تَمِيمٍ عَنْ عَمِّهِ قَالَخَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمُصَلَّى فَاسْتَسْقَى وَاسْتَقْبَلَ الْقِبْلَةَ وَقَلَبَ رِدَاءَهُ وَصَلَّى رَكْعَتَيْنِ","id":"Dan Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Sufyan bin Uyainah] dari [Abdullah bin Abu Bakar] dari [Abbad bin Tamim] dari [pamannya] ia berkata; \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam keluar menuju Mushalla (tanah lapang untuk shalat) hendak menunaikan shalat Istisqa`, maka beliau pun menghadap kiblat dan membalik pakaiannya kemudian shalat dua raka'at.\""},"1406":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي أَبُو بَكْرِ بْنُ مُحَمَّدِ بْنِ عَمْرٍو أَنَّ عَبَّادَ بْنَ تَمِيمٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ بْنَ زَيْدٍ الْأَنْصَارِيَّ أَخْبَرَهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الْمُصَلَّى يَسْتَسْقِي وَأَنَّهُ لَمَّا أَرَادَ أَنْ يَدْعُوَ اسْتَقْبَلَ الْقِبْلَةَ وَحَوَّلَ رِدَاءَهُ","id":"Dan Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] ia berkata, telah mengabarkan kepadaku [Abu Bakar bin Muhammad bin Amru] bahwa [Abbad bin Tamim] telah mengabarkan kepadanya, bahwa [Abdullah bin Zaid Al Anshari] telah mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam keluar ke tanah lapang untuk menunaikan shalat Istisqa`. Dan ketika beliau hendak berdo'a, beliau menghadap kiblat dan membalik pakaiannya."},"1407":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ قَالَا أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبَّادُ بْنُ تَمِيمٍ الْمَازِنِيُّ أَنَّهُ سَمِعَ عَمَّهُ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُاخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا يَسْتَسْقِي فَجَعَلَ إِلَى النَّاسِ ظَهْرَهُ يَدْعُو اللَّهَ وَاسْتَقْبَلَ الْقِبْلَةَ وَحَوَّلَ رِدَاءَهُ ثُمَّ صَلَّى رَكْعَتَيْنِ","id":"Dan telah menceritakan kepadaku [Abu Thahir] dan [Harmalah] keduanya berkata, telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata, telah mengabarkan kepadaku [Abbad bin Tamim Al Mazini] bahwa ia mendengar [pamannya] yang termasuk salah seorang dari sahabat Rasulullah shallallahu 'alaihi wasallam berkata; \"Suatu ketika Rasulullah shallallahu 'alaihi wasallam keluar untuk menunaikan shalat Istisqa`, lalu beliau membelakangi para jama'ah seraya berdo'a kepada Allah dengan menghadap kiblat. Kemudian beliau membalik pakaiannya lalu shalat dua raka'at.\""},"1408":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ عَنْ شُعْبَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْفَعُ يَدَيْهِ فِي الدُّعَاءِ حَتَّى يُرَى بَيَاضُ إِبْطَيْهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Abu Bukair] dari [Syu'bah] dari [Tsabit] dari [Anas] ia berkata; \"Saya melihat Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya saat berdo'a hingga terlihat putih ketiaknya.\""},"1409":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ وَعَبْدُ الْأَعْلَى عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَنَسٍأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ لَا يَرْفَعُ يَدَيْهِ فِي شَيْءٍ مِنْ دُعَائِهِ إِلَّا فِي الِاسْتِسْقَاءِ حَتَّى يُرَى بَيَاضُ إِبْطَيْهِغَيْرَ أَنَّ عَبْدَ الْأَعْلَى قَالَ يُرَى بَيَاضُ إِبْطِهِ أَوْ بَيَاضُ إِبْطَيْهِ و حَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ أَنَّ أَنَسَ بْنَ مَالِكٍ حَدَّثَهُمْ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] dan [Abdul A'la] dari [Sa'id] dari [Qatadah] dari [Anas] bahwasanya; Nabi shallallahu 'alaihi wasallam tidak mengangkat kedua tangannya ketika berdo'a kecuali dalam shalat Istisqa`, hingga terlihat putih ketiak beliau.\" Namun Abdul A'la berkata; terlihat putih ketiak beliau atau kedua ketiak beliau. Dan telah menceritakan kepada kami [Ibnul Mutsanna] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Abu Arubah] dari [Qatadah] bahwa [Anas bin Malik] telah menceritakan kepada mereka, dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1410":{"ar":"و حَدَّثَنَا عَبْدُ بْنُ حُمَيْدٍ حَدَّثَنَا الْحَسَنُ بْنُ مُوسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَسْقَى فَأَشَارَ بِظَهْرِ كَفَّيْهِ إِلَى السَّمَاءِ","id":"Dan telah menceritakan kepada kami [Abdu bin Humaid] telah menceritakan kepada kami [Al Hasan bin Musa] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam shalat Istisqa, lalu beliau memberi isyarat ke langit dengan punggung kedua telapak tangannya."},"1411":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَيَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ قَالَ يَحْيَى أَخْبَرَنَا وَقَالَ الْآخَرُونَ حَدَّثَنَا ��ِسْمَعِيلُ بْنُ جَعْفَرٍ عَنْ شَرِيكِ بْنِ أَبِي نَمِرٍ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَجُلًا دَخَلَ الْمَسْجِدَ يَوْمَ جُمُعَةٍ مِنْ بَابٍ كَانَ نَحْوَ دَارِ الْقَضَاءِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا ثُمَّ قَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْأَمْوَالُ وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ يُغِثْنَا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ ثُمَّ قَالَ اللَّهُمَّ أَغِثْنَا اللَّهُمَّ أَغِثْنَا اللَّهُمَّ أَغِثْنَا قَالَ أَنَسٌ وَلَا وَاللَّهِ مَا نَرَى فِي السَّمَاءِ مِنْ سَحَابٍ وَلَا قَزَعَةٍ وَمَا بَيْنَنَا وَبَيْنَ سَلْعٍ مِنْ بَيْتٍ وَلَا دَارٍ قَالَ فَطَلَعَتْ مِنْ وَرَائِهِ سَحَابَةٌ مِثْلُ التُّرْسِ فَلَمَّا تَوَسَّطَتْ السَّمَاءَ انْتَشَرَتْ ثُمَّ أَمْطَرَتْ قَالَ فَلَا وَاللَّهِ مَا رَأَيْنَا الشَّمْسَ سَبْتًا قَالَ ثُمَّ دَخَلَ رَجُلٌ مِنْ ذَلِكَ الْبَابِ فِي الْجُمُعَةِ الْمُقْبِلَةِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ يَخْطُبُ فَاسْتَقْبَلَهُ قَائِمًا فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَتْ الْأَمْوَالُ وَانْقَطَعَتْ السُّبُلُ فَادْعُ اللَّهَ يُمْسِكْهَا عَنَّا قَالَ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَيْهِ ثُمَّ قَالَ اللَّهُمَّ حَوْلَنَا وَلَا عَلَيْنَا اللَّهُمَّ عَلَى الْآكَامِ وَالظِّرَابِ وَبُطُونِ الْأَوْدِيَةِ وَمَنَابِتِ الشَّجَرِ فَانْقَلَعَتْ وَخَرَجْنَا نَمْشِي فِي الشَّمْسِقَالَ شَرِيكٌ فَسَأَلْتُ أَنَسَ بْنَ مَالِكٍ أَهُوَ الرَّجُلُ الْأَوَّلُ قَالَ لَا أَدْرِي و حَدَّثَنَا دَاوُدُ بْنُ رُشَيْدٍ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ عَنْ الْأَوْزَاعِيِّ حَدَّثَنِي إِسْحَقُ بْنُ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ أَصَابَتْ النَّاسَ سَنَةٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ عَلَى الْمِنْبَرِ يَوْمَ الْجُمُعَةِ إِذْ قَامَ أَعْرَابِيٌّ فَقَالَ يَا رَسُولَ اللَّهِ هَلَكَ الْمَالُ وَجَاعَ الْعِيَالُ وَسَاقَ الْحَدِيثَ بِمَعْنَاهُ وَفِيهِ قَالَ اللَّهُمَّ حَوَالَيْنَا وَلَا عَلَيْنَا قَالَ فَمَا يُشِيرُ بِيَدِهِ إِلَى نَاحِيَةٍ إِلَّا تَفَرَّجَتْ حَتَّى رَأَيْتُ الْمَدِينَةَ فِي مِثْلِ الْجَوْبَةِ وَسَالَ وَادِي قَنَاةَ شَهْرًا وَلَمْ يَجِئْ أَحَدٌ مِنْ نَاحِيَةٍ إِلَّا أَخْبَرَ بِجَوْدٍ و حَدَّثَنِي عَبْدُ الْأَعْلَى بْنُ حَمَّادٍ وَمُحَمَّدُ بْنُ أَبِي بَكْرٍ الْمُقَدَّمِيُّ قَالَا حَدَّثَنَا مُعْتَمِرٌ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ يَوْمَ الْجُمُعَةِ فَقَامَ إِلَيْهِ النَّاسُ فَصَاحُوا وَقَالُوا يَا نَبِيَّ اللَّهِ قَحَطَ الْمَطَرُ وَاحْمَرَّ الشَّجَرُ وَهَلَكَتْ الْبَهَائِمُ وَسَاقَ الْحَدِيثَ وَفِيهِ مِنْ رِوَايَةِ عَبْدِ الْأَعْلَى فَتَقَشَّعَتْ عَنْ الْمَدِينَةِ فَجَعَلَتْ تُمْطِرُ حَوَالَيْهَا وَمَا تُمْطِرُ بِالْمَدِينَةِ قَطْرَةً فَنَظَرْتُ إِلَى الْمَدِينَةِ وَإِنَّهَا لَفِي مِثْلِ الْإِكْلِيلِ و حَدَّثَنَاه أَبُو كُرَيْبٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ بِنَحْوِهِ وَزَادَ فَأَلَّفَ اللَّهُ بَيْنَ السَّحَابِ وَمَكَثْنَا حَتَّى رَأَيْتُ الرَّجُلَ الشَّدِيدَ تَهُمُّهُ نَفْسُهُ أَنْ يَأْتِيَ أَهْلَهُ و حَدَّثَنَا هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ حَدَّثَنِي أُسَامَةُ أَنَّ حَفْصَ بْنَ عُبَيْدِ اللَّهِ بْنِ أَنَسِ بْنِ مَالِكٍ حَدَّثَهُ أَنَّهُ سَمِعَ أَنَسَ بْنَ مَالِكٍ يَقُولُا جَاءَ أَعْرَابِيٌّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ الْجُمُعَةِ وَهُوَ عَلَى الْمِنْبَرِ وَاقْتَصَّ الْحَدِيثَ وَزَادَ فَرَأَيْتُ السَّحَابَ يَتَمَزَّقُ كَأَنَّهُ الْمُلَاءُ حِينَ تُطْوَى","id":"Dan Telah meceritakan kepada kami [Yahya bin Yahya] dan [Yahya bin Ayyub] dan [Qutaibah] dan [Ibnu Hujr] -Yahya berkata- telah mengabarkan kepada kami -sementara yang lain berkata- Telah menceritakan kepada kami [Isma'il bin Ja'far] dari [Syarik bin Abu Namir] dari [Anas bin Malik] bahwasanya; Ada seorang laki-laki yang masuk Masjid pada hari Jum'at dari pintu yang menghadap Darul Qadla`, sementara Rasulullah shallallahu 'alaihi wasallam berdiri sedang menyampaikan khutbah. Kemudian laki-laki itu segera menghadap ke arah Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, harta benda telah binasa dan jalan pun telah terputus. Karena itu, berdo'alah kepada Allah agar menurunkan hujan.\" Maka Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya seraya berdo'a: \"ALLAHUMMA AGHITSNAA ALLAHUMMA AGHITSNAA, ALLAHUMMA AGHITSNAA (Ya Allah, turunkanlah hujan kepada kami. Ya Allah, turunkanlah hujan kepada kami, Ya Allah, turunkanlah hujan kepada kami). Anas berkata, \"Tidak, demi Allah, kami tidak melihat mendung maupun gumpalan awan sedikitpun di langit, juga tidak ada di antara kami ataupun di antara celah meski satu rumah maupun tempat tinggal.\" Ia berkata, \"Maka datanglah dari arah belakangnya segumpalan awan yang menyerupai sebuah perisai. Setelah memenuhi langit, awan tersebut menyebar lalu turunlah hujan.\" Ia berkata, \"Tidak, demi Allah kami tidak dapat melihat matahari kala itu.\" Ia berkata, \"Kemudian ada seorang laki-laki yang masuk melalui pintu tersebut pada hari Jum'at selanjutnya, sedangkan Rasulullah shallallahu 'alaihi wasallam sedang berdiri menyampaikan khutbah, maka ia menghampiri beliau dengan berdiri dan mengatakan, \"Wahai Rasulullah, harta benda kami telah lenyap dan jalan-jalan pun sudah buntu, maka berdo'alah kepada Allah supaya Dia menetapkannya bagi kami.\" Ia mengatakan, \"Maka Rasulullah shallallahu 'alaihi wasallam mengangkat kedua tangannya lalu berdo'a, \"Ya Allah! Hujanilah di sekitar kami, jangan kepada kami. Ya, Allah! Berilah hujan ke daratan tinggi, beberapa anak bukit, perut lembah dan beberapa tanah yang menumbuhkan pepohonan.\" Maka kami segera berdiri dan keluar berjalan di bawah sinar matahari.\" Syarik berkata; Lalu aku pun bertanya kepada Anas bin Malik, \"Apakah laki-laki itu adalah laki-laki yang pertama?\" Ia menjawab, \"Saya tidak tahu.\" Dan telah meceritakan kepada kami [Dawud bin Rusyaidin] telah menceritakan kepada kami [Al Walid bin Muslim] dari [Al Auza'i] telah menceritakan kepadaku [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas bin Malik] ia berkata; Orang-orang tertimpa musim paceklik pada masa Rasulullah shallallahu 'alaihi wasallam. Maka ketika Rasulullah shallallahu 'alaihi wasallam sedang menyampaikan khutbah kepada orang banyak di atas mimbar pada hari Jum'at, tiba-tiba berdirilah seorang Arab pegunungan dan berkata, \"Wahai Rasulullah, harta telah binasa dan sanak keluarga kami pun kelaparan.\" Ia pun menuturkan hadits yang semakna dengan hadits di atas. Dan di dalamnya ia menyebutkan do'a: \"ALLAHUMMA HAWAALAINAA WALAA 'ALAINAA (Ya Allah, hujanilah sekitar kami dan jangan kepada kami).\" Dan tidaklah beliau memberi isyarat dengan tangannya, kecuali terlihat (gumpalan awan), hingga aku melihat kota Madinah bagaikan lobang. Dan lembah Qanath mengalirkan airnya selama satu bulan, dan tidaklah seseorang datang dari seberang, kecuali dengan membawa berita terjadinya hujan yang lebat. Dan telah menceritakan kepadaku [Abdul A'la bin Hammad] dan [Muhammad bin Abu Bakar Al Muqaddami] keduanya berkata, telah menceritakan kepada kami [Mu'tamir] telah menceritakan kepada kami [Ubaidullah] dari [Tsabit Al Bunani] dari [Anas bin Malik] ia berkata; Nabi shallallahu 'alaihi wasallam menyampaikan khutbah pada hari Jum'at, kemudian orang-orang datang kepada beliau dengan berteriak seraya berkata, \"Wahai Nabi Allah, hujan tak lagi turun, pepohonan telah memerah dan hewan ternak pun telah binasa.\" Ia pun menuturkan hadits. Dan di dalamnya -dari riwayatnya Abdul A'la- tercantum; \"Kemudian (awan itu pun) menyebar dari Madinah, hingga hujan pun turun membasahi sekelilingnya, sementara di kota Madinah tak turun hujan setetes pun. Sesudah itu, aku melihat Madinah, ternyata kota Madinah saat itu benar-benar seperti mahkota (lantaran hujan telah merata membasahinya).\" Dan telah menceritakan kepada kami [Abu Kuraib] telah menceritakan kepada kami [Abu Usamah] dari [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas] semisalnya. Dan ia menambahkan; \"Maka Allah menyatukan gumpalan-gumpalan awan itu, lalu kami tinggal di situ sejenak hingga aku melihat laki-laki itu tak sanggup lagi menahan keinginannya untuk segera mendatangi keluarganya.\" Dan Telah menceritakan kepada kami [Harun bin Sa'id Al Aili] Telah menceritakan kepada kami [Ibnu Wahab] telah menceritakan kepadaku [Usamah] bahwa [Hafsh bin Ubaidullah bin Anas bin Malik] telah menceritakan kepadanya, bahwa ia mendengar [Anas bin Malik] berkata; \"Ada seorang A'rabi (Arab pegunungan) datang kepada Rasulullah shallallahu 'alaihi wasallam pada hari Jum'at saat beliau berada di atas mimbar.\" Ia pun menuturkan hadits itu, dan ia menambahkan; \"Maka aku pun melihat awan yang saling memisah bagaikan air saat dituangkan.\""},"1412":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسٍ قَالَقَالَ أَنَسٌ أَصَابَنَا وَنَحْنُ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَطَرٌ قَالَ فَحَسَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَوْبَهُ حَتَّى أَصَابَهُ مِنْ الْمَطَرِ فَقُلْنَا يَا رَسُولَ اللَّهِ لِمَ صَنَعْتَ هَذَا قَالَ لِأَنَّهُ حَدِيثُ عَهْدٍ بِرَبِّهِ تَعَالَى","id":"Dan Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Ja'far bin Sulaiman] dari [Tsabit Al Bunani] dari [Anas] ia berkata; Kami diguyur hujan ketika bersama Rasulullah shallallahu 'alaihi wasallam, beliau membuka pakaiannya sehingga terkena hujan, lalu kami pun bertanya, \"Wahai Rasulullah, kenapa Anda melakukan hal itu?\" beliau menjawab: \"Karena hujan ini merupakan rahmat yang diberikan oleh Allah ta'ala.\""},"1413":{"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ جَعْفَرٍ وَهُوَ ابْنُ مُحَمَّدٍ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ أَنَّهُ سَمِعَ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَانَ يَوْمُ الرِّيحِ وَالْغَيْمِ عُرِفَ ذَلِكَ فِي وَجْهِهِ وَأَقْبَلَ وَأَدْبَرَ فَإِذَا مَطَرَتْ سُرَّ بِهِ وَذَهَبَ عَنْهُ ذَلِكَ قَالَتْ عَائِشَةُ فَسَأَلْتُهُ فَقَالَ إِنِّي خَشِيتُ أَنْ يَكُونَ عَذَابًا سُلِّطَ عَلَى أُمَّتِي وَيَقُولُ إِذَا رَأَى الْمَطَرَ رَحْمَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Sulaiman, yaitu anaknya Bilal] dari [Ja'far, yaitu anaknya Muhammad] dari [Atha` bin Abu Rabah] bahwa ia mendengar [Aisyah] isteri Nabi shallallahu 'alaihi wasallam berkata; Apabila ada angin bertiup kencang sekali, maka hal itu dapat diketahui dari wajah beliau shallallahu 'alaihi wasallam, beliau bolak-balik ke depan dan ke belakang. Dan ketika hujan turun, maka beliau pun senang dan hilanglah kekhawatirannya. Aisyah berkata; Maka saya pun menanyakan hal itu pada beliau, beliau menjawab: \"Saya khawatir, bisa jadi hal itu akan menjadi adzab yang ditimpakan kepada umatku.\" Dan ketika melihat hujan beliau bersabda: \"(ini adalah) rahmat.\""},"1414":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا ابْنُ وَهْبٍ قَالَ سَمِعْتُ ابْنَ جُرَيْجٍ يُحَدِّثُنَا عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا عَصَفَتْ الرِّيحُ قَالَ اللَّهُمَّ إِنِّي أَسْأَلُكَ خَيْرَهَا وَخَيْرَ مَا فِيهَا وَخَيْرَ مَا أُرْسِلَتْ بِهِ وَأَعُوذُ بِكَ مِنْ شَرِّهَا وَشَرِّ مَا فِيهَا وَشَرِّ مَا أُرْسِلَتْ بِهِ قَالَتْ وَإِذَا تَخَيَّلَتْ السَّمَاءُ تَغَيَّرَ لَوْنُهُ وَخَرَجَ وَدَخَلَ وَأَقْبَلَ وَأَدْبَرَ فَإِذَا مَطَرَتْ سُرِّيَ عَنْهُ فَعَرَفْتُ ذَلِكَ فِي وَجْهِهِ قَالَتْ عَائِشَةُ فَسَأَلْتُهُ فَقَالَ لَعَلَّهُ يَا عَائِشَةُ كَمَا قَالَ قَوْمُ عَادٍ{ فَلَمَّا رَأَوْهُ عَارِضًا مُسْتَقْبِلَ أَوْدِيَتِهِمْ قَالُوا هَذَا عَارِضٌ مُمْطِرُنَا }","id":"Dan telah menceritakan kepadaku [Abu Thahir] telah mengabarkan kepada kami [Ibnu Wahb] ia berkata, saya mendengar [Ibnu Juraij] menceritakan dari [Atha` bin Abu Rabah] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa ia berkata; Apabila ada angin bertiup kencang sekali, maka Nabi shallallahu 'alaihi wasallam biasanya membaca: \"ALLAHUMMA INNII ASALUKA KHAIRAHAA WA KHAIRA MAA FIIHAA WA KHAIRA MAA URSILAT BIHI WA A'UUDZU BIKA MIN SYARRIHAA WA SYARRI MAA FIIHAA WA SYARRI MAA URSILAT BIHI (Ya Allah, sungguh, aku memohon kepada-Mu kebaikan angin, kebaikan yang dikandungnya, dan kebaikan yang dibawanya. Dan aku berlindung kepada-Mu dari keburukannya, keburukan yang ada di dalamnya dan keburukan yang dibawanya).\" Apabila langit gelap berawan, maka beliau akan kelihatan pucat, keluar masuk rumah, ke depan dan ke belakang. Dan jika hujan turun, beliau pun merasa lega, dan hal itu dapat diketahui dari raut wajahnya. Aisyah berkata; Saya menanyakan hal itu pada beliau, maka beliau berkata: \"Wahai Aisyah, kalau cuaca seperti ini, saya khawatir jangan-jangan akan terjadi seperti apa yang diungkapkan oleh kaum 'Aad, 'Maka tatkala mereka melihat azab itu berupa awan yang menuju ke lembah-lembah mereka, berkatalah mereka: 'Inilah awan yang akan menurunkan hujan kepada kami.\""},"1415":{"ar":"و حَدَّثَنِي هَارُونُ بْنُ مَعْرُوفٍ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ ح و حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنَا عَمْرُو بْنُ الْحَارِثِ أَنَّ أَبَا النَّضْرِ حَدَّثَهُ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا قَالَتْمَا رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُسْتَجْمِعًا ضَاحِكًا حَتَّى أَرَى مِنْهُ لَهَوَاتِهِ إِنَّمَا كَانَ يَتَبَسَّمُ قَالَتْ وَكَانَ إِذَا رَأَى غَيْمًا أَوْ رِيحًا عُرِفَ ذَلِكَ فِي وَجْهِهِ فَقَالَتْ يَا رَسُولَ اللَّهِ أَرَى النَّاسَ إِذَا رَأَوْا الْغَيْمَ فَرِحُوا رَجَاءَ أَنْ يَكُونَ فِيهِ الْمَطَرُ وَأَرَاكَ إِذَا رَأَيْتَهُ عَرَفْتُ فِي وَجْهِكَ الْكَرَاهِيَةَ قَالَتْ فَقَالَ يَا عَائِشَةُ مَا يُؤَمِّنُنِي أَنْ يَكُونَ فِيهِ عَذَابٌ قَدْ عُذِّبَ قَوْمٌ بِالرِّيحِ وَقَدْ رَأَى قَوْمٌ الْعَذَابَ فَقَالُوا{ هَذَا عَارِضٌ مُمْطِرُنَا }","id":"Dan telah menceritakan kepadaku [Harun bin Ma'ruf] telah menceritakan kepada kami [Ibnu Wahb] dari [Amru bin Harits] -dalam jalur lain- Dan telah menceritakan kepadaku [Abu Thahir] telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepada kami [Amru bin Harits] bahwa [Abu Nadlr] telah menceritakan kepadanya dari [Sulaiman bin Yasar] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, bahwa ia berkata; \"Saya tidak pernah melihat Rasulullah shallallahu 'alaihi wasallam tertawa terbahak-bahak hingga kelihatan tenggorokan beliau, karena biasanya beliau hanya tersenyum.\" Aisyah juga berkata; Dan jika beliau melihat awan hitam mengkelam atau angin yang bertiup kencang, maka (kekhawatiran) dapat dilihat dari raut wajah beliau. Aisyah pun bertanya, \"Wahai Rasulullah, saya memperhatikan manusia, bila mereka melihat kabut hitam, maka mereka begitu senang, karena akan segera turun hujan, namun saya memperhatikan Tuan ketika melihatnya, saya dapat menangkap (kekhawatiran) di raut muka Tuan.\" Beliau menjawab: \"Wahai Aisyah, saya khawatir bahwa kabut itu akan menjadi adzab. Sungguh, telah ada suatu kaum yang diadzab dengan angin, dan kaum itu pun telah melihat adzab, namun mereka berkata, 'Inilah awan yang akan menurunkan hujan kepada kami.'\""},"1416":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا غُنْدَرٌ عَنْ شُعْبَةَ ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَابْنُ بَشَّارٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ مُجَاهِدٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ نُصِرْتُ بِالصَّبَا وَأُهْلِكَتْ عَادٌ بِالدَّبُورِو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ مُحَمَّدِ بْنِ أَبَانٍ الْجُعْفِيُّ حَدَّثَنَا عَبْدَةُ يَعْنِي ابْنَ سُلَيْمَانَ كِلَاهُمَا عَنْ الْأَعْمَشِ عَنْ مَسْعُودِ بْنِ مَالِكٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Ghandar] dari [Syu'bah] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Ibnu Basysyar] keduanya berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Mujahid] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Aku mendapat pertolongan dengan angin timur dan kaum 'Aad dibinasakan dengan angin Barat.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Mu'awiyah] -dalam jalur lain- Dan telah menceritakan kepada kami [Abdullah bin Umar bin Muhammad bin Aban Al Ju'fi] telah menceritakan kepada kami [Abdah, yakni anaknya Sulaiman] keduanya dari [Al A'masy] dari [Mas'ud bin Malik] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1417":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَاللَّفْظُ لَهُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْخَسَفَتْ الشَّمْسُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُصَلِّي فَأَطَالَ الْقِيَامَ جِدًّا ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ جِدًّا ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِيَامَ جِدًّا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ جِدًّا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ رَأْسَهُ فَقَامَ فَأَطَالَ الْقِيَامَ وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَأَطَالَ الرُّكُوعَ وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَخَطَبَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ مِنْ آيَاتِ اللَّهِ وَإِنَّهُمَا لَا يَنْخَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَكَبِّرُوا وَادْعُوا اللَّهَ وَصَلُّوا وَتَصَدَّقُوا يَا أُمَّةَ مُحَمَّدٍ إِنْ مِنْ أَحَدٍ أَغْيَرَ مِنْ اللَّهِ أَنْ يَزْنِيَ عَبْدُهُ أَوْ تَزْنِيَ أَمَتُهُ يَا أُمَّةَ مُحَمَّدٍ وَاللَّهِ لَوْ تَعْلَمُونَ مَا أَعْلَمُ لَبَكَيْتُمْ كَثِيرًا وَلَضَحِكْتُمْ قَلِيلًا أَلَا هَلْ بَلَّغْتُوَفِي رِوَايَةِ مَالِكٍ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ و حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ بِهَذَا الْإِسْنَادِ وَزَادَ ثُمَّ قَالَ أَمَّا بَعْدُ فَإِنَّ الشَّمْسَ وَالْقَمَرَ مِنْ آيَاتِ اللَّهِ وَزَادَ أَيْضًا ثُمَّ رَفَعَ يَدَيْهِ فَقَالَ اللَّهُمَّ هَلْ بَلَّغْتُ","id":"Dan Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] -dan lafazhnya juga darinya- ia berkata, telah menceritakan kepada kami [Abdullah bin Numair] telah menceritakan kepada kami [Hisyam] dari [bapaknya] dari [Aisyah] ia berkata; Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, lalu Rasulullah shallallahu 'alaihi wasallam melakukan shalat (gerhana). Beliau berdiri lama sekali, lalu ruku' dengan lama sekali, kemudian bangun dari ruku' dan berdiri lama sekali, namun tidak seperti lama berdirinya yang pertama, lalu beliau ruku' lama sekali, namun tidak seperti ruku'nya yang pertama, lalu beliau sujud. Kemudian beliau berdiri lama, namun tidak seperti lama berdirinya yang pertama, lalu beliau ruku' lama namun tidak seperti lama ruku'nya yang pertama. Kemudian beliau mengangkat kepalanya (bangkit), lalu berdiri lama, akan tetapi tidak seperti lama berdirinya yang pertama, kemudian beliau ruku' lama, namun tidak seperti lama ruku'nya yang pertama, lalu beliau sujud. Ketika Rasulullah shallallahu 'alaihi wasallam selesai shalat, matahari telah bersinar terang. Lalu beliau menyampaikan khutbah di hadapan para jama'ah. Beliau pertama-tama memuji dan menyanjung Allah, kemudian bersabda: \"Sesungguhnya matahari dan bulan adalah sebagian dari tanda kebesaran Allah, dan keduanya tidaklah mengalami gerhana karena kematian atau kelahiran seseorang. Karena itu, apabila kalian melihat gerhana matahari atau bulan, maka bertakbirlah dan berdo'alah kepada Allah, serta shalat dan bersedekahlah. Hai umat Muhammad, sungguh tidak ada kebencian yang melebihi kebencian Allah jika ada hamba-Nya (lelaki atau perempuan) yang berzina. Hai umat Muhammad, demi Allah, seandainya kalian mengetahui apa yang aku ketahui, niscaya kalian akan banyak menangis dan sedikit tertawa. Bukankah aku telah menyampaikan?\" Dan dalam riwayat Malik; \"Sesungguhnya matahari dan bulan adalah dua ayat dari ayat-ayat Allah.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abu Mu'awiyah] dari [Hisyam bin 'Urwah] dengan isnad ini. Dan ia juga menambahkan; \"Amma Ba'du, sesungguhnya matahari dan bulan termasuk dari ayat-ayat Allah.\" Ia juga menambahkan; \"Kemudian beliau mengangkat keduanya tangannya dan membaca: 'Ya Allah, bukankah aku telah menyampaikan? '\""},"1418":{"ar":"حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنِي ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ ح و حَدَّثَنِي أَبُو الطَّاهِرِ وَمُحَمَّدُ بْنُ سَلَمَةَ الْمُرَادِيُّ قَالَا حَدَّثَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْخَسَفَتْ الشَّمْسُ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى الْمَسْجِدِ فَقَامَ وَكَبَّرَ وَصَفَّ النَّاسُ وَرَاءَهُ فَاقْتَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قِرَاءَةً طَوِيلَةً ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ رَأْسَهُ فَقَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ قَامَ فَاقْتَرَأَ قِرَاءَةً طَوِيلَةً هِيَ أَدْنَى مِنْ الْقِرَاءَةِ الْأُولَى ثُمَّ كَبَّرَ فَرَكَعَ رُكُوعًا طَوِيلًا هُوَ أَدْنَى مِنْ الرُّكُوعِ الْأَوَّلِ ثُمَّ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ رَبَّنَا وَلَكَ الْحَمْدُ ثُمَّ سَجَدَ وَلَمْ يَذْكُرْ أَبُو الطَّاهِرِ ثُمَّ سَجَدَ ثُمَّ فَعَلَ فِي الرَّكْعَةِ الْأُخْرَى مِثْلَ ذَلِكَ حَتَّى اسْتَكْمَلَ أَرْبَعَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ وَانْجَلَتْ الشَّمْسُ قَبْلَ أَنْ يَنْصَرِفَ ثُمَّ قَامَ فَخَطَبَ النَّاسَ فَأَثْنَى عَلَى اللَّهِ بِمَا هُوَ أَهْلُهُ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهَا فَافْزَعُوا لِلصَّلَاةِ وَقَالَ أَيْضًا فَصَلُّوا حَتَّى يُفَرِّجَ اللَّهُ عَنْكُمْ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَيْتُ فِي مَقَامِي هَذَا كُلَّ شَيْءٍ وُعِدْتُمْ حَتَّى لَقَدْ رَأَيْتُنِي أُرِيدُ أَنْ آخُذَ قِطْفًا مِنْ الْجَنَّةِ حِينَ رَأَيْتُم��ونِي جَعَلْتُ أُقَدِّمُو قَالَ الْمُرَادِيُّ أَتَقَدَّمُ وَلَقَدْ رَأَيْتُ جَهَنَّمَ يَحْطِمُ بَعْضُهَا بَعْضًا حِينَ رَأَيْتُمُونِي تَأَخَّرْتُ وَرَأَيْتُ فِيهَا ابْنَ لُحَيٍّ وَهُوَ الَّذِي سَيَّبَ السَّوَائِبَ وَانْتَهَى حَدِيثُ أَبِي الطَّاهِرِ عِنْدَ قَوْلِهِ فَافْزَعُوا لِلصَّلَاةِ وَلَمْ يَذْكُرْ مَا بَعْدَهُ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepadaku [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] -dalam jalur lain- Dan telah menceritakan kepadaku [Abu Thahir] dan [Muhammad bin Salamah Al Muradi] keduanya berkata, telah menceritakan kepada kami [Ibnu Wahb] dari [Yunus] dari [Ibnu Syihab] ia berkata, telah mengabarkan kepadaku [Urwah bin Zubair] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; Terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam pun keluar menuju masjid dan berdiri lantas bertakbir (menunaikan shalat), sehingga orang-orang pun ikut membentuk shaf di belakangnya. Lalu Rasulullah shallallahu 'alaihi wasallam membaca dengan bacaan yang panjang. Kemudian beliau bertakbir lalu ruku dengan ruku' yang panjang. Kemudian beliau mengangkat kepalanya seraya membaca: \"SAMI'ALLAHU LIMAN HAMIDAH RABBANAA WA LAKALHAMDU (Allah Maha Mendengar siapa saja yang memuji-Nya).\" Kemudian beliau berdiri dan membaca dengan bacaan yang panjang, namun lebih pendek dari bacaan yang pertama. Setelah itu, beliau bertakbir lalu ruku' dengan ruku' yang panjang, namun lebih pendek dari ruku' yang pertama. Setelah itu, beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH RABBANAA WA LAKALHAMDU.\" Kemudian beliau sujud. -Abu Thahir tidak menyebutkan lafadz: kemudian beliau sujud.- Kemudian pada raka'at berikutnya, beliau berbuat seperti itu hingga sempurnalah shalatnya terdiri dari empat ruku' dan empat sujud. Sesudah itu, matahari pun kembali bersinar sebelum beliau beranjak bubar. Beliau kemudian berdiri dan menyampaikan khutbah kepada orang banyak. Beliau memuji Allah dengan pujian yang hak atas-Nya, kemudian beliau bersabda: \"Sesungguhnya matahari dan bulan adalah dua ayat (tanda) dari ayat-ayat Allah. Tidaklah terjadi gerhana pada keduanya karena kematian atau pun kelahiran seseorang. Maka apabila kalian melihatnya, bersegeralah untuk menunaikan shalat.\" dan beliau juga bersabda: \"Maka shalatlah kalian hingga Allah menampakkannya kembali pada kalian.\" Dan Rasulullah shallallahu 'alaihi wasallam juga bersabda: \"Aku telah melihat di tempatku berdiri ini, yaitu segala sesuatu yang dijanjikan kepada kalian. Bahkan aku melihat diriku ingin memetik buah dari Jannah, yakni saat kalian melihatku maju.\" Dan [Al Muradi] berkata; Ataqaddam (maju ke depan).\"Dan aku juga telah melihat neraka Jahannam yang saling menghancurkan satu sama lain, yaitu saat kalian melihatku mundur. Kemudian aku juga melihat di dalamnya ada Ibnu Luhay, yang telah mengirimkan As Sawa`ib (binatang yang dipersembahkan untuk berhala).\" Hadits Abu Thahir berakhir pada ungkapannya; \"Maka bersegeralah kalian untuk menunaikan shalat.\" dan ia tidak menyebutkan sesudahnya."},"1419":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ الرَّازِيُّ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ قَالَ الْأَوْزَاعِيُّ أَبُو عَمْرٍو وَغَيْرُهُ سَمِعْتُ ابْنَ شِهَابٍ الزُّهْرِيَّ يُخْبِرُ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ الشَّمْسَ خَسَفَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَبَعَثَ مُنَادِيًا الصَّلَاةُ جَامِعَةٌ فَاجْتَمَعُوا وَتَقَدَّمَ فَكَبَّرَ وَصَلَّى أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Mihran Ar Razi] telah menceritakan kepada kami [Al Walid bin Muslim] ia berkata, telah berkata [Al Auza'i Abu Amru] dan yang lainnya, saya mendengar [Ibnu Syihab Az Zuhri] dari [Urwah] dari [Aisyah] bahwasanya; Pernah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam. Maka beliau mengutus seseorang untuk menyerukan, \"ASH SHALAATU JAAMI'AH (marilah kita shalat berjama'ah) \" sehingga kaum muslimin pun berkumpul. Beliau maju (mengimami shalat), lalu bertakbir dan shalat empat raka'at. Pada tiap raka'at terdapat empat kali sujud."},"1420":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ مِهْرَانَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ نَمِرٍ أَنَّهُ سَمِعَ ابْنَ شِهَابٍ يُخْبِرُ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَهَرَ فِي صَلَاةِ الْخُسُوفِ بِقِرَاءَتِهِ فَصَلَّى أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍ","id":"Telah menceritakan kepada kami [Muhammad bin Mihran] telah menceritakan kepada kami [Al Walid bin Muslim] telah mengabarkan kepada kami [Abdurrahman bin Namr] bahwa ia mendengar [Ibnu Syihab] mengabarkan dari [Urwah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam mengeraskan suara bacaannya dalam shalat Khusuf (gerhana bulan). Dan beliau pun shalat, dalam dua raka'at beliau mengerjakan empat kali ruku' dan empat kali sujud."},"1421":{"ar":"قَالَ الزُّهْرِيُّ وَأَخْبَرَنِي كَثِيرُ بْنُ عَبَّاسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى أَرْبَعَ رَكَعَاتٍ فِي رَكْعَتَيْنِ وَأَرْبَعَ سَجَدَاتٍو حَدَّثَنَا حَاجِبُ بْنُ الْوَلِيدِ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ حَدَّثَنَا مُحَمَّدُ بْنُ الْوَلِيدِ الزُّبَيْدِيُّ عَنْ الزُّهْرِيِّ قَالَ كَانَ كَثِيرُ بْنُ عَبَّاسٍ يُحَدِّثُ أَنَّ ابْنَ عَبَّاسٍ كَانَ يُحَدِّثُ عَنْ صَلَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ كَسَفَتْ الشَّمْسُ بِمِثْلِ مَا حَدَّثَ عُرْوَةُ عَنْ عَائِشَةَ","id":"Telah menceritakan kepada kami [Muhammad bin Mihran] telah menceritakan kepada kami [Al Walid bin Muslim] telah mengabarkan kepada kami [Abdurrahman bin Namir] mendengar [Az Zuhri] berkata, dan telah mengabarkan kepadaku [Katsir bin Abbas] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, bahwasanya dalam shalat (Khusuf) beliau mengerjakan empat kali ruku' dan empat kali sujud dalam dua rakaat. Dan telah menceritakan kepada kami [Hajib bin Al Walid] telah menceritakan kepada kami [Muhammad bin Harb] telah menceritakan kepada kami [Muhammad bin Al Walid Az Zubaidi] dari [Az Zuhri] ia berkata, [Katsir bin Abbas] menceritakan bahwa [Ibnu Abbas] menceritakan tentang shalat kusuf (gerhana matahari) Rasulullah shallallahu 'alaihi wasallam sebagaimana hadits yang telah diceritakan oleh Urwah dari Aisyah."},"1422":{"ar":"و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا مُحَمَّدُ بْنُ بَكْرٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ قَالَ سَمِعْتُ عَطَاءً يَقُولُ سَمِعْتُ عُبَيْدَ بْنَ عُمَيْرٍ يَقُولُ حَدَّثَنِي مَنْ أُصَدِّقُ حَسِبْتُهُ يُرِيدُ عَائِشَةَأَنَّ الشَّمْسَ انْكَسَفَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ قِيَامًا شَدِيدًا يَقُومُ قَائِمًا ثُمَّ يَرْكَعُ ثُمَّ يَقُومُ ثُمَّ يَرْكَعُ ثُمَّ يَقُومُ ثُمَّ يَرْكَعُ رَكْعَتَيْنِ فِي ثَلَاثِ رَكَعَاتٍ وَأَرْبَعِ سَجَدَاتٍ فَانْصَرَفَ وَقَدْ تَجَلَّتْ الشَّمْسُ وَكَانَ إِذَا رَكَعَ قَالَ اللَّهُ أَكْبَرُ ثُمَّ يَرْكَعُ وَإِذَا رَفَعَ رَأْسَهُ قَالَ سَمِعَ اللَّهُ لِمَنْ حَمِدَهُ فَقَامَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَكْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا مِنْ آيَاتِ اللَّهِ يُخَوِّفُ اللَّهُ بِهِمَا عِبَادَهُ فَإِذَا رَأَيْتُمْ كُسُوفًا فَاذْكُرُوا اللَّهَ حَتَّى يَنْجَلِيَا","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Muhammad bin Bakar] telah mengabarkan kepada kami [Ibnu Juraij] ia berkata, saya mendengar [Atha`] berkata, saya mendengar [Ubaid bin Umair] berkata, telah menceritakan kepadaku seorang yang aku percayai maksudnya adalah [Aisyah] bahwasanya; Pada masa Rasulullah shallallahu 'alaihi wasallam pernah terjadi gerhana matahari. Maka beliau berdiri (shalat) lama sekali, kemudian beliau ruku', kemudian berdiri kebali. Kemudian ruku' lagi, kemudian beliau berdiri dan shalat dua rakaat dalam tiga ruku' dan empat sujud. Setelah itu, beliau beranjak, sementara matahari telah bersinar kembali. Ketika hendak ruku' belaiau membaca: \"ALLAHU AKBAR, \" baru kemudian beliau ruku'. Dan bila beliau bangkit dari ruku', beliau membaca: \"SAMI'ALLAHU LIMAN HAMIDAH (Allah Maha Mendengar akan pujian hamba-Nya).\" Sesudah itu beliau berdiri, memuji Allah dan menyanjung-Nya, kemudian beliau bersabda: \"Sesungguhnya tidaklah terjadi gerhana matahari dan bulan itu karena kematian seseorang dan tidak pula karena kelahirannya, akan tetapi keduanya termasuk ayat-ayat Allah. Dengan keduanya, Allah ingin menakuti para hamba-Nya, maka jika kalian melihat gerhana, berdzikirlah kepada Allah (shalat) hingga ia itu bersinar kembali.\""},"1423":{"ar":"و حَدَّثَنِي أَبُو غَسَّانَ الْمِسْمَعِيُّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا مُعَاذٌ وَهُوَ ابْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى سِتَّ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ","id":"Telah menceritakan kepadaku [Abu Ghassan Al Misma'i] dan [Muhammad bin Al Mutsanna] keduanya berkata, telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] dari [Qatadah] dari [Atha` bin Abu Rabah] dari [Ubaid bin Umair] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam shalat (khusuf) dengan enam ruku' dan empat sujud."},"1424":{"ar":"و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ الْقَعْنَبِيُّ حَدَّثَنَا سُلَيْمَانُ يَعْنِي ابْنَ بِلَالٍ عَنْ يَحْيَى عَنْ عَمْرَةَأَنَّ يَهُودِيَّةً أَتَتْ عَائِشَةَ تَسْأَلُهَا فَقَالَتْ أَعَاذَكِ اللَّهُ مِنْ عَذَابِ الْقَبْرِ قَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ يُعَذَّبُ النَّاسُ فِي الْقُبُورِ قَالَتْ عَمْرَةُ فَقَالَتْ عَائِشَةُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَائِذًا بِاللَّهِ ثُمَّ رَكِبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ غَدَاةٍ مَرْكَبًا فَخَسَفَتْ الشَّمْسُ قَالَتْ عَائِشَةُ فَخَرَجْتُ فِي نِسْوَةٍ بَيْنَ ظَهْرَيْ الْحُجَرِ فِي الْمَسْجِدِ فَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ مَرْكَبِهِ حَتَّى انْتَهَى إِلَى مُصَلَّاهُ الَّذِي كَانَ يُصَلِّي فِيهِ فَقَامَ وَقَامَ النَّاسُ وَرَاءَهُ قَالَتْ عَائِشَةُ فَقَامَ قِيَامًا طَوِيلًا ثُمَّ رَكَعَ فَرَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ فَرَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ ذَلِكَ الرُّكُوعِ ثُمَّ رَفَعَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَقَالَ إِنِّي قَدْ رَأَيْتُكُمْ تُفْتَنُونَ فِي الْقُبُورِ كَفِتْنَةِ الدَّجَّالِ قَالَتْ عَمْرَةُ فَسَمِعْتُ عَائِشَةَ تَقُولُ فَكُنْتُ أَسْمَعُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ ذَلِكَ يَتَعَوَّذُ مِنْ عَذَابِ النَّارِ وَعَذَابِ الْقَبْرِو حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ ح و حَدَّثَنِي ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ جَمِيعًا عَنْ يَحْيَى بْنِ سَعِيدٍ فِي هَذَا الْإِسْنَادِ بِمِثْلِ مَعْنَى حَدِيثِ سُلَيْمَانَ بْنِ بِلَالٍ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah Al Qa'nabi] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Yahya] dari [Amrah] bahwa seorang wanita Yahudi mendatangi [Aisyah] seraya berkata, \"Semoga Allah melindungimu dari siksa kubur.\" Aisyah berkata; Maka saya pun bertanya, \"Wahai Rasulullah, apakah Allah akan menyiksa manusia di alam kubur?\" Amrah berkata; Aisyah berkata; Rasulullah shallallahu 'alaihi wasallam menjawab: \"Mintalah perlindungan kepada Allah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam pergi dengan berkendaraan di siang hari, tiba-tiba terjadilah gerhana matahari. Aisyah berkata; Maka saya pun keluar melewati pintu rumah yang berada di dalam masjid bersama beberapa orang wanita. Kemudian datanglah Rasulullah shallallahu 'alaihi wasallam dari kendaraannya, beliau berjalan hingga sampai di Mushalla (tanah lapang) tempat beliau shalat. Lalu beliau berdiri (shalat) dan kaum muslimin pun ikut berdiri (shalat) di belakangnya. Aisyah berkata; Beliau berdiri lama sekali, kemudian beliau ruku' dengan ruku' yang lama sekali, setelah itu beliau bangkit dan berdiri lama sekali, namun tidak seperti berdirinya yang pertama. Kemudian beliau ruku' dengan sangat lama, namun tidak selama ruku'nya yang pertama, lalu beliau bangkit sementara matahari telah bersinar kembali. Akhirnya beliau bersabda: \"Sungguh, saya telah melihat bahwa kalian akan diuji di alam kubur nanti sebagaimana fitnah Dajjal.\" Amrah berkat; Saya mendengar Aisyah berkata, \"Setelah itu, saya mendengar Rasulullah shallallahu 'alaihi wasallam meminta perlindungan dari adzab neraka dan adzab kubur.\" Dan telah menceritakannya kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Abdul Wahhab] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] semuanya dari [Yahya bin Sa'id] dengan isnad ini, dan sesuai dengan makna haditsnya Sulaiman bin Bilal."},"1425":{"ar":"و حَدَّثَنِي يَعْقُوبُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ هِشَامٍ الدَّسْتَوَائِيِّ قَالَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي يَوْمٍ شَدِيدِ الْحَرِّ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَصْحَابِهِ فَأَطَالَ الْقِيَامَ حَتَّى جَعَلُوا يَخِرُّونَ ثُمَّ رَكَعَ فَأَطَالَ ثُمَّ رَفَعَ فَأَطَالَ ثُمَّ رَكَعَ فَأَطَالَ ثُمَّ رَفَعَ فَأَطَالَ ثُمَّ سَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَصَنَعَ نَحْوًا مِنْ ذَاكَ فَكَانَتْ أَرْبَعَ رَكَعَاتٍ وَأَرْبَعَ سَجَدَاتٍ ثُمَّ قَالَ إِنَّهُ عُرِضَ عَلَيَّ كُلُّ شَيْءٍ تُولَجُونَهُ فَعُرِضَتْ عَلَيَّ الْجَنَّةُ حَتَّى لَوْ تَنَاوَلْتُ مِنْهَا قِطْفًا أَخَذْتُهُ أَوْ قَالَ تَنَاوَلْتُ مِنْهَا قِطْفًا فَقَصُرَتْ يَدِي عَنْهُ وَعُرِضَتْ عَلَيَّ النَّارُ فَرَأَيْتُ فِيهَا امْرَأَةً مِنْ بَنِي إِسْرَائِيلَ تُعَذَّبُ فِي هِرَّةٍ لَهَا رَبَطَتْهَا فَلَمْ تُطْعِمْهَا وَلَمْ تَدَعْهَا تَأْكُلُ مِنْ خَشَاشِ الْأَرْضِ وَرَأَيْتُ أَبَا ثُمَامَةَ عَمْرَو بْنَ مَالِكٍ يَجُرُّ قُصْبَهُ فِي النَّارِ وَإِنَّهُمْ كَانُوا يَقُولُونَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَخْسِفَانِ إِلَّا لِمَوْتِ عَظِيمٍ وَإِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ يُرِيكُمُوهُمَا فَإِذَا خَسَفَا فَصَلُّوا حَتَّى تَنْجَلِيَو حَدَّثَنِيهِ أَبُو غَسَّانَ الْمِسْمَعِيُّ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ الصَّبَّاحِ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ إِلَّا أَنَّهُ قَالَ وَرَأَيْتُ فِي النَّارِ امْرَأَةً حِمْيَرِيَّةً سَوْدَاءَ طَوِيلَةً وَلَمْ يَقُلْ مِنْ بَنِي إِسْرَائِيلَ","id":"Telah menceritakan kepadaku [Ya'qub bin Ibrahim Ad Dauraqi] telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Hisyam Ad Dastawa`i] ia berkata, telah menceritakan kepada kami [Abu Zubair] dari [Jabir bin Abdullah] ia berkata; Pernah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam yakti di saat terik matahari bergitu sangat menyengat. Maka Rasulullah shallallahu 'alaihi wasallam shalat (gerhana) bersama para sahabatnya. Beliau memanjangkan berdirinya hingga para sahabat tersungkur lantas duduk karena keletihan. Kemudian beliau ruku' dan memanjangkan ruku'nya, kemudian bangkit dan memanjangkan berdirinya kembali. Lalu beliau ruku' dan memanjangkan ruku'nya. Sesudah itu, beliau bangkit dan sujud dua kali. Kemudian beliau berdiri dan melakukan hal yang serupa, hingga semuanya menjadi empat raka'at dan empat kali sujud. setelah itu, beliau bersabda: \"Sesungguhnya segala sesuatu yang akan kalian masuki telah diperlihatkan kepadaku. Diperlihatkanlah jannah atasku, hingga sekiranya aku memetik setandan buah darinya niscaya aku akan mengambilnya -atau beliau bersabda- Aku mencoba memetik setandan buah darinya namun tanganku tak sampai. Dan neraka juga diperlihatkan padaku, lalu di dalamnya aku melihat seorang wanita dari Bani Isra`il yang sedang disiksa lantaran kucing yang ia ikat dan tidak diberinya makan juga tidak dilepasnya hingga kucing itu bisa makan serangga-serangga bumi. Dan aku juga melihat Abu Tsumamah Amru bin Malik yang sedang terseret punggunggungnya di dalam neraka. Mereka (kaum Jahiliyah) mengatakan bahwa tidaklah terjadi gerhana matahari dan bulan kecuali karena kematian seorang yang agung. Padahal, keduanya adalah ayat dari ayat-ayat Allah yang diperlihatkan-Nya. Maka apabila terjadi gerhana pada keduanya, tunaikanlah shalat hingga nampak kembali.\" Dan Telah menceritakan kepadaku [Abu Ghassan Al Misma'i] Telah menceritakan kepada kami [Abdul Malik bin Shabah] dari [Hisyam] dengan isnad ini semisalnya. Hanya saja ia menyebutkan: \"Dan di dalam neraka aku melihat wanita Himyar yang berkulit hitam berpostur tubuh tinggi.\" Dan ia tidak menyebutkan, \"Dari Bani Isra`il.\""},"1426":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَتَقَارَبَا فِي اللَّفْظِ قَالَ حَدَّثَنَا أَبِي حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَانْكَسَفَتْ الشَّمْسُ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ مَاتَ إِبْرَاهِيمُ ابْنُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّاسُ إِنَّمَا انْكَسَفَتْ لِمَوْتِ إِبْرَاهِيمَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى بِالنَّاسِ سِتَّ رَكَعَاتٍ بِأَرْبَعِ سَجَدَاتٍ بَدَأَ فَكَبَّرَ ثُمَّ قَرَأَ فَأَطَالَ الْقِرَاءَةَ ثُمَّ رَكَعَ نَحْوًا مِمَّا قَامَ ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَقَرَأَ قِرَاءَةً دُونَ الْقِرَاءَةِ الْأُولَى ثُمَّ رَكَعَ نَحْوًا مِمَّا قَامَ ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ فَقَرَأَ قِرَاءَةً دُونَ الْقِرَاءَةِ الثَّانِيَةِ ثُمَّ رَكَعَ نَحْوًا مِمَّا قَامَ ثُمَّ رَفَعَ رَأْسَهُ مِنْ الرُّكُوعِ ثُمَّ انْحَدَرَ بِالسُّجُودِ فَسَجَدَ سَجْدَتَيْنِ ثُمَّ قَامَ فَرَكَعَ أَيْضًا ثَلَاثَ رَكَعَاتٍ لَيْسَ فِيهَا رَكْعَةٌ إِلَّا الَّتِي قَبْلَهَا أَطْوَلُ مِنْ الَّتِي بَعْدَهَا وَرُكُوعُهُ نَحْوًا مِنْ سُجُودِهِ ثُمَّ تَأَخَّرَ وَتَأَخَّرَتْ الصُّفُوفُ خَلْفَهُ حَتَّى انْتَهَيْنَا وَقَالَ أَبُو بَكْرٍ حَتَّى انْتَهَى إِلَى النِّسَاءِ ثُمَّ تَقَدَّمَ وَتَقَدَّمَ النَّاسُ مَعَهُ حَتَّى قَامَ فِي مَقَامِهِ فَانْصَرَفَ حِينَ انْصَرَفَ وَقَدْ آضَتْ الشَّمْسُ فَقَالَ يَا أَيُّهَا النَّاسُ إِنَّمَا الشَّمْسُ وَالْقَمَرُ آيَتَانِ مِنْ آيَاتِ اللَّهِ وَإِنَّهُمَا لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ مِنْ النَّاسِ وَقَالَ أَبُو بَكْرٍ لِمَوْتِ بَشَرٍ فَإِذَا رَأَيْتُمْ شَيْئًا مِنْ ذَلِكَ فَصَلُّوا حَتَّى تَنْجَلِيَ مَا مِنْ شَيْءٍ تُوعَدُونَهُ إِلَّا قَدْ رَأَيْتُهُ فِي صَلَاتِي هَذِهِ لَقَدْ جِيءَ بِالنَّارِ وَذَلِكُمْ حِينَ رَأَيْتُمُونِي تَأَخَّرْتُ مَخَافَةَ أَنْ يُصِيبَنِي مِنْ لَفْحِهَا وَحَتَّى رَأَيْتُ فِيهَا صَاحِبَ الْمِحْجَنِ يَجُرُّ قُصْبَهُ فِي النَّارِ كَانَ يَسْرِقُ الْحَاجَّ بِمِحْجَنِهِ فَإِنْ فُطِنَ لَهُ قَالَ إِنَّمَا تَعَلَّقَ بِمِحْجَنِي وَإِنْ غُفِلَ عَنْهُ ذَهَبَ بِهِ وَحَتَّى رَأَيْتُ فِيهَا صَاحِبَةَ الْهِرَّةِ الَّتِي رَبَطَتْهَا فَلَمْ تُطْعِمْهَا وَلَمْ تَدَعْهَا تَأْكُلُ مِنْ خَشَاشِ الْأَرْضِ حَتَّى مَاتَتْ جُوعًا ثُمَّ جِيءَ بِالْجَنَّةِ وَذَلِكُمْ حِينَ رَأَيْتُمُونِي تَقَدَّمْتُ حَتَّى قُمْتُ فِي مَقَامِي وَلَقَدْ مَدَدْتُ يَدِي وَأَنَا أُرِيدُ أَنْ أَتَنَاوَلَ مِنْ ثَمَرِهَا لِتَنْظُرُوا إِلَيْهِ ثُمَّ بَدَا لِي أَنْ لَا أَفْعَلَ فَمَا مِنْ شَيْءٍ تُوعَدُونَهُ إِلَّا قَدْ رَأَيْتُهُ فِي صَلَاتِي هَذِهِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] -yang lafazhnya hampir sama- ia berkata, telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Abdul Malik] dari [Atha`] dari [Jabir] ia berkata; Pernah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam bertepatan dengan hari wafatnya Ibrahim bin Rasulullah shallallahu 'alaihi wasallam, maka orang-orang pun mengatakan, \"Terjadinya gerhana matahari adalah karena kematiannya Ibrahim.\" Maka Rasulullah shallallahu 'alaihi wasallam berdiri menunaikan shalat (gerhana) bersama para sahabat sebanyak enam raka'at dengan empat kali sujud. Mula-mula beliau bertakbir, dan membaca ayat dan memanjangkan bacaannya itu. Kemudian beliau ruku' lama, lamanya kira-kira selama beliau berdiri itu. Kemudian beliau mengangkat kepala dari ruku' (I'tidal), lalu beliau membaca ayat, namun tidak sepanjang yang pertama. Kemudian beliau ruku', lamanya kira-kira seperti lamanya beliau berdiri. Kemudian I'tidal, lalu membaca ayat, tetapi panjangnya tidak sepanjang yang kedua. Kemudian beliau ruku', seperti lamanya beliau berdiri. Kemudian beliau mengangkat kepalanya dari ruku' kemudian langsung turun untuk sujud, dan beliau sujud dua kali. Kemudian beliau berdiri, dan sesudah itu ruku' pula tiga kali; dan bacaannya setiap raka'at yang dahulu lebih panjang daripada yang setelahnya. Begitu pula lama ruku' hampir sama dengan lamanya sujud. Kemudian beliau mundur, maka mundur pula seluruh shaf di belakang beliau hingga sampai dekat shafnya kaum wanita. Kemudian beliau maju, dan maju pula seluruh jama'ah mengikuti beliau, hingga sampai ke tempatnya semula. Sesudah itu, shalat gerhana selesai, dan matahari telah terang kembali. Di dalam khutbahnya antara lain beliau bersabda: \"Wahai sekalian manusia, sesungguhnya matahari dan bulan adalah dua ayat (bukti) di antara sekian banyak bukti kebesaran Allah. Dan gerhana pada keduanya itu terjadi bukan karena kematian seseorang. Karena itu, apabila kalian melihat gerhana, maka shalatlah, hingga ia terang kembali. Segala yang dijanjikan Allah telah diperlihatkan kepadaku dalam shalatku yang sebentar ini. Diperlihatkannya kepadaku neraka; yaitu ketika kalian melihat aku mundur, karena aku takut terkena jilatannya. Sehingga tampak olehku seorang pemilik tongkat (yang ujungnya bengkok) sedang menyeret ususnya di neraka, karena ia (dahulu) pernah mencuri harta jama'ah haji dengan tongkatya tersebut. Jika ada orang bertanya kepadanya, kenapa kamu mencuri? Ia menjawab, aku tak sengaja karena menyangkut pada tombakku. Tetapi jika orang lengah, dia mencuri lagi. Kulihat juga di dalam neraka ada seorang wanita pemilik kucing. Dia mengikat kucing itu namun tidak diberinya makan, dan tidak pula dilepaskannya agar kucing tersebut bisa mencari makannya sendiri seperti rumput-rumput kering, hingga akhirnya kucing itu mati kelaparan. Kemudian diperlihatkan pula kepadaku surga; yaitu ketika kalian melihatku maju, sehingga meski aku berdiri di tempatku ini aku ulurkan tanganku untuk memetik buah-buahannya, supaya kamu semua dapat melihatnya. Tapi ternyata aku tak dapat melakukannya. Tidak ada sesuatupun yang dijanjikan Allah, melainkan kulihat nyata di dalam shalatku ini.\""},"1427":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ الْهَمْدَانِيُّ حَدَّثَنَا ابْنُ نُمَيْرٍ حَدَّثَنَا هِشَامٌ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْخَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلْتُ عَلَى عَائِشَةَ وَهِيَ تُصَلِّي فَقُلْتُ مَا شَأْنُ النَّاسِ يُصَلُّونَ فَأَشَارَتْ بِرَأْسِهَا إِلَى السَّمَاءِ فَقُلْتُ آيَةٌ قَالَتْ نَعَمْ فَأَطَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقِيَامَ جِدًّا حَتَّى تَجَلَّانِي الْغَشْيُ فَأَخَذْتُ قِرْبَةً مِنْ مَاءٍ إِلَى جَنْبِي فَجَعَلْتُ أَصُبُّ عَلَى رَأْسِي أَوْ عَلَى وَجْهِي مِنْ الْمَاءِ قَالَتْ فَانْصَرَفَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَدْ تَجَلَّتْ الشَّمْسُ فَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَمَّا بَعْدُ مَا مِنْ شَيْءٍ لَمْ أَكُنْ رَأَيْتُهُ إِلَّا قَدْ رَأَيْتُهُ فِي مَقَامِي هَذَا حَتَّى الْجَنَّةَ وَالنَّارَ وَإِنَّهُ قَدْ أُوحِيَ إِلَيَّ أَنَّكُمْ تُفْتَنُونَ فِي الْقُبُورِ قَرِيبًا أَوْ مِثْلَ فِتْنَةِ الْمَسِيحِ الدَّجَّالِ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ فَيُؤْتَى أَحَدُكُمْ فَيُقَالُ مَا عِلْمُكَ بِهَذَا الرَّجُلِ فَأَمَّا الْمُؤْمِنُ أَوْ الْمُوقِنُ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ فَيَقُولُ هُوَ مُحَمَّدٌ هُوَ رَسُولُ اللَّهِ جَاءَنَا بِالْبَيِّنَاتِ وَالْهُدَى فَأَجَبْنَا وَأَطَعْنَا ثَلَاثَ مِرَارٍ فَيُقَالُ لَهُ نَمْ قَدْ كُنَّا نَعْلَمُ إِنَّكَ لَتُؤْمِنُ بِهِ فَنَمْ صَالِحًا وَأَمَّا الْمُنَافِقُ أَوْ الْمُرْتَابُ لَا أَدْرِي أَيَّ ذَلِكَ قَالَتْ أَسْمَاءُ فَيَقُولُ لَا أَدْرِي سَمِعْتُ النَّاسَ يَقُولُونَ شَيْئًا فَقُلْتُحَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامٍ عَنْ فَاطِمَةَ عَنْ أَسْمَاءَ قَالَتْ أَتَيْتُ عَائِشَةَ فَإِذَا النَّاسُ قِيَامٌ وَإِذَا هِيَ تُصَلِّي فَقُلْتُ مَا شَأْنُ النَّاسِ وَاقْتَصَّ الْحَدِيثَ بِنَحْوِ حَدِيثِ ابْنِ نُمَيْرٍ عَنْ هِشَامٍ أَخْبَرَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ قَالَ لَا تَقُلْ كَسَفَتْ الشَّمْسُ وَلَكِنْ قُلْ خَسَفَتْ الشَّمْسُ","id":"Telah menceritakan kepada kami [Muhamamd bin Ala` Al Hamdani] telah menceritakan kepada kami [Ibnu Numair] telah menceritakan kepada kami [Hisyam] dari [Fathimah] dari [Asma`] ia berkata; Pernah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam. Lalu aku pergi menemui Aisyah, dan kudapati dia sedang shalat. Aku bertanya kepadanya, \"Kenapa orang-orang sedang melaksanakan shalat?\" Dia memberi isyarat dengan kepalanya ke langit. Tanyaku, \"Ayat (tanda kebesaran Allah)?\" Aisyah menjawab, \"Ya, tanda kebesaran Allah.\" Rasulullah shallallahu 'alaihi wasallam lama sekali berdiri di dalam shalat, sehingga aku pusing. Lalu kuambil air satu qirbah dan kubawa kedekatku. Kemudian kubasahi kepala dan mukaku. Kata Asma` selanjutnya; ketika Rasulullah shallallahu 'alaihi wasallam telah usai menunaikan shalat, dan matahari telah terang kembali, beliau berkhutbah di hadapan manusia. Mula-mula beliau memuji dan menyanjung Allah. Sesudah itu, beliau bersabda antara lain: \"Tidak ada satupun yang belum pernah aku lihat, melainkan telah kusaksikan dalam shalatku ini, sampai-sampai surga dan neraka. Sesungguhnya telah diwahyukan kepadaku bahwa kalian akan segera ditanyai di dalam kubur, atau seperti fitnah bencana Dajja. Masing-masing kalian akan didatangi dan ditanyai, 'Apa pengetahuanmu tentang orang (Muhammad) ini? ' adapun orang-orang yang beriman dan meyakini akan menjawab, 'Dia adalah Muhammad Rasulullah shallallahu 'alaihi wasallam, beliau datang kepada kami dengan membawa keterangan-keterangan dan petunjuk, lalu kami terima dan kami patuhi.' Pertanyaan itu berulang-ulang hingga tiga kali. Sesudah itu, ia disuruh tidur. Katanya, 'Kami sudah tahu bahwa kamu betu-betul beriman dengannya. Karena itu, tidurlah dengan nyenyak.' Adapun orang-orang yang munafik dan orang-orang yang ragu dalam kepercayaannya, maka jawabnya, 'Aku tidak apakah itu. Kudengar orang banyak mengatakan begini dan begitu, lalu kuucapkan pula.'\" Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] dari [Hisyam] dari [Fathimah] dari [Asma`] ia berkata; Saya mendatangi Aisyah, ternyata orang-orang sedang berdiri (menunaikan shalat), maka saya pun bertanya, \"Kenapa orang-orang pada shalat?\" ia pun mengkisahkan hadits sebagaimana hadits Ibnu Numair dari Hisyam telah mengabarkan kepada kami Yahya bin Yahya telah mengabarkan kepada kami Sufyan bin Uyainah dari Az Zuhri dari Urwah ia berkata; Janganlah kalian mengatakan; \"KASAFAT ASY SYAMSU.\" Tetapi katakanlah, \"KHASAFAT ASY SYAMSU (terjadi gerhana matahari).\""},"1428":{"ar":"حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ حَدَّثَنَا ابْنُ جُرَيْجٍ حَدَّثَنِي مَنْصُورُ بْنُ عَبْد�� الرَّحْمَنِ عَنْ أُمِّهِ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّهَا قَالَتْفَزِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا قَالَتْ تَعْنِي يَوْمَ كَسَفَتْ الشَّمْسُ فَأَخَذَ دِرْعًا حَتَّى أُدْرِكَ بِرِدَائِهِ فَقَامَ لِلنَّاسِ قِيَامًا طَوِيلًا لَوْ أَنَّ إِنْسَانًا أَتَى لَمْ يَشْعُرْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكَعَ مَا حَدَّثَ أَنَّهُ رَكَعَ مِنْ طُولِ الْقِيَامِو حَدَّثَنِي سَعِيدُ بْنُ يَحْيَى الْأُمَوِيُّ حَدَّثَنِي أَبِي حَدَّثَنَا ابْنُ جُرَيْجٍ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَقَالَ قِيَامًا طَوِيلًا يَقُومُ ثُمَّ يَرْكَعُ وَزَادَ فَجَعَلْتُ أَنْظُرُ إِلَى الْمَرْأَةِ أَسَنَّ مِنِّي وَإِلَى الْأُخْرَى هِيَ أَسْقَمُ مِنِّي","id":"Telah menceritakan kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Al Harits] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Manshur bin Abdurrahman] dari [Ibunya, Shafiyyah binti Syaibah] dari [Asma` bin Abu Bakar] bahwa ia berkata; Pada hari terjadinya gerhana matahari, Nabi shallallahu 'alaihi wasallam terkejut. Maka beliau pun segera mengambil baju besi hingga memakaikannya dengan bajunya. Kemudian beliau berdiri menunaikan shalat bersama orang banyak. Beliau berdiri dengan sangat lama yang seandainya ada seseorang yang datang, maka di tidak akan menduga bahwa Nabi shallallahu 'alaihi wasallam akan ruku', karena memang begitu lamanya beliau berdiri.\" Dan telah menceritakan kepadaku [Sa'id bin Yahya Al Umawi] telah menceritakan kepadaku [bapakku] telah menceritakans kepada kami [Ibnu Juraij] dengan isnad ini, hadits yang semisalnya. Dan ia menyebutkan; \"Bediri yang lama. Beliau berdiri, kemudian ruku'.\" Dan ia juga menambahkan; \"Lalu aku melihat ke arah wanita yang lebih muda usianya dariku dan juga kepada wanita lain yang lebih kurus dariku.\""},"1429":{"ar":"و حَدَّثَنِي أَحْمَدُ بْنُ سَعِيدٍ الدَّارِمِيُّ حَدَّثَنَا حَبَّانُ حَدَّثَنَا وُهَيْبٌ حَدَّثَنَا مَنْصُورٌ عَنْ أُمِّهِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَفَزِعَ فَأَخْطَأَ بِدِرْعٍ حَتَّى أُدْرِكَ بِرِدَائِهِ بَعْدَ ذَلِكَ قَالَتْ فَقَضَيْتُ حَاجَتِي ثُمَّ جِئْتُ وَدَخَلْتُ الْمَسْجِدَ فَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمًا فَقُمْتُ مَعَهُ فَأَطَالَ الْقِيَامَ حَتَّى رَأَيْتُنِي أُرِيدُ أَنْ أَجْلِسَ ثُمَّ أَلْتَفِتُ إِلَى الْمَرْأَةِ الضَّعِيفَةِ فَأَقُولُ هَذِهِ أَضْعَفُ مِنِّي فَأَقُومُ فَرَكَعَ فَأَطَالَ الرُّكُوعَ ثُمَّ رَفَعَ رَأْسَهُ فَأَطَالَ الْقِيَامَ حَتَّى لَوْ أَنَّ رَجُلًا جَاءَ خُيِّلَ إِلَيْهِ أَنَّهُ لَمْ يَرْكَعْ","id":"Dan telah menceritakan kepadaku [Ahmad bin Sa'id Ad Darimi] telah menceritakan kepada kami [Habban] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepada kami [Manshur] dari [Ibunya] dari [Asma` binti Abu Bakar] ia berkata; Pernah terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka beliau bergegas dan keliru mengambil baju besi hingga beliau ditunjukkan letak pakaiannya. Kemudian aku buang hajat, kemudian datang dan masuk masjid. Lalu aku melihat Rasulullah shallallahu 'alaihi wasallam sedang berdiri dan aku pun ikut berdiri (shalat) bersama beliau. Beliau memperpanjang berdirinya hingga aku ingin duduk, kemudian aku menoleh ke arah perempuan yang lemah, aku pun berkata, 'Perempuan ini adalah lebih lemah dariku.' Akhirnya aku pun berdiri. Kemudian beliau ruku' dan memperpanjang ruku'nya. Lalu beliau mengangkat kepalanya dan kembali memperpanjang berdirinya hingga sekiranya ada seorang laki-laki datang niscaya ia akan menyangka bahwa beliau tidak akan ruku'."},"1430":{"ar":"حَدَّثَنَا سُوَيْدُ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصُ بْنُ مَيْسَرَةَ حَدَّثَنِي زَيْدُ بْنُ أَسْلَمَ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ قَالَانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالنَّاسُ مَعَهُ فَقَامَ قِيَامًا طَوِيلًا قَدْرَ نَحْوِ سُورَةِ الْبَقَرَةِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ قَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ رَفَعَ فَقَامَ قِيَامًا طَوِيلًا وَهُوَ دُونَ الْقِيَامِ الْأَوَّلِ ثُمَّ رَكَعَ رُكُوعًا طَوِيلًا وَهُوَ دُونَ الرُّكُوعِ الْأَوَّلِ ثُمَّ سَجَدَ ثُمَّ انْصَرَفَ وَقَدْ انْجَلَتْ الشَّمْسُ فَقَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمْ ذَلِكَ فَاذْكُرُوا اللَّهَ قَالُوا يَا رَسُولَ اللَّهِ رَأَيْنَاكَ تَنَاوَلْتَ شَيْئًا فِي مَقَامِكَ هَذَا ثُمَّ رَأَيْنَاكَ كَفَفْتَ فَقَالَ إِنِّي رَأَيْتُ الْجَنَّةَ فَتَنَاوَلْتُ مِنْهَا عُنْقُودًا وَلَوْ أَخَذْتُهُ لَأَكَلْتُمْ مِنْهُ مَا بَقِيَتْ الدُّنْيَا وَرَأَيْتُ النَّارَ فَلَمْ أَرَ كَالْيَوْمِ مَنْظَرًا قَطُّ وَرَأَيْتُ أَكْثَرَ أَهْلِهَا النِّسَاءَ قَالُوا بِمَ يَا رَسُولَ اللَّهِ قَالَ بِكُفْرِهِنَّ قِيلَ أَيَكْفُرْنَ بِاللَّهِ قَالَ بِكُفْرِ الْعَشِيرِ وَبِكُفْرِ الْإِحْسَانِ لَوْ أَحْسَنْتَ إِلَى إِحْدَاهُنَّ الدَّهْرَ ثُمَّ رَأَتْ مِنْكَ شَيْئًا قَالَتْ مَا رَأَيْتُ مِنْكَ خَيْرًا قَطُّو حَدَّثَنَاه مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا إِسْحَقُ يَعْنِي ابْنَ عِيسَى أَخْبَرَنَا مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ فِي هَذَا الْإِسْنَادِ بِمِثْلِهِ غَيْرَ أَنَّهُ قَالَ ثُمَّ رَأَيْنَاكَ تَكَعْكَعْتَ","id":"Telah menceritakan kepada kami [Suwaid bin Sa'id] telah menceritakan kepada kami [Hafsh bin Maisarah] telah menceritakan kepadaku [Zaid bin Aslam] dari [Atha` bin Yasar] dari [Ibnu Abbas] ia berkata; Pernah terjadi gerhana matahari pada zaman Rasulullah shallallahu 'alaihi wasallam. Maka Rasulullah shallallahu 'alaihi wasallam menunaikan shalat dan para sahabat pun ikut menyertainya. Kemudian beliau berdiri sangat lama kira-kira selama pembacaan surat Al Baqarah, lalu beliau ruku' dengan ruku' yang sangat lama. Kemudian beliau bangkit (dari ruku') dan berdiri dengan sangat lama namun tidak selama berdirinya yang pertama, lalu beliau ruku' lama sekali, namun tidak selama ruku'nya yang pertama, kemudian beliau sujud. setelah itu, beliau berdiri kembali dan berdirinya sangat lama, namun tidak selama berdirinya yang pertama. Lalu beliau ruku' dengan ruku' yang lama pula, namun tidak selama ruku'nya yang pertama. Kemudian beliau bangkit dan berdiri sangat lama, namun tidak sebagaimana berdirinya yang pertama, lalu beliau ruku' sangat lama, tetapi tidak selama ruku'nya yang pertama. Kemudian beliau sujud, hingga kemudian beliau beranjak (setelah usai menunaikan shalat) sementara matahari telah terang kembali. Maka beliau pun bersabda: \"Sesungguhnya matahari dan bulan adalah dua ayat dari ayat-ayat Allah. Tidaklah terjadi gerhana pada keduanya karena kematian seseorang atau pun kelahirannya. Jika kalian melihatnya, maka berdzikirlah kepada Allah.\" Para sahabat berkata, \"Wahai Rasulullah, kami melihat Anda sepertinya mendapatkan sesuatu di tempat Anda berdiri ini, dan kami juga melihat Anda menahan kedua tangan.\" Maka beliau pun menjelaskan: \"Sesungguhnya saya telah melihat surga, lalu saya mendapati satu tandan, sekiranya saya mengambilnya, niscaya kalian akan makan darinya selama dunia ini ada. Kemudian saya juga melihat neraka, maka saya belum pernah melihat pemandangan yang dahsyat seperti hari ini, dan saya melihat bahwa kebanyakan penghuninya adalah kaum wanita.\" Para sahabat bertanya, \"Apakah penyebabnya wahai Rasulullah?\" beliau menjawab: \"Lantaran kekufuran mereka.\" kemudian ditanyakan lagi kepada beliau: \"Apakah mereka kufur kepada Allah?\" beliau menjawab: \"Yaitu kufur (tidak menerima) kelebihan suami, dan mengkufuri kebaikannya. Sekiranya kamu berbuat baik kepada salah seorang dari mereka sepanjang masa, lalu ia mendapati satu keburukan darimu, niscaya ia akan mengatakan, 'Saya tidak pernah mendapati satu kebaikan pun darimu.'\" Dan telah menceritakannya kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Ishaq] yakni Ibnu Isa, telah mengabarkan kepada kami [Malik] dari [Zaid bin Aslam] dalam isnad ini semisalnya. Hanya saja ia menyebutkan; \"Kemudian kami melihat Anda menahan diri sejenak.\""},"1431":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ سُفْيَانَ عَنْ حَبِيبٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَصَلَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ كَسَفَتْ الشَّمْسُ ثَمَانَ رَكَعَاتٍ فِي أَرْبَعِ سَجَدَاتٍوَعَنْ عَلِيٍّ مِثْلُ ذَلِكَ","id":"Telah menceritakan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Sufyan] dari [Habib] dari [Thawus] dari [Ibnu Abbas] ia berkata; Ketika terjadi gerhana matahari, Rasulullah shallallahu 'alaihi wasallam shalat (gerhana) dengan delapan kali ruku' dan empat kali sujud (dalam dua raka'at). Dan dari [Ali bin Abu Thalib] juga diriwayatkan seperti itu."},"1432":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَأَبُو بَكْرِ بْنُ خَلَّادٍ كِلَاهُمَا عَنْ يَحْيَى الْقَطَّانِ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنَا حَبِيبٌ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ صَلَّى فِي كُسُوفٍ قَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ قَرَأَ ثُمَّ رَكَعَ ثُمَّ سَجَدَ قَالَ وَالْأُخْرَى مِثْلُهَا","id":"Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] dan [Abu Bakr bin Khallad] keduanya dari [Yahya Al Qaththan] - [Ibnul Mutsanna] berkata- telah menceritakan kepada kami [Yahya] dari [Sufyan] ia berkata, telah menceritakan kepada kami [Habib] dari [Thawus] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau menunaikan shalat gerhana. Beliau membaca (ayat), kemudian ruku', kemudian membaca lagi, kemudian beliau ruku', kemudian beliau membaca lagi, kemudian ruku' kemudian beliau membaca lagi, kemudian ruku' dan setelah itu, beliau ruku'. Ia berkata; Dan yang lain meriwayatkan semisalnya."},"1433":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا أَبُو النَّضْرِ حَدَّثَنَا أَبُو مُعَاوِيَةَ وَهُوَ شَيْبَانُ النَّحْوِيُّ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ سَلَّامٍ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ خَبَرِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ أَنَّهُ قَالَلَمَّا انْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نُودِيَ بِ الصَّلَاةَ جَامِعَةً فَرَكَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَكْعَتَيْنِ فِي سَجْدَةٍ ثُمَّ قَامَ فَرَكَعَ رَكْعَتَيْنِ فِي سَجْدَةٍ ثُمَّ جُلِّيَ عَنْ الشَّمْسِفَقَالَتْ عَائِشَةُ مَا رَكَعْتُ رُكُوعًا قَطُّ وَلَا سَجَدْتُ سُجُودًا قَطُّ كَانَ أَطْوَلَ مِنْهُ","id":"Telah menceritakan kepadaku [Muhammad bin Rafi'] Telah menceritakan kepada kami [Abu Nadlr] telah menceritakan kepada kami [Abu Mu'awiyah] ia adalah Syaiban An Nahwi, dari [Yahya] dari [Abu Salamah] dari [Abdullah bin Amru bin Ash] -dalam jalur lain- Dan telah menceritakan kepada kami [Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Mu'awiyah bin Sallam] dari [Yahya bin Abu Katsir] ia berkata, telah mengabarkan kepadaku [Abu Salamah bin Abdurrahman] dari kabar [Abdullah bin Amru bin Ash] bahwa ia berkata; Ketika terjadi gerhana matahari pada masa Rasulullah shallallahu 'alaihi wasallam, maka diserukanlah (kepada kaum muslimin) dengan seruan, \"ASH SHALAATU JAAMI'AH (Marilah kita menunaikan shalat jama'ah).\" Maka Rasulullah shallallahu 'alaihi wasallam ruku' dua raka'at dalam satu kali sujud, kemudian beliau berdiri lalu ruku' lagi dua raka'at dalam satu kali sujud. Setelah itu matahari sudah kembali normal, maka Aisyah pun berkata, \"Saya sama sekali tidak pernah melakukan ruku' dan tidak pula sujud yang lebih panjang darinya.\""},"1434":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ عَنْ إِسْمَعِيلَ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ يُخَوِّفُ اللَّهُ بِهِمَا عِبَادَهُ وَإِنَّهُمَا لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ مِنْ النَّاسِ فَإِذَا رَأَيْتُمْ مِنْهَا شَيْئًا فَصَلُّوا وَادْعُوا اللَّهَ حَتَّى يُكْشَفَ مَا بِكُمْ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim] dari [Isma'il] dari [Qais bin Abu Hazim] dari [Abu Mas'ud Al Anshari] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhya matahari dan bulan adalah dua ayat dari ayat-ayat Allah, yang dengan keduanya Allah hendak menakut-nakuti hamba-Nya. Dan tidaklah terjadi gerhana pada keduanya karena kematian seseorang atau pun kelahirannya. Jika kalian melihat gerhana, maka shalat dan berdo'alah kepada Allah sampai matahari kembali normal (seperti sedia kala).\""},"1435":{"ar":"و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ الْعَنْبَرِيُّ وَيَحْيَى بْنُ حَبِيبٍ قَالَا حَدَّثَنَا مُعْتَمِرٌ عَنْ إِسْمَعِيلَ عَنْ قَيْسٍ عَنْ أَبِي مَسْعُودٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَيْسَ يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ مِنْ النَّاسِ وَلَكِنَّهُمَا آيَتَانِ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمُوهُ فَقُومُوا فَصَلُّواو حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ وَأَبُو أُسَامَةَ وَابْنُ نُمَيْرٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ وَوَكِيعٌ ح و حَدَّثَنَا ابْنُ أَبِي عُمَرَ حَدَّثَنَا سُفْيَانُ وَمَرْوَانُ كُلُّهُمْ عَنْ إِسْمَعِيلَ بِهَذَا الْإِسْنَادِ وَفِي حَدِيثِ سُفْيَانَ وَوَكِيعٍ انْكَسَفَتْ الشَّمْسُ يَوْمَ مَاتَ إِبْرَاهِيمُ فَقَالَ النَّاسُ انْكَسَفَتْ لِمَوْتِ إِبْرَاهِيمَ","id":"Telah menceritakan kepada kami [Ubaidullah bin Mu'adz Al Anbari] dan [Yahya bin Habib] keduanya berkata, telah menceritakan kepada kami [Mu'tamir] dari [Isma'il] dari [Qais] dari [Abu Mas'ud] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya gerhana matahari dan bulan terjadi bukan karena kematian atau kelahiran seseorang. Tetapi keduanya merupakan dua ayat dari ayat-ayat Allah, maka jika kalian melihat (gerhana), berdiri dan shalatlah.\" Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dan [Abu Usamah] dan [Ibnu Numair] -dalam jalur lain- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] dan [Waki'] -dalam jalur lain- Dan telah menceritakan kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Sufyan] dan [Marwan] semuanya dari [Isma'il] dengan isnad ini. Dan di dalam hadits Sufyan dan Waki' disebutkan; Terjadi gerhana matahari tepat pada hari wafatnya Ibrahim, maka orang-orang pun mengatakan, \"Terjadinya gerhana matahari adalah karena kematian Ibrahim.\""},"1436":{"ar":"حَدَّثَنَا أَبُو عَامِرٍ الْأَشْعَرِيُّ عَبْدُ اللَّهِ بْنُ بَرَّادٍ وَمُحَمَّدُ بْنُ الْعَلَاءِ قَالَا حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بُرَيْدٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَخَسَفَتْ الشَّمْسُ فِي زَمَنِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَ فَزِعًا يَخْشَى أَنْ تَكُونَ السَّاعَةُ حَتَّى أَتَى الْمَسْجِدَ فَقَامَ يُصَلِّي بِأَطْوَلِ قِيَامٍ وَرُكُوعٍ وَسُجُودٍ مَا رَأَيْتُهُ يَفْعَلُهُ فِي صَلَاةٍ قَطُّ ثُمَّ قَالَ إِنَّ هَذِهِ الْآيَاتِ الَّتِي يُرْسِلُ اللَّهُ لَا تَكُونُ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّ اللَّهَ يُرْسِلُهَا يُخَوِّفُ بِهَا عِبَادَهُ فَإِذَا رَأَيْتُمْ مِنْهَا شَيْئًا فَافْزَعُوا إِلَى ذِكْرِهِ وَدُعَائِهِ وَاسْتِغْفَارِهِوَفِي رِوَايَةِ ابْنِ الْعَلَاءِ كَسَفَتْ الشَّمْسُ وَقَالَ يُخَوِّفُ عِبَادَهُ","id":"Telah menceritakan kepada kami [Abu Amir Al Asy'ari Abdullah bin Barrad] dan [Muhammad bin Al Ala`] keduanya berkata, telah menceritakan kepada kami [Abu Usamah] dari [Buraid] dari [Abu Burdah] dari [Abu Musa] ia berkata; Pada zaman Nabi shallallahu 'alaihi wasallam pernah terjadi gerhana matahari, beliau terkejut dan bergegas berdiri karena takut kalau-kalau akan terjadi kiamat. Sampai beliau masuk ke masjid dan melaksanakan shalat dengan berdiri, ruku dan sujud yang panjang sekali, aku belum pernah melihat beliau memanjangkan bacaan sedemikian lama sebelumnya, kemudian beliau bersabda: \"Sesungguhnya semua tanda-tanda yang dikirimkan Allah ini bukanlah disebabkan oleh meninggalnya atau lahirnya seseorang, akan tetapi Allah mengirimnya untuk menakut-nakuti para hamba-Nya. Oleh sebab itu jika kalian melihatnya maka bersegeralah berdzikir mengingat Allah, memanjatkan do'a padaNya, serta memohon ampunan-Nya.\" Dalam hadits yang diriwayatkan oleh Ibnu Al 'Alaa' disebutkan: \"Terjadi gerhana matahari…\" dan dia berkata; \"Untuk menakut-nakuti hambaNya\"."},"1437":{"ar":"و حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ حَيَّانَ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَبَيْنَمَا أَنَا أَرْمِي بِأَسْهُمِي فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ انْكَسَفَتْ الشَّمْسُ فَنَبَذْتُهُنَّ وَقُلْتُ لَأَنْظُرَنَّ إِلَى مَا يَحْدُثُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي انْكِسَافِ الشَّمْسِ الْيَوْمَ فَانْتَهَيْتُ إِلَيْهِ وَهُوَ رَافِعٌ يَدَيْهِ يَدْعُو وَيُكَبِّرُ وَيَحْمَدُ وَيُهَلِّلُ حَتَّى جُلِّيَ عَنْ الشَّمْسِ فَقَرَأَ سُورَتَيْنِ وَرَكَعَ رَكْعَتَيْنِ","id":"Telah menceritakan kepadaku [Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Bisyr Al Mufadldlal] telah menceritakan kepada kami [Al Jurairi] dari [Abul Ala` Hayyan bin Umair] dari [Abdurrahman bin Samurah] ia berkata; \"Pada suatu waktu di masa Rasulullah shallallahu 'alaihi wasallam ketika aku sedang bermain panah, tiba-tiba terjadi gerhana matahari. Lalu kulemparkan semua alat permainanku itu. Aku berkata; Aku akan melihat apakah gerangan yang dilakukan Rasulullah shallallahu 'alaihi wasallam bila terjadi gerhana matahari seperti itu. Setelah aku sampai ke tempat beliau, kudapati beliau sedang mengangkat tangannya berdo'a, takbir, tahmid dan tahlil sampai matahari terang kembali. Beliau membaca dua surat dan shalat dua raka'at.\""},"1438":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى بْنُ عَبْدِ الْأَعْلَى عَنْ الْجُرَيْرِيِّ عَنْ حَيَّانَ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَكُنْتُ أَرْتَمِي بِأَسْهُمٍ لِي بِالْمَدِينَةِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ كَسَفَتْ الشَّمْسُ فَنَبَذْتُهَا فَقُلْتُ وَاللَّهِ لَأَنْظُرَنَّ إِلَى مَا حَدَثَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي كُسُوفِ الشَّمْسِ قَالَ فَأَتَيْتُهُ وَهُوَ قَائِمٌ فِي الصَّلَاةِ رَافِعٌ يَدَيْهِ فَجَعَلَ يُسَبِّحُ وَيَحْمَدُ وَيُهَلِّلُ وَيُكَبِّرُ وَيَدْعُو حَتَّى حُسِرَ عَنْهَا قَالَ فَلَمَّا حُسِرَ عَنْهَا قَرَأَ سُورَتَيْنِ وَصَلَّى رَكْعَتَيْنِحَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا سَالِمُ بْنُ نُوحٍ أَخْبَرَنَا الْجُرَيْرِيُّ عَنْ حَيَّانَ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَ بَيْنَمَا أَنَا أَتَرَمَّى بِأَسْهُمٍ لِي عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ خَسَفَتْ الشَّمْسُ ثُمَّ ذَكَرَ نَحْوَ حَدِيثِهِمَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Abdul A'la bin Abdul A'la] dari [Al Jurairi] dari [Hayyan bin Umair] dari [Abdurrahman bin Samurah] -ia adalah salah seorang dari sahabat Rasulullah shallallahu 'alaihi wasallam- ia berkata; Aku sedang bermain panah di Madinah pada masa Rasulullah shallallahu 'alaihi wasallam, tiba-tiba terjadilah gerhana matahari, maka aku pun langsung membuangnya dan berkata, \"Demi Allah, aku benar-benar akan melihat apa yang hendak dikerjakan oleh Rasulullah shallallahu 'alaihi wasallam saat terjadi gerhana matahari. Lalu aku pun mendatangi beliau, dan ternyata beliau sedang berdiri untuk menunaikan shalat dengan mengangkat kedua tangannya. Beliau membaca tasbih, tahmid, tahlil dan takbir serta berdo'a hingga matahari bersinar kembali. Setelah matahari bersinar kembali, beliau membaca dua surat dan shalat dua raka'at. Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Salim bin Nuh] telah mengabarkan kepada kami [Al Jurairi] dari [Hayyan bin Umair] dari [Abdurrahman bin Samurah] ia berkata; Ketika aku sedang melempar panah di masa Rasulullah shallallahu 'alaihi wasallam, tiba-tiba terjadi gerhana matahari. Lalu ia pun menyebutkan hadits yang serupa dengan hadits keduanya."},"1439":{"ar":"و حَدَّثَنِي هَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ أَنَّ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ حَدَّثَهُ عَنْ أَبِيهِ الْقَاسِمِ بْنِ مُحَمَّدِ بْنِ أَبِي بَكْرٍ الصِّدِّيقِ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّهُ كَانَ يُخْبِرُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ إِنَّ الشَّمْسَ وَالْقَمَرَ لَا يَخْسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ وَلَكِنَّهُمَا آيَةٌ مِنْ آيَاتِ اللَّهِ فَإِذَا رَأَيْتُمُوهُمَا فَصَلُّوا","id":"Dan telah menceritakan kepadaku [Harun bin Sa'id Al Aili] telah menceritakan kepada kami [Ibnu Wahb] telah menceritakan kepadaku [Amru bin Al Harits] bahwa [Abdurrahman bin Qasim] telah menceritakan kepadanya dari bapaknya [Al Qasim bin Muhammad bin Abu Bakar Ash Shiddiq], dari [Abdullah bin Umar] bahwa ia telah mengabarkan dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Sesungguhnya tidaklah terjadi gerhana matahari dan bulan karena kematian seseorang atau pun kelahirannya, akan tetapi keduanya adalah ayat-ayat Allah. Karena itu, bila kalian melihat (gerhana), maka shalatlah.\""},"1440":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ قَالَا حَدَّثَنَا مُصْعَبٌ وَهُوَ ابْنُ الْمِقْدَامِ حَدَّثَنَا زَائِدَةُ حَدَّثَنَا زِيَادُ بْنُ عِلَاقَةَ وَفِي رِوَايَةِ أَبِي بَكْرٍ قَالَ قَالَ زِيَادُ بْنُ عِلَاقَةَ سَمِعْتُ الْمُغِيرَةَ بْنَ شُعْبَةَ يَقُولُانْكَسَفَتْ الشَّمْسُ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ مَاتَ إِبْرَاهِيمُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الشَّمْسَ وَالْقَمَرَ آيَتَانِ مِنْ آيَاتِ اللَّهِ لَا يَنْكَسِفَانِ لِمَوْتِ أَحَدٍ وَلَا لِحَيَاتِهِ فَإِذَا رَأَيْتُمُوهُمَا فَادْعُوا اللَّهَ وَصَلُّوا حَتَّى تَنْكَشِفَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Abdullah bin Numair] keduanya berkata, telah menceritakan kepada kami [Mush'ab] ia adalah anak Miqdam, telah menceritakan kepada kami [Za`idah] telah menceritakan kepada kami [Ziyad bin Ilaqah] -sementara di dalam riwayat Abu Bakr, ia berkata; Ziyad bin Ilaqah berkata- saya mendengar [Al Mughirah bin Syu'bah] berkata; Pernah terjadi gerhana matahari di masa Rasulullah shallallahu 'alaihi wasallam dan bertepatan dengan hari wafatnya Ibrahim putra Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Sesungguhnya matahari dan bulan adalah dua ayat dari ayat-ayat Allah. Tidaklah terjadi gerhana pada keduanya karena kematian salah seorang atau pun kelahirannya. Karena itu, jika kaliat melihat (gerhana pada) keduanya, maka berdo'alah kepada Allah dan shalatlah hingga ia bersinar kembali.\""},"1441":{"ar":"و حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ فُضَيْلُ بْنُ حُسَيْنٍ وَعُثْمَانُ بْنُ أَبِي شَيْبَةَ كِلَاهُمَا عَنْ بِشْرٍ قَالَ أَبُو كَامِلٍ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ حَدَّثَنَا عُمَارَةُ بْنُ غَزِيَّةَ حَدَّثَنَا يَحْيَى بْنُ عُمَارَةَ قَالَ سَمِعْتُ أَبَا س��عِيدٍ الْخُدْرِيَّ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا مَوْتَاكُمْ لَا إِلَهَ إِلَّا اللَّهُو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ جَمِيعًا بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Abu Kamil Al Jahdari Fudlail bin Husain] dan [Utsman bin Abu Syaibah] keduanya dari [Bisyr] - [Abu Kamil] berkata- Telah menceritakan kepada kami [Umarah bin Ghaziyyah] telah menceritakan kepada kami [Yahya bin Umarah] ia berkata, saya mendengar [Abu Sa'id Al Khudri] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tuntunlah orang yang sedang berada di penghujung ajalnya agar membaca (kalimat), 'LAA ILAAHA ILLALLAH.'\" Dan telah menceritakannya kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Aziz Ad Darawardi] -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Sulaiman bin Bilal] semuanya menggunakan isnad ini."},"1442":{"ar":"و حَدَّثَنَا أَبُو بَكْرٍ وَعُثْمَانُ ابْنَا أَبِي شَيْبَةَ ح و حَدَّثَنِي عَمْرٌو النَّاقِدُ قَالُوا جَمِيعًا حَدَّثَنَا أَبُو خَالِدٍ الْأَحْمَرُ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقِّنُوا مَوْتَاكُمْ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah menceritakan kepada kami [Abu Bakr] dan [Utsman] -keduanya adalah anak dari Abu Syaibah- -dalam jalur lain- Dan telah menceritakan kepadaku [Amru An Naqid] semuanya berkata, telah menceritakan kepada kami [Abu Khalid Al Ahmar] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda, \"Tuntunlahlah orang yang sedang berada di penghujung ajalnya dengan kalimat LAA ILAAHA ILLALLAAH\"."},"1443":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَقُتَيْبَةُ وَابْنُ حُجْرٍ جَمِيعًا عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ قَالَ ابْنُ أَيُّوبَ حَدَّثَنَا إِسْمَعِيلُ أَخْبَرَنِي سَعْدُ بْنُ سَعِيدٍ عَنْ عُمَرَ بْنِ كَثِيرِ بْنِ أَفْلَحَ عَنْ ابْنِ سَفِينَةَ عَنْ أُمِّ سَلَمَةَ أَنَّهَا قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ مُسْلِمٍ تُصِيبُهُ مُصِيبَةٌ فَيَقُولُ مَا أَمَرَهُ اللَّهُ{ إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ }اللَّهُمَّ أْجُرْنِي فِي مُصِيبَتِي وَأَخْلِفْ لِي خَيْرًا مِنْهَا إِلَّا أَخْلَفَ اللَّهُ لَهُ خَيْرًا مِنْهَا قَالَتْ فَلَمَّا مَاتَ أَبُو سَلَمَةَ قُلْتُ أَيُّ الْمُسْلِمِينَ خَيْرٌ مِنْ أَبِي سَلَمَةَ أَوَّلُ بَيْتٍ هَاجَرَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ إِنِّي قُلْتُهَا فَأَخْلَفَ اللَّهُ لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَرْسَلَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَاطِبَ بْنَ أَبِي بَلْتَعَةَ يَخْطُبُنِي لَهُ فَقُلْتُ إِنَّ لِي بِنْتًا وَأَنَا غَيُورٌ فَقَالَ أَمَّا ابْنَتُهَا فَنَدْعُو اللَّهَ أَنْ يُغْنِيَهَا عَنْهَا وَأَدْعُو اللَّهَ أَنْ يَذْهَبَ بِالْغَيْرَةِ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Qutaibah] dan [Ibnu Hujr] semuanya dari [Isma'il bin Ja'far] - [Ibnu Ayyub] berkata- telah menceritakan kepada kami [Isma'il] telah mengabarkan kepadaku [Sa'd bin Sa'id] dari [Umar bin Katsir bin Aflah] dari [Ibnu Safinah] dari [Ummu Salamah] bahwa ia berkata; saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang mukmin tertimpa musibah lalu ia membaca apa yang telah diperintahkan oleh Allah, 'INAA LILLAHI WAINNAA ILAIHI RAAJI'UUN ALLAHUMMA`JURNII FII MUSHIIBATI WA AKHLIF LII KHAIRAN MINHAA (Sesungguhnya kami adalah milik Allah dan akan kembali kepada Allah. Ya Allah, berilah kami pahala karena mushibah ini dan tukarlah bagiku dengan yang lebih baik daripadanya).' melainkan Allah menukar baginya dengan yang lebih baik.\" Ummu Salamah berkata; Ketika Abu Salamah telah meninggal, saya bertanya, \"Orang muslim manakan yang lebih baik daripada Abu Salamah? Dia adalah orang-orang yang pertama-tama hijrah kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian akupun mengucapkan doa tersebut. Maka Allah pun menggantikannya bagiku Rasulullah shallallahu 'alaihi wasallam.\" Ummu Salamah mengkisahkan; Rasulullah shallallahu 'alaihi wasallam mengutus Hatib bin Abu Balta'ah melamarku untuk beliau sendiri. Maka saya pun menjawab, \"Bagaimana mungkin, aku telah mempunyai seorang anak wanita, dan aku sendiri adalah seorang pencemburu.\" Selanjutnya beliau pun menjawab: \"Adapun anaknya, maka kita do'akan semoga Allah mencukupkan kebutuhannya, dan aku mendo'akan pula semoga Allah menghilangkan rasa cemburunya itu.\""},"1444":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ سَعْدِ بْنِ سَعِيدٍ قَالَ أَخْبَرَنِي عُمَرُ بْنُ كَثِيرِ بْنِ أَفْلَحَ قَالَ سَمِعْتُ ابْنَ سَفِينَةَ يُحَدِّثُ أَنَّهُ سَمِعَ أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ عَبْدٍ تُصِيبُهُ مُصِيبَةٌ فَيَقُولُ{ إِنَّا لِلَّهِ وَإِنَّا إِلَيْهِ رَاجِعُونَ }اللَّهُمَّ أْجُرْنِي فِي مُصِيبَتِي وَأَخْلِفْ لِي خَيْرًا مِنْهَا إِلَّا أَجَرَهُ اللَّهُ فِي مُصِيبَتِهِ وَأَخْلَفَ لَهُ خَيْرًا مِنْهَا قَالَتْ فَلَمَّا تُوُفِّيَ أَبُو سَلَمَةَ قُلْتُ كَمَا أَمَرَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْلَفَ اللَّهُ لِي خَيْرًا مِنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَو حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا أَبِي حَدَّثَنَا سَعْدُ بْنُ سَعِيدٍ أَخْبَرَنِي عُمَرُ يَعْنِي ابْنَ كَثِيرٍ عَنْ ابْنِ سَفِينَةَ مَوْلَى أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بِمِثْلِ حَدِيثِ أَبِي أُسَامَةَ وَزَادَ قَالَتْ فَلَمَّا تُوُفِّيَ أَبُو سَلَمَةَ قُلْتُ مَنْ خَيْرٌ مِنْ أَبِي سَلَمَةَ صَاحِبِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ عَزَمَ اللَّهُ لِي فَقُلْتُهَا قَالَتْ فَتَزَوَّجْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] dari [Sa'd bin Sa'id] ia berkata, telah mengabarkan kepadaku [Umar bin Katsir bin Aflah] ia berkata, saya mendengar [Ibnu Safinah] menceritakan bahwa ia mendengar [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang mukmin tertimpa musibah lalu ia membaca apa yang telah diperintahkan oleh Allah, 'INAA LILLAHI WAINNAA ILAIHI RAAJI'UUN ALLAHUMMA`JURNII FII MUSHIIBATI WA AKHLIF LII KHAIRAN MINHAA (Sesungguhnya kami adalah milik Allah dan akan kembali kepada Allah. Ya Allah, berilah kami pahala karena mushibah ini dan tukarlah bagiku dengan yang lebih baik daripadanya).' melainkan Allah menukar baginya dengan yang lebih baik.\" Ummu Salamah berkata; Ketika Abu Salamah telah meninggal, maka saya pun membaca sebagaimana yang diperintahkan oleh Rasulullah shallallahu 'alaihi wasallam, lalu Allah pun menggantikannya untukku dengan yang lebih baik darinya yaitu Rasulullah shallallahu 'alaihi wasallam. Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Sa'd bin Abu Sa'id] telah mengabarkan kepadaku [Umar bin Katsir] dari [Ibnu Safinah] Maula Ummu Salamah, dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda, yakni serupa dengan haditsnya Abu Usamah, dan ia menambahkan; (Ummu Salamah) berkata, \"Siapakah yang lebih baik dari Abu Salamah sahabat Rasulullah shallallahu 'alaihi wasallam, kemudian Allah pun mengokohkan hatiku untuk mengucapkannya. Lalu aku pun menikah dengan Rasulullah shallallahu 'alaihi wasallam.\""},"1445":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ أُمِّ سَلَمَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا حَضَرْتُمْ الْمَرِيضَ أَوْ الْمَيِّتَ فَقُولُوا خَيْرًا فَإِنَّ الْمَلَائِكَةَ يُؤَمِّنُونَ عَلَى مَا تَقُولُونَ قَالَتْ فَلَمَّا مَاتَ أَبُو سَلَمَةَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سَلَمَةَ قَدْ مَاتَ قَالَ قُولِي اللَّهُمَّ اغْفِرْ لِي وَلَهُ وَأَعْقِبْنِي مِنْهُ عُقْبَى حَسَنَةً قَالَتْ فَقُلْتُ فَأَعْقَبَنِي اللَّهُ مَنْ هُوَ خَيْرٌ لِي مِنْهُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] keduanya berkata, telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Ummu Salamah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kamu menjenguk orang sakit atau orang yang meninggal, maka ucapkanlah (do'a) yang baik, karena malaikat mengaminkan ucapan kalian.\" Abu Salamah mengkisahkan; Ketika Abu Salamah meninggal, saya mendatangi Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya Abu Salamah telah meninggal.\" Maka beliau pun bersabda: \"Ucapkanlah, 'ALLAHUMMAGHFIR LII WA LAHU WA`A'QIBNII MINHU UQBAA HASANAH (Ya Allah, ampunilah aku dan ampunilah dia. Dan berilah ganti kematiannya itu bagiku dengan ganti yang lebih baik).'\" maka saya pun membacanya, sehingga Allah menggantikan dengan yang lebih baik darinya, yaitu Muhammad shallallahu 'alaihi wasallam."},"1446":{"ar":"حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ قَبِيصَةَ بْنِ ذُؤَيْبٍ عَنْ أُمِّ سَلَمَةَ قَالَتْدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى أَبِي سَلَمَةَ وَقَدْ شَقَّ بَصَرُهُ فَأَغْمَضَهُ ثُمَّ قَالَ إِنَّ الرُّوحَ إِذَا قُبِضَ تَبِعَهُ الْبَصَرُ فَضَجَّ نَاسٌ مِنْ أَهْلِهِ فَقَالَ لَا تَدْعُوا عَلَى أَنْفُسِكُمْ إِلَّا بِخَيْرٍ فَإِنَّ الْمَلَائِكَةَ يُؤَمِّنُونَ عَلَى مَا تَقُولُونَ ثُمَّ قَالَ اللَّهُمَّ اغْفِرْ لِأَبِي سَلَمَةَ وَارْفَعْ دَرَجَتَهُ فِي الْمَهْدِيِّينَ وَاخْلُفْهُ فِي عَقِبِهِ فِي الْغَابِرِينَ وَاغْفِرْ لَنَا وَلَهُ يَا رَبَّ الْعَالَمِينَ وَافْسَحْ لَهُ فِي قَبْرِهِ وَنَوِّرْ لَهُ فِيهِو حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى الْقَطَّانُ الْوَاسِطِيُّ حَدَّثَنَا الْمُثَنَّى بْنُ مُعَاذِ بْنِ مُعَاذٍ حَدَّثَنَا أَبِي حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ الْحَسَنِ حَدَّثَنَا خَالِدٌ الْحَذَّاءُ بِهَذَا الْإِسْنَادِ نَحْوَهُ غَيْرَ أَنَّهُ قَالَ وَاخْلُفْهُ فِي تَرِكَتِهِ وَقَالَ اللَّهُمَّ أَوْسِعْ لَهُ فِي قَبْرِهِ وَلَمْ يَقُلْ افْسَحْ لَهُ وَزَادَ قَالَ خَالِدٌ الْحَذَّاءُ وَدَعْوَةٌ أُخْرَى سَابِعَةٌ نَسِيتُهَا","id":"Telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami [Mua'wiyah bin Amru] telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Qabishah bin Dzu`aib] dari [Ummu Salamah] ia berkata; Ketika Abu Salamah meninggal, Rasulullah shallallahu 'alaihi wasallam datang ke rumah kami untuk menjenguk jenazahnya. Saat itu, mata Abu Salamah tengah terbeliak, maka beliau pun menutupnya. Kemudian beliau bersabda: \"Apabila ruh telah dicabut, maka penglihatan akan mengikutinya dan keluarganya pun meratap hiteris. Dan janganlah sekali-kali mendo'akan atas diri kalian kecuali kebaikan, sebab ketika itu malaikat akan mengaminkan apa yang kalian ucapkan.\" Setelah itu, beliau berdo'a: \"ALLAHUMMAGHFIR LIABI SALAMAH WARFA' DARAJATAHU FIL MAHDIYYIIN WAKHLUFHU FI 'AQIBIHI FIL GHAABIRIIN, WAGHFIR LANAA WALAHU YAA RABBAL 'ALAMIIN, WAFSAH LAHU FII QABRIHI WA NAWWIR LAHU FIIHI (Ya Allah, ampunilah Abu Salamah, tinggikan derajatnya di kalangan orang-orang yang terpimpin dengan petunjuk-Mu dan gantilah ia bagi keluarganya yang ditinggalkannya. Ampunilah kami dan ampunilah dia. Wahai Rabb semesta alam. Lapangkanlah kuburnya dan terangilah dia di dalam kuburnya).\" Dan telah menceritakan kepada kami [Muhammad bin Musa Al Qaththan Al Wasithi] telah menceritakan kepada kami [Al Mutsanna bin Mu'adz] telah menceritakan kepada kami [bapakku] telah menceritakan kepada kami [Ubaidullah bin Al Hasan] telah menceritakan kepada kami [Khalid Al Hadzdza`] dengan Isnad ini dan serupa dengannya. Hanya saja, ia mengatakan; \"Dan gantikanlah ia bagi keluarganya.\" Ia juga mengatakan; \"Ya Allah, lapangkanlah kuburannya.\" Dan ia tidak mengatakan; \"IFSAH LAHU (lapangkanlah baginya).\" Dan ia menambahkan lagi; Khalid Al Hadzdza` berkata; \"Dan do'a lain yang ketujuh saya lupa.\""},"1447":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ عَنْ الْعَلَاءِ بْنِ يَعْقُوبَ قَالَ أَخْبَرَنِي أَبِي أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ تَرَوْا الْإِنْسَانَ إِذَا مَاتَ شَخَصَ بَصَرُهُ قَالُوا بَلَى قَالَ فَذَلِكَ حِينَ يَتْبَعُ بَصَرُهُ نَفْسَهُو حَدَّثَنَاه قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي الدَّرَاوَرْدِيَّ عَنْ الْعَلَاءِ بِهَذَا الْإِسْنَادِ","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] dari [Al 'Ala` bin Ya'qub] ia berkata, telah mengabarkan kepadaku [bapakku] bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukankah kalian telah menyaksikan bahwa jika seseorang meninggal dunia matanya akan terbelalak?\" Para sahabat menjawab, \"Ya, kami telah menyaksikan.\" Beliau bersabda: \"Itu terjadi sa'at pandangan matanya mengikuti ruhnya (yang keluar dari jasad-pent).\" Dan telah menceritakannya kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Abdul Aziz Ad Darawardi] dari [Al Ala`] dengan isnad ini."},"1448":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَابْنُ نُمَيْرٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ كُلُّهُمْ عَنْ ابْنِ عُيَيْنَةَ قَالَ ابْنُ نُمَيْرٍ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ أَبِيهِ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ قَالَ قَالَتْ أُمُّ سَلَمَةَلَمَّا مَاتَ أَبُو سَلَمَةَ قُلْتُ غَرِيبٌ وَفِي أَرْضِ غُرْبَةٍ لَأَبْكِيَنَّهُ بُكَاءً يُتَحَدَّثُ عَنْهُ فَكُنْتُ قَدْ تَهَيَّأْتُ لِلْبُكَاءِ عَلَيْهِ إِذْ أَقَبَلَتْ امْرَأَةٌ مِنْ الصَّعِيدِ تُرِيدُ أَنْ تُسْعِدَنِي فَاسْتَقْبَلَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ أَتُرِيدِينَ أَنْ تُدْخِلِي الشَّيْطَانَ بَيْتًا أَخْرَجَهُ اللَّهُ مِنْهُ مَرَّتَيْنِ فَكَفَفْتُ عَنْ الْبُكَاءِ فَلَمْ أَبْكِ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Ibnu Numair] dan [Ishaq bin Ibrahim] semuanya dari [Ibnu Uyainah] - [Ibnu Numair] berkata- telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Najih] dari [bapaknya] dari [Ubaid bin Umair] ia berkata; [Ummu Salamah] berkata; Ketika Abu Salamah meninggal dunia, saya pun berkata, \"Orang asing, meninggal pula di negeri asing. Akan kuratapi dia sepuas-puasnya sehingga menjadi buah bibir orang.\" Ketika aku bersiap-siap hendak meratapinya, tiba-tiba datang seorang perempuan dari dusun menawarkan diri hendak menolongku meratap. Lalu Rasulullah shallallahu 'alaihi wasallam mendatanginya seraya bersabda: \"Apakah kamu hendak memasukkan syetan lagi ke dalam rumah ini, yang mana Allah telah mengeluarkannya dari sini?\" beliau mengulanginya hingga dua kali. Maka mendengar sabda beliau itu, akhirnya aku menahan diri dan tidak jadi meratap."},"1449":{"ar":"حَدَّثَنَا أَبُو كَامِلٍ الْجَحْدَرِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ أَبِي عُثْمَانَ النَّهْدِيِّ عَنْ أُسَامَةَ بْنِ زَيْدٍ قَالَكُنَّا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَتْ إِلَيْهِ إِحْدَى بَنَاتِهِ تَدْعُوهُ وَتُخْبِرُهُ أَنَّ صَبِيًّا لَهَا أَوْ ابْنًا لَهَا فِي الْمَوْتِ فَقَالَ لِلرَّسُولِ ارْجِعْ إِلَيْهَا فَأَخْبِرْهَا أَنَّ لِلَّهِ مَا أَخَذَ وَلَهُ مَا أَعْطَى وَكُلُّ شَيْءٍ عِنْدَهُ بِأَجَلٍ مُسَمًّى فَمُرْهَا فَلْتَصْبِرْ وَلْتَحْتَسِبْ فَعَادَ الرَّسُولُ فَقَالَ إِنَّهَا قَدْ أَقْسَمَتْ لَتَأْتِيَنَّهَا قَالَ فَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَامَ مَعَهُ سَعْدُ بْنُ عُبَادَةَ وَمُعَاذُ بْنُ جَبَلٍ وَانْطَلَقْتُ مَعَهُمْ فَرُفِعَ إِلَيْهِ الصَّبِيُّ وَنَفْسُهُ تَقَعْقَعُ كَأَنَّهَا فِي شَنَّةٍ فَفَاضَتْ عَيْنَاهُ فَقَالَ لَهُ سَعْدٌ مَا هَذَا يَا رَسُولَ اللَّهِ قَالَ هَذِهِ رَحْمَةٌ جَعَلَهَا اللَّهُ فِي قُلُوبِ عِبَادِهِ وَإِنَّمَا يَرْحَمُ اللَّهُ مِنْ عِبَادِهِ الرُّحَمَاءَو حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا ابْنُ فُضَيْلٍ ح و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو مُعَاوِيَةَ جَمِيعًا عَنْ عَاصِمٍ الْأَحْوَلِ بِهَذَا الْإِسْنَادِ غَيْرَ أَنَّ حَدِيثَ حَمَّادٍ أَتَمُّ وَأَطْوَلُ","id":"Telah menceritakan kepada kami [Abu Kamil Al Jahdari] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ashim Al Ahwali] dari [Abu Utsman An Nahdi] dari [Usamah bin Zaid] ia berkata; Pada suatu hari ketika kami sedang berada di dekat Nabi shallallahu 'alaihi wasallam, tiba-tiba datang seorang suruhan dari puteri Nabi shallallahu 'alaihi wasallam (Zainab binti Muhammad), meminta agar Nabi shallallahu 'alaihi wasallam datang dan mengabarkan kepada beliau bahwa anak puteranya (cucu Nabi shallallahu 'alaihi wasallam) telah meninggal. Rasulullah shallallahu 'alaihi wasallam pun berpesan pada suruhan itu: \"Pulang dan sampaikanlah kepada Zainab, bahwa kepunyaan Allah jualah yang telah diambil dan kepunyaan-Nya pula yang telah diberikan. Segala sesuatu telah Allah tentukan ajalnya. Karena itu, suruhlah ia bersabar dan menahan diri.\" Tidak lama kemudian, pesuruh itu datang kembali dan berkata, \"Zainab sangat mengharapkan, sekiranya Rasulullah shallallahu 'alaihi wasallam sudi menjenguknya.\" Maka berangkatlah beliau bersama para sahabatnya antara lain, Sa'ad bin Ubadah, Mu'adz bin Jabar dan aku sendiri. Sesampainya di sana, diserahkanlah anak yang telah meninggal itu pada beliau, tiba-tiba nafas beliau terengah-engah seperti sedang kepayahan dan air matanya pun menetes. Lalu Sa'ad pun bertanya, \"Ada apa wahai Rasulullah?\" beliau menjawab: \"Ini adalah rahmah (kasih sayang) yang telah dijadikan Allah dalam hati para hamba-Nya. Sesungguhnya hamba Allah yang dirahmati oleh-Nya hanyalah orang yang memiliki kasih sayang.\" Dan telah menceritakan kepada kami [Muhammad bin Abdullah bin Numair] telah menceritakan kepada kami [Ibnu Fudlail] -dalam jalur lain- Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Mu'awiyah] semuanya dari [Ashim Al Ahwal] dengan isnad ini, hanya saja hadits Hammad lebih lengkap dan panjang."},"1450":{"ar":"حَدَّثَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى الصَّدَفِيُّ وَعَمْرُو بْنُ سَوَّادٍ الْعَامِرِيُّ قَالَا أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ سَعِيدِ بْنِ الْحَارِثِ الْأَنْصَارِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَاشْتَكَى سَعْدُ بْنُ عُبَادَةَ شَكْوَى لَهُ فَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ مَعَ عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَسَعْدِ بْنِ أَبِي وَقَّاصٍ وَعَبْدِ اللَّهِ بْنِ مَسْعُودٍ فَلَمَّا دَخَلَ عَلَيْهِ وَجَدَهُ فِي غَشِيَّةٍ فَقَالَ أَقَدْ قَضَى قَالُوا لَا يَا رَسُولَ اللَّهِ فَبَكَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَأَى الْقَوْمُ بُكَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَكَوْا فَقَالَ أَلَا تَسْمَعُونَ إِنَّ اللَّهَ لَا يُعَذِّبُ بِدَمْعِ الْعَيْنِ وَلَا بِحُزْنِ الْقَلْبِ وَلَكِنْ يُعَذِّبُ بِهَذَا وَأَشَارَ إِلَى لِسَانِهِ أَوْ يَرْحَمُ","id":"Telah menceritakan kepada kami [Yunus bin Abdul A'la Ash Shadafi] dan [Amru bin Sawwad Al Amiri] keduanya berkata, telah mengabarkan kepada kami [Abdullah bin Wahb] telah mengabarkan kepadaku [Amru bin Harits] dari [Sa'd bin Al Harits Al Anshari] dari [Abdullah bin Umar] ia berkata; Sa'ad bin Ubadah pernah mengeluhkan rasa sakit yang dideritanya, sehingga Rasulullah shallallahu 'alaihi wasallam bersama Abdur Rahman bin 'Auf, Sa'ad bin Abi Waqqash, dan Abdullah bin Mas'ud menjenguknya. Ketika beliau hendak masuk ternyata ia sedang dikerumuni keluarganya, maka beliau pun bertanya: \"Apakah ia telah meninggal dunia?\" Para sahabat menjawab, \"Belum wahai Rasulullah.\" Maka Rasulullah shallallahu 'alaihi wasallam meneteskan air mata. Melihat beliau menangis, para sahabatpun ikut menangis. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dengarkanlah oleh kalian, sesungguhnya Allah tidak mengadzab seseorang karena disebabkan tangisan atau perasaan sedih (dari orang yang ditinggalkannya) akan tetapi Dia mengadzab karena disebabkan oleh ini (beliau memberi isyarat pada lisannya), atau Dia akan mengasihinya.\""},"1451":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى الْعَنَزِيُّ حَدَّثَنَا مُحَمَّدُ بْنُ جَهْضَمٍ حَدَّثَنَا إِسْمَعِيلُ وَهُوَ ابْنُ جَعْفَرٍ عَنْ عُمَارَةَ يَعْنِي ابْنَ غَزِيَّةَ عَنْ سَعِيدِ بْنِ الْحَارِثِ بْنِ الْمُعَلَّى عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّهُ قَالَكُنَّا جُلُوسًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَجُلٌ مِنْ الْأَنْصَارِ فَسَلَّمَ عَلَيْهِ ثُمَّ أَدْبَرَ الْأَنْصَارِيُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَخَا الْأَنْصَارِ كَيْفَ أَخِي سَعْدُ بْنُ عُبَادَةَ فَقَالَ صَالِحٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَعُودُهُ مِنْكُمْ فَقَامَ وَقُمْنَا مَعَهُ وَنَحْنُ بِضْعَةَ عَشَرَ مَا عَلَيْنَا نِعَالٌ وَلَا خِفَافٌ وَلَا قَلَانِسُ وَلَا قُمُصٌ نَمْشِي فِي تِلْكَ السِّبَاخِ حَتَّى جِئْنَاهُ فَاسْتَأْخَرَ قَوْمُهُ مِنْ حَوْلِهِ حَتَّى دَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَصْحَابُهُ الَّذِينَ مَعَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna Al 'Anazi] telah menceritakan kepada kami [Muhammad bin Jahdlam] Telah menceritakan kepada kami [Isma'i bin Ja'far] dari [Umarah, anak Ghaziyyah] dari [Sa'id bin Al Harits Al Mu'alla] dari [Abdullah bin Umar] bahwa ia berkata; Ketika kami sedang duduk-duduk bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datang seorang sahabat Anshor menghampiri dan memberi salam kepada beliau. Kemudian ketika sahabat Anshar itu hendak pergi, Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: \"Wahai saudaraku dari kaum anshor, bagaimana keadaan saudaraku Sa'ad bin Ubadah?\" \"Ia baik-baik saja.\" jawabnya. Lalu Rasulullah shallallahu 'alaihi wasallam menawarkan: \"Siapakah di antara kalian yang mau menjenguknya?\" Kemudian beliau berdiri dan kamipun juga berdiri bersama beliau, dan ketika itu kami berjumlah belasan orang, kami tidak memakai sandal, sepatu, peci dan juga gamis. Kami berjalan di atas tanah yang gembur hingga kami sampai pada tempatnya, kemudian ia meminta orang yang sedang mengelilinginya untuk mundur agar Rasulullah shallallahu 'alaihi wasallam beserta para sahabat yang bersama beliau saat itu bisa mendekat padanya."},"1452":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ الْعَبْدِيُّ حَدَّثَنَا مُحَمَّدٌ يَعْنِي ابْنَ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ ثَابِتٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُاقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الصَّبْرُ عِنْدَ الصَّدْمَةِ الْأُولَى","id":"Telah menceritakan kepada kami [Muhammad bin Basysyar Al Abdi] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Tsabit] ia berkata, saya mendengar [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya kesabaran itu letaknya pada goncangan yang pertama.\""},"1453":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا شُعْبَةُ عَنْ ثَابِتٍ الْبُنَانِيِّ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى عَلَى امْرَأَةٍ تَبْكِي عَلَى صَبِيٍّ لَهَا فَقَالَ لَهَا اتَّقِي اللَّهَ وَاصْبِرِي فَقَالَتْ وَمَا تُبَالِي بِمُصِيبَتِي فَلَمَّا ذَهَبَ قِيلَ لَهَا إِنَّهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَهَا مِثْلُ الْمَوْتِ فَأَتَتْ بَابَهُ فَلَمْ تَجِدْ عَلَى بَابِهِ بَوَّابِينَ فَقَالَتْ يَا رَسُولَ اللَّهِ لَمْ أَعْرِفْكَ فَقَالَ إِنَّمَا الصَّبْرُ عِنْدَ أَوَّلِ صَدْمَةٍ أَوْ قَالَ عِنْدَ أَوَّلِ الصَّدْمَةِو حَدَّثَنَاه يَحْيَى بْنُ حَبِيبٍ الْحَارِثِيُّ حَدَّثَنَا خَالِدٌ يَعْنِي ابْنَ الْحَارِثِ ح و حَدَّثَنَا عُقْبَةُ بْنُ مُكْرَمٍ الْعَمِّيُّ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ عَمْرٍو ح و حَدَّثَنِي أَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ قَالُوا جَمِيعًا حَدَّثَنَا شُعْبَةُ بِهَذَا الْإِسْنَادِ نَحْوَ حَدِيثِ عُثْمَانَ بْنِ عُمَرَ بِقِصَّتِهِ وَفِي حَدِيثِ عَبْدِ الصَّمَدِ مَرَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِامْرَأَةٍ عِنْدَ قَبْرٍ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Syu'bah] dari [Tsabit Al Bunani] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam mendatangi seorang wanita yang sedang menangisi bayinya yang telah meninggal. Lalu beliau bersabda kepadanya: \"Bertakwalah kepada Allah dan bersabarlah.\" Wanita itu menjawab, \"Anda tidak merasakan bagaimana pedihnya musibah yang aku derita ini.\" Setelah beliau berlalu, dikatakanlah kepada wanita itu bahwa yang berbicara kepadanya itu adalah Rasulullah shallallahu 'alaihi wasallam. Mendengar hal itu, wanita itu (setengah mati ketakutan), lalu dia pergi menemui Rasulullah shallallahu 'alaihi wasallam dan didapatinya rumah beliau tidak dikawal, lalu ia masuk dan berkata, \"Tadi aku tidak mengenal Anda wahai Rasulullah, (maafkanlah aku).\" Beliau bersabda: \"Sesungguhnya kesabaran yang sebenarnya adalah pada goncangan yang pertama.\" Dan telah menceritakannya kepada kami [Yahya bin Habib Al Haritsi] telah menceritakan kepada kami [Khalid bin Harits] -dalam jalur lain- dan telah menceritakan kepada kami [Uqbah bin Mukram Al Ammi] telah menceritakan kepada kami [Abdul Malik bin Amru] -dalam jalur lain- Dan telah menceritakan kepadaku [Ahmad bin Ibrahim Ad Dauraqi] telah menceritakan kepada kami [Abdush Shamad] mereka berkata, telah menceritakan kepada kami [Syu'bah] dengan Isnad ini dan serupa dengan hadits Utsman bin Umar serta kisahnya. Dan dalam hadits Abdush Shamad; Nabi shallallahu 'alaihi wasallam melewati seorang wanita di sisi kuburan."},"1454":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ قَتَادَةَ يُحَدِّثُ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَعَ��ْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ فِي قَبْرِهِ بِمَا نِيحَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] Telah menceritakan kepada kami [Syu'bah] ia berkata, saya mendengar [Qatadah] menceritakan dari [Sa'id bin Al Musayyab] dari [Ibnu Umar] dari [Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mayit itu akan disiksa di dalam kuburnya, lantara ratapan yang ditujukan atasnya.\""},"1455":{"ar":"و حَدَّثَنَاه مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَيِّتُ يُعَذَّبُ فِي قَبْرِهِ بِمَا نِيحَ عَلَيْهِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] dari [Sa'id] dari [Qatadah] dari [Sa'id bin Al Musayyab] dari [Ibnu Umar] dari [Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mayit itu akan disiksa di dalam kuburnya, lantara ratapan yang ditujukan atasnya.\""},"1456":{"ar":"و حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَعْمَشِ عَنْ أَبِي صَالِحٍ عَنْ ابْنِ عُمَرَ قَالَ لَمَّا طُعِنَ عُمَرُ أُغْمِيَ عَلَيْهِ فَصِيحَ عَلَيْهِ فَلَمَّا أَفَاقَ قَالَ أَمَا عَلِمْتُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ الْحَيِّ","id":"Telah menceritakan kepadaku [Ali bin Hujr As Sa'di] telah menceritakan kepada kami [Ali bin Mushir] dari [Al A'masy] dari [Abu Shalih] dari [Ibnu Umar] ia berkata; Ketika khalifah [Umar] ditikam orang, beliau jatuh pingsan dan orang-orang pun meratapinya. Setelah siuman, Umar berkata, \"Tidakkah kalian tahu bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: 'Sesungguhnya mayit itu benar-benar akan disiksa lantara tangisan mereka yang hidup.'\""},"1457":{"ar":"و حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شُعَيْبُ بْنُ صَفْوَانَ أَبُو يَحْيَى عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِي مُوسَى قَالَ لَمَّا أُصِيبَ عُمَرُ أَقْبَلَ صُهَيْبٌ مِنْ مَنْزِلِهِ حَتَّى دَخَلَ عَلَى عُمَرَ فَقَامَ بِحِيَالِهِ يَبْكِي فَقَالَ عُمَرُ عَلَامَ تَبْكِي أَعَلَيَّ تَبْكِي قَالَ إِي وَاللَّهِ لَعَلَيْكَ أَبْكِي يَا أَمِيرَ الْمُؤْمِنِينَ قَالَ وَاللَّهِ لَقَدْ عَلِمْتَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يُبْكَى عَلَيْهِ يُعَذَّبُقَالَ فَذَكَرْتُ ذَلِكَ لِمُوسَى بْنِ طَلْحَةَ فَقَالَ كَانَتْ عَائِشَةُ تَقُولُ إِنَّمَا كَانَ أُولَئِكَ الْيَهُودَ","id":"Telah menceritakan kepadaku [Ali bin Hujr] telah mengabarkan kepada kami [Syu'aib bin Shafwan Abu Yahya] dari [Abdul Malik bin Umair] dari [Abu Burdah Abu Musa] dari [Abu Musa] ia berkata; Ketika khalifah [Umar] dapat musibah (ditikam orang) Shuhaib datang ke rumahnya. Sesampainya disana, ia berdiri di dekat Umar sambil menangis. Maka Umar pun bertanya, \"Kenapa kamu menangis, apakah kamu menangisiku?\" Shuhaib menjawab, \"Ya, demi Allah, aku menangisi Anda wahai Amirul mukminin.\" Umar berkata, \"Demi Allah, aku ingat bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: 'Siapa yang ditangisi, maka ia akan disiksa.'\" Maka saya pun menuturkan hal itu kepada Musa bin Thalhah, ia pun berkata, \"Aisyah berkata; Bahwa hal itu hanya akan terjadi pada orang-orang Yahudi.\""},"1458":{"ar":"و حَدَّثَنِي عَمْرٌو النَّاقِدُ حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ أَنَّ عُمَرَ بْنَ الْخَطَّابِ لَمَّا طُعِنَ عَوَّلَتْ عَلَيْهِ حَفْصَةُ فَقَالَ يَا حَفْصَةُ أَمَاسَمِعْتِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْمُعَوَّلُ عَلَيْهِ يُعَذَّبُ وَعَوَّلَ عَلَيْهِ صُهَيْبٌ فَقَالَ عُمَرُ يَا صُهَيْبُ أَمَا عَلِمْتَ أَنَّ الْمُعَوَّلَ عَلَيْهِ يُعَذَّبُ","id":"Dan telah menceritakan kepadaku [Amru An Naqid] telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwa ketika [Umar] ditikam, maka Hafshah pun menangisinya dengan suara yang keras, maka seketika itu Umar berkata, \"Wahai Hafshah, tidakkah kamu mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Orang yang ditangisi, akan disiksa.'\" Kemudian Shuhaib pun ikut menangis dengan mengangkat suara, maka Umar berkata, \"Wahai Shuhaib, tidakkah kamu tahu bahwa orang yang ditangisi akan diadzab?\""},"1459":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ ابْنُ رَافِعٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي مُلَيْكَةَ قَالَتُوُفِّيَتْ ابْنَةٌ لِعُثْمَانَ بْنِ عَفَّانَ بِمَكَّةَ قَالَ فَجِئْنَا لِنَشْهَدَهَا قَالَ فَحَضَرَهَا ابْنُ عُمَرَ وَابْنُ عَبَّاسٍ قَالَ وَإِنِّي لَجَالِسٌ بَيْنَهُمَا قَالَ جَلَسْتُ إِلَى أَحَدِهِمَا ثُمَّ جَاءَ الْآخَرُ فَجَلَسَ إِلَى جَنْبِي فَقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ لِعَمْرِو بْنِ عُثْمَانَ وَهُوَ مُوَاجِهُهُ أَلَا تَنْهَى عَنْ الْبُكَاءِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِ فَقَالَ ابْنُ عَبَّاسٍ قَدْ كَانَ عُمَرُ يَقُولُ بَعْضَ ذَلِكَ ثُمَّ حَدَّثَ فَقَالَ صَدَرْتُ مَعَ عُمَرَ مِنْ مَكَّةَ حَتَّى إِذَا كُنَّا بِالْبَيْدَاءِ إِذَا هُوَ بِرَكْبٍ تَحْتَ ظِلِّ شَجَرَةٍ فَقَالَ اذْهَبْ فَانْظُرْ مَنْ هَؤُلَاءِ الرَّكْبُ فَنَظَرْتُ فَإِذَا هُوَ صُهَيْبٌ قَالَ فَأَخْبَرْتُهُ فَقَالَ ادْعُهُ لِي قَالَ فَرَجَعْتُ إِلَى صُهَيْبٍ فَقُلْتُ ارْتَحِلْ فَالْحَقْ أَمِيرَ الْمُؤْمِنِينَ فَلَمَّا أَنْ أُصِيبَ عُمَرُ دَخَلَ صُهَيْبٌ يَبْكِي يَقُولُ وَا أَخَاهْ وَا صَاحِبَاهْ فَقَالَ عُمَرُ يَا صُهَيْبُ أَتَبْكِي عَلَيَّ وَقَدْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمَيِّتَ يُعَذَّبُ بِبَعْضِ بُكَاءِ أَهْلِهِ عَلَيْهِ فَقَالَ ابْنُ عَبَّاسٍ فَلَمَّا مَاتَ عُمَرُ ذَكَرْتُ ذَلِكَ لِعَائِشَةَ فَقَالَتْ يَرْحَمُ اللَّهُ عُمَرَ لَا وَاللَّهِ مَا حَدَّثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُعَذِّبُ الْمُؤْمِنَ بِبُكَاءِ أَحَدٍ وَلَكِنْ قَالَ إِنَّ اللَّهَ يَزِيدُ الْكَافِرَ عَذَابًا بِبُكَاءِ أَهْلِهِ عَلَيْهِقَالَ وَقَالَتْ عَائِشَةُ حَسْبُكُمْ الْقُرْآنُ{ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }قَالَ وَقَالَ ابْنُ عَبَّاسٍ عِنْدَ ذَلِكَ وَاللَّهُ{ أَضْحَكَ وَأَبْكَى }قَالَ ابْنُ أَبِي مُلَيْكَةَ فَوَاللَّهِ مَا قَالَ ابْنُ عُمَرَ مِنْ شَيْءٍ و حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ بِشْرٍ حَدَّثَنَا سُفْيَانُ قَالَ عَمْرٌو عَنْ ابْنِ أَبِي مُلَيْكَةَ كُنَّا فِي جَنَازَةِ أُمِّ أَبَانَ بِنْتِ عُثْمَانَ وَسَاقَ الْحَدِيثَ وَلَمْ يَنُصَّ رَفْعَ الْحَدِيثِ عَنْ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا نَصَّهُ أَيُّوبُ وَابْنُ جُرَيْجٍ وَحَدِيثُهُمَا أَتَمُّ مِنْ حَدِيثِ عَمْرٍو","id":"Telah menceritakan kepada kami [Muhammad bin Rafi'] dan [Abdu bin Humaid] - [Ibnu Rafi'] berkata- telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Abdullah bin Abu Mulaikah] ia berkata; Ketika puteri Utsman bin 'Affan meninggal di Makkah, kami datang menjenguknya. Hadir juga ketika itu antara lain, Ibnu Umar dan Ibnu Abbas. Dan aku duduk di antara keduanya. Kemudian datanglah orang lain lalu ia duduk di sampingku. Kemudian [Abdullah bin Umar] bertanya kepada Amru bin Utsman yang duduk berhadapan dengan Abdullah, \"Kenapa Anda tidak melarang orang-orang yang menangis? Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah bersabda: 'Sesungguhnya mayit benar-benar akan disiksa lantara tangisan keluarganya atasnya.'\" Maka [Ibnu Abbas] pun menjawab, \"Memang [Umar] pernah berkata demikian.\" Kemudian Ibnu Abbas melanjutkan; Aku pernah datang dari Makkah bersama Umar, dan ketika kami sampai di Baida`, tiba-tiba kami bertemu dengan suatu rombongan kendaraan yang sedang berhenti di bawah naungan pohon. Umar berkata, \"Coba periksa siapakah pemimpin rombongan itu.\" Setelah aku lihat, ternyata pemimpin rombongan itu adalah Shuhaib. Lalu kuberitahukan kepada Umar. Umar memerintahkan, \"Panggillah ia kemari.\" Aku kembali menemui Shuhaib dan kuperintahkan kepadanya, \"Turun dan temuilah Amirul mukminin sekarangan juga.\" Ketika Umar mendapat musibah ditikam orang, Shuhaib datang sambil menangis dan berkata, \"Wahai saudaraku, wahai saudaraku…\" maka Umar pun berkata, \"Shuhaib, apakah kamu menangisiku? padahal Rasulullah shallallahu 'alaihi wasallam telah bersabda bahwa mayit itu akan disiksa karena ditangisi oleh keluarganya.\" [Ibnu Abbas] berkata, \"Ketika Umar telah meninggal dunia, maka hadits yang diceritakan Umar itu aku sampaikan kepada 'Aisyah. Maka [Aisyah] pun berkata, \"Semoga Allah merahmati Umar. Tidak, demi Allah, Rasulullah shallallahu 'alaihi wasallam tidak pernah mengatakan bahwa Allah menyiksa orang mukmin karena tangisan seseorang. Yang sebenarnya, beliau bersabda seperti ini; 'Sesungguhnya Allah menambah siksaan terhadap orang kafir, karena tangisan keluarganya atasnya.'\" Abdullah berkata; Selanjutnya Aisyah berkata; Cukuplah firman Allah ini sebagai dalil bagi kalian, \"Dan orang yang berdosa, tidak akan memikul dosa orang lain.\" Ibnu Abbas berkata, \"Kalau demikian Allah membuat kamu tertawa dan menangis.\" Ibnu Mulaikah berkata, \"Demi Allah, Ibnu Umar tidak berkata apa-apa (mendengar penjelasan 'Aisyah itu).\" Dan [Abdurrahman bin Bisyr] telah menceritakan kepada kami [Sufyan] telah berkata [Amru] dari [Ibnu Abu Mulaikah] ia berkata; Kami berkumpul pada jenazah Ummu Aban binti Utsman. Ia pun menuturkan hadits, namun ia tidak menyatakan marfu'nya hadits dari Ibnu Umar dari Nabi shallallahu 'alaihi wasallam sebagaimana yang dinyatakan Ayyub dan Ibnu Juraij. Dan kedua hadits mereka adalah lebih lengkap daripada haditsnya Amru."},"1460":{"ar":"و حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ حَدَّثَنِي عُمَرُ بْنُ مُحَمَّدٍ أَنَّ سَالِمًا حَدَّثَهُ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَيِّتَ يُعَذَّبُ بِبُكَاءِ الْحَيِّ","id":"Telah menceritakan kepadaku [Harmalah bin Yahya] telah menceritakan kepada kami [Abdullah bin Wahb] telah menceritakan kepadaku [Umar bin Muhammad] bahwa [Salim] telah menceritakannya dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya mayit itu akan disiksa karena tangisan mereka yang masih hidup.\""},"1461":{"ar":"و حَدَّثَنَا خَلَفُ بْنُ هِشَامٍ وَأَبُو الرَّبِيعِ الزَّهْرَانِيُّ جَمِيعًا عَنْ حَمَّادٍ قَالَ خَلَفٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ قَالَذُكِرَ عِنْدَ عَائِشَةَ قَوْلُ ابْنِ عُمَرَ الْمَيِّتُ يُعَذَّبُ بِبُكَاءِ أَهْلِهِ عَلَيْهِ فَقَالَتْ رَحِمَ اللَّهُ أَبَا عَبْدِ الرَّحْمَنِ سَمِعَ شَيْئًا فَلَمْ يَحْفَظْهُ إِنَّمَا مَرَّتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَنَازَةُ يَهُودِيٍّ وَهُمْ يَبْكُونَ عَلَيْهِ فَقَالَ أَنْتُمْ تَبْكُونَ وَإِنَّهُ لَيُعَذَّبُ","id":"Telah menceritakan kepada kami [Khalaf bin Hisyam] dan [Abu Rabi' Az Zahrani] semua dari [Hammad] - [Khalaf] berkata- telah menceritakan kepada kami [Hammad bin Zaid] dari [Hisyam bin Urwah] dari [bapaknya] ia berkata; Pernah dituturkan di sisi Aisyah tentang ungkapan Umar bahwa mayit itu akan disiksa lantaran tangisan keluarga atasnya, maka [Aisyah] pun berkata, \"Semoga Allah merahmati Abu Abdurrahman, ia telah mendengar (hadits Rasulullah shallallahu 'alaihi wasallam), tetapi ia belum menghafalnya (dengan baik). Peristiwanya begini; Suatu ketika lewat di hadapan Nabi shallallahu 'alaihi wasallam jenazah seorang Yahudi dan ditangisi keluarganya. Maka Nabi shallallahu 'alaihi wasallam bersabda: 'Kalian menangisinya, sementara ia benar-benar disiksa (karena tangisan kalian) '\""},"1462":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ فِيمَا قُرِئَ عَلَيْهِ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّهَا أَخْبَرَتْهُ أَنَّهَا سَمِعَتْ عَائِشَةَوَذُكِرَ لَهَا أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ يَقُولُ إِنَّ الْمَيِّتَ لَيُعَذَّبُ بِبُكَاءِ الْحَيِّ فَقَالَتْ عَائِشَةُ يَغْفِرُ اللَّهُ لِأَبِي عَبْدِ الرَّحْمَنِ أَمَا إِنَّهُ لَمْ يَكْذِبْ وَلَكِنَّهُ نَسِيَ أَوْ أَخْطَأَ إِنَّمَا مَرَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى يَهُودِيَّةٍ يُبْكَى عَلَيْهَا فَقَالَ إِنَّهُمْ لَيَبْكُونَ عَلَيْهَا وَإِنَّهَا لَتُعَذَّبُ فِي قَبْرِهَا","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] -terkait dengan hadits yang telah dibacakan kepadanya- dari [Abdullah bin Abu Bakar] dari [bapaknya] dari [Amrah binti Abdurrahman] bahwa ia telah mengabarkan kepadanya bahwa ia telah mendengar [Aisyah] dan telah dituturkan kepadanya bahwa Ibnu Umar berkata, \"Sesungguhnya mayit itu benar-benar akan disiksa lantaran tangisan mereka yang masih hidup.\" Maka Aisyah pun berkata, \"Semoga Allah mengampuni Abu Abdurrahman, sesungguhnya ia tidaklah berdusta, namun ia telah lupa atau salah. Peristiwa sebenarnya adalah; suatu ketika Rasulullah shallallahu 'alaihi wasallam melewati jenazah wanita Yahudi dan ditangisi, maka beliau pun bersabda: 'Mereka benar-benar menangisinya, dan mayit itu benar-benar akan disiksa di dalam kuburnya.'\""},"1463":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا وَكِيعٌ عَنْ سَعِيدِ بْنِ عُبَيْدٍ الطَّائِيِّ وَمُحَمَّدِ بْنِ قَيْسٍ عَنْ عَلِيِّ بْنِ رَبِيعَةَ قَالَ أَوَّلُ مَنْ نِيحَ عَلَيْهِ بِالْكُوفَةِ قَرَظَةُ بْنُ كَعْبٍ فَقَالَ الْمُغِيرَةُ بْنُ شُعْبَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ نِيحَ عَلَيْهِ فَإِنَّهُ يُعَذَّبُ بِمَا نِيحَ عَلَيْهِ يَوْمَ الْقِيَامَةِو حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ أَخْبَرَنَا مُحَمَّدُ بْنُ قَيْسٍ الْأَسْدِيُّ عَنْ عَلِيِّ بْنِ رَبِيعَةَ الْأَسْدِيِّ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ و حَدَّثَنَاه ابْنُ أَبِي عُمَرَ حَدَّثَنَا مَرْوَانُ يَعْنِي الْفَزَارِيَّ حَدَّثَنَا سَعِيدُ بْنُ عُبَيْدٍ الطَّائِيُّ عَنْ عَلِيِّ بْنِ رَبِيعَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Waki'] dari [Sa'id bin Ubaid Ath Tha`i] dan [Muhammad bin Qais] dari [Ali bin Rabi'ah] ia berkata; Orang yang pertama kali diratapi di Kufah adalah Qarazhah bin Ka'ab, maka [Al Mughirah bin Syu'bah] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang meratapi mayit, maka mayit akan disiksa pada hari kiamat karena ratapan itu.\" Dan telah menceritakan kepadaku [Ali bin Hujr As Sa'di] telah menceritakan kepada kami [Ali bin Mushir] telah mengabarkan kepada kami [Muhammad bin Qais Al Asdi] dari [Ali bin Rabi'ah Al Asdi] dari [Al Mughirah bin Syu'bah] dari Nabi shallallahu 'alaihi wasallam semisalnya. Dan telah menceritakannya kepada kami [Ibnu Abu Umar] telah menceritakan kepada kami [Marwan Al Fazari] telah menceritakan kepada kami [Sa'id bin Ubaid Ath Tha`i] dari [Ali bin Rabi'ah] dari [Al Mughirah bin Syu'bah] dari Nabi shallallahu 'alaihi wasallam semisalnya."},"1464":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ ح و حَدَّثَنِي إِسْحَقُ بْنُ مَنْصُورٍ وَاللَّفْظُ لَهُ أَخْبَرَنَا حَبَّانُ بْنُ هِلَالٍ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى أَنَّ زَيْدًا حَدَّثَهُ أَنَّ أَبَا سَلَّامٍ حَدَّثَهُ أَنَّ أَبَا مَالِكٍ الْأَشْعَرِيَّ حَدَّثَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَرْبَعٌ فِي أُمَّتِي مِنْ أَمْرِ الْجَاهِلِيَّةِ لَا يَتْرُكُونَهُنَّ الْفَخْرُ فِي الْأَحْسَابِ وَالطَّعْنُ فِي الْأَنْسَابِ وَالْاسْتِسْقَاءُ بِالنُّجُومِ وَالنِّيَاحَةُ وَقَالَ النَّائِحَةُ إِذَا لَمْ تَتُبْ قَبْلَ مَوْتِهَا تُقَامُ يَوْمَ الْقِيَامَةِ وَعَلَيْهَا سِرْبَالٌ مِنْ قَطِرَانٍ وَدِرْعٌ مِنْ جَرَبٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Aban bin Yazid] -dalam jalur lain- Dan telah menceritakan kepadaku [Ishaq bin Manshur] -dan lafazh juga miliknya- telah mengabarkan kepada kami [Habban bin Hilal] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya] bahwa [Zaid] telah menceritakan kepadanya bawah [Abu Sallam] telah menceritakan kepadanya bahwa [Abu Malik Al Asy'ari] telah menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Ada empat perkara jahiliyah yang masih melekat pada umatku dan mereka belum meninggalkannya: Membanggakan kedudukan, mencela nasab (garis keturunan), meminta hujan dengan bintang-bintang, dan niyahah (meratapi mayit).\" Dan beliau bersabda: \"Orang yang meratapi mayit, jika ia belum bertaubat sebelum ajalnya tiba maka pada hari kiamat ia akan dibangkitkan dengan memakai baju panjang yang berwarna hitam dan memakai tameng dari pedang yang sudah karatan.\""},"1465":{"ar":"و حَدَّثَنَا ابْنُ الْمُثَنَّى وَابْنُ أَبِي عُمَرَ قَالَ ابْنُ الْمُثَنَّى حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ يَقُولُ أَخْبَرَتْنِي عَمْرَةُ أَنَّهَا سَمِعَتْ عَائِشَةَ تَقُولُلَمَّا جَاءَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَتْلُ ابْنِ حَارِثَةَ وَجَعْفَرِ بْنِ أَبِي طَالِبٍ وَعَبْدِ اللَّهِ بْنِ رَوَاحَةَ جَلَسَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْرَفُ فِيهِ الْحُزْنُ قَالَتْ وَأَنَا أَنْظُرُ مِنْ صَائِرِ الْبَابِ شَقِّ الْبَابِ فَأَتَاهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ نِسَاءَ جَعْفَرٍ وَذَكَرَ بُكَاءَهُنَّ فَأَمَرَهُ أَنْ يَذْهَبَ فَيَنْهَاهُنَّ فَذَهَبَ فَأَتَاهُ فَذَكَرَ أَنَّهُنَّ لَمْ يُطِعْنَهُ فَأَمَرَهُ الثَّانِيَةَ أَنْ يَذْهَبَ فَيَنْهَاهُنَّ فَذَهَبَ ثُمَّ أَتَاهُ فَقَالَ وَاللَّهِ لَقَدْ غَلَبْنَنَا يَا رَسُولَ اللَّهِ قَالَتْ فَزَعَمَتْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اذْهَبْ فَاحْثُ فِي أَفْوَاهِهِنَّ مِنْ التُّرَابِ قَالَتْ عَائِشَةُ فَقُلْتُ أَرْغَمَ اللَّهُ أَنْفَكَ وَاللَّهِ مَا تَفْعَلُ مَا أَمَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا تَرَكْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْعَنَاءِو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ نُمَيْرٍ ح و حَدَّثَنِي أَبُو الطَّاهِرِ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ مُعَاوِيَةَ بْنِ صَالِحٍ ح و حَدَّثَنِي أَحْمَدُ بْنُ إِبْرَاهِيمَ الدَّوْرَقِيُّ حَدَّثَنَا عَبْدُ الصَّمَدِ حَدَّثَنَا عَبْدُ الْعَزِيزِ يَعْنِي ابْنَ مُسْلِمٍ كُلُّهُمْ عَنْ يَحْيَى بْنِ سَعِيدٍ بِهَذَا الْإِسْنَادِ نَحْوَهُ وَفِي حَدِيثِ عَبْدِ الْعَزِيزِ وَمَا تَرَكْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْعِيِّ","id":"Telah menceritakan kepada kami [Ibnul Mutsanna] dan [Ibnu Abu Umar] - [Ibnul Mutsanna] berkata- telah menceritakan kepada kami [Abdul Wahhab] ia berkata, saya mendengar [Yahya bin Sa'id] berkata, telah mengabarkan kepadaku [Amrah] bahwa ia telah mendengar [Aisyah] berkata; Ketika berita mengenai tewasnya Ibnu Haritsah dan Ja'far bin Abi Thalib, dan Abdullah bin Rawahah sampai kepada Rasulullah shallallahu 'alaihi wasallam, beliau duduk dan terlihat tanda kesedihan di wajah beliau. Kata 'Aisyah selanjutnya; Aku melihat dari celah-celah pintu, seorang laki-laki datang kepada beliau seraya berkata, \"Wahai Rasulullah, isteri Ja'far menangis.\" Rasulullah shallallahu 'alaihi wasallam menyuruh orang itu agar mendiamkannya. Lalu orang itu pergi. Tidak berapa lama kemudian orang itu datang kembali dan mengatakan kepada beliau, bahwa mereka tidak mau didiamkan. Nabi shallallahu 'alaihi wasallam menyuruhnya pula kembali, namun tidak berapa lama, ia kembali lagi dan berkata, \"Demi Allah, mereka tidak mau didiamkan dan tidak mengindahkanku wahai Rasulullah.\" Aisyah mengira bahwa Rasulullah shallallahu 'alaihi wasallam menyuruh orang itu pergi dengan mengatakan: \"Pergilah! Dan sumpalkan tanah ke dalam mulutnya!\" Dan Aisyah pun berkata, \"Celaka kamu, Demi Allah, kamu belum melaksanakan dengan baik apa yang diperintahkan Rasulullah shallallahu 'alaihi wasallam kepadamu, sehingga kamu biarkan Rasulullah shallallahu 'alaihi wasallam dalam kesulitan.\" Dan telah menceritakannya kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdullah bin Numair] -dalam jalur lain- Dan telah menceritakan kepadaku [Abu Thahir] telah mengabarkan kepada kami [Abdullah bin Wahb] dari [Mu'awiyah bin Shalih] -dalam jalur lain- telah menceritakan kepadaku [Ahmad bin Ibrahim Ad Dauraqi] telah menceritakan kepada kami [Abdush Shamad] Telah menceritakan kepada kami [Abdul Aziz bin Muslim] dari [Yahya bin Sa'id] dengan isnad ini semisalnya. Dan di dalam hadits Abdul Aziz; \"Dan kamu telah meninggalkan keletihan bagi Rasulullah shallallahu 'alaihi wasallam.\""},"1466":{"ar":"حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادٌ حَدَّثَنَا أَيُّوبُ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَخَذَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَعَ الْبَيْعَةِ أَلَّا نَنُوحَ فَمَا وَفَتْ مِنَّا امْرَأَةٌ إِلَّا خَمْسٌ أُمُّ سُلَيْمٍ وَأُمُّ الْعَلَاءِ وَابْنَةُ أَبِي سَبْرَةَ امْرَأَةُ مُعَاذٍ أَوْ ابْنَةُ أَبِي سَبْرَةَ وَامْرَأَةُ مُعَاذٍ","id":"Telah menceritakan kepadaku [Abu Rabi' Az Zahrani] telah menceritakan kepada kami [Hammad] telah menceritakan kepada kami [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah membai'at kami untuk tidak melakukan Niyahah (meratapi mayit). Maka tidak seorang wanita pun dari kami yang wafat (lalu kami meratapinya) kecuali lima orang, yaitu Ummu Sulaim, Ummul 'Ala, putri Abu Sabrah isteri daripada Mu'adz atau anak perempuan Abu Sabrah dan isteri Mu'adz.\""},"1467":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا أَسْبَاطٌ حَدَّثَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْأَخَذَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْبَيْعَةِ أَلَّا تَنُحْنَ فَمَا وَفَتْ مِنَّا غَيْرُ خَمْسٍ مِنْهُنَّ أُمُّ سُلَيْمٍ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Asbath] telah menceritakan kepada kami [Hisyam] dari [Hafshah] dari [Ummu 'Athiyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah membai'at kami untuk tidak melakukan Niyahah (meratapi mayit). Maka tidak seorang wanita pun dari kami yang wafat (lalu kami meratapinya) kecuali lima orang, termasuk di antaranya adalah Ummu Sulaim.\""},"1468":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَإِسْحَقُ بْنُ إِبْرَاهِيمَ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ قَالَ زُهَيْرٌ حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ حَدَّثَنَا عَاصِمٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ يُبَايِعْنَكَ عَلَى أَنْ لَا يُشْرِكْنَ بِاللَّهِ شَيْئًا }{ وَلَا يَعْصِينَكَ فِي مَعْرُوفٍ }قَالَتْ كَانَ مِنْهُ النِّيَاحَةُ قَالَتْ فَقُلْتُ يَا رَسُولَ اللَّهِ إِلَّا آلَ فُلَانٍ فَإِنَّهُمْ كَانُوا أَسْعَدُونِي فِي الْجَاهِلِيَّةِ فَلَا بُدَّ لِي مِنْ أَنْ أُسْعِدَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا آلَ فُلَانٍ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] dan [Ishaq bin Ibrahim] semuanya dari [Abu Mu'awiyah] - [Zuhair] berkata- Telah menceritakan kepada kami [Muhammad bin Khazim] telah menceritakan kepada kami ['Ashim] dari [Hafshah] dari [Ummu 'Athiyyah] ia berkata; Ketika turun ayat ini, \"(Apabila datang kepadamu perempuan-perempuan yang beriman) untuk mengadakan janji setia, bahwa mereka tiada akan menyekutukan Allah, … dan tidak akan mendurhakaimu dalam urusan yang baik.\" Ummu 'Athyiyyah berkata; Termasuk di antaranya adalah An Niyahah (meratapi mayit). Saya berkata, \" Kecuali keluarga si Fulan, sesungguhnya mereka mengajakku untuk melakukan niyahah bersama mereka pada waktu jahiliyah, hingga saya terpaksa menyertai mereka melakukannya.\" Beliau bersabda: \"Kecuali keluarga si Fulan.\""},"1469":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَ��َا ابْنُ عُلَيَّةَ أَخْبَرَنَا أَيُّوبُ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ قَالَتْ أُمُّ عَطِيَّةَكُنَّا نُنْهَى عَنْ اتِّبَاعِ الْجَنَائِزِ وَلَمْ يُعْزَمْ عَلَيْنَا","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu 'Ulayyah] telah mengabarkan kepada kami [Ayyub] dari [Muhammad bin Sirin] ia berkata; [Ummu 'Athiyyah] berkata, \"Kami dilarang untuk turut mengiring jenazah, tetapi (larangn itu) tidak begitu ditekankan atas kami.\""},"1470":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا أَبُو أُسَامَةَ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ كِلَاهُمَا عَنْ هِشَامٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْنُهِينَا عَنْ اتِّبَاعِ الْجَنَائِزِ وَلَمْ يُعْزَمْ عَلَيْنَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abu Usamah] -dalam jalur lain- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus] keduanya dari [Hisyam] dari [Hafshah] dari [Ummu 'Athiyyah] ia berkata; \"Kami dilarang untuk turut mengiring jenazah, tetapi (larangan itu) tidak begitu ditekankan atas kami.\""},"1471":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْدَخَلَ عَلَيْنَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ ابْنَتَهُ فَقَالَ اغْسِلْنَهَا ثَلَاثًا أَوْ خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكَ إِنْ رَأَيْتُنَّ ذَلِكَ بِمَاءٍ وَسِدْرٍ وَاجْعَلْنَ فِي الْآخِرَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا فَرَغْتُنَّ فَآذِنَّنِي فَلَمَّا فَرَغْنَا آذَنَّاهُ فَأَلْقَى إِلَيْنَا حَقْوَهُ فَقَالَ أَشْعِرْنَهَا إِيَّاهُو حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْ مَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ ح و حَدَّثَنَا أَبُو الرَّبِيعِ الزَّهْرَانِيُّ وَقُتَيْبَةُ بْنُ سَعِيدٍ قَالَا حَدَّثَنَا حَمَّادٌ ح و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ كُلُّهُمْ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ قَالَتْ تُوُفِّيَتْ إِحْدَى بَنَاتِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي حَدِيثِ ابْنِ عُلَيَّةَ قَالَتْ أَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ ابْنَتَهُ وَفِي حَدِيثِ مَالِكٍ قَالَتْ دَخَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَتْ ابْنَتُهُ بِمِثْلِ حَدِيثِ يَزِيدَ بْنِ زُرَيْعٍ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ أُمِّ عَطِيَّةَ و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ بِنَحْوِهِ غَيْرَ أَنَّهُ قَالَ ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا أَوْ أَكْثَرَ مِنْ ذَلِكِ إِنْ رَأَيْتُنَّ ذَلِكِ فَقَالَتْ حَفْصَةُ عَنْ أُمِّ عَطِيَّةَ وَجَعَلْنَا رَأْسَهَا ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yazid bin Zurai'] dari [Ayyub] dari [Muhammad bin Sirin] dari [Ummu 'Athiyyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam masuk menemui kami yang sedang memandikan putrinya. Kemudian beliau pun bersabda: \"Mandikanlah ia sebanyak tiga atau lima kali, atau pun lebih dari itu. Setelah itu, gunakanlah adukan air dan daun bidara. Sedangkan untuk siraman terakhir, gunakanlah kapur barus, atau sejenis kapur barus. Setelah selesai, beritahukanlah padaku.\" Setelah selesai memandikan, kami pun memberitahukan kepada beliau, dan beliau langsung memberikan kainnya pada kami dan bersabda: \"Kenakanlah pada bagian bawah badannya.\" Dan telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Yazid bin Zurai'] dari [Ayyub] dari [Muhammad bin Sirin] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah] ia berkata, \"Kami memintal rambutnya menjadi tiga.\" Dan telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] -dalam jalur lain- Telah menceritakan kepada kami [Abu Rabi' Az Zahrani] dan [Qutaibah bin Sa'id] keduanya berkata, telah menceritakan kepada kami [Hammad] -dalam jalur lain- Dan telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu Ulayyah] semuanya dari [Ayyub] dari [Muhammad] dari [Ummu 'Athiyyah] ia berkata; \"Salah seorang putri Rasulullah shallallahu 'alaihi wasallam meninggal.\" Sementara di dalam hadits Ibnu Ulayyah; Rasulullah shallallahu 'alaihi wasallam datang menemui kami yang sedang memandikan mayit putrinya. Sedangkan di dalam haditsnya Malik; Rasulullah shallallahu 'alaihi wasallam masuk menemui kami saat anak putrinya meninggal. Serupa dengan hadits Yazid bin Zurai' dari Ayyub dari Muhamamd dari Ummu 'Atyiyyah. Dan menceritakan kepada kami [Qutaibah bin Sa'id] menceritakan kepada kami [Hammad] dari [Ayyub] dari [Hafshah] dari [Ummu Athiyyah] dengan hadits yang semisal, hanyasaja ia mengatakan 'tiga kali atau lima kali atau tujuh kali atau lebih banyak dari itu. Maka Hafshah berkata dari Ummu 'Athiyah, \"Dan kami memintal rambutnya menjadi tiga.\""},"1472":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ وَأَخْبَرَنَا أَيُّوبُ قَالَ وَقَالَتْ حَفْصَةُ عَنْ أُمِّ عَطِيَّةَ قَالَتْاغْسِلْنَهَا وِتْرًا ثَلَاثًا أَوْ خَمْسًا أَوْ سَبْعًا قَالَ وَقَالَتْ أُمُّ عَطِيَّةَ مَشَطْنَاهَا ثَلَاثَةَ قُرُونٍ","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] telah menceritakan kepada kami [Ibnu Ulayyah] dan telah mengabarkan kepada kami [Ayyub] ia berkata, dan telah berkata [Hafshah] dari [Ummu 'Athiyyah] ia berkata; \"Mandikanlah ia (puteri Rasulullah shallallahu 'alaihi wasallam) dengan bilangan ganjil, yakni tiga, lima atau tujuh kali.\" Ummu 'Atyhiyyah juga berkata, \"Dan kami memintal rambutnya menjadi tiga pintalan.\""},"1473":{"ar":"حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ جَمِيعًا عَنْ أَبِي مُعَاوِيَةَ قَالَ عَمْرٌو حَدَّثَنَا مُحَمَّدُ بْنُ خَازِمٍ أَبُو مُعَاوِيَةَ حَدَّثَنَا عَاصِمٌ الْأَحْوَلُ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْلَمَّا مَاتَتْ زَيْنَبُ بِنْتُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اغْسِلْنَهَا وِتْرًا ثَلَاثًا أَوْ خَمْسًا وَاجْعَلْنَ فِي الْخَامِسَةِ كَافُورًا أَوْ شَيْئًا مِنْ كَافُورٍ فَإِذَا غَسَلْتُنَّهَا فَأَعْلِمْنَنِي قَالَتْ فَأَعْلَمْنَاهُ فَأَعْطَانَا حَقْوَهُ وَقَالَ أَشْعِرْنَهَا إِيَّاهُو حَدَّثَنَا عَمْرٌو النَّاقِدُ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامُ بْنُ حَسَّانَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ قَالَتْ أَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَغْسِلُ إِحْدَى بَنَاتِهِ فَقَالَ اغْسِلْنَهَا وِتْرًا خَمْسًا أَوْ أَكْثَرَ مِنْ ذَلِكِ بِنَحْوِ حَدِيثِ أَيُّوبَ وَعَاصِمٍ وَقَالَ فِي الْحَدِيثِ قَالَتْ فَضَفَرْنَا شَعْرَهَا ثَلَاثَةَ أَثْلَاثٍ قَرْنَيْهَا وَنَاصِيَتَهَا","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Amru An Naqid] semuanya dari [Abu Mu'awiyah] - [Amru] berkata- Telah menceritakan kepada kami [Muhammad bin Khazim Abu Mu'awiyah] Telah menceritakan kepada kami [Ashim Al Ahwal] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah] ia berkata; Ketika Zainad binti Rasulullah shallallahu 'alaihi wasallam wafat, Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami, \"Mandikanlah ia dengan bilangan ganjil, tiga, lima atau tujuh. Dan pada bilangan ke lima, campurkanlah dengan kapur barus atau sesuatu dari jenis kapur barus. Dan jika kalian telah usai memandikannya, maka beritahukanlah padaku.\" Ummu 'Athiyyah berkata, \"Setelah itu, kami memberitahukan kepada beliau, sehingga beliau pun memberikan kainnya dan beliau bersabda: 'Kenakan padanya.'\" Dan telah menceritakan kepada kami [Amru An Naqid] telah menceritakan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam bin Hassan] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam menemui kami, sementara kami sedang memandikan salah seorang putinya. Beliau bersabda: \"Mandikanlah ia dengan bilangan yang ganjil, lima atau lebih dari itu.\" yakni serupa dengan hadits Ayyub dan 'Ashim. Kemudian di dalam hadits ia mengatakan; \"Lalu kami memintal rambutnya dengan tiga pintalan, yakni pada kedua tanduknya dan satu pada ubun-ubunnya.\""},"1474":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ عَنْ خَالِدٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَيْثُ أَمَرَهَا أَنْ تَغْسِلَ ابْنَتَهُ قَالَ لَهَا ابْدَأْنَ بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim] dari [Khalid] dari [Hafshah binti Sirin] dari [Ummu 'Athiyyah] bahwa ketika Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk memandikan jenazah putrinya, beliau bersabda: \"Mandikanlah mulai dari sebelah kanannya dan (dahulukan) anggota wudlunya.\""},"1475":{"ar":"حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَعَمْرٌو النَّاقِدُ كُلُّهُمْ عَنْ ابْنِ عُلَيَّةَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ عَنْ خَالِدٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُنَّ فِي غَسْلِ ابْنَتِهِ ابْدَأْنَ بِمَيَامِنِهَا وَمَوَاضِعِ الْوُضُوءِ مِنْهَا","id":"Telah menceritakan kepada kami [Yahya bin Ayyub] dan [Abu Bakar bin Abu Syaibah] dan [Amru An Naqid] semuanya dari [Ibnu Ulayyah] - [Abu Bakr] berkata- telah menceritakan kepada kami [Isma'il bin Ulayyah] dari [Khalid] dari [Hafshah] dari [Ummu 'Athiyyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda kepada mereka (ketika hendak memandikan jenazah putrinya): \"Mulailah dari sebelah kanannya dan (dahulukanlah) anggota wudlunya.\""},"1476":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى التَّمِيمِيُّ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِيَحْيَى قَالَ يَحْيَى أَخْبَرَنَا وَقَالَ الْآخَرُونَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ خَبَّابِ بْنِ الْأَرَتِّ قَالَهَاجَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَبِيلِ اللَّهِ نَبْتَغِي وَجْهَ اللَّهِ فَوَجَبَ أَجْرُنَا عَلَى اللَّهِ فَمِنَّا مَنْ مَضَى لَمْ يَأْكُلْ مِنْ أَجْرِهِ شَيْئًا مِنْهُمْ مُصْعَبُ بْنُ عُمَيْرٍ قُتِلَ يَوْمَ أُحُدٍ فَلَمْ يُوجَدْ لَهُ شَيْءٌ يُكَفَّنُ فِيهِ إِلَّا نَمِرَةٌ فَكُنَّا إِذَا وَضَعْنَاهَا عَلَى رَأْسِهِ خَرَجَتْ رِجْلَاهُ وَإِذَا وَضَعْنَاهَا عَلَى رِجْلَيْهِ خَرَجَ رَأْسُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَعُوهَا مِمَّا يَلِي رَأْسَهُ وَاجْعَلُوا عَلَى رِجْلَيْهِ الْإِذْخِرَ وَمِنَّا مَنْ أَيْنَعَتْ لَهُ ثَمَرَتُهُ فَهْوَ يَهْدِبُهَاو حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عِيسَى بْنُ يُونُسَ ح و حَدَّثَنَا مِنْجَابُ بْنُ الْحَارِثِ التَّمِيمِيُّ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَابْنُ أَبِي عُمَرَ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ عَنْ الْأَعْمَشِ بِهَذَا الْإِسْنَادِ نَحْوَهُ","id":"Telah menceritakan kepada kami [Yahya bin Yahya At Tamimi] dan [Abu Bakar bin Abu Syaibah] dan [Muhammad bin Abdullah bin Numair] dan [Abu Kuraib] -lafazhnya milik Yahya- Yahya berkata, telah mengabarkan kepada kami -sementara yang lain berkata- Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Khabbab bin Al Arat] ia berkata; Kami berhijrah di jalan Allah bersama Rasulullah shallallahu 'alaihi wasallam hanya untuk menggapai wajah Allah, maka Allah akan memberikan ganjarannya kepada kami (termasuk di antara adalah harta ghanimah). Namun di antara kami ada yang belum pernah mencicipi ganjarannya sedikitpun, salah satunya adalah Mush'ab bin Umair, karena ia terbunuh pada saat perang Uhud. Saat itu, tidak ada sesuatu pun untuk mengkafaninya kecuali sehelai kain burdah, yang apabila kami letakkan di atas kepalanya, maka kedua kakinya akan tampak, namun jika kami meletakkannya di atas kedua kakinya, maka kepalanya akan tampak. Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Letakkanlah tepat di bawah lehernya, dan letakkan Idzkhir (sejenis tumbuh-tumbuhan) di atas kedua kakinya.\" Maka di antara kami ada yang buah-buahannya telah masak dan ia memetiknya. Dan Telah menceritakan kepada kami [Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] -dalam jalur lain- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Isa bin Yunus] -dalam jalur lain- Dan telah menceritakan kepada kami [Minjab bin Harits At Tamimi] telah mengabarkan kepada kami [Ali bin Mushir] -dalam jalur lain- dan Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Ibnu Abu Umar] semuanya dari [Ibnu Uyainah] dari [Al A'masy] dengan isnad ini semisalnya."},"1477":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَأَبُو كُرَيْبٍ وَاللَّفْظُ لِيَحْيَى قَالَ يَحْيَى أَخْبَرَنَا وَقَالَ الْآخَرَانِ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُفِّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثَةِ أَثْوَابٍ بِيضٍ سَحُولِيَّةٍ مِنْ كُرْسُفٍ لَيْسَ فِيهَا قَمِيصٌ وَلَا عِمَامَةٌ أَمَّا الْحُلَّةُ فَإِنَّمَا شُبِّهَ عَلَى النَّاسِ فِيهَا أَنَّهَا اشْتُرِيَتْ لَهُ لِيُكَفَّنَ فِيهَا فَتُرِكَتْ الْحُلَّةُ وَكُفِّنَ فِي ثَلَاثَةِ أَثْوَابٍ بِيضٍ سَحُولِيَّةٍ فَأَخَذَهَا عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ فَقَالَ لَأَحْبِسَنَّهَا حَتَّى أُكَفِّنَ فِيهَا نَفْسِي ثُمَّ قَالَ لَوْ رَضِيَهَا اللَّهُ عَزَّ وَجَلَّ لِنَبِيِّهِ لَكَفَّنَهُ فِيهَا فَبَاعَهَا وَتَصَدَّقَ بِثَمَنِهَا","id":"Telah menceritakan kepada kami [Yahya bin Yahya] dan [Abu Bakar bin Abu Syaibah] dan [Abu Kuraib] -sedangkan lafazhnya dari Yahya- [Yahya] berkata, telah mengabarkan kepada kami -sementara dua orang yang lain berkata- Telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam dikafani dengan tiga helai kain berwarna putih, lembut dan terbuat dari kursuf (katun), tidak ada baju di dalamnya dan tidak juga serban. Sedangkan tentang Al Hullah (kain dari Yaman) membengingkan para sahabat, padahal telah dibeli untuk digunakan sebagai kain kafan beliau, maka hullah itu pun tidak digunakan. Beliau dikafankan dengan tiga helai kain putih yang lembut. Kemudian Abdullah bin Abu Bakar mengambil Hullah tersebut dan berkata, \"Aku akan menyimpannya hingga aku mengkafani diriku dengan kain ini.\" kemudian ia berkata lagi, \"Jika Allah meridlai Nabi-Nya, tentu beliau akan dikafani dengan kain ini.\" Akhirnya, ia pun menjualnya dan menyedekahkan uangnya."},"1478":{"ar":"و حَدَّثَنِي عَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْأُدْرِجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حُلَّةٍ يَمَنِيَّةٍ كَانَتْ لِعَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ ثُمَّ نُزِعَتْ عَنْهُ وَكُفِّنَ فِي ثَلَاثَةِ أَثْوَابٍ سُحُولٍ يَمَانِيَةٍ لَيْسَ فِيهَا عِمَامَةٌ وَلَا قَمِيصٌ فَرَفَعَ عَبْدُ اللَّهِ الْحُلَّةَ فَقَالَ أُكَفَّنُ فِيهَا ثُمَّ قَالَ لَمْ يُكَفَّنْ فِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُكَفَّنُ فِيهَا فَتَصَدَّقَ بِهَاو حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ وَابْنُ عُيَيْنَةَ وَابْنُ إِدْرِيسَ وَعَبْدَةُ وَوَكِيعٌ ح و حَدَّثَنَاه يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ كُلُّهُمْ عَنْ هِشَامٍ بِهَذَا الْإِسْنَادِ وَلَيْسَ فِي حَدِيثِهِمْ قِصَّةُ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ","id":"Telah menceritakan kepadaku [Ali bin Hujr As Sa'di] telah mengabarkan kepada kami [Ali bin Mushir] Telah menceritakan kepada kami [Hisyam bin Urwah] dari [bapaknya] dari [Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam dimasukkan ke dalam Hullah Yamaniyyah (kain pakaian dari Yaman) milik Abdullah bin Abu Bakr. Kemudian kain itu dilepaskan darinya, lalu beliau dikafani dengan tiga helai kain putih yang terbuat dari kapas Yamani dan di dalamnya tidak ada surban, tidak pula baju. Maka Abdullah pun mengangkat Hullah Yamaniyyah itu seraya berkata, \"Aku ingin mengkafani diriku dengannya, \" Kemudian ia berkata, \"Rasulullah shallallahu 'alaihi wasallam saja tidak dikafani dengannya, pantaskah diriku akan dikafani dengannya?.\" Maka ia pun menyedekahkannya. Dan telah menceritakannya kepada kami [Abu Bakar bin Abu Syaibah] Telah menceritakan kepada kami [Hafsh bin Ghiyats] dan [Ibnu Uyainah] dan [Ibnu Idris] dan [Abdah] dan [Waki'] -dalam jalur lain- Dan telah menceritakannya kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Abdul Aziz bin Muhammad] semuanya dari [Hisyam] dengan isnad ini, dan di dalam hadits mereka tidak tercantum kisah Abdullah bin Abu Bakar."},"1479":{"ar":"و حَدَّثَنِي ابْنُ أَبِي عُمَرَ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ يَزِيدَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَأَنَّهُ قَالَ سَأَلْتُ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهَا فِي كَمْ كُفِّنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ فِي ثَلَاثَةِ أَثْوَابٍ سَحُولِيَّةٍ","id":"Telah menceritakan kepadaku [Ibnu Abu Umar] telah menceritakan kepada kami [Abdul Aziz] dari [Yazid] dari [Muhammad bin Ibrahim] dari [Abu Salamah] bahwa ia berkata; Saya bertanya kepada [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, saya berkata kepadanya, \"Rasulullah shallallahu 'alaihi wasallam dikafani dengan berapa helai kain?\" Aisyah menjawab, \"(Beliau dikafani) dengan tiga helai kain putih.\""},"1480":{"ar":"و حَدَّثَنَا زُهَيْرُ بْنُ حَرْبٍ وَحَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالَ عَبْدٌ أَخْبَرَنِي و قَالَ الْآخَرَانِ حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّ عَائِشَةَ أُمَّ الْمُؤْمِنِينَ قَالَتْسُجِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ مَاتَ بِثَوْبِ حِبَرَةٍو حَدَّثَنَاه إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ قَالَ أَخْبَرَنَا مَعْمَرٌ ح و حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ الدَّارِمِيُّ أَخْبَرَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ سَوَاءً","id":"Telah menceritakan kepada kami [Zuhair bin Harb] dan [Hasan Al Hulwani] dan [Abdu bin Humaid] -Abdu berkata- telah mengabarkan kepadaku -dan dua orang yang lain berkata- telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] bahwa [Abu Salamah bin Abdurrahman] telah mengabarkan kepadanya, bahwa [Aisyah] Ummul Mukminin berkata, \"Saat meninggal, Rasulullah shallallahu 'alaihi wasallam ditutupi dengan kain Hibarah (yang terbuat dari kapas).\" Dan telah menceritakannya kepada kami [Ishaq bin Ibrahim] dan [Abdu bin Humaid] keduanya berkata, telah mengabarkan kepada kami [Abdurrazaq] ia berkata, telah mengabarkan kepada kami [Ma'mar] -dalam jalur lain- Dan telah menceritakan kepada kami [Abdullah bin Abdurrahman Ad Darimi] telah mengabarkan kepada kami [Abul Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dengan isnad ini, dan dengan hadits yang serupa."},"1481":{"ar":"حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ وَحَجَّاجُ بْنُ الشَّاعِرِ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِ أَنَّهُ سَمِعَ جَابِرَ بْنَ عَبْدِ اللَّهِ يُحَدِّثُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَطَبَ يَوْمًا فَذَكَرَ رَجُلًا مِنْ أَصْحَابِهِ قُبِضَ فَكُفِّنَ فِي كَفَنٍ غَيْرِ طَائِلٍ وَقُبِرَ لَيْلًا فَزَجَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُقْبَرَ الرَّجُلُ بِاللَّيْلِ حَتَّى يُصَلَّى عَلَيْهِ إِلَّا أَنْ يُضْطَرَّ إِنْسَانٌ إِلَى ذَلِكَ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا كَفَّنَ أَحَدُكُمْ أَخَاهُ فَلْيُحَسِّنْ كَفَنَهُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] dan [Hajjaj bin Asy Sya'ir] keduanya berkata, telah menceritakan kepada kami [Hajjaj bin Muhammad] ia berkata, [Ibnu Juraij] berkata, telah mengabarkan kepadaku [Abu Zubair] bahwa ia mendengar [Jabir bin Abdullah] menceritakan bahwa pada suatu hari Nabi shallallahu 'alaihi wasallam berkhutbah lalu menyebutkan kisah tentang salah seorang sahabatnya yang meninggal dan dikafani dengan kain yang tidak menutupi seluruh badannya, kemudian dimakamkan di malam hari. Rasulullah shallallahu 'alaihi wasallam melarang untuk menguburkannya di malam hari sampai dishalatkan, kecuali jika keadaannya sangat terpaksa, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jika salah seorang dari kalian mengkafani saudaranya, maka hendaknya ia memperbagus kafannya.\""},"1482":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ جَمِيعًا عَنْ ابْنِ عُيَيْنَةَ قَالَ أَبُو بَكْرٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَسْرِعُوا بِالْجَنَازَةِ فَإِنْ تَكُ صَالِحَةً فَخَيْرٌ لَعَلَّهُ قَالَ تُقَدِّمُونَهَا عَلَيْهِ وَإِنْ تَكُنْ غَيْرَ ذَلِكَ فَشَرٌّ تَضَعُونَهُ عَنْ رِقَابِكُمْو حَدَّثَنِي مُحَمَّدُ بْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ جَمِيعًا عَنْ عَبْدِ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ ح و حَدَّثَنَا يَحْيَى بْنُ حَبِيبٍ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي حَفْصَةَ كِلَاهُمَا عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَيْرَ أَنَّ فِي حَدِيثِ مَعْمَرٍ قَالَ لَا أَعْلَمُهُ إِلَّا رَفَعَ الْحَدِيثَ","id":"Telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] semuanya dari [Ibnu Uyainah] - [Abu Bakr] berkata- telah menceritakan kepada kami [Sufyan bin Uyainah] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Segerakanlah penguburan jenazah, karena jika ia adalah seorang yang shalih (mungkin ia akan berkata) segeralah mengantarkannya pada kebaikan. Tetapi, jika ia tidak termasuk orang yang shalih, maka berarti kalian mempercepat meletakkan keburukan dari pundak-pundak kalian.\" Dan telah menceritakan kepadaku [Muhammad bin Rafi'] dan [Abdu bin Humaid] semuanya dari [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] -dalam jalur lain- Dan telah menceritakan kepada kami [Yahya bin Habib] telah menceritakan kepada kami [Rauh bin Ubadah] Telah menceritakan kepada kami [Muhammad bin Abu Hafshah] keduanya dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam. Hanya saja di dalam hadits Ma'mar ia mengatakan; Saya tidak mengetahuinya, kecuali ia telah memarfu'kan hadits."},"1483":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى وَهَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ قَالَ هَارُونُ حَدَّثَنَا و قَالَ الْآخَرَانِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ بْنُ يَزِيدَ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي أَبُو أُمَامَةَ بْنُ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَسْرِعُوا بِالْجَنَازَةِ فَإِنْ كَانَتْ صَالِحَةً قَرَّبْتُمُوهَا إِلَى الْخَيْرِ وَإِنْ كَانَتْ غَيْرَ ذَلِكَ كَانَ شَرًّا تَضَعُونَهُ عَنْ رِقَابِكُمْ","id":"Dan telah menceritakan kepadaku [Abu Thahir] dan [Harmalah bin Yahya] dan [Harun bin Sa'id Al Aili] -Harun berkata- telah menceritakan kepada kami -sementara dua orang yang lain berkata- telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus bin Yazid] dari [Ibnu Syihab] ia berkata, telah menceritakan kepadaku [Abu Umamah bin Sahl bin Hunaif] dari [Abu Hurairah] ia berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Segerakanlah penguburan jenazah, karena jika ia adalah seorang yang shalih, maka kalian telah mendekatkannya pada kebaikan. Tetapi, jika ia tidak termasuk orang yang shalih, maka berarti kalian mempercepat meletakkan keburukan dari pundak-pundak kalian.\""},"1484":{"ar":"و حَدَّثَنِي أَبُو الطَّاهِرِ وَحَرْمَلَةُ بْنُ يَحْيَى وَهَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَاللَّفْظُ لِهَارُونَ وَحَرْمَلَةَ قَالَ هَارُونُ حَدَّثَنَا وَقَالَ الْآخَرَانِ أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ هُرْمُزَ الْأَعْرَجُ أَنَّ أَبَا هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَهِدَ الْجَنَازَةَ حَتَّى يُصَلَّى عَلَيْهَا فَلَهُ قِيرَاطٌ وَمَنْ شَهِدَهَا حَتَّى تُدْفَنَ فَلَهُ قِيرَاطَانِ قِيلَ وَمَا الْقِيرَاطَانِ قَالَ مِثْلُ الْجَبَلَيْنِ الْعَظِيمَيْنِانْتَهَى حَدِيثُ أَبِي الطَّاهِرِ وَزَادَ الْآخَرَانِ قَالَ ابْنُ شِهَابٍ قَالَ سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ وَكَانَ ابْنُ عُمَرَ يُصَلِّي عَلَيْهَا ثُمَّ يَنْصَرِفُ فَلَمَّا بَلَغَهُ حَدِيثُ أَبِي هُرَيْرَةَ قَالَ لَقَدْ ضَيَّعْنَا قَرَارِيطَ كَثِيرَةً و حَدَّثَنَاه أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا عَبْدُ الْأَعْلَى ح و حَدَّثَنَا ابْنُ رَافِعٍ وَعَبْدُ بْنُ حُمَيْدٍ عَنْ عَبْدِ الرَّزَّاقِ كِلَاهُمَا عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَوْلِهِ الْجَبَلَيْنِ الْعَظِيمَيْنِ وَلَمْ يَذْكُرَا مَا بَعْدَهُ وَفِي حَدِيثِ عَبْدِ الْأَعْلَى حَتَّى يُفْرَغَ مِنْهَا وَفِي حَدِيثِ عَبْدِ الرَّزَّاقِ حَتَّى تُوضَعَ فِي اللَّحْدِ و حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَ حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ أَنَّهُ قَالَ حَدَّثَنِي رِجَالٌ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ حَدِيثِ مَعْمَرٍ وَقَالَ وَمَنْ اتَّبَعَهَا حَتَّى تُدْفَنَ","id":"Telah menceritakan kepadaku [Abu Thahir] dan [Harmalah bin Yahya] dan [Harun bin Sa'id Al Aili] -dan lafazh milik Harun dan Harmalah, Harun berkata- telah menceritakan kepada kami -sementara dua orang yang lain berkata- telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] ia berkata, telah menceritakan kepadaku [Abdurrahman bin Hurmuz Al A'raj] bahwa [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang turut menyaksikan pengurusan jenazah hingga ia menshalitinya, maka baginya pahala sebesar satu qirath. Sedangkan siapa yang turut menyaksikan pengurusannya hingga jenazah itu dimakamkan, maka baginya pahala sebesar dua qirath.\" Lalu ditanyakanlah, \"Apakah itu dua qirath?\" beliau menjawab: \"Seperti dua gunung yang besar.\" sampai disinilah haditsnya Abu Thahir. Kemudian dua orang itu menambahkan; Ibnu Syihab berkata, Salim bin Abdullah bin Umar berkata; Ibnu Umar pernah menshalati jenazah lalu ia bubar dan pergi. Dan ketika hadits Abu Hurairah sampai padanya, ia pun berkata, \"Sungguh, kita telah menyia-nyiakan banyak qirath.\" Dan telah menceritakannya kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Abdul A'la] -dalam jalur lain- Dan Telah menceritakan kepada kami [Ibnu Rafi'] dan [Abdu bin Humaid] dari [Abdurrazaq] keduanya dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, hingga sampai pada; \"Seperti dua gunung yang besar.\" Dan ia tidak menyebutkan sesudahnya. Dan di dalam haditsnya Abdul A'la tercantum; \"Hingga pengurusan (jenazah itu) selesai.\" Sementara di dalam riwayat Abdurrazaq tercantum; \"Hingga (jenazah itu) diletakkan di dalam liang lahad.\" Dan telah menceritakan kepadaku [Abdul Malik bin Syu'aib bin Laits] telah menceritakan kepadaku [bapakku] dari [kakekku] ia berkata, telah menceritakan kepadaku [Uqail bin Khalid] dari [Ibnu Syihab] ia berkata, telah menceritakan kepadaku [seorang laki-laki] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, yakni seperti haditsnya Ma'mar. dan ia menyebutkan; \"Hingga (jenazah itu) dikebumikan.\""},"1485":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا بَهْزٌ حَدَّثَنَا وُهَيْبٌ حَدَّثَنِي سُهَيْلٌ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى عَلَى جَنَازَةٍ وَلَمْ يَتْبَعْهَا فَلَهُ قِيرَاطٌ فَإِنْ تَبِعَهَا فَلَهُ قِيرَاطَانِ قِيلَ وَمَا الْقِيرَاطَانِ قَالَ أَصْغَرُهُمَا مِثْلُ أُحُدٍ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Bahz] telah menceritakan kepada kami [Wuhaib] telah menceritakan kepadaku [Suhail] dari [bapaknya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang menshalatkan jenazah, namun ia tidak sampai ikut mengantarnya maka baginya pahala satu qirath. Dan jika ia turut mengantarnya, maka baginya pahala dua qirath.\" Kemudian ditanyakanlah, \"Seperti apakah dua qirath itu?\" beliau menjawab: \"Yang paling kecil di antaranya adalah seperti gunung uhud.\""},"1486":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ يَزِيدَ بْنِ كَيْسَانَ حَدَّثَنِي أَبُو حَازِمٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى عَلَى جَنَازَةٍ فَلَهُ قِيرَاطٌ وَمَنْ اتَّبَعَهَا حَتَّى تُوضَعَ فِي الْقَبْرِ فَقِيرَاطَانِقَالَ قُلْتُ يَا أَبَا هُرَيْرَةَ وَمَا الْقِيرَاطُ قَالَ مِثْلُ أُحُدٍ","id":"Telah menceritakan kepada kami [Muhammad bin Hatim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Yazid bin Kaisan] telah menceritakan kepadaku [Abu Hazim] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa yang menshalatkan jenazah, maka baginya pahala satu qirath, dan siapa yang mengantarnya hingga jenazah itu di letakkan di liang kubur, maka baginya pahala dua qirath.\" Saya bertanya, \"Wahai Abu Hurairah, seperti apakah dua qirath itu?\" ia menjawab, \"Yaitu seperti gunung Uhud.\""},"1487":{"ar":"حَدَّثَنَا شَيْبَانُ بْنُ فَرُّوخَ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ حَدَّثَنَا نَافِعٌ قَالَ قِيلَ لِابْنِ عُمَرَ إِنَّ أَبَا هُرَيْرَةَ يَقُولُاسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ تَبِعَ جَنَازَةً فَلَهُ قِيرَاطٌ مِنْ الْأَجْرِفَقَالَ ابْنُ عُمَرَ أَكْثَرَ عَلَيْنَا أَبُو هُرَيْرَةَ فَبَعَثَ إِلَى عَائِشَةَ فَسَأَلَهَا فَصَدَّقَتْ أَبَا هُرَيْرَةَ فَقَالَ ابْنُ عُمَرَ لَقَدْ فَرَّطْنَا فِي قَرَارِيطَ كَثِيرَةٍ","id":"Telah menceritakan kepada kami [Syaiban bin Farukh] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Nafi'] ia berkata; telah dikatakan kepada Ibnu Umar, bahwa [Abu Hurairah] berkata; Saya mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapa yang mengikuti jenazah, maka baginya satu qirath pahala.\" Ibnu Umar berkata, \"Yang paling banyak (menceritakan hadits kepada kita) adalah Abu Hurairah.\" Lalu ia pun mengutus seseorang kepada Aisyah dan menanyakan hal itu padanya, maka [Aisyah] pun membenarkan Abu Hurairah. Maka Ibnu Umar pun berkata, \"Sungguh, kita telah melewatkan qirath yang banyak.\""},"1488":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنِي حَيْوَةُ حَدَّثَنِي أَبُو صَخْرٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ أَنَّهُ حَدَّثَهُ أَنَّ دَاوُدَ بْنَ عَامِرِ بْنِ سَعْدِ بْنِ أَبِي وَقَّاصٍ حَدَّثَهُ عَنْ أَبِيهِ أَنَّهُكَانَ قَاعِدًا عِنْدَ عَبْدِ اللَّهِ بْنِ عُمَرَ إِذْ طَلَعَ خَبَّابٌ صَاحِبُ الْمَقْصُورَةِ فَقَالَ يَا عَبْدَ اللَّهِ بْنَ عُمَرَ أَلَا تَسْمَعُ مَا يَقُولُ أَبُو هُرَيْرَةَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ خَرَجَ مَعَ جَنَازَةٍ مِنْ بَيْتِهَا وَصَلَّى عَلَيْهَا ثُمَّ تَبِعَهَا حَتَّى تُدْفَنَ كَانَ لَهُ قِيرَاطَانِ مِنْ أَجْرٍ كُلُّ قِيرَاطٍ مِثْلُ أُحُدٍ وَمَنْ صَلَّى عَلَيْهَا ثُمَّ رَجَعَ كَانَ لَهُ مِنْ الْأَجْرِ مِثْلُ أُحُدٍفَأَرْسَلَ ابْنُ عُمَرَ خَبَّابًا إِلَى عَائِشَةَ يَسْأَلُهَا عَنْ قَوْلِ أَبِي هُرَيْرَةَ ثُمَّ يَرْجِعُ إِلَيْهِ فَيُخْبِرُهُ مَا قَالَتْ وَأَخَذَ ابْنُ عُمَرَ قَبْضَةً مِنْ حَصْبَاءِ الْمَسْجِدِ يُقَلِّبُهَا فِي يَدِهِ حَتَّى رَجَعَ إِلَيْهِ الرَّسُولُ فَقَالَ قَالَتْ عَائِشَةُ صَدَقَ أَبُو هُرَيْرَةَ فَضَرَبَ ابْنُ عُمَرَ بِالْحَصَى الَّذِي كَانَ فِي يَدِهِ الْأَرْضَ ثُمَّ قَالَ لَقَدْ فَرَّطْنَا فِي قَرَارِيطَ كَثِيرَةٍ","id":"Dan telah menceritakan kepadaku [Muhammad bin Abdullah bin Numair] Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepadaku [Haiwah] telah menceritakan kepadaku [Abu Shakhrah] dari [Yazid bin Abdullah bin Qusaith] bahwa ia telah menceritakan kepadanya bahwa [Dawud bin Amir bin Sa'd bin Abu Waqash] telah menceritakan kepadanya dari [bapaknya] bahwa suatu ketika ia pernah duduk di sisi Ibnu Umar, tiba-tiba datanglah khabbab pemilik maqshurah seraya berkata, \"Wahai Abdullah bin Umar, tidakkah Anda mendengar apa yang dikatakan oleh [Abu Hurairah], bahwa ia pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa yang menghadiri jenazah, lalu ia menshalatkannya dan turut mengantarkannya hingga jenazah itu dikuburkan, maka baginya dua qrath pahala. Setiap qrath adalah seperti gunung Uhud. Dan siapa yang menshalatinya lalu ia langsung pulang, maka baginya adalah pahala seperti gunung Uhud.'\" Maka Ibnu Umar pun mengutus Khabbab kepada [Aisyah] untuk menanyakan ungkapan Abu Hurairah. Setelah itu, ia kembali untuk mengabarkan perihal komentar Aisyah. Setelah melihat ia kembali, Ibnu Umar langsung mengambil segenggam pasir yang terhampar di dalam Masjid, ia membolak-balikkannya di tangan hingga utusannya kembali. Sesampainya di situ, sang utusan pun berkata; Aisyah berkata, \"Abu Hurairah telah berkata benar.\" Maka seketika itu, Ibnu Umar pun langsung menghempaskan segenggam tanah di tangannya ke tanah, kemudian ia berkata, \"Sungguh, kita telah melewatkan qirath yang banyak.\""},"1489":{"ar":"و حَدَّثَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي قَتَادَةُ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ مَعْدَانَ بْنِ أَبِي طَلْحَةَ الْيَعْمَرِيِّ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ صَلَّى عَلَى جَنَازَةٍ فَلَهُ قِيرَاطٌ فَإِنْ شَهِدَ دَفْنَهَا فَلَهُ قِيرَاطَانِ الْقِيرَاطُ مِثْلُ أُحُدٍو حَدَّثَنِي ابْنُ بَشَّارٍ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي قَالَ وَحَدَّثَنَا ابْنُ الْمُثَنَّى حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ سَعِيدٍ ح و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ حَدَّثَنَا عَفَّانُ حَدَّثَنَا أَبَانُ كُلُّهُمْ عَنْ قَتَادَةَ بِهَذَا الْإِسْنَادِ مِثْلَهُ وَفِي حَدِيثِ سَعِيدٍ وَهِشَامٍ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْقِيرَاطِ فَقَالَ مِثْلُ أُحُدٍ","id":"Dan telah menceritakan kepada kami [Muhammad bin Basysyar] telah menceritakan kepada kami [Yahya, yaitu anaknya Sa'id] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Qatadah] dari [Salim bin Abul Ja'd] dari [Ma'dan bin Abu Thalhah Al Ya'mari] dari [Tsauban] maula Rasulullah shallallahu 'alaihi wasallam, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa menshalatkan jenazah, maka baginya satu qirath pahala. Dan bila turut menyaksikan pemakamannya, maka baginya dua qirath pahala. Sedangkan besar satu qirath seperti besarnya gunung Uhud.\" Dan telah menceritakan kepadaku [Muhammad bin Basysyar] Telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [bapakku] ia berkata, dan telah menceritakan kepada kami [Ibnul Mutsanna] telah menceritakan kepada kami [Ibnu Abu Adi] dari [Sa'id] -dalam jalur lain- Dan telah menceritakan kepadaku [Zuhair bin Harb] telah menceritakan kepada kami ['Affan] Telah menceritakan kepada kami [Aban] semuanya dari [Qatadah] dengan isnad ini, hadits yang semisal dengannya. Dan di dalam hadits Sa'id dan Hisyam; Nabi shallallahu 'alaihi wasallam ditanya tentang qirath, maka beliau menjawab: \"(Yaitu) sebesar gunung Uhud.\""},"1490":{"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عِيسَى حَدَّثَنَا ابْنُ الْمُبَارَكِ أَخْبَرَنَا سَلَّامُ بْنُ أَبِي مُطِيعٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ رَضِيعِ عَائِشَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ مَيِّتٍ تُصَلِّي عَلَيْهِ أُمَّةٌ مِنْ الْمُسْلِمِينَ يَبْلُغُونَ مِائَةً كُلُّهُمْ يَشْفَعُونَ لَهُ إِلَّا شُفِّعُوا فِيهِقَالَ فَحَدَّثْتُ بِهِ شُعَيْبَ بْنَ الْحَبْحَابِ فَقَالَ حَدَّثَنِي بِهِ أَنَسُ بْنُ مَالِكٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Al Hasan bin Isa] telah menceritakan kepada kami [Ibnul Mubarak] telah mengabarkan kepada kami [Sallam bin Abu Muthi'] dari [Ayyub] dari [Abu Qilabah] dari [Abdullah bin Yazid] saudara sesusuan Aisyah, dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mayat yang dishalatkan oleh kaum muslimin dengan jumlah melebihi seratus orang, dan semuanya mendo'akannya, maka do'a mereka untuknya akan dikabulkan.\" Lalu saya menceritakannya kepada [Syu'aib bin Habhab], maka ia pun berkata; [Anas bin Malik] telah menceritakannya kepadaku dari Nabi shallallahu 'alaihi wasallam."},"1491":{"ar":"حَدَّثَنَا هَارُونُ بْنُ مَعْرُوفٍ وَهَارُونُ بْنُ سَعِيدٍ الْأَيْلِيُّ وَالْوَلِيدُ بْنُ شُجَاعٍ السَّكُونِيُّ قَالَ الْوَلِيدُ حَدَّثَنِي و قَالَ الْآخَرَانِ حَدَّثَنَا ابْنُ وَهْبٍ أَخْبَرَنِي أَبُو صَخْرٍ عَنْ شَرِيكِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ مَوْلَى ابْنِ عَبَّاسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّهُ مَاتَ ابْنٌ لَهُ بِقُدَيْدٍ أَوْ بِعُسْفَانَ فَقَالَ يَا كُرَيْبُ انْظُرْ مَا اجْتَمَعَ لَهُ مِنْ النَّاسِ قَالَ فَخَرَجْتُ فَإِذَا نَاسٌ قَدْ اجْتَمَعُوا لَهُ فَأَخْبَرْتُهُ فَقَالَ تَقُولُ هُمْ أَرْبَعُونَ قَالَ نَعَمْ قَالَ أَخْرِجُوهُ فَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ رَجُلٍ مُسْلِمٍ يَمُوتُ فَيَقُومُ عَلَى جَنَازَتِهِ أَرْبَعُونَ رَجُلًا لَا يُشْرِكُونَ بِاللَّهِ شَيْئًا إِلَّا شَفَّعَهُمْ اللَّهُ فِيهِوَفِي رِوَايَةِ ابْنِ مَعْرُوفٍ عَنْ شَرِيكِ بْنِ أَبِي نَمِرٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ","id":"Telah menceritakan kepada kami [Harun bin Ma'ruf] dan [Harun bin Sa'id Al Aili] dan [Al Walid bin Syuja' As Sakuni] -[Al Walid] berkata- telah menceritakan kepadaku -sementara dua orang yang lain berkata- telah menceritakan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Abu Shakhr] dari [Syarik bin Abdullah bin Abu Namir] dari [Kuraib] Maula Ibnu Abbas, dari [Ibnu Abbas] bahwa anaknya telah meninggal di kawasan Qudaid atau 'Usfan, maka ia pun berkata, \"Wahai Kuraib, lihatlah berapa orang yang berkumpul untuk menshalatkannya.\" Kuraib berkata; Maka aku pun keluar, ternyata orang-orang telah berkumpul untuk (menshalatkan) -nya. Lalu aku memberitahukannya kepada Ibnu Abbas, dan ia bertanya, \"Apakah jumlah mereka mencapai empat puluh orang?\" Kuraib menjawab, \"Ya.\" Kemudian Ibnu Abbas berkata, \"Keluarkanlah mayit itu, karena aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidaklah seorang muslim meninggal dunia, dan dishalatkan oleh lebih dari empat puluh orang, yang mana mereka tidak menyekutukan Allah, niscaya Allah akan mengabulkan do'a mereka untuknya.'\" Sementara di dalam riwayat Ibnu Ma'ruf adalah dari Syarik bin Abu Namir dari Kuraib dari Ibnu Abbas."},"1492":{"ar":"و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَأَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ وَزُهَيْرُ بْنُ حَرْبٍ وَعَلِيُّ بْنُ حُجْرٍ السَّعْدِيُّ كُلُّهُمْ عَنْ ابْنِ عُلَيَّةَ وَاللَّفْظُ لِيَحْيَى قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَمُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَيْهَا خَيْرًا فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ وَجَبَتْ وَجَبَتْ وَمُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَيْهَا شَرًّا فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَبَتْ وَجَبَتْ وَجَبَتْ قَالَ عُمَرُ فِدًى لَكَ أَبِي وَأُمِّي مُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَيْهَا خَيْرٌ فَقُلْتَ وَجَبَتْ وَجَبَتْ وَجَبَتْ وَمُرَّ بِجَنَازَةٍ فَأُثْنِيَ عَلَيْهَا شَرٌّ فَقُلْتَ وَجَبَتْ وَجَبَتْ وَجَبَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَثْنَيْتُمْ عَلَيْهِ خَيْرًا وَجَبَتْ لَهُ الْجَنَّةُ وَمَنْ أَثْنَيْتُمْ عَلَيْهِ شَرًّا وَجَبَتْ لَهُ النَّارُ أَنْتُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ أَنْتُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِ أَنْتُمْ شُهَدَاءُ اللَّهِ فِي الْأَرْضِو حَدَّثَنِي أَبُو الرَّبِيعِ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادٌ يَعْنِي ابْنَ زَيْدٍ ح و حَدَّثَنِي يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا جَعْفَرُ بْنُ سُلَيْمَانَ كِلَاهُمَا عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَ مُرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِجَنَازَةٍ فَذَكَرَ بِمَعْنَى حَدِيثِ عَبْدِ الْعَزِيزِ عَنْ أَنَسٍ غَيْرَ أَنَّ حَدِيثَ عَبْدِ الْعَزِيزِ أَتَمُّ","id":"Dan telah menceritakan kepada kami [Yahya bin Ayyub] dan [Abu Bakar bin Abu Syaibah] dan [Zuhair bin Harb] dan [Ali bin Hujr As Sa'di] semuanya dari [Ibnu Ulayyah] -sedangkan lafazhnya milik Yahya- telah mengabarkan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas bin Malik] ia berkata; Suatu ketika iringan jenazah lewat di hadapan Rasulullah shallallahu 'alaihi wasallam, mayit itu dipuji dengan kebaikan, maka beliau pun bersabda: \"Telah wajib baginya, telah wajib baginya, telah wajib baginya.\" Kemudian lewatlah iringan jenazah lain di hadapan beliau, namun mayat itu dicaci dengan keburukan, maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Telah wajib baginya, telah wajib baginya, telah wajib baginya.\" Maka Umar berkata, \"Ibu dan ayahku menjadi tebusan bagimu, telah lewat iringan jenazah lalu mayit itu dipuji dengan kebaikan kemudian Anda mengatakan: 'Telah wajib baginya, telah wajib baginya, telah wajib baginya.' Setelah itu, lewatlah jenazah lain, dan mayit itu dicaci dengan keburukan lalu Anda pun mengatakan: 'Telah wajib baginya, telah wajib baginya, telah wajib baginya.'\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Siapa yang telah kalian puji dengan kebaikan, maka telah wajib baginya surga. Dan siapa yang telah kalian cela dengan keburukan, maka telah wajib pula baginya neraka. Kalian adalah Syuhada`ullahi (para saksi Allah) di muka bumi, kalian adalah Syuhada`ullahi (para saksi Allah) di muka bumi.\" Dan telah menceritakan kepadaku [Abu Rabi' Az Zahrani] telah menceritakan kepada kami [Hammad] yakni Ibnu Zaid -dalam jalur lain- Dan telah menceritakan kepadaku [Yahya bin Yahya] telah mengabarkan kepada kami [Ja'far bin Sulaiman] keduanya dari [Tsabit] dari [Anas] ia berkata; Suatu ketika iringan jenazah lewat di hadapan Rasulullah shallallahu 'alaihi wasallam. Ia pun menyebutkan makna hadits Abdul Aziz, dari Anas. Hanya saja haditsnya Abdul Aziz lebih sempurna."},"1493":{"ar":"و حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ عَنْ مَالِكِ بْنِ أَنَسٍ فِيمَا ق��رِئَ عَلَيْهِ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَلْحَلَةَ عَنْ مَعْبَدِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ بْنِ رِبْعِيٍّ أَنَّهُ كَانَ يُحَدِّثُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرَّ عَلَيْهِ بِجَنَازَةٍ فَقَالَ مُسْتَرِيحٌ وَمُسْتَرَاحٌ مِنْهُ قَالُوا يَا رَسُولَ اللَّهِ مَا الْمُسْتَرِيحُ وَالْمُسْتَرَاحُ مِنْهُ فَقَالَ الْعَبْدُ الْمُؤْمِنُ يَسْتَرِيحُ مِنْ نَصَبِ الدُّنْيَا وَالْعَبْدُ الْفَاجِرُ يَسْتَرِيحُ مِنْهُ الْعِبَادُ وَالْبِلَادُ وَالشَّجَرُ وَالدَّوَابُّو حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ الرَّزَّاقِ جَمِيعًا عَنْ عَبْدِ اللَّهِ بْنِ سَعِيدِ بْنِ أَبِي هِنْدٍ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ ابْنٍ لِكَعْبِ بْنِ مَالِكٍ عَنْ أَبِي قَتَادَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَفِي حَدِيثِ يَحْيَى بْنِ سَعِيدٍ يَسْتَرِيحُ مِنْ أَذَى الدُّنْيَا وَنَصَبِهَا إِلَى رَحْمَةِ اللَّهِ","id":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] dari [Malik bin Anas] -terkait dengan hadits yang telah dibacakan kepadanya- dari [Muhammad bin Amru bin Halhalah] dari [Ma'bad bin Ka'ab bin Malik] dari [Abu Qatadah bin Rabi'i] bahwa ia menceritakan bahwasanya; Suatu ketika iringan jenazah lewat di hadapan Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"MUTARIIH dan MUSTARAAH.\" Para sahabat bertanya, \"Wahai Rasulullah, apakah itu MUSTARIIH dan MUSTARAAH?\" beliau menjawab, \"Seorang hamba yang mukmin YASTARIH (akan beristirahat) dari memakmurkan dunia, sementara seorang hamba yang fajir, justru seluruh hamba, negeri, pepohonan dan binatang melata akan YASTARIH (beristirahat) dari (kezhalimannya) \" Dan Telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Yahya bin Sa'id] -dalam jalur lain- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Abdurrazaq] semuanya dari [Abdullah bin Sa'id bin Abu Hind] dari [Muhammad bin Amru] dari [Ibnu Ka'ab bin Malik] dari [Abu Qatadah] dari Nabi shallallahu 'alaihi wasallam. Dan di dalam hadits Yahya bin Sa'id: \"(Seorang hamba mukmin) akan beristirahat dari kesulitan dan kepenatan dunia menuju rahmat Allah.\""},"1494":{"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَى لِلنَّاسِ النَّجَاشِيَ فِي الْيَوْمِ الَّذِي مَاتَ فِيهِ فَخَرَجَ بِهِمْ إِلَى الْمُصَلَّى وَكَبَّرَ أَرْبَعَ تَكْبِيرَاتٍ","id":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam memanggil kaum muslimin untuk menunaikan (shalat ghaib) untuk raja Najasyi, pada hari wafatnya. Maka beliau pun keluar menuju mushalla (tanah lapang) bersama mereka dan bertakbir sebanyak empat kali takbir."},"1495":{"ar":"و حَدَّثَنِي عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَ حَدَّثَنِي عُقَيْلُ بْنُ خَالِدٍ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّهُمَا حَدَّثَاهُ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَنَعَى لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّجَاشِيَ صَاحِبَ الْحَبَشَةِ فِي الْيَوْمِ الَّذِي مَاتَ فِيهِ فَقَالَ اسْتَغْفِرُوا لِأَخِيكُمْقَالَ ابْنُ شِهَابٍ وَحَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفَّ بِهِمْ بِالْمُصَلَّى فَصَلَّى فَكَبَّرَ عَلَيْهِ أَرْبَعَ تَكْبِيرَاتٍ و حَدَّثَنِي عَمْرٌو النَّاقِدُ وَحَسَنٌ الْحُلْوَانِيُّ وَعَبْدُ بْنُ حُمَيْدٍ قَالُوا حَدَّثَنَا يَعْقُوبُ وَهُوَ ابْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ كَرِوَايَةِ عُقَيْلٍ بِالْإِسْنَادَيْنِ جَمِيعًا","id":"Dan telah menceritakan kepadaku [Abdul Malik bin Syu'aib bin Laits] telah menceritakan kepadaku [bapakku] dari [kakekku] ia berkata, telah menceritakan kepadaku [Uqail bin Khalid] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Abu Salamah bin Abdurrahman] bahwa keduanya telah menceritakan kepadanya dari [Abu Hurairah] bahwa ia berkata; Rasulullah shallallahu 'alaihi wasallam mengajak kami untuk menunaikan shalat (ghaib) untuk kematian An Najasyi, raja negeri Habasyah. Beliau bersabda: \"Mintakanlah ampunan untuk saudara kalian (An Najasyi).\" Ibnu Syihab berkata; Dan telah menceritakan kepadaku Sa'id bin Al Musayyab, bahwa Abu Hurairah telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam mengatur shaf mereka di Mushalla (tanah lapang), lalu beliau shalat (ghaib) dan bertakbir atasnya sebanyak empat kali takbir. Dan telah menceritakan kepadaku [Amru An Naqid] dan [Hasan Al Hulwani] dan [Abdu Humaid] mereka berkata, telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd] telah menceritakan kepada kami [bapakku] dari [Shalih] dari [Ibnu Syihab] sebagaimana riwayat Uqail dengan kedua isnad itu."},"1496":{"ar":"و حَدَّثَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ عَنْ سَلِيمِ بْنِ حَيَّانَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ مِينَاءَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى أَصْحَمَةَ النَّجَاشِيِّ فَكَبَّرَ عَلَيْهِ أَرْبَعًا","id":"Dan telah menceritakan kepada kami [Abu Bakar bin Abu Syaibah] telah menceritakan kepada kami [Yazid bin Harun] dari [Salim bin Hayyan] ia berkata, telah menceritakan kepada kami [Sa'id bin Mina`] dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam shalat (ghaib) atas kematian raja An Najasyi, maka beliau pun bertakbir atasnya sebanyak empat kali takbir."},"1497":{"ar":"و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ الْيَوْمَ عَبْدٌ لِلَّهِ صَالِحٌ أَصْحَمَةُ فَقَامَ فَأَمَّنَا وَصَلَّى عَلَيْهِ","id":"Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij] dari [Atha`] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada hari ini, seorang hamba Allah yang shalih Ashmahah meninggal dunia.\" Akhirnya beliau berdiri dan mengimami kami dan shalat (ghaib) atasnya."},"1498":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ عُبَيْدٍ الْغُبَرِيُّ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ ح و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ وَاللَّفْظُ لَهُ حَدَّثَنَا ابْنُ عُلَيَّةَ حَدَّثَنَا أَيُّوبُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَخًا لَكُمْ قَدْ مَاتَ فَقُومُوا فَصَلُّوا عَلَيْهِ قَالَ فَقُمْنَا فَصَفَّنَا صَفَّيْنِ","id":"Telah menceritakan kepada kami [Muhammad bin Ubaid Al Ghubari] telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Abu Zubair] dari [Jabir bin Abdullah] -dalam jalur lain- Dan telah menceritakan kepada kami [Yahya bin Ayyub] -dan lafazh juga miliknya- Telah menceritakan kepada kami [Ibnu Ulayyah] Telah menceritakan kepada kami [Ayyub] dari [Abu Zubair] dari [Jabir bin Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saudara kalian telah meninggal, karena itu berdirilah untuk menunaikan shalat (ghaib) atasnya.\" Maka kami pun berdiri, dan beliau mengatur shaf kami menjadi dua shaf."},"1499":{"ar":"و حَدَّثَنِي زُهَيْرُ بْنُ حَرْبٍ وَعَلِيُّ بْنُ حُجْرٍ قَالَا حَدَّثَنَا إِسْمَعِيلُ ح و حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَقَالَ رَسُولُ اللَّهِ إِنَّ أَخًا لَكُمْ قَدْ مَاتَ فَقُومُوا فَصَلُّوا عَلَيْهِ يَعْنِي النَّجَاشِيَوَفِي رِوَايَةِ زُهَيْرٍ إِنَّ أَخَاكُمْ","id":"Dan telah menceritakan kepadaku [Zuhair bin Harb] dan [Ali bin Hujr] telah menceritakan kepada kami [Isma'il] -dalam jalur lain- Dan telah menceritakan kepada kami [Yahya bin Ayyub] Telah menceritakan kepada kami [Ibnu Ulayyah] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saudara kalian (raja Najasyi) telah meninggal, karena itu berdirilah kalian (untuk shalat ghaib) atasnya.\" Dan di dalam riwayat Zuhair tercantum; \"Sesungguhnya saudara kalian (Inna Akhaakum).\""},"1500":{"ar":"حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ وَمُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ نُمَيْرٍ قَالَا حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَلَّى عَلَى قَبْرٍ بَعْدَ مَا دُفِنَ فَكَبَّرَ عَلَيْهِ أَرْبَعًاقَالَ الشَّيْبَانِيُّ فَقُلْتُ لِلشَّعْبِيِّ مَنْ حَدَّثَكَ بِهَذَا قَالَ الثِّقَةُ عَبْدُ اللَّهِ بْنُ عَبَّاسٍ هَذَا لَفْظُ حَدِيثِ حَسَنٍ وَفِي رِوَايَةِ ابْنِ نُمَيْرٍ قَالَ انْتَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى قَبْرٍ رَطْبٍ فَصَلَّى عَلَيْهِ وَصَفُّوا خَلْفَهُ وَكَبَّرَ أَرْبَعًا قُلْتُ لِعَامِرٍ مَنْ حَدَّثَكَ قَالَ الثِّقَةُ مَنْ شَهِدَهُ ابْنُ عَبَّاسٍ و حَدَّثَنَا يَحْيَى بْنُ يَحْيَى أَخْبَرَنَا هُشَيْمٌ ح و حَدَّثَنَا حَسَنُ بْنُ الرَّبِيعِ وَأَبُو كَامِلٍ قَالَا حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ زِيَادٍ ح و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا جَرِيرٌ ح و حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمٍ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا سُفْيَانُ ح و حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُعَاذٍ حَدَّثَنَا أَبِي ح و حَدَّثَنَا مُحَمَّدُ بْنُ الْمُثَنَّى حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ كُلُّ هَؤُلَاءِ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِهِ وَلَيْسَ فِي حَدِيثِ أَحَدٍ مِنْهُمْ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَبَّرَ عَلَيْهِ أَرْبَعًا و حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَهَارُونُ بْنُ عَبْدِ اللَّهِ جَمِيعًا عَنْ وَهْبِ بْنِ جَرِيرٍ عَنْ شُعْبَةَ عَنْ إِسْمَعِيلَ بْنِ أَبِي خَالِدٍ ح و حَدَّثَنِي أَبُو غَسَّانَ مُحَمَّدُ بْنُ عَمْرٍو الرَّازِيُّ حَدَّثَنَا يَحْيَى بْنُ الضُّرَيْسِ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ أَبِي حَصِينٍ كِلَاهُمَا عَنْ الشَّعْبِيِّ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي صَلَاتِهِ عَلَى الْقَبْرِ نَحْوَ حَدِيثِ الشَّيْبَانِيِّ لَيْسَ فِي حَدِيثِهِمْ وَكَبَّرَ أَرْبَعًا","id":"Telah menceritakan kepada kami [Hasan bin Rabi'] dan [Muhammad bin Abdullah bin Numair] keduanya berkata, telah menceritakan kepada kami [Abdullah bin Idris] dari [Asy Syaiban] dari [Asy Sya'bi] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menshalatkan jenazah di atas kuburan setelah dikebumikannya mayit. Beliau bertakbir atasnya empat kali. [Asy Syaibani] berkata; Saya bertanya kepada [Asy Sya'bi], \"Siapa yang menceritakanmu hadits ini?\" ia menjawab, \"Yaitu seorang yang tsiqqah (terpercaya), [Abdullah bin Abbas]. Dan ini adalah lafazh haditsnya Hasan.\" Dan dalam riwayat Ibnu Numair ia berkata; Rasulullah shallallahu 'alaihi wasallam sampai pada kuburan yang masih lembab, maka beliau pun menshalatinya, kemudian para sahabat berbaris di belakangnya. Lalu beliau bertakbir empat kali. Saya bertanya kepada [Amir], \"Siapa yang menceritakan hadits ini kepadamu?\" ia menjawab, \"Dari seorang yang terpercaya yaitu [Ibnu Abbas].\" Dan Telah menceritakan kepada kami [Yahya bin Yahya] telah mengabarkan kepada kami [Husyaim] -dalam jalur lain- Dan telah menceritakan kepada kami [Hasan bin Rabi'] dan [Abu Kamil] keduanya berkata, telah menceritakan kepada kami [Abdul Wahid bin Ziyad] -dalam jalur lain- Telah menceritakan kepada kami [Abdul Wahid bin Ziyad] -dalam jalur lain- Dan telah menceritakan kepada kami [Ishaq bin Ibrahim] telah mengabarkan kepada kami [Jarir] -dalam jalur lain- Dan telah menceritakan kepadaku [Muhammad bin Hatim] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Sufyan] -dalam jalur lain- Dan telah menceritakan kepada kami [Ubaidullah bin Mu'adz] telah menceritakan kepada kami [bapakku] -dalam jalur lain- Dan telah menceritakan kepada kami [Muhammad bin Al Mutsanna] Telah menceritakan kepada kami [Muhammad bin Ja'far] ia berkata, telah menceritakan kepada kami [Syu'bah] semuanya dari [Asy Syaibani] dari [Asy Sya'bi] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam dengan hadits semisalnya. Dan di antara hadits mereka itu, tidak ada satu pun yang menyatakan; Bahwa Nabi shallallahu 'alaihi wasallam bertakbir atasnya empat kali. Dan Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Harun bin Abdullah] semuanya dari [Wahb bin Jarir] dari [Syu'bah] dari [Isma'il bin Abu Khalid] -dalam jalur lain- Dan telah menceritakan kepadaku [Abu Ghassan Muhammad bin Amr Ar Razi] telah menceritakan kepada kami [Yahya bin Adl Dlurais] telah menceritakan kepada kami [Ibrahim bin Thahman] dari [Abu Hashin] keduanya dari [Asy Sya'bi] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, mengenai shalat (jenazah) di kuburan, sebagaimana hadits Asy Syaibani, namun di dalam hadits mereka tidak tercantum; \"Beliau bertakbir sebanyak empat kali.\""}};
